class FortuneCustomToolbarItem {
  const FortuneCustomToolbarItem({
    required this.key,
    this.tooltip,
    this.children,
    this.iconName,
    this.icon,
    this.disabled = false,
    this.onClick,
  });

  final String key;
  final String? tooltip;
  final Object? children;
  final String? iconName;
  final Object? icon;
  final bool disabled;
  final FortuneCustomToolbarItemClick? onClick;

  Map<String, Object?> toJson() {
    return {
      'key': key,
      if (tooltip != null) 'tooltip': tooltip,
      if (children != null) 'children': cloneFortuneMetadata(children),
      if (iconName != null) 'iconName': iconName,
      if (icon != null) 'icon': cloneFortuneMetadata(icon),
      if (disabled) 'disabled': true,
    };
  }
}

