class _FortuneFontFamilyCandidate {
  const _FortuneFontFamilyCandidate({
    required this.family,
    required this.baseFamily,
  });

  final String family;
  final String baseFamily;
}

typedef FortuneFontFamilyMergeCallback =
    void Function(String source, String family);
typedef FortuneFontFamilyFilterCallback = void Function(String family);

String _fortuneCleanFontFamilyName(String value) {
  return value
      .replaceAll('"', '')
      .replaceAll("'", '')
      .replaceAll(RegExp(r'[_\-]+'), ' ')
      .replaceAll(RegExp(r'\s+'), ' ')
      .trim();
}

String _fortuneFontFamilyKey(String value) {
  return value.toLowerCase();
}

bool _fortuneIsCommonFontFamily(String family) {
  final key = _fortuneFontFamilyKey(family);
  if (_fortuneUncommonFontFamilyContains.any(key.contains)) {
    return false;
  }
  if (_fortuneCommonFontFamilyKeys.contains(key)) {
    return true;
  }
  return _fortuneCommonFontFamilyPrefixes.any(key.startsWith);
}

String fortuneNormalizeFontFamily(String? raw, {String fallback = 'Arial'}) {
  if (raw == null || raw.trim().isEmpty) {
    return fallback;
  }
  final index = int.tryParse(raw);
  if (index != null && index >= 0 && index < fortuneFontArray.length) {
    return fortuneFontArray[index];
  }
  final family = _fortuneCleanFontFamilyName(raw);
  return family.isEmpty ? fallback : family;
}

String _fortuneStripFontStyleSuffix(String value) {
  var family = value;
  while (true) {
    final alias = _fortuneFontFamilyAliases[_fortuneFontFamilyKey(family)];
    if (alias != null) {
      family = alias;
    }
    if (family.length > 1 && family.endsWith('체')) {
      return family.substring(0, family.length - 1);
    }
    final words = family.split(' ');
    if (words.length < 2) {
      return family;
    }
    var stripped = family;
    for (final suffixLength in const [3, 2, 1]) {
      if (words.length <= suffixLength) {
        continue;
      }
      final suffix = words.sublist(words.length - suffixLength).join(' ');
      if (_fortuneFontStyleSuffixes.contains(suffix.toLowerCase())) {
        stripped = words.sublist(0, words.length - suffixLength).join(' ');
        break;
      }
    }
    if (stripped == family) {
      return family;
    }
    family = stripped;
  }
}

List<String> fortuneMergeFontFamilies(
  Iterable<String> fontFamilies, {
  Iterable<String> fallback = fortuneFontArray,
  FortuneFontFamilyMergeCallback? onCollapsedFamily,
  FortuneFontFamilyMergeCallback? onDuplicateFamily,
  FortuneFontFamilyFilterCallback? onFilteredFamily,
}) {
  final candidates = <_FortuneFontFamilyCandidate>[];
  void collect(String value) {
    final cleaned = _fortuneCleanFontFamilyName(value);
    if (cleaned.isEmpty) {
      return;
    }
    candidates.add(
      _FortuneFontFamilyCandidate(family: cleaned, baseFamily: cleaned),
    );
  }

  for (final family in fallback) {
    collect(family);
  }
  for (final family in fontFamilies) {
    collect(family);
  }

  final exactFamilies = <String>{};
  for (final candidate in candidates) {
    exactFamilies.add(_fortuneFontFamilyKey(candidate.family));
  }

  final result = <String>[];
  final seen = <String>{};
  for (final candidate in candidates) {
    var baseFamily = candidate.baseFamily;
    var baseKey = _fortuneFontFamilyKey(baseFamily);
    final commonFamily = _fortuneCommonFontFamilyAliases[baseKey];
    if (commonFamily != null &&
        (exactFamilies.contains(_fortuneFontFamilyKey(commonFamily)) ||
            _fortunePlatformFontFamilyAliasKeys.contains(baseKey))) {
      baseFamily = commonFamily;
      baseKey = _fortuneFontFamilyKey(baseFamily);
    }
    final familyKey = _fortuneFontFamilyKey(candidate.family);
    final shouldCollapse = baseKey != familyKey;
    final family = shouldCollapse ? baseFamily : candidate.family;
    if (shouldCollapse) {
      onCollapsedFamily?.call(candidate.family, family);
    }
    if (!_fortuneIsCommonFontFamily(family)) {
      onFilteredFamily?.call(candidate.family);
      continue;
    }
    final key = _fortuneFontFamilyKey(family);
    if (seen.add(key)) {
      result.add(family);
    } else {
      onDuplicateFamily?.call(candidate.family, family);
    }
  }
  return result;
}

List<String> fortuneSortFontFamilies(
  Iterable<String> fontFamilies, {
  Iterable<String> preferred = const <String>[],
}) {
  final preferredKeys = {
    for (final family in preferred) _fortuneFontFamilyKey(family),
  };
  final sorted = fontFamilies.toList();
  sorted.sort((left, right) {
    final leftKey = _fortuneFontFamilyKey(left);
    final rightKey = _fortuneFontFamilyKey(right);
    final leftPreferred = preferredKeys.contains(leftKey);
    final rightPreferred = preferredKeys.contains(rightKey);
    if (leftPreferred != rightPreferred) {
      return leftPreferred ? -1 : 1;
    }
    final nameCompare = leftKey.compareTo(rightKey);
    if (nameCompare != 0) {
      return nameCompare;
    }
    return left.compareTo(right);
  });
  return sorted;
}

Iterable<String> fortuneFontFamilyDebugListLines(
  String label,
  List<String> families, {
  int chunkSize = 40,
}) sync* {
  yield 'font $label final count=${families.length}';
  for (var index = 0; index < families.length; index += chunkSize) {
    final end = math.min(index + chunkSize, families.length);
    yield 'font $label final ${index + 1}-$end=${families.sublist(index, end).join(' | ')}';
  }
}

String fortuneResolveFontFamily(
  String? raw,
  Iterable<String> availableFamilies, {
  String fallback = 'Arial',
}) {
  final requested = fortuneNormalizeFontFamily(raw, fallback: fallback);
  final available = fortuneMergeFontFamilies(availableFamilies);
  if (available.isEmpty) {
    return requested;
  }
  final availableByKey = <String, String>{
    for (final family in available) _fortuneFontFamilyKey(family): family,
  };
  final requestedKey = _fortuneFontFamilyKey(requested);
  final exact = availableByKey[requestedKey];
  if (exact != null) {
    return exact;
  }

  final requestedBase = _fortuneStripFontStyleSuffix(requested);
  final requestedBaseKey = _fortuneFontFamilyKey(requestedBase);
  final baseExact = availableByKey[requestedBaseKey];
  if (baseExact != null) {
    return baseExact;
  }

  final familyByBaseKey = <String, String>{
    for (final family in available)
      _fortuneFontFamilyKey(_fortuneStripFontStyleSuffix(family)): family,
  };
  final baseMatch = familyByBaseKey[requestedBaseKey];
  if (baseMatch != null) {
    return baseMatch;
  }

  final categoryMatch = _fortuneFontCategoryFallback(requested, available);
  if (categoryMatch != null) {
    return categoryMatch;
  }

  final tokenMatch = _fortuneClosestFontTokenMatch(requested, available);
  if (tokenMatch != null) {
    return tokenMatch;
  }

  return availableByKey[_fortuneFontFamilyKey(fallback)] ?? available.first;
}

String? _fortuneClosestFontTokenMatch(
  String requested,
  List<String> available,
) {
  final requestedTokens = _fortuneFontFamilyTokens(requested);
  if (requestedTokens.isEmpty) {
    return null;
  }
  String? bestFamily;
  var bestScore = 0;
  for (final family in available) {
    final tokens = _fortuneFontFamilyTokens(family);
    if (tokens.isEmpty) {
      continue;
    }
    final shared = requestedTokens.intersection(tokens).length;
    if (shared == 0) {
      continue;
    }
    final score = shared * 10 - (requestedTokens.length - tokens.length).abs();
    if (score > bestScore) {
      bestScore = score;
      bestFamily = family;
    }
  }
  return bestFamily;
}

Set<String> _fortuneFontFamilyTokens(String family) {
  return _fortuneStripFontStyleSuffix(
    family,
  ).toLowerCase().split(' ').where((token) => token.isNotEmpty).toSet();
}

String? _fortuneFontCategoryFallback(String requested, List<String> available) {
  final key = _fortuneFontFamilyKey(requested);
  if (RegExp(r'\b(mono|code|console|coding|courier)\b').hasMatch(key)) {
    return _fortuneFirstAvailableFont(available, const [
      'Cascadia Mono',
      'Consolas',
      'Courier New',
      'D2Coding',
    ]);
  }
  if (RegExp(
    r'\b(serif|times|roman|batang|gungseo|mincho|ming|simsun)\b',
  ).hasMatch(key)) {
    return _fortuneFirstAvailableFont(available, const [
      'Times New Roman',
      'Noto Serif KR',
      '바탕',
      '궁서',
    ]);
  }
  if (RegExp(r'\b(sans|gothic|ui|gulim|dotum|malgun)\b').hasMatch(key)) {
    return _fortuneFirstAvailableFont(available, const [
      'Arial',
      '맑은 고딕',
      'Noto Sans KR',
      '굴림',
      '돋움',
    ]);
  }
  return null;
}

String? _fortuneFirstAvailableFont(
  List<String> available,
  List<String> preferences,
) {
  final byKey = <String, String>{
    for (final family in available) _fortuneFontFamilyKey(family): family,
  };
  for (final preference in preferences) {
    final family = byKey[_fortuneFontFamilyKey(preference)];
    if (family != null) {
      return family;
    }
  }
  return null;
}

