const String formulaError = 'ERROR';
const String formulaErrorDivZero = 'DIV/0';
const String formulaErrorName = 'NAME';
const String formulaErrorNotAvailable = 'N/A';
const String formulaErrorNull = 'NULL';
const String formulaErrorNum = 'NUM';
const String formulaErrorRef = 'REF';
const String formulaErrorValue = 'VALUE';

// ignore: constant_identifier_names
const String ERROR = formulaError;
// ignore: constant_identifier_names
const String ERROR_DIV_ZERO = formulaErrorDivZero;
// ignore: constant_identifier_names
const String ERROR_NAME = formulaErrorName;
// ignore: constant_identifier_names
const String ERROR_NOT_AVAILABLE = formulaErrorNotAvailable;
// ignore: constant_identifier_names
const String ERROR_NULL = formulaErrorNull;
// ignore: constant_identifier_names
const String ERROR_NUM = formulaErrorNum;
// ignore: constant_identifier_names
const String ERROR_REF = formulaErrorRef;
// ignore: constant_identifier_names
const String ERROR_VALUE = formulaErrorValue;

const Map<String, String> _formulaParserErrors = {
  formulaError: '#ERROR!',
  formulaErrorDivZero: '#DIV/0!',
  formulaErrorName: '#NAME?',
  formulaErrorNotAvailable: '#N/A',
  formulaErrorNull: '#NULL!',
  formulaErrorNum: '#NUM!',
  formulaErrorRef: '#REF!',
  formulaErrorValue: '#VALUE!',
};

String? formulaParserError(Object? type) {
  final normalized = '$type'.replaceAll(RegExp(r'[#!?]'), '');
  return _formulaParserErrors[normalized];
}

bool isValidStrict(Object? type) {
  return _formulaParserErrors.containsValue(type);
}

