  '#a0a7e6',
  '#c4ebad',
  '#96dee8',
];

int fortunePresenceHashCode(String value) {
  var hash = 0;
  for (final codeUnit in value.codeUnits) {
    hash = 0xffffffff & (((hash << 5) - hash) + codeUnit);
    if (hash & 0x80000000 != 0) {
      hash -= 0x100000000;
    }
  }
  return hash;
}

String fortunePresenceColorForUserId(String userId) {
  final index =
      fortunePresenceHashCode(userId).abs() %
      fortunePresenceColorPalette.length;
  return fortunePresenceColorPalette[index];
}

