List<Presence> addPresence(Iterable<Presence>? presences, Presence presence) {
  return addPresences(presences, [presence]);
}

List<Presence> addPresences(
  Iterable<Presence>? presences,
  Iterable<Presence> newPresences,
) {
  final nextPresenceList = newPresences
      .map((presence) => Map<String, Object?>.from(presence))
      .toList();
  final nextKeys = nextPresenceList.map(_presenceComparisonKey).toSet();
  return [
    for (final presence in presences ?? const <Presence>[])
      if (!nextKeys.contains(_presenceComparisonKey(presence)))
        Map<String, Object?>.from(presence),
    ...nextPresenceList,
  ];
}

List<Presence> removePresence(
  Iterable<Presence>? presences,
  Presence presence,
) {
  return removePresences(presences, [presence]);
}

List<Presence> removePresences(
  Iterable<Presence>? presences,
  Iterable<Presence> removedPresences,
) {
  final removedKeys = removedPresences.map(_presenceComparisonKey).toSet();
  return [
    for (final presence in presences ?? const <Presence>[])
      if (!removedKeys.contains(_presenceComparisonKey(presence)))
        Map<String, Object?>.from(presence),
  ];
}

Object? _presenceComparisonKey(Presence presence) {
  return presence['userId'] ?? presence['username'];
}

