Context storeSheetParamALL(Context ctx) {
  final sheetIndex = _apiContextSheetIndex(ctx);
  if (sheetIndex == null) {
    return ctx;
  }
  final files = ctx['luckysheetfile'] as List;
  final sheet = files[sheetIndex];
  if (sheet is! Map) {
    return ctx;
  }
  sheet['config'] = cloneFortuneMetadata(ctx['config']);
  sheet['luckysheet_select_save'] = cloneFortuneMetadata(
    ctx['luckysheet_select_save'],
  );
  sheet['luckysheet_selection_range'] = cloneFortuneMetadata(
    ctx['luckysheet_selection_range'],
  );
  sheet['zoomRatio'] = ctx['zoomRatio'];
  return ctx;
}

Context updateContextWithSheetData(Context ctx, List<List<Object?>> data) {
  final rowCount = data.length;
  final columnCount = rowCount == 0 ? 0 : data.first.length;
  final rowLength = _nullableDoubleArg(ctx['defaultrowlen']) ?? 19;
  final columnLength = _nullableDoubleArg(ctx['defaultcollen']) ?? 73;
  final config = ctx['config'] is Map
      ? Map<Object?, Object?>.from(ctx['config'] as Map)
      : const <Object?, Object?>{};
  final zoomRatio = _nullableDoubleArg(ctx['zoomRatio']) ?? 1;
  final rowAxis = _apiContextAxisFromConfig(
    count: rowCount,
    defaultLength: rowLength,
    configuredLengths: config['rowlen'],
    hiddenIndexes: config['rowhidden'],
    zoomRatio: zoomRatio,
  );
  final columnAxis = _apiContextAxisFromConfig(
    count: columnCount,
    defaultLength: columnLength,
    configuredLengths: config['columnlen'],
    hiddenIndexes: config['colhidden'],
    zoomRatio: zoomRatio,
  );
  ctx['visibledatarow'] = rowAxis;
  ctx['visibledatacolumn'] = columnAxis;
  ctx['rh_height'] = (rowAxis.isEmpty ? 0 : rowAxis.last) + 80;
  ctx['ch_width'] = (columnAxis.isEmpty ? 0 : columnAxis.last) + 120;
  final selection = ctx['luckysheet_select_save'];
  if (selection is Iterable) {
    ctx['luckysheet_select_save'] = [
      for (final item in selection.whereType<Map>())
        if (_selectionRangeFromApiMap(item) case final range?)
          _selectionRangeToApiMap(
            _apiContextClampRange(range, rowCount, columnCount),
          ),
    ];
  }
  return ctx;
}

List<num> _apiContextAxisFromConfig({
  required int count,
  required num defaultLength,
  required Object? configuredLengths,
  required Object? hiddenIndexes,
  required num zoomRatio,
}) {
  final lengths = configuredLengths is Map ? configuredLengths : null;
  final hidden = hiddenIndexes is Map ? hiddenIndexes : null;
  final axis = <num>[];
  var current = 0;
  for (var index = 0; index < count; index += 1) {
    if (_apiMapContainsIndex(hidden, index)) {
      axis.add(current);
      continue;
    }
    final configuredLength = _apiMapIndexNumber(lengths, index);
    final length = configuredLength ?? defaultLength;
    current += ((length + 1) * zoomRatio).round();
    axis.add(current);
  }
  return axis;
}

bool _apiMapContainsIndex(Map<Object?, Object?>? map, int index) {
  if (map == null) {
    return false;
  }
  return map.containsKey(index) || map.containsKey('$index');
}

num? _apiMapIndexNumber(Map<Object?, Object?>? map, int index) {
  if (map == null) {
    return null;
  }
  return _nullableDoubleArg(map[index] ?? map['$index']);
}

Context updateContextWithCanvas(
  Context ctx, {
  required num placeholderWidth,
  required num placeholderHeight,
}) {
  final rowHeaderWidth = _nullableDoubleArg(ctx['rowHeaderWidth']) ?? 46;
  final columnHeaderHeight =
      _nullableDoubleArg(ctx['columnHeaderHeight']) ?? 20;
  final devicePixelRatio = _nullableDoubleArg(ctx['devicePixelRatio']) ?? 1;
  ctx['luckysheetTableContentHW'] = [placeholderWidth, placeholderHeight];
  ctx['cellmainHeight'] = placeholderHeight - columnHeaderHeight;
  ctx['cellmainWidth'] = placeholderWidth - rowHeaderWidth;
  ctx['canvasStyle'] = <String, Object?>{
    'width': '${placeholderWidth}px',
    'height': '${placeholderHeight}px',
  };
  ctx['canvasSize'] = <String, Object?>{
    'width': (placeholderWidth * devicePixelRatio).ceil(),
    'height': (placeholderHeight * devicePixelRatio).ceil(),
  };
  return ctx;
}

Context jfrefreshgrid(
  Context ctx, {
  Object? data,
  Object? range,
  bool isRunExecFunction = true,
}) {
  final rawRange = range ?? ctx['luckysheet_select_save'];
  final ranges = _apiContextRanges(rawRange);
  if (ranges.isEmpty) {
    return ctx;
  }
  final refreshData = data ?? ctx['flowdata'];
  ctx['refreshRange'] = [
    for (final item in ranges) _selectionRangeToApiMap(item),
  ];
  if (refreshData != null) {
    ctx['refreshData'] = cloneFortuneMetadata(refreshData);
  }
  if (!isRunExecFunction) {
    return ctx;
  }
  final formulaCache = ctx['formulaCache'] is Map
      ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
      : <String, Object?>{};
  final sheetId = '${ctx['currentSheetId'] ?? ''}';
  final execFunctionExist = <Map<String, Object?>>[];
  for (final item in ranges) {
    for (var row = item.rowStart; row <= item.rowEnd; row += 1) {
      for (
        var column = item.columnStart;
        column <= item.columnEnd;
        column += 1
      ) {
        execFunctionExist.add({'r': row, 'c': column, 'i': sheetId});
      }
    }
  }
  formulaCache['execFunctionExist'] = execFunctionExist.reversed.toList();
  formulaCache['execFunctionGlobalData'] = null;
  ctx['formulaCache'] = formulaCache;
  return ctx;
}

