Map<String, Object?>? getrangeseleciton({
  String? anchorText,
  int anchorOffset = 0,
  bool anchorParentIsSpan = false,
  String? anchorElementId,
  List<String> spans = const [],
  String? previousSiblingText,
}) {
  if (anchorParentIsSpan && anchorOffset != 0) {
    final text = (anchorText ?? '').trim();
    if (text.isEmpty && previousSiblingText != null) {
      return <String, Object?>{
        'source': 'previousSibling',
        'text': previousSiblingText.trim(),
      };
    }
    return <String, Object?>{'source': 'parentSpan', 'text': text};
  }
  if (anchorElementId == 'luckysheet-rich-text-editor' ||
      anchorElementId == 'luckysheet-functionbox-cell') {
    if (spans.isEmpty) {
      return null;
    }
    final last = spans.last.trim();
    if (last.isEmpty && spans.length > 1) {
      return <String, Object?>{
        'source': 'previousEditorSpan',
        'text': spans[spans.length - 2].trim(),
        'index': spans.length - 2,
      };
    }
    return <String, Object?>{
      'source': 'editorSpan',
      'text': last,
      'index': spans.length - 1,
    };
  }
  if (anchorOffset == 0 && previousSiblingText != null) {
    return <String, Object?>{
      'source': 'previousSibling',
      'text': previousSiblingText.trim(),
    };
  }
  return null;
}

Context rangeHightlightselected(
  Context ctx, {
  String? selectionText,
  String? functionName,
}) {
  final currentText = selectionText?.trim();
  if (currentText == null || currentText.isEmpty) {
    return ctx;
  }
  if (RegExp(r'^[a-zA-Z_]+$').hasMatch(currentText)) {
    ctx['functionSearchText'] = currentText.toUpperCase();
    ctx['functionHint'] = null;
  } else {
    ctx['functionHint'] = functionName?.toUpperCase();
    ctx['functionCandidates'] = <Object?>[];
  }
  return ctx;
}

Context handleFormulaInput(
  Context ctx, {
  FortuneSheet? sheet,
  required String editorText,
  int keyCode = 0,
  String? preText,
  String? copyToId,
  bool refreshRangeSelect = true,
  int? caretSpanIndex,
  int? caretOffset,
  List<int> rangeIndexes = const [],
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  final previousText = preText ?? editorText;
  final escapedValue = '${escapeScriptTag(editorText)}';
  final formulaMode =
      escapedValue.isNotEmpty &&
      escapedValue.startsWith('=') &&
      (keyCode != 229 || escapedValue.length == 1);
  if (formulaMode) {
    final html = functionHTMLGenerate(
      escapedValue,
      rangeIndexes: refreshRangeSelect ? const [] : rangeIndexes,
    );
    ctx['formulaInputHtml'] = html;
    if (copyToId != null) {
      ctx['formulaCopyTo'] = <String, Object?>{'id': copyToId, 'html': html};
    }
    final formulaCache = ctx['formulaCache'] is Map
        ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
        : <String, Object?>{};
    formulaCache['functionRangeIndex'] = [
      caretSpanIndex ?? _apiFormulaInputLastSpanIndex(html),
      caretOffset ?? _apiPlainTextFromHtml(escapedValue).length,
    ];
    if (refreshRangeSelect) {
      formulaCache['rangestart'] = false;
      formulaCache['rangedrag_column_start'] = false;
      formulaCache['rangedrag_row_start'] = false;
    }
    ctx['formulaCache'] = formulaCache;
    ctx['formulaInputRestoreCaret'] = true;
    if (refreshRangeSelect) {
      ctx.addAll(cancelFunctionrangeSelected());
      if (keyCode != 46 && sheet != null) {
        ctx['formulaRangeHighlight'] = createRangeHightlight(
          sheet,
          html,
          visibleDataRows: visibleDataRows,
          visibleDataColumns: visibleDataColumns,
        );
      }
    }
    return ctx;
  }

  if (previousText.startsWith('=') && !escapedValue.startsWith('=')) {
    final html = '${escapeHTMLTag(escapedValue)}';
    ctx['formulaInputHtml'] = html;
    if (copyToId != null) {
      ctx['formulaCopyTo'] = <String, Object?>{'id': copyToId, 'html': html};
    }
    return ctx;
  }

  if (!previousText.startsWith('=') && copyToId != null) {
    ctx['formulaCopyTo'] = <String, Object?>{
      'id': copyToId,
      'html': escapeHTMLTag(escapedValue),
    };
  }
  return ctx;
}

int _apiFormulaInputLastSpanIndex(String html) {
  final matches = RegExp(
    r'<span\b',
    caseSensitive: false,
  ).allMatches(html).length;
  return math.max(matches - 1, 0);
}

Map<String, Object?> rangeSetValue(
  FortuneWorkbook workbook,
  Context ctx,
  FortuneRange selected, {
  bool isRangeSelection = false,
  String? copyToId,
  int? rangeIndex,
}) {
  final sheetId = '${ctx['currentSheetId'] ?? workbook.activeSheet.id}';
  final formulaCache = ctx['formulaCache'] is Map
      ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
      : <String, Object?>{};
  final normalizedSelection = _apiRangeSetValueSelection(
    workbook,
    sheetId,
    selected,
  );
  final rangeText = getRangetxt(
    workbook,
    sheetId,
    normalizedSelection,
    currentSheetId:
        '${formulaCache['rangetosheet'] ?? workbook.activeSheet.id}',
  );
  final changingRange =
      formulaCache['rangestart'] == true ||
      formulaCache['rangedrag_column_start'] == true ||
      formulaCache['rangedrag_row_start'] == true;
  final nextRangeIndex =
      rangeIndex ?? _nullableIntArg(formulaCache['rangechangeindex']) ?? 0;
  final replaceExisting = !isRangeSelection && changingRange;
  final spanHtml =
      '<span class="fortune-formula-functionrange-cell" '
      'rangeindex="$nextRangeIndex" dir="auto" '
      'style="color:${colors[nextRangeIndex % colors.length]};">'
      '$rangeText</span>';

  formulaCache['rangechangeindex'] = nextRangeIndex;
  ctx['formulaCache'] = formulaCache;
  setCaretPosition(ctx, children: 0, pos: rangeText.length);
  final payload = <String, Object?>{
    'type': replaceExisting ? 'replaceRange' : 'insertRange',
    'range': rangeText,
    'rangeIndex': nextRangeIndex,
    'html': spanHtml,
    'caret': ctx['caretPosition'],
  };
  ctx['rangeSetValue'] = payload;
  if (copyToId != null) {
    ctx['formulaCopyTo'] = <String, Object?>{'id': copyToId, 'html': spanHtml};
  }
  return payload;
}

FortuneRange _apiRangeSetValueSelection(
  FortuneWorkbook workbook,
  String sheetId,
  FortuneRange selected,
) {
  final sheet = getSheetByIndex(workbook, id: sheetId);
  final cell =
      sheet?.cells[FortuneCellCoord(selected.rowStart, selected.columnStart)];
  final merge = cell?.merge;
  if (merge != null &&
      merge.row == selected.rowStart &&
      merge.column == selected.columnStart) {
    return FortuneRange(
      rowStart: selected.rowStart,
      rowEnd: selected.rowStart,
      columnStart: selected.columnStart,
      columnEnd: selected.columnStart,
      rowFocus: selected.rowFocus,
      columnFocus: selected.columnFocus,
    );
  }
  return selected;
}

String isFunctionRange(
  Context ctx,
  String text, {
  void Function(String rangeText)? cellRangeFunction,
}) {
  final formulaText = text.startsWith('=') ? text.substring(1) : text;
  final ranges = <String>[];
  final transformed = _apiFormulaReferenceTransform(
    formulaText,
    onRange: (rangeText) {
      ranges.add(rangeText);
      cellRangeFunction?.call(rangeText);
    },
  );
  ctx['functionRangeRefs'] = ranges;
  ctx['functionRangeExpression'] = transformed;
  return transformed;
}

List<Object?> execfunction(
  Context ctx,
  String text,
  int row,
  int column, {
  String? id,
  Object? result,
  Object? formulaError,
  bool isRefresh = false,
  bool notInsertFunc = false,
}) {
  if (text.contains(error['r']!)) {
    return [false, error['r'], text];
  }
  final sheetId = id ?? '${ctx['currentSheetId'] ?? ''}';
  ctx['calculateSheetId'] = sheetId;
  final expression = isFunctionRange(ctx, text);
  final value = formulaError ?? result ?? expression;
  if (!notInsertFunc) {
    final calcChainSet = ctx['calcChainSet'] is Set
        ? Set<Object?>.from(ctx['calcChainSet'] as Set)
        : <Object?>{};
    calcChainSet.add('${row}_${column}_$sheetId');
    ctx['calcChainSet'] = calcChainSet;
  }
  if (isRefresh) {
    execFunctionGroup(ctx, row, column, value, id: sheetId);
  }
  return [true, value, text];
}

Context execFunctionGroup(
  Context ctx,
  int? originRow,
  int? originColumn,
  Object? value, {
  String? id,
  bool isForce = false,
}) {
  final sheetId = id ?? '${ctx['currentSheetId'] ?? ''}';
  final formulaCache = ctx['formulaCache'] is Map
      ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
      : <String, Object?>{};
  final globalData = formulaCache['execFunctionGlobalData'] is Map
      ? Map<String, Object?>.from(formulaCache['execFunctionGlobalData'] as Map)
      : <String, Object?>{};
  if (value != null && originRow != null && originColumn != null) {
    globalData['${originRow}_${originColumn}_$sheetId'] = {'v': value};
  }

  final updateValueObjects = <String, int>{};
  final existing = formulaCache['execFunctionExist'];
  if (existing is Iterable) {
    for (final item in existing.whereType<Map>()) {
      final row = item['r'];
      final column = item['c'];
      final itemId = item['i'] ?? sheetId;
      updateValueObjects['r${row}c${column}i$itemId'] = 1;
    }
  } else if (originRow != null && originColumn != null) {
    updateValueObjects['r${originRow}c${originColumn}i$sheetId'] = 1;
  }

  formulaCache['execFunctionGlobalData'] = globalData;
  formulaCache['execFunctionUpdateValueObjects'] = updateValueObjects;
  formulaCache.remove('execFunctionExist');
  ctx['formulaCache'] = formulaCache;
  ctx['execFunctionGroup'] = <String, Object?>{
    'origin': originRow == null || originColumn == null
        ? null
        : {'r': originRow, 'c': originColumn, 'id': sheetId},
    'isForce': isForce,
    'updateValueObjects': updateValueObjects,
  };
  return ctx;
}

String _apiFormulaReferenceTransform(
  String text, {
  required void Function(String rangeText) onRange,
}) {
  final buffer = StringBuffer();
  final token = StringBuffer();
  var quote = '';
  var braces = 0;

  void flushToken() {
    final raw = token.toString();
    token.clear();
    final trimmed = raw.trim();
    if (trimmed.isNotEmpty && iscelldata(trimmed)) {
      onRange(trimmed);
      buffer.write("luckysheet_getcelldata('$trimmed')");
    } else if (trimmed.startsWith(':') && iscelldata(trimmed.substring(1))) {
      final rangeText = trimmed.substring(1);
      onRange(rangeText);
      buffer.write("luckysheet_getSpecialReference(false,'$rangeText')");
    } else if (RegExp(r'^\{.*\}$').hasMatch(trimmed)) {
      buffer.write("luckysheet_getarraydata('$trimmed')");
    } else {
      buffer.write(raw);
    }
  }

  for (var index = 0; index < text.length; index += 1) {
    final char = text[index];
    if ((char == '"' || char == "'") && braces == 0) {
      if (quote == char) {
        quote = '';
      } else if (quote.isEmpty) {
        quote = char;
      }
      token.write(char);
      continue;
    }
    if (quote.isNotEmpty) {
      token.write(char);
      continue;
    }
    if (char == '{') {
      braces += 1;
      token.write(char);
      continue;
    }
    if (char == '}') {
      braces = math.max(braces - 1, 0);
      token.write(char);
      continue;
    }
    if (braces == 0 && _apiFormulaTokenSeparators.contains(char)) {
      flushToken();
      buffer.write(char);
      continue;
    }
    token.write(char);
  }
  flushToken();
  return buffer.toString();
}

const Set<String> _apiFormulaTokenSeparators = {
  '(',
  ')',
  ',',
  '+',
  '-',
  '*',
  '/',
  '%',
  '^',
  '&',
  '=',
  '>',
  '<',
};

int? _apiContextSheetIndex(Context ctx) {
  final files = ctx['luckysheetfile'];
  if (files is! List) {
    return null;
  }
  final currentSheetId = ctx['currentSheetId'];
  for (var index = 0; index < files.length; index += 1) {
    final item = files[index];
    if (item is Map && item['id'] == currentSheetId) {
      return index;
    }
  }
  return null;
}

List<num> _apiContextAxis(int count, num length) {
  var current = 0.0;
  return [for (var index = 0; index < count; index += 1) current += length];
}

List<FortuneRange> _apiContextRanges(Object? value) {
  if (value is FortuneRange) {
    return [value];
  }
  if (value is Iterable<FortuneRange>) {
    return value.toList();
  }
  if (value is Iterable) {
    return [
      for (final item in value.whereType<Map>())
        ?_selectionRangeFromApiMap(item),
    ];
  }
  return const [];
}

FortuneRange _apiContextClampRange(
  FortuneRange range,
  int rowCount,
  int columnCount,
) {
  final maxRow = math.max(rowCount - 1, 0);
  final maxColumn = math.max(columnCount - 1, 0);
  return FortuneRange(
    rowStart: math.min(range.rowStart, maxRow),
    rowEnd: math.min(range.rowEnd, maxRow),
    columnStart: math.min(range.columnStart, maxColumn),
    columnEnd: math.min(range.columnEnd, maxColumn),
    rowFocus: range.rowFocus == null ? null : math.min(range.rowFocus!, maxRow),
    columnFocus: range.columnFocus == null
        ? null
        : math.min(range.columnFocus!, maxColumn),
    extraFields: range.extraFields,
  );
}

class FortuneApiError implements Exception {
  const FortuneApiError(this.message);

  final String message;

  @override
  String toString() => message;
}

// ignore: constant_identifier_names
const FortuneApiError INVALID_PARAMS = FortuneApiError('invalid params');

// ignore: constant_identifier_names
const FortuneApiError SHEET_NOT_FOUND = FortuneApiError('sheet not found');

const int _apiMaxRowCount = 10000;
const int _apiMaxColumnCount = 1000;

const double minZoomRatio = 0.1;
const double maxZoomRatio = 4;

const double zoomStep = 0.1;

// ignore: constant_identifier_names
const double MIN_ZOOM_RATIO = minZoomRatio;

// ignore: constant_identifier_names
const double MAX_ZOOM_RATIO = maxZoomRatio;

double handleKeydownForZoom(
  num currentZoom, {
  String? key,
  int? which,
  bool ctrlKey = false,
}) {
  if (!ctrlKey) {
    return currentZoom.toDouble();
  }
  var zoom = currentZoom == 0 ? 1.0 : currentZoom.toDouble();
  var handled = false;
  if (key == '-' || which == 189) {
    zoom -= zoomStep;
    handled = true;
  } else if (key == '+' || which == 187) {
    zoom += zoomStep;
    handled = true;
  } else if (key == '0' || which == 48) {
    zoom = 1;
    handled = true;
  }
  if (handled) {
    zoom = zoom.clamp(minZoomRatio, maxZoomRatio).toDouble();
  }
  return double.parse(zoom.toStringAsFixed(1));
}

Map<String, Object?>? handleWithCtrlOrMetaKey({
  String? key,
  String? code,
  int? keyCode,
  bool shiftKey = false,
  bool hasSelection = true,
  int selectionCount = 1,
  bool allowEdit = true,
  bool hasPartialMerge = false,
  bool paintModelOn = false,
}) {
  final eventCode = code ?? _apiKeyboardCodeFromKey(key, keyCode);
  final eventKey = key ?? _apiKeyboardKeyFromCode(eventCode, keyCode);
  final isArrow = const {
    'ArrowUp',
    'ArrowDown',
    'ArrowLeft',
    'ArrowRight',
  }.contains(eventKey);

  Map<String, Object?> action(
    String type, {
    bool preventDefault = true,
    bool stopPropagation = false,
    Map<String, Object?> extra = const {},
  }) {
    return {
      'type': type,
      'key': eventKey,
      'code': eventCode,
      'shiftKey': shiftKey,
      'preventDefault': preventDefault,
      'stopPropagation': stopPropagation,
      ...extra,
    };
  }

  if (shiftKey) {
    if (isArrow) {
      return action('controlShiftArrow', extra: {'direction': eventKey});
    }
    if (const {';', '"', ':', "'"}.contains(eventKey)) {
      return action('insertCurrentTime', extra: {'keyCode': keyCode});
    }
    if (eventCode == 'KeyZ') {
      return action('redo', stopPropagation: true);
    }
    return null;
  }

  if (isArrow) {
    return action('controlArrow', extra: {'direction': eventKey});
  }
  if (eventCode == 'KeyB') {
    return action('bold');
  }
  if (eventCode == 'KeyC') {
    return action('copy', stopPropagation: true);
  }
  if (eventCode == 'KeyF') {
    return action('showSearch');
  }
  if (eventCode == 'KeyH') {
    return action('showReplace');
  }
  if (eventCode == 'KeyV') {
    if (selectionCount > 1) {
      return action('pasteBlockedMultiSelection', preventDefault: false);
    }
    return action('paste', stopPropagation: true);
  }
  if (eventCode == 'KeyX') {
    if (!hasSelection) {
      return null;
    }
    if (hasPartialMerge) {
      return action('cutBlockedPartialMerge', preventDefault: false);
    }
    if (selectionCount > 1) {
      return action('cutBlockedMultiSelection', preventDefault: false);
    }
    return action(
      'cut',
      stopPropagation: true,
      extra: {'cancelPaintModel': paintModelOn},
    );
  }
  if (eventCode == 'KeyZ') {
    return action('undo', stopPropagation: true);
  }
  if (eventCode == 'KeyY') {
    return action('redo', stopPropagation: true);
  }
  if (eventCode == 'KeyA') {
    return action('selectAll');
  }
  if (eventCode == 'KeyD') {
    if (!hasSelection || !allowEdit) {
      return null;
    }
    return action('fillDown', stopPropagation: true);
  }
  if (eventCode == 'KeyR') {
    if (!hasSelection || !allowEdit) {
      return null;
    }
    return action('fillRight', stopPropagation: true);
  }
  return null;
}

Map<String, Object?>? handleArrowKey({
  required String key,
  int moveCount = 1,
  bool hasCellUpdate = false,
  bool cellSelectedMove = false,
  bool cellSelectedExtend = false,
}) {
  if (hasCellUpdate || cellSelectedMove || cellSelectedExtend) {
    return null;
  }
  if (key == 'ArrowUp') {
    return {
      'type': 'moveHighlightCell',
      'position': 'down',
      'index': -moveCount,
      'rangeType': 'rangeOfSelect',
    };
  }
  if (key == 'ArrowDown') {
    return {
      'type': 'moveHighlightCell',
      'position': 'down',
      'index': moveCount,
      'rangeType': 'rangeOfSelect',
    };
  }
  if (key == 'ArrowLeft') {
    return {
      'type': 'moveHighlightCell',
      'position': 'right',
      'index': -moveCount,
      'rangeType': 'rangeOfSelect',
    };
  }
  if (key == 'ArrowRight') {
    return {
      'type': 'moveHighlightCell',
      'position': 'right',
      'index': moveCount,
      'rangeType': 'rangeOfSelect',
    };
  }
  return null;
}

Map<String, Object?>? moveHighlightCell(
  Context ctx,
  String position,
  int index,
  String type, {
  FortuneSheet? sheet,
}) {
  final dataSize = _apiContextDataSize(ctx);
  if (dataSize == null) {
    return null;
  }
  if (type == 'rangeOfSelect') {
    final selections = ctx['luckysheet_select_save'];
    if (selections is! List || selections.isEmpty || selections.last is! Map) {
      return null;
    }
    final current = _selectionRangeFromApiMap(selections.last as Map);
    if (current == null) {
      return null;
    }
    final moved = _apiMoveHighlightCellRange(
      ctx,
      current,
      position,
      index,
      dataSize['rows']!,
      dataSize['columns']!,
      sheet: sheet,
    );
    final next = _selectionRangeToApiMap(moved.range);
    next['moveXY'] = {'x': moved.moveRow, 'y': moved.moveColumn};
    selections[selections.length - 1] = next;
    ctx['luckysheet_select_save'] = selections;
    ctx['moveHighlightCell'] = <String, Object?>{
      'type': type,
      'position': position,
      'index': index,
      'range': next,
      'scrollTo': {
        'row': moved.range.rowFocus,
        'column': moved.range.columnFocus,
      },
    };
    return ctx['moveHighlightCell'] as Map<String, Object?>;
  }
  if (type == 'rangeOfFormula') {
    final formulaCache = ctx['formulaCache'] is Map
        ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
        : <String, Object?>{};
    final rawRange = formulaCache['func_selectedrange'];
    if (rawRange is! Map) {
      return null;
    }
    final current = _selectionRangeFromApiMap(rawRange);
    if (current == null) {
      return null;
    }
    final moved = _apiMoveHighlightCellRange(
      ctx,
      current,
      position,
      index,
      dataSize['rows']!,
      dataSize['columns']!,
      sheet: sheet,
    );
    final geometry = _apiMoveHighlightGeometry(ctx, moved.range);
    final next = <String, Object?>{
      ..._selectionRangeToApiMap(moved.range),
      ...geometry,
      'left_move': geometry['left'],
      'width_move': geometry['width'],
      'top_move': geometry['top'],
      'height_move': geometry['height'],
      'moveXY': {'x': moved.moveRow, 'y': moved.moveColumn},
    };
    formulaCache['func_selectedrange'] = next;
    ctx['formulaCache'] = formulaCache;
    ctx['moveHighlightCell'] = <String, Object?>{
      'type': type,
      'position': position,
      'index': index,
      'range': next,
    };
    return ctx['moveHighlightCell'] as Map<String, Object?>;
  }
  return null;
}

Map<String, Object?>? moveHighlightRange(
  Context ctx,
  String position,
  int index,
  String type,
) {
  final dataSize = _apiContextDataSize(ctx);
  if (dataSize == null) {
    return null;
  }
  if (type == 'rangeOfSelect') {
    final selections = ctx['luckysheet_select_save'];
    if (selections is! List || selections.isEmpty || selections.last is! Map) {
      return null;
    }
    final range = _selectionRangeFromApiMap(selections.last as Map);
    if (range == null || range.rowFocus == null || range.columnFocus == null) {
      return null;
    }
    final nextRange = _apiMoveHighlightRangeCore(
      range,
      position,
      index,
      dataSize['rows']!,
      dataSize['columns']!,
    );
    final next = _selectionRangeToApiMap(nextRange);
    selections[selections.length - 1] = next;
    ctx['luckysheet_select_save'] = selections;
    ctx['moveHighlightRange'] = <String, Object?>{
      'type': type,
      'position': position,
      'index': index,
      'range': next,
      'scrollTo': _apiMoveHighlightScrollTarget(nextRange, position),
    };
    return ctx['moveHighlightRange'] as Map<String, Object?>;
  }
  if (type == 'rangeOfFormula') {
    final formulaCache = ctx['formulaCache'] is Map
        ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
        : <String, Object?>{};
    final rawRange = formulaCache['func_selectedrange'];
    if (rawRange is! Map) {
      return null;
    }
    final range = _selectionRangeFromApiMap(rawRange);
    if (range == null) {
      return null;
    }
    final nextRange = _apiMoveHighlightRangeCore(
      range,
      position,
      index,
      dataSize['rows']!,
      dataSize['columns']!,
    );
    final geometry = _apiMoveHighlightGeometry(ctx, nextRange);
    final next = <String, Object?>{
      ..._selectionRangeToApiMap(nextRange),
      ...geometry,
      'left_move': geometry['left'],
      'width_move': geometry['width'],
      'top_move': geometry['top'],
      'height_move': geometry['height'],
    };
    formulaCache['func_selectedrange'] = next;
    ctx['formulaCache'] = formulaCache;
    ctx['moveHighlightRange'] = <String, Object?>{
      'type': type,
      'position': position,
      'index': index,
      'range': next,
    };
    return ctx['moveHighlightRange'] as Map<String, Object?>;
  }
  return null;
}

({FortuneRange range, int moveRow, int moveColumn}) _apiMoveHighlightCellRange(
  Context ctx,
  FortuneRange current,
  String position,
  int index,
  int rowCount,
  int columnCount, {
  FortuneSheet? sheet,
}) {
  var currentRow = current.rowFocus ?? current.rowStart;
  var currentColumn = current.columnFocus ?? current.columnStart;
  final visibleRows = ctx['visibledatarow'] is List
      ? List<num>.from(ctx['visibledatarow'] as List)
      : _apiContextAxis(rowCount, 19);
  final visibleColumns = ctx['visibledatacolumn'] is List
      ? List<num>.from(ctx['visibledatacolumn'] as List)
      : _apiContextAxis(columnCount, 73);
  if (sheet != null) {
    final currentMerge = _apiMergeRangeContaining(
      sheet,
      currentRow,
      currentColumn,
    );
    if (currentMerge != null) {
      if (index > 0) {
        if (position == 'down') {
          currentRow = currentMerge.rowEnd;
          currentColumn = currentMerge.columnStart;
        } else if (position == 'right') {
          currentRow = currentMerge.rowStart;
          currentColumn = currentMerge.columnEnd;
        }
      } else {
        currentRow = currentMerge.rowStart;
        currentColumn = currentMerge.columnStart;
      }
    }
  }
  var moveRow =
      _apiMoveHighlightMoveIndex(current.extraFields['moveXY'], 'x') ??
      currentRow;
  var moveColumn =
      _apiMoveHighlightMoveIndex(current.extraFields['moveXY'], 'y') ??
      currentColumn;
  if (position == 'down') {
    currentRow += index;
    moveRow = currentRow;
  } else if (position == 'right') {
    currentColumn += index;
    moveColumn = currentColumn;
  }
  currentRow = currentRow.clamp(0, math.max(rowCount - 1, 0));
  currentColumn = currentColumn.clamp(0, math.max(columnCount - 1, 0));
  moveRow = moveRow.clamp(0, math.max(rowCount - 1, 0));
  moveColumn = moveColumn.clamp(0, math.max(columnCount - 1, 0));
  var range = FortuneRange(
    rowStart: currentRow,
    rowEnd: currentRow,
    columnStart: currentColumn,
    columnEnd: currentColumn,
    rowFocus: currentRow,
    columnFocus: currentColumn,
  );
  if (sheet != null) {
    final targetMerge = _apiMergeRangeContaining(
      sheet,
      currentRow,
      currentColumn,
    );
    if (targetMerge != null) {
      range = FortuneRange(
        rowStart: targetMerge.rowStart,
        rowEnd: targetMerge.rowEnd,
        columnStart: targetMerge.columnStart,
        columnEnd: targetMerge.columnEnd,
        rowFocus: targetMerge.rowStart,
        columnFocus: targetMerge.columnStart,
      );
      moveRow = targetMerge.rowStart.clamp(0, visibleRows.length - 1);
      moveColumn = targetMerge.columnStart.clamp(0, visibleColumns.length - 1);
    }
  }
  return (range: range, moveRow: moveRow, moveColumn: moveColumn);
}

int? _apiMoveHighlightMoveIndex(Object? value, String key) {
  if (value is Map) {
    final raw = value[key];
    if (raw is int) {
      return raw;
    }
    if (raw is num) {
      return raw.toInt();
    }
  }
  return null;
}

Map<String, int>? _apiContextDataSize(Context ctx) {
  final flowdata = ctx['flowdata'];
  if (flowdata is List && flowdata.isNotEmpty && flowdata.first is List) {
    return {
      'rows': flowdata.length,
      'columns': (flowdata.first as List).length,
    };
  }
  final rows = ctx['visibledatarow'];
  final columns = ctx['visibledatacolumn'];
  if (rows is List &&
      columns is List &&
      rows.isNotEmpty &&
      columns.isNotEmpty) {
    return {'rows': rows.length, 'columns': columns.length};
  }
  return null;
}

FortuneRange _apiMoveHighlightRangeCore(
  FortuneRange range,
  String position,
  int index,
  int rowCount,
  int columnCount,
) {
  var rowStart = range.rowStart;
  var rowEnd = range.rowEnd;
  var columnStart = range.columnStart;
  var columnEnd = range.columnEnd;
  final rowFocus = range.rowFocus;
  final columnFocus = range.columnFocus;
  if (position == 'down') {
    if (rowFocus != null && rowFocus > rowStart && rowFocus == rowEnd) {
      rowStart += index;
    } else if (rowFocus != null && rowFocus < rowEnd && rowFocus == rowStart) {
      rowEnd += index;
    } else if (index > 0) {
      rowEnd += index;
    } else {
      rowStart += index;
    }
  } else if (position == 'right') {
    if (columnFocus != null &&
        columnFocus > columnStart &&
        columnFocus == columnEnd) {
      columnStart += index;
    } else if (columnFocus != null &&
        columnFocus < columnEnd &&
        columnFocus == columnStart) {
      columnEnd += index;
    } else if (index > 0) {
      columnEnd += index;
    } else {
      columnStart += index;
    }
  }
  final clamped = _apiContextClampRange(
    FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
      rowFocus: range.rowFocus,
      columnFocus: range.columnFocus,
      extraFields: range.extraFields,
    ),
    rowCount,
    columnCount,
  );
  return FortuneRange(
    rowStart: math.min(clamped.rowStart, clamped.rowEnd),
    rowEnd: math.max(clamped.rowStart, clamped.rowEnd),
    columnStart: math.min(clamped.columnStart, clamped.columnEnd),
    columnEnd: math.max(clamped.columnStart, clamped.columnEnd),
    rowFocus: clamped.rowFocus,
    columnFocus: clamped.columnFocus,
    extraFields: clamped.extraFields,
  );
}

Map<String, Object?> _apiMoveHighlightScrollTarget(
  FortuneRange range,
  String position,
) {
  if (position == 'down') {
    return {
      'row': range.rowFocus == range.rowStart ? range.rowEnd : range.rowStart,
    };
  }
  return {
    'column': range.columnFocus == range.columnStart
        ? range.columnEnd
        : range.columnStart,
  };
}

Map<String, Object?> _apiMoveHighlightGeometry(
  Context ctx,
  FortuneRange range,
) {
  final visibleRows = ctx['visibledatarow'] is List
      ? List<num>.from(ctx['visibledatarow'] as List)
      : _apiContextAxis(range.rowEnd + 1, 19);
  final visibleColumns = ctx['visibledatacolumn'] is List
      ? List<num>.from(ctx['visibledatacolumn'] as List)
      : _apiContextAxis(range.columnEnd + 1, 73);
  final top = range.rowStart == 0 ? 0 : visibleRows[range.rowStart - 1];
  final left = range.columnStart == 0
      ? 0
      : visibleColumns[range.columnStart - 1];
  final bottom = visibleRows[range.rowEnd];
  final right = visibleColumns[range.columnEnd];
  return {
    'top': top,
    'height': bottom - top - 1,
    'left': left,
    'width': right - left - 1,
  };
}

