Map<String, Object?>? _apiRangeDragPayload(
  FortuneWorkbook workbook,
  Context ctx, {
  required num x,
  required num y,
  required String mode,
  String? copyToId,
}) {
  final formulaCache = ctx['formulaCache'] is Map
      ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
      : <String, Object?>{};
  final rawSelected = formulaCache['func_selectedrange'];
  if (rawSelected is! Map ||
      rawSelected['left'] == null ||
      rawSelected['top'] == null ||
      rawSelected['width'] == null ||
      rawSelected['height'] == null) {
    return null;
  }
  final selected = _selectionRangeFromApiMap(rawSelected);
  if (selected == null) {
    return null;
  }
  final visibleRows = ctx['visibledatarow'] is List
      ? List<num>.from(ctx['visibledatarow'] as List)
      : _apiContextAxis(selected.rowEnd + 1, 19);
  final visibleColumns = ctx['visibledatacolumn'] is List
      ? List<num>.from(ctx['visibledatacolumn'] as List)
      : _apiContextAxis(selected.columnEnd + 1, 73);
  if (visibleRows.isEmpty || visibleColumns.isEmpty) {
    return null;
  }
  final rowLocationResult = rowLocation(y, visibleRows);
  final columnLocationResult = colLocation(x, visibleColumns);
  final rowPre = mode == 'column' ? 0 : rowLocationResult[0];
  final row = mode == 'column' ? visibleRows.last : rowLocationResult[1];
  final rowIndex = mode == 'column'
      ? visibleRows.length - 1
      : rowLocationResult[2].toInt();
  final colPre = mode == 'row' ? 0 : columnLocationResult[0];
  final col = mode == 'row' ? visibleColumns.last : columnLocationResult[1];
  final colIndex = mode == 'row'
      ? visibleColumns.length - 1
      : columnLocationResult[2].toInt();

  final rangeTop = _nullableDoubleArg(rawSelected['top']) ?? 0;
  final rangeHeight = _nullableDoubleArg(rawSelected['height']) ?? 0;
  final rangeLeft = _nullableDoubleArg(rawSelected['left']) ?? 0;
  final rangeWidth = _nullableDoubleArg(rawSelected['width']) ?? 0;
  var top = rangeTop;
  var height = rangeHeight;
  var left = rangeLeft;
  var width = rangeWidth;
  var rowSelected = <Object?>[selected.rowStart, selected.rowEnd];
  var columnSelected = <Object?>[selected.columnStart, selected.columnEnd];

  if (mode != 'column') {
    if (rangeTop > rowPre) {
      top = rowPre.toDouble();
      height = rangeTop + rangeHeight - rowPre;
      rowSelected = [rowIndex, selected.rowEnd];
    } else if (rangeTop == rowPre) {
      top = rowPre.toDouble();
      height = rangeTop + rangeHeight - rowPre;
      rowSelected = [rowIndex, selected.rowStart];
    } else {
      top = rangeTop;
      height = row - rangeTop - 1;
      rowSelected = [selected.rowStart, rowIndex];
    }
  } else {
    rowSelected = <Object?>[0, rowIndex];
    top = rowPre.toDouble();
    height = row - rowPre - 1;
  }

  if (mode != 'row') {
    if (rangeLeft > colPre) {
      left = colPre.toDouble();
      width = rangeLeft + rangeWidth - colPre;
      columnSelected = [colIndex, selected.columnEnd];
    } else if (rangeLeft == colPre) {
      left = colPre.toDouble();
      width = rangeLeft + rangeWidth - colPre;
      columnSelected = [colIndex, selected.columnStart];
    } else {
      left = rangeLeft;
      width = col - rangeLeft - 1;
      columnSelected = [selected.columnStart, colIndex];
    }
  } else {
    columnSelected = <Object?>[0, colIndex];
    left = colPre.toDouble();
    width = col - colPre - 1;
  }

  final selectedApi = <String, Object?>{
    'row': mode == 'column' ? <Object?>[null, null] : rowSelected,
    'column': mode == 'row' ? <Object?>[null, null] : columnSelected,
  };
  final sheetId = '${ctx['currentSheetId'] ?? workbook.activeSheet.id}';
  final rangeText = getRangetxt(
    workbook,
    sheetId,
    selectedApi,
    currentSheetId:
        '${formulaCache['rangetosheet'] ?? workbook.activeSheet.id}',
  );
  final nextSelected = <String, Object?>{
    ...Map<String, Object?>.from(rawSelected),
    'row': rowSelected,
    'column': columnSelected,
    'left_move': left,
    'width_move': width,
    'top_move': top,
    'height_move': height,
  };
  formulaCache['func_selectedrange'] = nextSelected;
  ctx['formulaCache'] = formulaCache;
  final payload = <String, Object?>{
    'type': mode,
    'range': selectedApi,
    'rangeText': rangeText,
    'formulaRangeSelect': {
      'left': left,
      'top': top,
      'width': width,
      'height': height,
    },
  };
  ctx['rangeDrag'] = payload;
  if (copyToId != null) {
    ctx['formulaCopyTo'] = <String, Object?>{'id': copyToId, 'text': rangeText};
  }
  return payload;
}

Map<String, Object?>? handleGlobalEnter({
  bool altKey = false,
  bool metaKey = false,
  List<int> cellUpdate = const [],
  FortuneSelection? lastSelection,
}) {
  final hasCellUpdate = cellUpdate.length >= 2;
  Map<String, Object?> action(
    String type, {
    Map<String, Object?> extra = const {},
  }) {
    return {'type': type, 'preventDefault': true, ...extra};
  }

  if ((altKey || metaKey) && hasCellUpdate) {
    return action(
      'insertLineBreakInCell',
      extra: {'row': cellUpdate[0], 'column': cellUpdate[1]},
    );
  }
  if (hasCellUpdate) {
    final row = cellUpdate[0];
    final column = cellUpdate[1];
    return action(
      'commitCellAndMoveDown',
      extra: {
        'cellUpdate': [row, column],
        'selection': {
          'row': [row, row],
          'column': [column, column],
          'row_focus': row,
          'column_focus': column,
        },
        'move': {
          'type': 'moveHighlightCell',
          'position': 'down',
          'index': 1,
          'rangeType': 'rangeOfSelect',
        },
      },
    );
  }
  if (lastSelection == null) {
    return null;
  }
  return action(
    'startEditCell',
    extra: {
      'cellUpdate': [lastSelection.row, lastSelection.column],
    },
  );
}

Map<String, Object?>? handleGlobalKeyDown({
  required String key,
  int? keyCode,
  String? code,
  bool ctrlKey = false,
  bool metaKey = false,
  bool altKey = false,
  bool shiftKey = false,
  bool allowEdit = true,
  bool sheetFocused = true,
  bool hasContextMenu = false,
  bool filterContextMenu = false,
  bool hasSelectionRange = false,
  bool hasCellUpdate = false,
  List<int> cellUpdate = const [],
  FortuneSelection? lastSelection,
  int selectionCount = 1,
  bool hasSelection = true,
  bool activeImage = false,
  bool hasPartialMerge = false,
  bool paintModelOn = false,
  int moveCount = 1,
}) {
  Map<String, Object?> action(
    String type, {
    bool preventDefault = false,
    Map<String, Object?> extra = const {},
  }) {
    return {
      'type': type,
      'key': key,
      'keyCode': keyCode,
      'code': code,
      'resetSelectStatus': true,
      'preventDefault': preventDefault,
      ...extra,
    };
  }

  if (hasContextMenu || filterContextMenu) {
    return null;
  }
  if (key == 'Escape' && hasSelectionRange) {
    return action('clearSelectionRange');
  }
  final editingWithBlockedKey =
      hasCellUpdate &&
      !const {
        'Enter',
        'Tab',
        'ArrowUp',
        'ArrowDown',
        'ArrowLeft',
        'ArrowRight',
        'F4',
        'Escape',
      }.contains(key);
  if (editingWithBlockedKey) {
    return null;
  }
  if (ctrlKey && shiftKey && key == 'F') {
    return action(
      'toggleSheetFocus',
      preventDefault: true,
      extra: {'sheetFocused': !sheetFocused},
    );
  }
  if (!sheetFocused) {
    return null;
  }
  if (key == 'Enter') {
    if (!allowEdit) {
      return null;
    }
    final enter = handleGlobalEnter(
      altKey: altKey,
      metaKey: metaKey,
      cellUpdate: cellUpdate,
      lastSelection: lastSelection,
    );
    return enter == null
        ? null
        : action('globalEnter', preventDefault: true, extra: {'enter': enter});
  }
  if (key == 'Tab') {
    if (hasCellUpdate) {
      return null;
    }
    return action(
      'tabMove',
      preventDefault: true,
      extra: {
        'move': {
          'type': 'moveHighlightCell',
          'position': 'right',
          'index': shiftKey ? -1 : 1,
          'rangeType': 'rangeOfSelect',
        },
      },
    );
  }
  if (key == 'F2') {
    if (!allowEdit || hasCellUpdate || lastSelection == null) {
      return null;
    }
    return action(
      'startEditCell',
      preventDefault: true,
      extra: {
        'cellUpdate': [lastSelection.row, lastSelection.column],
      },
    );
  }
  if (key == 'F4' && hasCellUpdate) {
    return action('formulaReferenceToggle', preventDefault: true);
  }
  if (key == 'Escape' && hasCellUpdate) {
    return action(
      'cancelEditAndMoveCurrent',
      preventDefault: true,
      extra: {
        'move': {
          'type': 'moveHighlightCell',
          'position': 'down',
          'index': 0,
          'rangeType': 'rangeOfSelect',
        },
      },
    );
  }
  if (ctrlKey || metaKey) {
    final handled = handleWithCtrlOrMetaKey(
      key: key,
      code: code,
      keyCode: keyCode,
      shiftKey: shiftKey,
      hasSelection: hasSelection,
      selectionCount: selectionCount,
      allowEdit: allowEdit,
      hasPartialMerge: hasPartialMerge,
      paintModelOn: paintModelOn,
    );
    return handled == null
        ? null
        : action(
            'ctrlMeta',
            preventDefault: handled['preventDefault'] == true,
            extra: {'intent': handled},
          );
  }
  if (shiftKey &&
      const {'ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'}.contains(key)) {
    return action(
      'shiftArrow',
      preventDefault: true,
      extra: {'direction': key},
    );
  }
  if (key == 'Escape') {
    return action('clearContextMenu');
  }
  if (key.toLowerCase() == 'delete' || key.toLowerCase() == 'backspace') {
    if (!allowEdit) {
      return null;
    }
    return action(
      activeImage ? 'removeActiveImage' : 'deleteSelectedCellText',
      preventDefault: true,
    );
  }
  if (const {'ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'}.contains(key)) {
    final arrow = handleArrowKey(
      key: key,
      moveCount: moveCount,
      hasCellUpdate: hasCellUpdate,
    );
    return arrow == null ? null : action('arrow', extra: {'move': arrow});
  }
  if (_apiIsEditableInputKey(key, keyCode) && allowEdit && hasSelection) {
    return action(
      'startEditWithInput',
      preventDefault: true,
      extra: {'input': key},
    );
  }
  return null;
}

Map<String, Object?>? handleGlobalWheel({
  num deltaX = 0,
  num deltaY = 0,
  num scrollLeft = 0,
  num scrollTop = 0,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num zoomRatio = 1,
  bool searchDialogMouseEnter = false,
  bool showSearch = false,
  bool showReplace = false,
  bool filterContextMenu = false,
  bool verticalScrollLock = false,
  bool horizontalScrollLock = false,
  List<num>? visibleRowsUnique,
  List<num>? visibleColumnsUnique,
}) {
  if (searchDialogMouseEnter && showSearch && showReplace) {
    return null;
  }
  if (filterContextMenu) {
    return null;
  }
  final rows = _apiUniqueNums(visibleRowsUnique ?? visibleDataRows);
  final columns = _apiUniqueNums(visibleColumnsUnique ?? visibleDataColumns);
  final rowStart = _apiSortedIndex(rows, scrollTop) + 1;
  if (deltaY != 0 && !verticalScrollLock) {
    var step = (1 / zoomRatio).round();
    if (step < 1) {
      step = 1;
    }
    var rowEnd = deltaY > 0 ? rowStart + step : rowStart - step;
    if (rowEnd >= rows.length) {
      rowEnd = rows.length - 1;
    }
    if (rowEnd < 0) {
      rowEnd = 0;
    }
    return {
      'type': 'verticalScroll',
      'scrollTop': rowEnd == 0 || rows.isEmpty ? 0 : rows[rowEnd - 1],
      'horizontalScrollLock': true,
      'verticalScrollLock': verticalScrollLock,
      'visibleRowsUnique': rows,
      'visibleColumnsUnique': columns,
      'preventDefault': true,
      'cacheClearDelayMs': 500,
      'scrollLockDelayMs': 50,
    };
  }
  if (deltaX != 0 && !horizontalScrollLock) {
    return {
      'type': 'horizontalScroll',
      'scrollLeft':
          scrollLeft + (deltaX > 0 ? 20 * zoomRatio : -20 * zoomRatio),
      'verticalScrollLock': true,
      'horizontalScrollLock': horizontalScrollLock,
      'visibleRowsUnique': rows,
      'visibleColumnsUnique': columns,
      'preventDefault': true,
      'cacheClearDelayMs': 500,
      'scrollLockDelayMs': 50,
    };
  }
  return {
    'type': 'wheelNoop',
    'visibleRowsUnique': rows,
    'visibleColumnsUnique': columns,
    'preventDefault': true,
  };
}

Map<String, Object?>? handleCopy({
  List<FortuneRange> selections = const [],
  bool paintModelOn = false,
  bool hasPartialMerge = false,
  bool hasConditionFormatOverlap = false,
  bool hasOverlap = false,
}) {
  if (selections.isEmpty) {
    return null;
  }
  Map<String, Object?> blocked(String reason) {
    return {'type': 'copyBlocked', 'reason': reason, 'pasteIsCut': false};
  }

  if (hasPartialMerge) {
    return blocked('partialMerge');
  }
  if (selections.length > 1 && hasConditionFormatOverlap) {
    return blocked('conditionFormatMultiSelection');
  }
  if (selections.length > 1) {
    final first = _normalizedApiRange(selections.first) ?? selections.first;
    var isSameRow = true;
    var isSameColumn = true;
    for (final selection in selections.skip(1)) {
      final current = _normalizedApiRange(selection) ?? selection;
      if (current.rowStart != first.rowStart ||
          current.rowEnd != first.rowEnd) {
        isSameRow = false;
      }
      if (current.columnStart != first.columnStart ||
          current.columnEnd != first.columnEnd) {
        isSameColumn = false;
      }
    }
    if ((!isSameRow && !isSameColumn) || hasOverlap) {
      return blocked('invalidMultiSelection');
    }
  }
  return {
    'type': 'copy',
    'cancelPaintModel': paintModelOn,
    'pasteIsCut': false,
    'selectionCount': selections.length,
    'selections': [
      for (final selection in selections) _selectionRangeToApiMap(selection),
    ],
  };
}

Map<String, Object?>? copy(Context ctx, {FortuneSheet? sheet}) {
  final rawSelections = ctx['luckysheet_select_save'];
  if (rawSelections is! List || rawSelections.isEmpty) {
    return null;
  }
  final ranges = <FortuneRange>[];
  final rangeMaps = <Map<String, Object?>>[];
  for (final rawSelection in rawSelections) {
    if (rawSelection is! Map) {
      continue;
    }
    final range = _selectionRangeFromApiMap(rawSelection);
    if (range == null) {
      continue;
    }
    ranges.add(range);
    rangeMaps.add(_selectionRangeToApiMap(range));
  }
  if (ranges.isEmpty) {
    return null;
  }
  var rowLengthChanged = false;
  var hasMergedCell = false;
  if (sheet != null) {
    for (final range in ranges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        if (sheet.hiddenRows.contains(row)) {
          continue;
        }
        if (sheet.rowHeights.containsKey(row)) {
          rowLengthChanged = true;
        }
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          if (sheet.hiddenColumns.contains(column)) {
            continue;
          }
          final merge = sheet.cells[FortuneCellCoord(row, column)]?.merge;
          if (merge != null && merge.rowSpan > 0) {
            hasMergedCell = true;
          }
        }
      }
    }
  }
  final dataSheetId = '${ctx['currentSheetId'] ?? sheet?.id ?? ''}';
  final copySave = <String, Object?>{
    'dataSheetId': dataSheetId,
    'copyRange': rangeMaps,
    'RowlChange': rowLengthChanged,
    'HasMC': hasMergedCell,
  };
  ctx['luckysheet_selection_range'] = rangeMaps;
  ctx['luckysheet_copy_save'] = copySave;
  ctx['luckysheet_paste_iscut'] = false;
  final html = sheet == null ? null : rangeValueToHtml(sheet, ranges);
  if (html != null && html.isNotEmpty) {
    ctx['iscopyself'] = true;
    ctx['copyHtml'] = html;
  }
  return {
    'type': 'copy',
    'pasteIsCut': false,
    'luckysheetSelectionRange': rangeMaps,
    'luckysheetCopySave': copySave,
    if (html != null && html.isNotEmpty) 'copyHtml': html,
  };
}

Map<String, Object?> handleOverlayTouchStart({
  required num pageX,
  required num pageY,
}) {
  return {
    'touchMoveStatus': true,
    'touchMoveStartPos': {'x': pageX, 'y': pageY, 'vy': 0, 'moveType': 'y'},
  };
}

Map<String, Object?>? handleOverlayTouchMove(
  Map<String, Object?>? touchMoveStartPos, {
  required num pageX,
  required num pageY,
  required num scrollLeft,
  required num scrollTop,
  bool touchMoveStatus = true,
  int touchCount = 1,
}) {
  if (!touchMoveStatus || touchCount > 1 || touchMoveStartPos == null) {
    return null;
  }
  final startX = _nullableDoubleArg(touchMoveStartPos['x']);
  final startY = _nullableDoubleArg(touchMoveStartPos['y']);
  if (startX == null || startY == null) {
    return null;
  }
  final slideX = pageX - startX;
  final slideY = pageY - startY;
  final nextScrollLeft = scrollLeft - slideX;
  final nextScrollTop = scrollTop - slideY;
  return {
    'scrollLeft': nextScrollLeft,
    'scrollTop': nextScrollTop,
    'scrollbarX': {'scrollLeft': nextScrollLeft},
    'scrollbarY': {'scrollTop': nextScrollTop},
    'touchMoveStartPos': {
      ...touchMoveStartPos,
      'vy_y': slideY,
      'scrollTop': nextScrollTop,
      'vy_x': slideX,
      'scrollLeft': nextScrollLeft,
    },
  };
}

Map<String, Object?> handleOverlayTouchEnd() {
  return const {'touchMoveStatus': false, 'touchHandleStatus': false};
}

Map<String, Object?>? handleOverlayMouseMove({
  required num pageX,
  required num pageY,
  bool allowEdit = true,
  Map<String, Object?>? commentBox,
  Map<String, Object?>? globalCacheImage,
  Map<String, Object?>? globalCacheChart,
  Map<String, Object?>? searchDialogMoveProps,
  Map<String, Object?>? rangeSelectionModalMoveProps,
  FortuneSheet? sheet,
  FortuneRange? selection,
  List<int>? moveIndex,
  bool isCellsMoving = false,
  num? dragStartX,
  num? dragStartY,
  num containerLeft = 0,
  num containerTop = 0,
  num containerWidth = 0,
  num containerHeight = 0,
  num windowWidth = 0,
  num windowHeight = 0,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
  num zoomRatio = 1,
  Iterable<Map<String, Object?>> commentBoxes = const [],
  Map<String, Object?>? editingCommentBox,
  bool scrollStatus = false,
  bool selectStatus = false,
  bool rowsSelectedStatus = false,
  bool colsSelectedStatus = false,
  bool cellSelectedExtend = false,
  bool colsChangeSize = false,
  bool rowsChangeSize = false,
}) {
  final commentResize = onCommentBoxResize(
    commentBox,
    pageX: pageX,
    pageY: pageY,
    zoomRatio: zoomRatio,
    allowEdit: allowEdit,
  );
  if (commentResize != null) {
    return {'type': 'commentBoxResize', 'payload': commentResize};
  }
  final commentMove = onCommentBoxMove(
    commentBox,
    pageX: pageX,
    pageY: pageY,
    allowEdit: allowEdit,
  );
  if (commentMove != null) {
    return {'type': 'commentBoxMove', 'payload': commentMove};
  }
  final imageMove = onImageMove(
    globalCacheImage,
    pageX: pageX,
    pageY: pageY,
    allowEdit: allowEdit,
  );
  if (imageMove != null) {
    return {'type': 'imageMove', 'payload': imageMove};
  }
  final imageResize = onImageResize(
    globalCacheImage,
    pageX: pageX,
    pageY: pageY,
    zoomRatio: zoomRatio,
    allowEdit: allowEdit,
  );
  if (imageResize != null) {
    return {'type': 'imageResize', 'payload': imageResize};
  }
  final imageCropChange = onImageCropChange(
    globalCacheImage,
    pageX: pageX,
    pageY: pageY,
    allowEdit: allowEdit,
  );
  if (imageCropChange != null) {
    return {'type': 'imageCropChange', 'payload': imageCropChange};
  }
  final chartMove = onChartMove(
    globalCacheChart,
    pageX: pageX,
    pageY: pageY,
    windowWidth: windowWidth,
    windowHeight: windowHeight,
    allowEdit: allowEdit,
  );
  if (chartMove != null) {
    return {'type': 'chartMove', 'payload': chartMove};
  }
  final chartResize = onChartResize(
    globalCacheChart,
    pageX: pageX,
    pageY: pageY,
    windowWidth: windowWidth,
    windowHeight: windowHeight,
    allowEdit: allowEdit,
  );
  if (chartResize != null) {
    return {'type': 'chartResize', 'payload': chartResize};
  }
  if (selection != null && moveIndex != null) {
    final cellsMove = onCellsMove(
      pageX: pageX,
      pageY: pageY,
      containerLeft: containerLeft,
      containerTop: containerTop,
      containerWidth: containerWidth,
      containerHeight: containerHeight,
      visibleDataRows: visibleDataRows,
      visibleDataColumns: visibleDataColumns,
      selection: selection,
      moveIndex: moveIndex,
      isMoving: isCellsMoving,
      dragStartX: dragStartX,
      dragStartY: dragStartY,
      scrollLeft: scrollLeft,
      scrollTop: scrollTop,
      rowHeaderWidth: rowHeaderWidth,
      columnHeaderHeight: columnHeaderHeight,
      zoomRatio: zoomRatio,
    );
    if (cellsMove != null) {
      return {'type': 'cellsMove', 'payload': cellsMove};
    }
  }
  if (sheet != null &&
      visibleDataRows.isNotEmpty &&
      visibleDataColumns.isNotEmpty) {
    final commentHover = overShowComment(
      sheet,
      pageX: pageX,
      pageY: pageY,
      containerLeft: containerLeft,
      containerTop: containerTop,
      scrollLeft: scrollLeft,
      scrollTop: scrollTop,
      rowHeaderWidth: rowHeaderWidth,
      columnHeaderHeight: columnHeaderHeight,
      visibleDataRows: visibleDataRows,
      visibleDataColumns: visibleDataColumns,
      commentBoxes: commentBoxes,
      editingCommentBox: editingCommentBox,
      zoomRatio: zoomRatio,
    );
    if (commentHover != null) {
      return {'type': 'commentHover', 'payload': commentHover};
    }
  }
  final searchMove = onSearchDialogMove(
    searchDialogMoveProps,
    pageX: pageX,
    pageY: pageY,
  );
  if (searchMove != null) {
    return {'type': 'searchDialogMove', 'payload': searchMove};
  }
  final rangeModalMove = onRangeSelectionModalMove(
    rangeSelectionModalMoveProps,
    pageX: pageX,
    pageY: pageY,
  );
  if (rangeModalMove != null) {
    return {'type': 'rangeSelectionModalMove', 'payload': rangeModalMove};
  }
  final shouldRender =
      scrollStatus ||
      selectStatus ||
      rowsSelectedStatus ||
      colsSelectedStatus ||
      isCellsMoving ||
      cellSelectedExtend ||
      colsChangeSize ||
      rowsChangeSize;
  if (shouldRender) {
    return {
      'type': 'mouseRender',
      'scrollStatus': scrollStatus,
      'selectStatus': selectStatus,
      'rowsSelectedStatus': rowsSelectedStatus,
      'colsSelectedStatus': colsSelectedStatus,
      'cellSelectedMove': isCellsMoving,
      'cellSelectedExtend': cellSelectedExtend,
      'colsChangeSize': colsChangeSize,
      'rowsChangeSize': rowsChangeSize,
    };
  }
  return null;
}

Map<String, Object?> handleOverlayMouseUp({
  FortuneSheet? sheet,
  String? activeImg,
  Map<String, num>? imagePosition,
  Map<String, num>? imageCropPosition,
  Map<String, Object?>? globalCacheImage,
  String? activeChart,
  Map<String, num>? chartPosition,
  Map<String, Object?>? globalCacheChart,
  Map<String, Object?>? commentBox,
  Map<String, num>? commentPosition,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
  num zoomRatio = 1,
  Map<String, Object?>? funcSelectedRange,
  bool rangeStart = false,
  bool rangeDragColumnStart = false,
  bool rangeDragRowStart = false,
  int rangeIndex = 0,
  FortuneRange? selection,
  FortuneRange? target,
  bool isCellsMoving = false,
  bool dragStarted = false,
  bool allowEdit = true,
  bool hasPartMerge = false,
  bool hasTargetPartMerge = false,
  int? maxRowIndex,
  int? maxColumnIndex,
  bool selectStatus = false,
  bool paintModelOn = false,
  bool paintSingle = false,
  String? copySheetId,
  String? currentSheetId,
}) {
  var nextSheet = sheet;
  final payload = <String, Object?>{
    'type': 'overlayMouseUp',
    'searchDialog': onSearchDialogMoveEnd()['searchDialog'],
    'linkCard': onRangeSelectionModalMoveEnd()['linkCard'],
    'luckysheetSelectStatus': false,
    'luckysheetScrollStatus': false,
    'luckysheetRowsSelectedStatus': false,
    'luckysheetColsSelectedStatus': false,
    'luckysheetModelMoveState': false,
  };
  if (nextSheet != null) {
    final afterImageMove = onImageMoveEnd(
      nextSheet,
      activeImg: activeImg,
      position: imagePosition,
      zoomRatio: zoomRatio,
      globalCacheImage: globalCacheImage,
    );
    final afterImageResize = onImageResizeEnd(
      afterImageMove,
      activeImg: activeImg,
      position: imagePosition,
      zoomRatio: zoomRatio,
      globalCacheImage: globalCacheImage,
    );
    nextSheet = onImageCropChangeEnd(
      afterImageResize,
      activeImg: activeImg,
      position: imageCropPosition,
      globalCacheImage: globalCacheImage,
    );
    final afterChartMove = onChartMoveEnd(
      nextSheet,
      activeChart: activeChart,
      position: chartPosition,
    );
    nextSheet = onChartResizeEnd(
      afterChartMove,
      activeChart: activeChart,
      position: chartPosition,
      globalCacheChart: globalCacheChart,
    );
    if (commentBox != null && visibleDataRows.isNotEmpty) {
      final commentEnd = commentBox['resizingId'] == null
          ? onCommentBoxMoveEnd(
              nextSheet,
              commentBox: commentBox,
              position: commentPosition,
              visibleDataRows: visibleDataRows,
              visibleDataColumns: visibleDataColumns,
              zoomRatio: zoomRatio,
            )
          : onCommentBoxResizeEnd(
              nextSheet,
              commentBox: commentBox,
              position: commentPosition,
              visibleDataRows: visibleDataRows,
              visibleDataColumns: visibleDataColumns,
              zoomRatio: zoomRatio,
            );
      nextSheet = commentEnd['sheet'] as FortuneSheet? ?? nextSheet;
      payload['editingCommentBox'] = commentEnd['editingCommentBox'];
    }
    if (selection != null && target != null) {
      final moveEnd = onCellsMoveEnd(
        nextSheet,
        selection: selection,
        target: target,
        isMoving: isCellsMoving,
        dragStarted: dragStarted,
        allowEdit: allowEdit,
        hasPartMerge: hasPartMerge,
        hasTargetPartMerge: hasTargetPartMerge,
        maxRowIndex: maxRowIndex,
        maxColumnIndex: maxColumnIndex,
      );
      if (moveEnd != null) {
        payload['cellsMoveEnd'] = moveEnd;
        nextSheet = moveEnd['sheet'] as FortuneSheet? ?? nextSheet;
      }
    }
    payload['sheet'] = nextSheet;
  }
  payload['formulaRangeDragEnd'] = onFormulaRangeDragEnd(
    funcSelectedRange: funcSelectedRange,
    rangeStart: rangeStart,
    rangeDragColumnStart: rangeDragColumnStart,
    rangeDragRowStart: rangeDragRowStart,
    rangeIndex: rangeIndex,
  );
  if (selectStatus && paintModelOn) {
    payload['formatPainterPaste'] = true;
    if (paintSingle) {
      payload['cancelPaintModel'] = cancelPaintModel(
        copySheetId: copySheetId,
        currentSheetId: currentSheetId,
      );
    }
  }
  return payload;
}

Map<String, Object?>? handlePaste({
  Context? ctx,
  String? htmlData,
  String? plainTextData,
  bool allowEdit = true,
  bool isPasteAction = true,
  bool beforePasteAllowed = true,
  BeforePasteHook? beforePaste,
  bool hasCopyRange = false,
  bool clipboardMatchesCopyRange = true,
  bool isCut = false,
}) {
  if (!allowEdit) {
    return null;
  }
  if (!isPasteAction) {
    return null;
  }
  final textData = (htmlData?.isNotEmpty ?? false) ? htmlData! : plainTextData;
  if (textData == null || textData.isEmpty) {
    return null;
  }
  if (!beforePasteAllowed) {
    return {'type': 'pasteBlockedBeforeHook', 'text': textData};
  }
  if (beforePaste?.call(_apiPasteSelection(ctx), textData) == false) {
    return {'type': 'pasteBlockedBeforeHook', 'text': textData};
  }
  final hasFortuneTable = textData.contains('fortune-copy-action-table');
  final effectiveHasCopyRange =
      hasCopyRange || _apiCopySaveHasRanges(ctx?['luckysheet_copy_save']);
  final effectiveIsCut = isCut || ctx?['luckysheet_paste_iscut'] == true;
  if (hasFortuneTable && effectiveHasCopyRange && clipboardMatchesCopyRange) {
    if (effectiveIsCut && ctx != null) {
      ctx['luckysheet_paste_iscut'] = false;
      ctx['luckysheet_selection_range'] = <Object?>[];
    }
    return {
      'type': effectiveIsCut ? 'cutPaste' : 'copyPaste',
      'text': textData,
      'resetCellUpdate': true,
      'resetPasteAction': true,
      if (effectiveIsCut) 'resetCut': true,
      if (effectiveIsCut) 'clearSelectionRange': true,
    };
  }
  if (textData.contains('fortune-copy-action-image')) {
    return {
      'type': 'imagePaste',
      'text': textData,
      'resetCellUpdate': true,
      'resetPasteAction': true,
    };
  }
  return {
    'type': textData.contains('table') ? 'htmlTablePaste' : 'plainTextPaste',
    'text': textData,
    'resetCellUpdate': true,
    'resetPasteAction': true,
  };
}

Map<String, Object?>? handlePasteByClick({
  Context? ctx,
  required String clipboardData,
  String? textareaData,
  String? triggerType,
  bool allowEdit = true,
  bool beforePasteAllowed = true,
  BeforePasteHook? beforePaste,
  bool hasCopyRange = false,
  bool isCut = false,
}) {
  if (!allowEdit) {
    return null;
  }
  final data = (textareaData?.isNotEmpty ?? false)
      ? textareaData!
      : clipboardData;
  if (data.isEmpty) {
    return null;
  }
  if (!beforePasteAllowed) {
    return {'type': 'pasteBlockedBeforeHook', 'text': data};
  }
  if (beforePaste?.call(_apiPasteSelection(ctx), data) == false) {
    return {'type': 'pasteBlockedBeforeHook', 'text': data};
  }
  final effectiveHasCopyRange =
      hasCopyRange || _apiCopySaveHasRanges(ctx?['luckysheet_copy_save']);
  final effectiveIsCut = isCut || ctx?['luckysheet_paste_iscut'] == true;
  if (data.contains('fortune-copy-action-table') && effectiveHasCopyRange) {
    if (effectiveIsCut && ctx != null) {
      ctx['luckysheet_paste_iscut'] = false;
    }
    return {
      'type': effectiveIsCut ? 'cutPaste' : 'copyPaste',
      'text': data,
      if (clipboardData.isNotEmpty) 'writeHtml': clipboardData,
      if (effectiveIsCut) 'resetCut': true,
    };
  }
  if (data.contains('fortune-copy-action-image')) {
    return {
      'type': 'imagePaste',
      'text': data,
      if (clipboardData.isNotEmpty) 'writeHtml': clipboardData,
    };
  }
  if (triggerType == 'btn') {
    return {
      'type': 'pasteBlockedButtonTrigger',
      'text': data,
      if (clipboardData.isNotEmpty) 'writeHtml': clipboardData,
    };
  }
  return {
    'type': clipboardData.startsWith('=')
        ? 'formulaStringPaste'
        : clipboardData.contains('table')
        ? 'htmlTablePaste'
        : 'plainTextPaste',
    'text': data,
    if (clipboardData.isNotEmpty) 'writeHtml': clipboardData,
  };
}

List<FortuneRange>? _apiPasteSelection(Context? ctx) {
  if (ctx == null) {
    return null;
  }
  return _selectionRangesFrom(ctx['luckysheet_select_save']).toList();
}

bool _apiCopySaveHasRanges(Object? copySave) {
  if (copySave is! Map) {
    return false;
  }
  final copyRange = copySave['copyRange'];
  return copyRange is List && copyRange.isNotEmpty;
}

Map<String, Object?>? pasteHandler({
  required int dataRowCount,
  required int dataColumnCount,
  required FortuneRange? selection,
  int selectionCount = 1,
  int rowMaxLength = 0,
  int columnMaxLength = 0,
  bool allowEdit = true,
  bool hasPartialMerge = false,
  bool hasBorderInfo = false,
}) {
  if (!allowEdit) {
    return null;
  }
  if (selectionCount != 1 || selection == null) {
    return {
      'type': 'pasteBlockedMultiSelection',
      'selectionCount': selectionCount,
    };
  }
  if (dataRowCount <= 0 || dataColumnCount <= 0) {
    return null;
  }
  final minRow = selection.rowStart;
  final maxRow = minRow + dataRowCount - 1;
  final minColumn = selection.columnStart;
  final maxColumn = minColumn + dataColumnCount - 1;
  if (hasPartialMerge) {
    return {
      'type': 'pasteBlockedPartialMerge',
      'range': {
        'row': [minRow, maxRow],
        'column': [minColumn, maxColumn],
      },
    };
  }
  final addRows = math.max(0, maxRow - rowMaxLength + 1);
  final addColumns = math.max(0, maxColumn - columnMaxLength + 1);
  return {
    'type': 'pasteApplyRange',
    'range': {
      'row': [minRow, maxRow],
      'column': [minColumn, maxColumn],
    },
    'copySize': {'rows': dataRowCount, 'columns': dataColumnCount},
    'addRows': addRows,
    'addColumns': addColumns,
    'ensureMergeConfig': true,
    if (hasBorderInfo) 'ensureBorderInfo': true,
  };
}

Map<String, Object?>? pasteHandlerOfPlainText(
  FortuneWorkbook workbook,
  Context ctx,
  String data, {
  bool allowEdit = true,
  bool hasPartialMerge = false,
}) {
  if (!allowEdit) {
    return null;
  }
  final selections = _apiContextRanges(ctx['luckysheet_select_save']);
  if (selections.length != 1) {
    return {
      'type': 'pasteBlockedMultiSelection',
      'selectionCount': selections.length,
    };
  }
  final rows = _apiPlainTextPasteRows(data);
  if (rows.isEmpty || rows.first.isEmpty) {
    return null;
  }
  final targetSheetId = ctx['currentSheetId']?.toString().isNotEmpty == true
      ? ctx['currentSheetId'].toString()
      : workbook.activeSheet.id;
  final targetIndex = getSheetIndex(workbook, targetSheetId);
  if (targetIndex == null) {
    return null;
  }
  final selection = selections.last;
  final rowStart = selection.rowStart;
  final columnStart = selection.columnStart;
  final rowEnd = rowStart + rows.length - 1;
  final columnEnd = columnStart + rows.first.length - 1;
  final applyRange = FortuneRange(
    rowStart: rowStart,
    rowEnd: rowEnd,
    columnStart: columnStart,
    columnEnd: columnEnd,
  );
  if (hasPartialMerge) {
    return {
      'type': 'pasteBlockedPartialMerge',
      'range': _selectionRangeToApiMap(applyRange),
    };
  }

  final targetSheet = workbook.sheets[targetIndex];
  final targetCells = {
    for (final entry in targetSheet.cells.entries)
      entry.key: entry.value.copyWith(),
  };
  final writtenCoords = <FortuneCellCoord>[];
  for (var rowOffset = 0; rowOffset < rows.length; rowOffset += 1) {
    final rowValues = rows[rowOffset];
    for (
      var columnOffset = 0;
      columnOffset < rowValues.length;
      columnOffset += 1
    ) {
      final coord = FortuneCellCoord(
        rowStart + rowOffset,
        columnStart + columnOffset,
      );
      targetCells[coord] = _apiPlainTextPasteCell(
        targetCells[coord],
        rowValues[columnOffset],
      );
      writtenCoords.add(coord);
    }
  }

  var nextSheet = targetSheet.copyWith(
    cells: targetCells,
    rowCount: _apiExpandedCount(targetSheet.rowCount, rowEnd),
    columnCount: _apiExpandedCount(targetSheet.columnCount, columnEnd),
    selectionSave: [_selectionRangeToApiMap(applyRange)],
  );
  for (final coord in writtenCoords) {
    nextSheet = _apiSheetWithFunctionGroupCleanupAfterValueSet(
      targetSheet,
      nextSheet,
      coord.row,
      coord.column,
    );
  }
  final nextSheets = workbook.sheets.map((sheet) => sheet.copyWith()).toList();
  nextSheets[targetIndex] = nextSheet;
  return {
    'type': 'pasteHandlerOfPlainText',
    'workbook': workbook.copyWith(sheets: nextSheets),
    'sheet': nextSheet,
    'applyRange': _selectionRangeToApiMap(applyRange),
    'copySize': {'rows': rows.length, 'columns': rows.first.length},
  };
}

Map<String, Object?>? pasteHandlerOfHtmlTable(
  FortuneWorkbook workbook,
  Context ctx,
  String html, {
  bool allowEdit = true,
  bool hasPartialMerge = false,
}) {
  final tableData = _apiHtmlTablePasteData(html);
  if (tableData.matrix.isEmpty) {
    return null;
  }
  final payload = pasteHandlerOfPlainText(
    workbook,
    ctx,
    _apiTextMatrixToTsv(tableData.matrix),
    allowEdit: allowEdit,
    hasPartialMerge: hasPartialMerge,
  );
  if (payload == null) {
    return null;
  }
  if (tableData.spans.isEmpty &&
      tableData.borders.isEmpty &&
      tableData.styles.isEmpty &&
      tableData.rowHeights.isEmpty &&
      tableData.columnWidths.isEmpty) {
    return payload;
  }
  final pastedSheet = payload['sheet'];
  final pastedWorkbook = payload['workbook'];
  final rawApplyRange = payload['applyRange'];
  final applyRange = rawApplyRange is Map
      ? _selectionRangeFromApiMap(rawApplyRange)
      : null;
  if (pastedSheet is! FortuneSheet ||
      pastedWorkbook is! FortuneWorkbook ||
      applyRange == null) {
    return payload;
  }
  var nextSheet = pastedSheet;
  if (tableData.styles.isNotEmpty) {
    final nextCells = Map<FortuneCellCoord, FortuneCell>.from(nextSheet.cells);
    for (final style in tableData.styles) {
      final coord = FortuneCellCoord(
        applyRange.rowStart + style.row,
        applyRange.columnStart + style.column,
      );
      nextCells[coord] = style.applyTo(nextCells[coord] ?? const FortuneCell());
    }
    nextSheet = nextSheet.copyWith(cells: nextCells);
  }
  if (tableData.rowHeights.isNotEmpty) {
    nextSheet = nextSheet.setRowHeight({
      for (final rowHeight in tableData.rowHeights)
        applyRange.rowStart + rowHeight.row: rowHeight.height,
    }, custom: true);
  }
  if (tableData.columnWidths.isNotEmpty) {
    nextSheet = nextSheet.setColumnWidth({
      for (final columnWidth in tableData.columnWidths)
        applyRange.columnStart + columnWidth.column: columnWidth.width,
    }, custom: true);
  }
  for (final span in tableData.spans) {
    nextSheet = nextSheet.mergeCells(
      FortuneRange(
        rowStart: applyRange.rowStart + span.row,
        rowEnd: applyRange.rowStart + span.row + span.rowSpan - 1,
        columnStart: applyRange.columnStart + span.column,
        columnEnd: applyRange.columnStart + span.column + span.columnSpan - 1,
      ),
      'merge-cell',
    );
  }
  if (tableData.borders.isNotEmpty) {
    nextSheet = nextSheet.copyWith(
      borderInfo: [
        ...nextSheet.borderInfo,
        for (final border in tableData.borders)
          FortuneBorderInfo(
            rangeType: 'range',
            borderType: border.borderType,
            color: _nullableColorArg(border.color) ?? const Color(0xff000000),
            rawColor: border.color,
            hasRawColor: true,
            style: border.style,
            ranges: [
              FortuneRange(
                rowStart: applyRange.rowStart + border.row,
                rowEnd: applyRange.rowStart + border.row,
                columnStart: applyRange.columnStart + border.column,
                columnEnd: applyRange.columnStart + border.column,
              ),
            ],
          ),
      ],
    );
  }
  final nextSheets = pastedWorkbook.sheets
      .map((sheet) => sheet.copyWith())
      .toList();
  final targetIndex = getSheetIndex(pastedWorkbook, nextSheet.id);
  if (targetIndex == null) {
    return payload;
  }
  nextSheets[targetIndex] = nextSheet;
  return {
    ...payload,
    'workbook': pastedWorkbook.copyWith(sheets: nextSheets),
    'sheet': nextSheet,
    'htmlTableMerges': [
      for (final span in tableData.spans)
        {
          'row': applyRange.rowStart + span.row,
          'column': applyRange.columnStart + span.column,
          'rowspan': span.rowSpan,
          'colspan': span.columnSpan,
        },
    ],
    'htmlTableBorders': [
      for (final border in tableData.borders)
        {
          'row': applyRange.rowStart + border.row,
          'column': applyRange.columnStart + border.column,
          'borderType': border.borderType,
          'style': border.style,
          'color': border.color,
        },
    ],
    'htmlTableStyles': [
      for (final style in tableData.styles)
        {
          'row': applyRange.rowStart + style.row,
          'column': applyRange.columnStart + style.column,
          ...style.toPayload(),
        },
    ],
    'htmlTableRowHeights': [
      for (final rowHeight in tableData.rowHeights)
        {
          'row': applyRange.rowStart + rowHeight.row,
          'height': rowHeight.height,
        },
    ],
    'htmlTableColumnWidths': [
      for (final columnWidth in tableData.columnWidths)
        {
          'column': applyRange.columnStart + columnWidth.column,
          'width': columnWidth.width,
        },
    ],
  };
}

List<List<String>> htmlTableToPasteMatrix(String html) {
  return _apiHtmlTablePasteData(html).matrix;
}

_HtmlTablePasteData _apiHtmlTablePasteData(String html) {
  final tableMatch = RegExp(
    r'<table\b[^>]*>(.*?)</table>',
    caseSensitive: false,
    dotAll: true,
  ).firstMatch(html);
  final tableHtml = tableMatch?.group(1) ?? html;
  final styleRules = _apiHtmlStyleRules(html);
  final rowMatches = RegExp(
    r'<tr\b([^>]*)>(.*?)</tr>',
    caseSensitive: false,
    dotAll: true,
  ).allMatches(tableHtml);
  final grid = <List<String?>>[];
  final spans = <_HtmlTableSpan>[];
  final borders = <_HtmlTableBorder>[];
  final styles = <_HtmlTableCellStyle>[];
  final rowHeights = <_HtmlTableRowHeight>[];
  final columnWidths = _apiHtmlTableColumnWidths(tableHtml);
  var rowIndex = 0;
  for (final rowMatch in rowMatches) {
    while (grid.length <= rowIndex) {
      grid.add(<String?>[]);
    }
    final row = grid[rowIndex];
    final rowAttrs = rowMatch.group(1) ?? '';
    final rowHeight = _apiHtmlTableRowHeightFromAttrs(rowIndex, rowAttrs);
    if (rowHeight != null) {
      rowHeights.add(rowHeight);
    }
    var columnIndex = 0;
    final cellMatches = RegExp(
      r'<(t[dh])\b([^>]*)>(.*?)</\1>',
      caseSensitive: false,
      dotAll: true,
    ).allMatches(rowMatch.group(2) ?? '');
    for (final cellMatch in cellMatches) {
      while (columnIndex < row.length && row[columnIndex] != null) {
        columnIndex += 1;
      }
      final tagName = cellMatch.group(1)?.toLowerCase() ?? 'td';
      final attrs = cellMatch.group(2) ?? '';
      final rowSpan = math.max(
        1,
        int.tryParse(_apiHtmlAttribute(attrs, 'rowspan') ?? '') ?? 1,
      );
      final columnSpan = math.max(
        1,
        int.tryParse(_apiHtmlAttribute(attrs, 'colspan') ?? '') ?? 1,
      );
      if (rowSpan > 1 || columnSpan > 1) {
        spans.add(
          _HtmlTableSpan(
            row: rowIndex,
            column: columnIndex,
            rowSpan: rowSpan,
            columnSpan: columnSpan,
          ),
        );
      }
      final innerHtml = cellMatch.group(3) ?? '';
      final text = _apiHtmlCellText(innerHtml);
      final style = _apiHtmlCellStyleText(
        tagName: tagName,
        attrs: attrs,
        styleRules: styleRules,
      );
      borders.addAll(
        _apiHtmlTableBordersFromStyle(
          row: rowIndex,
          column: columnIndex,
          rowSpan: rowSpan,
          columnSpan: columnSpan,
          style: style,
        ),
      );
      final cellStyle = _apiHtmlTableCellStyleFromStyle(
        row: rowIndex,
        column: columnIndex,
        style: style,
        html: innerHtml,
      );
      if (cellStyle != null) {
        styles.add(cellStyle);
      }
      for (var rowOffset = 0; rowOffset < rowSpan; rowOffset += 1) {
        final targetRowIndex = rowIndex + rowOffset;
        while (grid.length <= targetRowIndex) {
          grid.add(<String?>[]);
        }
        final targetRow = grid[targetRowIndex];
        while (targetRow.length < columnIndex + columnSpan) {
          targetRow.add(null);
        }
        for (
          var columnOffset = 0;
          columnOffset < columnSpan;
          columnOffset += 1
        ) {
          targetRow[columnIndex + columnOffset] =
              rowOffset == 0 && columnOffset == 0 ? text : '';
        }
      }
      columnIndex += columnSpan;
    }
    rowIndex += 1;
  }
  final columnCount = grid.fold<int>(
    0,
    (maxColumns, row) => math.max(maxColumns, row.length),
  );
  return _HtmlTablePasteData(
    matrix: [
      for (final row in grid)
        [
          for (var column = 0; column < columnCount; column += 1)
            column < row.length ? row[column] ?? '' : '',
        ],
    ],
    spans: spans,
    borders: borders,
    styles: styles,
    rowHeights: rowHeights,
    columnWidths: columnWidths,
  );
}

class _HtmlTablePasteData {
  const _HtmlTablePasteData({
    required this.matrix,
    required this.spans,
    required this.borders,
    required this.styles,
    required this.rowHeights,
    required this.columnWidths,
  });

  final List<List<String>> matrix;
  final List<_HtmlTableSpan> spans;
  final List<_HtmlTableBorder> borders;
  final List<_HtmlTableCellStyle> styles;
  final List<_HtmlTableRowHeight> rowHeights;
  final List<_HtmlTableColumnWidth> columnWidths;
}

List<_HtmlTableColumnWidth> _apiHtmlTableColumnWidths(String html) {
  final columnWidths = <_HtmlTableColumnWidth>[];
  final colMatches = RegExp(
    r'<col(?:group)?\b([^>]*)>',
    caseSensitive: false,
    dotAll: true,
  ).allMatches(html);
  var column = 0;
  for (final colMatch in colMatches) {
    final attrs = colMatch.group(1) ?? '';
    final width = _apiHtmlTableColumnWidthFromAttrs(attrs);
    final span =
        _apiHtmlTableColumnSpanFromAttrs(attrs) ?? (width == null ? 0 : 1);
    if (width != null) {
      for (var offset = 0; offset < span; offset += 1) {
        columnWidths.add(
          _HtmlTableColumnWidth(column: column + offset, width: width),
        );
      }
    }
    column += span;
  }
  return columnWidths;
}

double? _apiHtmlTableColumnWidthFromAttrs(String attrs) {
  final styleWidth = _apiCssDeclarations(
    _apiHtmlAttribute(attrs, 'style') ?? '',
  )['width'];
  final width = _apiHtmlCssDimensionToPixels(
    _apiHtmlAttribute(attrs, 'width') ?? styleWidth,
  );
  if (width == null || width < 0) {
    return null;
  }
  return width;
}

int? _apiHtmlTableColumnSpanFromAttrs(String attrs) {
  final rawSpan = _apiHtmlAttribute(attrs, 'span')?.trim();
  if (rawSpan == null || rawSpan.isEmpty) {
    return null;
  }
  final span = int.tryParse(rawSpan);
  if (span == null || span <= 0) {
    return null;
  }
  return span;
}

double? _apiHtmlCssDimensionToPixels(String? rawValue) {
  final value = rawValue?.trim().toLowerCase();
  if (value == null || value.isEmpty) {
    return null;
  }
  final match = RegExp(r'^(\d+(?:\.\d+)?)(px|pt)?$').firstMatch(value);
  if (match == null) {
    return null;
  }
  final numeric = double.tryParse(match.group(1)!);
  if (numeric == null || !numeric.isFinite) {
    return null;
  }
  return (match.group(2) ?? 'px') == 'pt' ? numeric * 96 / 72 : numeric;
}

_HtmlTableRowHeight? _apiHtmlTableRowHeightFromAttrs(int row, String attrs) {
  final rawHeight = _apiHtmlAttribute(attrs, 'height');
  if (rawHeight == null || rawHeight.trim().isEmpty) {
    return null;
  }
  final height = double.tryParse(rawHeight.trim());
  if (height == null || height < 0) {
    return null;
  }
  return _HtmlTableRowHeight(row: row, height: height);
}

