class _HtmlTableCellStyle {
  const _HtmlTableCellStyle({
    required this.row,
    required this.column,
    this.background,
    this.foreground,
    this.bold,
    this.italic,
    this.underline,
    this.strikeThrough,
    this.fontSize,
    this.fontFamily,
    this.horizontalAlign,
    this.verticalAlign,
    this.textRotation,
  });

  final int row;
  final int column;
  final String? background;
  final String? foreground;
  final int? bold;
  final int? italic;
  final int? underline;
  final int? strikeThrough;
  final num? fontSize;
  final Object? fontFamily;
  final int? horizontalAlign;
  final int? verticalAlign;
  final num? textRotation;

  FortuneCell applyTo(FortuneCell cell) {
    return cell.copyWith(
      background: background == null
          ? _sentinel
          : _nullableColorArg(background),
      rawBackground: background ?? _sentinel,
      hasRawBackground: background == null ? null : true,
      foreground: foreground == null
          ? _sentinel
          : _nullableColorArg(foreground),
      rawForeground: foreground ?? _sentinel,
      hasRawForeground: foreground == null ? null : true,
      bold: bold == null ? null : bold != 0,
      rawBold: bold ?? _sentinel,
      hasRawBold: bold == null ? null : true,
      italic: italic == null ? null : italic != 0,
      rawItalic: italic ?? _sentinel,
      hasRawItalic: italic == null ? null : true,
      underline: underline == null ? null : underline != 0,
      rawUnderline: underline ?? _sentinel,
      hasRawUnderline: underline == null ? null : true,
      strikeThrough: strikeThrough == null ? null : strikeThrough != 0,
      rawStrikeThrough: strikeThrough ?? _sentinel,
      hasRawStrikeThrough: strikeThrough == null ? null : true,
      fontSize: fontSize ?? _sentinel,
      rawFontSize: fontSize ?? _sentinel,
      hasRawFontSize: fontSize == null ? null : true,
      fontFamily: fontFamily ?? _sentinel,
      rawFontFamily: fontFamily ?? _sentinel,
      hasRawFontFamily: fontFamily == null ? null : true,
      horizontalAlign: horizontalAlign?.toString() ?? _sentinel,
      rawHorizontalAlign: horizontalAlign ?? _sentinel,
      hasRawHorizontalAlign: horizontalAlign == null ? null : true,
      verticalAlign: verticalAlign?.toString() ?? _sentinel,
      rawVerticalAlign: verticalAlign ?? _sentinel,
      hasRawVerticalAlign: verticalAlign == null ? null : true,
      textRotation: textRotation?.toString() ?? _sentinel,
      rawTextRotation: textRotation ?? _sentinel,
      hasRawTextRotation: textRotation == null ? null : true,
    );
  }

  Map<String, Object?> toPayload() {
    return {
      if (background != null) 'background': background,
      if (foreground != null) 'foreground': foreground,
      if (bold != null) 'bold': bold,
      if (italic != null) 'italic': italic,
      if (underline != null) 'underline': underline,
      if (strikeThrough != null) 'strikeThrough': strikeThrough,
      if (fontSize != null) 'fontSize': fontSize,
      if (fontFamily != null) 'fontFamily': fontFamily,
      if (horizontalAlign != null) 'horizontalAlign': horizontalAlign,
      if (verticalAlign != null) 'verticalAlign': verticalAlign,
      if (textRotation != null) 'textRotation': textRotation,
    };
  }
}

_HtmlTableCellStyle? _apiHtmlTableCellStyleFromStyle({
  required int row,
  required int column,
  required String style,
  required String html,
}) {
  final declarations = _apiCssDeclarations(style);
  final hasExactStrikeTag = html.contains('<s>');
  if (declarations.isEmpty && !hasExactStrikeTag) {
    return null;
  }
  final background = _apiCssColorDeclaration(
    declarations['background-color'] ?? declarations['background'],
  );
  final foreground = _apiCssColorDeclaration(declarations['color']);
  final bold = _apiCssBoldDeclaration(declarations['font-weight']);
  final italic = _apiCssItalicDeclaration(declarations['font-style']);
  final decoration = declarations['text-decoration'] ?? '';
  final underline = decoration.toLowerCase().contains('underline') ? 1 : null;
  final strikeThrough =
      decoration.toLowerCase().contains('line-through') || hasExactStrikeTag
      ? 1
      : null;
  final fontSize = _apiCssFontSizeDeclaration(declarations['font-size']);
  final fontFamily = _apiCssFontFamilyDeclaration(declarations['font-family']);
  final horizontalAlign = _apiCssHorizontalAlignDeclaration(
    declarations['text-align'],
  );
  final verticalAlign = _apiCssVerticalAlignDeclaration(
    declarations['vertical-align'],
  );
  final textRotation = _apiCssTextRotationDeclaration(
    declarations['mso-rotate'],
  );
  if (background == null &&
      foreground == null &&
      bold == null &&
      italic == null &&
      underline == null &&
      strikeThrough == null &&
      fontSize == null &&
      fontFamily == null &&
      horizontalAlign == null &&
      verticalAlign == null &&
      textRotation == null) {
    return null;
  }
  return _HtmlTableCellStyle(
    row: row,
    column: column,
    background: background,
    foreground: foreground,
    bold: bold,
    italic: italic,
    underline: underline,
    strikeThrough: strikeThrough,
    fontSize: fontSize,
    fontFamily: fontFamily,
    horizontalAlign: horizontalAlign,
    verticalAlign: verticalAlign,
    textRotation: textRotation,
  );
}

String? _apiCssColorDeclaration(String? value) {
  final color = value?.trim();
  if (color == null || color.isEmpty || color == 'transparent') {
    return null;
  }
  if (color == 'rgba(0, 0, 0, 0)') {
    return null;
  }
  return _apiNormalizeColorAttr(color, null)?.toString();
}

int? _apiCssBoldDeclaration(String? value) {
  final fontWeight = value?.trim().toLowerCase();
  if (fontWeight == null || fontWeight.isEmpty) {
    return null;
  }
  if (fontWeight == 'normal' || fontWeight == '400') {
    return 0;
  }
  final numeric = int.tryParse(fontWeight);
  if (numeric != null) {
    return numeric >= 600 ? 1 : 0;
  }
  return fontWeight == 'bold' || fontWeight == 'bolder' ? 1 : null;
}

int? _apiCssItalicDeclaration(String? value) {
  final fontStyle = value?.trim().toLowerCase();
  if (fontStyle == null || fontStyle.isEmpty) {
    return null;
  }
  if (fontStyle == 'normal') {
    return 0;
  }
  return fontStyle == 'italic' || fontStyle == 'oblique' ? 1 : null;
}

num? _apiCssFontSizeDeclaration(String? value) {
  final fontSize = value?.trim().toLowerCase();
  if (fontSize == null || fontSize.isEmpty) {
    return null;
  }
  final match = RegExp(r'^(\d+(?:\.\d+)?)(px|pt)?$').firstMatch(fontSize);
  if (match == null) {
    return null;
  }
  final numeric = double.tryParse(match.group(1)!);
  if (numeric == null) {
    return null;
  }
  final points = numeric * 72 / 96;
  return points.round();
}

Object? _apiCssFontFamilyDeclaration(String? value) {
  final fontFamily = value?.trim();
  if (fontFamily == null || fontFamily.isEmpty) {
    return null;
  }
  var hasFamily = false;
  for (final family in fontFamily.split(',')) {
    final normalized = family.replaceAll('"', '').replaceAll("'", '').trim();
    if (normalized.isEmpty) {
      continue;
    }
    hasFamily = true;
    final index = fortuneFontArray.indexWhere(
      (font) => font.toLowerCase() == normalized.toLowerCase(),
    );
    if (index >= 0) {
      return index;
    }
  }
  return hasFamily ? 0 : null;
}

int? _apiCssHorizontalAlignDeclaration(String? value) {
  return switch (value?.trim().toLowerCase()) {
    'center' => 0,
    'left' || 'start' || 'general' => 1,
    'right' || 'end' => 2,
    _ => null,
  };
}

int? _apiCssVerticalAlignDeclaration(String? value) {
  return switch (value?.trim().toLowerCase()) {
    'middle' => 0,
    'top' || 'text-top' => 1,
    'bottom' || 'text-bottom' => 2,
    _ => null,
  };
}

num? _apiCssTextRotationDeclaration(String? value) {
  final rotation = value?.trim();
  if (rotation == null || rotation.isEmpty) {
    return null;
  }
  return num.tryParse(rotation);
}

List<_HtmlTableBorder> _apiHtmlTableBordersFromStyle({
  required int row,
  required int column,
  required int rowSpan,
  required int columnSpan,
  required String style,
}) {
  final declarations = _apiCssDeclarations(style);
  if (declarations.isEmpty) {
    return const [];
  }
  final sides = {
    'top': _apiCssBorderSide(declarations, 'top'),
    'bottom': _apiCssBorderSide(declarations, 'bottom'),
    'left': _apiCssBorderSide(declarations, 'left'),
    'right': _apiCssBorderSide(declarations, 'right'),
  };
  final borders = <_HtmlTableBorder>[];
  final safeRowSpan = math.max(1, rowSpan);
  final safeColumnSpan = math.max(1, columnSpan);
  for (var rowOffset = 0; rowOffset < safeRowSpan; rowOffset += 1) {
    for (
      var columnOffset = 0;
      columnOffset < safeColumnSpan;
      columnOffset += 1
    ) {
      if (rowOffset == 0 && sides['top'] != null) {
        borders.add(
          _apiHtmlTableBorder(
            row + rowOffset,
            column + columnOffset,
            'border-top',
            sides['top']!,
          ),
        );
      }
      if (rowOffset == safeRowSpan - 1 && sides['bottom'] != null) {
        borders.add(
          _apiHtmlTableBorder(
            row + rowOffset,
            column + columnOffset,
            'border-bottom',
            sides['bottom']!,
          ),
        );
      }
      if (columnOffset == 0 && sides['left'] != null) {
        borders.add(
          _apiHtmlTableBorder(
            row + rowOffset,
            column + columnOffset,
            'border-left',
            sides['left']!,
          ),
        );
      }
      if (columnOffset == safeColumnSpan - 1 && sides['right'] != null) {
        borders.add(
          _apiHtmlTableBorder(
            row + rowOffset,
            column + columnOffset,
            'border-right',
            sides['right']!,
          ),
        );
      }
    }
  }
  return borders;
}

