class _HtmlCssBorderSide {
  const _HtmlCssBorderSide({required this.style, required this.color});

  final int style;
  final String color;
}

Map<String, String> _apiCssDeclarations(String style) {
  final declarations = <String, String>{};
  for (final part in style.split(';')) {
    final separator = part.indexOf(':');
    if (separator <= 0) {
      continue;
    }
    declarations[part.substring(0, separator).trim().toLowerCase()] = part
        .substring(separator + 1)
        .trim();
  }
  return declarations;
}

Map<String, Map<String, String>> _apiHtmlStyleRules(String html) {
  final rules = <String, Map<String, String>>{};
  final styleBlocks = RegExp(
    r'<style\b[^>]*>(.*?)</style>',
    caseSensitive: false,
    dotAll: true,
  ).allMatches(html);
  for (final block in styleBlocks) {
    final css = (block.group(1) ?? '')
        .replaceAll(RegExp(r'<!--'), '')
        .replaceAll(RegExp(r'-->'), '');
    final ruleMatches = RegExp(
      r'([^{}]+)\{([^{}]*)\}',
      caseSensitive: false,
      dotAll: true,
    ).allMatches(css);
    for (final rule in ruleMatches) {
      final declarations = _apiCssDeclarations(rule.group(2) ?? '');
      if (declarations.isEmpty) {
        continue;
      }
      final selectors = (rule.group(1) ?? '').split(',');
      for (final selector in selectors) {
        final normalized = selector.trim().toLowerCase();
        if (normalized.isEmpty) {
          continue;
        }
        if (normalized == 'td' ||
            normalized == 'th' ||
            RegExp(r'^\.[a-z0-9_-]+$').hasMatch(normalized)) {
          rules[normalized] = {...?rules[normalized], ...declarations};
        }
      }
    }
  }
  return rules;
}

String _apiHtmlCellStyleText({
  required String tagName,
  required String attrs,
  required Map<String, Map<String, String>> styleRules,
}) {
  final declarations = <String, String>{};
  declarations.addAll(styleRules[tagName] ?? const <String, String>{});
  final classAttr = _apiHtmlAttribute(attrs, 'class') ?? '';
  for (final className in classAttr.split(RegExp(r'\s+'))) {
    if (className.trim().isEmpty) {
      continue;
    }
    declarations.addAll(
      styleRules['.${className.trim().toLowerCase()}'] ??
          const <String, String>{},
    );
  }
  final alignAttr = _apiHtmlAttribute(attrs, 'align')?.trim();
  if (alignAttr != null && alignAttr.isNotEmpty) {
    final currentTextAlign = declarations['text-align']?.trim().toLowerCase();
    if (currentTextAlign == null || currentTextAlign == 'general') {
      declarations['text-align'] = alignAttr;
    }
  }
  final verticalAlignAttr = _apiHtmlAttribute(attrs, 'valign')?.trim();
  if (verticalAlignAttr != null && verticalAlignAttr.isNotEmpty) {
    declarations.putIfAbsent('vertical-align', () => verticalAlignAttr);
  }
  declarations.addAll(
    _apiCssDeclarations(_apiHtmlAttribute(attrs, 'style') ?? ''),
  );
  return declarations.entries
      .map((entry) => '${entry.key}:${entry.value}')
      .join(';');
}

_HtmlCssBorderSide? _apiCssBorderSide(
  Map<String, String> declarations,
  String side,
) {
  final shorthand = declarations['border-$side'] ?? declarations['border'];
  final explicitWidth = declarations['border-$side-width'];
  final explicitStyle = declarations['border-$side-style'];
  final explicitColor = declarations['border-$side-color'];
  final parts = shorthand == null
      ? const <String>[]
      : shorthand.split(RegExp(r'\s+')).where((part) => part.isNotEmpty);
  var width = explicitWidth ?? '';
  var lineStyle = explicitStyle ?? '';
  var color = explicitColor ?? '';
  for (final part in parts) {
    final lower = part.toLowerCase();
    if (RegExp(r'^(\d+(?:\.\d+)?)(px|pt)$').hasMatch(lower)) {
      width = part;
    } else if ({
      'solid',
      'dashed',
      'dotted',
      'double',
      'none',
    }.contains(lower)) {
      lineStyle = lower;
    } else {
      color = part;
    }
  }
  if (width.isEmpty || lineStyle.isEmpty || lineStyle == 'none') {
    return null;
  }
  if (width.toLowerCase().startsWith('0')) {
    return null;
  }
  final normalizedColor = _apiNormalizeColorAttr(
    color.isEmpty ? '#000000' : color,
    '#000000',
  )?.toString();
  final border = getQKBorder(width, lineStyle, normalizedColor ?? '#000000');
  final parsedStyle = _nullableIntArg(border.first) ?? 0;
  if (parsedStyle == 0) {
    return null;
  }
  return _HtmlCssBorderSide(
    style: parsedStyle,
    color:
        (border.length > 1 ? border[1] : normalizedColor)?.toString() ??
        '#000000',
  );
}

String _apiTextMatrixToTsv(List<List<String>> matrix) {
  return matrix.map((row) => row.join('\t')).join('\n');
}

String _apiHtmlCellText(String html) {
  final withLineBreaks = html.replaceAll(
    RegExp(r'<br\s*/?>', caseSensitive: false),
    '\n',
  );
  return _apiDecodeHtmlEntities(_apiPlainTextFromHtml(withLineBreaks)).trim();
}

String _apiDecodeHtmlEntities(String text) {
  return text.replaceAllMapped(RegExp(r'&(#x?[0-9a-fA-F]+|[A-Za-z]+);'), (
    match,
  ) {
    final entity = match.group(1)!;
    if (entity.startsWith('#x') || entity.startsWith('#X')) {
      final codePoint = int.tryParse(entity.substring(2), radix: 16);
      return codePoint == null
          ? match.group(0)!
          : String.fromCharCode(codePoint);
    }
    if (entity.startsWith('#')) {
      final codePoint = int.tryParse(entity.substring(1));
      return codePoint == null
          ? match.group(0)!
          : String.fromCharCode(codePoint);
    }
    return switch (entity.toLowerCase()) {
      'amp' => '&',
      'lt' => '<',
      'gt' => '>',
      'quot' => '"',
      'apos' || '#39' => "'",
      'nbsp' => ' ',
      _ => match.group(0)!,
    };
  });
}

List<List<String>> _apiPlainTextPasteRows(String data) {
  final rows = <List<String>>[];
  final lines = data.replaceAll('\r', '').split('\n');
  if (lines.isEmpty) {
    return rows;
  }
  final columnCount = lines.first.split('\t').length;
  for (final line in lines) {
    final columns = line.split('\t');
    if (columns.length < columnCount) {
      continue;
    }
    rows.add(columns);
  }
  return rows;
}

FortuneCell _apiPlainTextPasteCell(FortuneCell? originCell, String value) {
  Object? nextValue = value;
  if (isRealNum(value)) {
    if (originCell?.cellType?.format == '@') {
      nextValue = value;
    } else {
      nextValue = _apiGenerateNumericValue(value) ?? value;
    }
  }
  if (originCell != null) {
    final format = originCell.cellType?.format;
    final display = format == null ? '$nextValue' : update(format, nextValue);
    return originCell.copyWith(
      value: '$nextValue',
      rawValue: cloneFortuneMetadata(nextValue),
      hasRawValue: true,
      displayValue: display,
      rawDisplayValue: cloneFortuneMetadata(display),
      hasRawDisplayValue: true,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
    );
  }
  final mask = genarate(nextValue);
  if (mask == null) {
    return const FortuneCell();
  }
  return _cellWithApiValueMap(const FortuneCell(), {
    'm': mask[0],
    'ct': mask[1],
    'v': mask[2],
  });
}

Map<String, Object?>? handleFormulaStringPaste(
  FortuneWorkbook workbook,
  Context ctx,
  String formulaStr, {
  Object? result,
  Object? formulaError,
  bool allowEdit = true,
}) {
  if (!allowEdit || !formulaStr.startsWith('=')) {
    return null;
  }
  final selections = _apiContextRanges(ctx['luckysheet_select_save']);
  if (selections.length != 1) {
    return {
      'type': 'pasteBlockedMultiSelection',
      'selectionCount': selections.length,
    };
  }
  final targetSheetId = ctx['currentSheetId']?.toString().isNotEmpty == true
      ? ctx['currentSheetId'].toString()
      : workbook.activeSheet.id;
  final targetIndex = getSheetIndex(workbook, targetSheetId);
  if (targetIndex == null) {
    return null;
  }
  final selection = selections.first;
  final row = selection.rowStart;
  final column = selection.columnStart;
  final executed = execfunction(
    ctx,
    formulaStr,
    row,
    column,
    id: targetSheetId,
    result: result,
    formulaError: formulaError,
    isRefresh: true,
  );
  final value = executed[1];
  final targetSheet = workbook.sheets[targetIndex];
  final targetCells = {
    for (final entry in targetSheet.cells.entries)
      entry.key: entry.value.copyWith(),
  };
  final coord = FortuneCellCoord(row, column);
  final current = targetCells[coord] ?? const FortuneCell();
  final display = value?.toString() ?? '';
  targetCells[coord] = current.copyWith(
    value: display,
    rawValue: cloneFortuneMetadata(value),
    hasRawValue: true,
    displayValue: display,
    rawDisplayValue: cloneFortuneMetadata(display),
    hasRawDisplayValue: true,
    formula: formulaStr,
    rawFormula: formulaStr,
    hasRawFormula: true,
  );
  final nextSheet = targetSheet.copyWith(cells: targetCells);
  final nextSheets = workbook.sheets.map((sheet) => sheet.copyWith()).toList();
  nextSheets[targetIndex] = nextSheet;
  return {
    'type': 'formulaStringPaste',
    'workbook': workbook.copyWith(sheets: nextSheets),
    'sheet': nextSheet,
    'cell': {'r': row, 'c': column, 'i': targetSheetId},
    'execution': executed,
  };
}

