Map<String, Object?>? _apiPasteHandlerOfCopyRange(
  FortuneWorkbook workbook,
  Context ctx,
  Map<String, Object?>? copyRange, {
  required String type,
  bool clearSource = false,
}) {
  if (copyRange == null) {
    return null;
  }
  final parsedSourceRanges = _apiCopySaveRanges(copyRange);
  final sourceRanges = clearSource && parsedSourceRanges.isNotEmpty
      ? <FortuneRange>[parsedSourceRanges.first]
      : parsedSourceRanges;
  final sourceRange = sourceRanges.isEmpty ? null : sourceRanges.first;
  final selections = _apiContextRanges(ctx['luckysheet_select_save']);
  if (sourceRange == null || selections.isEmpty) {
    return null;
  }
  final activeSheetId = '${ctx['currentSheetId'] ?? workbook.activeSheet.id}';
  final sourceSheetId = '${copyRange['dataSheetId'] ?? activeSheetId}';
  final sourceIndex = getSheetIndex(workbook, sourceSheetId);
  final targetIndex = getSheetIndex(workbook, activeSheetId);
  if (sourceIndex == null || targetIndex == null) {
    return null;
  }
  final sourceSheet = workbook.sheets[sourceIndex];
  final targetSheet = workbook.sheets[targetIndex];
  final sourceMatrix = _apiCopySourceMatrix(sourceSheet, sourceRanges);
  if (sourceMatrix == null || sourceMatrix.isEmpty) {
    return null;
  }
  final targetSelection = selections.last;
  final sourceRows = sourceMatrix.length;
  final sourceColumns = sourceMatrix.first.length;
  var applyRange = targetSelection;
  if (targetSelection.rowStart == targetSelection.rowEnd &&
      targetSelection.columnStart == targetSelection.columnEnd) {
    applyRange = FortuneRange(
      rowStart: targetSelection.rowStart,
      rowEnd: targetSelection.rowStart + sourceRows - 1,
      columnStart: targetSelection.columnStart,
      columnEnd: targetSelection.columnStart + sourceColumns - 1,
      rowFocus: targetSelection.rowFocus,
      columnFocus: targetSelection.columnFocus,
    );
  } else if (type == 'pasteHandlerOfCopyPaste') {
    final targetRows = targetSelection.rowEnd - targetSelection.rowStart + 1;
    final targetColumns =
        targetSelection.columnEnd - targetSelection.columnStart + 1;
    if (targetRows % sourceRows != 0 || targetColumns % sourceColumns != 0) {
      applyRange = FortuneRange(
        rowStart: targetSelection.rowStart,
        rowEnd: targetSelection.rowStart + sourceRows - 1,
        columnStart: targetSelection.columnStart,
        columnEnd: targetSelection.columnStart + sourceColumns - 1,
        rowFocus: targetSelection.rowFocus,
        columnFocus: targetSelection.columnFocus,
      );
    }
  }
  final nextSheets = workbook.sheets.map((sheet) => sheet.copyWith()).toList();
  final sourceCells = <FortuneCellCoord, FortuneCell>{
    for (final entry in sourceSheet.cells.entries)
      entry.key: entry.value.copyWith(),
  };
  final targetCells = <FortuneCellCoord, FortuneCell>{
    for (final entry in targetSheet.cells.entries)
      entry.key: entry.value.copyWith(),
  };
  final sourceDataVerification = _cloneStringObjectMap(
    sourceSheet.dataVerification,
  );
  final targetDataVerification = _cloneStringObjectMap(
    targetSheet.dataVerification,
  );
  final sourceHyperlinks = _cloneStringObjectMap(sourceSheet.hyperlinks);
  final targetHyperlinks = _cloneStringObjectMap(targetSheet.hyperlinks);
  final sourceFilter = _cloneStringObjectMap(sourceSheet.filter);
  final sourceRawDataVerification = _apiCloneRawMetadataMap(
    sourceSheet.rawDataVerification,
  );
  final copiedRawDataVerification = _apiCloneRawMetadataMap(
    sourceSheet.rawDataVerification,
  );
  var targetRawDataVerification = _apiCloneRawMetadataMap(
    targetSheet.rawDataVerification,
  );
  final sourceRawHyperlinks = _apiCloneRawMetadataMap(
    sourceSheet.rawHyperlinks,
  );
  final copiedRawHyperlinks = _apiCloneRawMetadataMap(
    sourceSheet.rawHyperlinks,
  );
  var targetRawHyperlinks = _apiCloneRawMetadataMap(targetSheet.rawHyperlinks);
  final sourceComputedBorders = getBorderInfoCompute(sourceSheet);
  final targetComputedBorders = getBorderInfoCompute(targetSheet);
  final filterMetadataUpdate = clearSource && sourceIndex == targetIndex
      ? _apiFilterMetadataForCutPaste(
          sourceFilter: sourceFilter,
          sourceRawFilter: sourceSheet.rawFilter,
          sourceFilterSelect: sourceSheet.filterSelect,
          sourceRange: sourceRange,
          applyRange: applyRange,
          hasRawFilter: sourceSheet.hasRawFilter,
        )
      : null;
  var nextRawBorderInfo = _apiDropRawBorderInfo(
    targetSheet,
    targetComputedBorders,
  );
  final nextConditionFormats =
      type == 'pasteHandlerOfCopyPaste' && sourceRanges.length == 1
      ? _apiPasteCopyConditionFormats(
          sourceSheet.conditionFormats,
          targetSheet.conditionFormats,
          sourceRange,
          applyRange,
        )
      : clearSource && sourceRanges.length == 1 && sourceIndex == targetIndex
      ? _apiMoveConditionFormats(
          targetSheet.conditionFormats,
          sourceRange,
          applyRange,
        )
      : clearSource && sourceRanges.length == 1 && sourceIndex != targetIndex
      ? _apiPasteCopyConditionFormats(
          sourceSheet.conditionFormats,
          targetSheet.conditionFormats,
          sourceRange,
          applyRange,
        )
      : _sentinel;
  final nextSourceConditionFormats =
      clearSource && sourceRanges.length == 1 && sourceIndex != targetIndex
      ? _apiCutSourceConditionFormats(
          sourceSheet.conditionFormats,
          sourceRange,
          applyRange,
        )
      : _sentinel;
  final skipHiddenTargets = type == 'pasteHandlerOfCopyPaste';
  final clearedSource = <FortuneCellCoord>[];
  final touchedTargets = <FortuneCellCoord>[];
  if (clearSource) {
    for (var row = sourceRange.rowStart; row <= sourceRange.rowEnd; row += 1) {
      for (
        var column = sourceRange.columnStart;
        column <= sourceRange.columnEnd;
        column += 1
      ) {
        sourceCells.remove(FortuneCellCoord(row, column));
        sourceDataVerification.remove('${row}_$column');
        sourceHyperlinks.remove('${row}_$column');
        sourceRawDataVerification?.remove('${row}_$column');
        sourceRawHyperlinks?.remove('${row}_$column');
        if (sourceIndex == targetIndex) {
          targetDataVerification.remove('${row}_$column');
          targetHyperlinks.remove('${row}_$column');
          targetRawDataVerification?.remove('${row}_$column');
          targetRawHyperlinks?.remove('${row}_$column');
        }
        clearedSource.add(FortuneCellCoord(row, column));
      }
    }
    var nextSourceSheet = sourceSheet.copyWith(
      cells: sourceCells,
      dataVerification: sourceDataVerification,
      rawDataVerification: sourceRawDataVerification,
      hasRawDataVerification: sourceRawDataVerification != null,
      rawBorderInfo: _apiRawBorderInfoWithoutRanges(
        sourceSheet.rawBorderInfo,
        sourceRanges,
      ),
      hasRawBorderInfo: sourceSheet.hasRawBorderInfo,
      borderInfo: _apiClearFormatBorderInfo(
        sourceSheet.borderInfo,
        sourceRanges,
      ),
      conditionFormats: nextSourceConditionFormats,
      filter: filterMetadataUpdate == null ? null : const <String, Object?>{},
      rawFilter: filterMetadataUpdate == null ? _sentinel : null,
      hasRawFilter: filterMetadataUpdate == null ? null : false,
      filterSelect: filterMetadataUpdate == null ? _sentinel : null,
      hasRawFilterSelect: filterMetadataUpdate == null ? null : false,
      hyperlinks: sourceHyperlinks,
      rawHyperlinks: sourceRawHyperlinks,
      hasRawHyperlinks: sourceRawHyperlinks != null,
    );
    for (final coord in clearedSource) {
      nextSourceSheet = _apiSheetWithFunctionGroupCleanupAfterValueSet(
        sourceSheet,
        nextSourceSheet,
        coord.row,
        coord.column,
      );
    }
    nextSheets[sourceIndex] = nextSourceSheet;
    if (sourceIndex == targetIndex) {
      targetCells
        ..clear()
        ..addAll(sourceCells);
      nextRawBorderInfo = _apiRawBorderInfoListWithoutRanges(
        nextRawBorderInfo,
        sourceRanges,
      );
      touchedTargets.addAll(clearedSource);
    }
  }
  final cleared = <FortuneCellCoord>[];
  final copied = <String>[];
  for (var row = applyRange.rowStart; row <= applyRange.rowEnd; row += 1) {
    for (
      var column = applyRange.columnStart;
      column <= applyRange.columnEnd;
      column += 1
    ) {
      if (skipHiddenTargets &&
          (targetSheet.hiddenRows.contains(row) ||
              targetSheet.hiddenColumns.contains(column))) {
        continue;
      }
      final sourceSlot =
          sourceMatrix[(row - applyRange.rowStart) %
              sourceRows][(column - applyRange.columnStart) % sourceColumns];
      final sourceCoord = sourceSlot.coord;
      final targetCoord = FortuneCellCoord(row, column);
      final sourceCell = sourceSlot.cell;
      if (sourceCell == null) {
        targetCells.remove(targetCoord);
        cleared.add(targetCoord);
      } else {
        final targetCell = targetCells[targetCoord] ?? const FortuneCell();
        targetCells[targetCoord] = type == 'pasteHandlerOfPaintModel'
            ? _apiPaintTargetCell(targetCell, sourceCell)
            : _apiPasteTargetCell(
                sourceCell,
                sourceCoord,
                targetSheet.id,
                row,
                column,
                adjustFormula: type == 'pasteHandlerOfCopyPaste',
              );
        copied.add('${sourceCoord.row}_${sourceCoord.column}->${row}_$column');
      }
      touchedTargets.add(targetCoord);
      final sourceKey = '${sourceCoord.row}_${sourceCoord.column}';
      final targetKey = '${row}_$column';
      final sourceVerification = sourceSheet.dataVerification[sourceKey];
      if (sourceVerification != null) {
        targetDataVerification[targetKey] = cloneFortuneMetadata(
          sourceVerification,
        );
      }
      if (copiedRawDataVerification?.containsKey(sourceKey) == true) {
        targetRawDataVerification ??= <Object?, Object?>{};
        targetRawDataVerification[targetKey] = cloneFortuneMetadata(
          copiedRawDataVerification![sourceKey],
        );
      }
      final sourceHyperlink =
          sourceSheet.hyperlinks[sourceKey] ??
          _apiHyperlinkToMap(sourceCell?.hyperlink);
      if (sourceHyperlink != null) {
        targetHyperlinks[targetKey] = cloneFortuneMetadata(sourceHyperlink);
      }
      if (copiedRawHyperlinks?.containsKey(sourceKey) == true) {
        targetRawHyperlinks ??= <Object?, Object?>{};
        targetRawHyperlinks[targetKey] = cloneFortuneMetadata(
          copiedRawHyperlinks![sourceKey],
        );
      }
      _apiDropCopyBorderInfo(
        nextRawBorderInfo,
        sourceComputedBorders,
        sourceCoord,
        targetCoord,
      );
    }
  }
  var nextSheet = targetSheet.copyWith(
    cells: targetCells,
    rowCount: _apiExpandedCount(targetSheet.rowCount, applyRange.rowEnd),
    columnCount: _apiExpandedCount(
      targetSheet.columnCount,
      applyRange.columnEnd,
    ),
    dataVerification: targetDataVerification,
    rawDataVerification: targetRawDataVerification,
    hasRawDataVerification: targetRawDataVerification != null,
    filter: filterMetadataUpdate?.filter,
    rawFilter: filterMetadataUpdate == null
        ? _sentinel
        : filterMetadataUpdate.rawFilter,
    hasRawFilter: filterMetadataUpdate?.hasRawFilter,
    filterSelect: filterMetadataUpdate == null
        ? _sentinel
        : filterMetadataUpdate.filterSelect,
    hasRawFilterSelect: filterMetadataUpdate == null
        ? null
        : filterMetadataUpdate.filterSelect != null,
    hyperlinks: targetHyperlinks,
    rawHyperlinks: targetRawHyperlinks,
    hasRawHyperlinks: targetRawHyperlinks != null,
    rawBorderInfo: nextRawBorderInfo,
    hasRawBorderInfo:
        nextRawBorderInfo.isNotEmpty || targetSheet.hasRawBorderInfo,
    conditionFormats: nextConditionFormats,
    selectionSave: [_selectionRangeToApiMap(applyRange)],
  );
  for (final coord in touchedTargets) {
    nextSheet = _apiSheetWithFunctionGroupCleanupAfterValueSet(
      targetSheet,
      nextSheet,
      coord.row,
      coord.column,
    );
  }
  nextSheets[targetIndex] = nextSheet;
  final nextWorkbook = workbook.copyWith(sheets: nextSheets);
  final payload = <String, Object?>{
    'type': type,
    'workbook': nextWorkbook,
    'sheet': nextSheet,
    'sourceRange': _selectionRangeToApiMap(sourceRange),
    'applyRange': _selectionRangeToApiMap(applyRange),
    'copied': copied,
    'cleared': [for (final coord in cleared) '${coord.row}_${coord.column}'],
    if (clearSource)
      'clearedSource': [
        for (final coord in clearedSource) '${coord.row}_${coord.column}',
      ],
  };
  ctx[type] = payload;
  return payload;
}

FortuneCell _apiPaintTargetCell(
  FortuneCell targetCell,
  FortuneCell sourceCell,
) {
  return targetCell.copyWith(
    merge: sourceCell.merge,
    cellType: sourceCell.cellType,
    quotePrefix: sourceCell.quotePrefix,
    rawQuotePrefix: sourceCell.rawQuotePrefix,
    hasRawQuotePrefix: sourceCell.hasRawQuotePrefix,
    locked: sourceCell.locked,
    rawLocked: sourceCell.rawLocked,
    hasRawLocked: sourceCell.hasRawLocked,
    comment: sourceCell.comment,
    background: sourceCell.background,
    rawBackground: sourceCell.rawBackground,
    hasRawBackground: sourceCell.hasRawBackground,
    foreground: sourceCell.foreground,
    rawForeground: sourceCell.rawForeground,
    hasRawForeground: sourceCell.hasRawForeground,
    bold: sourceCell.bold,
    rawBold: sourceCell.rawBold,
    hasRawBold: sourceCell.hasRawBold,
    italic: sourceCell.italic,
    rawItalic: sourceCell.rawItalic,
    hasRawItalic: sourceCell.hasRawItalic,
    strikeThrough: sourceCell.strikeThrough,
    rawStrikeThrough: sourceCell.rawStrikeThrough,
    hasRawStrikeThrough: sourceCell.hasRawStrikeThrough,
    underline: sourceCell.underline,
    rawUnderline: sourceCell.rawUnderline,
    hasRawUnderline: sourceCell.hasRawUnderline,
    fontSize: sourceCell.fontSize,
    rawFontSize: sourceCell.rawFontSize,
    hasRawFontSize: sourceCell.hasRawFontSize,
    fontFamily: sourceCell.fontFamily,
    rawFontFamily: sourceCell.rawFontFamily,
    hasRawFontFamily: sourceCell.hasRawFontFamily,
    horizontalAlign: sourceCell.horizontalAlign,
    rawHorizontalAlign: sourceCell.rawHorizontalAlign,
    hasRawHorizontalAlign: sourceCell.hasRawHorizontalAlign,
    verticalAlign: sourceCell.verticalAlign,
    rawVerticalAlign: sourceCell.rawVerticalAlign,
    hasRawVerticalAlign: sourceCell.hasRawVerticalAlign,
    textWrap: sourceCell.textWrap,
    rawTextWrap: sourceCell.rawTextWrap,
    hasRawTextWrap: sourceCell.hasRawTextWrap,
    textRotation: sourceCell.textRotation,
    rawTextRotation: sourceCell.rawTextRotation,
    hasRawTextRotation: sourceCell.hasRawTextRotation,
    textRotationMode: sourceCell.textRotationMode,
    rawTextRotationMode: sourceCell.rawTextRotationMode,
    hasRawTextRotationMode: sourceCell.hasRawTextRotationMode,
    inlineRuns: sourceCell.inlineRuns,
  );
}

int? _apiExpandedCount(int? count, int lastIndex) {
  if (count == null) {
    return null;
  }
  return math.max(count, lastIndex + 1);
}

({
  Map<String, Object?> filter,
  Object? rawFilter,
  bool hasRawFilter,
  Object? filterSelect,
})?
_apiFilterMetadataForCutPaste({
  required Map<String, Object?> sourceFilter,
  required Object? sourceRawFilter,
  required Object? sourceFilterSelect,
  required FortuneRange sourceRange,
  required FortuneRange applyRange,
  required bool hasRawFilter,
}) {
  if (sourceFilter.isEmpty && !hasRawFilter && sourceFilterSelect == null) {
    return null;
  }
  final sourceFilterRange = _apiRangeFromFilterSelectMetadata(
    sourceFilterSelect,
  );
  if (sourceFilterRange == null ||
      !_apiRangeContainsRange(sourceRange, sourceFilterRange)) {
    return null;
  }
  final visibleRows = [
    for (var row = sourceRange.rowStart; row <= sourceRange.rowEnd; row += 1)
      row,
  ];
  final visibleColumns = [
    for (
      var column = sourceRange.columnStart;
      column <= sourceRange.columnEnd;
      column += 1
    )
      column,
  ];
  final filterSelect = _apiTranslateFilterRangeMetadata(
    sourceFilterSelect,
    targetRange: applyRange,
    copiedVisibleRows: visibleRows,
    copiedVisibleColumns: visibleColumns,
  );
  final filterSelectRange = _apiRangeFromFilterSelectMetadata(filterSelect);
  return (
    filter: _apiTranslatedFilterMap(
      sourceFilter,
      filterSelectRange: filterSelectRange,
      fallbackTargetRange: applyRange,
      copiedVisibleRows: visibleRows,
      copiedVisibleColumns: visibleColumns,
    ),
    rawFilter: hasRawFilter
        ? _apiTranslatedRawFilter(
            sourceRawFilter,
            filterSelectRange: filterSelectRange,
            fallbackTargetRange: applyRange,
            copiedVisibleRows: visibleRows,
            copiedVisibleColumns: visibleColumns,
          )
        : null,
    hasRawFilter: hasRawFilter,
    filterSelect: filterSelect,
  );
}

Map<String, Object?> _apiTranslatedFilterMap(
  Map<String, Object?> sourceFilter, {
  required FortuneRange? filterSelectRange,
  required FortuneRange fallbackTargetRange,
  required List<int> copiedVisibleRows,
  required List<int> copiedVisibleColumns,
}) {
  final filter = <String, Object?>{};
  for (final entry in sourceFilter.entries) {
    final raw = entry.value;
    if (raw is! Map) {
      filter[_apiTranslateFilterKey(
        entry.key,
        targetStart: fallbackTargetRange.columnStart,
        copiedVisibleIndexes: copiedVisibleColumns,
      )] = cloneFortuneMetadata(
        raw,
      );
      continue;
    }
    final config = Map<String, Object?>.from(cloneFortuneMetadata(raw) as Map);
    _apiTranslateFilterConfig(
      config,
      targetRange: filterSelectRange,
      fallbackTargetRange: fallbackTargetRange,
      copiedVisibleRows: copiedVisibleRows,
      copiedVisibleColumns: copiedVisibleColumns,
    );
    final cindex = _nullableIntArg(config['cindex']);
    final key = cindex != null && filterSelectRange != null
        ? '${cindex - filterSelectRange.columnStart}'
        : _apiTranslateFilterKey(
            entry.key,
            targetStart: fallbackTargetRange.columnStart,
            copiedVisibleIndexes: copiedVisibleColumns,
          );
    filter[key] = config;
  }
  return filter;
}

Object? _apiTranslatedRawFilter(
  Object? rawFilter, {
  required FortuneRange? filterSelectRange,
  required FortuneRange fallbackTargetRange,
  required List<int> copiedVisibleRows,
  required List<int> copiedVisibleColumns,
}) {
  if (rawFilter is! Map) {
    return cloneFortuneMetadata(rawFilter);
  }
  return _apiTranslatedFilterMap(
    {
      for (final entry in rawFilter.entries)
        '${entry.key}': cloneFortuneMetadata(entry.value),
    },
    filterSelectRange: filterSelectRange,
    fallbackTargetRange: fallbackTargetRange,
    copiedVisibleRows: copiedVisibleRows,
    copiedVisibleColumns: copiedVisibleColumns,
  );
}

String _apiTranslateFilterKey(
  String key, {
  required int targetStart,
  required List<int> copiedVisibleIndexes,
}) {
  final column = int.tryParse(key);
  if (column == null) {
    return key;
  }
  final mapped = _apiMapVisibleIndex(
    column,
    copiedVisibleIndexes: copiedVisibleIndexes,
    targetStart: targetStart,
  );
  return '${mapped ?? column}';
}

void _apiTranslateFilterConfig(
  Map<String, Object?> config, {
  required FortuneRange? targetRange,
  required FortuneRange fallbackTargetRange,
  required List<int> copiedVisibleRows,
  required List<int> copiedVisibleColumns,
}) {
  final rowTargetStart = targetRange?.rowStart ?? fallbackTargetRange.rowStart;
  final columnTargetStart =
      targetRange?.columnStart ?? fallbackTargetRange.columnStart;
  final rowRange = _apiMapVisibleRange(
    _nullableIntArg(config['str']),
    _nullableIntArg(config['edr']),
    copiedVisibleIndexes: copiedVisibleRows,
    targetStart: rowTargetStart,
  );
  if (rowRange != null) {
    config['str'] = rowRange.$1;
    config['edr'] = rowRange.$2;
  }
  final columnRange = _apiMapVisibleRange(
    _nullableIntArg(config['stc']),
    _nullableIntArg(config['edc']),
    copiedVisibleIndexes: copiedVisibleColumns,
    targetStart: columnTargetStart,
  );
  if (columnRange != null) {
    config['stc'] = columnRange.$1;
    config['edc'] = columnRange.$2;
  }
  final cindex = _nullableIntArg(config['cindex']);
  if (cindex != null) {
    final mapped = _apiMapVisibleIndex(
      cindex,
      copiedVisibleIndexes: copiedVisibleColumns,
      targetStart: columnTargetStart,
    );
    if (mapped != null) {
      config['cindex'] = mapped;
    }
  }
  final rowhidden = config['rowhidden'];
  if (rowhidden is Map) {
    final translated = <String, Object?>{};
    for (final entry in rowhidden.entries) {
      final row = _nullableIntArg(entry.key);
      final mapped = row == null
          ? null
          : _apiMapVisibleIndex(
              row,
              copiedVisibleIndexes: copiedVisibleRows,
              targetStart: rowTargetStart,
            );
      if (mapped != null) {
        translated['$mapped'] = cloneFortuneMetadata(entry.value);
      }
    }
    if (translated.isEmpty) {
      config.remove('rowhidden');
    } else {
      config['rowhidden'] = translated;
    }
  }
}

Object? _apiTranslateFilterRangeMetadata(
  Object? raw, {
  required FortuneRange targetRange,
  required List<int> copiedVisibleRows,
  required List<int> copiedVisibleColumns,
  String? key,
}) {
  if (raw is Map) {
    return {
      for (final entry in raw.entries)
        entry.key: _apiTranslateFilterRangeMetadata(
          entry.value,
          targetRange: targetRange,
          copiedVisibleRows: copiedVisibleRows,
          copiedVisibleColumns: copiedVisibleColumns,
          key: '${entry.key}',
        ),
    };
  }
  if (raw is List) {
    if (key == 'row') {
      return _apiTranslateNumericFilterList(
        raw,
        targetStart: targetRange.rowStart,
        copiedVisibleIndexes: copiedVisibleRows,
      );
    }
    if (key == 'column') {
      return _apiTranslateNumericFilterList(
        raw,
        targetStart: targetRange.columnStart,
        copiedVisibleIndexes: copiedVisibleColumns,
      );
    }
    return [
      for (final item in raw)
        _apiTranslateFilterRangeMetadata(
          item,
          targetRange: targetRange,
          copiedVisibleRows: copiedVisibleRows,
          copiedVisibleColumns: copiedVisibleColumns,
        ),
    ];
  }
  final value = _nullableIntArg(raw);
  if (value != null) {
    if (key == 'row_focus' || key == 'r') {
      return _apiMapVisibleIndex(
            value,
            copiedVisibleIndexes: copiedVisibleRows,
            targetStart: targetRange.rowStart,
          ) ??
          value;
    }
    if (key == 'column_focus' || key == 'c') {
      return _apiMapVisibleIndex(
            value,
            copiedVisibleIndexes: copiedVisibleColumns,
            targetStart: targetRange.columnStart,
          ) ??
          value;
    }
  }
  return cloneFortuneMetadata(raw);
}

List<Object?> _apiTranslateNumericFilterList(
  List raw, {
  required int targetStart,
  required List<int> copiedVisibleIndexes,
}) {
  if (raw.length >= 2) {
    final range = _apiMapVisibleRange(
      _nullableIntArg(raw[0]),
      _nullableIntArg(raw[1]),
      copiedVisibleIndexes: copiedVisibleIndexes,
      targetStart: targetStart,
    );
    if (range != null) {
      return [range.$1, range.$2, ...raw.skip(2)];
    }
  }
  return [
    for (final item in raw)
      if (_nullableIntArg(item) case final value?)
        _apiMapVisibleIndex(
              value,
              copiedVisibleIndexes: copiedVisibleIndexes,
              targetStart: targetStart,
            ) ??
            item
      else
        cloneFortuneMetadata(item),
  ];
}

int? _apiMapVisibleIndex(
  int value, {
  required List<int> copiedVisibleIndexes,
  required int targetStart,
}) {
  final index = copiedVisibleIndexes.indexOf(value);
  return index < 0 ? null : targetStart + index;
}

(int, int)? _apiMapVisibleRange(
  int? start,
  int? end, {
  required List<int> copiedVisibleIndexes,
  required int targetStart,
}) {
  if (start == null || end == null) {
    return null;
  }
  final lower = math.min(start, end);
  final upper = math.max(start, end);
  final mapped = <int>[
    for (var i = 0; i < copiedVisibleIndexes.length; i += 1)
      if (copiedVisibleIndexes[i] >= lower && copiedVisibleIndexes[i] <= upper)
        targetStart + i,
  ];
  if (mapped.isEmpty) {
    return null;
  }
  return (mapped.first, mapped.last);
}

FortuneRange? _apiRangeFromFilterSelectMetadata(Object? raw) {
  if (raw is! Map) {
    return null;
  }
  final row = raw['row'];
  final column = raw['column'];
  if (row is! List || column is! List || row.length < 2 || column.length < 2) {
    return null;
  }
  final rowStart = _nullableIntArg(row[0]);
  final rowEnd = _nullableIntArg(row[1]);
  final columnStart = _nullableIntArg(column[0]);
  final columnEnd = _nullableIntArg(column[1]);
  if (rowStart == null ||
      rowEnd == null ||
      columnStart == null ||
      columnEnd == null) {
    return null;
  }
  return FortuneRange(
    rowStart: rowStart,
    rowEnd: rowEnd,
    columnStart: columnStart,
    columnEnd: columnEnd,
  );
}

bool _apiRangeContainsRange(FortuneRange outer, FortuneRange inner) {
  return inner.rowStart >= outer.rowStart &&
      inner.rowEnd <= outer.rowEnd &&
      inner.columnStart >= outer.columnStart &&
      inner.columnEnd <= outer.columnEnd;
}

FortuneCell _apiPasteTargetCell(
  FortuneCell sourceCell,
  FortuneCellCoord sourceCoord,
  String targetSheetId,
  int row,
  int column, {
  bool adjustFormula = false,
}) {
  var nextCell = sourceCell.copyWith();
  final sourceFormula = _apiCellFormulaText(sourceCell);
  if (adjustFormula && sourceFormula != null) {
    var formula = sourceFormula;
    final rowDelta = row - sourceCoord.row;
    final columnDelta = column - sourceCoord.column;
    if (rowDelta > 0) {
      formula = functionCopy(formula, 'down', rowDelta);
    } else if (rowDelta < 0) {
      formula = functionCopy(formula, 'up', rowDelta.abs());
    }
    if (columnDelta > 0) {
      formula = functionCopy(formula, 'right', columnDelta);
    } else if (columnDelta < 0) {
      formula = functionCopy(formula, 'left', columnDelta.abs());
    }
    final nextFormula = formula.startsWith('=') ? formula : '=$formula';
    nextCell = nextCell.copyWith(
      formula: nextFormula,
      rawFormula: sourceCell.hasRawFormula ? nextFormula : _sentinel,
      hasRawFormula: sourceCell.hasRawFormula,
    );
  }
  final hyperlink = sourceCell.hyperlink;
  if (hyperlink == null) {
    return nextCell;
  }
  return nextCell.copyWith(
    hyperlink: hyperlink.copyWith(row: row, column: column, id: targetSheetId),
  );
}

String? _apiCellFormulaText(FortuneCell? cell) {
  if (cell == null) {
    return null;
  }
  if (cell.formula != null) {
    return cell.formula;
  }
  final rawFormula = cell.hasRawFormula ? cell.rawFormula : null;
  return rawFormula is String ? rawFormula : null;
}

bool _apiCellHasFormulaMetadata(FortuneCell? cell) {
  return cell?.formula != null ||
      (cell?.hasRawFormula == true && cell?.rawFormula != null);
}

Map<String, Object?>? _apiHyperlinkToMap(FortuneHyperlink? hyperlink) {
  if (hyperlink == null) {
    return null;
  }
  final linkType = hyperlink.linkType;
  final linkAddress = hyperlink.linkAddress;
  if (linkType == null && linkAddress == null) {
    return null;
  }
  final link = <String, Object?>{};
  if (linkType != null) {
    link['linkType'] = linkType;
  }
  if (linkAddress != null) {
    link['linkAddress'] = linkAddress;
  }
  return link;
}

class _ApiCopyCellSlot {
  const _ApiCopyCellSlot(this.coord, this.cell);

  final FortuneCellCoord coord;
  final FortuneCell? cell;
}

List<FortuneRange> _apiCopySaveRanges(Map<String, Object?> copyRange) {
  final rawCopyRange = copyRange['copyRange'];
  if (rawCopyRange is List && rawCopyRange.isNotEmpty) {
    final ranges = <FortuneRange>[];
    for (final range in rawCopyRange) {
      if (range is Map) {
        final parsed = _selectionRangeFromApiMap(range);
        if (parsed != null) {
          ranges.add(parsed);
        }
      }
    }
    return ranges;
  }
  final range = _selectionRangeFromApiMap(copyRange);
  return range == null ? const [] : [range];
}

List<List<_ApiCopyCellSlot>>? _apiCopySourceMatrix(
  FortuneSheet sourceSheet,
  List<FortuneRange> ranges,
) {
  if (ranges.isEmpty) {
    return null;
  }
  final first = ranges.first;
  final sameRows =
      ranges.length > 1 &&
      ranges.every(
        (range) =>
            range.rowStart == first.rowStart && range.rowEnd == first.rowEnd,
      );
  final sameColumns =
      ranges.length > 1 &&
      ranges.every(
        (range) =>
            range.columnStart == first.columnStart &&
            range.columnEnd == first.columnEnd,
      );
  final effectiveRanges = sameRows || sameColumns || ranges.length == 1
      ? ranges
      : <FortuneRange>[first];
  final stripFormula = effectiveRanges.length > 1;
  final matrix = <List<_ApiCopyCellSlot>>[];
  if (sameRows) {
    for (var row = first.rowStart; row <= first.rowEnd; row += 1) {
      final rowSlots = <_ApiCopyCellSlot>[];
      for (final range in effectiveRanges) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          rowSlots.add(
            _apiCopyCellSlot(sourceSheet, row, column, stripFormula),
          );
        }
      }
      matrix.add(rowSlots);
    }
    return matrix;
  }
  for (final range in effectiveRanges) {
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      final rowSlots = <_ApiCopyCellSlot>[];
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        rowSlots.add(_apiCopyCellSlot(sourceSheet, row, column, stripFormula));
      }
      matrix.add(rowSlots);
    }
  }
  return matrix;
}

_ApiCopyCellSlot _apiCopyCellSlot(
  FortuneSheet sourceSheet,
  int row,
  int column,
  bool stripFormula,
) {
  final coord = FortuneCellCoord(row, column);
  final cell = sourceSheet.cells[coord];
  if (cell == null) {
    return _ApiCopyCellSlot(coord, null);
  }
  if (!stripFormula) {
    return _ApiCopyCellSlot(coord, cell.copyWith());
  }
  return _ApiCopyCellSlot(
    coord,
    cell.copyWith(
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      sparkline: null,
      rawSparkline: null,
      hasSparkline: false,
      hasRawSparkline: false,
    ),
  );
}

Map<String, Object?> handleColSizeHandleMouseDown({
  required num pageX,
  required num headerLeft,
  required List<num> visibleDataColumns,
  num windowScrollX = 0,
  num scrollLeft = 0,
  num scrollTop = 0,
  num cellAreaHeight = 0,
  Object? freeze,
}) {
  final mouseX = pageX - headerLeft - windowScrollX;
  final rawX = mouseX + scrollLeft;
  final fixed = fixPositionOnFrozenCells(
    freeze,
    x: rawX,
    y: 0,
    mouseX: mouseX,
    mouseY: 0,
  );
  final column = colLocation(fixed['x']! as num, visibleDataColumns);
  final columnEnd = column[1];
  final columnIndex = column[2].toInt();
  return {
    'type': 'colSizeHandleMouseDown',
    'luckysheetCellUpdate': <int>[],
    'luckysheetColsChangeSize': true,
    'luckysheetScrollStatus': true,
    'luckysheetColsChangeSizeStart': [rawX, columnIndex],
    'changeSizeLineStyle': {
      'height': '${cellAreaHeight + scrollTop}px',
      'borderWidth': '0 1px 0 0',
      'top': '0',
      'left': '${columnEnd - 3}px',
      'width': '1px',
    },
    'stopPropagation': true,
  };
}

