Map<String, Object?> handleRowSizeHandleMouseUp({
  required num pageY,
  required num containerTop,
  required num columnHeaderHeight,
  required num containerHeight,
  required num scrollTop,
  required num startY,
  required int rowIndex,
  required List<num> visibleDataRows,
  List<FortuneRange> selections = const [],
  num defaultRowLength = 19,
  num zoomRatio = 1,
}) {
  final y = pageY - containerTop - columnHeaderHeight + scrollTop;
  var delta = y + 3 - startY;
  if (y >= containerHeight - 20 + scrollTop) {
    delta = containerHeight - 20 - startY + scrollTop;
  }
  var size = defaultRowLength;
  if (rowIndex >= 0 && rowIndex < visibleDataRows.length) {
    size =
        visibleDataRows[rowIndex] -
        (rowIndex > 0 ? visibleDataRows[rowIndex - 1] : 0);
  }
  size = math.max<num>(10, size + delta);
  final appliedSize = (size / zoomRatio).ceil();
  final rowLengths = <int, int>{};
  final selectedRows = selections.where(
    (selection) => selection.extraFields['row_select'] == true,
  );
  final applySelected = selectedRows.any(
    (selection) =>
        rowIndex >= selection.rowStart && rowIndex <= selection.rowEnd,
  );
  if (applySelected) {
    for (final selection in selectedRows) {
      for (var row = selection.rowStart; row <= selection.rowEnd; row += 1) {
        rowLengths[row] = appliedSize;
      }
    }
  } else {
    rowLengths[rowIndex] = appliedSize;
  }
  return {
    'type': 'rowSizeHandleMouseUp',
    'row': rowIndex,
    'size': appliedSize,
    'rawSize': size,
    'delta': delta,
    'rowlen': rowLengths,
    'customHeight': {for (final row in rowLengths.keys) row: 1},
  };
}

Map<String, Object?>? handleColSizeHandleMouseUp({
  required num pageX,
  required num containerLeft,
  required num rowHeaderWidth,
  required num containerWidth,
  required num scrollLeft,
  required num startX,
  required int columnIndex,
  List<FortuneRange> selections = const [],
  Map<int, num> columnLengths = const {},
  num defaultColumnLength = 73,
  num zoomRatio = 1,
}) {
  final x = pageX - containerLeft - rowHeaderWidth + scrollLeft;
  var delta = x + 3 - startX;
  if (x >= containerWidth - 100 + scrollLeft) {
    delta = containerWidth - 100 - startX + scrollLeft;
  }
  delta /= zoomRatio;
  final firstColumnLength = columnLengths[columnIndex] ?? defaultColumnLength;
  var size = (columnLengths[columnIndex] ?? defaultColumnLength) + delta;
  if ((size - firstColumnLength).abs() < 3) {
    return null;
  }
  size = math.max<num>(10, size);
  final appliedSize = (size / zoomRatio).ceil();
  final nextColumnLengths = <int, int>{};
  final selectedColumns = selections.where(
    (selection) => selection.extraFields['column_select'] == true,
  );
  final applySelected = selectedColumns.any(
    (selection) =>
        columnIndex >= selection.columnStart &&
        columnIndex <= selection.columnEnd,
  );
  if (applySelected) {
    for (final selection in selectedColumns) {
      for (
        var col = selection.columnStart;
        col <= selection.columnEnd;
        col += 1
      ) {
        nextColumnLengths[col] = appliedSize;
      }
    }
  } else {
    nextColumnLengths[columnIndex] = appliedSize;
  }
  return {
    'type': 'colSizeHandleMouseUp',
    'column': columnIndex,
    'size': appliedSize,
    'rawSize': size,
    'delta': delta,
    'columnlen': nextColumnLengths,
    'customWidth': {for (final column in nextColumnLengths.keys) column: 1},
  };
}

Map<String, Object?> handleColFreezeHandleMouseUp({
  required num pageX,
  required num containerLeft,
  required num rowHeaderWidth,
  required num scrollLeft,
  required List<num> visibleDataColumns,
  FortuneFrozenPane? currentFrozen,
}) {
  final x = pageX - containerLeft - rowHeaderWidth + scrollLeft;
  final location = colLocation(x, visibleDataColumns);
  final columnIndex = x > (location[1] + location[0]) / 2
      ? location[2].toInt()
      : location[2].toInt() - 1;
  FortuneFrozenPane? nextFrozen;
  if (columnIndex < 0) {
    nextFrozen = switch (currentFrozen?.type) {
      'rangeBoth' || 'both' => currentFrozen!.copyWith(type: 'rangeRow'),
      'column' || 'rangeColumn' => null,
      _ => currentFrozen,
    };
  } else if (currentFrozen == null) {
    nextFrozen = FortuneFrozenPane(
      type: 'rangeColumn',
      rowFocus: 0,
      columnFocus: columnIndex,
    );
  } else {
    final nextType = switch (currentFrozen.type) {
      'rangeRow' || 'row' => 'rangeBoth',
      _ => currentFrozen.type,
    };
    nextFrozen = currentFrozen.copyWith(
      type: nextType,
      columnFocus: columnIndex,
      rowFocus: currentFrozen.rowFocus ?? 0,
    );
  }
  return {
    'type': 'colFreezeHandleMouseUp',
    'column': columnIndex,
    'frozen': _apiFrozenPanePayload(nextFrozen),
  };
}

Map<String, Object?> handleRowFreezeHandleMouseUp({
  required num pageY,
  required num containerTop,
  required num columnHeaderHeight,
  required num scrollTop,
  required List<num> visibleDataRows,
  FortuneFrozenPane? currentFrozen,
}) {
  final y = pageY - containerTop - columnHeaderHeight + scrollTop;
  final location = rowLocation(y, visibleDataRows);
  final rowIndex = y > (location[1] + location[0]) / 2
      ? location[2].toInt()
      : location[2].toInt() - 1;
  FortuneFrozenPane? nextFrozen;
  if (rowIndex < 0) {
    nextFrozen = switch (currentFrozen?.type) {
      'rangeBoth' || 'both' => currentFrozen!.copyWith(type: 'rangeColumn'),
      'row' || 'rangeRow' => null,
      _ => currentFrozen,
    };
  } else if (currentFrozen == null) {
    nextFrozen = FortuneFrozenPane(
      type: 'rangeRow',
      rowFocus: rowIndex,
      columnFocus: 0,
    );
  } else {
    final nextType = switch (currentFrozen.type) {
      'rangeColumn' || 'column' => 'rangeBoth',
      _ => currentFrozen.type,
    };
    nextFrozen = currentFrozen.copyWith(
      type: nextType,
      rowFocus: rowIndex,
      columnFocus: currentFrozen.columnFocus ?? 0,
    );
  }
  return {
    'type': 'rowFreezeHandleMouseUp',
    'row': rowIndex,
    'frozen': _apiFrozenPanePayload(nextFrozen),
  };
}

Map<String, Object?>? _apiFrozenPanePayload(FortuneFrozenPane? frozen) {
  if (frozen == null) {
    return null;
  }
  return {
    for (final entry in frozen.extraFields.entries)
      entry.key: cloneFortuneMetadata(entry.value),
    'type': frozen.type,
    'range': {
      for (final entry in frozen.rangeExtraFields.entries)
        entry.key: cloneFortuneMetadata(entry.value),
      if (frozen.columnFocus != null) 'column_focus': frozen.columnFocus,
      if (frozen.rowFocus != null) 'row_focus': frozen.rowFocus,
    },
  };
}

Map<String, Object?>? handleContextMenu({
  required String area,
  required num pageX,
  required num pageY,
  required num workbookLeft,
  required num workbookTop,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  List<FortuneRange> selections = const [],
  List<Object?> cellContextMenu = const [true],
  bool allowEdit = true,
  bool ctrlKey = false,
  bool metaKey = false,
  num windowScrollX = 0,
  num windowScrollY = 0,
  num scrollLeft = 0,
  num scrollTop = 0,
  Object? freeze,
}) {
  if (!allowEdit || cellContextMenu.isEmpty) {
    return null;
  }
  final contextMenu = <String, Object?>{
    'x': pageX - workbookLeft,
    'y': pageY - workbookTop,
    'pageX': pageX,
    'pageY': pageY,
  };
  Map<String, Object?> result({String? headerMenu, Object? selection}) {
    return {
      'type': 'contextMenu',
      'area': area,
      'contextMenu': {...contextMenu, 'headerMenu': ?headerMenu},
      'selection': ?selection,
      'preventDefault': true,
    };
  }

  if (area == 'cell') {
    final mouseX = pageX - containerLeft - windowScrollX;
    final mouseY = pageY - containerTop - windowScrollY;
    final fixed = fixPositionOnFrozenCells(
      freeze,
      x: mouseX + scrollLeft,
      y: mouseY + scrollTop,
      mouseX: mouseX,
      mouseY: mouseY,
    );
    final row = rowLocation(fixed['y']! as num, visibleDataRows);
    final column = colLocation(fixed['x']! as num, visibleDataColumns);
    final rowIndex = row[2].toInt();
    final columnIndex = column[2].toInt();
    final isInSelection = selections.any(
      (selection) =>
          rowIndex >= selection.rowStart &&
          rowIndex <= selection.rowEnd &&
          columnIndex >= selection.columnStart &&
          columnIndex <= selection.columnEnd,
    );
    if (isInSelection) {
      return result();
    }
    final selection = {
      'mode': ctrlKey || metaKey ? 'append' : 'replace',
      'range': {
        'left': column[0],
        'width': column[1] - column[0] - 1,
        'top': row[0],
        'height': row[1] - row[0] - 1,
        'left_move': column[0],
        'width_move': column[1] - column[0] - 1,
        'top_move': row[0],
        'height_move': row[1] - row[0] - 1,
        'row': [rowIndex, rowIndex],
        'column': [columnIndex, columnIndex],
        'row_focus': rowIndex,
        'column_focus': columnIndex,
      },
    };
    return result(selection: selection);
  }

  if (area == 'rowHeader') {
    final mouseY = pageY - containerTop - windowScrollY;
    final fixed = fixPositionOnFrozenCells(
      freeze,
      x: 0,
      y: mouseY + scrollTop,
      mouseX: 0,
      mouseY: mouseY,
    );
    final row = rowLocation(fixed['y']! as num, visibleDataRows);
    final rowIndex = row[2].toInt();
    final isInSelection = selections.any(
      (selection) =>
          rowIndex >= selection.rowStart &&
          rowIndex <= selection.rowEnd &&
          selection.extraFields['column_select'] != true,
    );
    if (isInSelection) {
      return result(headerMenu: 'row');
    }
    final lastColumnIndex = math.max(0, visibleDataColumns.length - 1).toInt();
    final lastColumnEnd = visibleDataColumns.isEmpty
        ? 0
        : visibleDataColumns[lastColumnIndex];
    return result(
      headerMenu: 'row',
      selection: {
        'mode': 'replace',
        'range': {
          'left': colLocationByIndex(0, visibleDataColumns)[0],
          'width':
              colLocationByIndex(0, visibleDataColumns)[1] -
              colLocationByIndex(0, visibleDataColumns)[0] -
              1,
          'top': row[0],
          'height': row[1] - row[0] - 1,
          'left_move': 0,
          'width_move': lastColumnEnd - 1,
          'top_move': row[0],
          'height_move': row[1] - row[0] - 1,
          'row': [rowIndex, rowIndex],
          'column': [0, lastColumnIndex],
          'row_focus': rowIndex,
          'column_focus': 0,
          'row_select': true,
        },
      },
    );
  }

  if (area == 'columnHeader') {
    final mouseX = pageX - containerLeft - windowScrollX;
    final fixed = fixPositionOnFrozenCells(
      freeze,
      x: mouseX + scrollLeft,
      y: 0,
      mouseX: mouseX,
      mouseY: 0,
    );
    final column = colLocation(fixed['x']! as num, visibleDataColumns);
    final columnIndex = column[2].toInt();
    final isInSelection = selections.any(
      (selection) =>
          columnIndex >= selection.columnStart &&
          columnIndex <= selection.columnEnd &&
          selection.extraFields['row_select'] != true,
    );
    if (isInSelection) {
      return result(headerMenu: 'column');
    }
    final lastRowIndex = math.max(0, visibleDataRows.length - 1).toInt();
    final lastRowEnd = visibleDataRows.isEmpty
        ? 0
        : visibleDataRows[lastRowIndex];
    return result(
      headerMenu: 'column',
      selection: {
        'mode': 'replace',
        'range': {
          'left': column[0],
          'width': column[1] - column[0] - 1,
          'top': rowLocationByIndex(0, visibleDataRows)[0],
          'height':
              rowLocationByIndex(0, visibleDataRows)[1] -
              rowLocationByIndex(0, visibleDataRows)[0] -
              1,
          'left_move': column[0],
          'width_move': column[1] - column[0] - 1,
          'top_move': 0,
          'height_move': lastRowEnd - 1,
          'row': [0, lastRowIndex],
          'column': [columnIndex, columnIndex],
          'row_focus': 0,
          'column_focus': columnIndex,
          'column_select': true,
        },
      },
    );
  }
  return result();
}

Map<String, Object?>? handleCellAreaDoubleClick({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num scrollLeft = 0,
  num scrollTop = 0,
  Object? freeze,
  bool allowEdit = true,
  bool formulaRangeActive = false,
  Set<String> checkboxCells = const <String>{},
  int? selectionFocusRow,
  int? selectionFocusColumn,
}) {
  if (formulaRangeActive || !allowEdit) {
    return null;
  }
  final mouseX = pageX - containerLeft;
  final mouseY = pageY - containerTop;

  final fixed = fixPositionOnFrozenCells(
    freeze,
    x: mouseX + scrollLeft,
    y: mouseY + scrollTop,
    mouseX: mouseX,
    mouseY: mouseY,
  );
  final row = rowLocation(fixed['y']! as num, visibleDataRows);
  final column = colLocation(fixed['x']! as num, visibleDataColumns);
  var rowIndex = row[2].toInt();
  var columnIndex = column[2].toInt();
  if (checkboxCells.contains('${rowIndex}_$columnIndex')) {
    return null;
  }
  if (selectionFocusRow != null &&
      selectionFocusColumn != null &&
      (selectionFocusRow != rowIndex || selectionFocusColumn != columnIndex)) {
    rowIndex = selectionFocusRow;
    columnIndex = selectionFocusColumn;
  }
  return {
    'type': 'updateCell',
    'row': rowIndex,
    'column': columnIndex,
    'mouse': {'x': mouseX, 'y': mouseY},
    'cellPosition': {'row': row, 'column': column},
  };
}

Map<String, Object?>? handleCellAreaMouseDown({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required num containerWidth,
  required num containerHeight,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  List<FortuneRange> selections = const [],
  num scrollLeft = 0,
  num scrollTop = 0,
  Object? freeze,
  bool ctrlKey = false,
  bool metaKey = false,
  bool rightButton = false,
}) {
  final mouseX = pageX - containerLeft;
  final mouseY = pageY - containerTop;
  final rawX = mouseX + scrollLeft;
  final rawY = mouseY + scrollTop;
  if (rawX >= containerWidth + scrollLeft ||
      rawY >= containerHeight + scrollTop) {
    return null;
  }
  final fixed = fixPositionOnFrozenCells(
    freeze,
    x: rawX,
    y: rawY,
    mouseX: mouseX,
    mouseY: mouseY,
  );
  final rowLocationPayload = rowLocation(fixed['y']! as num, visibleDataRows);
  final columnLocationPayload = colLocation(
    fixed['x']! as num,
    visibleDataColumns,
  );
  final rowIndex = rowLocationPayload[2].toInt();
  final columnIndex = columnLocationPayload[2].toInt();
  if (rightButton &&
      selections.any(
        (selection) =>
            rowIndex >= selection.rowStart &&
            rowIndex <= selection.rowEnd &&
            columnIndex >= selection.columnStart &&
            columnIndex <= selection.columnEnd,
      )) {
    return null;
  }
  final rowPre = rowLocationPayload[0];
  final row = rowLocationPayload[1];
  final columnPre = columnLocationPayload[0];
  final column = columnLocationPayload[1];
  final selection = {
    'left': columnPre,
    'width': column - columnPre - 1,
    'top': rowPre,
    'height': row - rowPre - 1,
    'left_move': columnPre,
    'width_move': column - columnPre - 1,
    'top_move': rowPre,
    'height_move': row - rowPre - 1,
    'row': [rowIndex, rowIndex],
    'column': [columnIndex, columnIndex],
    'row_focus': rowIndex,
    'column_focus': columnIndex,
  };
  return {
    'type': 'cellAreaMouseDown',
    'mouse': {'x': mouseX, 'y': mouseY},
    'cell': {
      'row': rowIndex,
      'column': columnIndex,
      'rowLocation': rowLocationPayload,
      'columnLocation': columnLocationPayload,
    },
    'scrollStatus': true,
    'selectionMode': (ctrlKey || metaKey) ? 'append' : 'replace',
    'selection': selection,
  };
}

Map<String, Object?>? handleRowHeaderMouseDown({
  required num pageY,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  List<FortuneRange> selections = const [],
  num scrollTop = 0,
  Object? freeze,
  bool ctrlKey = false,
  bool metaKey = false,
  bool rightButton = false,
  bool protectedAllSelected = true,
}) {
  if (!protectedAllSelected ||
      visibleDataRows.isEmpty ||
      visibleDataColumns.isEmpty) {
    return null;
  }
  final mouseY = pageY - containerTop;
  final fixed = fixPositionOnFrozenCells(
    freeze,
    x: 0,
    y: mouseY + scrollTop,
    mouseX: 0,
    mouseY: mouseY,
  );
  final rowLocationPayload = rowLocation(fixed['y']! as num, visibleDataRows);
  final rowIndex = rowLocationPayload[2].toInt();
  final columnIndex = visibleDataColumns.length - 1;
  if (rightButton &&
      selections.any(
        (selection) =>
            rowIndex >= selection.rowStart &&
            rowIndex <= selection.rowEnd &&
            selection.columnStart == 0 &&
            selection.columnEnd == columnIndex,
      )) {
    return null;
  }
  final rowPre = rowLocationPayload[0];
  final row = rowLocationPayload[1];
  final firstColumn = colLocationByIndex(0, visibleDataColumns);
  final selection = {
    'left': firstColumn[0],
    'width': firstColumn[1] - firstColumn[0] - 1,
    'top': rowPre,
    'height': row - rowPre - 1,
    'left_move': 0,
    'width_move': visibleDataColumns[columnIndex] - 1,
    'top_move': rowPre,
    'height_move': row - rowPre - 1,
    'row': [rowIndex, rowIndex],
    'column': [0, columnIndex],
    'row_focus': rowIndex,
    'column_focus': 0,
    'row_select': true,
  };
  return {
    'type': 'rowHeaderMouseDown',
    'row': rowIndex,
    'selectionMode': (ctrlKey || metaKey) ? 'append' : 'replace',
    'rowsSelectedStatus': true,
    'selectStatus': !(ctrlKey || metaKey),
    'scrollStatus': true,
    'selection': selection,
  };
}

Map<String, Object?>? handleColumnHeaderMouseDown({
  required num pageX,
  required num containerLeft,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  List<FortuneRange> selections = const [],
  num scrollLeft = 0,
  Object? freeze,
  bool ctrlKey = false,
  bool metaKey = false,
  bool rightButton = false,
  bool protectedAllSelected = true,
}) {
  if (!protectedAllSelected ||
      visibleDataRows.isEmpty ||
      visibleDataColumns.isEmpty) {
    return null;
  }
  final mouseX = pageX - containerLeft;
  final fixed = fixPositionOnFrozenCells(
    freeze,
    x: mouseX + scrollLeft,
    y: 0,
    mouseX: mouseX,
    mouseY: 0,
  );
  final columnLocationPayload = colLocation(
    fixed['x']! as num,
    visibleDataColumns,
  );
  final columnIndex = columnLocationPayload[2].toInt();
  final rowIndex = visibleDataRows.length - 1;
  if (rightButton &&
      selections.any(
        (selection) =>
            columnIndex >= selection.columnStart &&
            columnIndex <= selection.columnEnd &&
            selection.rowStart == 0 &&
            selection.rowEnd == rowIndex,
      )) {
    return null;
  }
  final columnPre = columnLocationPayload[0];
  final column = columnLocationPayload[1];
  final firstRow = rowLocationByIndex(0, visibleDataRows);
  final selection = {
    'left': columnPre,
    'width': column - columnPre - 1,
    'top': firstRow[0],
    'height': firstRow[1] - firstRow[0] - 1,
    'left_move': columnPre,
    'width_move': column - columnPre - 1,
    'top_move': 0,
    'height_move': visibleDataRows[rowIndex] - 1,
    'row': [0, rowIndex],
    'column': [columnIndex, columnIndex],
    'row_focus': 0,
    'column_focus': columnIndex,
    'column_select': true,
  };
  return {
    'type': 'columnHeaderMouseDown',
    'column': columnIndex,
    'orderbyindex': columnIndex,
    'selectionMode': (ctrlKey || metaKey) ? 'append' : 'replace',
    'colsSelectedStatus': true,
    'selectStatus': !(ctrlKey || metaKey),
    'scrollStatus': true,
    'selection': selection,
  };
}

List<num> _apiUniqueNums(List<num> values) {
  final seen = <num>{};
  final result = <num>[];
  for (final value in values) {
    if (seen.add(value)) {
      result.add(value);
    }
  }
  return result;
}

bool _apiIsEditableInputKey(String key, int? keyCode) {
  if (key == 'CapsLock' || key == 'Win') {
    return false;
  }
  if (key.length == 1) {
    return true;
  }
  return keyCode == 8 || keyCode == 32 || keyCode == 46 || keyCode == 0;
}

String? _apiKeyboardCodeFromKey(String? key, int? keyCode) {
  if (key == null) {
    return null;
  }
  if (key.length == 1) {
    final upper = key.toUpperCase();
    if (RegExp(r'^[A-Z]$').hasMatch(upper)) {
      return 'Key$upper';
    }
  }
  if (keyCode == 186) {
    return 'Semicolon';
  }
  if (keyCode == 222) {
    return 'Quote';
  }
  return null;
}

String? _apiKeyboardKeyFromCode(String? code, int? keyCode) {
  if (code != null && code.startsWith('Key') && code.length == 4) {
    return code.substring(3).toLowerCase();
  }
  if (keyCode == 186) {
    return ';';
  }
  if (keyCode == 222) {
    return "'";
  }
  return null;
}

