    'left': '${left}px',
    'width': '${width}px',
    'top': '${top}px',
    'height': '${height}px',
    'display': 'block',
  };
}

Map<String, Object?> hideDropCellSelection() {
  return const {'display': 'none'};
}

Map<String, Object?> createDropCellRange({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
}) {
  final x = pageX - containerLeft - rowHeaderWidth + scrollLeft;
  final y = pageY - containerTop - columnHeaderHeight + scrollTop;
  final row = rowLocation(y, visibleDataRows);
  final column = colLocation(x, visibleDataColumns);
  return {
    'luckysheetCellSelectedExtend': true,
    'luckysheetScrollStatus': true,
    'luckysheetCellSelectedExtendIndex': [row[2].toInt(), column[2].toInt()],
    'dropCellSelection': showDropCellSelection(
      left: column[0],
      width: column[1] - column[0] - 1,
      top: row[0],
      height: row[1] - row[0] - 1,
    ),
  };
}

Map<String, Object?> createFormulaRangeSelect(Map<String, Object?> select) {
  return {'formulaRangeSelect': _cloneStringObjectMap(select)};
}

Map<String, Object?>? updateDropCell(
  FortuneWorkbook workbook,
  Context ctx, {
  Map<String, Object?>? cache,
}) {
  final sourceCache =
      cache ??
      (ctx['dropCellCache'] is Map
          ? Map<String, Object?>.from(ctx['dropCellCache'] as Map)
          : null);
  if (sourceCache == null) {
    return null;
  }
  final copyRange = _apiDropCacheRange(sourceCache['copyRange']);
  final applyRange = _apiDropCacheRange(sourceCache['applyRange']);
  if (copyRange == null || applyRange == null) {
    return null;
  }
  final sheetId = '${ctx['currentSheetId'] ?? workbook.activeSheet.id}';
  final sheetIndex = getSheetIndex(workbook, sheetId);
  if (sheetIndex == null) {
    return null;
  }
  final sheet = workbook.sheets[sheetIndex];
  final direction = '${sourceCache['direction'] ?? 'down'}';
  final applyType = '${sourceCache['applyType'] ?? ''}';
  final fillSeries = applyType == '1' || applyType == '3';
  final copyRows = copyRange.rowEnd - copyRange.rowStart + 1;
  final copyColumns = copyRange.columnEnd - copyRange.columnStart + 1;
  final nextCells = <FortuneCellCoord, FortuneCell>{
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  final nextDataVerification = _cloneStringObjectMap(sheet.dataVerification);
  final sourceRawDataVerification = _apiCloneRawMetadataMap(
    sheet.rawDataVerification,
  );
  var nextRawDataVerification = _apiCloneRawMetadataMap(
    sheet.rawDataVerification,
  );
  final computedBorders = FortuneBorderCompute.compute(sheet);
  final nextRawBorderInfo = _apiDropRawBorderInfo(sheet, computedBorders);
  final nextConditionFormats = _apiDropConditionFormats(
    sheet.conditionFormats,
    copyRange,
    applyRange,
  );
  final copied = <String>[];
  final formulaRecalc = <Map<String, Object?>>[];
  final touchedTargets = <FortuneCellCoord>[];
  for (var row = applyRange.rowStart; row <= applyRange.rowEnd; row += 1) {
    for (
      var column = applyRange.columnStart;
      column <= applyRange.columnEnd;
      column += 1
    ) {
      if (sheet.hiddenRows.contains(row) ||
          sheet.hiddenColumns.contains(column)) {
        continue;
      }
      final sourceRowOffset = direction == 'up'
          ? (applyRange.rowEnd - row) % copyRows
          : (row - applyRange.rowStart) % copyRows;
      final sourceColumnOffset = direction == 'left'
          ? (applyRange.columnEnd - column) % copyColumns
          : (column - applyRange.columnStart) % copyColumns;
      final sourceCoord = FortuneCellCoord(
        direction == 'up'
            ? copyRange.rowEnd - sourceRowOffset
            : copyRange.rowStart + sourceRowOffset,
        direction == 'left'
            ? copyRange.columnEnd - sourceColumnOffset
            : copyRange.columnStart + sourceColumnOffset,
      );
      final targetCoord = FortuneCellCoord(row, column);
      final sourceCell = sheet.cells[sourceCoord];
      if (sourceCell == null) {
        if (applyType == '2') {
          final targetCell = sheet.cells[targetCoord] ?? const FortuneCell();
          nextCells[targetCoord] = _apiDropFormatOnlyCell(
            const FortuneCell(),
            targetCell,
          );
          touchedTargets.add(targetCoord);
          _apiDropCopyDataVerification(
            nextDataVerification,
            sheet,
            sourceCoord,
            targetCoord,
          );
          nextRawDataVerification = _apiDropCopyRawDataVerification(
            sourceRawDataVerification,
            nextRawDataVerification,
            sourceCoord,
            targetCoord,
          );
          _apiDropCopyBorderInfo(
            nextRawBorderInfo,
            computedBorders,
            sourceCoord,
            targetCoord,
          );
          continue;
        }
        nextCells.remove(targetCoord);
        touchedTargets.add(targetCoord);
        _apiDropCopyBorderInfo(
          nextRawBorderInfo,
          computedBorders,
          sourceCoord,
          targetCoord,
        );
        _apiDropCopyDataVerification(
          nextDataVerification,
          sheet,
          sourceCoord,
          targetCoord,
        );
        nextRawDataVerification = _apiDropCopyRawDataVerification(
          sourceRawDataVerification,
          nextRawDataVerification,
          sourceCoord,
          targetCoord,
        );
      } else {
        final nextCell = applyType == '2'
            ? _apiDropFormatOnlyCell(
                sourceCell,
                sheet.cells[targetCoord] ?? const FortuneCell(),
              )
            : _apiDropSeriesCell(
                    sheet,
                    copyRange,
                    applyRange,
                    sourceCoord,
                    targetCoord,
                    direction,
                    fillSeries,
                  ) ??
                  _apiDropWorkdayDateCell(
                    sheet,
                    copyRange,
                    applyRange,
                    sourceCoord,
                    targetCoord,
                    direction,
                    applyType,
                  ) ??
                  _apiDropDateSeriesCell(
                    sheet,
                    copyRange,
                    applyRange,
                    sourceCoord,
                    targetCoord,
                    direction,
                    applyType,
                  ) ??
                  _apiDropChineseWeekSeriesCell(
                    sheet,
                    copyRange,
                    applyRange,
                    sourceCoord,
                    targetCoord,
                    direction,
                    applyType,
                  ) ??
                  _apiDropChineseNumberSeriesCell(
                    sheet,
                    copyRange,
                    applyRange,
                    sourceCoord,
                    targetCoord,
                    direction,
                    applyType,
                  ) ??
                  _apiDropExtendNumberSeriesCell(
                    sheet,
                    copyRange,
                    applyRange,
                    sourceCoord,
                    targetCoord,
                    direction,
                    fillSeries,
                  ) ??
                  _apiDropCopiedCell(
                    sourceCell,
                    direction,
                    row - applyRange.rowStart + 1,
                    column - applyRange.columnStart + 1,
                  );
        nextCells[targetCoord] = nextCell;
        touchedTargets.add(targetCoord);
        final nextFormula = _apiCellFormulaText(nextCell);
        if (applyType != '2' && nextFormula != null) {
          formulaRecalc.add({
            'r': row,
            'c': column,
            'i': sheetId,
            'f': nextFormula,
          });
        }
        copied.add('${sourceCoord.row}_${sourceCoord.column}->${row}_$column');
        _apiDropCopyDataVerification(
          nextDataVerification,
          sheet,
          sourceCoord,
          targetCoord,
        );
        nextRawDataVerification = _apiDropCopyRawDataVerification(
          sourceRawDataVerification,
          nextRawDataVerification,
          sourceCoord,
          targetCoord,
        );
        _apiDropCopyBorderInfo(
          nextRawBorderInfo,
          computedBorders,
          sourceCoord,
          targetCoord,
        );
      }
    }
  }
  var nextSheet = sheet.copyWith(
    cells: nextCells,
    rawBorderInfo: nextRawBorderInfo,
    hasRawBorderInfo: nextRawBorderInfo.isNotEmpty || sheet.hasRawBorderInfo,
    conditionFormats: nextConditionFormats,
    dataVerification: nextDataVerification,
    rawDataVerification: nextRawDataVerification,
    hasRawDataVerification: nextRawDataVerification != null,
    selectionSave: [_selectionRangeToApiMap(applyRange)],
  );
  for (final coord in touchedTargets) {
    nextSheet = _apiSheetWithFunctionGroupCleanupAfterValueSet(
      sheet,
      nextSheet,
      coord.row,
      coord.column,
    );
  }
  final nextSheets = workbook.sheets.map((sheet) => sheet.copyWith()).toList();
  nextSheets[sheetIndex] = nextSheet;
  final nextWorkbook = workbook.copyWith(sheets: nextSheets);
  if (formulaRecalc.isNotEmpty) {
    final formulaCache = ctx['formulaCache'] is Map
        ? Map<String, Object?>.from(ctx['formulaCache'] as Map)
        : <String, Object?>{};
    formulaCache['execFunctionExist'] = formulaRecalc.reversed
        .map((item) => {'r': item['r'], 'c': item['c'], 'i': item['i']})
        .toList();
    formulaCache['execFunctionGlobalData'] = null;
    ctx['formulaCache'] = formulaCache;
  }
  final payload = <String, Object?>{
    'type': 'updateDropCell',
    'workbook': nextWorkbook,
    'sheet': nextSheet,
    'direction': direction,
    'applyType': applyType.isEmpty ? null : applyType,
    'copyRange': _selectionRangeToApiMap(copyRange),
    'applyRange': _selectionRangeToApiMap(applyRange),
    'copied': copied,
    'formulaRecalc': formulaRecalc,
    'dropCellSelection': hideDropCellSelection(),
  };
  ctx['updateDropCell'] = payload;
  return payload;
}

void _apiDropCopyDataVerification(
  Map<String, Object?> nextDataVerification,
  FortuneSheet sheet,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
) {
  final sourceVerification =
      sheet.dataVerification['${sourceCoord.row}_${sourceCoord.column}'];
  if (sourceVerification == null) {
    return;
  }
  nextDataVerification['${targetCoord.row}_${targetCoord.column}'] =
      cloneFortuneMetadata(sourceVerification);
}

Map<Object?, Object?>? _apiDropCopyRawDataVerification(
  Map<Object?, Object?>? sourceRawDataVerification,
  Map<Object?, Object?>? nextRawDataVerification,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
) {
  final sourceKey = '${sourceCoord.row}_${sourceCoord.column}';
  if (sourceRawDataVerification?.containsKey(sourceKey) != true) {
    return nextRawDataVerification;
  }
  final targetKey = '${targetCoord.row}_${targetCoord.column}';
  final next = nextRawDataVerification ?? <Object?, Object?>{};
  next[targetKey] = cloneFortuneMetadata(sourceRawDataVerification![sourceKey]);
  return next;
}

List<Object?> _apiDropRawBorderInfo(
  FortuneSheet sheet,
  Map<FortuneCellCoord, FortuneCellBorders> computedBorders,
) {
  if (sheet.hasRawBorderInfo && sheet.rawBorderInfo is List) {
    return [
      for (final item in sheet.rawBorderInfo! as List)
        cloneFortuneMetadata(item),
    ];
  }
  return [
    for (final entry in computedBorders.entries)
      _apiDropRawCellBorder(entry.key, entry.value),
  ];
}

void _apiDropCopyBorderInfo(
  List<Object?> rawBorderInfo,
  Map<FortuneCellCoord, FortuneCellBorders> computedBorders,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
) {
  final sourceBorders = computedBorders[sourceCoord];
  if (sourceBorders != null && !sourceBorders.isEmpty) {
    rawBorderInfo.addAll(
      _apiDropRawBorderForTarget(targetCoord, sourceBorders),
    );
  } else if (computedBorders.containsKey(targetCoord)) {
    rawBorderInfo.addAll(
      _apiDropRawBorderForTarget(targetCoord, const FortuneCellBorders()),
    );
  }
}

List<Object?> _apiRawBorderInfoListWithoutRanges(
  Object? rawBorderInfo,
  Iterable<FortuneRange> ranges,
) {
  final next = _apiRawBorderInfoWithoutRanges(rawBorderInfo, ranges);
  return next is List
      ? [for (final item in next) cloneFortuneMetadata(item)]
      : <Object?>[];
}

Object? _apiRawBorderInfoWithoutRanges(
  Object? rawBorderInfo,
  Iterable<FortuneRange> ranges,
) {
  var current = rawBorderInfo;
  for (final range in ranges) {
    current = _apiRawBorderInfoWithoutRange(current, range);
  }
  return current;
}

Object? _apiRawBorderInfoWithoutRange(
  Object? rawBorderInfo,
  FortuneRange range,
) {
  if (rawBorderInfo is! List) {
    return rawBorderInfo == null ? null : cloneFortuneMetadata(rawBorderInfo);
  }
  final next = <Object?>[];
  for (final item in rawBorderInfo) {
    if (item is! Map) {
      next.add(cloneFortuneMetadata(item));
      continue;
    }
    final map = Map<Object?, Object?>.from(cloneFortuneMetadata(item) as Map);
    final rangeType = _nullableStringArg(map['rangeType']);
    if (rangeType == 'cell') {
      final value = map['value'];
      final row = value is Map ? _nullableIntArg(value['row_index']) : null;
      final column = value is Map ? _nullableIntArg(value['col_index']) : null;
      if (row == null ||
          column == null ||
          row < range.rowStart ||
          row > range.rowEnd ||
          column < range.columnStart ||
          column > range.columnEnd) {
        next.add(map);
      }
      continue;
    }
    if (rangeType == 'range') {
      final ranges = <FortuneRange>[];
      for (final borderRange in _apiRawBorderRanges(map['range'])) {
        ranges.addAll(cfSplitRange(borderRange, range, range, 'restPart'));
      }
      if (ranges.isNotEmpty) {
        map['range'] = [for (final split in ranges) _apiRawBorderRange(split)];
        next.add(map);
      }
      continue;
    }
    next.add(map);
  }
  return next;
}

List<Object?> _apiDropRawBorderForTarget(
  FortuneCellCoord coord,
  FortuneCellBorders borders,
) {
  if (borders.slash != null) {
    return [_apiDropRawSlashBorder(coord, borders.slash!)];
  }
  return [_apiDropRawCellBorder(coord, borders)];
}

Map<String, Object?> _apiDropRawCellBorder(
  FortuneCellCoord coord,
  FortuneCellBorders borders,
) {
  return {
    'rangeType': 'cell',
    'value': {
      'row_index': coord.row,
      'col_index': coord.column,
      'l': _apiDropRawBorderSide(borders.left),
      'r': _apiDropRawBorderSide(borders.right),
      't': _apiDropRawBorderSide(borders.top),
      'b': _apiDropRawBorderSide(borders.bottom),
    },
  };
}

Map<String, Object?> _apiDropRawSlashBorder(
  FortuneCellCoord coord,
  FortuneBorderSide side,
) {
  return {
    'rangeType': 'range',
    'borderType': 'border-slash',
    'color': _apiColorToHex(side.color),
    'style': side.style,
    'range': [
      _apiRawBorderRange(
        FortuneRange(
          rowStart: coord.row,
          rowEnd: coord.row,
          columnStart: coord.column,
          columnEnd: coord.column,
          rowFocus: coord.row,
          columnFocus: coord.column,
        ),
      ),
    ],
  };
}

Map<String, Object?>? _apiDropRawBorderSide(FortuneBorderSide? side) {
  if (side == null) {
    return null;
  }
  return {'color': _apiColorToHex(side.color), 'style': side.style};
}

String _apiColorToHex(Color color) {
  final argb = color.toARGB32();
  final red = (argb >> 16) & 0xff;
  final green = (argb >> 8) & 0xff;
  final blue = argb & 0xff;
  return '#${red.toRadixString(16).padLeft(2, '0')}'
      '${green.toRadixString(16).padLeft(2, '0')}'
      '${blue.toRadixString(16).padLeft(2, '0')}';
}

FortuneCell? _apiDropSeriesCell(
  FortuneSheet sheet,
  FortuneRange copyRange,
  FortuneRange applyRange,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
  String direction,
  bool fillSeries,
) {
  if (!fillSeries) {
    return null;
  }
  final vertical = direction == 'down' || direction == 'up';
  final values = <double?>[];
  if (vertical) {
    for (var row = copyRange.rowStart; row <= copyRange.rowEnd; row += 1) {
      final number = _apiDropNumericValue(
        sheet.cells[FortuneCellCoord(row, sourceCoord.column)],
      );
      values.add(number);
    }
  } else {
    for (
      var column = copyRange.columnStart;
      column <= copyRange.columnEnd;
      column += 1
    ) {
      final number = _apiDropNumericValue(
        sheet.cells[FortuneCellCoord(sourceCoord.row, column)],
      );
      values.add(number);
    }
  }
  final sourceOffset = vertical
      ? sourceCoord.row - copyRange.rowStart
      : sourceCoord.column - copyRange.columnStart;
  if (sourceOffset < 0 || sourceOffset >= values.length) {
    return null;
  }
  final sourceNumber = values[sourceOffset];
  if (sourceNumber == null) {
    return null;
  }
  var sequenceStart = sourceOffset;
  var sequenceEnd = sourceOffset;
  while (sequenceStart > 0 && values[sequenceStart - 1] != null) {
    sequenceStart -= 1;
  }
  while (sequenceEnd + 1 < values.length && values[sequenceEnd + 1] != null) {
    sequenceEnd += 1;
  }
  final sequence = [
    for (var index = sequenceStart; index <= sequenceEnd; index += 1)
      values[index]!,
  ];
  if (sequence.length < 2) {
    return null;
  }
  final targetOrdinal = vertical
      ? (direction == 'up'
            ? applyRange.rowEnd - targetCoord.row + 1
            : targetCoord.row - applyRange.rowStart + 1)
      : (direction == 'left'
            ? applyRange.columnEnd - targetCoord.column + 1
            : targetCoord.column - applyRange.columnStart + 1);
  final groupTargetOrdinal = _apiDropGroupTargetOrdinal(
    targetOrdinal,
    values.length,
    sequenceStart,
    sequenceEnd,
  );
  if (groupTargetOrdinal == 0) {
    return null;
  }
  final forecastX = direction == 'down' || direction == 'right'
      ? sequence.length + groupTargetOrdinal
      : 1 - groupTargetOrdinal;
  final seriesValue = _apiDropForecastValue(sequence, forecastX);
  final text = _apiCssNumber(seriesValue);
  final sourceCell = sheet.cells[sourceCoord];
  if (sourceCell == null) {
    return null;
  }
  return sourceCell.copyWith(value: text, displayValue: text, formula: null);
}

int _apiDropGroupTargetOrdinal(
  int targetOrdinal,
  int copyLength,
  int sequenceStart,
  int sequenceEnd,
) {
  if (targetOrdinal <= 0 || copyLength <= 0) {
    return 0;
  }
  final sequenceLength = sequenceEnd - sequenceStart + 1;
  final fullCycles = targetOrdinal ~/ copyLength;
  final remainder = targetOrdinal % copyLength;
  final remainderEnd = remainder - 1;
  final remainderCount = remainderEnd < sequenceStart
      ? 0
      : math.min(sequenceEnd, remainderEnd) - sequenceStart + 1;
  return fullCycles * sequenceLength + math.max(0, remainderCount);
}

FortuneCell? _apiDropDateSeriesCell(
  FortuneSheet sheet,
  FortuneRange copyRange,
  FortuneRange applyRange,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
  String direction,
  String applyType,
) {
  if (!{'1', '3', '4', '6', '7'}.contains(applyType)) {
    return null;
  }
  final vertical = direction == 'down' || direction == 'up';
  final dates = <DateTime?>[];
  if (vertical) {
    for (var row = copyRange.rowStart; row <= copyRange.rowEnd; row += 1) {
      final date = _apiDropDateValue(
        sheet.cells[FortuneCellCoord(row, sourceCoord.column)],
      );
      dates.add(date);
    }
  } else {
    for (
      var column = copyRange.columnStart;
      column <= copyRange.columnEnd;
      column += 1
    ) {
      final date = _apiDropDateValue(
        sheet.cells[FortuneCellCoord(sourceCoord.row, column)],
      );
      dates.add(date);
    }
  }
  final sourceOffset = vertical
      ? sourceCoord.row - copyRange.rowStart
      : sourceCoord.column - copyRange.columnStart;
  if (sourceOffset < 0 || sourceOffset >= dates.length) {
    return null;
  }
  if (dates[sourceOffset] == null) {
    return null;
  }
  var sequenceStart = sourceOffset;
  var sequenceEnd = sourceOffset;
  while (sequenceStart > 0 && dates[sequenceStart - 1] != null) {
    sequenceStart -= 1;
  }
  while (sequenceEnd + 1 < dates.length && dates[sequenceEnd + 1] != null) {
    sequenceEnd += 1;
  }
  final dateSequence = [
    for (var index = sequenceStart; index <= sequenceEnd; index += 1)
      dates[index]!,
  ];
  if (dateSequence.length < 2) {
    return null;
  }
  final orderedDates = direction == 'up' || direction == 'left'
      ? dateSequence.reversed.toList()
      : dateSequence;
  final step = _apiDropDateStep(orderedDates, applyType, direction);
  if (step == null) {
    return null;
  }
  final targetOrdinal = vertical
      ? (direction == 'up'
            ? applyRange.rowEnd - targetCoord.row + 1
            : targetCoord.row - applyRange.rowStart + 1)
      : (direction == 'left'
            ? applyRange.columnEnd - targetCoord.column + 1
            : targetCoord.column - applyRange.columnStart + 1);
  final groupTargetOrdinal = _apiDropGroupTargetOrdinal(
    targetOrdinal,
    dates.length,
    sequenceStart,
    sequenceEnd,
  );
  if (groupTargetOrdinal == 0) {
    return null;
  }
  final sourceIndex = (groupTargetOrdinal - 1) % orderedDates.length;
  final cycle = (groupTargetOrdinal - 1) ~/ orderedDates.length + 1;
  final sourceDate = step.sourceCycle
      ? orderedDates[sourceIndex]
      : orderedDates.last;
  final multiplier = step.sourceCycle ? cycle : groupTargetOrdinal;
  final date = switch (step.unit) {
    _ApiDropDateUnit.month => _apiDropAddMonths(
      sourceDate,
      step.amount * multiplier,
    ),
    _ApiDropDateUnit.year => _apiDropAddMonths(
      sourceDate,
      step.amount * 12 * multiplier,
    ),
    _ApiDropDateUnit.day => sourceDate.add(
      Duration(days: step.amount * multiplier),
    ),
  };
  final displayText = _apiDropDateText(date);
  final sourceCell = sheet.cells[sourceCoord];
  if (sourceCell == null) {
    return null;
  }
  return sourceCell.copyWith(
    value: _apiCssNumber(datenumLocal(date)),
    displayValue: displayText,
    formula: null,
  );
}

FortuneCell? _apiDropWorkdayDateCell(
  FortuneSheet sheet,
  FortuneRange copyRange,
  FortuneRange applyRange,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
  String direction,
  String applyType,
) {
  if (applyType != '5') {
    return null;
  }
  final vertical = direction == 'down' || direction == 'up';
  final dates = <DateTime?>[];
  if (vertical) {
    for (var row = copyRange.rowStart; row <= copyRange.rowEnd; row += 1) {
      final date = _apiDropDateValue(
        sheet.cells[FortuneCellCoord(row, sourceCoord.column)],
      );
      dates.add(date);
    }
  } else {
    for (
      var column = copyRange.columnStart;
      column <= copyRange.columnEnd;
      column += 1
    ) {
      final date = _apiDropDateValue(
        sheet.cells[FortuneCellCoord(sourceCoord.row, column)],
      );
      dates.add(date);
    }
  }
  final sourceOffset = vertical
      ? sourceCoord.row - copyRange.rowStart
      : sourceCoord.column - copyRange.columnStart;
  if (sourceOffset < 0 || sourceOffset >= dates.length) {
    return null;
  }
  if (dates[sourceOffset] == null) {
    return null;
  }
  var sequenceStart = sourceOffset;
  var sequenceEnd = sourceOffset;
  while (sequenceStart > 0 && dates[sequenceStart - 1] != null) {
    sequenceStart -= 1;
  }
  while (sequenceEnd + 1 < dates.length && dates[sequenceEnd + 1] != null) {
    sequenceEnd += 1;
  }
  final dateSequence = [
    for (var index = sequenceStart; index <= sequenceEnd; index += 1)
      dates[index]!,
  ];
  if (dateSequence.length < 2) {
    return null;
  }
  final orderedDates = direction == 'up' || direction == 'left'
      ? dateSequence.reversed.toList()
      : dateSequence;
  final plan = _apiDropWorkdayPlan(orderedDates, direction);
  if (plan == null) {
    return null;
  }
  final targetOrdinal = vertical
      ? (direction == 'up'
            ? applyRange.rowEnd - targetCoord.row + 1
            : targetCoord.row - applyRange.rowStart + 1)
      : (direction == 'left'
            ? applyRange.columnEnd - targetCoord.column + 1
            : targetCoord.column - applyRange.columnStart + 1);
  final groupTargetOrdinal = _apiDropGroupTargetOrdinal(
    targetOrdinal,
    dates.length,
    sequenceStart,
    sequenceEnd,
  );
  if (groupTargetOrdinal == 0) {
    return null;
  }
  final sourceIndex = (groupTargetOrdinal - 1) % orderedDates.length;
  final cycle = (groupTargetOrdinal - 1) ~/ orderedDates.length + 1;
  final nextDate = switch (plan.mode) {
    _ApiDropWorkdayMode.anchorMonth => _apiDropAddMonths(
      orderedDates.last,
      plan.amount * groupTargetOrdinal,
    ),
    _ApiDropWorkdayMode.sourceMonth => _apiDropAddMonths(
      orderedDates[sourceIndex],
      plan.amount * cycle,
    ),
    _ApiDropWorkdayMode.sourceWeek => orderedDates[sourceIndex].add(
      Duration(days: plan.amount * cycle),
    ),
  };
  final workday = _apiPreviousWorkday(nextDate);
  final displayText = _apiDropDateText(workday);
  final sourceCell = sheet.cells[sourceCoord];
  if (sourceCell == null) {
    return null;
  }
  return sourceCell.copyWith(
    value: _apiCssNumber(datenumLocal(workday)),
    displayValue: displayText,
    formula: null,
  );
}

_ApiDropWorkdayPlan? _apiDropWorkdayPlan(
  List<DateTime> orderedDates,
  String direction,
) {
  final sameDayOfMonth = orderedDates.every(
    (date) => date.day == orderedDates.first.day,
  );
  final monthSteps = <int>[];
  final daySteps = <int>[];
  for (var index = 1; index < orderedDates.length; index += 1) {
    final previous = orderedDates[index - 1];
    final current = orderedDates[index];
    monthSteps.add(
      (current.year - previous.year) * 12 + current.month - previous.month,
    );
    daySteps.add(current.difference(previous).inDays);
  }
  final equalMonthStep = monthSteps.every((step) => step == monthSteps.first);
  if (sameDayOfMonth && equalMonthStep && monthSteps.first != 0) {
    return _ApiDropWorkdayPlan(
      _ApiDropWorkdayMode.anchorMonth,
      monthSteps.first,
    );
  }
  if (!daySteps.every((step) => step == daySteps.first)) {
    return null;
  }
  final forward = direction == 'down' || direction == 'right';
  if (daySteps.first.abs() > 7) {
    return _ApiDropWorkdayPlan(
      _ApiDropWorkdayMode.sourceMonth,
      forward ? 1 : -1,
    );
  }
  return _ApiDropWorkdayPlan(_ApiDropWorkdayMode.sourceWeek, forward ? 7 : -7);
}

DateTime _apiPreviousWorkday(DateTime date) {
  if (date.weekday == DateTime.sunday) {
    return date.subtract(const Duration(days: 2));
  }
  if (date.weekday == DateTime.saturday) {
    return date.subtract(const Duration(days: 1));
  }
  return date;
}

_ApiDropDateStep? _apiDropDateStep(
  List<DateTime> dates,
  String applyType,
  String direction,
) {
  if (dates.length < 2) {
    return null;
  }
  if (applyType == '6') {
    return _apiDropMonthDateStep(dates, direction);
  }
  if (applyType == '7') {
    return _apiDropYearDateStep(dates, direction);
  }
  if (applyType == '1' || applyType == '3') {
    return _apiDropSeriesDateStep(dates);
  }
  if (applyType == '4' && dates.length > 2) {
    return _apiDropMultiDateStep(dates);
  }
  final unit = switch (applyType) {
    _ => _ApiDropDateUnit.day,
  };
  final steps = <int>[];
  for (var index = 1; index < dates.length; index += 1) {
    final previous = dates[index - 1];
    final current = dates[index];
    final step = switch (unit) {
      _ApiDropDateUnit.month =>
        (current.year - previous.year) * 12 + current.month - previous.month,
      _ApiDropDateUnit.year => current.year - previous.year,
      _ApiDropDateUnit.day => current.difference(previous).inDays,
    };
    steps.add(step);
  }
  if (steps.any((step) => step != steps.first)) {
    return null;
  }
  return _ApiDropDateStep(unit, steps.first);
}

_ApiDropDateStep? _apiDropSeriesDateStep(List<DateTime> dates) {
  final sameDay = dates.every((date) => date.day == dates.first.day);
  final monthSteps = <int>[];
  final daySteps = <int>[];
  for (var index = 1; index < dates.length; index += 1) {
    final previous = dates[index - 1];
    final current = dates[index];
    monthSteps.add(
      (current.year - previous.year) * 12 + current.month - previous.month,
    );
    daySteps.add(current.difference(previous).inDays);
  }
  final equalMonthStep = monthSteps.every((step) => step == monthSteps.first);
  if (sameDay && equalMonthStep && monthSteps.first != 0) {
    return _ApiDropDateStep(_ApiDropDateUnit.month, monthSteps.first);
  }
  final equalDayStep = daySteps.every((step) => step == daySteps.first);
  if (!sameDay && equalDayStep && daySteps.first != 0) {
    return _ApiDropDateStep(_ApiDropDateUnit.day, daySteps.first);
  }
  return null;
}

_ApiDropDateStep? _apiDropMultiDateStep(List<DateTime> dates) {
  final sameDay = dates.every((date) => date.day == dates.first.day);
  final monthSteps = <int>[];
  final daySteps = <int>[];
  for (var index = 1; index < dates.length; index += 1) {
    final previous = dates[index - 1];
    final current = dates[index];
    monthSteps.add(
      (current.year - previous.year) * 12 + current.month - previous.month,
    );
    daySteps.add(current.difference(previous).inDays);
  }
  final equalMonthStep = monthSteps.every((step) => step == monthSteps.first);
  if (sameDay && equalMonthStep && monthSteps.first != 0) {
    return _ApiDropDateStep(_ApiDropDateUnit.month, monthSteps.first);
  }
  final equalDayStep = daySteps.every((step) => step == daySteps.first);
  if (!sameDay && equalDayStep && daySteps.first != 0) {
    return _ApiDropDateStep(_ApiDropDateUnit.day, daySteps.first);
  }
  return null;
}

_ApiDropDateStep? _apiDropMonthDateStep(
  List<DateTime> dates,
  String direction,
) {
  final sameDay = dates.every((date) => date.day == dates.first.day);
  final monthSteps = <int>[];
  final daySteps = <int>[];
  for (var index = 1; index < dates.length; index += 1) {
    final previous = dates[index - 1];
    final current = dates[index];
    monthSteps.add(
      (current.year - previous.year) * 12 + current.month - previous.month,
    );
    daySteps.add(current.difference(previous).inDays);
  }
  final equalMonthStep = monthSteps.every((step) => step == monthSteps.first);
  if (sameDay && equalMonthStep && monthSteps.first != 0) {
    return _ApiDropDateStep(_ApiDropDateUnit.month, monthSteps.first);
  }
  if (dates.length > 2 &&
      (sameDay || daySteps.any((step) => step != daySteps.first))) {
    return null;
  }
  final forward = direction == 'down' || direction == 'right';
  return _ApiDropDateStep(
    _ApiDropDateUnit.month,
    forward ? 1 : -1,
    sourceCycle: true,
  );
}

_ApiDropDateStep? _apiDropYearDateStep(List<DateTime> dates, String direction) {
  final sameDay = dates.every((date) => date.day == dates.first.day);
  final sameMonth = dates.every((date) => date.month == dates.first.month);
  final yearSteps = <int>[];
  final monthSteps = <int>[];
  final daySteps = <int>[];
  for (var index = 1; index < dates.length; index += 1) {
    final previous = dates[index - 1];
    final current = dates[index];
    yearSteps.add(current.year - previous.year);
    monthSteps.add(
      (current.year - previous.year) * 12 + current.month - previous.month,
    );
    daySteps.add(current.difference(previous).inDays);
  }
  final equalYearStep = yearSteps.every((step) => step == yearSteps.first);
  if (sameDay && sameMonth && equalYearStep && yearSteps.first != 0) {
    return _ApiDropDateStep(_ApiDropDateUnit.year, yearSteps.first);
  }
  final equalMonthStep = monthSteps.every((step) => step == monthSteps.first);
  final equalDayStep = daySteps.every((step) => step == daySteps.first);
  if (dates.length > 2 && !((sameDay && equalMonthStep) || equalDayStep)) {
    return null;
  }
  final forward = direction == 'down' || direction == 'right';
  return _ApiDropDateStep(
    _ApiDropDateUnit.year,
    forward ? 1 : -1,
    sourceCycle: true,
  );
}

DateTime _apiDropAddMonths(DateTime date, int months) {
  final monthIndex = date.month - 1 + months;
  final year = date.year + (monthIndex / 12).floor();
  final month = monthIndex % 12 + 1;
  final lastDay = DateTime(year, month + 1, 0).day;
  return DateTime(year, month, math.min(date.day, lastDay));
}

DateTime? _apiDropDateValue(FortuneCell? cell) {
  if (cell == null ||
      _apiCellHasFormulaMetadata(cell) ||
      cell.cellType?.type != 'd') {
    return null;
  }
  final display = _apiDropCellText(cell);
  if (display != null) {
    final parsed = _apiGenerateParseDate(display, is12HourDate: false);
    if (parsed != null) {
      return DateTime(parsed.year, parsed.month, parsed.day);
    }
  }
  final raw = cell.hasRawValue ? cell.rawValue : cell.value;
  final serial = _apiDropParseNumber('$raw');
  if (serial == null) {
    return null;
  }
  return _apiDateFromSerial(serial);
}

DateTime _apiDateFromSerial(num serial) {
  final wholeDays = serial.floor();
  final fraction = serial - wholeDays;
  var date = DateTime.utc(1899, 12, 31).add(Duration(days: wholeDays));
  if (serial >= 60) {
    date = date.subtract(const Duration(days: 1));
  }
  date = date.add(
    Duration(seconds: (fraction * Duration.secondsPerDay).round()),
  );
  return DateTime(date.year, date.month, date.day);
}

String _apiDropDateText(DateTime date) {
  return '${date.year.toString().padLeft(4, '0')}-'
      '${date.month.toString().padLeft(2, '0')}-'
      '${date.day.toString().padLeft(2, '0')}';
}

FortuneCell? _apiDropChineseWeekSeriesCell(
  FortuneSheet sheet,
  FortuneRange copyRange,
  FortuneRange applyRange,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
  String direction,
  String applyType,
) {
  if (applyType != '1' && applyType != '3') {
    return null;
  }
  final vertical = direction == 'down' || direction == 'up';
  final values = <_ApiDropChineseWeek?>[];
  if (vertical) {
    for (var row = copyRange.rowStart; row <= copyRange.rowEnd; row += 1) {
      final parsed = _apiDropChineseWeekValue(
        _apiDropCellText(
          sheet.cells[FortuneCellCoord(row, sourceCoord.column)],
        ),
      );
      values.add(parsed);
    }
  } else {
    for (
      var column = copyRange.columnStart;
      column <= copyRange.columnEnd;
      column += 1
    ) {
      final parsed = _apiDropChineseWeekValue(
        _apiDropCellText(
          sheet.cells[FortuneCellCoord(sourceCoord.row, column)],
        ),
      );
      values.add(parsed);
    }
  }
  final sourceOffset = vertical
      ? sourceCoord.row - copyRange.rowStart
      : sourceCoord.column - copyRange.columnStart;
  if (sourceOffset < 0 || sourceOffset >= values.length) {
    return null;
  }
  final sourceValue = values[sourceOffset];
  if (sourceValue == null) {
    return null;
  }
  final prefix = sourceValue.prefix;
  var sequenceStart = sourceOffset;
  var sequenceEnd = sourceOffset;
  while (sequenceStart > 0 &&
      values[sequenceStart - 1] != null &&
      values[sequenceStart - 1]!.prefix == prefix) {
    sequenceStart -= 1;
  }
  while (sequenceEnd + 1 < values.length &&
      values[sequenceEnd + 1] != null &&
      values[sequenceEnd + 1]!.prefix == prefix) {
    sequenceEnd += 1;
  }
  final sequenceValues = [
    for (var index = sequenceStart; index <= sequenceEnd; index += 1)
      values[index]!.value,
  ];
  if (sequenceValues.length < 2) {
    return null;
  }
  final orderedValues = direction == 'up' || direction == 'left'
      ? sequenceValues.reversed.toList()
      : sequenceValues;
  if (!_apiDropIsEqualDifference([
    for (final value in orderedValues) value.toDouble(),
  ])) {
    return null;
  }
  final step = orderedValues[1] - orderedValues[0];
  final targetOrdinal = vertical
      ? (direction == 'up'
            ? applyRange.rowEnd - targetCoord.row + 1
            : targetCoord.row - applyRange.rowStart + 1)
      : (direction == 'left'
            ? applyRange.columnEnd - targetCoord.column + 1
            : targetCoord.column - applyRange.columnStart + 1);
  final groupTargetOrdinal = _apiDropGroupTargetOrdinal(
    targetOrdinal,
    values.length,
    sequenceStart,
    sequenceEnd,
  );
  if (groupTargetOrdinal == 0) {
    return null;
  }
  final nextValue = _apiNormalizeWeekValue(
    orderedValues.last + step * groupTargetOrdinal,
  );
  final text = _apiChineseWeekText(prefix, nextValue);
  final sourceCell = sheet.cells[sourceCoord];
  if (sourceCell == null) {
    return null;
  }
  return sourceCell.copyWith(value: text, displayValue: text, formula: null);
}

_ApiDropChineseWeek? _apiDropChineseWeekValue(String? text) {
  if (text == null) {
    return null;
  }
  if (_apiIsChnWeek2(text)) {
    return _ApiDropChineseWeek('周', _apiChineseWeekNumber(text.substring(1)));
  }
  if (_apiIsChnWeek3(text)) {
    return _ApiDropChineseWeek('星期', _apiChineseWeekNumber(text.substring(2)));
  }
  if (text == '日') {
    return const _ApiDropChineseWeek('', 7);
  }
  final number = _apiChineseWeekNumber(text);
  if (number >= 1 && number <= 6) {
    return _ApiDropChineseWeek('', number);
  }
  return null;
}

int _apiChineseWeekNumber(String text) {
  return text == '日' ? 7 : _apiChineseToNumber(text);
}

int _apiNormalizeWeekValue(int value) {
  var normalized = value % 7;
  if (normalized <= 0) {
    normalized += 7;
  }
  return normalized;
}

String _apiChineseWeekText(String prefix, int value) {
  final suffix = value == 7 ? '日' : _apiNumberToChinese(value);
  return '$prefix$suffix';
}

FortuneCell? _apiDropChineseNumberSeriesCell(
  FortuneSheet sheet,
  FortuneRange copyRange,
  FortuneRange applyRange,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
  String direction,
  String applyType,
) {
  if (applyType != '1' && applyType != '3' && applyType != '8') {
    return null;
  }
  final vertical = direction == 'down' || direction == 'up';
  final values = <int?>[];
  if (vertical) {
    for (var row = copyRange.rowStart; row <= copyRange.rowEnd; row += 1) {
      final text = _apiDropCellText(
        sheet.cells[FortuneCellCoord(row, sourceCoord.column)],
      );
      values.add(
        isChnNumber(text) && text != '日' ? _apiChineseToNumber(text!) : null,
      );
    }
  } else {
    for (
      var column = copyRange.columnStart;
      column <= copyRange.columnEnd;
      column += 1
    ) {
      final text = _apiDropCellText(
        sheet.cells[FortuneCellCoord(sourceCoord.row, column)],
      );
      values.add(
        isChnNumber(text) && text != '日' ? _apiChineseToNumber(text!) : null,
      );
    }
  }
  final sourceOffset = vertical
      ? sourceCoord.row - copyRange.rowStart
      : sourceCoord.column - copyRange.columnStart;
  if (sourceOffset < 0 || sourceOffset >= values.length) {
    return null;
  }
  if (values[sourceOffset] == null) {
    return null;
  }
  var sequenceStart = sourceOffset;
  var sequenceEnd = sourceOffset;
  while (sequenceStart > 0 && values[sequenceStart - 1] != null) {
    sequenceStart -= 1;
  }
  while (sequenceEnd + 1 < values.length && values[sequenceEnd + 1] != null) {
    sequenceEnd += 1;
  }
  final sequenceValues = [
    for (var index = sequenceStart; index <= sequenceEnd; index += 1)
      values[index]!,
  ];
  if (sequenceValues.length < 2) {
    return null;
  }
  final orderedValues = direction == 'up' || direction == 'left'
      ? sequenceValues.reversed.toList()
      : sequenceValues;
  if (!_apiDropIsEqualDifference([
    for (final value in orderedValues) value.toDouble(),
  ])) {
    return null;
  }
  final step = orderedValues[1] - orderedValues[0];
  final targetOrdinal = vertical
      ? (direction == 'up'
            ? applyRange.rowEnd - targetCoord.row + 1
            : targetCoord.row - applyRange.rowStart + 1)
      : (direction == 'left'
            ? applyRange.columnEnd - targetCoord.column + 1
            : targetCoord.column - applyRange.columnStart + 1);
  final groupTargetOrdinal = _apiDropGroupTargetOrdinal(
    targetOrdinal,
    values.length,
    sequenceStart,
    sequenceEnd,
  );
  if (groupTargetOrdinal == 0) {
    return null;
  }
  final nextNumber = orderedValues.last + step * groupTargetOrdinal;
  final text = nextNumber <= 0 ? '零' : _apiNumberToChinese(nextNumber);
  final sourceCell = sheet.cells[sourceCoord];
  if (sourceCell == null) {
    return null;
  }
  return sourceCell.copyWith(value: text, displayValue: text, formula: null);
}

int _apiChineseToNumber(String value) {
  var result = 0;
  var section = 0;
  var number = 0;
  for (var index = 0; index < value.length; index += 1) {
    final char = value[index];
    final digit = _apiChnNumChar[char];
    if (digit != null) {
      number = digit;
      if (index == value.length - 1) {
        section += number;
      }
    } else {
      final unit = _apiChnNameValue[char] ?? 1;
      final sectionUnit = char == '万' || char == '亿';
      if (sectionUnit) {
        section = (section + number) * unit;
        result += section;
        section = 0;
      } else {
        section += number * unit;
      }
      number = 0;
    }
  }
  return result + section;
}

String _apiNumberToChinese(int value) {
  const sections = ['', '万', '亿'];
  if (value == 0) {
    return '零';
  }
  var number = value;
  var unitPosition = 0;
  var needZero = false;
  var text = '';
  while (number > 0) {
    final section = number % 10000;
    if (needZero) {
      text = '零$text';
    }
    final sectionText = _apiSectionToChinese(section);
    text =
        '$sectionText${section != 0 ? sections[unitPosition] : sections[0]}$text';
    needZero = section < 1000 && section > 0;
    number ~/= 10000;
    unitPosition += 1;
  }
  return text;
}

String _apiSectionToChinese(int section) {
  const digits = ['零', '一', '二', '三', '四', '五', '六', '七', '八', '九'];
  const units = ['', '十', '百', '千'];
  var value = section;
  var unitPosition = 0;
  var zero = true;
  var text = '';
  while (value > 0) {
    final digit = value % 10;
    if (digit == 0) {
      if (!zero) {
        zero = true;
        text = '${digits[digit]}$text';
      }
    } else {
      zero = false;
      text = '${digits[digit]}${units[unitPosition]}$text';
    }
    unitPosition += 1;
    value ~/= 10;
  }
  return text;
}

FortuneCell? _apiDropExtendNumberSeriesCell(
  FortuneSheet sheet,
  FortuneRange copyRange,
  FortuneRange applyRange,
  FortuneCellCoord sourceCoord,
  FortuneCellCoord targetCoord,
  String direction,
  bool fillSeries,
) {
  if (!fillSeries) {
    return null;
  }
  final vertical = direction == 'down' || direction == 'up';
  final parts = <List<Object?>?>[];
  if (vertical) {
    for (var row = copyRange.rowStart; row <= copyRange.rowEnd; row += 1) {
      final cell = sheet.cells[FortuneCellCoord(row, sourceCoord.column)];
      final parsed = isExtendNumber(_apiDropCellText(cell));
      parts.add(parsed.first == true ? parsed : null);
    }
  } else {
    for (
      var column = copyRange.columnStart;
      column <= copyRange.columnEnd;
      column += 1
    ) {
      final cell = sheet.cells[FortuneCellCoord(sourceCoord.row, column)];
      final parsed = isExtendNumber(_apiDropCellText(cell));
      parts.add(parsed.first == true ? parsed : null);
    }
  }
  final sourceOffset = vertical
      ? sourceCoord.row - copyRange.rowStart
      : sourceCoord.column - copyRange.columnStart;
  if (sourceOffset < 0 || sourceOffset >= parts.length) {
    return null;
  }
  final sourcePart = parts[sourceOffset];
  if (sourcePart == null) {
    return null;
  }
  final before = sourcePart[2];
  final after = sourcePart[3];
  var sequenceStart = sourceOffset;
  var sequenceEnd = sourceOffset;
  while (sequenceStart > 0 &&
      parts[sequenceStart - 1] != null &&
      parts[sequenceStart - 1]![2] == before &&
      parts[sequenceStart - 1]![3] == after) {
    sequenceStart -= 1;
  }
  while (sequenceEnd + 1 < parts.length &&
      parts[sequenceEnd + 1] != null &&
      parts[sequenceEnd + 1]![2] == before &&
      parts[sequenceEnd + 1]![3] == after) {
    sequenceEnd += 1;
  }
  final sequenceParts = [
    for (var index = sequenceStart; index <= sequenceEnd; index += 1)
      parts[index]!,
  ];
  if (sequenceParts.length < 2) {
    return null;
  }
  final numericParts = direction == 'up' || direction == 'left'
      ? sequenceParts.reversed.toList()
      : sequenceParts;
  final numbers = [
    for (final part in numericParts) (part[1] as num).toDouble(),
  ];
  if (!_apiDropIsEqualDifference(numbers)) {
    return null;
  }
  final step = numbers[1] - numbers[0];
  final targetOrdinal = vertical
      ? (direction == 'up'
            ? applyRange.rowEnd - targetCoord.row + 1
            : targetCoord.row - applyRange.rowStart + 1)
      : (direction == 'left'
            ? applyRange.columnEnd - targetCoord.column + 1
            : targetCoord.column - applyRange.columnStart + 1);
  final groupTargetOrdinal = _apiDropGroupTargetOrdinal(
    targetOrdinal,
    parts.length,
    sequenceStart,
    sequenceEnd,
  );
  if (groupTargetOrdinal == 0) {
    return null;
  }
  final last = numericParts.last;
  final nextNumber = (last[1] as num) + step * groupTargetOrdinal;
  final text = '${last[2]}${_apiCssNumber(nextNumber.abs())}${last[3]}';
  final sourceCell = sheet.cells[sourceCoord];
  if (sourceCell == null) {
    return null;
  }
  return sourceCell.copyWith(value: text, displayValue: text, formula: null);
}

String? _apiDropCellText(FortuneCell? cell) {
  if (cell == null || _apiCellHasFormulaMetadata(cell)) {
    return null;
  }
  if (cell.cellType?.type == 'd') {
    return null;
  }
  if (cell.hasRawDisplayValue && cell.rawDisplayValue != null) {
    return '${cell.rawDisplayValue}';
  }
  if (cell.displayValue != null) {
    return cell.displayValue;
  }
  if (cell.hasRawValue && cell.rawValue != null) {
    return '${cell.rawValue}';
  }
  return cell.value;
}

double? _apiDropNumericValue(FortuneCell? cell) {
  if (cell == null || _apiCellHasFormulaMetadata(cell)) {
    return null;
  }
  if (cell.cellType?.type == 'd') {
    return null;
  }
  final raw = cell.hasRawValue ? cell.rawValue : cell.value;
  final value = _apiDropParseNumber('$raw');
  if (value != null) {
    return value.toDouble();
  }
  final display = cell.hasRawDisplayValue
      ? cell.rawDisplayValue
      : cell.displayValue;
  return _apiDropParseNumber('$display')?.toDouble();
}

num? _apiDropParseNumber(String value) {
  final text = value.trim();
  if (text.isEmpty) {
    return null;
  }
  return num.tryParse(text);
}

num _apiDropForecastValue(List<double> values, int x) {
  if (values.length > 2 && _apiDropIsEqualRatio(values)) {
    final ratio = values[1] / values[0];
    final result = x > values.length
        ? values.last * math.pow(ratio, x - values.length)
        : values.first / math.pow(ratio, 1 - x);
    return _apiRoundFive(result.toDouble());
  }
  final xValues = [
    for (var index = 1; index <= values.length; index += 1) index,
  ];
  final averageX = xValues.reduce((a, b) => a + b) / xValues.length;
  final averageY = values.reduce((a, b) => a + b) / values.length;
  var numerator = 0.0;
  var denominator = 0.0;
  for (var index = 0; index < values.length; index += 1) {
    numerator += (xValues[index] - averageX) * (values[index] - averageY);
    denominator += math.pow(xValues[index] - averageX, 2).toDouble();
  }
  final slope = denominator == 0 ? 1 : numerator / denominator;
  final intercept = averageY - slope * averageX;
  return _apiRoundFive(intercept + slope * x);
}

bool _apiDropIsEqualRatio(List<double> values) {
  if (values.length < 3 || values.first == 0 || values[1] == 0) {
    return false;
  }
  final ratio = values[1] / values.first;
  for (var index = 1; index < values.length; index += 1) {
    if (values[index - 1] == 0 || values[index] / values[index - 1] != ratio) {
      return false;
    }
  }
  return true;
}

bool _apiDropIsEqualDifference(List<double> values) {
  if (values.length < 2) {
    return false;
  }
  final step = values[1] - values[0];
  for (var index = 1; index < values.length; index += 1) {
    if (values[index] - values[index - 1] != step) {
      return false;
    }
  }
  return true;
}

num _apiRoundFive(num value) {
  return (value * 100000).round() / 100000;
}

enum _ApiDropDateUnit { day, month, year }

class _ApiDropDateStep {
  const _ApiDropDateStep(this.unit, this.amount, {this.sourceCycle = false});

  final _ApiDropDateUnit unit;
  final int amount;
  final bool sourceCycle;
}

enum _ApiDropWorkdayMode { anchorMonth, sourceMonth, sourceWeek }

class _ApiDropWorkdayPlan {
  const _ApiDropWorkdayPlan(this.mode, this.amount);

  final _ApiDropWorkdayMode mode;
  final int amount;
}

class _ApiDropChineseWeek {
  const _ApiDropChineseWeek(this.prefix, this.value);

  final String prefix;
  final int value;
}

FortuneRange? _apiDropCacheRange(Object? value) {
  if (value is FortuneRange) {
    return value;
  }
  if (value is Map) {
    return _selectionRangeFromApiMap(value);
  }
  return null;
}

