    background: source.background,
    rawBackground: source.rawBackground,
    hasRawBackground: source.hasRawBackground,
    foreground: source.foreground,
    rawForeground: source.rawForeground,
    hasRawForeground: source.hasRawForeground,
    bold: source.bold,
    rawBold: source.rawBold,
    hasRawBold: source.hasRawBold,
    italic: source.italic,
    rawItalic: source.rawItalic,
    hasRawItalic: source.hasRawItalic,
    strikeThrough: source.strikeThrough,
    rawStrikeThrough: source.rawStrikeThrough,
    hasRawStrikeThrough: source.hasRawStrikeThrough,
    underline: source.underline,
    rawUnderline: source.rawUnderline,
    hasRawUnderline: source.hasRawUnderline,
    fontSize: source.fontSize,
    rawFontSize: source.rawFontSize,
    hasRawFontSize: source.hasRawFontSize,
    fontFamily: source.fontFamily,
    rawFontFamily: source.rawFontFamily,
    hasRawFontFamily: source.hasRawFontFamily,
    horizontalAlign: source.horizontalAlign,
    rawHorizontalAlign: source.rawHorizontalAlign,
    hasRawHorizontalAlign: source.hasRawHorizontalAlign,
    verticalAlign: source.verticalAlign,
    rawVerticalAlign: source.rawVerticalAlign,
    hasRawVerticalAlign: source.hasRawVerticalAlign,
    textWrap: source.textWrap,
    rawTextWrap: source.rawTextWrap,
    hasRawTextWrap: source.hasRawTextWrap,
    textRotation: source.textRotation,
    rawTextRotation: source.rawTextRotation,
    hasRawTextRotation: source.hasRawTextRotation,
    textRotationMode: source.textRotationMode,
    rawTextRotationMode: source.rawTextRotationMode,
    hasRawTextRotationMode: source.hasRawTextRotationMode,
  );
}

FortuneCell _apiDropCopiedCell(
  FortuneCell cell,
  String direction,
  int rowStep,
  int columnStep,
) {
  final formula = _apiCellFormulaText(cell);
  if (formula == null || formula.isEmpty) {
    return cell.copyWith();
  }
  final copiedFormula = switch (direction) {
    'up' => functionCopy(formula, 'up', rowStep),
    'down' => functionCopy(formula, 'down', rowStep),
    'left' => functionCopy(formula, 'left', columnStep),
    'right' => functionCopy(formula, 'right', columnStep),
    _ => formula,
  };
  final nextFormula = copiedFormula.startsWith('=')
      ? copiedFormula
      : '=$copiedFormula';
  return cell.copyWith(
    formula: nextFormula,
    rawFormula: cell.hasRawFormula ? nextFormula : _sentinel,
    hasRawFormula: cell.hasRawFormula,
  );
}

Map<String, Object?>? onCellsMoveStart({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  required FortuneRange selection,
  bool allowEdit = true,
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
}) {
  if (!allowEdit) {
    return null;
  }
  final location = _apiMoveCellsLocation(
    pageX: pageX,
    pageY: pageY,
    containerLeft: containerLeft,
    containerTop: containerTop,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
    scrollLeft: scrollLeft,
    scrollTop: scrollTop,
    rowHeaderWidth: rowHeaderWidth,
    columnHeaderHeight: columnHeaderHeight,
  );
  final rowIndex = _apiClampInt(
    location['rowIndex']!.toInt(),
    selection.rowStart,
    selection.rowEnd,
  );
  final columnIndex = _apiClampInt(
    location['columnIndex']!.toInt(),
    selection.columnStart,
    selection.columnEnd,
  );
  final row = rowLocationByIndex(rowIndex, visibleDataRows);
  final column = colLocationByIndex(columnIndex, visibleDataColumns);
  return {
    'luckysheetCellSelectedMove': true,
    'luckysheetScrollStatus': true,
    'luckysheetCellSelectedMoveIndex': [rowIndex, columnIndex],
    'dragCellStartPos': {'x': pageX, 'y': pageY},
    'cellSelectedMove': _apiCellsMoveStyle(
      left: column[0],
      top: row[0],
      width: column[1] - column[0] - 1,
      height: row[1] - row[0] - 1,
    ),
  };
}

Map<String, Object?>? onCellsMove({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required num containerWidth,
  required num containerHeight,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  required FortuneRange selection,
  required List<int> moveIndex,
  bool isMoving = true,
  num? dragStartX,
  num? dragStartY,
  num dragCellThreshold = 8,
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
  num zoomRatio = 1,
}) {
  if (!isMoving || moveIndex.length < 2) {
    return null;
  }
  if (dragStartX != null && dragStartY != null) {
    final deltaX = (dragStartX - pageX).abs();
    final deltaY = (dragStartY - pageY).abs();
    if (deltaX < dragCellThreshold && deltaY < dragCellThreshold) {
      return null;
    }
  }
  final location = _apiMoveCellsLocation(
    pageX: pageX,
    pageY: pageY,
    containerLeft: containerLeft,
    containerTop: containerTop,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
    scrollLeft: scrollLeft,
    scrollTop: scrollTop,
    rowHeaderWidth: rowHeaderWidth,
    columnHeaderHeight: columnHeaderHeight,
  );
  final rowIndex = location['rowIndex']!.toInt();
  final columnIndex = location['columnIndex']!.toInt();
  final rowIndexOriginal = moveIndex[0];
  final columnIndexOriginal = moveIndex[1];
  var rowStart = selection.rowStart - rowIndexOriginal + rowIndex;
  var rowEnd = selection.rowEnd - rowIndexOriginal + rowIndex;
  var columnStart = selection.columnStart - columnIndexOriginal + columnIndex;
  var columnEnd = selection.columnEnd - columnIndexOriginal + columnIndex;
  final x = location['x']!;
  final y = location['y']!;
  final winHeight = containerHeight - 20 * zoomRatio;
  final winWidth = containerWidth - 60 * zoomRatio;

  if (rowStart < 0 || y < 0) {
    rowStart = 0;
    rowEnd = selection.rowEnd - selection.rowStart;
  }
  if (columnStart < 0 || x < 0) {
    columnStart = 0;
    columnEnd = selection.columnEnd - selection.columnStart;
  }
  if (visibleDataRows.isNotEmpty &&
      (rowEnd >= visibleDataRows.length - 1 || y > winHeight)) {
    rowStart =
        visibleDataRows.length - 1 - selection.rowEnd + selection.rowStart;
    rowEnd = visibleDataRows.length - 1;
  }
  if (visibleDataColumns.isNotEmpty &&
      (columnEnd >= visibleDataColumns.length - 1 || x > winWidth)) {
    columnStart =
        visibleDataColumns.length -
        1 -
        selection.columnEnd +
        selection.columnStart;
    columnEnd = visibleDataColumns.length - 1;
  }
  rowStart = math.max(0, rowStart);
  columnStart = math.max(0, columnStart);
  rowEnd = math.max(rowStart, rowEnd);
  columnEnd = math.max(columnStart, columnEnd);
  final left = columnStart - 1 == -1 ? 0 : visibleDataColumns[columnStart - 1];
  final right = visibleDataColumns[columnEnd];
  final top = rowStart - 1 == -1 ? 0 : visibleDataRows[rowStart - 1];
  final bottom = visibleDataRows[rowEnd];
  return {
    'range': FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
    ),
    'cellSelectedMove': _apiCellsMoveStyle(
      left: left,
      top: top,
      width: right - left - 2,
      height: bottom - top - 2,
    ),
    'dragCellStartPos': null,
  };
}

Map<String, Object?>? onCellsMoveEnd(
  FortuneSheet sheet, {
  required FortuneRange selection,
  required FortuneRange target,
  bool isMoving = true,
  bool dragStarted = false,
  bool allowEdit = true,
  bool hasPartMerge = false,
  bool hasTargetPartMerge = false,
  int? maxRowIndex,
  int? maxColumnIndex,
  String mergeMessage =
      'Cannot perform this operation on partially merged cells',
}) {
  if (!isMoving) {
    return null;
  }
  final hidePayload = <String, Object?>{
    'luckysheetCellSelectedMove': false,
    'cellSelectedMove': const {'display': 'none'},
  };
  if (dragStarted) {
    return {...hidePayload, 'dragCellStartPos': null};
  }
  if (!allowEdit) {
    return {...hidePayload, 'blocked': 'allowEdit'};
  }
  final source = _normalizedApiRange(selection);
  final rawTarget = _normalizedApiRange(target);
  if (source == null || rawTarget == null) {
    return null;
  }
  final targetRange = _apiClampMoveTarget(
    FortuneRange(
      rowStart: rawTarget.rowStart,
      rowEnd: rawTarget.rowStart + source.rowEnd - source.rowStart,
      columnStart: rawTarget.columnStart,
      columnEnd: rawTarget.columnStart + source.columnEnd - source.columnStart,
      rowFocus: selection.rowFocus == source.rowEnd
          ? rawTarget.rowStart + source.rowEnd - source.rowStart
          : rawTarget.rowStart,
      columnFocus: selection.columnFocus == source.columnEnd
          ? rawTarget.columnStart + source.columnEnd - source.columnStart
          : rawTarget.columnStart,
    ),
    maxRowIndex: maxRowIndex,
    maxColumnIndex: maxColumnIndex,
  );
  if (source.rowStart == targetRange.rowStart &&
      source.columnStart == targetRange.columnStart) {
    return null;
  }
  final sourceHasPartMerge =
      hasPartMerge ||
      hasPartMC(
        sheet,
        source.rowStart,
        source.rowEnd,
        source.columnStart,
        source.columnEnd,
      );
  final targetHasPartMerge =
      hasTargetPartMerge ||
      hasPartMC(
        sheet,
        targetRange.rowStart,
        targetRange.rowEnd,
        targetRange.columnStart,
        targetRange.columnEnd,
      );
  if (sourceHasPartMerge || targetHasPartMerge) {
    return {...hidePayload, 'blocked': 'partialMerge', 'message': mergeMessage};
  }

  final rowDelta = targetRange.rowStart - source.rowStart;
  final columnDelta = targetRange.columnStart - source.columnStart;
  final copiedCells = <FortuneCellCoord, FortuneCell>{};
  final copiedNulls = <FortuneCellCoord>{};
  final movedHyperlinks = <String, Object?>{};
  for (var row = source.rowStart; row <= source.rowEnd; row += 1) {
    for (
      var column = source.columnStart;
      column <= source.columnEnd;
      column += 1
    ) {
      final coord = FortuneCellCoord(row, column);
      final cell = sheet.cells[coord];
      if (cell != null) {
        copiedCells[coord] = cell.copyWith();
      }
      if (sheet.nullCells.contains(coord)) {
        copiedNulls.add(coord);
      }
      final hyperlink = sheet.hyperlinks['${row}_$column'];
      if (hyperlink != null) {
        movedHyperlinks['${row}_$column'] = cloneFortuneMetadata(hyperlink);
      }
    }
  }

  final nextCells = <FortuneCellCoord, FortuneCell>{
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  final nextNullCells = Set<FortuneCellCoord>.from(sheet.nullCells);
  final nextHyperlinks = _cloneStringObjectMap(sheet.hyperlinks);
  for (var row = source.rowStart; row <= source.rowEnd; row += 1) {
    for (
      var column = source.columnStart;
      column <= source.columnEnd;
      column += 1
    ) {
      final coord = FortuneCellCoord(row, column);
      nextCells.remove(coord);
      nextNullCells.remove(coord);
      nextHyperlinks.remove('${row}_$column');
    }
  }
  for (var row = targetRange.rowStart; row <= targetRange.rowEnd; row += 1) {
    for (
      var column = targetRange.columnStart;
      column <= targetRange.columnEnd;
      column += 1
    ) {
      final coord = FortuneCellCoord(row, column);
      nextCells.remove(coord);
      nextNullCells.remove(coord);
      nextHyperlinks.remove('${row}_$column');
    }
  }

  for (final entry in copiedCells.entries) {
    final destination = FortuneCellCoord(
      entry.key.row + rowDelta,
      entry.key.column + columnDelta,
    );
    nextCells[destination] = _apiMoveCellMerge(
      entry.value,
      rowDelta,
      columnDelta,
    );
  }
  for (final coord in copiedNulls) {
    nextNullCells.add(
      FortuneCellCoord(coord.row + rowDelta, coord.column + columnDelta),
    );
  }
  for (final entry in movedHyperlinks.entries) {
    final parts = entry.key.split('_');
    if (parts.length != 2) {
      continue;
    }
    final row = int.tryParse(parts[0]);
    final column = int.tryParse(parts[1]);
    if (row == null || column == null) {
      continue;
    }
    nextHyperlinks['${row + rowDelta}_${column + columnDelta}'] =
        cloneFortuneMetadata(entry.value);
  }

  final nextSelection = FortuneRange(
    rowStart: targetRange.rowStart,
    rowEnd: targetRange.rowEnd,
    columnStart: targetRange.columnStart,
    columnEnd: targetRange.columnEnd,
    rowFocus: targetRange.rowFocus,
    columnFocus: targetRange.columnFocus,
  );
  final nextSheet = sheet.copyWith(
    cells: nextCells,
    nullCells: nextNullCells,
    hyperlinks: nextHyperlinks,
    borderInfo: _apiMoveBorderInfo(sheet.borderInfo, source, targetRange),
    rawBorderInfo: _apiMoveRawBorderInfo(
      sheet.rawBorderInfo,
      source,
      targetRange,
    ),
    hasRawBorderInfo: sheet.hasRawBorderInfo,
    conditionFormats: _apiMoveConditionFormats(
      sheet.conditionFormats,
      source,
      targetRange,
    ),
    selectionSave: [_selectionRangeToApiMap(nextSelection)],
  );
  return {
    ...hidePayload,
    'sheet': nextSheet,
    'selection': nextSelection,
    'range': [
      _selectionRangeToApiMap(source),
      _selectionRangeToApiMap(targetRange),
    ],
  };
}

FortuneRange _apiClampMoveTarget(
  FortuneRange target, {
  int? maxRowIndex,
  int? maxColumnIndex,
}) {
  final rowSpan = target.rowEnd - target.rowStart;
  final columnSpan = target.columnEnd - target.columnStart;
  var rowStart = math.max(0, target.rowStart);
  var columnStart = math.max(0, target.columnStart);
  if (maxRowIndex != null && rowStart + rowSpan > maxRowIndex) {
    rowStart = math.max(0, maxRowIndex - rowSpan);
  }
  if (maxColumnIndex != null && columnStart + columnSpan > maxColumnIndex) {
    columnStart = math.max(0, maxColumnIndex - columnSpan);
  }
  final rowEnd = rowStart + rowSpan;
  final columnEnd = columnStart + columnSpan;
  return FortuneRange(
    rowStart: rowStart,
    rowEnd: rowEnd,
    columnStart: columnStart,
    columnEnd: columnEnd,
    rowFocus: target.rowFocus == target.rowEnd ? rowEnd : rowStart,
    columnFocus: target.columnFocus == target.columnEnd
        ? columnEnd
        : columnStart,
  );
}

FortuneCell _apiMoveCellMerge(FortuneCell cell, int rowDelta, int columnDelta) {
  final merge = cell.merge;
  if (merge == null) {
    return cell.copyWith();
  }
  return cell.copyWith(
    merge: merge.copyWith(
      row: merge.row + rowDelta,
      column: merge.column + columnDelta,
    ),
  );
}

List<FortuneBorderInfo> _apiMoveBorderInfo(
  List<FortuneBorderInfo> borderInfo,
  FortuneRange source,
  FortuneRange target,
) {
  final next = <FortuneBorderInfo>[];
  for (final item in borderInfo) {
    if (item.borderType == 'border-slash') {
      final ranges = _apiMoveSlashBorderRanges(item.ranges, source, target);
      if (ranges.isNotEmpty) {
        next.add(item.copyWith(ranges: ranges));
      }
      continue;
    }
    final ranges = <FortuneRange>[];
    for (final range in item.ranges) {
      ranges.addAll(cfSplitRange(range, source, target, 'allPart'));
    }
    if (ranges.isNotEmpty) {
      next.add(item.copyWith(ranges: ranges));
    }
  }
  return next;
}

List<FortuneRange> _apiMoveSlashBorderRanges(
  Iterable<FortuneRange> ranges,
  FortuneRange source,
  FortuneRange target,
) {
  final rowDelta = target.rowStart - source.rowStart;
  final columnDelta = target.columnStart - source.columnStart;
  return [
    for (final range in ranges)
      if (_apiRangeStartInRange(range, source))
        range.copyWith(
          rowStart: range.rowStart + rowDelta,
          rowEnd: range.rowEnd + rowDelta,
          columnStart: range.columnStart + columnDelta,
          columnEnd: range.columnEnd + columnDelta,
          rowFocus: range.rowFocus == null ? null : range.rowFocus! + rowDelta,
          columnFocus: range.columnFocus == null
              ? null
              : range.columnFocus! + columnDelta,
        )
      else
        range.copyWith(),
  ];
}

Object? _apiMoveRawBorderInfo(
  Object? rawBorderInfo,
  FortuneRange source,
  FortuneRange target,
) {
  if (rawBorderInfo is! List) {
    return cloneFortuneMetadata(rawBorderInfo);
  }
  final next = <Object?>[];
  final movedCells = <Map<Object?, Object?>>[];
  final rowDelta = target.rowStart - source.rowStart;
  final columnDelta = target.columnStart - source.columnStart;
  for (final item in rawBorderInfo) {
    if (item is! Map) {
      next.add(cloneFortuneMetadata(item));
      continue;
    }
    final map = Map<Object?, Object?>.from(item);
    final rangeType = _nullableStringArg(map['rangeType']);
    if (rangeType == 'range') {
      final ranges = _apiMoveRawBorderRanges(map['range'], source, target);
      if (ranges.isNotEmpty) {
        map['range'] = ranges;
        next.add(map);
      }
      continue;
    }
    if (rangeType == 'cell') {
      final value = map['value'];
      if (value is Map) {
        final valueMap = Map<Object?, Object?>.from(value);
        final row = _nullableIntArg(valueMap['row_index']);
        final column = _nullableIntArg(valueMap['col_index']);
        if (row != null &&
            column != null &&
            row >= source.rowStart &&
            row <= source.rowEnd &&
            column >= source.columnStart &&
            column <= source.columnEnd) {
          valueMap['row_index'] = row + rowDelta;
          valueMap['col_index'] = column + columnDelta;
          movedCells.add({...map, 'value': valueMap});
          continue;
        }
      }
    }
    next.add(map);
  }
  next.addAll(movedCells);
  return next;
}

List<Object?> _apiMoveRawBorderRanges(
  Object? rawRanges,
  FortuneRange source,
  FortuneRange target,
) {
  if (rawRanges is! List) {
    return const [];
  }
  final next = <Object?>[];
  for (final item in rawRanges) {
    if (item is! Map) {
      next.add(cloneFortuneMetadata(item));
      continue;
    }
    final range = _selectionRangeFromApiMap(item);
    if (range == null) {
      next.add(Map<Object?, Object?>.from(item));
      continue;
    }
    for (final split in cfSplitRange(range, source, target, 'allPart')) {
      next.add(_selectionRangeToApiMap(split));
    }
  }
  return next;
}

Object? _apiMoveConditionFormats(
  Object? conditionFormats,
  FortuneRange source,
  FortuneRange target,
) {
  final rules = _apiConditionFormatList(conditionFormats);
  if (rules.isEmpty) {
    return conditionFormats is Iterable ? <Object?>[] : conditionFormats;
  }
  return [
    for (final rule in rules)
      if (rule is Map)
        _apiMoveConditionFormatRule(rule, source, target)
      else
        cloneFortuneMetadata(rule),
  ];
}

Map<String, Object?> _apiMoveConditionFormatRule(
  Map rule,
  FortuneRange source,
  FortuneRange target,
) {
  final next = <String, Object?>{
    for (final entry in rule.entries)
      entry.key.toString(): cloneFortuneMetadata(entry.value),
  };
  final cellRanges = rule['cellrange'];
  if (cellRanges is! Iterable) {
    return next;
  }
  final movedRanges = <Map<String, Object?>>[];
  for (final item in cellRanges) {
    final range = item is FortuneRange
        ? item
        : item is Map
        ? _selectionRangeFromApiMap(item)
        : null;
    if (range == null) {
      continue;
    }
    for (final split in cfSplitRange(range, source, target, 'allPart')) {
      movedRanges.add(_selectionRangeToApiMap(split));
    }
  }
  next['cellrange'] = movedRanges;
  return next;
}

Object? _apiDropConditionFormats(
  Object? conditionFormats,
  FortuneRange copyRange,
  FortuneRange applyRange,
) {
  final rules = _apiConditionFormatList(conditionFormats);
  if (rules.isEmpty) {
    return _sentinel;
  }
  var changed = false;
  final nextRules = <Object?>[];
  for (final rule in rules) {
    if (rule is! Map) {
      nextRules.add(cloneFortuneMetadata(rule));
      continue;
    }
    final nextRule = <String, Object?>{
      for (final entry in rule.entries)
        entry.key.toString(): cloneFortuneMetadata(entry.value),
    };
    final cellRanges = rule['cellrange'];
    if (cellRanges is Iterable) {
      final hasOperatePart = cellRanges.any((item) {
        final range = item is FortuneRange
            ? item
            : item is Map
            ? _selectionRangeFromApiMap(item)
            : null;
        return range != null &&
            cfSplitRange(
              range,
              copyRange,
              applyRange,
              'operatePart',
            ).isNotEmpty;
      });
      if (hasOperatePart) {
        final nextCellRanges = [
          for (final item in cellRanges) cloneFortuneMetadata(item),
          _selectionRangeToApiMap(applyRange),
        ];
        nextRule['cellrange'] = nextCellRanges;
        changed = true;
      }
    }
    nextRules.add(nextRule);
  }
  return changed ? nextRules : _sentinel;
}

Object? _apiPasteCopyConditionFormats(
  Object? sourceConditionFormats,
  Object? targetConditionFormats,
  FortuneRange sourceRange,
  FortuneRange applyRange,
) {
  final sourceRules = _apiConditionFormatList(sourceConditionFormats);
  if (sourceRules.isEmpty) {
    return _sentinel;
  }
  final nextRules = _apiConditionFormatList(targetConditionFormats);
  var changed = false;
  final sourceRows = sourceRange.rowEnd - sourceRange.rowStart + 1;
  final sourceColumns = sourceRange.columnEnd - sourceRange.columnStart + 1;
  for (final rule in sourceRules) {
    if (rule is! Map) {
      continue;
    }
    final cellRanges = rule['cellrange'];
    if (cellRanges is! Iterable) {
      continue;
    }
    final movedRanges = <Map<String, Object?>>[];
    for (
      var targetRow = applyRange.rowStart;
      targetRow <= applyRange.rowEnd;
      targetRow += sourceRows
    ) {
      for (
        var targetColumn = applyRange.columnStart;
        targetColumn <= applyRange.columnEnd;
        targetColumn += sourceColumns
      ) {
        final targetRange = FortuneRange(
          rowStart: targetRow,
          rowEnd: math.min(targetRow + sourceRows - 1, applyRange.rowEnd),
          columnStart: targetColumn,
          columnEnd: math.min(
            targetColumn + sourceColumns - 1,
            applyRange.columnEnd,
          ),
        );
        for (final item in cellRanges) {
          final range = item is FortuneRange
              ? item
              : item is Map
              ? _selectionRangeFromApiMap(item)
              : null;
          if (range == null) {
            continue;
          }
          for (final split in cfSplitRange(
            range,
            sourceRange,
            targetRange,
            'operatePart',
          )) {
            movedRanges.add(_selectionRangeToApiMap(split));
          }
        }
      }
    }
    if (movedRanges.isEmpty) {
      continue;
    }
    final nextRule = <String, Object?>{
      for (final entry in rule.entries)
        entry.key.toString(): cloneFortuneMetadata(entry.value),
    };
    nextRule['cellrange'] = movedRanges;
    nextRules.add(nextRule);
    changed = true;
  }
  return changed ? nextRules : _sentinel;
}

Object? _apiCutSourceConditionFormats(
  Object? sourceConditionFormats,
  FortuneRange sourceRange,
  FortuneRange applyRange,
) {
  final sourceRules = _apiConditionFormatList(sourceConditionFormats);
  if (sourceRules.isEmpty) {
    return _sentinel;
  }
  var changed = false;
  final nextRules = <Object?>[];
  for (final rule in sourceRules) {
    if (rule is! Map) {
      nextRules.add(cloneFortuneMetadata(rule));
      continue;
    }
    final nextRule = <String, Object?>{
      for (final entry in rule.entries)
        entry.key.toString(): cloneFortuneMetadata(entry.value),
    };
    final cellRanges = rule['cellrange'];
    if (cellRanges is Iterable) {
      final restRanges = <Map<String, Object?>>[];
      for (final item in cellRanges) {
        final range = item is FortuneRange
            ? item
            : item is Map
            ? _selectionRangeFromApiMap(item)
            : null;
        if (range == null) {
          continue;
        }
        for (final split in cfSplitRange(
          range,
          sourceRange,
          applyRange,
          'restPart',
        )) {
          restRanges.add(_selectionRangeToApiMap(split));
        }
      }
      nextRule['cellrange'] = restRanges;
      changed = true;
    }
    nextRules.add(nextRule);
  }
  return changed ? nextRules : _sentinel;
}

Map<String, num> _apiMoveCellsLocation({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  required num scrollLeft,
  required num scrollTop,
  required num rowHeaderWidth,
  required num columnHeaderHeight,
}) {
  final x = pageX - containerLeft - rowHeaderWidth + scrollLeft;
  final y = pageY - containerTop - columnHeaderHeight + scrollTop;
  final row = rowLocation(y, visibleDataRows);
  final column = colLocation(x, visibleDataColumns);
  return {
    'x': x,
    'y': y,
    'rowPre': row[0],
    'row': row[1],
    'rowIndex': row[2],
    'columnPre': column[0],
    'column': column[1],
    'columnIndex': column[2],
  };
}

Map<String, Object?> _apiCellsMoveStyle({
  required num left,
  required num top,
  required num width,
  required num height,
}) {
  return {
    'left': '${left}px',
    'top': '${top}px',
    'width': '${width}px',
    'height': '${height}px',
    'display': 'block',
  };
}

int _apiClampInt(int value, int minValue, int maxValue) {
  return math.max(minValue, math.min(maxValue, value));
}

Map<String, Object?>? onDropCellSelect({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  required FortuneRange selection,
  required List<int> extendIndex,
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
}) {
  if (extendIndex.length < 2) {
    return null;
  }
  final location = _apiDropCellLocation(
    pageX: pageX,
    pageY: pageY,
    containerLeft: containerLeft,
    containerTop: containerTop,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
    scrollLeft: scrollLeft,
    scrollTop: scrollTop,
    rowHeaderWidth: rowHeaderWidth,
    columnHeaderHeight: columnHeaderHeight,
  );
  final rowIndex = location['rowIndex']!;
  final columnIndex = location['columnIndex']!;
  final rowIndexOriginal = extendIndex[0];
  final columnIndexOriginal = extendIndex[1];
  final top = _nullableDoubleArg(selection.extraFields['top_move']);
  var height = _nullableDoubleArg(selection.extraFields['height_move']);
  final left = _nullableDoubleArg(selection.extraFields['left_move']);
  var width = _nullableDoubleArg(selection.extraFields['width_move']);
  if (top == null || height == null || left == null || width == null) {
    return null;
  }
  var nextTop = top;
  var nextLeft = left;
  if ((rowIndexOriginal - rowIndex).abs() >
      (columnIndexOriginal - columnIndex).abs()) {
    if (rowIndex < selection.rowStart || rowIndex > selection.rowEnd) {
      final rowPre = location['rowPre']!;
      final row = location['row']!;
      if (nextTop >= rowPre) {
        height += nextTop - rowPre;
        nextTop = rowPre.toDouble();
      } else {
        height = row - nextTop - 1;
      }
    }
  } else {
    if (columnIndex < selection.columnStart ||
        columnIndex > selection.columnEnd) {
      final columnPre = location['columnPre']!;
      final column = location['column']!;
      if (nextLeft >= columnPre) {
        width += nextLeft - columnPre;
        nextLeft = columnPre.toDouble();
      } else {
        width = column - nextLeft - 1;
      }
    }
  }
  return {
    'dropCellSelection': showDropCellSelection(
      left: nextLeft,
      width: width,
      top: nextTop,
      height: height,
    ),
  };
}

Map<String, Object?>? onDropCellSelectEnd(
  FortuneSheet sheet, {
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  required FortuneRange selection,
  required List<int> extendIndex,
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
}) {
  if (extendIndex.length < 2) {
    return null;
  }
  final location = _apiDropCellLocation(
    pageX: pageX,
    pageY: pageY,
    containerLeft: containerLeft,
    containerTop: containerTop,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
    scrollLeft: scrollLeft,
    scrollTop: scrollTop,
    rowHeaderWidth: rowHeaderWidth,
    columnHeaderHeight: columnHeaderHeight,
  );
  final rowIndex = location['rowIndex']!.toInt();
  final columnIndex = location['columnIndex']!.toInt();
  final rowIndexOriginal = extendIndex[0];
  final columnIndexOriginal = extendIndex[1];
  var rowStart = selection.rowStart;
  var rowEnd = selection.rowEnd;
  var columnStart = selection.columnStart;
  var columnEnd = selection.columnEnd;
  FortuneRange? applyRange;
  var direction = '';
  if ((rowIndexOriginal - rowIndex).abs() >
      (columnIndexOriginal - columnIndex).abs()) {
    if (rowIndex >= selection.rowStart && rowIndex <= selection.rowEnd) {
      return null;
    }
    final topMove = _nullableDoubleArg(selection.extraFields['top_move']);
    if (topMove != null && topMove >= location['rowPre']!) {
      applyRange = FortuneRange(
        rowStart: rowIndex,
        rowEnd: selection.rowStart - 1,
        columnStart: selection.columnStart,
        columnEnd: selection.columnEnd,
      );
      direction = 'up';
      rowStart -= selection.rowStart - rowIndex;
    } else {
      applyRange = FortuneRange(
        rowStart: selection.rowEnd + 1,
        rowEnd: rowIndex,
        columnStart: selection.columnStart,
        columnEnd: selection.columnEnd,
      );
      direction = 'down';
      rowEnd += rowIndex - selection.rowEnd;
    }
  } else {
    if (columnIndex >= selection.columnStart &&
        columnIndex <= selection.columnEnd) {
      return null;
    }
    final leftMove = _nullableDoubleArg(selection.extraFields['left_move']);
    if (leftMove != null && leftMove >= location['columnPre']!) {
      applyRange = FortuneRange(
        rowStart: selection.rowStart,
        rowEnd: selection.rowEnd,
        columnStart: columnIndex,
        columnEnd: selection.columnStart - 1,
      );
      direction = 'left';
      columnStart -= selection.columnStart - columnIndex;
    } else {
      applyRange = FortuneRange(
        rowStart: selection.rowStart,
        rowEnd: selection.rowEnd,
        columnStart: selection.columnEnd + 1,
        columnEnd: columnIndex,
      );
      direction = 'right';
      columnEnd += columnIndex - selection.columnEnd;
    }
  }
  if (pageY - containerTop - columnHeaderHeight + scrollTop < 0) {
    rowStart = 0;
    rowEnd = selection.rowStart;
  }
  if (pageX - containerLeft - rowHeaderWidth + scrollLeft < 0) {
    columnStart = 0;
    columnEnd = selection.columnStart;
  }
  if (_apiHasMergeInRange(sheet, selection) ||
      _apiHasMergeInRange(
        sheet,
        FortuneRange(
          rowStart: rowStart,
          rowEnd: rowEnd,
          columnStart: columnStart,
          columnEnd: columnEnd,
        ),
      )) {
    return null;
  }
  return {
    ...autoFillCell(sheet, selection, applyRange, direction),
    'selection': _selectionRangeToApiMap(
      FortuneRange(
        rowStart: rowStart,
        rowEnd: rowEnd,
        columnStart: columnStart,
        columnEnd: columnEnd,
      ),
    ),
    'dropCellSelection': hideDropCellSelection(),
  };
}

Map<String, num> _apiDropCellLocation({
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
}) {
  final x = pageX - containerLeft - rowHeaderWidth + scrollLeft;
  final y = pageY - containerTop - columnHeaderHeight + scrollTop;
  final rowLocationResult = rowLocation(y, visibleDataRows);
  final columnLocationResult = colLocation(x, visibleDataColumns);
  return {
    'x': x,
    'y': y,
    'rowPre': rowLocationResult[0],
    'row': rowLocationResult[1],
    'rowIndex': rowLocationResult[2],
    'columnPre': columnLocationResult[0],
    'column': columnLocationResult[1],
    'columnIndex': columnLocationResult[2],
  };
}

bool _apiHasMergeInRange(FortuneSheet sheet, FortuneRange range) {
  final normalized = _normalizedApiRange(range) ?? range;
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      if (sheet.cells[FortuneCellCoord(row, column)]?.merge != null) {
        return true;
      }
    }
  }
  return false;
}

Map<String, Object?> onFormulaRangeDragEnd({
  Map<String, Object?>? funcSelectedRange,
  bool rangeStart = false,
  bool rangeDragColumnStart = false,
  bool rangeDragRowStart = false,
  int rangeIndex = 0,
}) {
  final payload = <String, Object?>{'selectingRangeIndex': -1};
  final left = funcSelectedRange?['left_move'];
  final top = funcSelectedRange?['top_move'];
  final width = funcSelectedRange?['width_move'];
  final height = funcSelectedRange?['height_move'];
  if (left != null &&
      top != null &&
      width != null &&
      height != null &&
      (rangeStart || rangeDragColumnStart || rangeDragRowStart)) {
    payload['formulaRangeSelect'] = <String, Object?>{
      'rangeIndex': rangeIndex,
      'left': left,
      'top': top,
      'width': width,
      'height': height,
    };
  }
  return payload;
}

List<Map<String, Object?>> createRangeHightlight(
  FortuneSheet sheet,
  String inputInnerHtmlStr, {
  int ignoreRangeIndex = -1,
  int selectingRangeIndex = -1,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  final highlights = <Map<String, Object?>>[];
  final spanPattern = RegExp(
    r'<span\b([^>]*)>(.*?)</span>',
    caseSensitive: false,
    dotAll: true,
  );
  for (final match in spanPattern.allMatches(inputInnerHtmlStr)) {
    final attrs = match.group(1) ?? '';

    if (!attrs.contains('fortune-formula-functionrange-cell')) {
      continue;
    }
    final rangeIndex = _apiHtmlAttribute(attrs, 'rangeindex') ?? '0';
    final parsedRangeIndex = int.tryParse(rangeIndex) ?? 0;
    if (parsedRangeIndex == ignoreRangeIndex ||
        parsedRangeIndex == selectingRangeIndex) {
      continue;
    }
    final rangeText = _apiPlainTextFromHtml(match.group(2) ?? '').trim();
    final range = getRangeByTxt(
      sheet,
      rangeText,
    ).whereType<FortuneRange>().firstOrNull;
    if (range == null) {
      continue;
    }
    final rowStart = rowLocationByIndex(range.rowStart, visibleDataRows)[0];
    final rowEnd = rowLocationByIndex(range.rowEnd, visibleDataRows)[1];
    final columnStart = colLocationByIndex(
      range.columnStart,
      visibleDataColumns,
    )[0];
    final columnEnd = colLocationByIndex(
      range.columnEnd,
      visibleDataColumns,
    )[1];
    highlights.add({
      'rangeIndex': parsedRangeIndex,
      'left': columnStart,
      'top': rowStart,
      'width': columnEnd - columnStart - 1,
      'height': rowEnd - rowStart - 1,
      'backgroundColor': colors[parsedRangeIndex % colors.length],
    });
  }
  return highlights;
}

String? _apiHtmlAttribute(String attrs, String name) {
  final escapedName = RegExp.escape(name);
  final doubleQuoted = RegExp(
    '$escapedName="([^"]*)"',
    caseSensitive: false,
  ).firstMatch(attrs);
  if (doubleQuoted != null) {
    return doubleQuoted.group(1);
  }
  final singleQuoted = RegExp(
    "$escapedName='([^']*)'",
    caseSensitive: false,
  ).firstMatch(attrs);
  if (singleQuoted != null) {
    return singleQuoted.group(1);
  }
  return RegExp(
    '$escapedName='
    r'([^\s>]+)',
    caseSensitive: false,
  ).firstMatch(attrs)?.group(1);
}

String _apiPlainTextFromHtml(String html) {
  return html.replaceAll(RegExp(r'<[^>]*>'), '');
}

Map<String, Object?> cancelFunctionrangeSelected({
  int selectingRangeIndex = -1,
}) {
  return {
    if (selectingRangeIndex == -1) 'formulaRangeSelect': null,
    'rangeCountVisible': false,
    'formulaSearchVisible': false,
    'formulaHelpVisible': false,
  };
}

Map<String, Object?> cancelNormalSelected({int selectingRangeIndex = -1}) {
  return {
    ...cancelFunctionrangeSelected(selectingRangeIndex: selectingRangeIndex),
    'luckysheetCellUpdate': const <Object?>[],
    'formulaRangeHighlight': const <Object?>[],
    'functionHint': null,
    'inputBoxStyle': null,
    'inputBoxIndexVisible': false,
  };
}

Map<String, Object?> cancelPaintModel({
  String? copySheetId,
  String? currentSheetId,
}) {
  if (copySheetId == null) {
    return const <String, Object?>{};
  }
  return {
    'selectionRangeTargetSheetId': copySheetId == currentSheetId
        ? currentSheetId
        : copySheetId,
    'luckysheetSelectionRange': const <Object?>[],
    'luckysheetCopySave': const {
      'dataSheetId': '',
      'copyRange': [
        {
          'row': [0],
          'column': [0],
        },
      ],
      'RowlChange': false,
      'HasMC': false,
    },
    'luckysheetPaintModelOn': false,
  };
}

Map<String, Object?>? handleFormatPainter(
  FortuneSheet sheet, {
  List<FortuneRange>? selection,
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return null;
  }
  final ranges = selection ?? getSelection(sheet);
  if (ranges.length != 1) {
    return null;
  }
  final range = ranges.single;
  if (hasPartMC(
    sheet,
    range.rowStart,
    range.rowEnd,
    range.columnStart,
    range.columnEnd,
  )) {
    return null;
  }
  var rowLengthChanged = false;
  var hasMergedCell = false;
  for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
    if (sheet.hiddenRows.contains(row)) {
      continue;
    }
    if (sheet.rowHeights.containsKey(row)) {
      rowLengthChanged = true;
    }
    for (
      var column = range.columnStart;
      column <= range.columnEnd;
      column += 1
    ) {
      final merge = sheet.cells[FortuneCellCoord(row, column)]?.merge;
      if (merge != null && merge.rowSpan > 0) {
        hasMergedCell = true;
      }
    }
  }
  final rangeMap = _selectionRangeToApiMap(range);
  return {
    ...cancelPaintModel(copySheetId: sheet.id, currentSheetId: sheet.id),
    'luckysheetSelectionRange': [rangeMap],
    'luckysheetCopySave': {
      'dataSheetId': sheet.id,
      'copyRange': [rangeMap],
      'RowlChange': rowLengthChanged,
      'HasMC': hasMergedCell,
    },
    'luckysheetPaintModelOn': true,
    'luckysheetPaintSingle': true,
  };
}

List<bool> getTypeItemHide(FortuneSheet sheet, FortuneRange copyRange) {
  final normalized = _normalizedApiRange(copyRange);
  if (normalized == null) {
    return const <bool>[];
  }
  var hasNumber = false;
  var hasExtendNumber = false;
  var hasDate = false;
  var hasChn = false;
  var hasChnWeek1 = false;
  var hasChnWeek2 = false;
  var hasChnWeek3 = false;
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      final cell = sheet.cells[FortuneCellCoord(row, column)];
      if (cell == null || cell.formula != null) {
        continue;
      }
      final value = cell.hasRawValue ? cell.rawValue : cell.value;
      if (value == null) {
        continue;
      }
      final cellType = cell.cellType?.type;
      final displayValue = cell.hasRawDisplayValue
          ? cell.rawDisplayValue
          : cell.displayValue ?? cell.value;
      if (cellType == 'n') {
        hasNumber = true;
      } else if (cellType == 'd') {
        hasDate = true;
      } else if (isExtendNumber(displayValue)[0] == true) {
        hasExtendNumber = true;
      } else if (isChnNumber(displayValue) && displayValue != '日') {
        hasChn = true;
      } else if (displayValue == '日') {
        hasChnWeek1 = true;
      } else if (_apiIsChnWeek2(displayValue)) {
        hasChnWeek2 = true;
      } else if (_apiIsChnWeek3(displayValue)) {
        hasChnWeek3 = true;
      }
    }
  }
  return <bool>[
    hasNumber,
    hasExtendNumber,
    hasDate,
    hasChn,
    hasChnWeek1,
    hasChnWeek2,
    hasChnWeek3,
  ];
}

Map<String, Object?> autoFillCell(
  FortuneSheet sheet,
  FortuneRange copyRange,
  FortuneRange applyRange,
  String direction,
) {
  final typeItemHide = getTypeItemHide(sheet, copyRange);
  final hasFillSeriesType = typeItemHide.take(7).any((hidden) => hidden);
  return <String, Object?>{
    'copyRange': _apiDropRangeMap(copyRange),
    'applyRange': _apiDropRangeMap(applyRange),
    'direction': direction,
    'applyType': hasFillSeriesType ? '1' : '0',
  };
}

Map<String, Object?> _apiDropRangeMap(FortuneRange range) {
  final normalized = _normalizedApiRange(range) ?? range;
  return <String, Object?>{
    'row': <int>[normalized.rowStart, normalized.rowEnd],
    'column': <int>[normalized.columnStart, normalized.columnEnd],
  };
}

bool _apiIsChnWeek2(Object? text) {
  final value = text?.toString();
  return value == '周一' ||
      value == '周二' ||
      value == '周三' ||
      value == '周四' ||
      value == '周五' ||
      value == '周六' ||
      value == '周日';
}

bool _apiIsChnWeek3(Object? text) {
  final value = text?.toString();
  return value == '星期一' ||
      value == '星期二' ||
      value == '星期三' ||
      value == '星期四' ||
      value == '星期五' ||
      value == '星期六' ||
      value == '星期日';
}

