String fortuneSparklineType(Object? raw) {
  if (raw is Map) {
    final type = raw['type'] ?? raw['chartType'] ?? raw['name'];
    if (type != null) {
      return '$type'.toLowerCase();
    }
  }
  return 'line';
}

List<double> fortuneSparklineValues(Object? raw) {
  final values = <double>[];

  void collect(Object? value) {
    if (value == null) {
      return;
    }
    if (value is num) {
      if (value.isFinite) {
        values.add(value.toDouble());
      }
      return;
    }
    if (value is String) {
      for (final token in value.split(RegExp(r'[,\s]+'))) {
        final parsed = double.tryParse(token.trim());
        if (parsed != null && parsed.isFinite) {
          values.add(parsed);
        }
      }
      return;
    }
    if (value is List) {
      for (final item in value) {
        collect(item);
      }
      return;
    }
    if (value is Map) {
      for (final key in const ['data', 'values', 'value', 'range']) {
        if (value.containsKey(key)) {
          collect(value[key]);
          return;
        }
      }
    }
  }

  collect(raw);
  return values;
}

List<Object?> fortuneSparklineChildren(Object? raw) {
  final children = <Object?>[];

  void collectChildren(Object? value) {
    if (value is List) {
      for (final item in value) {
        if (item is Map) {
          children.add(item);
        } else if (item is List) {
          children.add({'type': 'line', 'data': item});
        } else {
          collectChildren(item);
        }
      }
      return;
    }
    if (value is Map) {
      final type = value['type'] ?? value['chartType'] ?? value['name'];
      final normalizedType = type == null ? null : '$type'.toLowerCase();
      if (normalizedType != null &&
          normalizedType != 'compose' &&
          normalizedType != 'composespline' &&
          normalizedType != 'composesplines') {
        children.add(value);
        return;
      }
      for (final key in const [
        'children',
        'sparklines',
        'charts',
        'items',
        'series',
        'configs',
        'data',
        'values',
        'value',
        'range',
      ]) {
        if (value.containsKey(key)) {
          collectChildren(value[key]);
          return;
        }
      }
    }
  }

  collectChildren(raw);
  return children;
}

List<Offset> fortuneSparklinePoints(List<double> values, ui.Rect rect) {
  if (values.length < 2 || rect.width <= 0 || rect.height <= 0) {
    return const [];
  }
  final minimum = values.reduce(math.min);
  final maximum = values.reduce(math.max);
  final span = maximum - minimum;
  return [
    for (var index = 0; index < values.length; index += 1)
      Offset(
        rect.left + rect.width * index / (values.length - 1),
        rect.bottom -
            (span == 0 ? 0.5 : (values[index] - minimum) / span) * rect.height,
      ),
  ];
}

String indexToColumnChar(int index) {
  var value = index;
  var text = '';
  while (value >= 0) {
    text = String.fromCharCode((value % 26) + 65) + text;
    value = value ~/ 26 - 1;
  }
  return text;
}

int? columnCharToIndex(String? value) {
  if (value == null || value.isEmpty) {
    return null;
  }
  final normalized = value.toLowerCase();
  var index = 0;
  for (var position = 0; position < normalized.length; position += 1) {
    final charNumber = normalized.codeUnitAt(position) - 96;
    index +=
        charNumber * math.pow(26, normalized.length - position - 1).toInt();
  }
  if (index == 0) {
    return null;
  }
  return index - 1;
}

int rowLabelToIndex(Object? label) {
  final parsed = _formulaParserParseInt(label);
  if (parsed == null) {
    return -1;
  }
  return math.max(parsed - 1, -1);
}

String rowIndexToLabel(int row) {
  return row >= 0 ? '${row + 1}' : '';
}

int columnLabelToIndex(Object? label) {
  var result = 0;
  if (label is String) {
    final normalized = label.toUpperCase();
    for (
      var index = 0, power = normalized.length - 1;
      index < normalized.length;
      index += 1, power -= 1
    ) {
      final charIndex = normalized.codeUnitAt(index) - 65;
      final value = charIndex >= 0 && charIndex < 26 ? charIndex : -1;
      result += math.pow(26, power).toInt() * (value + 1);
    }
  }
  return result - 1;
}

String columnIndexToLabel(int column) => indexToColumnChar(column);

final RegExp _formulaParserLabelExtractRegExp = RegExp(
  r"^(?:([A-Za-z0-9_\u00C0-\u02AF]+|'(?:(?!').|'')*')!)?([\$])?([A-Za-z]*)([\$])?([0-9]*)$",
);

List<Object?> extractLabel(Object? label) {
  if (label is! String) {
    return const [];
  }
  final match = _formulaParserLabelExtractRegExp.firstMatch(
    label.toUpperCase(),
  );
  if (match == null) {
    return const [];
  }
  final sheetNameText = match.group(1);
  final columnAbs = match.group(2);
  final column = match.group(3) ?? '';
  final rowAbs = match.group(4);
  final row = match.group(5) ?? '';
  final sheetName = sheetNameText == null
      ? null
      : label
            .substring(0, sheetNameText.length)
            .replaceAll(RegExp(r"^'|'$"), '')
            .replaceAll("''", "'");
  final extracted = <Object?>[
    {'index': rowLabelToIndex(row), 'label': row, 'isAbsolute': rowAbs == r'$'},
    {
      'index': columnLabelToIndex(column),
      'label': column,
      'isAbsolute': columnAbs == r'$',
    },
  ];
  if (sheetName != null) {
    extracted.add(sheetName);
  }
  return extracted;
}

String toLabel(Map<String, Object?> row, Map<String, Object?> column) {
  final rowIndex = row['index'];
  final columnIndex = column['index'];
  final rowText = rowIndex is int ? rowIndexToLabel(rowIndex) : '';
  final columnText = columnIndex is int ? columnIndexToLabel(columnIndex) : '';
  return '${column['isAbsolute'] == true ? r'$' : ''}$columnText'
      '${row['isAbsolute'] == true ? r'$' : ''}$rowText';
}

num? toNumber(Object? number) {
  if (number is num) {
    return number;
  }
  if (number is String) {
    return number.contains('.')
        ? _formulaParserParseDouble(number) ?? double.nan
        : _formulaParserParseInt(number) ?? double.nan;
  }
  return null;
}

num invertNumber(Object? number) {
  final value = toNumber(number);
  if (value == null) {
    return double.nan;
  }
  if (value == 0) {
    return -0.0;
  }
  return -1 * value;
}

String trimEdges(String value, [int margin = 1]) {
  return value.substring(margin, value.length - margin);
}

int? _formulaParserParseInt(Object? value) {
  final match = RegExp(r'^\s*([+-]?\d+)').firstMatch('$value');
  return match == null ? null : int.tryParse(match.group(1)!);
}

double? _formulaParserParseDouble(String value) {
  final match = RegExp(
    r'^\s*([+-]?(?:(?:\d+\.?\d*)|(?:\.\d+))(?:[eE][+-]?\d+)?)',
  ).firstMatch(value);
  return match == null ? null : double.tryParse(match.group(1)!);
}

List<num> mousePosition(
  num x,
  num y, {
  num rowHeaderWidth = 0,
  num toolbarHeight = 0,
  num calculatebarHeight = 0,
  num columnHeaderHeight = 0,
}) {
  return [
    x - rowHeaderWidth,
    y - toolbarHeight - calculatebarHeight - columnHeaderHeight,
  ];
}

List<num> rowLocationByIndex(int rowIndex, List<num> visibleRow) {
  if (visibleRow.isEmpty) {
    return const [0, 0, 0];
  }
  final boundedIndex = rowIndex.clamp(0, visibleRow.length - 1);
  final row = visibleRow[boundedIndex];
  final previousRow = boundedIndex == 0 ? 0 : visibleRow[boundedIndex - 1];
  return [previousRow, row, boundedIndex];
}

List<num> rowLocation(num offsetY, List<num> visibleRow) {
  if (visibleRow.isEmpty) {
    return const [0, 0, 0];
  }
  var rowIndex = _apiSortedIndex(visibleRow, offsetY);
  if (rowIndex >= visibleRow.length && offsetY > 0) {
    rowIndex = visibleRow.length - 1;
  } else if (rowIndex < 0 && offsetY <= 0) {
    rowIndex = 0;
  }
  return rowLocationByIndex(rowIndex, visibleRow);
}

List<num> colLocationByIndex(int columnIndex, List<num> visibleColumn) {
  if (visibleColumn.isEmpty) {
    return const [0, 0, 0];
  }
  final boundedIndex = columnIndex.clamp(0, visibleColumn.length - 1);
  final column = visibleColumn[boundedIndex];
  final previousColumn = boundedIndex == 0
      ? 0
      : visibleColumn[boundedIndex - 1];
  return [previousColumn, column, boundedIndex];
}

List<num> colLocation(num offsetX, List<num> visibleColumn) {
  if (visibleColumn.isEmpty) {
    return const [0, 0, 0];
  }
  var columnIndex = _apiSortedIndex(visibleColumn, offsetX);
  if (columnIndex >= visibleColumn.length && offsetX > 0) {
    columnIndex = visibleColumn.length - 1;
  } else if (columnIndex < 0 && offsetX <= 0) {
    columnIndex = 0;
  }
  return colLocationByIndex(columnIndex, visibleColumn);
}

num getFrozenHandleTop(
  FortuneSheet? sheet, {
  List<num> visibleDataRows = const [],
  num scrollTop = 0,
}) {
  final frozen = sheet?.frozen;
  if (frozen != null && frozen.freezesRows) {
    return rowLocationByIndex(frozen.rowFocus ?? 0, visibleDataRows)[1] +
        scrollTop;
  }
  return scrollTop;
}

num getFrozenHandleLeft(
  FortuneSheet? sheet, {
  List<num> visibleDataColumns = const [],
  num scrollLeft = 0,
}) {
  final frozen = sheet?.frozen;
  if (frozen != null && frozen.freezesColumns) {
    return colLocationByIndex(frozen.columnFocus ?? 0, visibleDataColumns)[1] -
        2 +
        scrollLeft;
  }
  return scrollLeft;
}

Map<String, Object?> scroll({
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
  Object? scrollLeft,
  Object? scrollTop,
  Object? targetRow,
  Object? targetColumn,
}) {
  final result = <String, Object?>{};
  if (scrollLeft != null) {
    if (scrollLeft is! num) {
      throw INVALID_PARAMS;
    }
    result['scrollLeft'] = scrollLeft;
  } else if (targetColumn != null) {
    if (targetColumn is! num) {
      throw INVALID_PARAMS;
    }
    final offset = _apiScrollOffsetFromTarget(
      targetColumn.toInt(),
      visibleDataColumns,
    );
    if (offset != null) {
      result['scrollLeft'] = offset;
    }
  }
  if (scrollTop != null) {
    if (scrollTop is! num) {
      throw INVALID_PARAMS;
    }
    result['scrollTop'] = scrollTop;
  } else if (targetRow != null) {
    if (targetRow is! num) {
      throw INVALID_PARAMS;
    }
    final offset = _apiScrollOffsetFromTarget(
      targetRow.toInt(),
      visibleDataRows,
    );
    if (offset != null) {
      result['scrollTop'] = offset;
    }
  }
  return result;
}

Map<String, num> scrollToHighlightCell(
  FortuneSheet? sheet,
  int row,
  int column, {
  num scrollLeft = 0,
  num scrollTop = 0,
  num viewportWidth = 0,
  num viewportHeight = 0,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  var nextScrollLeft = scrollLeft;
  var nextScrollTop = scrollTop;
  final frozen = sheet?.frozen;
  if (row >= 0 && row < visibleDataRows.length) {
    final rowFocus = frozen?.rowFocus ?? 0;
    final freezeHeight = frozen != null && row > rowFocus
        ? _apiAxisValue(visibleDataRows, rowFocus)
        : 0;
    final rowBottom = visibleDataRows[row];
    final rowTop = row == 0 ? 0 : visibleDataRows[row - 1];
    if (rowBottom - scrollTop - viewportHeight + 20 > 0) {
      nextScrollTop = rowBottom - viewportHeight + 20;
    } else if (rowTop - scrollTop - freezeHeight < 0) {
      nextScrollTop = rowTop - math.max<num>(20, freezeHeight);
    }
  }
  if (column >= 0 && column < visibleDataColumns.length) {
    final columnFocus = frozen?.columnFocus ?? 0;
    final freezeWidth = frozen != null && column > columnFocus
        ? _apiAxisValue(visibleDataColumns, columnFocus)
        : 0;
    final columnRight = visibleDataColumns[column];
    final columnLeft = column == 0 ? 0 : visibleDataColumns[column - 1];
    if (columnRight - scrollLeft - viewportWidth + 20 > 0) {
      nextScrollLeft = columnRight - viewportWidth + 20;
    } else if (columnLeft - scrollLeft - freezeWidth < 0) {
      nextScrollLeft = columnLeft - math.max<num>(20, freezeWidth);
    }
  }
  return <String, num>{
    'scrollLeft': nextScrollLeft,
    'scrollTop': nextScrollTop,
  };
}

Map<String, num> scrollToFrozenRowCol(
  FortuneSheet? sheet,
  Object? freeze, {
  num scrollLeft = 0,
  num scrollTop = 0,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
  List<FortuneRange>? selection,
}) {
  var nextScrollLeft = scrollLeft;
  var nextScrollTop = scrollTop;
  final ranges = selection ?? sheet?.getSelection();
  if (ranges == null || ranges.isEmpty) {
    return <String, num>{
      'scrollLeft': nextScrollLeft,
      'scrollTop': nextScrollTop,
    };
  }
  final range = ranges.first;
  int? row;
  final rowFocus = range.rowFocus;
  if (rowFocus == range.rowStart) {
    row = range.rowEnd;
  } else if (rowFocus == range.rowEnd) {
    row = range.rowStart;
  }
  int? column;
  final columnFocus = range.columnFocus;
  if (columnFocus == range.columnStart) {
    column = range.columnEnd;
  } else if (columnFocus == range.columnEnd) {
    column = range.columnStart;
  }

  final vertical = _apiFreezeAxisScrollData(
    freeze,
    'vertical',
    'freezenverticaldata',
  );
  if (vertical != null && column != null && visibleDataColumns.isNotEmpty) {
    final columnIndex = column.clamp(0, visibleDataColumns.length - 1);
    final freezeColumnIndex =
        (vertical.$1 + _apiSortedIndex(vertical.$2, scrollLeft)).clamp(
          0,
          visibleDataColumns.length - 1,
        );
    if (visibleDataColumns[columnIndex] <=
        visibleDataColumns[freezeColumnIndex] + vertical.$3) {
      nextScrollLeft = 0;
    }
  }

  final horizontal = _apiFreezeAxisScrollData(
    freeze,
    'horizontal',
    'freezenhorizontaldata',
  );
  if (horizontal != null && row != null && visibleDataRows.isNotEmpty) {
    final rowIndex = row.clamp(0, visibleDataRows.length - 1);
    final freezeRowIndex =
        (horizontal.$1 + _apiSortedIndex(horizontal.$2, scrollTop)).clamp(
          0,
          visibleDataRows.length - 1,
        );
    if (visibleDataRows[rowIndex] <=
        visibleDataRows[freezeRowIndex] + horizontal.$3) {
      nextScrollTop = 0;
    }
  }
  return <String, num>{
    'scrollLeft': nextScrollLeft,
    'scrollTop': nextScrollTop,
  };
}

num _apiAxisValue(List<num> values, int index) {
  if (values.isEmpty) {
    return 0;
  }
  return values[index.clamp(0, values.length - 1)];
}

num? _apiScrollOffsetFromTarget(int targetIndex, List<num> visibleAxis) {
  if (targetIndex <= 0) {
    return 0;
  }
  final previousIndex = targetIndex - 1;
  if (previousIndex < 0 || previousIndex >= visibleAxis.length) {
    return null;
  }
  return visibleAxis[previousIndex];
}

List<num> computeRowlenArr(
  FortuneSheet sheet,
  int rowHeight, {
  FortuneSettings? settings,
}) {
  final rowlenArr = <num>[];
  var height = 0.0;
  final defaultRowHeight =
      sheet.defaultRowHeight?.toDouble() ??
      settings?.defaultRowHeight.toDouble() ??
      const FortuneSettings().defaultRowHeight.toDouble();
  for (var row = 0; row < rowHeight; row += 1) {
    var rowlen = sheet.rowHeights[row] ?? defaultRowHeight;
    if (sheet.hiddenRows.contains(row)) {
      rowlen = _nullableDoubleArg(sheet.hiddenRowValues[row]) ?? 0;
      rowlenArr.add(height);
      continue;
    }
    height += rowlen + 1;
    rowlenArr.add(height);
  }
  return rowlenArr;
}

bool isShowHidenCR(FortuneSheet sheet, [Iterable<FortuneRange>? ranges]) {
  final selection = (ranges ?? sheet.getSelection()).toList();
  if (selection.isEmpty ||
      (sheet.hiddenRows.isEmpty && sheet.hiddenColumns.isEmpty)) {
    return false;
  }
  final first = selection.first;
  return sheet.hiddenColumns.contains(first.columnStart) ||
      sheet.hiddenRows.contains(first.rowStart);
}

int hideCRCount(FortuneSheet sheet, String type, {FortuneRange? selection}) {
  final range = selection ?? sheet.getSelection().firstOrNull;
  if (range == null) {
    return 0;
  }
  if (type == 'ArrowUp' || type == 'ArrowDown') {
    final hiddenRows = sheet.hiddenRows.toList()..sort();
    final step = type == 'ArrowUp' ? -1 : 1;
    return _apiHiddenAxisCount(hiddenRows, range.rowStart + step, step);
  }
  if (type == 'ArrowLeft' || type == 'ArrowRight') {
    final hiddenColumns = sheet.hiddenColumns.toList()..sort();
    final step = type == 'ArrowLeft' ? -1 : 1;
    return _apiHiddenAxisCount(hiddenColumns, range.columnStart + step, step);
  }
  return 1;
}

int _apiHiddenAxisCount(List<int> hiddenAxis, int firstIndex, int step) {
  var count = 1;
  var current = firstIndex;
  while (hiddenAxis.contains(current)) {
    count += 1;
    current += step;
  }
  return count;
}

