FortuneSheet saveImage(FortuneSheet sheet, List<FortuneImage> insertedImgs) {
  return sheet.copyWith(images: insertedImgs);
}

FortuneSheet removeActiveImage(
  FortuneSheet sheet,
  String? activeImg, {
  List<FortuneImage>? insertedImgs,
}) {
  final images = insertedImgs ?? sheet.images;
  if (activeImg == null) {
    return saveImage(sheet, images);
  }
  return saveImage(sheet, [
    for (final image in images)
      if (image.id != activeImg) image,
  ]);
}

FortuneSheet insertImage(
  FortuneSheet sheet, {
  required String src,
  required num width,
  required num height,
  String? id,
  Iterable<FortuneRange>? selection,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  final ranges = (selection ?? getSelection(sheet)).toList();
  final last = ranges.isEmpty ? null : ranges.last;
  var rowIndex = last?.rowFocus ?? last?.rowStart ?? 0;
  var columnIndex = last?.columnFocus ?? last?.columnStart ?? 0;
  final anchor = sheet.mergeAnchorFor(FortuneCellCoord(rowIndex, columnIndex));
  rowIndex = anchor.row;
  columnIndex = anchor.column;
  final left = columnIndex == 0 || visibleDataColumns.length < columnIndex
      ? 0
      : visibleDataColumns[columnIndex - 1];
  final top = rowIndex == 0 || visibleDataRows.length < rowIndex
      ? 0
      : visibleDataRows[rowIndex - 1];
  final image = FortuneImage(
    id: id ?? generateRandomId(null),
    src: src,
    left: left.toDouble(),
    top: top.toDouble(),
    width: width.toDouble() * 0.5,
    height: height.toDouble() * 0.5,
    extraFields: {'originWidth': width, 'originHeight': height},
  );
  return saveImage(sheet, [...sheet.images, image]);
}

