Map<String, Object?>? onImageMove(
  Map<String, Object?>? globalCacheImage, {
  required num pageX,
  required num pageY,
  num? minLeft,
  num minTop = 0,
  num? maxLeft,
  num? maxTop,
  bool allowEdit = true,
}) {
  if (!allowEdit ||
      globalCacheImage == null ||
      globalCacheImage['resizingSide'] != null) {
    return null;
  }
  final start = globalCacheImage['cursorMoveStartPosition'];
  final initial = globalCacheImage['imgInitialPosition'];
  if (start is! Map || initial is! Map) {
    return null;
  }
  final startX = _nullableDoubleArg(start['x']);
  final startY = _nullableDoubleArg(start['y']);
  final left = _nullableDoubleArg(initial['left']);
  final top = _nullableDoubleArg(initial['top']);
  if (startX == null || startY == null || left == null || top == null) {
    return null;
  }
  final nextLeft = _apiClampImagePosition(
    left + pageX - startX,
    minLeft,
    maxLeft,
  );
  final nextTop = _apiClampImagePosition(top + pageY - startY, minTop, maxTop);
  return {'left': nextLeft, 'top': nextTop};
}

num _apiClampImagePosition(num value, num? min, num? max) {
  final lower = min;
  final upper = max == null
      ? null
      : lower == null
      ? max
      : math.max<num>(lower, max);
  var result = lower == null ? value : math.max<num>(lower, value);
  if (upper != null) {
    result = math.min<num>(upper, result);
  }
  return result;
}

