Map<String, num>? onChartMove(
  Map<String, Object?>? globalCacheChart, {
  required num pageX,
  required num pageY,
  required num windowWidth,
  required num windowHeight,
  bool allowEdit = true,
}) {
  if (!allowEdit ||
      globalCacheChart == null ||
      globalCacheChart['resizingSide'] != null) {
    return null;
  }
  final start = globalCacheChart['cursorMoveStartPosition'];
  final initial = globalCacheChart['chartInitialPosition'];
  if (start is! Map || initial is! Map) {
    return null;
  }
  final offsetX = _nullableDoubleArg(start['x']);
  final offsetY = _nullableDoubleArg(start['y']);
  final width = _nullableDoubleArg(initial['width']);
  final height = _nullableDoubleArg(initial['height']);
  if (offsetX == null || offsetY == null || width == null || height == null) {
    return null;
  }
  final maxLeft = math.max<num>(0, windowWidth - width - 22 - 36);
  final maxTop = math.max<num>(0, windowHeight - height - 42 - 6);
  return {
    'left': _apiClampImagePosition(pageX - offsetX, 0, maxLeft),
    'top': _apiClampImagePosition(pageY - offsetY, 0, maxTop),
  };
}

