Map<String, num>? onChartResize(
  Map<String, Object?>? globalCacheChart, {
  required num pageX,
  required num pageY,
  required num windowWidth,
  required num windowHeight,
  bool allowEdit = true,
}) {
  if (!allowEdit || globalCacheChart == null || pageX < 0 || pageY < 0) {
    return null;
  }
  final side = _nullableStringArg(globalCacheChart['resizingSide']);
  final start = globalCacheChart['cursorMoveStartPosition'];
  final initial = globalCacheChart['chartInitialPosition'];
  if (side == null || start is! Map || initial is! Map) {
    return null;
  }
  final startX = _nullableDoubleArg(start['x']);
  final startY = _nullableDoubleArg(start['y']);
  final initialWidth = _nullableDoubleArg(initial['width']);
  final initialHeight = _nullableDoubleArg(initial['height']);
  final initialLeft = _nullableDoubleArg(initial['left']);
  final initialTop = _nullableDoubleArg(initial['top']);
  if (startX == null ||
      startY == null ||
      initialWidth == null ||
      initialHeight == null ||
      initialLeft == null ||
      initialTop == null) {
    return null;
  }
  num left = initialLeft;
  num top = initialTop;
  num width = initialWidth;
  num height = initialHeight;
  final leftChange = pageX - startX;
  final topChange = pageY - startY;
  const minSize = 60;

  if (const {'lm', 'lt', 'lb'}.contains(side)) {
    left = pageX;
    width = initialWidth - leftChange;
    final maxLeft = initialWidth + initialLeft - minSize;
    if (left > maxLeft) {
      left = maxLeft;
      width = initialWidth - (maxLeft - startX);
    } else if (left <= 0) {
      left = 0;
      width = initialWidth + startX;
    }
  }
  if (const {'rm', 'rt', 'rb'}.contains(side)) {
    width = initialWidth + leftChange;
    if (width < minSize) {
      width = minSize;
    } else if (width >= windowWidth - initialLeft - 22 - 36) {
      width = windowWidth - initialLeft - 22 - 36;
    }
  }
  if (const {'mt', 'lt', 'rt'}.contains(side)) {
    top = pageY;
    height = initialHeight - topChange;
    final maxTop = initialHeight + initialTop - minSize;
    if (top > maxTop) {
      top = maxTop;
      height = initialHeight - (maxTop - startY);
    } else if (top <= 0) {
      top = 0;
      height = initialHeight + startY;
    }
  }
  if (const {'mb', 'lb', 'rb'}.contains(side)) {
    height = initialHeight + topChange;
    if (height < minSize) {
      height = minSize;
    } else if (height >= windowHeight - initialTop - 42 - 6) {
      height = windowHeight - initialTop - 42 - 6;
    }
  }
  return {'left': left, 'top': top, 'width': width, 'height': height};
}

FortuneSheet onChartMoveEnd(
