    'width': width,
    'height': height,
  });
}

FortuneSheet _apiUpdateRawChartGeometry(
  FortuneSheet sheet,
  String chartId,
  Map<String, num> geometry,
) {
  var changed = false;
  final extraFields = _cloneStringObjectMap(sheet.extraFields);

  Object? updateRaw(Object? raw) {
    if (raw is List) {
      return [
        for (final item in raw)
          item is Map ? updateRaw(item) : cloneFortuneMetadata(item),
      ];
    }
    if (raw is Map) {
      if (_apiRawChartMatches(raw, chartId)) {
        changed = true;
        return _apiRawChartWithGeometry(raw, geometry);
      }
      final next = <String, Object?>{};
      for (final entry in raw.entries) {
        final key = '${entry.key}';
        final value = entry.value;
        if (value is Map &&
            (key == chartId || _apiRawChartMatches(value, chartId))) {
          changed = true;
          next[key] = _apiRawChartWithGeometry(value, geometry);
        } else if (value is List || value is Map) {
          next[key] = updateRaw(value);
        } else {
          next[key] = cloneFortuneMetadata(value);
        }
      }
      return next;
    }
    return cloneFortuneMetadata(raw);
  }

  for (final key in const ['chart', 'charts']) {
    if (extraFields.containsKey(key)) {
      extraFields[key] = updateRaw(extraFields[key]);
    }
  }
  return changed ? sheet.copyWith(extraFields: extraFields) : sheet.copyWith();
}

bool _apiRawChartMatches(Map raw, String chartId) {
  return raw['id']?.toString() == chartId ||
      raw['chart_id']?.toString() == chartId ||
      raw['chartId']?.toString() == chartId;
}

Map<String, Object?> _apiRawChartWithGeometry(
  Map raw,
  Map<String, num> geometry,
) {
  final next = <String, Object?>{
    for (final entry in raw.entries)
      '${entry.key}': cloneFortuneMetadata(entry.value),
  };
  for (final entry in geometry.entries) {
    next[entry.key] = entry.value;
  }
  return next;
}

