Map<String, Object?>? onImageResize(
  Map<String, Object?>? globalCacheImage, {
  required num pageX,
  required num pageY,
  num zoomRatio = 1,
  num? maxWidth,
  num? maxHeight,
  bool allowEdit = true,
}) {
  if (!allowEdit || globalCacheImage == null) {
    return null;
  }
  final side = _nullableStringArg(globalCacheImage['resizingSide']);
  final start = globalCacheImage['cursorMoveStartPosition'];
  final initial = globalCacheImage['imgInitialPosition'];
  if (side == null || start is! Map || initial is! Map) {
    return null;
  }
  final startX = _nullableDoubleArg(start['x']);
  final startY = _nullableDoubleArg(start['y']);
  final parsedLeft = _nullableDoubleArg(initial['left']);
  final parsedTop = _nullableDoubleArg(initial['top']);
  final parsedWidth = _nullableDoubleArg(initial['width']);
  final parsedHeight = _nullableDoubleArg(initial['height']);
  if (startX == null ||
      startY == null ||
      parsedLeft == null ||
      parsedTop == null ||
      parsedWidth == null ||
      parsedHeight == null) {
    return null;
  }
  num left = parsedLeft;
  num top = parsedTop;
  num width = parsedWidth;
  num height = parsedHeight;
  final dx = pageX - startX;
  final dy = pageY - startY;
  final minHeight = 60 * zoomRatio;
  final minWidth = 1.5 * 60 * zoomRatio;
  if (const {'lm', 'lt', 'lb'}.contains(side)) {
    if (width - dx < minWidth) {
      left += width - minWidth;
      width = minWidth;
    } else {
      left += dx;
      width -= dx;
    }
    left = math.max<num>(0, left);
  }
  if (const {'rm', 'rt', 'rb'}.contains(side)) {
    width = width + dx < minWidth ? minWidth : width + dx;
  }
  if (const {'mt', 'lt', 'rt'}.contains(side)) {
    if (height - dy < minHeight) {
      top += height - minHeight;
      height = minHeight;
    } else {
      top += dy;
      height -= dy;
    }
    top = math.max<num>(0, top);
  }
  if (const {'mb', 'lb', 'rb'}.contains(side)) {
    height = height + dy < minHeight ? minHeight : height + dy;
  }
  width = _apiClampImagePosition(width, minWidth, maxWidth);
  height = _apiClampImagePosition(height, minHeight, maxHeight);
  return {
    'left': left,
    'top': top,
    'width': width,
    'height': height,
    'backgroundSize': '${width}px ${height}px',
  };
}

FortuneSheet onImageResizeEnd(
  FortuneSheet sheet, {
  required String? activeImg,
  required Map<String, num>? position,
  num zoomRatio = 1,
  Map<String, Object?>? globalCacheImage,
}) {
  if (activeImg == null ||
      position == null ||
      globalCacheImage?['resizingSide'] == null) {
    return sheet.copyWith();
  }
  return _apiUpdateImage(sheet, activeImg, (image) {
    return image.copyWith(
      left: (position['left'] ?? image.left) / zoomRatio,
      top: (position['top'] ?? image.top) / zoomRatio,
      width: (position['width'] ?? image.width) / zoomRatio,
      height: (position['height'] ?? image.height) / zoomRatio,
    );
  });
}

Map<String, Object?>? onImageCropChange(
  Map<String, Object?>? globalCacheImage, {
  required num pageX,
  required num pageY,
  bool allowEdit = true,
}) {
  if (!allowEdit || globalCacheImage == null) {
    return null;
  }
  final side = _nullableStringArg(
    globalCacheImage['cropChangeSide'] ?? globalCacheImage['cropChange'],
  );
  final start = globalCacheImage['cursorMoveStartPosition'];
  final crop =
      globalCacheImage['cropInitialPosition'] ?? globalCacheImage['crop'];
  final defaults =
      globalCacheImage['imageDefaultPosition'] ?? globalCacheImage['default'];
  if (side == null || start is! Map || crop is! Map || defaults is! Map) {
    return null;
  }
  final startX = _nullableDoubleArg(start['x']);
  final startY = _nullableDoubleArg(start['y']);
  var width = _nullableDoubleArg(crop['width']);
  var height = _nullableDoubleArg(crop['height']);
  var offsetLeft = _nullableDoubleArg(crop['offsetLeft']);
  var offsetTop = _nullableDoubleArg(crop['offsetTop']);
  final defaultWidth = _nullableDoubleArg(defaults['width']);
  final defaultHeight = _nullableDoubleArg(defaults['height']);
  final defaultLeft = _nullableDoubleArg(defaults['left']) ?? 0;
  final defaultTop = _nullableDoubleArg(defaults['top']) ?? 0;
  if (startX == null ||
      startY == null ||
      width == null ||
      height == null ||
      offsetLeft == null ||
      offsetTop == null ||
      defaultWidth == null ||
      defaultHeight == null) {
    return null;
  }
  final dx = pageX - startX;
  final dy = pageY - startY;
  final originalRight = width + offsetLeft;
  final originalBottom = height + offsetTop;
  if (const {'lt', 'lm', 'lb'}.contains(side)) {
    offsetLeft = (offsetLeft + dx).clamp(0, originalRight - 1);
    width = originalRight - offsetLeft;
  }
  if (const {'rt', 'rm', 'rb'}.contains(side)) {
    width = (width + dx).clamp(1, defaultWidth - offsetLeft);
  }
  if (const {'lt', 'mt', 'rt'}.contains(side)) {
    offsetTop = (offsetTop + dy).clamp(0, originalBottom - 1);
    height = originalBottom - offsetTop;
  }
  if (const {'lb', 'mb', 'rb'}.contains(side)) {
    height = (height + dy).clamp(1, defaultHeight - offsetTop);
  }
  final fixed = globalCacheImage['fixedPosition'];
  final fixedLeft = fixed is Map ? _nullableDoubleArg(fixed['left']) : null;
  final fixedTop = fixed is Map ? _nullableDoubleArg(fixed['top']) : null;
  final left = (fixedLeft ?? defaultLeft) + offsetLeft;
  final top = (fixedTop ?? defaultTop) + offsetTop;
  return {
    'width': width,
    'height': height,
    'offsetLeft': offsetLeft,
    'offsetTop': offsetTop,
    'left': left,
    'top': top,
    'maskStyle': {
      'width': defaultWidth,
      'height': defaultHeight,
      'left': -offsetLeft,
      'top': -offsetTop,
    },
    'contentStyle': {
      'backgroundSize': '${defaultWidth}px ${defaultHeight}px',
      'backgroundPosition': '${-offsetLeft}px ${-offsetTop}px',
    },
  };
}

FortuneSheet onImageCropChangeEnd(
  FortuneSheet sheet, {
  required String? activeImg,
  required Map<String, num>? position,
  Map<String, Object?>? globalCacheImage,
}) {
  if (activeImg == null ||
      position == null ||
      (globalCacheImage?['cropChangeSide'] ??
              globalCacheImage?['cropChange']) ==
          null) {
    return sheet.copyWith();
  }
  return _apiUpdateImage(sheet, activeImg, (image) {
    final extraFields = _cloneStringObjectMap(image.extraFields);
    extraFields['crop'] = {
      'width': position['width'],
      'height': position['height'],
      'offsetLeft': position['offsetLeft'],
      'offsetTop': position['offsetTop'],
    };
    return image.copyWith(extraFields: extraFields);
  });
}

FortuneSheet _apiUpdateImage(
  FortuneSheet sheet,
  String imageId,
  FortuneImage Function(FortuneImage image) update,
) {
  var changed = false;
  final images = <FortuneImage>[];
  for (final image in sheet.images) {
    if (image.id == imageId) {
      images.add(update(image));
      changed = true;
    } else {
      images.add(image.copyWith());
    }
  }
  return changed ? saveImage(sheet, images) : sheet.copyWith();
}

