Map<String, Object?> onCommentBoxResizeEnd(
  FortuneSheet sheet, {
  required Map<String, Object?>? commentBox,
  required Map<String, num>? position,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num zoomRatio = 1,
}) {
  final rc = commentBox?['commentRC'];
  final row = rc is Map ? _nullableIntArg(rc['r']) : null;
  final column = rc is Map ? _nullableIntArg(rc['c']) : null;
  if (commentBox?['resizingId'] == null ||
      position == null ||
      row == null ||
      column == null) {
    return {'sheet': sheet.copyWith(), 'editingCommentBox': null};
  }
  final nextSheet = _apiUpdateComment(sheet, row, column, (comment) {
    return comment.copyWith(
      left: (position['left'] ?? comment.left ?? 0) / zoomRatio,
      top: (position['top'] ?? comment.top ?? 0) / zoomRatio,
      width: (position['width'] ?? comment.width ?? 0) / zoomRatio,
      height: (position['height'] ?? comment.height ?? 0) / zoomRatio,
    );
  });
  return {
    'sheet': nextSheet,
    'editingCommentBox': setEditingComment(
      nextSheet,
      row,
      column,
      visibleDataRows: visibleDataRows,
      visibleDataColumns: visibleDataColumns,
      zoomRatio: zoomRatio,
    ),
  };
}

FortuneSheet _apiUpdateComment(
  FortuneSheet sheet,
  int row,
  int column,
  FortuneCellComment Function(FortuneCellComment comment) update,
) {
  final coord = FortuneCellCoord(row, column);
  final current = sheet.cells[coord];
  final comment = current?.comment;
  if (current == null || comment == null) {
    return sheet.copyWith();
  }
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  cells[coord] = current.copyWith(comment: update(comment));
  return sheet.copyWith(cells: cells);
}

