Map<String, Object?> _apiModalMoveStart({
  required num pageX,
  required num pageY,
  required Map<String, num> position,
  num leftOffset = 0,
  num topOffset = 0,
}) {
  return {
    'cursorMoveStartPosition': {'x': pageX, 'y': pageY},
    'initialPosition': {
      'left': (position['left'] ?? 0) - leftOffset,
      'top': (position['top'] ?? 0) - topOffset,
      'width': position['width'] ?? 0,
      'height': position['height'] ?? 0,
    },
  };
}

Map<String, Object?>? _apiModalMove(
  Map<String, Object?>? moveProps, {
  required num pageX,
  required num pageY,
}) {
  if (moveProps == null) {
    return null;
  }
  final start = moveProps['cursorMoveStartPosition'];
  final initial = moveProps['initialPosition'];
  if (start is! Map || initial is! Map) {
    return null;
  }
  final startX = _nullableDoubleArg(start['x']);
  final startY = _nullableDoubleArg(start['y']);
  final left = _nullableDoubleArg(initial['left']);
  final top = _nullableDoubleArg(initial['top']);
  if (startX == null || startY == null || left == null || top == null) {
    return null;
  }
  return {
    'left': left + pageX - startX,
    'top': math.max<num>(0, top + pageY - startY),
  };
}

Map<String, Object?>? frozenTofreezen(
  FortuneFrozenPane? frozen, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
}) {
  if (frozen == null) {
    return null;
  }
  final result = <String, Object?>{};
  final type = switch (frozen.type) {
    'row' => 'rangeRow',
    'column' => 'rangeColumn',
    'both' => 'rangeBoth',
    _ => frozen.type,
  };
  if ((type == 'rangeRow' || type == 'rangeBoth') &&
      visibleDataRows.isNotEmpty) {
    const scrollTop = 0;
    var rowStart = _apiSortedIndex(visibleDataRows, scrollTop);
    final rowFocus = (frozen.rowFocus ?? 0).clamp(
      0,
      visibleDataRows.length - 1,
    );
    if (rowFocus > rowStart) {
      rowStart = rowFocus;
    }
    final top = visibleDataRows[rowStart] - 2 - scrollTop + columnHeaderHeight;
    result['horizontal'] = <String, Object?>{
      'freezenhorizontaldata': <Object?>[
        visibleDataRows[rowStart],
        rowStart + 1,
        scrollTop,
        _apiCutVolumn(visibleDataRows, rowStart + 1),
        top,
      ],
      'top': top,
    };
  }
  if ((type == 'rangeColumn' || type == 'rangeBoth') &&
      visibleDataColumns.isNotEmpty) {
    const scrollLeft = 0;
    var columnStart = _apiSortedIndex(visibleDataColumns, scrollLeft);
    final columnFocus = (frozen.columnFocus ?? 0).clamp(
      0,
      visibleDataColumns.length - 1,
    );
    if (columnFocus > columnStart) {
      columnStart = columnFocus;
    }
    final left =
        visibleDataColumns[columnStart] - 2 - scrollLeft + rowHeaderWidth;
    result['vertical'] = <String, Object?>{
      'freezenverticaldata': <Object?>[
        visibleDataColumns[columnStart],
        columnStart + 1,
        scrollLeft,
        _apiCutVolumn(visibleDataColumns, columnStart + 1),
        left,
      ],
      'left': left,
    };
  }
  return result;
}

Map<String, Object?>? initFreeze(
  FortuneSheet sheet, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
}) {
  return frozenTofreezen(
    sheet.frozen,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
    rowHeaderWidth: rowHeaderWidth,
    columnHeaderHeight: columnHeaderHeight,
  );
}

Map<String, Object?> fixPositionOnFrozenCells(
  Object? freeze, {
  required num x,
  required num y,
  required num mouseX,
  required num mouseY,
}) {
  var nextX = x;
  var nextY = y;
  var inHorizontalFreeze = false;
  var inVerticalFreeze = false;
  final vertical = _apiFreezeAxisData(
    freeze,
    'vertical',
    'freezenverticaldata',
  );
  if (vertical != null && mouseX < vertical.$1 - vertical.$3) {
    nextX = mouseX + vertical.$3;
    inVerticalFreeze = true;
  }
  final horizontal = _apiFreezeAxisData(
    freeze,
    'horizontal',
    'freezenhorizontaldata',
  );
  if (horizontal != null && mouseY < horizontal.$1 - horizontal.$3) {
    nextY = mouseY + horizontal.$3;
    inHorizontalFreeze = true;
  }
  return {
    'x': nextX,
    'y': nextY,
    'inHorizontalFreeze': inHorizontalFreeze,
    'inVerticalFreeze': inVerticalFreeze,
  };
}

List<num> _apiCutVolumn(List<num> values, int cutIndex) {
  if (cutIndex <= 0) {
    return List<num>.from(values);
  }
  if (cutIndex >= values.length) {
    return const [];
  }
  return values.sublist(cutIndex);
}

Map<String, Object?> fixRowStyleOverflowInFreeze(
  int rowStart,
  int rowEnd,
  Object? freeze, {
  required List<num> visibleDataRows,
  num scrollTop = 0,
}) {
  final data = _apiFreezeAxisData(
    freeze,
    'horizontal',
    'freezenhorizontaldata',
  );
  if (data == null) {
    return const <String, Object?>{};
  }
  final freezeTop = data.$1;
  final freezeRowIndex = data.$2;
  final offTop = scrollTop - data.$3;
  final rowBottom = _apiAxisValue(visibleDataRows, rowEnd);
  final rowTop = rowStart <= 0
      ? 0
      : _apiAxisValue(visibleDataRows, rowStart - 1);
  final height = rowBottom - rowTop - 1;
  return _apiFreezeOverflowStyle(
    start: rowStart,
    end: rowEnd,
    freezeEdge: freezeTop,
    freezeIndex: freezeRowIndex,
    offset: offTop,
    startEdge: rowTop,
    size: height,
    positionKey: 'top',
    sizeKey: 'height',
  );
}

Map<String, Object?> fixColumnStyleOverflowInFreeze(
  int columnStart,
  int columnEnd,
  Object? freeze, {
  required List<num> visibleDataColumns,
  num scrollLeft = 0,
}) {
  final data = _apiFreezeAxisData(freeze, 'vertical', 'freezenverticaldata');
  if (data == null) {
    return const <String, Object?>{};
  }
  final freezeLeft = data.$1;
  final freezeColumnIndex = data.$2;
  final offLeft = scrollLeft - data.$3;
  final columnRight = _apiAxisValue(visibleDataColumns, columnEnd);
  final columnLeft = columnStart <= 0
      ? 0
      : _apiAxisValue(visibleDataColumns, columnStart - 1);
  final width = columnRight - columnLeft - 1;
  return _apiFreezeOverflowStyle(
    start: columnStart,
    end: columnEnd,
    freezeEdge: freezeLeft,
    freezeIndex: freezeColumnIndex,
    offset: offLeft,
    startEdge: columnLeft,
    size: width,
    positionKey: 'left',
    sizeKey: 'width',
  );
}

(num, int, num)? _apiFreezeAxisData(
  Object? freeze,
  String axisKey,
  String dataKey,
) {
  if (freeze is! Map) {
    return null;
  }
  final axis = freeze[axisKey];
  if (axis is! Map) {
    return null;
  }
  final data = axis[dataKey];
  if (data is! List || data.length < 3) {
    return null;
  }
  final edge = _nullableDoubleArg(data[0]);
  final index = _nullableIntArg(data[1]);
  final scroll = _nullableDoubleArg(data[2]);
  if (edge == null || index == null || scroll == null) {
    return null;
  }
  return (edge, index, scroll);
}

(int, List<num>, num)? _apiFreezeAxisScrollData(
  Object? freeze,
  String axisKey,
  String dataKey,
) {
  if (freeze is! Map) {
    return null;
  }
  final axis = freeze[axisKey];
  if (axis is! Map) {
    return null;
  }
  final data = axis[dataKey];
  if (data is! List || data.length < 5) {
    return null;
  }
  final index = _nullableIntArg(data[1]);
  final tail = _apiNumList(data[3]);
  final handleOffset = _nullableDoubleArg(data[4]);
  if (index == null || tail == null || handleOffset == null) {
    return null;
  }
  return (index, tail, handleOffset);
}

List<num>? _apiNumList(Object? value) {
  if (value is! Iterable) {
    return null;
  }
  final result = <num>[];
  for (final item in value) {
    final number = _nullableDoubleArg(item);
    if (number == null) {
      return null;
    }
    result.add(number);
  }
  return result;
}

Map<String, Object?> _apiFreezeOverflowStyle({
  required int start,
  required int end,
  required num freezeEdge,
  required int freezeIndex,
  required num offset,
  required num startEdge,
  required num size,
  required String positionKey,
  required String sizeKey,
}) {
  final result = <String, Object?>{};
  final clipEdge = freezeEdge + offset;
  if (start >= freezeIndex) {
    if (startEdge + size < clipEdge) {
      result['display'] = 'none';
    } else if (startEdge < clipEdge) {
      result[positionKey] = clipEdge;
      result[sizeKey] = size - (clipEdge - startEdge);
    }
  } else if (end >= freezeIndex) {
    if (startEdge + size < clipEdge) {
      result[positionKey] = startEdge + offset;
      result[sizeKey] = freezeEdge - startEdge;
    } else {
      result[positionKey] = startEdge + offset;
      result[sizeKey] = size - offset;
    }
  } else {
    result[positionKey] = startEdge + offset;
  }
  return result;
}

List<FortuneRange> normalizeSelection(
  FortuneSheet sheet,
  List<FortuneRange>? selection, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
}) {
  if (selection == null) {
    return const [];
  }
  return [
    for (final range in selection)
      _apiNormalizeSelectionRange(
        sheet,
        range,
        visibleDataRows: visibleDataRows,
        visibleDataColumns: visibleDataColumns,
      ),
  ];
}

FortuneRange _apiNormalizeSelectionRange(
  FortuneSheet sheet,
  FortuneRange range, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
}) {
  final rowFocus = range.rowFocus ?? range.rowStart;
  final columnFocus = range.columnFocus ?? range.columnStart;
  final moveGeometry = _apiSelectionGeometry(
    range.rowStart,
    range.rowEnd,
    range.columnStart,
    range.columnEnd,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
  );
  final mergeRange = _apiMergeRangeContaining(sheet, rowFocus, columnFocus);
  final focusGeometry = mergeRange == null
      ? _apiSelectionGeometry(
          rowFocus,
          rowFocus,
          columnFocus,
          columnFocus,
          visibleDataRows: visibleDataRows,
          visibleDataColumns: visibleDataColumns,
        )
      : _apiSelectionGeometry(
          mergeRange.rowStart,
          mergeRange.rowEnd,
          mergeRange.columnStart,
          mergeRange.columnEnd,
          visibleDataRows: visibleDataRows,
          visibleDataColumns: visibleDataColumns,
        );
  return range.copyWith(
    rowFocus: rowFocus,
    columnFocus: columnFocus,
    extraFields: {
      ...range.extraFields,
      if (focusGeometry != null) ...{
        'left': focusGeometry['left'],
        'width': focusGeometry['width'],
        'top': focusGeometry['top'],
        'height': focusGeometry['height'],
      },
      if (moveGeometry != null) ...{
        'left_move': moveGeometry['left'],
        'width_move': moveGeometry['width'],
        'top_move': moveGeometry['top'],
        'height_move': moveGeometry['height'],
      },
    },
  );
}

Map<String, num>? _apiSelectionGeometry(
  int rowStart,
  int rowEnd,
  int columnStart,
  int columnEnd, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
}) {
  if (rowStart < 0 ||
      rowEnd < rowStart ||
      columnStart < 0 ||
      columnEnd < columnStart ||
      rowEnd >= visibleDataRows.length ||
      columnEnd >= visibleDataColumns.length) {
    return null;
  }
  final row = visibleDataRows[rowEnd];
  final rowPrevious = rowStart == 0 ? 0 : visibleDataRows[rowStart - 1];
  final column = visibleDataColumns[columnEnd];
  final columnPrevious = columnStart == 0
      ? 0
      : visibleDataColumns[columnStart - 1];
  return {
    'left': columnPrevious,
    'width': column - columnPrevious <= 0 ? 0 : column - columnPrevious - 1,
    'top': rowPrevious,
    'height': row - rowPrevious <= 0 ? 0 : row - rowPrevious - 1,
  };
}

List<Map<String, Object?>> selectionCopyShow(
  Iterable<FortuneRange>? ranges, {
  Iterable<FortuneRange>? selectionRange,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  final sourceRanges = (ranges ?? selectionRange)?.toList() ?? const [];
  final overlays = <Map<String, Object?>>[];
  for (final range in sourceRanges) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    final geometry = _apiSelectionGeometry(
      normalized.rowStart,
      normalized.rowEnd,
      normalized.columnStart,
      normalized.columnEnd,
      visibleDataRows: visibleDataRows,
      visibleDataColumns: visibleDataColumns,
    );
    if (geometry == null) {
      continue;
    }
    overlays.add({
      'row': [normalized.rowStart, normalized.rowEnd],
      'column': [normalized.columnStart, normalized.columnEnd],
      'style': {
        'display': 'block',
        'left': geometry['left'],
        'width': geometry['width'],
        'top': geometry['top'],
        'height': geometry['height'],
      },
      'parts': const [
        'fortune-selection-copy-top fortune-copy',
        'fortune-selection-copy-right fortune-copy',
        'fortune-selection-copy-bottom fortune-copy',
        'fortune-selection-copy-left fortune-copy',
        'fortune-selection-copy-hc',
      ],
    });
  }
  return overlays;
}

FortuneRange? _apiMergeRangeContaining(
  FortuneSheet sheet,
  int row,
  int column,
) {
  for (final range in _apiMergedRanges(sheet)) {
    if (row >= range.rowStart &&
        row <= range.rowEnd &&
        column >= range.columnStart &&
        column <= range.columnEnd) {
      return range;
    }
  }
  return null;
}

Map<String, Object?>? mergeBorder(
  FortuneSheet sheet,
  int row,
  int column, {
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  final range = _apiMergeRangeContaining(sheet, row, column);
  if (range == null) {
    return null;
  }
  final rowPrevious = range.rowStart == 0
      ? -1
      : rowLocationByIndex(range.rowStart, visibleDataRows)[0] - 1;
  final rowEnd = rowLocationByIndex(range.rowEnd, visibleDataRows)[1];
  final columnPrevious = colLocationByIndex(
    range.columnStart,
    visibleDataColumns,
  )[0];
  final columnEnd = colLocationByIndex(range.columnEnd, visibleDataColumns)[1];
  return {
    'row': [rowPrevious, rowEnd, range.rowStart, range.rowEnd],
    'column': [columnPrevious, columnEnd, range.columnStart, range.columnEnd],
  };
}

Map<String, Object?>? mergeMoveMain(
  FortuneSheet sheet,
  List<int> columnSelected,
  List<int> rowSelected,
  FortuneRange? selection,
  num top,
  num height,
  num left,
  num width, {
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  final mergedRanges = _apiMergedRanges(sheet).toList();
  if (mergedRanges.isEmpty) {
    return null;
  }
  var nextColumns = List<int>.from(columnSelected);
  var nextRows = List<int>.from(rowSelected);
  var nextTop = top;
  var nextHeight = height;
  var nextLeft = left;
  var nextWidth = width;
  nextRows[1] = math.max(nextRows[0], nextRows[1]);
  nextColumns[1] = math.max(nextColumns[0], nextColumns[1]);
  var keepLooping = true;
  final expandedMergeKeys = <String>{};
  while (keepLooping) {
    keepLooping = false;
    for (final mergeRange in mergedRanges) {
      final key = '${mergeRange.rowStart}_${mergeRange.columnStart}';
      if (expandedMergeKeys.contains(key)) {
        continue;
      }
      final changed = _apiMergeMove(
        sheet,
        mergeRange,
        nextColumns,
        nextRows,
        selection,
        nextTop,
        nextHeight,
        nextLeft,
        nextWidth,
        visibleDataRows: visibleDataRows,
        visibleDataColumns: visibleDataColumns,
      );
      if (changed != null) {
        expandedMergeKeys.add(key);
        nextColumns = (changed['columnSelected']! as List).cast<int>();
        nextRows = (changed['rowSelected']! as List).cast<int>();
        nextTop = changed['top']! as num;
        nextHeight = changed['height']! as num;
        nextLeft = changed['left']! as num;
        nextWidth = changed['width']! as num;
        keepLooping = true;
      }
    }
  }
  return {
    'columnSelected': nextColumns,
    'rowSelected': nextRows,
    'top': nextTop,
    'height': nextHeight,
    'left': nextLeft,
    'width': nextWidth,
  };
}

Map<String, Object?>? _apiMergeMove(
  FortuneSheet sheet,
  FortuneRange mergeRange,
  List<int> columnSelected,
  List<int> rowSelected,
  FortuneRange? selection,
  num top,
  num height,
  num left,
  num width, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
}) {
  final rowStart = mergeRange.rowStart;
  final rowEnd = mergeRange.rowEnd;
  final columnStart = mergeRange.columnStart;
  final columnEnd = mergeRange.columnEnd;
  final nextColumns = List<int>.from(columnSelected);
  final nextRows = List<int>.from(rowSelected);
  nextColumns[0] = math.min(nextColumns[0], nextColumns[1]);
  nextRows[0] = math.min(nextRows[0], nextRows[1]);
  final containsOrIntersects =
      (nextColumns[0] <= columnStart &&
          nextColumns[1] >= columnEnd &&
          nextRows[0] <= rowStart &&
          nextRows[1] >= rowEnd) ||
      (!(nextColumns[1] < columnStart || nextColumns[0] > columnEnd) &&
          !(nextRows[1] < rowStart || nextRows[0] > rowEnd));
  if (!containsOrIntersects) {
    return null;
  }
  final mergeGeometry = mergeBorder(
    sheet,
    rowStart,
    columnStart,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
  );
  if (mergeGeometry == null) {
    return null;
  }
  final rowGeometry = (mergeGeometry['row']! as List).cast<Object?>();
  final columnGeometry = (mergeGeometry['column']! as List).cast<Object?>();
  final mergeTop = rowGeometry[0]! as num;
  final mergeBottom = rowGeometry[1]! as num;
  final mergeLeft = columnGeometry[0]! as num;
  final mergeRight = columnGeometry[1]! as num;
  var nextTop = top;
  var nextHeight = height;
  var nextLeft = left;
  var nextWidth = width;
  if (!(nextColumns[1] < columnStart || nextColumns[0] > columnEnd)) {
    if (nextRows[0] <= rowEnd && nextRows[0] >= rowStart) {
      nextHeight += nextTop - mergeTop;
      nextTop = mergeTop;
      nextRows[0] = rowStart;
    }
    if (nextRows[1] >= rowStart && nextRows[1] <= rowEnd) {
      nextHeight = mergeBottom - nextTop;
      nextRows[1] = rowEnd;
    }
  }
  if (!(nextRows[1] < rowStart || nextRows[0] > rowEnd)) {
    if (nextColumns[0] <= columnEnd && nextColumns[0] >= columnStart) {
      nextWidth += nextLeft - mergeLeft;
      nextLeft = mergeLeft;
      nextColumns[0] = columnStart;
    }
    if (nextColumns[1] >= columnStart && nextColumns[1] <= columnEnd) {
      nextWidth = mergeRight - nextLeft;
      nextColumns[1] = columnEnd;
    }
  }
  return {
    'columnSelected': nextColumns,
    'rowSelected': nextRows,
    'top': nextTop,
    'height': nextHeight,
    'left': nextLeft,
    'width': nextWidth,
  };
}

int _apiSortedIndex(List<num> values, num value) {
  var low = 0;
  var high = values.length;
  while (low < high) {
    final middle = (low + high) >> 1;
    if (values[middle] < value) {
      low = middle + 1;
    } else {
      high = middle;
    }
  }
  return low;
}

String rgbToHex(String color) {
  final raw = color.contains('rgba')
      ? color.replaceFirst('rgba(', '').replaceFirst(')', '')
      : color.replaceFirst('rgb(', '').replaceFirst(')', '');
  final values = raw.split(',');
  final red = num.parse(values[0]).toInt();
  final green = num.parse(values[1]).toInt();
  final blue = num.parse(values[2]).toInt();
  final hex = ((1 << 24) + (red << 16) + (green << 8) + blue)
      .toRadixString(16)
      .substring(1);
  return '#$hex';
}

Object? escapeScriptTag(Object? value) {
  if (value is! String) {
    return value;
  }
  return value
      .replaceAll('<script>', '&lt;script&gt;')
      .replaceFirst('</script>', '&lt;/script&gt;');
}

Object? escapeHTMLTag(Object? value) {
  if (value is! String) {
    return value;
  }
  if (value.startsWith('<span') || value.startsWith('=')) {
    return value;
  }
  return value.replaceAll('<', '&lt;').replaceAll('>', '&gt;');
}

String replaceHtml(String template, Map<String, Object?> values) {
  return template.replaceAllMapped(RegExp(r'\$\{([\w]+)\}'), (match) {
    final key = match.group(1)!;
    if (values.containsKey(key)) {
      return '${values[key]}';
    }
    return match.group(0)!;
  });
}

String getRegExpStr(String value) {
  return value
      .replaceFirst('~*', r'\*')
      .replaceFirst('~?', r'\?')
      .replaceFirst('.', r'\.')
      .replaceFirst('*', '.*')
      .replaceFirst('?', '.');
}

String chatatABC(int index) => indexToColumnChar(index);

String generateRandomSheetName(
  Iterable<FortuneSheet> sheets, {
  bool isPivotTable = false,
  String pivotTableTitle = 'PivotTable',
}) {
  final file = sheets.toList();
  var index = file.length;
  for (final sheet in file) {
    final name = sheet.name;
    if (name.contains('Sheet') || name.contains(pivotTableTitle)) {
      final suffix = _apiParseFloat(
        name.replaceFirst('Sheet', '').replaceFirst(pivotTableTitle, ''),
      );
      if (suffix != null && suffix.ceil() > index) {
        index = suffix.ceil();
      }
    }
  }
  return isPivotTable ? '$pivotTableTitle${index + 1}' : 'Sheet${index + 1}';
}

int? getSheetIndex(FortuneWorkbook workbook, String id) {
  for (var index = 0; index < workbook.sheets.length; index += 1) {
    if (workbook.sheets[index].id == id) {
      return index;
    }
  }
  return null;
}

String? getSheetIdByName(FortuneWorkbook workbook, String name) {
  for (final sheet in workbook.sheets) {
    if (sheet.name == name) {
      return sheet.id;
    }
  }
  return null;
}

const String fortuneSheetGridClientWidthMmKey = 'gridClientWidthMm';
const String fortuneSheetGridClientHeightMmKey = 'gridClientHeightMm';
const String fortuneSheetRulerVisibleKey = 'rulerVisible';
const String fortuneSheetRulerGuidesKey = 'rulerGuides';
const double fortuneSheetLogicalPixelsPerInch = 96;

double fortuneMillimetersToLogicalPixels(num millimeters) {
  return millimeters * fortuneSheetLogicalPixelsPerInch / 25.4;
}

double fortuneLogicalPixelsToMillimeters(num logicalPixels) {
  return logicalPixels * 25.4 / fortuneSheetLogicalPixelsPerInch;
}

double fortuneMillimetersToPixels(num millimeters, num dpi) {
  if (dpi <= 0) {
    throw INVALID_PARAMS;
  }
  return millimeters * dpi / 25.4;
}

class FortuneSheetGridClientPhysicalSize {
  const FortuneSheetGridClientPhysicalSize({
    required this.widthMm,
    required this.heightMm,
  });

  final int widthMm;
  final int heightMm;

  Size get logicalSize => Size(
    fortuneMillimetersToLogicalPixels(widthMm),
    fortuneMillimetersToLogicalPixels(heightMm),
  );

  Size pixelsAtDpi(num dpi) => Size(
    fortuneMillimetersToPixels(widthMm, dpi),
    fortuneMillimetersToPixels(heightMm, dpi),
  );

  @override
  bool operator ==(Object other) {
    return other is FortuneSheetGridClientPhysicalSize &&
        other.widthMm == widthMm &&
        other.heightMm == heightMm;
  }

  @override
  int get hashCode => Object.hash(widthMm, heightMm);
}

int? fortuneSheetGridClientWidthMm(FortuneSheet sheet) {
  return _nullableIntArg(sheet.extraFields[fortuneSheetGridClientWidthMmKey]);
}

int? fortuneSheetGridClientHeightMm(FortuneSheet sheet) {
  return _nullableIntArg(sheet.extraFields[fortuneSheetGridClientHeightMmKey]);
}

Size? fortuneSheetGridClientLogicalSize(FortuneSheet sheet) {
  return fortuneSheetGridClientPhysicalSize(sheet)?.logicalSize;
}

FortuneSheetGridClientPhysicalSize? fortuneSheetGridClientPhysicalSize(
  FortuneSheet sheet,
) {
  final widthMm = fortuneSheetGridClientWidthMm(sheet);
  final heightMm = fortuneSheetGridClientHeightMm(sheet);
  if (widthMm == null || heightMm == null) {
    return null;
  }
  return FortuneSheetGridClientPhysicalSize(
    widthMm: widthMm,
    heightMm: heightMm,
  );
}

FortuneSheet? getSheetByIndex(FortuneWorkbook workbook, {String? id}) {
  if (id == null) {
    return workbook.activeSheet.copyWith();
  }
  final index = getSheetIndex(workbook, id);
  return index == null ? null : workbook.sheets[index].copyWith();
}

String getNowDateTime(int format) {
  final now = DateTime.now();
  final year = now.year.toString();
  final month = _apiTwoDigit(now.month);
  final day = _apiTwoDigit(now.day);
  if (format == 1) {
    return '$year-$month-$day';
  }
  if (format == 2) {
    final hour = _apiTwoDigit(now.hour);
    final minute = _apiTwoDigit(now.minute);
    final second = _apiTwoDigit(now.second);
    return '$year-$month-$day $hour:$minute:$second';
  }
  return '';
}

List<Object?> getQKBorder(String width, String type, String color) {
  var borderType = '';
  final parsedWidth = _apiParseFloat(width) ?? 0;
  if (width.contains('pt')) {
    if (parsedWidth >= 1.5) {
      borderType = 'Thick';
    } else if (parsedWidth >= 1) {
      borderType = 'Medium';
    }
  } else {
    if (parsedWidth >= 3) {
      borderType = 'Thick';
    } else if (parsedWidth >= 2) {
      borderType = 'Medium';
    }
  }

  var style = 0;
  switch (type.toLowerCase()) {
    case 'double':
      style = 2;
    case 'dotted':
      style = borderType == 'Medium' || borderType == 'Thick' ? 3 : 10;
    case 'dashed':
      style = borderType == 'Medium' || borderType == 'Thick' ? 4 : 9;
    case 'solid':
      style = switch (borderType) {
        'Medium' => 8,
        'Thick' => 13,
        _ => 1,
      };
  }
  return [style, color];
}

Object? checkCF(int row, int column, Object? computeMap) {
  if (computeMap is! Map) {
    return null;
  }
  return computeMap['${row}_$column'];
}

Map<String, Map<String, Object?>> compute(FortuneSheet sheet) {
  return getComputeMap(sheet) ?? <String, Map<String, Object?>>{};
}

Map<String, Map<String, Object?>>? getComputeMap(FortuneSheet sheet) {
  final ruleArr = _apiConditionFormatList(sheet.conditionFormats);
  if (ruleArr.isEmpty) {
    return <String, Map<String, Object?>>{};
  }
  final computeMap = <String, Map<String, Object?>>{};
  for (final item in ruleArr.whereType<Map>()) {
    final cellRanges = _apiConditionRuleRanges(item['cellrange']);
    if (cellRanges.isEmpty) {
      continue;
    }
    final format = item['format'];
    final type = '${item['type'] ?? ''}';
    if (type == 'dataBar') {
      _apiApplyDataBarCondition(sheet, computeMap, cellRanges, format);
      continue;
    }
    if (type == 'colorGradation') {
      _apiApplyColorGradation(sheet, computeMap, cellRanges, format);
      continue;
    }
    final textColor = format is Map ? format['textColor'] : null;
    final cellColor = format is Map ? format['cellColor'] : null;
    final conditionName = '${item['conditionName'] ?? ''}';
    final conditionValue = item['conditionValue'];
    if (conditionValue is! List || conditionValue.isEmpty) {
      continue;
    }
    if (conditionName == 'duplicateValue') {
      _apiApplyDuplicateValueCondition(
        sheet,
        computeMap,
        cellRanges,
        conditionValue,
        textColor,
        cellColor,
      );
      continue;
    }
    if (conditionName == 'aboveAverage' || conditionName == 'belowAverage') {
      _apiApplyAverageCondition(
        sheet,
        computeMap,
        cellRanges,
        conditionName,
        textColor,
        cellColor,
      );
      continue;
    }
    if (conditionName == 'top10' ||
        conditionName == 'top10_percent' ||
        conditionName == 'last10' ||
        conditionName == 'last10_percent') {
      _apiApplyTopLastCondition(
        sheet,
        computeMap,
        cellRanges,
        conditionName,
        conditionValue,
        textColor,
        cellColor,
      );
      continue;
    }
    if (conditionName == 'occurrenceDate') {
      _apiApplyOccurrenceDateCondition(
        sheet,
        computeMap,
        cellRanges,
        conditionValue,
        textColor,
        cellColor,
      );
      continue;
    }
    for (final range in cellRanges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final value = sheet.getCellValue(row, column);
          if (isRealNull(value)) {
            continue;
          }
          if (!_apiConditionRuleMatches(conditionName, value, conditionValue)) {
            continue;
          }
          computeMap['${row}_$column'] = <String, Object?>{
            'textColor': textColor,
            'cellColor': cellColor,
          };
        }
      }
    }
  }
  return computeMap;
}

void _apiApplyDataBarCondition(
  FortuneSheet sheet,
  Map<String, Map<String, Object?>> computeMap,
  List<FortuneRange> cellRanges,
  Object? format,
) {
  final values = <MapEntry<FortuneCellCoord, int>>[];
  for (final range in cellRanges) {
    values.addAll(
      _apiConditionNumericValues(
        sheet,
        range,
      ).map((entry) => MapEntry(entry.key, entry.value.toInt())),
    );
  }
  if (values.isEmpty) {
    return;
  }
  final min = values.map((entry) => entry.value).reduce(math.min);
  final max = values.map((entry) => entry.value).reduce(math.max);
  if (min < 0) {
    final plusLen = ((max / (max - min)) * 10).round() / 10;
    final minusLen = ((min.abs() / (max - min)) * 10).round() / 10;
    for (final entry in values) {
      if (entry.value < 0) {
        _apiSetDataBar(computeMap, entry.key, {
          'valueType': 'minus',
          'minusLen': minusLen,
          'valueLen': ((entry.value.abs() / min.abs()) * 100).round() / 100,
          'format': format,
        });
      } else if (entry.value > 0) {
        _apiSetDataBar(computeMap, entry.key, {
          'valueType': 'plus',
          'plusLen': plusLen,
          'minusLen': minusLen,
          'valueLen': ((entry.value / max) * 100).round() / 100,
          'format': format,
        });
      }
    }
    return;
  }
  for (final entry in values) {
    _apiSetDataBar(computeMap, entry.key, {
      'valueType': 'plus',
      'plusLen': 1,
      'valueLen': max == 0 ? 1 : ((entry.value / max) * 100).round() / 100,
      'format': format,
    });
  }
}

void _apiSetDataBar(
  Map<String, Map<String, Object?>> computeMap,
  FortuneCellCoord coord,
  Map<String, Object?> dataBar,
) {
  final cellStyle = computeMap.putIfAbsent(
    '${coord.row}_${coord.column}',
    () => <String, Object?>{},
  );
  cellStyle['dataBar'] = dataBar;
}

void _apiApplyOccurrenceDateCondition(
  FortuneSheet sheet,
  Map<String, Map<String, Object?>> computeMap,
  List<FortuneRange> cellRanges,
  List<Object?> conditionValue,
  Object? textColor,
  Object? cellColor,
) {
  final dateRange = _apiConditionDateRange(conditionValue[0]);
  if (dateRange == null) {
    return;
  }
  for (final range in cellRanges) {
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final cell = sheet.cells[FortuneCellCoord(row, column)];
        if (cell?.cellType?.type != 'd') {
          continue;
        }
        final serial =
            _apiConditionDateSerial(sheet.getCellValue(row, column)) ??
            _apiConditionDateSerial(cell?.value) ??
            _apiConditionDateSerial(cell?.displayValue);
        if (serial == null || serial < dateRange.$1 || serial > dateRange.$2) {
          continue;
        }
        _apiSetConditionStyle(computeMap, row, column, textColor, cellColor);
      }
    }
  }
}

(int, int)? _apiConditionDateRange(Object? value) {
  final text = '${value ?? ''}'.trim();
  if (text.isEmpty) {
    return null;
  }
  final parts = text.split(RegExp(r'\s+-\s+'));
  if (parts.length == 2) {
    final start = _apiConditionDateSerial(parts[0]);
    final end = _apiConditionDateSerial(parts[1]);
    if (start == null || end == null) {
      return null;
    }
    return (math.min(start, end), math.max(start, end));
  }
  final exact = _apiConditionDateSerial(text);
  return exact == null ? null : (exact, exact);
}

int? _apiConditionDateSerial(Object? value) {
  if (value == null) {
    return null;
  }
  if (value is num) {
    return value.floor();
  }
  final text = '$value'.trim();
  if (text.isEmpty) {
    return null;
  }
  final number = double.tryParse(text);
  if (number != null) {
    return number.floor();
  }
  final match = RegExp(
    r'^(\d{4})[-/.](\d{1,2})[-/.](\d{1,2})',
  ).firstMatch(text);
  if (match == null) {
    return null;
  }
  final year = int.parse(match.group(1)!);
  final month = int.parse(match.group(2)!);
  final day = int.parse(match.group(3)!);
  final date = DateTime.utc(year, month, day);
  if (date.year != year || date.month != month || date.day != day) {
    return null;
  }
  return date.difference(DateTime.utc(1899, 12, 30)).inDays;
}

void _apiApplyTopLastCondition(
  FortuneSheet sheet,
  Map<String, Map<String, Object?>> computeMap,
  List<FortuneRange> cellRanges,
  String conditionName,
  List<Object?> conditionValue,
  Object? textColor,
  Object? cellColor,
) {
  final projectValue = int.tryParse('${conditionValue[0]}');
  if (projectValue == null) {
    return;
  }
  for (final range in cellRanges) {
    final values = _apiConditionNumericValues(sheet, range);
    if (values.isEmpty) {
      continue;
    }
    final sorted = values.map((entry) => entry.value).toList()
      ..sort((left, right) => right.compareTo(left));
    final count = conditionName.endsWith('_percent')
        ? (projectValue * sorted.length) ~/ 100
        : projectValue;
    final selected = conditionName.startsWith('top')
        ? sorted.take(count).toSet()
        : sorted.skip(math.max(sorted.length - count, 0)).toSet();
    for (final entry in values) {
      if (!selected.contains(entry.value)) {
        continue;
      }
      _apiSetConditionStyle(
        computeMap,
        entry.key.row,
        entry.key.column,
        textColor,
        cellColor,
      );
    }
  }
}

void _apiApplyAverageCondition(
  FortuneSheet sheet,
  Map<String, Map<String, Object?>> computeMap,
  List<FortuneRange> cellRanges,
  String conditionName,
  Object? textColor,
  Object? cellColor,
) {
  for (final range in cellRanges) {
    final values = _apiConditionNumericValues(sheet, range);
    if (values.isEmpty) {
      continue;
    }
    final average =
        values.fold<num>(0, (sum, entry) => sum + entry.value) / values.length;
    for (final entry in values) {
      final shouldApply = conditionName == 'aboveAverage'
          ? entry.value > average
          : entry.value < average;
      if (!shouldApply) {
        continue;
      }
      _apiSetConditionStyle(
        computeMap,
        entry.key.row,
        entry.key.column,
        textColor,
        cellColor,
      );
    }
  }
}

List<MapEntry<FortuneCellCoord, num>> _apiConditionNumericValues(
  FortuneSheet sheet,
  FortuneRange range,
) {
  final values = <MapEntry<FortuneCellCoord, num>>[];
  for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
    for (
      var column = range.columnStart;
      column <= range.columnEnd;
      column += 1
    ) {
      final cell = sheet.cells[FortuneCellCoord(row, column)];
      if (cell?.cellType?.type != 'n') {
        continue;
      }
      final value = num.tryParse('${sheet.getCellValue(row, column)}');
      if (value == null) {
        continue;
      }
      values.add(MapEntry(FortuneCellCoord(row, column), value));
    }
  }
  return values;
}

void _apiApplyDuplicateValueCondition(
  FortuneSheet sheet,
  Map<String, Map<String, Object?>> computeMap,
  List<FortuneRange> cellRanges,
  List<Object?> conditionValue,
  Object? textColor,
  Object? cellColor,
) {
  final mode = '${conditionValue[0]}';
  if (mode != '0' && mode != '1') {
    return;
  }
  for (final range in cellRanges) {
    final valueMap = <String, List<FortuneCellCoord>>{};
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final value = sheet.getCellValue(row, column);
        valueMap
            .putIfAbsent('$value', () => <FortuneCellCoord>[])
            .add(FortuneCellCoord(row, column));
      }
    }
    for (final entries in valueMap.values) {
      final shouldApply = mode == '0'
          ? entries.length > 1
          : entries.length == 1;
      if (!shouldApply) {
        continue;
      }
      for (final coord in entries) {
        _apiSetConditionStyle(
          computeMap,
          coord.row,
          coord.column,
          textColor,
          cellColor,
        );
      }
    }
  }
}

void _apiSetConditionStyle(
  Map<String, Map<String, Object?>> computeMap,
  int row,
  int column,
  Object? textColor,
  Object? cellColor,
) {
  final cellStyle = computeMap.putIfAbsent(
    '${row}_$column',
    () => <String, Object?>{},
  );
  cellStyle['textColor'] = textColor;
  cellStyle['cellColor'] = cellColor;
}

void _apiApplyColorGradation(
  FortuneSheet sheet,
  Map<String, Map<String, Object?>> computeMap,
  List<FortuneRange> cellRanges,
  Object? format,
) {
  if (format is! List || (format.length != 2 && format.length != 3)) {
    return;
  }
  final maxColor = '${format[0]}';
  final midColor = format.length == 3 ? '${format[1]}' : null;
  final minColor = '${format[format.length - 1]}';
  final values = <String, int>{};
  for (final range in cellRanges) {
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final cell = sheet.cells[FortuneCellCoord(row, column)];
        if (cell?.cellType?.type != 'n') {
          continue;
        }
        final number = _apiConditionFormatIntValue(cell);
        if (number == null) {
          continue;
        }
        values['${row}_$column'] = number;
      }
    }
  }
  if (values.isEmpty) {
    return;
  }
  final min = values.values.reduce(math.min);
  final max = values.values.reduce(math.max);
  if (midColor != null) {
    final average =
        values.values.reduce((sum, value) => sum + value) ~/ values.length;
    for (final entry in values.entries) {
      final cellStyle = computeMap.putIfAbsent(
        entry.key,
        () => <String, Object?>{},
      );
      if (entry.value == min) {
        cellStyle['cellColor'] = minColor;
      } else if (entry.value > min && entry.value < average) {
        cellStyle['cellColor'] = getColorGradation(
          minColor,
          midColor,
          min,
          average,
          entry.value,
        );
      } else if (entry.value == average) {
        cellStyle['cellColor'] = midColor;
      } else if (entry.value > average && entry.value < max) {
        cellStyle['cellColor'] = getColorGradation(
          midColor,
          maxColor,
          average,
          max,
          entry.value,
        );
      } else if (entry.value == max) {
        cellStyle['cellColor'] = maxColor;
      }
    }
    return;
  }
  for (final entry in values.entries) {
    final cellStyle = computeMap.putIfAbsent(
      entry.key,
      () => <String, Object?>{},
    );
    if (entry.value == min) {
      cellStyle['cellColor'] = minColor;
    } else if (entry.value == max) {
      cellStyle['cellColor'] = maxColor;
    } else if (min != max) {
      cellStyle['cellColor'] = getColorGradation(
        minColor,
        maxColor,
        min,
        max,
        entry.value,
      );
    }
  }
}

int? _apiConditionFormatIntValue(FortuneCell? cell) {
  final rawValue = cell == null
      ? null
      : cell.hasRawValue
      ? cell.rawValue
      : cell.value;
  final number = num.tryParse('$rawValue');
  return number?.toInt();
}

List<FortuneRange> _apiConditionRuleRanges(Object? value) {
  if (value is! Iterable) {
    return const [];
  }
  return [
    for (final item in value.whereType<Map>()) ?_selectionRangeFromApiMap(item),
  ];
}

bool _apiConditionRuleMatches(
  String conditionName,
  Object? value,
  List<Object?> conditionValue,
) {
  final expected = conditionValue[0];
  final valueNumber = num.tryParse('$value');
  final expectedNumber = num.tryParse('$expected');
  return switch (conditionName) {
    'greaterThan' =>
      valueNumber != null &&
          expectedNumber != null &&
          valueNumber > expectedNumber,
    'lessThan' =>
      valueNumber != null &&
          expectedNumber != null &&
          valueNumber < expectedNumber,
    'equal' => '$value' == '$expected',
    'textContains' => '$value'.contains('$expected'),
    'between' =>
      conditionValue.length > 1 &&
          valueNumber != null &&
          num.tryParse('${conditionValue[1]}') != null &&
          _apiBetween(
            valueNumber,
            expectedNumber,
            num.tryParse('${conditionValue[1]}')!,
          ),
    _ => false,
  };
}

bool _apiBetween(num value, num? first, num second) {
  if (first == null) {
    return false;
  }
  final lower = math.min(first, second);
  final upper = math.max(first, second);
  return value >= lower && value <= upper;
}

List<Map<String, Object?>> getHistoryRules(Iterable<FortuneSheet> sheets) {
  return _apiConditionRulesBySheet(sheets);
}

List<Map<String, Object?>> getCurrentRules(Iterable<FortuneSheet> sheets) {
  return _apiConditionRulesBySheet(sheets);
}

Map<String, Object?> setConditionRules(
  FortuneSheet sheet,
  Map<String, Object?> rules, {
  Iterable<FortuneRange>? selection,
  Map<String, String> conditionformat = const {},
}) {
  if (!checkProtectionFormatCells(sheet)) {
    return <String, Object?>{
      'valid': false,
      'message': null,
      'sheet': sheet,
      'rule': null,
    };
  }
  final conditionName = '${rules['rulesType'] ?? ''}';
  final conditionRange = <Map<String, Object?>>[];
  final conditionValue = <Object?>[];
  String? message;

  Object? readSingleRangeValue(Object? value) {
    final rangeText = '${value ?? ''}';
    final ranges = getRangeByTxt(
      sheet,
      rangeText,
    ).whereType<FortuneRange>().toList();
    if (ranges.isEmpty) {
      return _sentinel;
    }
    if (ranges.length != 1 ||
        ranges.single.rowStart != ranges.single.rowEnd ||
        ranges.single.columnStart != ranges.single.columnEnd) {
      message = conditionformat['onlySingleCell'] ?? 'only single cell';
      return null;
    }
    final range = ranges.single;
    conditionRange.add(_selectionRangeToApiMap(range));
    return sheet.getCellValue(range.rowStart, range.columnStart);
  }

  bool pushInputValue(Object? value) {
    final rangeValue = readSingleRangeValue(value);
    if (message != null) {
      return false;
    }
    if (rangeValue != _sentinel) {
      conditionValue.add(rangeValue);
      return true;
    }
    if (value == null || '$value'.isEmpty) {
      message =
          conditionformat['conditionValueCanOnly'] ?? 'invalid condition value';
      return false;
    }
    conditionValue.add(value);
    return true;
  }

  if (conditionName == 'greaterThan' ||
      conditionName == 'lessThan' ||
      conditionName == 'equal' ||
      conditionName == 'textContains') {
    if (!pushInputValue(rules['rulesValue'])) {
      return <String, Object?>{
        'valid': false,
        'message': message,
        'sheet': sheet,
        'rule': null,
      };
    }
  } else if (conditionName == 'between') {
    final between = rules['betweenValue'];
    final value1 = between is Map ? between['value1'] : null;
    final value2 = between is Map ? between['value2'] : null;
    if (!pushInputValue(value1) || !pushInputValue(value2)) {
      return <String, Object?>{
        'valid': false,
        'message': message,
        'sheet': sheet,
        'rule': null,
      };
    }
  } else if (conditionName == 'occurrenceDate') {
    final value = rules['dateValue'];
    if (value == null || '$value'.isEmpty) {
      return <String, Object?>{
        'valid': false,
        'message':
            conditionformat['pleaseSelectADate'] ?? 'please select a date',
        'sheet': sheet,
        'rule': null,
      };
    }
    conditionValue.add(value);
  } else if (conditionName == 'duplicateValue') {
    conditionValue.add(rules['repeatValue']);
  } else if (conditionName == 'top10' ||
      conditionName == 'top10_percent' ||
      conditionName == 'last10' ||
      conditionName == 'last10_percent') {
    final value = '${rules['projectValue'] ?? ''}';
    final number = int.tryParse(value);
    if (number == null || '$number' != value || number < 1 || number > 1000) {
      return <String, Object?>{
        'valid': false,
        'message':
            conditionformat['pleaseEnterInteger'] ?? 'please enter integer',
        'sheet': sheet,
        'rule': null,
      };
    }
    conditionValue.add(value);
  } else {
    conditionValue.add(conditionName);
  }

  Object? checkedColor(Object? value) {
    if (value is Map && value['check'] == true) {
      return value['color'];
    }
    return null;
  }

  final rule = <String, Object?>{
    'type': 'default',
    'cellrange': [
      for (final range in selection ?? sheet.getSelection())
        _selectionRangeToApiMap(range),
    ],
    'format': <String, Object?>{
      'textColor': checkedColor(rules['textColor']),
      'cellColor': checkedColor(rules['cellColor']),
    },
    'conditionName': conditionName,
    'conditionRange': conditionRange,
    'conditionValue': conditionValue,
  };
  final ruleArr = _apiConditionFormatList(sheet.conditionFormats)..add(rule);
  return <String, Object?>{
    'valid': true,
    'message': null,
    'sheet': sheet.copyWith(conditionFormats: ruleArr),
    'rule': rule,
  };
}

FortuneSheet updateItem(
  FortuneSheet sheet,
  String type, {
  Iterable<FortuneRange>? selection,
  Object? textColor,
  Object? cellColor,
}) {
  if (!checkProtectionFormatCells(sheet)) {
    return sheet;
  }
  if (type == 'delSheet') {
    return sheet.copyWith(conditionFormats: const []);
  }
  final ruleArr = _apiConditionFormatList(sheet.conditionFormats);
  ruleArr.add(<String, Object?>{
    'type': type,
    'cellrange': [
      for (final range in selection ?? sheet.getSelection())
        _selectionRangeToApiMap(range),
    ],
    'format': <String, Object?>{'textColor': textColor, 'cellColor': cellColor},
  });
  return sheet.copyWith(conditionFormats: ruleArr);
}

List<Object?> _apiConditionFormatList(Object? value) {
  if (value is Iterable) {
    return [for (final item in value) cloneFortuneMetadata(item)];
  }
  return <Object?>[];
}

String getColorGradation(
  String color1,
  String color2,
  num value1,
  num value2,
  num value,
) {
  final rgb1 = _apiRgbParts(color1);
  final rgb2 = _apiRgbParts(color2);
  final valueRange = value1 - value2;
  final valueOffset = value1 - value;
  final red = (rgb1[0] - ((rgb1[0] - rgb2[0]) / valueRange) * valueOffset)
      .round();
  final green = (rgb1[1] - ((rgb1[1] - rgb2[1]) / valueRange) * valueOffset)
      .round();
  final blue = (rgb1[2] - ((rgb1[2] - rgb2[2]) / valueRange) * valueOffset)
      .round();
  return 'rgb($red, $green, $blue)';
}

List<int> _apiRgbParts(String color) {
  final match = RegExp(
    r'rgb\s*\(\s*(-?\d+)\s*,\s*(-?\d+)\s*,\s*(-?\d+)\s*\)',
  ).firstMatch(color);
  if (match == null) {
    return const [0, 0, 0];
  }
  return [
    int.parse(match.group(1)!),
    int.parse(match.group(2)!),
    int.parse(match.group(3)!),
  ];
}

Object? normalizedCellAttr(
  FortuneCell? cell,
  String attr, {
  int defaultFontSize = 10,
}) {
  if (cell == null) {
    return null;
  }
  final value = _apiRawCellAttr(cell, attr);
  if (const {'bl', 'it', 'ff', 'cl', 'un'}.contains(attr)) {
    return _apiNormalizeFlagAttr(value);
  }
  if (attr == 'fc' || attr == 'bc') {
    return _apiNormalizeColorAttr(value, '#000000');
  }
  if (attr == 'bg') {
    return _apiNormalizeColorAttr(value, null);
  }
  if (attr.startsWith('bs')) {
    return value ?? 'none';
  }
  if (attr == 'ht') {
    final normalized = value?.toString() ?? '1';
    return const {'0', '1', '2'}.contains(normalized) ? normalized : '1';
  }
  if (attr == 'vt') {
    final normalized = value?.toString() ?? '0';
    return const {'0', '1', '2'}.contains(normalized) ? normalized : '0';
  }
  if (attr == 'fs') {
    return value ?? defaultFontSize.toString();
  }
  if (attr == 'tb' || attr == 'tr') {
    return value ?? '0';
  }
  return value;
}

Object? normalizedAttr(
  FortuneSheet sheet,
  int row,
  int column,
  String attr, {
  int defaultFontSize = 10,
}) {
  final cell = sheet.cells[FortuneCellCoord(row, column)];
  if (cell == null) {
    return null;
  }
  return normalizedCellAttr(cell, attr, defaultFontSize: defaultFontSize);
}

Object? getRealCellValue(FortuneCell? cell, {String attr = 'v'}) {
  if (cell == null) {
    return null;
  }
  final displayValue = cell.hasRawDisplayValue
      ? cell.rawDisplayValue
      : cell.displayValue;
  if (displayValue != null) {
    return displayValue;
  }
  final attrValue = _apiRawCellAttr(cell, attr);
  if (attrValue != null) {
    return attrValue;
  }
  if (isInlineStringCT(cell.cellType)) {
    return cloneFortuneMetadata(cell.cellType!.style);
  }
  if (cell.inlineRuns != null) {
    final rawCellType = FortuneSheetCodec.cellToJson(cell)['ct'];
    if (rawCellType is Map) {
      return cloneFortuneMetadata(rawCellType['s']);
    }
  }
  return null;
}

Object? _apiGetCellValue(FortuneCell cell) {
  final displayValue = cell.hasRawDisplayValue
      ? cell.rawDisplayValue
      : cell.displayValue;
  final cellType = cell.cellType;
  if (cellType?.type == 'd' && displayValue != null) {
    return displayValue;
  }
  if (cellType?.type == 'inlineStr' && cell.inlineRuns != null) {
    return cell.inlineRuns!.map((run) => run.text).join();
  }
  if (!cell.hasRawValue && cell.value.isEmpty) {
    return null;
  }
  return cell.hasRawValue ? cell.rawValue : cell.value;
}

Object? _apiGetFormulaCellValue(FortuneCell cell) {
  final formula = cell.formula;
  if (formula != null) {
    return formula;
  }
  if (cell.hasRawValue) {
    return cell.rawValue;
  }
  if (cell.value.isEmpty) {
    return null;
  }
  return cell.value;
}

Object? valueShowEs(FortuneCell? cell) {
  if (cell == null) {
    return null;
  }
  final displayValue = cell.hasRawDisplayValue
      ? cell.rawDisplayValue
      : cell.displayValue;
  if (displayValue == null) {
    return _apiRawCellAttr(cell, 'v');
  }
  final value = '$displayValue';
  if (!_apiFuzzyNum(value).isNaN) {
    if (value.contains('%')) {
      return value;
    }
    return _apiRawCellAttr(cell, 'v');
  }
  final cellType = cell.cellType?.type;
  if (cellType == 'd' || cellType == 'b') {
    return value;
  }
  return _apiRawCellAttr(cell, 'v');
}

double _apiFuzzyNum(String value) {
  final direct = double.tryParse(value);
  if (direct != null) {
    return direct;
  }
  var weight = 1.0;
  var text = value
      .replaceAllMapped(
        RegExp(r'([\d]),([\d])'),
        (match) => '${match.group(1)}${match.group(2)}',
      )
      .replaceAll(r'$', '')
      .replaceAllMapped(RegExp(r'%'), (_) {
        weight *= 100;
        return '';
      });
  final stripped = double.tryParse(text);
  if (stripped != null) {
    return stripped / weight;
  }
  text = text.replaceAllMapped(RegExp(r'[(](.*)[)]'), (match) {
    weight = -weight;
    return match.group(1)!;
  });
  final parenthesized = double.tryParse(text);
  return parenthesized == null ? double.nan : parenthesized / weight;
}

Map<String, num> getArrowCanvasSize(num fromX, num fromY, num toX, num toY) {
  var left = toX - 5;
  if (fromX < toX) {
    left = fromX - 5;
  }
  var top = toY - 5;
  if (fromY < toY) {
    top = fromY - 5;
  }
  final width = (fromX - toX).abs() + 10;
  final height = (fromY - toY).abs() + 10;
  var x1 = width - 5;
  num x2 = 5;
  if (fromX < toX) {
    x1 = 5;
    x2 = width - 5;
  }
  var y1 = height - 5;
  num y2 = 5;
  if (fromY < toY) {
    y1 = 5;
    y2 = height - 5;
  }
  return {
    'left': left,
    'top': top,
    'width': width,
    'height': height,
    'fromX': x1,
    'fromY': y1,
    'toX': x2,
    'toY': y2,
  };
}

Map<String, Object?> drawArrow(
  String rc,
  Map<String, num> size, [
  String color = '#000',
  num theta = 30,
  num headlen = 6,
]) {
  final left = size['left']!;
  final top = size['top']!;
  final width = size['width']!;
  final height = size['height']!;
  final fromX = size['fromX']!;
  final fromY = size['fromY']!;
  final toX = size['toX']!;
  final toY = size['toY']!;
  final angle = math.atan2(fromY - toY, fromX - toX) * 180 / math.pi;
  final angle1 = (angle + theta) * math.pi / 180;
  final angle2 = (angle - theta) * math.pi / 180;
  final topX = headlen * math.cos(angle1);
  final topY = headlen * math.sin(angle1);
  final botX = headlen * math.cos(angle2);
  final botY = headlen * math.sin(angle2);

  return {
    'rc': rc,
    'canvasId': 'arrowCanvas-$rc',
    'left': left,
    'top': top,
    'width': width,
    'height': height,
    'style': {
      'left': '${left}px',
      'top': '${top}px',
      'width': '${width}px',
      'height': '${height}px',
    },
    'line': {'fromX': fromX, 'fromY': fromY, 'toX': toX, 'toY': toY},
    'arrowHead': [
      {'x': toX + topX, 'y': toY + topY},
      {'x': toX, 'y': toY},
      {'x': toX + botX, 'y': toY + botY},
    ],
    'color': color,
    'theta': theta,
    'headlen': headlen,
    'arrowWidth': 1,
  };
}

Map<String, num> getCellTopRightPostion(
  FortuneSheet sheet,
  int row,
  int column, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
}) {
  final mergeRange = _apiMergeRangeContaining(sheet, row, column);
  final targetRow = mergeRange?.rowStart ?? row;
  final targetColumn = mergeRange?.columnEnd ?? column;
  final rowPrevious = targetRow == 0 ? 0 : visibleDataRows[targetRow - 1];
  final columnEnd = visibleDataColumns[targetColumn];
  return {'toX': columnEnd, 'toY': rowPrevious};
}

Map<String, Object?> getCommentBoxByRC(
  FortuneSheet sheet,
  int row,
  int column, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num zoomRatio = 1,
}) {
  final comment = sheet.cells[FortuneCellCoord(row, column)]?.comment;
  final position = getCellTopRightPostion(
    sheet,
    row,
    column,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
  );
  final toX = position['toX']!;
  final toY = position['toY']!;
  final left = comment?.left == null
      ? toX + 18 * zoomRatio
      : comment!.left! * zoomRatio;
  var top = comment?.top == null
      ? toY - 18 * zoomRatio
      : comment!.top! * zoomRatio;
  final width = comment?.width == null
      ? (commentBoxProps['defaultWidth']! as num) * zoomRatio
      : comment!.width! * zoomRatio;
  final height = comment?.height == null
      ? (commentBoxProps['defaultHeight']! as num) * zoomRatio
      : comment!.height! * zoomRatio;
  if (top < 0) {
    top = 2;
  }
  return {
    'r': row,
    'c': column,
    'rc': '${row}_$column',
    'left': left,
    'top': top,
    'width': width,
    'height': height,
    'value': comment?.value ?? '',
    'size': getArrowCanvasSize(left, top, toX, toY),
    'autoFocus': false,
  };
}

Map<String, Object?>? overShowComment(
  FortuneSheet sheet, {
  required num pageX,
  required num pageY,
  required num containerLeft,
  required num containerTop,
  required num scrollLeft,
  required num scrollTop,
  required num rowHeaderWidth,
  required num columnHeaderHeight,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  Iterable<Map<String, Object?>> commentBoxes = const [],
  Map<String, Object?>? editingCommentBox,
  num zoomRatio = 1,
}) {
  var x = pageX - containerLeft - rowHeaderWidth + scrollLeft;
  var y = pageY - containerTop - columnHeaderHeight + scrollTop;
  var row = rowLocation(y, visibleDataRows)[2].toInt();
  var column = colLocation(x, visibleDataColumns)[2].toInt();
  final anchor = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
  row = anchor.row;
  column = anchor.column;
  final rc = '${row}_$column';
  final comment = sheet.cells[FortuneCellCoord(row, column)]?.comment;
  final alreadyShown = commentBoxes.any((box) => box['rc'] == rc);
  if (comment == null ||
      comment.isShow ||
      alreadyShown ||
      editingCommentBox?['rc'] == rc) {
    return null;
  }
  return getCommentBoxByRC(
    sheet,
    row,
    column,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
    zoomRatio: zoomRatio,
  );
}

FortuneSheet newComment(
  FortuneSheet sheet,
  int row,
  int column, {
  bool allowEdit = true,
  BeforeCommentHook? beforeInsertComment,
  AfterCommentHook? afterInsertComment,
}) {
  if (!allowEdit || row < 0 || column < 0) {
    return sheet.copyWith();
  }
  if (beforeInsertComment?.call(row, column) == false) {
    return sheet.copyWith();
  }
  final coord = FortuneCellCoord(row, column);
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  final current = cells[coord] ?? const FortuneCell();
  cells[coord] = current.copyWith(
    comment: const FortuneCellComment(value: '', isShow: false),
  );
  final nextSheet = sheet.copyWith(cells: cells);
  afterInsertComment?.call(row, column);
  return nextSheet;
}

Map<String, Object?>? editComment(
  FortuneSheet sheet,
  int row,
  int column, {
  bool allowEdit = true,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num zoomRatio = 1,
}) {
  if (!allowEdit || row < 0 || column < 0) {
    return null;
  }
  final comment = sheet.cells[FortuneCellCoord(row, column)]?.comment;
  if (comment == null) {
    return null;
  }
  return {
    ...getCommentBoxByRC(
      sheet,
      row,
      column,
      visibleDataRows: visibleDataRows,
      visibleDataColumns: visibleDataColumns,
      zoomRatio: zoomRatio,
    ),
    'autoFocus': true,
  };
}

Map<String, Object?>? setEditingComment(
  FortuneSheet sheet,
  int row,
  int column, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num zoomRatio = 1,
}) {
  if (row < 0 || column < 0) {
    return null;
  }
  return {
    ...getCommentBoxByRC(
      sheet,
      row,
      column,
      visibleDataRows: visibleDataRows,
      visibleDataColumns: visibleDataColumns,
      zoomRatio: zoomRatio,
    ),
    'autoFocus': true,
  };
}

Map<String, Object?> removeEditingComment(
  FortuneSheet sheet,
  int row,
  int column,
  Object? value, {
  Iterable<Map<String, Object?>> commentBoxes = const [],
  BeforeUpdateCommentHook? beforeUpdateComment,
  AfterUpdateCommentHook? afterUpdateComment,
}) {
  final boxes = [
    for (final box in commentBoxes) Map<String, Object?>.from(box),
  ];
  if (row < 0 || column < 0) {
    return {'sheet': sheet.copyWith(), 'commentBoxes': boxes};
  }
  if (beforeUpdateComment?.call(row, column, value) == false) {
    return {'sheet': sheet.copyWith(), 'commentBoxes': boxes};
  }
  final coord = FortuneCellCoord(row, column);
  final current = sheet.cells[coord];
  final comment = current?.comment;
  if (current == null || comment == null) {
    return {'sheet': sheet.copyWith(), 'commentBoxes': boxes};
  }
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  cells[coord] = current.copyWith(
    comment: comment.copyWith(value: value?.toString() ?? ''),
  );
  final nextBoxes = comment.isShow
      ? boxes
      : boxes.where((box) => box['rc'] != '${row}_$column').toList();
  final nextSheet = sheet.copyWith(cells: cells);
  afterUpdateComment?.call(row, column, comment.value, value);
  return {'sheet': nextSheet, 'commentBoxes': nextBoxes};
}

FortuneSheet deleteComment(
  FortuneSheet sheet,
  int row,
  int column, {
  bool allowEdit = true,
  BeforeCommentHook? beforeDeleteComment,
  AfterCommentHook? afterDeleteComment,
}) {
  if (!allowEdit || row < 0 || column < 0) {
    return sheet.copyWith();
  }
  if (beforeDeleteComment?.call(row, column) == false) {
    return sheet.copyWith();
  }
  final coord = FortuneCellCoord(row, column);
  final current = sheet.cells[coord];
  if (current == null || current.comment == null) {
    return sheet.copyWith();
  }
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  cells[coord] = current.copyWith(comment: null);
  final nextSheet = sheet.copyWith(cells: cells);
  afterDeleteComment?.call(row, column);
  return nextSheet;
}

List<Map<String, Object?>> showComments(
  FortuneSheet sheet,
  Iterable<Object?> commentShowCells, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num zoomRatio = 1,
}) {
  final commentBoxes = <Map<String, Object?>>[];
  for (final item in commentShowCells) {
    final coord = _apiCommentCoord(item);
    if (coord == null) {
      continue;
    }
    commentBoxes.add(
      getCommentBoxByRC(
        sheet,
        coord.row,
        coord.column,
        visibleDataRows: visibleDataRows,
        visibleDataColumns: visibleDataColumns,
        zoomRatio: zoomRatio,
      ),
    );
  }
  return commentBoxes;
}

FortuneSheet showHideComment(FortuneSheet sheet, int row, int column) {
  if (row < 0 || column < 0) {
    return sheet.copyWith();
  }
  final coord = FortuneCellCoord(row, column);
  final current = sheet.cells[coord];
  final comment = current?.comment;
  if (current == null || comment == null) {
    return sheet.copyWith();
  }
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  cells[coord] = current.copyWith(
    comment: comment.copyWith(isShow: !comment.isShow),
  );
  return sheet.copyWith(cells: cells);
}

FortuneSheet showHideAllComments(FortuneSheet sheet) {
  final commentEntries = sheet.cells.entries
      .where((entry) => entry.value.comment != null)
      .toList();
  if (commentEntries.isEmpty) {
    return sheet.copyWith();
  }
  final nextIsShow = !commentEntries.every(
    (entry) => entry.value.comment!.isShow,
  );
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  for (final entry in commentEntries) {
    final comment = entry.value.comment!;
    cells[entry.key] = entry.value.copyWith(
      comment: comment.copyWith(isShow: nextIsShow),
    );
  }
  return sheet.copyWith(cells: cells);
}

FortuneCellCoord? _apiCommentCoord(Object? item) {
  if (item is FortuneCellCoord) {
    return item;
  }
  if (item is Map) {
    final row = _nullableIntArg(item['r'] ?? item['row']);
    final column = _nullableIntArg(item['c'] ?? item['column']);
    if (row != null && column != null) {
      return FortuneCellCoord(row, column);
    }
  }
  return null;
}

Map<String, Object?> getFilterColumnValues(
  FortuneSheet sheet,
  int column,
  int startRow,
  int endRow,
  int startColumn, {
  Map<int, Map<String, Object?>> filter = const {},
  String valueBlank = '(Blank)',
  String yearText = 'Year',
  String monthText = 'Month',
}) {
  final hidden = _apiFilterHiddenRows(filter, column, startColumn);
  final otherHiddenRows = hidden.$1;
  final hiddenRows = hidden.$2;
  final visibleRows = <int>[];
  final flattenValues = <String>[];
  final dates = <Map<String, Object?>>[];
  final datesUncheck = <String>[];
  final dateRowMap = <String, List<int>>{};
  final valuesMap = <String, List<Map<String, Object?>>>{};
  final valuesUncheck = <String>[];
  final valueRowMap = <String, List<int>>{};

  for (var row = startRow + 1; row <= endRow; row += 1) {
    if (otherHiddenRows.contains(row)) {
      continue;
    }
    visibleRows.add(row);
    final cell = sheet.cells[FortuneCellCoord(row, column)];
    final rawValue = cell?.hasRawValue == true ? cell?.rawValue : cell?.value;
    final value = cell == null || isRealNull(rawValue) ? null : rawValue;
    if (cell != null && value != null && cell.cellType?.type == 'd') {
      final dateStr = _apiFilterDateText(value);
      final parts = dateStr.split('-');
      if (parts.length == 3) {
        final year = parts[0];
        final month = parts[1];
        final day = parts[2];
        final hasYearValue = dates.any((node) => node['value'] == year);
        final yearValue = _apiFilterDateNode(
          dates,
          key: year,
          type: 'year',
          value: year,
          text: '$year$yearText',
        );
        final monthChildren =
            yearValue['children']! as List<Map<String, Object?>>;
        final monthValue = _apiFilterDateNode(
          monthChildren,
          key: '$year-$month',
          type: 'month',
          value: month,
          text: '$month$monthText',
        );
        final dayChildren =
            monthValue['children']! as List<Map<String, Object?>>;
        final dayValue = _apiFilterDateNode(
          dayChildren,
          key: dateStr,
          type: 'day',
          value: day,
          text: day,
        );
        for (final node in [yearValue, monthValue, dayValue]) {
          (node['rows']! as List<int>).add(row);
          (node['dateValues']! as List<String>).add(dateStr);
        }
        dateRowMap.putIfAbsent(dateStr, () => <int>[]).add(row);
        if (!hasYearValue) {
          flattenValues.add(dateStr);
        }
        if (hiddenRows.contains(row) && !datesUncheck.contains(dateStr)) {
          datesUncheck.add(dateStr);
        }
        continue;
      }
    }

    final mask = value == null
        ? null
        : cell?.hasRawDisplayValue == true
        ? cell?.rawDisplayValue
        : (cell?.displayValue ?? cell?.value);
    final text = mask == null ? valueBlank : mask.toString();
    final valueKey = value?.toString() ?? 'null';
    final key = '$valueKey#\$\$\$#$mask';
    final data = valuesMap.putIfAbsent(
      valueKey,
      () => <Map<String, Object?>>[],
    );
    var maskValue = data.cast<Map<String, Object?>?>().firstWhere(
      (item) => item?['mask'] == mask,
      orElse: () => null,
    );
    if (maskValue == null) {
      maskValue = {
        'key': key,
        'value': value,
        'text': text,
        'mask': mask,
        'rows': <int>[],
      };
      data.add(maskValue);
      flattenValues.add(text);
    }
    (maskValue['rows']! as List<int>).add(row);
    if (hiddenRows.contains(row) && !valuesUncheck.contains(key)) {
      valuesUncheck.add(key);
    }
    valueRowMap.putIfAbsent(key, () => <int>[]).add(row);
  }
  return {
    'dates': dates,
    'datesUncheck': datesUncheck,
    'dateRowMap': dateRowMap,
    'values': [for (final group in valuesMap.values) ...group],
    'valuesUncheck': valuesUncheck,
    'valueRowMap': valueRowMap,
    'visibleRows': visibleRows,
    'flattenValues': flattenValues,
  };
}

(Set<int>, Set<int>) _apiFilterHiddenRows(
  Map<int, Map<String, Object?>> filter,
  int column,
  int startColumn,
) {
  final otherHiddenRows = <int>{};
  final hiddenRows = <int>{};
  for (final entry in filter.entries) {
    final config = entry.value;
    final cindex = _nullableIntArg(config['cindex']) ?? entry.key + startColumn;
    final rowhidden = config['rowhidden'];
    if (rowhidden is! Map) {
      continue;
    }
    final target = cindex == column ? hiddenRows : otherHiddenRows;
    for (final row in rowhidden.keys) {
      final index = _nullableIntArg(row);
      if (index != null) {
        target.add(index);
      }
    }
  }
  return (otherHiddenRows, hiddenRows);
}

Map<String, Object?> _apiFilterDateNode(
  List<Map<String, Object?>> nodes, {
  required String key,
  required String type,
  required String value,
  required String text,
}) {
  for (final node in nodes) {
    if (node['value'] == value) {
      return node;
    }
  }
  final node = <String, Object?>{
    'key': key,
    'type': type,
    'value': value,
    'text': text,
    'children': <Map<String, Object?>>[],
    'rows': <int>[],
    'dateValues': <String>[],
  };
  nodes.add(node);
  return node;
}

String _apiFilterDateText(Object value) {
  return update('YYYY-MM-DD', value);
}

Map<String, Object?> getFilterColumnColors(
  FortuneSheet sheet,
  int column,
  int startRow,
  int endRow, {
  Set<int>? hiddenRows,
}) {
  final hidden = hiddenRows ?? sheet.hiddenRows;
  final conditionComputeMap = getComputeMap(sheet);
  final backgroundMap = <String, Map<String, Object?>>{};
  final foregroundMap = <String, Map<String, Object?>>{};
  for (var row = startRow + 1; row <= endRow; row += 1) {
    final cell = sheet.cells[FortuneCellCoord(row, column)];
    final rawValue = cell?.hasRawValue == true ? cell?.rawValue : cell?.value;
    final isRowHidden = hidden.contains(row);
    final conditionStyle = checkCF(row, column, conditionComputeMap);
    final conditionCellColor = conditionStyle is Map
        ? conditionStyle['cellColor']
        : null;
    final conditionTextColor = conditionStyle is Map
        ? conditionStyle['textColor']
        : null;
    final background = _apiFilterNormalizeColor(
      conditionCellColor ??
          normalizedAttr(sheet, row, column, 'bg') ??
          '#ffffff',
    );
    final backgroundData = backgroundMap.putIfAbsent(
      background,
      () => {'color': background, 'checked': !isRowHidden, 'rows': <int>[]},
    );
    (backgroundData['rows']! as List<int>).add(row);
    if (isRowHidden) {
      backgroundData['checked'] = false;
    }
    final hasValue = cell != null && !isRealNull(rawValue);
    final foreground = cell == null
        ? null
        : _apiFilterNormalizeColor(
            conditionTextColor ?? normalizedAttr(sheet, row, column, 'fc'),
          );
    if (foreground != null && hasValue) {
      final foregroundData = foregroundMap.putIfAbsent(
        foreground,
        () => {'color': foreground, 'checked': !isRowHidden, 'rows': <int>[]},
      );
      (foregroundData['rows']! as List<int>).add(row);
      if (isRowHidden) {
        foregroundData['checked'] = false;
      }
    }
  }
  final backgroundColors = backgroundMap.values.toList();
  final foregroundColors = foregroundMap.values.toList();
  return {
    'bgColors': backgroundColors.length < 2 ? const [] : backgroundColors,
    'fcColors': foregroundColors.length < 2 ? const [] : foregroundColors,
  };
}

String _apiFilterNormalizeColor(Object? color) {
  var value = color?.toString() ?? '#ffffff';
  if (value.contains('rgb')) {
    value = rgbToHex(value);
  }
  if (value.length == 4 && value.startsWith('#')) {
    value =
        '#${value[1]}${value[1]}${value[2]}${value[2]}${value[3]}${value[3]}';
  }
  return value;
}

Map<String, Object?>? createFilterOptions(
  FortuneRange? filterSave, {
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  Map<int, Object?>? filterObj,
}) {
  final range = filterSave == null ? null : _normalizedApiRange(filterSave);
  if (range == null) {
    return null;
  }
  final rowEnd = range.rowEnd;
  final rowStart = range.rowStart;
  final columnEnd = range.columnEnd;
  final columnStart = range.columnStart;
  final row = rowEnd >= 0 && rowEnd < visibleDataRows.length
      ? visibleDataRows[rowEnd]
      : 0;
  final rowPrevious = rowStart == 0
      ? 0
      : rowStart - 1 < visibleDataRows.length
      ? visibleDataRows[rowStart - 1]
      : 0;
  final column = columnEnd >= 0 && columnEnd < visibleDataColumns.length
      ? visibleDataColumns[columnEnd]
      : 0;
  final columnPrevious = columnStart == 0
      ? 0
      : columnStart - 1 < visibleDataColumns.length
      ? visibleDataColumns[columnStart - 1]
      : 0;
  final items = <Map<String, Object?>>[];
  for (
    var columnIndex = columnStart;
    columnIndex <= columnEnd;
    columnIndex += 1
  ) {
    var left = 0;
    if (columnIndex >= 0 &&
        columnIndex < visibleDataColumns.length &&
        _apiJsTruthy(visibleDataColumns[columnIndex])) {
      left = visibleDataColumns[columnIndex].toInt() - 20;
    }
    items.add({'col': columnIndex, 'left': left, 'top': rowPrevious});
  }
  return {
    'startRow': rowStart,
    'endRow': rowEnd,
    'startCol': columnStart,
    'endCol': columnEnd,
    'left': columnPrevious,
    'top': rowPrevious,
    'width': column - columnPrevious - 1,
    'height': row - rowPrevious - 1,
    'items': items,
  };
}

FortuneSheet clearFilter(FortuneSheet sheet) {
  final hiddenRowsFromFilter = <int>{};
  for (final item in sheet.filter.values) {
    if (item is Map && item['rowhidden'] is Map) {
      for (final key in (item['rowhidden']! as Map).keys) {
        final row = int.tryParse('$key');
        if (row != null) {
          hiddenRowsFromFilter.add(row);
        }
      }
    }
  }
  final nextHiddenRows = {...sheet.hiddenRows}..removeAll(hiddenRowsFromFilter);
  final nextHiddenRowValues = Map<int, Object?>.from(sheet.hiddenRowValues)
    ..removeWhere((key, _) => hiddenRowsFromFilter.contains(key));
  return sheet.copyWith(
    hiddenRows: nextHiddenRows,
    hiddenRowValues: nextHiddenRowValues,
    filter: const {},
    rawFilter: null,
    hasRawFilter: false,
    filterSelect: null,
    hasRawFilterSelect: false,
  );
}

FortuneSheet createFilter(
  FortuneSheet sheet, {
  Iterable<FortuneRange>? selection,
}) {
  final ranges = (selection ?? sheet.getSelection()).toList();
  if (ranges.length > 1 || sheet.isPivotTable == true) {
    return sheet.copyWith();
  }
  if (sheet.filterSelect is Map && (sheet.filterSelect! as Map).isNotEmpty) {
    return clearFilter(sheet);
  }
  if (ranges.isEmpty) {
    return sheet.copyWith();
  }
  final last = _normalizedApiRange(ranges.first);
  if (last == null) {
    return sheet.copyWith();
  }
  var filterRange = last;
  if (last.rowStart == last.rowEnd && last.columnStart == last.columnEnd) {
    final row = last.rowEnd;
    int? startColumn;
    int? endColumn;
    for (var column = 0; column <= _apiSheetMaxColumn(sheet); column += 1) {
      final cell = sheet.cells[FortuneCellCoord(row, column)];
      final value = cell?.hasRawValue == true ? cell?.rawValue : cell?.value;
      if (!isRealNull(value)) {
        startColumn ??= column;
      } else if (startColumn != null) {
        endColumn = column - 1;
        break;
      }
    }
    endColumn ??= _apiSheetMaxColumn(sheet);
    filterRange = FortuneRange(
      rowStart: row,
      rowEnd: row,
      columnStart: startColumn ?? 0,
      columnEnd: endColumn,
    );
  }
  return sheet.copyWith(filterSelect: _selectionRangeToApiMap(filterRange));
}

FortuneSheet saveFilter(
  FortuneSheet sheet,
  bool optionState,
  Map<String, Object?> hiddenRows,
  Object? caljs,
  int startRow,
  int endRow,
  int columnIndex,
  int startColumn,
  int endColumn,
) {
  final otherHiddenRows = <String, Object?>{};
  for (final value in sheet.filter.values) {
    if (value is! Map || value['cindex'] == columnIndex) {
      continue;
    }
    final rowhidden = value['rowhidden'];
    if (rowhidden is Map) {
      otherHiddenRows.addAll({
        for (final entry in rowhidden.entries) '${entry.key}': entry.value,
      });
    }
  }
  final rowHiddenAll = <String, Object?>{...otherHiddenRows, ...hiddenRows};
  final nextFilter = _cloneStringObjectMap(sheet.filter);
  final key = '${columnIndex - startColumn}';
  if (optionState) {
    nextFilter[key] = <String, Object?>{
      'caljs': cloneFortuneMetadata(caljs),
      'rowhidden': cloneFortuneMetadata(hiddenRows),
      'optionstate': optionState,
      'str': startRow,
      'edr': endRow,
      'cindex': columnIndex,
      'stc': startColumn,
      'edc': endColumn,
    };
  } else {
    nextFilter.remove(key);
  }
  final nextHiddenRows = <int>{};
  final nextHiddenRowValues = <int, Object?>{};
  for (final entry in rowHiddenAll.entries) {
    final row = int.tryParse(entry.key);
    if (row != null) {
      nextHiddenRows.add(row);
      nextHiddenRowValues[row] = cloneFortuneMetadata(entry.value);
    }
  }
  return sheet.copyWith(
    filter: nextFilter,
    hiddenRows: nextHiddenRows,
    hiddenRowValues: nextHiddenRowValues,
  );
}

void labelFilterOptionState(
  Map<int, Map<String, Object?>> filter,
  bool optionstate,
  Map<String, Object?> rowhidden,
  Object? caljs,
  int str,
  int edr,
  int cindex,
  int stc,
  int edc, {
  bool saveData = false,
  Map<int, Map<String, Object?>>? sheetFilter,
}) {
  final key = cindex - stc;
  final param = <String, Object?>{
    'caljs': cloneFortuneMetadata(caljs),
    'rowhidden': cloneFortuneMetadata(rowhidden),
    'optionstate': optionstate,
    'str': str,
    'edr': edr,
    'cindex': cindex,
    'stc': stc,
    'edc': edc,
  };
  if (optionstate) {
    filter[key] = param;
  } else {
    filter.remove(key);
  }
  if (!saveData || sheetFilter == null) {
    return;
  }
  if (optionstate) {
    sheetFilter[key] = Map<String, Object?>.from(
      cloneFortuneMetadata(param)! as Map,
    );
  } else {
    sheetFilter.remove(key);
  }
}

Map<String, Object?> getFontStyleByCell(
  FortuneCell? cell, {
  List<Object?>? checksAF,
  Map<String, Object?>? checksCF,
  bool isCheck = true,
}) {
  final style = <String, Object?>{};
  if (cell == null) {
    return style;
  }
  Object? attrValue(String attr) =>
      isCheck ? normalizedCellAttr(cell, attr) : _apiRawCellAttr(cell, attr);
  final bold = _apiFlagNumber(attrValue('bl'));
  if (bold != 0) {
    style['fontWeight'] = 'bold';
  }
  final italic = _apiFlagNumber(attrValue('it'));
  if (italic != 0) {
    style['fontStyle'] = 'italic';
  }
  final fontSize = num.tryParse('${attrValue('fs')}') ?? 10;
  if (fontSize != 10) {
    style['fontSize'] = '${_apiCssNumber(fontSize)}pt';
  }
  final foreground = attrValue('fc');
  final checkTextColor = checksCF?['textColor'];
  if (foreground != '#000000' ||
      (checksAF?.isNotEmpty ?? false) ||
      checkTextColor != null) {
    style['color'] =
        checkTextColor ??
        (checksAF?.isNotEmpty == true ? checksAF!.first : foreground);
  }
  final strikeThrough = _apiFlagNumber(attrValue('cl'));
  if (strikeThrough != 0) {
    style['textDecoration'] = 'line-through';
  }
  final underline = _apiFlagNumber(attrValue('un'));
  if (underline == 1 || underline == 3) {
    final color = cell.extraFields['_color'] ?? foreground;
    final size = _nullableDoubleArg(cell.extraFields['_fontSize']) ?? fontSize;
    style['borderBottom'] = '${size ~/ 9}px solid $color';
  }
  return style;
}

num _apiFlagNumber(Object? value) {
  if (value is bool) {
    return value ? 1 : 0;
  }
  if (value is num) {
    return value;
  }
  if (value is String) {
    return num.tryParse(value) ?? (value.isEmpty ? 0 : 1);
  }
  return value == null ? 0 : 1;
}

Map<String, Object?> getStyleByCell(
  FortuneCell? cell, {
  List<Object?>? checksAF,
  Map<String, Object?>? checksCF,
}) {
  final style = <String, Object?>{};
  if (cell == null) {
    return style;
  }
  if (_apiHasRawCellAttr(cell, 'bg')) {
    final cellColor = checksCF?['cellColor'];
    if (cellColor != null) {
      style['background'] = '$cellColor';
    } else if ((checksAF?.length ?? 0) > 1) {
      style['background'] = '${checksAF![1]}';
    } else {
      style['background'] = '${normalizedCellAttr(cell, 'bg')}';
    }
  }
  if (_apiHasRawCellAttr(cell, 'ht')) {
    final value = num.tryParse('${normalizedCellAttr(cell, 'ht')}') ?? 1;
    if (value == 0) {
      style['textAlign'] = 'center';
    } else if (value == 2) {
      style['textAlign'] = 'right';
    }
  }
  if (_apiHasRawCellAttr(cell, 'vt')) {
    final value = num.tryParse('${normalizedCellAttr(cell, 'vt')}') ?? 0;
    if (value == 0) {
      style['alignItems'] = 'center';
    } else if (value == 2) {
      style['alignItems'] = 'flex-end';
    }
  }
  if (cell.inlineRuns == null) {
    style.addAll(
      getFontStyleByCell(cell, checksAF: checksAF, checksCF: checksCF),
    );
  }
  return style;
}

bool _apiHasRawCellAttr(FortuneCell cell, String attr) {
  return switch (attr) {
    'bg' => cell.background != null || cell.hasRawBackground,
    'ht' => cell.horizontalAlign != null || cell.hasRawHorizontalAlign,
    'vt' => cell.verticalAlign != null || cell.hasRawVerticalAlign,
    _ => _apiRawCellAttr(cell, attr) != null,
  };
}

String getInlineStringHTML(FortuneCell? cell) {
  final runs = cell?.inlineRuns;
  if (runs == null || runs.isEmpty) {
    return '';
  }
  final buffer = StringBuffer();
  for (var index = 0; index < runs.length; index += 1) {
    final run = runs[index];
    if (run.text.isEmpty) {
      continue;
    }
    final style = getFontStyleByCell(
      _apiCellFromInlineRun(run),
      isCheck: false,
    );
    final styleText = style.entries
        .map((entry) => '${_apiKebabCase(entry.key)}:${entry.value};')
        .join();
    buffer.write(
      "<span class=\"luckysheet-input-span\" index='$index' style='$styleText'>${run.text}</span>",
    );
  }
  return buffer.toString();
}

bool isInlineStringCell(Object? cell) {
  if (cell is FortuneCell) {
    return cell.inlineRuns != null && cell.inlineRuns!.isNotEmpty;
  }
  if (cell is Map) {
    return isInlineStringCT(cell['ct']);
  }
  return false;
}

bool isInlineStringCT(Object? cellType) {
  if (cellType is FortuneCellType) {
    final style = cellType.style;
    return cellType.type == 'inlineStr' && style is List && style.isNotEmpty;
  }
  if (cellType is Map) {
    final styles = cellType['s'];
    return cellType['t'] == 'inlineStr' && styles is List && styles.isNotEmpty;
  }
  return false;
}

String getInlineStringNoStyle(int row, int column, FortuneSheet sheet) {
  final cell = sheet.cells[FortuneCellCoord(row, column)];
  if (cell == null) {
    return '';
  }
  final runs = cell.inlineRuns;
  if (runs != null && runs.isNotEmpty) {
    return runs
        .where((run) => run.text.isNotEmpty)
        .map((run) => run.text)
        .join();
  }
  final cellType = cell.cellType;
  if (isInlineStringCT(cellType)) {
    return _apiInlineStringValueFromStyles(cellType!.style);
  }
  return '';
}

FortuneCell updateInlineStringFormatOutside(
  FortuneCell cell,
  String key,
  Object? value,
) {
  final runs = cell.inlineRuns;
  if (runs == null || runs.isEmpty) {
    return cell.copyWith();
  }
  return cell.copyWith(
    inlineRuns: [
      for (final run in runs) _apiInlineRunWithAttr(run, key, value),
    ],
  );
}

FortuneCell updateInlineStringFormat(
  FortuneCell cell,
  String key,
  Object? value, {
  required int startOffset,
  required int endOffset,
}) {
  final runs = cell.inlineRuns;
  if (runs == null || runs.isEmpty || startOffset >= endOffset) {
    return cell.copyWith();
  }
  final nextRuns = <FortuneInlineTextRun>[];
  var cursor = 0;
  for (final run in runs) {
    final text = run.text;
    final runStart = cursor;
    final runEnd = cursor + text.length;
    cursor = runEnd;
    if (text.isEmpty || endOffset <= runStart || startOffset >= runEnd) {
      nextRuns.add(run);
      continue;
    }
    final localStart = math.max(0, startOffset - runStart);
    final localEnd = math.min(text.length, endOffset - runStart);
    if (localStart > 0) {
      nextRuns.add(_apiInlineRunWithText(run, text.substring(0, localStart)));
    }
    if (localEnd > localStart) {
      nextRuns.add(
        _apiInlineRunWithAttr(
          _apiInlineRunWithText(run, text.substring(localStart, localEnd)),
          key,
          value,
        ),
      );
    }
    if (localEnd < text.length) {
      nextRuns.add(_apiInlineRunWithText(run, text.substring(localEnd)));
    }
  }
  return cell.copyWith(inlineRuns: nextRuns);
}

FortuneInlineTextRun _apiInlineRunWithText(
  FortuneInlineTextRun run,
  String text,
) {
  return run.copyWith(text: text, rawText: text, hasRawText: true);
}

FortuneInlineTextRun _apiInlineRunWithAttr(
  FortuneInlineTextRun run,
  String key,
  Object? value,
) {
  return switch (key) {
    'v' => run.copyWith(
      text: value,
      rawText: cloneFortuneMetadata(value),
      hasRawText: true,
    ),
    'fc' => run.copyWith(
      foreground: value,
      rawForeground: cloneFortuneMetadata(value),
      hasRawForeground: true,
    ),
    'bl' => run.copyWith(
      bold: _nullableBoolArg(value),
      rawBold: cloneFortuneMetadata(value),
      hasRawBold: true,
    ),
    'it' => run.copyWith(
      italic: _nullableBoolArg(value),
      rawItalic: cloneFortuneMetadata(value),
      hasRawItalic: true,
    ),
    'cl' => run.copyWith(
      strikeThrough: _nullableBoolArg(value),
      rawStrikeThrough: cloneFortuneMetadata(value),
      hasRawStrikeThrough: true,
    ),
    'un' => run.copyWith(
      underline: _nullableBoolArg(value),
      rawUnderline: cloneFortuneMetadata(value),
      hasRawUnderline: true,
    ),
    'fs' => run.copyWith(
      fontSize: value,
      rawFontSize: cloneFortuneMetadata(value),
      hasRawFontSize: true,
    ),
    'ff' => run.copyWith(
      fontFamily: value,
      rawFontFamily: cloneFortuneMetadata(value),
      hasRawFontFamily: true,
    ),
    'bg' => run.copyWith(
      extraFields: value == null
          ? (Map<String, Object?>.from(run.extraFields)..remove('bg'))
          : {...run.extraFields, 'bg': cloneFortuneMetadata(value)},
    ),
    _ => run.copyWith(
      extraFields: {...run.extraFields, key: cloneFortuneMetadata(value)},
    ),
  };
}

String _apiInlineStringValueFromStyles(Object? styles) {
  if (styles is! List) {
    return '';
  }
  final buffer = StringBuffer();
  for (final style in styles) {
    if (style is Map) {
      final value = style['v'];
      if (_apiIsTruthy(value)) {
        buffer.write(value);
      }
    }
  }
  return buffer.toString();
}

Map<String, Object?> convertCssToStyleList(
  String cssText,
  FortuneCell originCell,
) {
  if (cssText.isEmpty) {
    return const <String, Object?>{};
  }
  final styleList = <String, Object?>{
    'fc': _apiRawCellAttr(originCell, 'fc') ?? '#000000',
    'fs': _apiParseFloat('${_apiRawCellAttr(originCell, 'fs') ?? 10}') ?? 10,
    'cl': _apiCellFlagNumber(originCell, 'cl'),
    'un': _apiCellFlagNumber(originCell, 'un'),
    'bl': _apiCellFlagNumber(originCell, 'bl'),
    'it': _apiCellFlagNumber(originCell, 'it'),
    'ff': _apiRawCellAttr(originCell, 'ff') ?? 0,
  };
  for (final rawStyle in cssText.split(';')) {
    final style = rawStyle.toLowerCase();
    final separator = style.indexOf(':');
    if (separator < 0) {
      continue;
    }
    final key = style.substring(0, separator).trim();
    final value = style.substring(separator + 1).trim();
    if (key == 'font-weight' && value == 'bold') {
      styleList['bl'] = 1;
    }
    if (key == 'font-style' && value == 'italic') {
      styleList['it'] = 1;
    }
    if (key == 'font-size') {
      final parsed = _apiParseFloat(value);
      if (parsed != null) {
        styleList['fs'] = parsed.toInt();
      }
    }
    if (key == 'color') {
      styleList['fc'] = value;
    }
    if (key == 'text-decoration') {
      styleList['cl'] = 1;
    }
    if (key == 'border-bottom') {
      styleList['un'] = 1;
    }
    if (key == 'lucky-strike') {
      styleList['cl'] = _apiJsNumber(value);
    }
    if (key == 'lucky-underline') {
      styleList['un'] = _apiJsNumber(value);
    }
  }
  return styleList;
}

List<Map<String, Object?>> convertSpanToShareString(
  Iterable<Map<String, Object?>> spans,
  FortuneCell originCell,
) {
  final styles = <Map<String, Object?>>[];
  String? previousStyle;
  for (var index = 0; index < spans.length; index += 1) {
    final span = spans.elementAt(index);
    final cssText = '${span['style'] ?? span['cssText'] ?? ''}';
    final styleList = Map<String, Object?>.from(
      convertCssToStyleList(cssText, originCell),
    );
    final currentStyle = _apiInlineStyleSignature(styleList);
    var value = '${span['text'] ?? span['innerText'] ?? span['v'] ?? ''}'
        .replaceAll('\n', '\r\n');
    if (index == spans.length - 1 &&
        value.endsWith('\r\n') &&
        !value.endsWith('\r\n\r\n')) {
      value = value.substring(0, value.length - 2);
    }
    if (currentStyle == previousStyle && styles.isNotEmpty) {
      styles.last['v'] = '${styles.last['v'] ?? ''}$value';
    } else {
      styleList['v'] = value;
      styles.add(styleList);
      previousStyle = currentStyle;
    }
  }
  return styles;
}

String _apiInlineStyleSignature(Map<String, Object?> style) {
  final keys = style.keys.toList()..sort();
  return [for (final key in keys) '$key:${style[key]}'].join(';');
}

num _apiCellFlagNumber(FortuneCell cell, String attr) {
  final value = _apiRawCellAttr(cell, attr);
  if (value == true) {
    return 1;
  }
  if (value == false || value == null) {
    return 0;
  }
  if (value is num) {
    return value;
  }
  final parsed = num.tryParse('$value');
  return parsed ?? 0;
}

num _apiJsNumber(String value) {
  final parsed = num.tryParse(value.trim());
  if (parsed == null) {
    return double.nan;
  }
  return parsed;
}

FortuneCell _apiCellFromInlineRun(FortuneInlineTextRun run) {
  return FortuneCell(
    value: run.text,
    foreground: run.foreground ?? const Color(0xff000000),
    rawForeground: run.rawForeground,
    hasRawForeground: run.hasRawForeground,
    bold: run.bold ?? false,
    rawBold: run.rawBold,
    hasRawBold: run.hasRawBold,
    italic: run.italic ?? false,
    rawItalic: run.rawItalic,
    hasRawItalic: run.hasRawItalic,
    strikeThrough: run.strikeThrough ?? false,
    rawStrikeThrough: run.rawStrikeThrough,
    hasRawStrikeThrough: run.hasRawStrikeThrough,
    underline: run.underline ?? false,
    rawUnderline: run.rawUnderline,
    hasRawUnderline: run.hasRawUnderline,
    fontSize: run.fontSize,
    rawFontSize: run.rawFontSize,
    hasRawFontSize: run.hasRawFontSize,
    fontFamily: run.fontFamily,
    rawFontFamily: run.rawFontFamily,
    hasRawFontFamily: run.hasRawFontFamily,
    extraFields: run.extraFields,
  );
}

String _apiKebabCase(String value) {
  return value.replaceAllMapped(
    RegExp(r'([a-z0-9])([A-Z])'),
    (match) => '${match.group(1)}-${match.group(2)!.toLowerCase()}',
  );
}

List<List<FortuneCell?>> getDataBySelectionNoCopy(
  FortuneSheet sheet,
  FortuneRange? range,
) {
  final normalized = range == null ? null : _normalizedApiRange(range);
  if (normalized == null) {
    return const [];
  }
  final data = <List<FortuneCell?>>[];
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    if (sheet.hiddenRows.contains(row)) {
      continue;
    }
    final rowData = <FortuneCell?>[];
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      if (sheet.hiddenColumns.contains(column)) {
        continue;
      }
      rowData.add(sheet.cells[FortuneCellCoord(row, column)]);
    }
    data.add(rowData);
  }
  return data;
}

List<List<FortuneCell?>> getdatabyselection(
  FortuneSheet sheet,
  FortuneRange? range,
) {
  final effectiveRange = range ?? sheet.getSelection().firstOrNull;
  final normalized = effectiveRange == null
      ? null
      : _normalizedApiRange(effectiveRange);
  if (normalized == null) {
    return const [];
  }
  final data = <List<FortuneCell?>>[];
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    if (sheet.hiddenRows.contains(row)) {
      continue;
    }
    if (!sheet.cells.keys.any((coord) => coord.row == row)) {
      continue;
    }
    final rowData = <FortuneCell?>[];
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      if (sheet.hiddenColumns.contains(column)) {
        continue;
      }
      rowData.add(sheet.cells[FortuneCellCoord(row, column)]);
    }
    data.add(rowData);
  }
  return data;
}

Map<String, Object> calcSelectionInfo(
  FortuneSheet sheet, {
  Iterable<FortuneRange>? selection,
  String? lang,
}) {
  final ranges = (selection ?? sheet.getSelection()).toList();
  var numberC = 0;
  var count = 0;
  var sum = 0.0;
  var max = double.negativeInfinity;
  var min = double.infinity;
  for (final range in ranges) {
    final data = getDataBySelectionNoCopy(sheet, range);
    if (data.isEmpty) {
      continue;
    }
    final columnCount = data.first.length;
    for (var row = 0; row < data.length; row += 1) {
      for (var column = 0; column < columnCount; column += 1) {
        if (row >= data.length || column >= data[row].length) {
          break;
        }
        final cell = data[row][column];
        final value = _apiSelectionDisplayValue(cell);
        final cellType = cell?.cellType?.type;
        final numericValue = value == null ? null : _apiParseFloat(value);
        if (cellType == 'n' || (cellType == 'g' && numericValue != null)) {
          final valueNumber = numericValue ?? double.nan;
          count += 1;
          sum += valueNumber;
          max = math.max(valueNumber, max);
          min = math.min(valueNumber, min);
          numberC += 1;
        } else if (value != null) {
          count += 1;
        }
      }
    }
  }
  return <String, Object>{
    'numberC': numberC,
    'count': count,
    'sum': _apiSelectionInfoNumber(sum, lang),
    'max': _apiSelectionInfoNumber(max, lang),
    'min': _apiSelectionInfoNumber(min, lang),
    'average': _apiSelectionInfoNumber(sum / numberC, lang),
  };
}

String? _apiSelectionDisplayValue(FortuneCell? cell) {
  if (cell == null) {
    return null;
  }
  final display = _apiRawCellAttr(cell, 'm') ?? _apiRawCellAttr(cell, 'v');
  return display?.toString();
}

String _apiSelectionInfoNumber(num value, String? lang) {
  if (value.isNaN) {
    return 'NaN';
  }
  if (value == double.infinity) {
    return 'Infinity';
  }
  if (value == double.negativeInfinity) {
    return '-Infinity';
  }
  final format = lang != null && lang != 'zh' && lang != 'zh_tw'
      ? '0.00'
      : 'w0.00';
  return update(format, value);
}

FortuneCell? getOrigincell(FortuneSheet? sheet, int? row, int? column) {
  if (sheet == null || row == null || column == null) {
    return null;
  }
  return sheet.cells[FortuneCellCoord(row, column)];
}

String? getcellFormula(
  FortuneSheet? sheet,
  int? row,
  int? column, {
  Map<FortuneCellCoord, FortuneCell>? data,
}) {
  final cell = data == null
      ? getOrigincell(sheet, row, column)
      : row == null || column == null
      ? null
      : data[FortuneCellCoord(row, column)];
  return cell?.formula;
}

List<FortuneRange> getRange(FortuneSheet? sheet) {
  if (sheet == null) {
    return const [];
  }
  return [for (final range in sheet.getSelection()) range.copyWith()];
}

List<FortuneRange> getSelectRange(
  FortuneSheet? sheet, {
  Iterable<FortuneRange>? selection,
}) {
  if (sheet == null) {
    return const [];
  }
  final ranges = (selection ?? sheet.getSelection()).toList();
  if (ranges.isEmpty ||
      (ranges.length == 1 &&
          ranges.first.rowStart == ranges.first.rowEnd &&
          ranges.first.columnStart == ranges.first.columnEnd)) {
    return [
      FortuneRange(
        rowStart: 0,
        rowEnd: _apiSelectionRowEnd(sheet),
        columnStart: 0,
        columnEnd: _apiSelectionColumnEnd(sheet),
      ),
    ];
  }
  return [for (final range in ranges) range.copyWith()];
}

List<FortuneCellCoord> getFlattenedRange(
  FortuneSheet sheet, {
  Iterable<FortuneRange>? ranges,
}) {
  final sourceRanges = ranges ?? getRange(sheet);
  final result = <FortuneCellCoord>[];
  for (final range in sourceRanges) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      for (
        var column = normalized.columnStart;
        column <= normalized.columnEnd;
        column += 1
      ) {
        result.add(FortuneCellCoord(row, column));
      }
    }
  }
  return result;
}

bool isAllSelectedCellsInStatus(
  FortuneSheet sheet,
  String attr,
  Object? status, {
  Iterable<FortuneRange>? ranges,
}) {
  final cells = getFlattenedRange(sheet, ranges: ranges);
  for (final coord in cells) {
    if (!sheet.cells.containsKey(coord)) {
      return false;
    }
    if (normalizedAttr(sheet, coord.row, coord.column, attr) != status) {
      return false;
    }
  }
  return true;
}

List<FortuneRange> cfSplitRange(
  FortuneRange range1,
  FortuneRange range2,
  FortuneRange range3,
  String type,
) {
  final intersectRowStart = math.max(range1.rowStart, range2.rowStart);
  final intersectRowEnd = math.min(range1.rowEnd, range2.rowEnd);
  final intersectColumnStart = math.max(range1.columnStart, range2.columnStart);
  final intersectColumnEnd = math.min(range1.columnEnd, range2.columnEnd);
  final hasIntersection =
      intersectRowStart <= intersectRowEnd &&
      intersectColumnStart <= intersectColumnEnd;

  if (!hasIntersection) {
    return switch (type) {
      'allPart' || 'restPart' => [range1.copyWith()],
      'operatePart' => const [],
      _ => const [],
    };
  }

  final restRanges = <FortuneRange>[];
  void addRange(int rowStart, int rowEnd, int columnStart, int columnEnd) {
    if (rowStart <= rowEnd && columnStart <= columnEnd) {
      restRanges.add(
        FortuneRange(
          rowStart: rowStart,
          rowEnd: rowEnd,
          columnStart: columnStart,
          columnEnd: columnEnd,
        ),
      );
    }
  }

  addRange(
    range1.rowStart,
    intersectRowStart - 1,
    range1.columnStart,
    range1.columnEnd,
  );
  addRange(
    intersectRowStart,
    intersectRowEnd,
    range1.columnStart,
    intersectColumnStart - 1,
  );
  addRange(
    intersectRowStart,
    intersectRowEnd,
    intersectColumnEnd + 1,
    range1.columnEnd,
  );
  addRange(
    intersectRowEnd + 1,
    range1.rowEnd,
    range1.columnStart,
    range1.columnEnd,
  );

  final rowOffset = range3.rowStart - range2.rowStart;
  final columnOffset = range3.columnStart - range2.columnStart;
  final operatedRange = FortuneRange(
    rowStart: intersectRowStart + rowOffset,
    rowEnd: intersectRowEnd + rowOffset,
    columnStart: intersectColumnStart + columnOffset,
    columnEnd: intersectColumnEnd + columnOffset,
  );

  return switch (type) {
    'allPart' => [...restRanges, operatedRange],
    'restPart' => restRanges,
    'operatePart' => [operatedRange],
    _ => const [],
  };
}

// ignore: non_constant_identifier_names
List<FortuneRange> CFSplitRange(
  FortuneRange range1,
  FortuneRange range2,
  FortuneRange range3,
  String type,
) => cfSplitRange(range1, range2, range3, type);

List<List<String>> getNullData(int rowLength, int columnLength) {
  final data = <List<String>>[];
  for (var row = 0; row < rowLength; row += 1) {
    final rowData = <String>[];
    for (var column = 0; column < columnLength; column += 1) {
      rowData.add('');
    }
    data.add(rowData);
  }
  return data;
}

String getRegStr(String regStr, Iterable<Object?> splitSymbols) {
  var result = '';
  var mark = 0;
  for (final split in splitSymbols) {
    final symbol = _apiSplitSymbol(split);
    if (symbol == null || !symbol.checked) {
      continue;
    }
    final id = symbol.id;
    if (id == 'Tab') {
      result += r'\t';
      mark += 1;
    } else if (id == 'semicolon') {
      if (mark > 0) {
        result += '|';
      }
      result += ';';
      mark = 1;
    } else if (id == 'comma') {
      if (mark > 0) {
        result += '|';
      }
      result += ',';
      mark += 1;
    } else if (id == 'space') {
      if (mark > 0) {
        result += '|';
      }
      result += r'\s';
      mark += 1;
    } else if (id == 'splitsimple') {
      result = '[$result]+';
    } else if (id == 'other') {
      final text = symbol.value;
      if (text.isNotEmpty) {
        if (mark > 0) {
          result += '|';
        }
        result += text;
      }
    }
  }
  return result;
}

List<List<String>> getDataArr(
  String regStr,
  FortuneSheet sheet,
  FortuneRange range, {
  int? column,
}) {
  final normalized = _normalizedApiRange(range);
  if (normalized == null) {
    return const [];
  }
  final splitColumn = column ?? normalized.columnStart;
  final dataArr = <List<String>>[];
  if (regStr.isNotEmpty) {
    final regExp = RegExp(regStr);
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      final value = _apiSplitColumnCellValue(sheet, row, splitColumn);
      dataArr.add(value.toString().split(regExp));
    }
    final rowLength = dataArr.length;
    final columnLength = dataArr.fold<int>(
      0,
      (max, row) => math.max(max, row.length),
    );
    final result = getNullData(rowLength, columnLength);
    for (var row = 0; row < result.length; row += 1) {
      for (var col = 0; col < result[row].length; col += 1) {
        if (col < dataArr[row].length) {
          result[row][col] = dataArr[row][col];
        }
      }
    }
    return result;
  }
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    final value = _apiSplitColumnCellValue(sheet, row, splitColumn);
    dataArr.add([value.toString()]);
  }
  return dataArr;
}

Object _apiSplitColumnCellValue(FortuneSheet sheet, int row, int column) {
  final cell = sheet.cells[FortuneCellCoord(row, column)];
  if (cell == null) {
    return '';
  }
  final display = cell.hasRawDisplayValue
      ? cell.rawDisplayValue
      : cell.displayValue;
  return display ?? sheet.getCellValue(row, column) ?? '';
}

({bool checked, String id, String value})? _apiSplitSymbol(Object? split) {
  if (split is String) {
    return (checked: true, id: split, value: '');
  }
  if (split is! Map) {
    return null;
  }
  final id = split['id'] ?? split['key'];
  if (id == null) {
    return null;
  }
  return (
    checked: _apiTruthy(split['checked']),
    id: id.toString(),
    value: (split['value'] ?? split['text'] ?? '').toString(),
  );
}

bool _apiTruthy(Object? value) {
  if (value is bool) {
    return value;
  }
  if (value is num) {
    return value != 0;
  }
  if (value is String) {
    return value.toLowerCase() == 'true' || value == '1';
  }
  return false;
}

const Map<String, int> _apiChnNumChar = {
  '零': 0,
  '一': 1,
  '二': 2,
  '三': 3,
  '四': 4,
  '五': 5,
  '六': 6,
  '七': 7,
  '八': 8,
  '九': 9,
};

const Map<String, int> _apiChnNameValue = {
  '十': 10,
  '百': 100,
  '千': 1000,
  '万': 10000,
  '亿': 100000000,
};

bool isChnNumber(Object? text) {
  final value = text is num ? '$text' : text?.toString();
  if (value == null) {
    return false;
  }
  if (value.length == 1) {
    return value == '日' || _apiChnNumChar.containsKey(value);
  }
  for (final char in value.split('')) {
    if (!_apiChnNumChar.containsKey(char) &&
        !_apiChnNameValue.containsKey(char)) {
      return false;
    }
  }
  return true;
}

List<Object?> isExtendNumber(Object? text) {
  final value = text is num ? '$text' : text?.toString();
  if (value == null) {
    return const [false];
  }
  final matches = RegExp(r'0|([1-9]+[0-9]*)').allMatches(value).toList();
  if (matches.isEmpty) {
    return const [false];
  }
  final match = matches.last;
  final matchText = match.group(0)!;
  return [
    true,
    num.parse(matchText),
    value.substring(0, match.start),
    value.substring(match.end),
  ];
}

bool hasChinaword(String value) {
  return RegExp(
    r'[\u4E00-\u9FA5]|[\uFE30-\uFFA0]',
    caseSensitive: false,
  ).hasMatch(value);
}

bool isFormula(Object? value) {
  return value is String && value.startsWith('=') && value.length > 1;
}

bool checkBracketNum(String formula) {
  final leftCount = '('.allMatches(formula).length;
  final rightCount = ')'.allMatches(formula).length;
  var quotedLeftCount = 0;
  var quotedRightCount = 0;
  final quotedTextPattern = RegExp(r'''(['"])(?:(?!\1).)*?\1''');
  for (final match in quotedTextPattern.allMatches(formula)) {
    final text = match.group(0)!;
    quotedLeftCount += '('.allMatches(text).length;
    quotedRightCount += ')'.allMatches(text).length;
  }
  return leftCount - quotedLeftCount == rightCount - quotedRightCount;
}

List<bool> isfreezonFuc(String text) {
  final row = text.replaceAll(RegExp(r'[^0-9]'), '');
  final column = text.replaceAll(RegExp(r'[^A-Za-z]'), '');
  final rowMarker = _apiCharBeforeFirst(text, row);
  final columnMarker = _apiCharBeforeFirst(text, column);
  return [rowMarker == r'$', columnMarker == r'$'];
}

String functionCopy(String text, [String mode = 'down', int step = 1]) {
  final formulaText = text.startsWith('=') ? text.substring(1) : text;
  final buffer = StringBuffer();
  final chars = formulaText.split('');
  var current = '';
  var doubleQuoteDepth = 0;
  for (var index = 0; index < chars.length; index += 1) {
    final char = chars[index];
    if (char == '(' && doubleQuoteDepth == 0) {
      if (current.isNotEmpty) {
        buffer.write('$current(');
      } else {
        buffer.write('(');
      }
      current = '';
    } else if (char == ')' && doubleQuoteDepth == 0) {
      buffer
        ..write(functionCopy(current, mode, step))
        ..write(')');
      current = '';
    } else if (char == '"') {
      if (doubleQuoteDepth > 0) {
        buffer.write('$current"');
        doubleQuoteDepth -= 1;
        current = '';
      } else {
        doubleQuoteDepth += 1;
        current += char;
      }
    } else if (char == ',' && doubleQuoteDepth == 0) {
      buffer
        ..write(functionCopy(current, mode, step))
        ..write(',');
      current = '';
    } else if (char == '&' && doubleQuoteDepth == 0) {
      if (current.isNotEmpty) {
        buffer
          ..write(functionCopy(current, mode, step))
          ..write('&');
        current = '';
      } else {
        buffer.write('&');
      }
    } else if (_apiFormulaHtmlOperators.contains(char) &&
        doubleQuoteDepth == 0) {
      final next = index + 1 < chars.length ? chars[index + 1] : '';
      final previous = _apiFormulaHtmlPreviousNonSpace(formulaText, index - 1);
      final twoCharOperator = '$char$next';
      if (_apiFormulaHtmlOperators.contains(twoCharOperator)) {
        if (current.isNotEmpty) {
          buffer.write(functionCopy(current, mode, step));
          current = '';
        }
        buffer.write(twoCharOperator);
        index += 1;
      } else if (char == '-' &&
          RegExp(r'^[0-9]$').hasMatch(next) &&
          (previous == null ||
              previous == '(' ||
              previous == ',' ||
              previous == ' ' ||
              _apiFormulaHtmlOperators.contains(previous))) {
        current += char;
      } else {
        if (current.isNotEmpty) {
          buffer
            ..write(functionCopy(current, mode, step))
            ..write(char);
          current = '';
        } else {
          buffer.write(char);
        }
      }
    } else {
      current += char;
    }

    if (index == chars.length - 1) {
      final trimmed = current.trim();
      if (iscelldata(trimmed)) {
        buffer.write(_apiFunctionCopyUpdateParam(mode, trimmed, step));
      } else {
        buffer.write(trimmed);
      }
    }
  }
  return buffer.toString();
}

String _apiFunctionCopyUpdateParam(String mode, String text, int step) {
  final parts = text.split('!');
  final rangeText = parts.length > 1 ? parts[1] : parts[0];
  final prefix = parts.length > 1 ? '${parts[0]}!' : '';
  if (!rangeText.contains(':')) {
    var row = _apiFunctionCopyParseInt(
      rangeText.replaceAll(RegExp(r'[^0-9]'), ''),
    );
    var column = columnCharToIndex(
      rangeText.replaceAll(RegExp(r'[^A-Za-z]'), ''),
    );
    final frozen = isfreezonFuc(rangeText);
    if (mode == 'up' && !frozen[0]) {
      row = row == null ? null : row - step;
    } else if (mode == 'right' && !frozen[1]) {
      column = column == null ? null : column + step;
    } else if (mode == 'left' && !frozen[1]) {
      column = column == null ? null : column - step;
    } else if (mode == 'down' && !frozen[0]) {
      row = row == null ? null : row + step;
    }
    final rowMarker = frozen[0] ? r'$' : '';
    final columnMarker = frozen[1] ? r'$' : '';
    if (row != null && column != null) {
      return '$prefix$columnMarker${indexToColumnChar(column)}$rowMarker$row';
    }
    if (row != null) {
      return '$prefix$rowMarker$row';
    }
    if (column != null) {
      return '$prefix$columnMarker${indexToColumnChar(column)}';
    }
    return text;
  }

  final rangeParts = rangeText.split(':');
  if (rangeParts.length != 2) {
    return text;
  }
  var startRow = _apiFunctionCopyParseInt(
    rangeParts[0].replaceAll(RegExp(r'[^0-9]'), ''),
  );
  var endRow = _apiFunctionCopyParseInt(
    rangeParts[1].replaceAll(RegExp(r'[^0-9]'), ''),
  );
  if (startRow != null && endRow != null && startRow > endRow) {
    return text;
  }
  var startColumn = columnCharToIndex(
    rangeParts[0].replaceAll(RegExp(r'[^A-Za-z]'), ''),
  );
  var endColumn = columnCharToIndex(
    rangeParts[1].replaceAll(RegExp(r'[^A-Za-z]'), ''),
  );
  if (startColumn != null && endColumn != null && startColumn > endColumn) {
    return text;
  }

  final startFrozen = isfreezonFuc(rangeParts[0]);
  final endFrozen = isfreezonFuc(rangeParts[1]);
  if (mode == 'up') {
    if (!startFrozen[0]) startRow = startRow == null ? null : startRow - step;
    if (!endFrozen[0]) endRow = endRow == null ? null : endRow - step;
  } else if (mode == 'right') {
    if (!startFrozen[1]) {
      startColumn = startColumn == null ? null : startColumn + step;
    }
    if (!endFrozen[1]) endColumn = endColumn == null ? null : endColumn + step;
  } else if (mode == 'left') {
    if (!startFrozen[1]) {
      startColumn = startColumn == null ? null : startColumn - step;
    }
    if (!endFrozen[1]) endColumn = endColumn == null ? null : endColumn - step;
  } else if (mode == 'down') {
    if (!startFrozen[0]) startRow = startRow == null ? null : startRow + step;
    if (!endFrozen[0]) endRow = endRow == null ? null : endRow + step;
  }

  if ((startRow != null && startRow < 0) ||
      (startColumn != null && startColumn < 0)) {
    return error['r']!;
  }
  final startRowMarker = startFrozen[0] ? r'$' : '';
  final startColumnMarker = startFrozen[1] ? r'$' : '';
  final endRowMarker = endFrozen[0] ? r'$' : '';
  final endColumnMarker = endFrozen[1] ? r'$' : '';
  if (startColumn == null && endColumn == null) {
    return '$prefix$startRowMarker$startRow:$endRowMarker$endRow';
  }
  if (startRow == null && endRow == null) {
    return '$prefix$startColumnMarker${indexToColumnChar(startColumn!)}:'
        '$endColumnMarker${indexToColumnChar(endColumn!)}';
  }
  return '$prefix$startColumnMarker${indexToColumnChar(startColumn!)}'
      '$startRowMarker$startRow:'
      '$endColumnMarker${indexToColumnChar(endColumn!)}$endRowMarker$endRow';
}

int? _apiFunctionCopyParseInt(String value) {
  if (value.isEmpty) {
    return null;
  }
  return int.tryParse(value);
}

String _apiCharBeforeFirst(String text, String search) {
  final index = text.indexOf(search);
  if (index > 0) {
    return text[index - 1];
  }
  if (index == 0 && text.isNotEmpty) {
    return text[text.length - 1];
  }
  return '';
}

String functionHTMLGenerate(String text, {List<int> rangeIndexes = const []}) {
  if (text.isEmpty || !text.startsWith('=')) {
    return text;
  }
  final state = _FormulaHtmlState();
  return '<span dir="auto" class="luckysheet-formula-text-color">=</span>'
      '${_apiFunctionHTML(text, rangeIndexes, state)}';
}

class _FormulaHtmlState {
  int index = 0;
}

String _apiFunctionHTML(
  String text,
  List<int> rangeIndexes,
  _FormulaHtmlState state,
) {
  var formulaText = text.startsWith('=') ? text.substring(1) : text;
  final buffer = StringBuffer();
  final matchConfig = <String, int>{
    'bracket': 0,
    'squote': 0,
    'dquote': 0,
    'braces': 0,
  };
  var i = 0;
  var current = '';
  while (i < formulaText.length) {
    final char = formulaText[i];
    if (char == '(' &&
        matchConfig['squote'] == 0 &&
        matchConfig['dquote'] == 0 &&
        matchConfig['braces'] == 0) {
      matchConfig['bracket'] = matchConfig['bracket']! + 1;
      if (current.isNotEmpty) {
        buffer.write(
          '<span dir="auto" class="luckysheet-formula-text-func">$current</span>'
          '<span dir="auto" class="luckysheet-formula-text-lpar">(</span>',
        );
      } else {
        buffer.write(
          '<span dir="auto" class="luckysheet-formula-text-lpar">(</span>',
        );
      }
      current = '';
    } else if (char == ')' &&
        matchConfig['squote'] == 0 &&
        matchConfig['dquote'] == 0 &&
        matchConfig['braces'] == 0) {
      matchConfig['bracket'] = matchConfig['bracket']! - 1;
      buffer
        ..write(_apiFunctionHTML(current, rangeIndexes, state))
        ..write(
          '<span dir="auto" class="luckysheet-formula-text-rpar">)</span>',
        );
      current = '';
    } else if (char == '{' &&
        matchConfig['squote'] == 0 &&
        matchConfig['dquote'] == 0) {
      current += char;
      matchConfig['braces'] = matchConfig['braces']! + 1;
    } else if (char == '}' &&
        matchConfig['squote'] == 0 &&
        matchConfig['dquote'] == 0) {
      current += char;
      matchConfig['braces'] = matchConfig['braces']! - 1;
    } else if (char == '"' && matchConfig['squote'] == 0) {
      if (matchConfig['dquote']! > 0) {
        buffer.write(current.isNotEmpty ? '$current"</span>' : '"</span>');
        matchConfig['dquote'] = matchConfig['dquote']! - 1;
        current = '';
      } else {
        matchConfig['dquote'] = matchConfig['dquote']! + 1;
        if (current.isNotEmpty) {
          buffer
            ..write(_apiFunctionHTML(current, rangeIndexes, state))
            ..write(
              '<span dir="auto" class="luckysheet-formula-text-string">"',
            );
        } else {
          buffer.write(
            '<span dir="auto" class="luckysheet-formula-text-string">"',
          );
        }
        current = '';
      }
    } else if (char == "'" && matchConfig['dquote'] == 0) {
      current += char;
      matchConfig['squote'] = matchConfig['squote'] == 0 ? 1 : 0;
    } else if (char == ',' &&
        matchConfig['squote'] == 0 &&
        matchConfig['dquote'] == 0 &&
        matchConfig['braces'] == 0) {
      buffer
        ..write(_apiFunctionHTML(current, rangeIndexes, state))
        ..write(
          '<span dir="auto" class="luckysheet-formula-text-comma">,</span>',
        );
      current = '';
    } else if (char == '&' &&
        matchConfig['squote'] == 0 &&
        matchConfig['dquote'] == 0 &&
        matchConfig['braces'] == 0) {
      if (current.isNotEmpty) {
        buffer
          ..write(_apiFunctionHTML(current, rangeIndexes, state))
          ..write(
            '<span dir="auto" class="luckysheet-formula-text-calc">&</span>',
          );
        current = '';
      } else {
        buffer.write(
          '<span dir="auto" class="luckysheet-formula-text-calc">&</span>',
        );
      }
    } else if (_apiFormulaHtmlOperators.contains(char) &&
        matchConfig['squote'] == 0 &&
        matchConfig['dquote'] == 0 &&
        matchConfig['braces'] == 0) {
      final next = i + 1 < formulaText.length ? formulaText[i + 1] : '';
      final previous = _apiFormulaHtmlPreviousNonSpace(formulaText, i - 1);
      final twoCharOperator = '$char$next';
      if (_apiFormulaHtmlOperators.contains(twoCharOperator)) {
        if (current.isNotEmpty) {
          buffer.write(_apiFunctionHTML(current, rangeIndexes, state));
          current = '';
        }
        buffer.write(
          '<span dir="auto" class="luckysheet-formula-text-calc">$twoCharOperator</span>',
        );
        i += 1;
      } else if (char == '-' &&
          RegExp(r'^[0-9]$').hasMatch(next) &&
          (previous == null ||
              previous == '(' ||
              previous == ',' ||
              previous == ' ' ||
              _apiFormulaHtmlOperators.contains(previous))) {
        current += char;
      } else {
        if (current.isNotEmpty) {
          buffer.write(_apiFunctionHTML(current, rangeIndexes, state));
          current = '';
        }
        buffer.write(
          '<span dir="auto" class="luckysheet-formula-text-calc">$char</span>',
        );
      }
    } else {
      current += char;
    }

    if (i == formulaText.length - 1) {
      buffer.write(_apiFunctionHtmlTail(current, rangeIndexes, state));
    }
    i += 1;
  }
  return buffer.toString();
}

const Set<String> _apiFormulaHtmlOperators = {
  '==',
  '!=',
  '<>',
  '<=',
  '>=',
  '=',
  '+',
  '-',
  '>',
  '<',
  '/',
  '*',
  '%',
  '&',
  '^',
};

final Map<Object?, Object?> _apiMeasureTextCache = <Object?, Object?>{};

Map<Object?, Object?> clearMeasureTextCache([Map<Object?, Object?>? cache]) {
  final target = cache ?? _apiMeasureTextCache;
  target.clear();
  return target;
}

Map<String, num>? _apiMeasureTextCacheValue(Object? value) {
  if (value is! Map) {
    return null;
  }
  if (value is Map<String, num>) {
    return value;
  }
  final width = _nullableDoubleArg(value['width']);
  final descent = _nullableDoubleArg(value['actualBoundingBoxDescent']);
  final ascent = _nullableDoubleArg(value['actualBoundingBoxAscent']);
  if (width == null || descent == null || ascent == null) {
    return null;
  }
  return {
    'width': width,
    'actualBoundingBoxDescent': descent,
    'actualBoundingBoxAscent': ascent,
  };
}

Map<String, num> getMeasureText(
  Object? value,
  Map<String, Object?> measureText, {
  String font = '',
  String? fontset,
  String textBaseline = 'alphabetic',
  num zoomRatio = 1,
  num fallbackTextHeight = 0,
  Map<Object?, Object?>? cache,
  Map<String, Object?>? descTextMeasure,
  Map<String, Object?>? matchTextMeasure,
}) {
  final target = cache ?? _apiMeasureTextCache;
  final fontKey = fontset ?? font;
  final cacheKey = '${value}_$fontKey';
  final zoomedCacheKey = '${value}_${zoomRatio}_$fontKey';
  final cached = _apiMeasureTextCacheValue(
    target[cacheKey] ?? target[zoomedCacheKey],
  );
  if (cached != null) {
    return cached;
  }

  final width = _nullableDoubleArg(measureText['width']) ?? 0;
  var descent = _nullableDoubleArg(measureText['actualBoundingBoxDescent']);
  var ascent = _nullableDoubleArg(measureText['actualBoundingBoxAscent']);
  if (descent == null || ascent == null || descent.isNaN || ascent.isNaN) {
    final textHeight = fallbackTextHeight;
    if (textBaseline == 'top') {
      descent = textHeight.toDouble();
      ascent = 0;
    } else if (textBaseline == 'middle') {
      descent = textHeight / 2;
      ascent = textHeight / 2;
    } else {
      descent = 0;
      ascent = textHeight.toDouble();
    }
  }

  if (textBaseline == 'alphabetic') {
    final descFallback = _nullableDoubleArg(
      descTextMeasure?['actualBoundingBoxDescent'],
    );
    final matchFallback = _nullableDoubleArg(
      matchTextMeasure?['actualBoundingBoxDescent'],
    );
    if (descFallback != null &&
        matchFallback != null &&
        descent <= matchFallback) {
      descent = descFallback == 0 ? 0 : descFallback;
    }
  }

  final result = {
    'width': width * zoomRatio,
    'actualBoundingBoxDescent': descent * zoomRatio,
    'actualBoundingBoxAscent': ascent * zoomRatio,
  };
  target[zoomedCacheKey] = result;
  return result;
}

Map<String, Object?>? getCellTextInfo(
  FortuneCell? cell, {
  Map<String, Object?> option = const {},
  Map<String, Object?> measureText = const {},
  int defaultFontSize = 10,
  num zoomRatio = 1,
  Map<Object?, Object?>? cache,
}) {
  if (cell == null) {
    return null;
  }
  final value = _apiCellTextValue(cell);
  if (value.isEmpty) {
    return null;
  }
  final spaceWidth = _nullableDoubleArg(option['space_width']) ?? 2;
  final spaceHeight = _nullableDoubleArg(option['space_height']) ?? 2;
  final fontSize =
      _apiParseFloat(
        '${normalizedCellAttr(cell, 'fs', defaultFontSize: defaultFontSize)}',
      ) ??
      defaultFontSize;
  final fontset = getFontSet(
    {
      'it': normalizedCellAttr(cell, 'it'),
      'bl': normalizedCellAttr(cell, 'bl'),
      'fs': fontSize,
      'ff': normalizedCellAttr(cell, 'ff'),
    },
    defaultFontSize,
    fontArray: fortuneFontArray,
  );
  final fallbackWidth = value.length * fontSize * 0.6;
  final measured = getMeasureText(
    value,
    measureText.isEmpty ? {'width': fallbackWidth} : measureText,
    fontset: fontset,
    textBaseline: 'alphabetic',
    fallbackTextHeight: fontSize,
    zoomRatio: zoomRatio,
    cache: cache,
  );
  final textHeight =
      (measured['actualBoundingBoxAscent'] ?? 0) +
      (measured['actualBoundingBoxDescent'] ?? 0);
  final rotation = _apiCellTextRotation(cell);
  final line = drawLineInfo(
    {
      'text': value,
      'value': value,
      'width': measured['width'],
      'height': textHeight,
      'left': spaceWidth,
      'top': spaceHeight,
      'inline': false,
    },
    normalizedCellAttr(cell, 'cl'),
    normalizedCellAttr(cell, 'un'),
    {
      'textMetrics': measured,
      'space_width': spaceWidth,
      'space_height': spaceHeight,
    },
  );
  return <String, Object?>{
    'text': value,
    'values': [line],
    'fontset': fontset,
    'fontSize': fontSize,
    'width': measured['width'],
    'height': textHeight,
    'cellWidth': _nullableDoubleArg(option['cellWidth']),
    'cellHeight': _nullableDoubleArg(option['cellHeight']),
    'spaceWidth': spaceWidth,
    'spaceHeight': spaceHeight,
    'horizonAlign': normalizedCellAttr(cell, 'ht'),
    'verticalAlign': normalizedCellAttr(cell, 'vt'),
    'textWrap': normalizedCellAttr(cell, 'tb'),
    'textRotationMode': normalizedCellAttr(cell, 'tr'),
    'textRotation': rotation['angle'],
    'isRotateUp': rotation['isRotateUp'],
    'isVerticalText': normalizedCellAttr(cell, 'tr') == '3',
    'mode': option['cellWidth'] == null ? 'onlyWidth' : '',
  };
}

String _apiCellTextValue(FortuneCell cell) {
  if (cell.inlineRuns != null && cell.inlineRuns!.isNotEmpty) {
    return cell.inlineRuns!.map((run) => run.text).join();
  }
  final displayValue = cell.hasRawDisplayValue
      ? cell.rawDisplayValue
      : cell.displayValue;
  final rawValue = cell.hasRawValue ? cell.rawValue : cell.value;
  return '${displayValue ?? rawValue ?? ''}';
}

Map<String, Object?> _apiCellTextRotation(FortuneCell cell) {
  final mode = '${normalizedCellAttr(cell, 'tr') ?? '0'}';
  final rawAngle = cell.hasRawTextRotation
      ? cell.rawTextRotation
      : cell.textRotation;
  num angle =
      _apiParseFloat('$rawAngle') ??
      switch (mode) {
        '1' => 45,
        '4' => 90,
        '2' => 135,
        '5' => 180,
        _ => 0,
      };
  if (angle > 180 || angle < 0) {
    angle = 0;
  }
  var isRotateUp = 1;
  if (angle > 90) {
    angle = 90 - angle;
    isRotateUp = 0;
  }
  return {'angle': angle.truncate(), 'isRotateUp': isRotateUp};
}

bool isSupportBoundingBox(Map<String, Object?> measureText) {
  return measureText['actualBoundingBoxAscent'] != null;
}

bool israngeseleciton(
  String? text, {
  int? anchorOffset,
  bool istooltip = false,
}) {
  final trimmed = text?.trim() ?? '';
  if (trimmed.isEmpty) {
    return false;
  }
  final offset = anchorOffset == null
      ? trimmed.length
      : math.min(math.max(anchorOffset, 0), trimmed.length);
  if (offset == 0) {
    return false;
  }
  final lastText = trimmed.substring(offset - 1, offset);
  if (istooltip) {
    return lastText == '(' || lastText == ',';
  }
  return lastText == '(' ||
      lastText == ',' ||
      lastText == '=' ||
      _apiFormulaHtmlOperators.contains(lastText) ||
      lastText == '&';
}

String? _apiFormulaHtmlPreviousNonSpace(String text, int index) {
  var current = index;
  while (current >= 0) {
    final char = text[current];
    if (char != ' ') {
      return char;
    }
    current -= 1;
  }
  return null;
}

String _apiFunctionHtmlTail(
  String text,
  List<int> rangeIndexes,
  _FormulaHtmlState state,
) {
  if (text.isEmpty) {
    return '';
  }
  final trimmed = text.trim();
  if (iscelldata(trimmed)) {
    final rangeIndex = rangeIndexes.length > state.index
        ? rangeIndexes[state.index]
        : state.index;
    state.index += 1;
    final color = colors.isEmpty ? '' : colors[rangeIndex % colors.length];
    return '<span class="fortune-formula-functionrange-cell" '
        'rangeindex="$rangeIndex" dir="auto" style="color:$color;">$text</span>';
  }
  if (text.contains('</span>')) {
    return '';
  }
  final arrayMatch = RegExp(r'\{.*?\}').firstMatch(trimmed);
  if (arrayMatch == null) {
    return '<span dir="auto" class="luckysheet-formula-text-color">$text</span>';
  }
  final arrayText = arrayMatch.group(0)!;
  final arrayStart = text.indexOf(arrayText);
  final buffer = StringBuffer();
  if (arrayStart > 0) {
    buffer.write(
      '<span dir="auto" class="luckysheet-formula-text-color">${text.substring(0, arrayStart)}</span>',
    );
  }
  buffer.write(
    '<span dir="auto" style="color:#959a05" class="luckysheet-formula-text-array">$arrayText</span>',
  );
  if (arrayStart + arrayText.length < text.length) {
    buffer.write(
      '<span dir="auto" class="luckysheet-formula-text-color">${text.substring(arrayStart + arrayText.length)}</span>',
    );
  }
  return buffer.toString();
}

bool iscelldata(String txt) {
  final parts = txt.split('!');
  final rangeText = parts.length > 1 ? parts[1] : parts[0];
  final cellPattern = RegExp(
    r'^(([a-zA-Z]+)|([$][a-zA-Z]+))(([0-9]+)|([$][0-9]+))$',
  );
  if (!rangeText.contains(':')) {
    final row = _apiCellTextRow(rangeText);
    final column = columnCharToIndex(
      rangeText.replaceAll(RegExp(r'[^A-Za-z]'), ''),
    );
    if (row != null && column != null && cellPattern.hasMatch(rangeText)) {
      return true;
    }
    return false;
  }

  final rangePattern = RegExp(
    r'^(((([a-zA-Z]+)|([$][a-zA-Z]+))(([0-9]+)|([$][0-9]+)))|((([a-zA-Z]+)|([$][a-zA-Z]+)))|((([0-9]+)|([$][0-9]+s))))$',
  );
  final rangeParts = rangeText.split(':');
  if (rangeParts.length != 2) {
    return false;
  }
  final startRow = _apiCellTextRow(rangeParts[0]);
  final endRow = _apiCellTextRow(rangeParts[1]);
  if (startRow != null && endRow != null && startRow > endRow) {
    return false;
  }
  final startColumn = columnCharToIndex(
    rangeParts[0].replaceAll(RegExp(r'[^A-Za-z]'), ''),
  );
  final endColumn = columnCharToIndex(
    rangeParts[1].replaceAll(RegExp(r'[^A-Za-z]'), ''),
  );
  if (startColumn != null && endColumn != null && startColumn > endColumn) {
    return false;
  }
  return rangePattern.hasMatch(rangeParts[0]) &&
      rangePattern.hasMatch(rangeParts[1]);
}

Map<String, Object?> isLinkValid(String linkType, String linkAddress) {
  if (linkAddress.isEmpty) {
    return {'isValid': false, 'tooltip': ''};
  }
  if (linkType == 'webpage') {
    final normalizedAddress =
        RegExp(r'^https?://', caseSensitive: false).hasMatch(linkAddress)
        ? linkAddress
        : 'https://$linkAddress';
    final isValid = RegExp(
      r'^https?://([\w\-.]+)+[\w-]*([\w\-./?%&=]+)?$',
      caseSensitive: false,
    ).hasMatch(normalizedAddress);
    return {
      'isValid': isValid,
      'tooltip': isValid ? '' : 'Invalid link address',
    };
  }
  if (linkType == 'cellrange' && !iscelldata(linkAddress)) {
    return {'isValid': false, 'tooltip': 'Invalid cell range'};
  }
  return {'isValid': true, 'tooltip': ''};
}

Object? getCellHyperlink(FortuneSheet? sheet, int row, int column) {
  return sheet?.hyperlinks['${row}_$column'];
}

Map<String, int>? getCellRowColumn(
  FortuneSheet? sheet,
  num pageX,
  num pageY, {
  num containerLeft = 0,
  num containerTop = 0,
  num scrollLeft = 0,
  num scrollTop = 0,
  num rowHeaderWidth = 0,
  num columnHeaderHeight = 0,
  List<num>? visibleDataRows,
  List<num>? visibleDataColumns,
}) {
  if (sheet == null) {
    return null;
  }
  final rows =
      visibleDataRows ?? sheet.metrics(const FortuneSettings()).visibleDataRows;
  final columns =
      visibleDataColumns ??
      sheet.metrics(const FortuneSettings()).visibleDataColumns;
  final y = pageY - containerTop - columnHeaderHeight + scrollTop;
  final x = pageX - containerLeft - rowHeaderWidth + scrollLeft;
  final row = rowLocation(y, rows)[2].toInt();
  final column = colLocation(x, columns)[2].toInt();
  final anchor = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
  return {'r': anchor.row, 'c': anchor.column};
}

Map<String, Object?>? showLinkCard(
  FortuneSheet? sheet,
  int row,
  int column, {
  bool isEditing = false,
  bool isMouseDown = false,
  Map<String, Object?>? linkCard,
  List<num>? visibleDataRows,
  List<num>? visibleDataColumns,
}) {
  if (sheet == null) {
    return null;
  }
  if (linkCard?['selectingCellRange'] == true) {
    return linkCard;
  }
  final rc = '${row}_$column';
  if (linkCard?['rc'] == rc) {
    return linkCard;
  }
  final link = getCellHyperlink(sheet, row, column);
  final cardSheetId = _nullableStringArg(linkCard?['sheetId']);
  final cardIsEditing = linkCard?['isEditing'] == true;
  if (!isEditing &&
      link == null &&
      (isMouseDown || !cardIsEditing || cardSheetId != sheet.id)) {
    return null;
  }
  if (isEditing ||
      (link != null && (!cardIsEditing || isMouseDown)) ||
      cardSheetId != sheet.id) {
    final rows =
        visibleDataRows ??
        sheet.metrics(const FortuneSettings()).visibleDataRows;
    final columns =
        visibleDataColumns ??
        sheet.metrics(const FortuneSettings()).visibleDataColumns;
    final cellLeft = column <= 0
        ? 0
        : colLocationByIndex(column - 1, columns)[1];
    final cellBottom = rowLocationByIndex(row, rows)[1];
    final cell = sheet.cells[FortuneCellCoord(row, column)];
    final originText = cell?.hasRawValue == true ? cell?.rawValue : cell?.value;
    return {
      'sheetId': sheet.id,
      'r': row,
      'c': column,
      'rc': rc,
      'originText': originText == null ? '' : '$originText',
      'originType': _apiHyperlinkField(link, 'linkType') ?? 'webpage',
      'originAddress': _apiHyperlinkField(link, 'linkAddress') ?? '',
      'position': {'cellLeft': cellLeft, 'cellBottom': cellBottom},
      'isEditing': isEditing,
    };
  }
  return linkCard;
}

String? _apiHyperlinkField(Object? link, String field) {
  if (link is FortuneHyperlink) {
    return switch (field) {
      'linkType' => link.linkType,
      'linkAddress' => link.linkAddress,
      _ => null,
    };
  }
  if (link is Map) {
    return _nullableStringArg(link[field]);
  }
  return null;
}

Map<String, Object?>? goToLink(
  FortuneWorkbook workbook,
  String currentSheetId,
  int row,
  int column,
  String linkType,
  String linkAddress, {
  List<num>? visibleDataRows,
  List<num>? visibleDataColumns,
}) {
  final currentSheet = getSheetByIndex(workbook, id: currentSheetId);
  if (currentSheet == null ||
      !currentSheet.hyperlinks.containsKey('${row}_$column')) {
    return null;
  }
  if (linkType == 'webpage') {
    final url =
        RegExp(r'^https?://', caseSensitive: false).hasMatch(linkAddress)
        ? linkAddress
        : 'https://$linkAddress';
    return {'type': 'webpage', 'url': url, 'clearLinkCard': true};
  }
  if (linkType == 'sheet') {
    final sheetId = getSheetIdByName(workbook, linkAddress);
    if (sheetId == null) {
      return null;
    }
    return {'type': 'sheet', 'sheetId': sheetId, 'clearLinkCard': true};
  }
  final range = getcellrange(workbook, linkAddress, formulaId: currentSheetId);
  if (range == null) {
    return null;
  }
  final rowRange = range['row'];
  final columnRange = range['column'];
  if (rowRange is! List || columnRange is! List) {
    return null;
  }
  final rowStart = _nullableIntArg(rowRange[0]);
  final rowEnd = _nullableIntArg(rowRange[1]);
  final columnStart = _nullableIntArg(columnRange[0]);
  final columnEnd = _nullableIntArg(columnRange[1]);
  final targetSheetId = _nullableStringArg(range['sheetId']) ?? currentSheetId;
  final targetSheet = getSheetByIndex(workbook, id: targetSheetId);
  if (rowStart == null ||
      rowEnd == null ||
      columnStart == null ||
      columnEnd == null ||
      targetSheet == null) {
    return null;
  }
  final rows =
      visibleDataRows ?? targetSheet.metrics(workbook.settings).visibleDataRows;
  final columns =
      visibleDataColumns ??
      targetSheet.metrics(workbook.settings).visibleDataColumns;
  final scrollTop = rowStart <= 0
      ? 0
      : rowLocationByIndex(rowStart - 1, rows)[1];
  final scrollLeft = columnStart <= 0
      ? 0
      : colLocationByIndex(columnStart - 1, columns)[1];
  final selection = normalizeSelection(
    targetSheet,
    [
      FortuneRange(
        rowStart: rowStart,
        rowEnd: rowEnd,
        columnStart: columnStart,
        columnEnd: columnEnd,
        extraFields: {'sheetId': targetSheetId},
      ),
    ],
    visibleDataRows: rows,
    visibleDataColumns: columns,
  );
  return {
    'type': 'cellrange',
    'sheetId': targetSheetId,
    'scrollLeft': scrollLeft,
    'scrollTop': scrollTop,
    'selection': selection,
    'clearLinkCard': true,
  };
}

FortuneSheet saveHyperlink(
  FortuneSheet sheet,
  int row,
  int column,
  String linkText,
  String linkType,
  String linkAddress,
) {
  if (linkType.isEmpty || linkAddress.isEmpty) {
    return sheet;
  }
  final key = '${row}_$column';
  final linkValue = linkText.isEmpty ? linkAddress : linkText;
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  final coord = FortuneCellCoord(row, column);
  final cell = cells[coord] ?? const FortuneCell();
  cells[coord] = cell.copyWith(
    value: linkValue,
    rawValue: linkValue,
    hasRawValue: true,
    displayValue: linkValue,
    rawDisplayValue: linkValue,
    hasRawDisplayValue: true,
    foreground: const Color(0xff0000ff),
    rawForeground: 'rgb(0, 0, 255)',
    hasRawForeground: true,
    underline: true,
    rawUnderline: 1,
    hasRawUnderline: true,
    hyperlink: FortuneHyperlink(
      row: row,
      column: column,
      id: sheet.id,
      linkType: linkType,
      linkAddress: linkAddress,
    ),
  );
  final hyperlinks = _cloneStringObjectMap(sheet.hyperlinks)
    ..[key] = {'linkType': linkType, 'linkAddress': linkAddress};
  return sheet.copyWith(cells: cells, hyperlinks: hyperlinks);
}

FortuneSheet removeHyperlink(
  FortuneSheet sheet,
  int row,
  int column, {
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet;
  }
  final key = '${row}_$column';
  final hyperlinks = _cloneStringObjectMap(sheet.hyperlinks)..remove(key);
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  final coord = FortuneCellCoord(row, column);
  final cell = cells[coord];
  if (cell != null) {
    cells[coord] = FortuneCell(
      value: cell.value,
      rawValue: cloneFortuneMetadata(cell.rawValue),
      hasRawValue: cell.hasRawValue,
      displayValue: cell.displayValue,
      rawDisplayValue: cloneFortuneMetadata(cell.rawDisplayValue),
      hasRawDisplayValue: cell.hasRawDisplayValue,
    );
  }
  return sheet.copyWith(cells: cells, hyperlinks: hyperlinks);
}

String generateRandomId(
  String? prefix, {
  String userAgent = 'flutter',
  DateTime? now,
  math.Random? random,
}) {
  final idPrefix = prefix ?? 'img';
  final source = userAgent.replaceAll(RegExp(r'[^a-zA-Z0-9]'), '');
  final chars = source.isEmpty ? 'flutter'.split('') : source.split('');
  final generator = random ?? math.Random();
  final mid = StringBuffer();
  for (var index = 0; index < 12; index += 1) {
    mid.write(chars[generator.nextInt(chars.length)]);
  }
  final timestamp = (now ?? DateTime.now()).millisecondsSinceEpoch;
  return '${idPrefix}_${mid}_$timestamp';
}

int? _apiCellTextRow(String text) {
  final digits = text.replaceAll(RegExp(r'[^0-9]'), '');
  final row = int.tryParse(digits);
  return row == null ? null : row - 1;
}

bool valueIsError(String value) {
  return error.values.contains(value);
}

List<Object?>? genarate(Object? value) {
  if (value == null) {
    return null;
  }

  final text = '$value';
  Object? displayText;
  Map<String, Object?> cellType = <String, Object?>{};
  Object? parsedValue = value;

  final thousandsMatch = RegExp(r'^-?[0-9]{1,},[0-9]{3}$').hasMatch(text);
  if (thousandsMatch) {
    displayText = text;
    parsedValue =
        num.tryParse(text.split('.')[0].replaceFirst(',', '')) ?? value;
    var format = '#,##0';
    final decimalPart = text.split('.').length > 1 ? text.split('.')[1] : '';
    if (decimalPart.isNotEmpty) {
      format = '#,##0.${'0' * decimalPart.length}';
    }
    cellType = {'fa': format, 't': 'n'};
  } else if (text.startsWith("'")) {
    displayText = text.substring(1);
    cellType = {'fa': '@', 't': 's'};
  } else if (text.toUpperCase() == 'TRUE') {
    displayText = 'TRUE';
    cellType = {'fa': 'General', 't': 'b'};
    parsedValue = true;
  } else if (text.toUpperCase() == 'FALSE') {
    displayText = 'FALSE';
    cellType = {'fa': 'General', 't': 'b'};
    parsedValue = false;
  } else if (valueIsError(text)) {
    displayText = text;
    cellType = {'fa': 'General', 't': 'e'};
  } else if (RegExp(
    r'^\d{6}(18|19|20)?\d{2}(0[1-9]|1[12])(0[1-9]|[12]\d|3[01])\d{3}(\d|X)$',
    caseSensitive: false,
  ).hasMatch(text)) {
    displayText = text;
    cellType = {'fa': '@', 't': 's'};
  } else if (isRealNum(value) &&
      _apiGenerateNumericValue(text) != null &&
      _apiGenerateNumericValue(text)!.abs() > 0 &&
      (_apiGenerateNumericValue(text)!.abs() >= 1e11 ||
          _apiGenerateNumericValue(text)!.abs() < 1e-9)) {
    final number = _apiGenerateNumericValue(text)!;
    parsedValue = number;
    final decimalDigits = _apiGenerateScientificDigits(number);
    cellType = {
      'fa': decimalDigits == 0 ? '#0.E+00' : '#0.${'0' * decimalDigits}E+00',
      't': 'n',
    };
    displayText = _apiGenerateFormatScientific(number, decimalDigits);
  } else if (text.contains('%')) {
    final percent = _apiGeneratePercent(text);
    if (percent == null) {
      displayText = text;
      cellType = {'fa': '@', 't': 's'};
    } else {
      parsedValue = percent['value'];
      final percentText = _apiGenerateFormatFixed(
        (parsedValue as num) * 100,
        percent['decimalLength'] as int,
        useThousands: percent['useThousands'] as bool,
      );
      displayText = percent['trailingDecimal'] == true
          ? '$percentText.%'
          : '$percentText%';
      cellType = {'fa': percent['format'], 't': 'n'};
    }
  } else if (text.contains('.')) {
    final decimal = _apiGenerateDecimal(text);
    if (decimal == null) {
      displayText = text;
      cellType = {'fa': '@', 't': 's'};
    } else {
      parsedValue = decimal['value'];
      final decimalText = _apiGenerateFormatFixed(
        parsedValue as num,
        decimal['decimalLength'] as int,
        useThousands: decimal['useThousands'] as bool,
      );
      displayText = decimal['trailingDecimal'] == true
          ? '$decimalText.'
          : decimalText;
      cellType = {'fa': decimal['format'], 't': 'n'};
    }
  } else if (isRealNum(value)) {
    final number = _apiGenerateNumericValue(text)!;
    displayText = number.toString();
    cellType = {'fa': 'General', 't': 'n'};
    parsedValue = number;
  } else if (_apiGenerateDatePayload(text) case final datePayload?) {
    displayText = datePayload['display'];
    cellType = {'fa': datePayload['format'], 't': 'd'};
    parsedValue = datePayload['value'];
  } else {
    displayText = text;
    cellType = {'fa': 'General', 't': 'g'};
  }

  return [displayText, cellType, parsedValue];
}

String update(String fmt, Object? value) {
  if (value == null) {
    return '';
  }
  final format = fmt;
  if (format.isEmpty || format.toLowerCase() == 'general') {
    return _apiFormatGeneralValue(value);
  }
  final effectiveValue = value is DateTime ? datenumLocal(value) : value;
  if (format == '@') {
    return _apiFormatTextPlaceholderValue(effectiveValue);
  }
  if (_apiIsWanYiNumberFormat(format)) {
    return _apiFormatWanYiNumber(format, effectiveValue);
  }
  final number = effectiveValue is num
      ? effectiveValue
      : num.tryParse('$effectiveValue');
  if (number == null) {
    final sections = _apiSplitFormatSections(format);
    if (sections.length > 3) {
      return _apiFormatTextSection(
        sections[3],
        _apiFormatTextPlaceholderValue(effectiveValue),
      );
    }
    if (format.contains('@')) {
      return _apiFormatTextSection(
        format,
        _apiFormatTextPlaceholderValue(effectiveValue),
      );
    }
    return '$effectiveValue';
  }
  final section = _apiFormatSection(format, number);
  if (section.format.isEmpty) {
    return '';
  }
  final sectionFormat = _apiStripNumericBracketDirectives(section.format);
  final sectionNumber = section.value;
  if (is_date(sectionFormat)) {
    if (sectionNumber < 0) {
      return '';
    }
    if (_apiDateSerialOutOfRange(sectionNumber)) {
      if (_apiDateFormatReturnsBlankWhenOutOfRange(sectionFormat)) {
        return '';
      }
      if (sectionNumber > 2958465 &&
          _apiDateFormatHasAbsoluteTime(sectionFormat)) {
        return '';
      }
      if (_apiDateFormatRequiresParsedDate(sectionFormat)) {
        return '#####';
      }
    }
    return _apiGenerateFormatDate(
      _apiDatePartsFromSerial(sectionNumber),
      sectionFormat,
      serial: sectionNumber,
    );
  }
  if (_apiIsParenthesizedNegativeNumberFormat(sectionFormat)) {
    return _apiFormatParenthesizedNegativeNumber(sectionFormat, number);
  }
  if (_apiIsEngineeringScientificNumberFormat(sectionFormat)) {
    return _apiFormatEngineeringScientificNumber(sectionFormat, sectionNumber);
  }
  if (RegExp(r'E[+-]0+', caseSensitive: false).hasMatch(sectionFormat)) {
    final decimalDigits = _apiFormatDecimalPlacesBefore(sectionFormat, 'E');
    return _apiFormatScientificWithLiterals(
      sectionFormat,
      sectionNumber,
      decimalDigits,
    );
  }
  if (sectionFormat.contains('%')) {
    final decimalDigits = _apiFormatDecimalPlaceRangeBefore(sectionFormat, '%');
    final percentCount = RegExp('%').allMatches(sectionFormat).length;
    final displayNumber = sectionNumber * math.pow(100, percentCount);
    return _apiFormatNumericWithLiteralDigits(
      sectionFormat,
      displayNumber,
      decimalDigits: decimalDigits,
    );
  }
  if (_apiIsDollarCurrencyNumberFormat(sectionFormat)) {
    return _apiFormatDollarCurrencyNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsFixedDenominatorFractionNumberFormat(sectionFormat)) {
    return _apiFormatFixedDenominatorFractionNumber(
      sectionFormat,
      sectionNumber,
    );
  }
  if (_apiIsFractionNumberFormat(sectionFormat)) {
    return _apiFormatFractionNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsPhoneNumberFormat(sectionFormat)) {
    return _apiFormatPhoneNumber(sectionNumber);
  }
  if (_apiIsHyphenGroupNumberFormat(sectionFormat)) {
    return _apiFormatHyphenGroupNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsHashOnlyCommaNumberFormat(sectionFormat)) {
    return _apiFormatHashOnlyCommaNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsCommaDecimalCarryNumberFormat(sectionFormat)) {
    return _apiFormatCommaDecimalCarryNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsPaddedCommaNumberFormat(sectionFormat)) {
    return _apiFormatPaddedCommaNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsTrailingDotCommaIntegerFormat(sectionFormat)) {
    return _apiFormatTrailingDotCommaInteger(sectionNumber);
  }
  if (_apiIsRedundantCommaPrefixNumberFormat(sectionFormat)) {
    return _apiFormatRedundantCommaPrefixNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsDec1NumberFormat(sectionFormat)) {
    return _apiFormatDec1Number(sectionFormat, sectionNumber);
  }
  if (_apiIsDecimalOnlyNumberFormat(sectionFormat)) {
    return _apiFormatDecimalOnlyNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsIgnoredTrailingQuestionDecimalFormat(sectionFormat)) {
    return _apiFormatIgnoredTrailingQuestionDecimal(
      sectionFormat,
      sectionNumber,
    );
  }
  if (_apiIsTrailingQuestionDecimalIntegerFormat(
    sectionFormat,
    sectionNumber,
  )) {
    return _apiFormatTrailingQuestionDecimalInteger(
      sectionFormat,
      sectionNumber,
    );
  }
  if (_apiIsZeroOptionalDecimalIntegerFormat(sectionFormat, sectionNumber)) {
    return _apiFormatZeroOptionalDecimalInteger(sectionFormat, sectionNumber);
  }
  if (_apiIsPlainTrailingDotIntegerFormat(sectionFormat, sectionNumber)) {
    return _apiFormatPlainTrailingDotInteger(sectionFormat, sectionNumber);
  }
  if (_apiIsSimplePlaceholderNumberFormat(sectionFormat)) {
    return _apiFormatSimplePlaceholderNumber(sectionFormat, sectionNumber);
  }
  if (_apiIsQuestionLiteralNumberFormat(sectionFormat)) {
    return _apiFormatQuestionLiteralNumber(sectionFormat, sectionNumber);
  }
  if (RegExp(r'[#0]').hasMatch(sectionFormat)) {
    return _apiFormatNumericWithLiterals(sectionFormat, sectionNumber);
  }
  final literal = _apiFormatLiteralSegment(sectionFormat);
  if (literal.trim().isNotEmpty) {
    return literal;
  }
  return '$effectiveValue';
}

String _apiFormatGeneralValue(Object value) {
  if (value is bool) {
    return value ? 'TRUE' : 'FALSE';
  }
  if (value is DateTime) {
    return update('m/d/yy', datenumLocal(value));
  }
  if (value is num) {
    if (!value.isFinite) {
      return value.toString().toUpperCase();
    }
    if (_apiGeneralValueIsJsInt32(value)) {
      return value.toInt().toString();
    }
    return _apiFormatGeneralNumber(value);
  }
  return '$value';
}

bool _apiGeneralValueIsJsInt32(num value) {
  return value == value.truncateToDouble() &&
      value >= -2147483648 &&
      value <= 2147483647;
}

String _apiFormatGeneralNumber(num value) {
  final numeric = value.toDouble();
  if (numeric == 0) {
    return '0';
  }
  final exponent = (math.log(numeric.abs()) * math.log10e).floor();
  String text;
  if (exponent >= -4 && exponent <= -1) {
    text = numeric.toStringAsPrecision(10 + exponent);
  } else if (exponent.abs() <= 9) {
    text = _apiFormatGeneralSmallExp(numeric);
  } else if (exponent == 10) {
    final fixed = numeric.toStringAsFixed(10);
    text = fixed.substring(0, math.min(12, fixed.length));
  } else {
    text = _apiFormatGeneralLargeExp(numeric);
  }
  return _apiStripGeneralDecimal(_apiNormalizeGeneralExponent(text));
}

String _apiFormatGeneralSmallExp(double value) {
  final width = value < 0 ? 12 : 11;
  var text = _apiStripGeneralDecimal(value.toStringAsFixed(12));
  if (text.length <= width) {
    return text;
  }
  text = value.toStringAsPrecision(10);
  if (text.length <= width) {
    return text;
  }
  return value.toStringAsExponential(5);
}

String _apiFormatGeneralLargeExp(double value) {
  final text = _apiStripGeneralDecimal(value.toStringAsFixed(11));
  if (text.length > (value < 0 ? 12 : 11) || text == '0' || text == '-0') {
    return value.toStringAsPrecision(6);
  }
  return text;
}

String _apiNormalizeGeneralExponent(String value) {
  final upper = value.toUpperCase();
  return upper
      .replaceFirstMapped(
        RegExp(r'(?:\.0*|(\.\d*[1-9])0+)E'),
        (match) => '${match.group(1) ?? ''}E',
      )
      .replaceFirstMapped(
        RegExp(r'([E][+-]?)(\d)$'),
        (match) => '${match.group(1)!}0${match.group(2)!}',
      );
}

String _apiStripGeneralDecimal(String value) {
  if (!value.contains('.')) {
    return value;
  }
  return value
      .replaceFirstMapped(RegExp(r'(\.|\d)0+$'), (match) => match.group(1)!)
      .replaceFirst(RegExp(r'\.$'), '');
}

String _apiFormatTextPlaceholderValue(Object value) {
  if (value is bool) {
    return value ? 'TRUE' : 'FALSE';
  }
  if (value is num && value.isFinite && value == value.truncateToDouble()) {
    return value.toInt().toString();
  }
  return '$value';
}

({String format, num value}) _apiFormatSection(String format, num value) {
  final sections = _apiSplitFormatSections(format);
  final conditional = _apiFormatConditionalSection(sections, value);
  if (conditional != null) {
    return conditional;
  }
  if (sections.length == 1) {
    return (format: format, value: value);
  }
  if (value < 0) {
    if (sections.length > 1) {
      return (format: sections[1], value: value.abs());
    }
    return (format: sections[0], value: value);
  }
  if (value == 0 && sections.length > 2) {
    return (format: sections[2], value: value);
  }
  return (format: sections[0], value: value);
}

({String format, num value})? _apiFormatConditionalSection(
  List<String> sections,
  num value,
) {
  var hasCondition = false;
  String? fallback;
  for (final section in sections) {
    final condition = _apiFormatSectionCondition(section);
    if (condition == null) {
      fallback ??= section;
      continue;
    }
    hasCondition = true;
    if (_apiFormatConditionMatches(
      condition.operator,
      value,
      condition.limit,
    )) {
      return (format: section, value: value < 0 ? value.abs() : value);
    }
  }
  if (hasCondition && fallback != null) {
    return (format: fallback, value: value);
  }
  return null;
}

({String operator, num limit})? _apiFormatSectionCondition(String section) {
  var index = 0;
  while (index < section.length && section[index] == '[') {
    final end = section.indexOf(']', index + 1);
    if (end < 0) {
      return null;
    }
    final token = section.substring(index + 1, end);
    final match = RegExp(
      r'^(<=|>=|<>|<|>|=)(-?\d+(?:\.\d+)?)$',
    ).firstMatch(token);
    if (match != null) {
      return (operator: match.group(1)!, limit: num.parse(match.group(2)!));
    }
    index = end + 1;
  }
  return null;
}

bool _apiFormatConditionMatches(String operator, num value, num limit) {
  return switch (operator) {
    '<' => value < limit,
    '<=' => value <= limit,
    '>' => value > limit,
    '>=' => value >= limit,
    '=' => value == limit,
    '<>' => value != limit,
    _ => false,
  };
}

bool _apiIsParenthesizedNegativeNumberFormat(String format) {
  return format.startsWith('(') &&
      !RegExp(r'\).*[0#]').hasMatch(format) &&
      RegExp(r'[0#?]').hasMatch(format);
}

String _apiFormatParenthesizedNegativeNumber(String format, num value) {
  final innerFormat = format
      .replaceFirst(RegExp(r'^\( *'), '')
      .replaceFirst(RegExp(r' \)'), '')
      .replaceAll(')', '');
  final formatted = update(innerFormat, value.abs());
  return value < 0 ? '($formatted)' : formatted;
}

bool _apiIsEngineeringScientificNumberFormat(String format) {
  return RegExp(r'^#+0\.0E\+0$', caseSensitive: false).hasMatch(format);
}

bool _apiIsWanYiNumberFormat(String format) {
  return RegExp(r'^[wW](?:0(?:\.0+)?)?$').hasMatch(format);
}

String _apiFormatWanYiNumber(String format, Object? value) {
  final numericValue = value is num ? value : num.tryParse('$value');
  if (numericValue == null || numericValue.isNaN) {
    return '$value';
  }
  final precisionFormat = format.substring(1);
  var displayValue = numericValue;
  final isNegative = displayValue < 0;
  if (isNegative) {
    displayValue = displayValue.abs();
  }
  final integer = displayValue.toInt();
  var text = _apiJsNumberText(displayValue);
  if (integer.toString().length > 4) {
    if (integer.toString().length > 8) {
      final yi = (displayValue / 100000000).toInt();
      final wan = (displayValue - yi * 10000).toInt();
      var remainder = displayValue - (yi * 100000000 + wan * 10000);
      final remainderText = precisionFormat.isEmpty
          ? _apiJsNumberText(remainder)
          : _apiFormatWanYiPrecision(remainder, precisionFormat);
      text = '$yi亿$wan万$remainderText';
    } else {
      final wan = (displayValue / 10000).toInt();
      var remainder = displayValue - wan * 10000;
      final remainderText = precisionFormat.isEmpty
          ? _apiJsNumberText(remainder)
          : _apiFormatWanYiPrecision(remainder, precisionFormat);
      text = '$wan万$remainderText';
    }
    text = _apiNormalizeWanYiNumberText(text);
  } else if (precisionFormat.isNotEmpty) {
    text = _apiFormatWanYiPrecision(displayValue, precisionFormat);
  }
  return isNegative ? '-$text' : text;
}

String _apiFormatWanYiPrecision(num value, String precisionFormat) {
  if (precisionFormat == '0') {
    return value.toStringAsFixed(0);
  }
  final match = RegExp(r'^0\.(0+)$').firstMatch(precisionFormat);
  if (match != null) {
    return value.toStringAsFixed(match.group(1)!.length);
  }
  return _apiJsNumberText(value);
}

String _apiNormalizeWanYiNumberText(String text) {
  var result = text;
  if (result.contains('亿0万0')) {
    result = result.replaceFirst('0万0', '');
  } else if (result.contains('亿0万')) {
    result = result.replaceFirst('0万', '');
  } else if (result.contains('万0')) {
    result = result.replaceFirst('万0', '万');
  }
  if (result.contains('亿') && !result.contains('万')) {
    final afterYi = result.substring(result.indexOf('亿') + 1);
    if (!afterYi.startsWith('.') && afterYi.isNotEmpty) {
      final padded = _apiWanYiPadFollowingDigits(afterYi);
      result = '${result.substring(0, result.indexOf('亿') + 1)}$padded';
    }
  } else if (!result.contains('亿') && result.contains('万')) {
    final afterWan = result.substring(result.indexOf('万') + 1);
    if (!afterWan.startsWith('.') && afterWan.isNotEmpty) {
      final padded = _apiWanYiPadFollowingDigits(afterWan);
      result = '${result.substring(0, result.indexOf('万') + 1)}$padded';
    }
  } else if (result.contains('亿') && result.contains('万')) {
    final yiIndex = result.indexOf('亿');
    final wanIndex = result.indexOf('万');
    final afterYi = result.substring(yiIndex + 1, wanIndex);
    final afterWan = result.substring(wanIndex + 1);
    final paddedYi = _apiWanYiPadFollowingDigits(afterYi);
    result =
        '${result.substring(0, yiIndex + 1)}$paddedYi${result.substring(wanIndex)}';
    if (!afterWan.startsWith('.') && afterWan.isNotEmpty) {
      final paddedWan = _apiWanYiPadFollowingDigits(afterWan);
      result = '${result.substring(0, result.indexOf('万') + 1)}$paddedWan';
    }
  }
  return result;
}

String _apiWanYiPadFollowingDigits(String value) {
  final parsedText = _apiJsParseIntText(value);
  final length = (parsedText ?? 'NaN').length;
  return switch (length) {
    1 => '000$value',
    2 => '00$value',
    3 => '0$value',
    _ => value,
  };
}

String? _apiJsParseIntText(String value) {
  final match = RegExp(r'^[+-]?\d+').firstMatch(value.trimLeft());
  if (match == null) {
    return null;
  }
  return int.parse(match.group(0)!).toString();
}

String _apiJsNumberText(num value) {
  if (value.isFinite && value == value.truncateToDouble()) {
    return value.truncate().toString();
  }
  return '$value';
}

String _apiFormatEngineeringScientificNumber(String format, num value) {
  if (value == 0) {
    return '0.0E+0';
  }
  if (value < 0) {
    return '-${_apiFormatEngineeringScientificNumber(format, value.abs())}';
  }
  final period = format.indexOf('.');
  final exponent = (math.log(value) / math.ln10).floor();
  var remainder = exponent % period;
  if (remainder < 0) {
    remainder += period;
  }
  final decimalDigits = format.indexOf('E') - format.indexOf('.') - 1;
  final precision = decimalDigits + 1 + ((period + remainder) % period);
  var text = (value / math.pow(10, remainder)).toStringAsPrecision(precision);
  if (!RegExp('[Ee]').hasMatch(text)) {
    if (!text.contains('.')) {
      text =
          '${text[0]}.${text.substring(1)}E+${exponent - text.length + remainder}';
    } else {
      text = '${text}E+${exponent - remainder}';
    }
    while (text.startsWith('0.')) {
      final moveEnd = math.min(2 + period, text.length);
      text =
          '${text[0]}${text.substring(2, moveEnd)}.${text.substring(moveEnd)}';
      text = text
          .replaceFirstMapped(RegExp(r'^0+([1-9])'), (match) => match[1]!)
          .replaceFirst(RegExp(r'^0+\.'), '0.');
    }
    text = text.replaceFirst('+-', '-');
  }
  final pivot = (period + remainder) % period;
  text = text.replaceFirstMapped(RegExp(r'^([+-]?)(\d*)\.(\d*)[Ee]'), (match) {
    final fraction = match[3]!;
    final split = math.min(pivot, fraction.length);
    return '${match[1]!}${match[2]!}${fraction.substring(0, split)}.${fraction.substring(split)}E';
  });
  return text.replaceFirst('e', 'E');
}

bool _apiIsFractionNumberFormat(String format) {
  return RegExp(r'[#0?]+ ?/ ?[#0?]+').hasMatch(format);
}

bool _apiIsDollarCurrencyNumberFormat(String format) {
  return format.startsWith(r'$') && format.length > 1;
}

String _apiFormatDollarCurrencyNumber(String format, num value) {
  final numericFormat = format.substring(format[1] == ' ' ? 2 : 1);
  return r'$' + update(numericFormat, value);
}

bool _apiIsFixedDenominatorFractionNumberFormat(String format) {
  return RegExp(r'^# (\?+)( ?)\/( ?)(\d+)').hasMatch(format);
}

String _apiFormatFixedDenominatorFractionNumber(String format, num value) {
  final match = RegExp(r'^# (\?+)( ?)\/( ?)(\d+)').firstMatch(format);
  if (match == null) {
    return '$value';
  }
  final numeratorPlaceholders = match.group(1)!;
  final beforeSlash = match.group(2)!;
  final afterSlash = match.group(3)!;
  final denominatorText = match.group(4)!;
  final denominator = int.parse(denominatorText);
  final sign = value < 0 ? '-' : '';
  final rounded = (value.abs() * denominator).round();
  final whole = rounded ~/ denominator;
  final numerator = rounded - whole * denominator;
  final wholeText = whole == 0 ? '' : '$whole';
  if (numerator == 0) {
    final blankWidth =
        numeratorPlaceholders.length + 1 + denominatorText.length;
    return '$sign$wholeText ${' ' * blankWidth}';
  }
  final numeratorText = '$numerator'.padLeft(numeratorPlaceholders.length);
  final fixedDenominatorText = '$denominator'.padLeft(
    denominatorText.length,
    '0',
  );
  return '$sign$wholeText $numeratorText$beforeSlash/$afterSlash$fixedDenominatorText';
}

bool _apiIsPhoneNumberFormat(String format) {
  return RegExp(r'\(###\) ###\\?-####').hasMatch(format);
}

String _apiFormatPhoneNumber(num value) {
  final digits = _apiGenerateFormatFixed(
    value,
    0,
    useThousands: false,
    minDecimalLength: 0,
  );
  final area = digits.substring(0, math.min(3, digits.length));
  final prefixStart = math.min(3, digits.length);
  final prefixEnd = math.min(6, digits.length);
  final prefix = digits.substring(prefixStart, prefixEnd);
  final suffix = digits.substring(prefixEnd);
  return '($area) $prefix-$suffix';
}

bool _apiIsHyphenGroupNumberFormat(String format) {
  return RegExp(r'^[0#]+(\\?-[0#]+)+$').hasMatch(format);
}

String _apiFormatHyphenGroupNumber(String format, num value) {
  final digits = _apiGenerateFormatFixed(
    value.abs(),
    0,
    useThousands: false,
    minDecimalLength: 0,
  );
  final normalizedFormat = format.replaceAll(r'\', '');
  final result = StringBuffer();
  var digitIndex = digits.length - 1;
  for (var index = normalizedFormat.length - 1; index >= 0; index -= 1) {
    final char = normalizedFormat[index];
    if (char == '0' || char == '#') {
      if (digitIndex >= 0) {
        result.write(digits[digitIndex]);
        digitIndex -= 1;
      } else if (char == '0') {
        result.write('0');
      }
    } else {
      result.write(char);
    }
  }
  return result.toString().split('').reversed.join();
}

bool _apiIsHashOnlyCommaNumberFormat(String format) {
  return RegExp(r'^#+,#+(\.[#0]*0)?$').hasMatch(format);
}

String _apiFormatHashOnlyCommaNumber(String format, num value) {
  final decimalDigits = _apiFormatDecimalPlaceRange(format);
  if (format == '#,###.00' || format == '###,###.00') {
    return _apiFormatCommaDecimalCarryNumber(
      '#,##0.00',
      value,
    ).replaceFirst(RegExp(r'^0\.'), '.');
  }
  final numericText = _apiFormatNumericWithLiteralDigits(
    format,
    value,
    decimalDigits: decimalDigits,
  );
  if (decimalDigits.max == 0 && value.round() == 0) {
    return '';
  }
  if (decimalDigits.max > 0) {
    if (numericText.startsWith('0.')) {
      return numericText.substring(1);
    }
  }
  return numericText;
}

bool _apiIsCommaDecimalCarryNumberFormat(String format) {
  return format == '###,##0.00' || RegExp(r'^#,##0\.[#0]*0$').hasMatch(format);
}

String _apiFormatCommaDecimalCarryNumber(String format, num value) {
  if (value < 0) {
    return '-${_apiFormatCommaDecimalCarryNumber(format, value.abs())}';
  }
  final decimalDigits = _apiFormatDecimalPlaceRange(format).max;
  final scale = math.pow(10, decimalDigits).toInt();
  final integer = value.floor();
  final decimalValue = ((value - integer) * scale).round();
  final carry = decimalValue.toString().length > decimalDigits ? 1 : 0;
  final integerText = _apiGenerateFormatFixed(
    integer + carry,
    0,
    useThousands: true,
    minDecimalLength: 0,
  );
  final decimalText = decimalValue.toString().padLeft(decimalDigits, '0');
  return '$integerText.$decimalText';
}

bool _apiIsPaddedCommaNumberFormat(String format) {
  return RegExp(r'^00,000\.[#0]*0$').hasMatch(format);
}

String _apiFormatPaddedCommaNumber(String format, num value) {
  if (value < 0) {
    return '-${_apiFormatPaddedCommaNumber(format, value.abs())}';
  }
  final decimalDigits = _apiFormatDecimalPlaceRange(format);
  final scale = math.pow(10, decimalDigits.max).toInt();
  final integer = value.floor();
  final decimalValue = ((value - integer) * scale).round();
  var integerPart = integer.toString();
  if (integerPart.length <= 3) {
    integerPart = '00,${integerPart.padLeft(3, '0')}';
  } else if (integerPart.length == 4) {
    integerPart = '0${integerPart.substring(0, 1)},${integerPart.substring(1)}';
  } else {
    integerPart = _apiGenerateFormatFixed(
      int.parse(integerPart),
      0,
      useThousands: true,
      minDecimalLength: 0,
    );
  }
  final decimalText = decimalValue.toString().padLeft(decimalDigits.min, '0');
  return '$integerPart.$decimalText';
}

bool _apiIsTrailingDotCommaIntegerFormat(String format) {
  return RegExp(r'^#{1,3},##0\.$').hasMatch(format);
}

String _apiFormatTrailingDotCommaInteger(num value) {
  return _apiGenerateFormatFixed(
    value,
    0,
    useThousands: true,
    minDecimalLength: 0,
  );
}

bool _apiIsRedundantCommaPrefixNumberFormat(String format) {
  return RegExp(r'^#,#*,#0').hasMatch(format);
}

String _apiFormatRedundantCommaPrefixNumber(String format, num value) {
  final normalizedFormat = format.replaceFirst(RegExp(r'^#,#*,'), '');
  if (_apiIsDecimalOnlyNumberFormat(normalizedFormat)) {
    return _apiFormatDecimalOnlyNumber(normalizedFormat, value);
  }
  if (_apiIsSimplePlaceholderNumberFormat(normalizedFormat)) {
    return _apiFormatSimplePlaceholderNumber(normalizedFormat, value);
  }
  return _apiFormatNumericWithLiterals(normalizedFormat, value);
}

bool _apiIsDec1NumberFormat(String format) {
  return RegExp(r'^#*0*\.[#0]+$').hasMatch(format);
}

String _apiFormatDec1Number(String format, num value) {
  final decimalFormat = format.split('.').last;
  final maxDecimals = decimalFormat.length;
  final minDecimals = '0'.allMatches(decimalFormat).length;
  var text = _apiGenerateFormatFixed(
    value,
    maxDecimals,
    useThousands: false,
    minDecimalLength: minDecimals,
  );
  if (!text.contains('.')) {
    text = '$text.';
  }
  if (RegExp(r'^-0(?:\.0*)?$').hasMatch(text)) {
    text = text.substring(1);
  }
  if (!format.contains('0.') && text.startsWith('0.')) {
    return text.substring(1);
  }
  return text;
}

bool _apiIsDecimalOnlyNumberFormat(String format) {
  return RegExp(r'^#+\.[#0]+$').hasMatch(format) ||
      RegExp(r'^\.[#0]+$').hasMatch(format);
}

String _apiFormatDecimalOnlyNumber(String format, num value) {
  final normalizedFormat = format.replaceFirst(RegExp(r'^#+'), '');
  final decimalDigits = _apiFormatDecimalPlaceRange(normalizedFormat);
  final numericText = _apiGenerateFormatFixed(
    value.abs(),
    decimalDigits.max,
    useThousands: false,
    minDecimalLength: decimalDigits.min,
  );
  if (value < 0) {
    return '-$numericText';
  }
  final trimmed = numericText.startsWith('0.')
      ? numericText.substring(1)
      : numericText;
  return trimmed;
}

bool _apiIsIgnoredTrailingQuestionDecimalFormat(String format) {
  return RegExp(r'^#*0*\.[#0]+\?+$').hasMatch(format);
}

String _apiFormatIgnoredTrailingQuestionDecimal(String format, num value) {
  final normalizedFormat = format.replaceFirst(RegExp(r'\?+$'), '');
  return update(normalizedFormat, value);
}

bool _apiIsTrailingQuestionDecimalIntegerFormat(String format, num value) {
  return value.isFinite &&
      value == value.roundToDouble() &&
      RegExp(r'^[#0?]+\.\?+$').hasMatch(format);
}

String _apiFormatTrailingQuestionDecimalInteger(String format, num value) {
  final parts = format.split('.');
  final rounded = value.round();
  final sign = rounded < 0 ? '-' : '';
  if (rounded < 0 && RegExp(r'^[#?]+$').hasMatch(parts.first)) {
    final integerText = _apiFormatSimplePlaceholderInteger(
      parts.first,
      '$rounded',
    );
    return '$integerText.${' ' * parts.last.length}';
  }
  final integerText = _apiFormatSimplePlaceholderInteger(
    parts.first,
    rounded.abs().toString(),
  );
  return '$sign$integerText.${' ' * parts.last.length}';
}

bool _apiIsZeroOptionalDecimalIntegerFormat(String format, num value) {
  return value.isFinite &&
      value == value.roundToDouble() &&
      RegExp(r'^0+\.#+$').hasMatch(format);
}

String _apiFormatZeroOptionalDecimalInteger(String format, num value) {
  final rounded = value.round();
  return '$rounded.';
}

bool _apiIsPlainTrailingDotIntegerFormat(String format, num value) {
  return value.isFinite &&
      value == value.roundToDouble() &&
      RegExp(r'^[#0?]+\.$').hasMatch(format);
}

String _apiFormatPlainTrailingDotInteger(String format, num value) {
  final integerFormat = format.substring(0, format.length - 1);
  final rounded = value.round();
  final sign = rounded < 0 ? '-' : '';
  if (rounded < 0 && RegExp(r'^[#?]+$').hasMatch(integerFormat)) {
    final integerText = _apiFormatSimplePlaceholderInteger(
      integerFormat,
      '$rounded',
    );
    return '$integerText.';
  }
  final integerText = _apiFormatSimplePlaceholderInteger(
    integerFormat,
    rounded.abs().toString(),
  );
  return '$sign$integerText.';
}

bool _apiIsSimplePlaceholderNumberFormat(String format) {
  return RegExp(r'^[#0?]+(\.[#0]+)?$').hasMatch(format);
}

bool _apiIsQuestionLiteralNumberFormat(String format) {
  return format.contains('?') && !RegExp(r'[#0]').hasMatch(format);
}

String _apiFormatQuestionLiteralNumber(String format, num value) {
  final parts = <String>[];
  final questionIndexes = <int>[];
  var index = 0;
  while (index < format.length) {
    if (format[index] == '"') {
      index += 1;
      while (index < format.length && format[index] != '"') {
        parts.add(format[index]);
        index += 1;
      }
      if (index < format.length) {
        index += 1;
      }
      continue;
    }
    if (format[index] == r'\') {
      if (index + 1 < format.length) {
        parts.add(format[index + 1]);
        index += 2;
      } else {
        index += 1;
      }
      continue;
    }
    if (format[index] == '_') {
      parts.add(' ');
      index += index + 1 < format.length ? 2 : 1;
      continue;
    }
    if (format[index] == '*') {
      index = _apiAdvanceStarFillToken(format, index);
      continue;
    }
    if (format[index] == '?') {
      questionIndexes.add(parts.length);
      parts.add(' ');
      index += 1;
      continue;
    }
    parts.add(format[index]);
    index += 1;
  }
  final rounded = value.round();
  if (rounded == 0 || questionIndexes.isEmpty) {
    return parts.join();
  }
  final digits = rounded.abs().toString();
  var digitIndex = digits.length - 1;
  for (var index = questionIndexes.length - 1; index >= 0; index -= 1) {
    if (digitIndex < 0) {
      break;
    }
    parts[questionIndexes[index]] = digits[digitIndex];
    digitIndex -= 1;
  }
  if (digitIndex >= 0) {
    parts.insert(questionIndexes.first, digits.substring(0, digitIndex + 1));
  }
  if (rounded < 0) {
    parts.insert(questionIndexes.first, '-');
  }
  return parts.join();
}

String _apiFormatSimplePlaceholderNumber(String format, num value) {
  final match = RegExp(r'^([#0?]+)(?:\.([#0]+))?$').firstMatch(format);
  if (match == null) {
    return _apiFormatNumericWithLiterals(format, value);
  }
  final integerFormat = match.group(1)!;
  final decimalFormat = match.group(2);
  final decimalDigits = _apiFormatDecimalPlaceRange(format);
  final numericText = _apiGenerateFormatFixed(
    value.abs(),
    decimalDigits.max,
    useThousands: false,
    minDecimalLength: decimalDigits.min,
  );
  final parts = numericText.split('.');
  final paddedInteger = _apiApplyPlaceholderPadding(integerFormat, parts.first);
  final sign = value < 0 ? '-' : '';
  if (decimalFormat == null || parts.length == 1) {
    if (value < 0 &&
        RegExp(r'^[#?]+$').hasMatch(integerFormat) &&
        parts.first == '0') {
      return _apiFormatSimplePlaceholderInteger(integerFormat, parts.first);
    }
    if (value < 0 && RegExp(r'^[#?]+$').hasMatch(integerFormat)) {
      return _apiFormatSimplePlaceholderInteger(
        integerFormat,
        '-${parts.first}',
      );
    }
    return '$sign${_apiFormatSimplePlaceholderInteger(integerFormat, parts.first)}';
  }
  if (value < 0 && RegExp(r'^[#?]+$').hasMatch(integerFormat)) {
    final signedInteger = _apiApplyPlaceholderPadding(
      integerFormat,
      '-${parts.first}',
    );
    return '$signedInteger.${parts[1]}';
  }
  return '$sign$paddedInteger.${parts[1]}';
}

String _apiFormatSimplePlaceholderInteger(String placeholders, String digits) {
  if (RegExp(r'^[#?]+$').hasMatch(placeholders) && digits == '0') {
    return placeholders.replaceAll('#', '').replaceAll('?', ' ');
  }
  final zeroStart = placeholders.indexOf('0');
  if (zeroStart > 0 && RegExp(r'^#+0+$').hasMatch(placeholders)) {
    final width = placeholders.length - zeroStart;
    return digits.padLeft(width, '0');
  }
  return _apiApplyPlaceholderPadding(placeholders, digits);
}

String _apiApplyPlaceholderPadding(String placeholders, String digits) {
  if (digits.length >= placeholders.length) {
    return digits;
  }
  final prefix = placeholders
      .substring(0, placeholders.length - digits.length)
      .replaceAll('#', '')
      .replaceAll('?', ' ');
  return '$prefix$digits';
}

String _apiFormatFractionNumber(String format, num value) {
  final match = RegExp(r'([#0?]+)( ?)\/( ?)([#0?]+)').firstMatch(format);
  if (match == null) {
    return '$value';
  }
  final numeratorPlaceholders = match.group(1)!;
  final beforeSlash = match.group(2)!;
  final afterSlash = match.group(3)!;
  final denominatorPlaceholders = match.group(4)!;
  final hasWholePart =
      format.substring(0, match.start).contains('#') ||
      format.substring(0, match.start).contains('0');
  final fractionWidth = hasWholePart
      ? math.min(
          math.max(
            numeratorPlaceholders.length,
            denominatorPlaceholders.length,
          ),
          7,
        )
      : math.min(denominatorPlaceholders.length, 7);
  final maxDenominator = math.pow(10, fractionWidth).toInt() - 1;
  final sign = value < 0 ? '-' : '';
  final fractionParts = _apiApproximateFraction(
    value.abs().toDouble(),
    maxDenominator,
    mixed: hasWholePart,
  );
  final displayWhole = fractionParts[0];
  final bestNumerator = fractionParts[1];
  final bestDenominator = fractionParts[2];
  if (bestNumerator == 0 && hasWholePart) {
    final blankWidth =
        2 * fractionWidth + 1 + beforeSlash.length + afterSlash.length;
    return '$sign$displayWhole ${' ' * blankWidth}';
  }
  final numeratorText = hasWholePart
      ? '$bestNumerator'.padLeft(fractionWidth)
      : _apiApplyPlaceholderPadding(numeratorPlaceholders, '$bestNumerator');
  final denominatorText = '$bestDenominator'.padRight(fractionWidth);
  final fractionText = '$numeratorText$beforeSlash/$afterSlash$denominatorText';
  if (!hasWholePart) {
    return '$sign$fractionText';
  }
  final wholeText = displayWhole == 0 ? '' : '$displayWhole';
  return '$sign$wholeText $fractionText';
}

List<int> _apiApproximateFraction(
  double value,
  int maxDenominator, {
  required bool mixed,
}) {
  var remaining = value;
  var previousNumerator2 = 0;
  var previousNumerator1 = 1;
  var numerator = 0;
  var previousDenominator2 = 1;
  var previousDenominator1 = 0;
  var denominator = 0;
  while (previousDenominator1 < maxDenominator) {
    final whole = remaining.floor();
    numerator = whole * previousNumerator1 + previousNumerator2;
    denominator = whole * previousDenominator1 + previousDenominator2;
    if (remaining - whole < 0.00000005) {
      break;
    }
    remaining = 1 / (remaining - whole);
    previousNumerator2 = previousNumerator1;
    previousNumerator1 = numerator;
    previousDenominator2 = previousDenominator1;
    previousDenominator1 = denominator;
  }
  if (denominator > maxDenominator) {
    if (previousDenominator1 > maxDenominator) {
      denominator = previousDenominator2;
      numerator = previousNumerator2;
    } else {
      denominator = previousDenominator1;
      numerator = previousNumerator1;
    }
  }
  if (!mixed) {
    return <int>[0, numerator, denominator];
  }
  final whole = numerator ~/ denominator;
  return <int>[whole, numerator - whole * denominator, denominator];
}

List<String> _apiSplitFormatSections(String format) {
  final sections = <String>[];
  final current = StringBuffer();
  var inQuote = false;
  var index = 0;
  while (index < format.length) {
    final char = format[index];
    if (char == r'\') {
      current.write(char);
      if (index + 1 < format.length) {
        index += 1;
        current.write(format[index]);
      }
      index += 1;
      continue;
    }
    if (char == '_' || char == '*') {
      current.write(char);
      if (index + 1 < format.length) {
        index += 1;
        current.write(format[index]);
      }
      index += 1;
      continue;
    }
    if (char == '"') {
      inQuote = !inQuote;
      current.write(char);
      index += 1;
      continue;
    }
    if (char == ';') {
      sections.add(current.toString());
      current.clear();
      index += 1;
      continue;
    }
    current.write(char);
    index += 1;
  }
  sections.add(current.toString());
  if (inQuote) {
    throw FormatException('Format |$format| unterminated string');
  }
  return sections;
}

String _apiStripNumericBracketDirectives(String format) {
  final result = StringBuffer();
  final isDateFormat = is_date(format);
  var index = 0;
  while (index < format.length) {
    if (format[index] != '[') {
      result.write(format[index]);
      index += 1;
      continue;
    }
    final end = format.indexOf(']', index + 1);
    if (end < 0) {
      throw FormatException(
        'unterminated "[" block: |${format.substring(index)}|',
      );
    }
    final token = format.substring(index + 1, end);
    if (RegExp(r'^[hms]+$', caseSensitive: false).hasMatch(token)) {
      result.write(format.substring(index, end + 1));
    } else if (token.startsWith(r'$') && !isDateFormat) {
      final currency = RegExp(r'^\$([^\-\[\]]*)').firstMatch(token)?.group(1);
      result.write(currency == null || currency.isEmpty ? r'$' : currency);
    }
    index = end + 1;
  }
  return result.toString();
}

String _apiFormatTextSection(String format, String value) {
  final result = StringBuffer();
  var index = 0;
  while (index < format.length) {
    if (format[index] == '"') {
      index += 1;
      while (index < format.length && format[index] != '"') {
        result.write(format[index]);
        index += 1;
      }
      if (index < format.length) {
        index += 1;
      }
      continue;
    }
    if (format[index] == r'\') {
      if (index + 1 < format.length) {
        result.write(format[index + 1]);
        index += 2;
      } else {
        index += 1;
      }
      continue;
    }
    if (format[index] == '_') {
      result.write(' ');
      index += index + 1 < format.length ? 2 : 1;
      continue;
    }
    if (format[index] == '*') {
      index = _apiAdvanceStarFillToken(format, index);
      continue;
    }
    if (format[index] == '[') {
      final end = format.indexOf(']', index + 1);
      if (end < 0) {
        throw FormatException(
          'unterminated "[" block: |${format.substring(index)}|',
        );
      }
      final token = format.substring(index + 1, end);
      if (token.contains(r'$')) {
        final currency = RegExp(r'\$([^\-\[\]]*)').firstMatch(token)?.group(1);
        result.write(currency == null || currency.isEmpty ? r'$' : currency);
      }
      index = end + 1;
      continue;
    }
    if (format[index] == '@') {
      result.write(value);
      index += 1;
      continue;
    }
    result.write(format[index]);
    index += 1;
  }
  return result.toString();
}

num? _apiGenerateNumericValue(String value) {
  return num.tryParse(value.replaceAll(',', ''));
}

int _apiFormatDecimalPlaces(String format) {
  final decimal = format.indexOf('.');
  if (decimal < 0) {
    return 0;
  }
  var count = 0;
  for (var index = decimal + 1; index < format.length; index += 1) {
    final char = format[index];
    if (char == '0' || char == '#') {
      count += 1;
    } else {
      break;
    }
  }
  return count;
}

int _apiFormatDecimalPlacesBefore(String format, String marker) {
  final markerIndex = format.toUpperCase().indexOf(marker.toUpperCase());
  final head = markerIndex < 0 ? format : format.substring(0, markerIndex);
  return _apiFormatDecimalPlaces(head);
}

({int min, int max}) _apiFormatDecimalPlaceRange(String format) {
  final decimal = format.indexOf('.');
  if (decimal < 0) {
    return (min: 0, max: 0);
  }
  var min = 0;
  var max = 0;
  for (var index = decimal + 1; index < format.length; index += 1) {
    final char = format[index];
    if (char == '0') {
      min += 1;
      max += 1;
    } else if (char == '#') {
      max += 1;
    } else {
      break;
    }
  }
  return (min: min, max: max);
}

({int min, int max}) _apiFormatDecimalPlaceRangeBefore(
  String format,
  String marker,
) {
  final markerIndex = format.toUpperCase().indexOf(marker.toUpperCase());
  final head = markerIndex < 0 ? format : format.substring(0, markerIndex);
  return _apiFormatDecimalPlaceRange(head);
}

String _apiFormatNumericWithLiterals(String format, num value) {
  return _apiFormatNumericWithLiteralDigits(
    format,
    value,
    decimalDigits: _apiFormatDecimalPlaceRange(format),
  );
}

String _apiFormatNumericWithLiteralDigits(
  String format,
  num value, {
  required ({int min, int max}) decimalDigits,
}) {
  final firstNumeric = format.indexOf(RegExp(r'[#0]'));
  if (firstNumeric < 0) {
    return '$value';
  }
  var lastNumeric = firstNumeric;
  for (var index = firstNumeric + 1; index < format.length; index += 1) {
    if (format[index] == '#' || format[index] == '0') {
      lastNumeric = index;
    }
  }
  var scaleCommas = 0;
  var suffixStart = lastNumeric + 1;
  while (suffixStart < format.length && format[suffixStart] == ',') {
    scaleCommas += 1;
    suffixStart += 1;
  }
  final scaledValue = scaleCommas == 0
      ? value
      : value / math.pow(1000, scaleCommas);
  final prefix = _apiFormatLiteralSegment(format.substring(0, firstNumeric));
  final suffix = _apiFormatLiteralSegment(format.substring(suffixStart));
  final numericText = _apiGenerateFormatFixed(
    scaledValue,
    decimalDigits.max,
    useThousands: format.contains(','),
    minDecimalLength: decimalDigits.min,
  );
  return '$prefix$numericText$suffix';
}

String _apiFormatScientificWithLiterals(
  String format,
  num value,
  int decimalDigits,
) {
  final firstNumeric = format.indexOf(RegExp(r'[#0]'));
  if (firstNumeric < 0) {
    return _apiGenerateFormatScientific(value, decimalDigits);
  }
  final upperFormat = format.toUpperCase();
  final exponentMatch = RegExp(r'E[+-]0+').firstMatch(upperFormat);
  final exponentIndex = exponentMatch?.start ?? -1;
  if (exponentIndex < 0) {
    return _apiGenerateFormatScientific(value, decimalDigits);
  }
  final forcePositiveSign = upperFormat[exponentIndex + 1] == '+';
  final exponentEnd = exponentMatch!.end;
  final prefix = _apiFormatLiteralSegment(format.substring(0, firstNumeric));
  final suffix = _apiFormatLiteralSegment(format.substring(exponentEnd));
  return '$prefix${_apiGenerateFormatScientific(value, decimalDigits, forcePositiveSign: forcePositiveSign)}$suffix';
}

String _apiFormatLiteralSegment(String segment) {
  final result = StringBuffer();
  var index = 0;
  while (index < segment.length) {
    if (segment[index] == '"') {
      index += 1;
      while (index < segment.length && segment[index] != '"') {
        result.write(segment[index]);
        index += 1;
      }
      if (index < segment.length) {
        index += 1;
      }
      continue;
    }
    if (segment[index] == r'\') {
      if (index + 1 < segment.length) {
        result.write(segment[index + 1]);
        index += 2;
      } else {
        index += 1;
      }
      continue;
    }
    if (segment[index] == '_') {
      result.write(' ');
      index += index + 1 < segment.length ? 2 : 1;
      continue;
    }
    if (segment[index] == '*') {
      index = _apiAdvanceStarFillToken(segment, index);
      continue;
    }
    result.write(segment[index]);
    index += 1;
  }
  return result.toString();
}

int _apiAdvanceStarFillToken(String format, int index) {
  var next = index + 1;
  if (next < format.length && (format[next] == ' ' || format[next] == '*')) {
    next += 1;
  }
  return next;
}

bool _apiDateSerialOutOfRange(num serial) {
  return serial < 1 || serial > 2958465;
}

bool _apiDateFormatHasAbsoluteTime(String format) {
  var index = 0;
  while (index < format.length) {
    final char = format[index];
    if (char == '"') {
      index += 1;
      while (index < format.length && format[index] != '"') {
        index += 1;
      }
      index += index < format.length ? 1 : 0;
      continue;
    }
    if (char == r'\') {
      index += index + 1 < format.length ? 2 : 1;
      continue;
    }
    if (char == '[') {
      final end = format.indexOf(']', index + 1);
      if (end < 0) {
        return false;
      }
      final token = format.substring(index + 1, end).toLowerCase();
      if (token.isNotEmpty && RegExp(r'^[hms]+$').hasMatch(token)) {
        return true;
      }
      index = end + 1;
      continue;
    }
    index += 1;
  }
  return false;
}

bool _apiDateFormatReturnsBlankWhenOutOfRange(String format) {
  var index = 0;
  while (index < format.length) {
    final char = format[index];
    if (char == '"') {
      index += 1;
      while (index < format.length && format[index] != '"') {
        index += 1;
      }
      index += index < format.length ? 1 : 0;
      continue;
    }
    if (char == r'\') {
      index += index + 1 < format.length ? 2 : 1;
      continue;
    }
    final marker = format.substring(index).toUpperCase();
    if (marker.startsWith('AM/PM') ||
        marker.startsWith('A/P') ||
        format.substring(index).startsWith('上午/下午')) {
      return true;
    }
    if ((char == 'B' || char == 'b') &&
        index + 1 < format.length &&
        (format[index + 1] == '1' || format[index + 1] == '2')) {
      return true;
    }
    index += 1;
  }
  return false;
}

bool _apiDateFormatRequiresParsedDate(String format) {
  String? nearestTokenBefore(int offset) {
    var cursor = offset - 1;
    while (cursor >= 0) {
      final char = format[cursor];
      final lower = char.toLowerCase();
      if ('ymdhsbeg'.contains(lower)) {
        return lower;
      }
      if (char == ']') {
        final start = format.lastIndexOf('[', cursor - 1);
        cursor = start < 0 ? -1 : start - 1;
        continue;
      }
      if (char == '"') {
        final start = format.lastIndexOf('"', cursor - 1);
        cursor = start < 0 ? -1 : start - 1;
        continue;
      }
      if (cursor > 0 && format[cursor - 1] == r'\') {
        cursor -= 2;
        continue;
      }
      cursor -= 1;
    }
    return null;
  }

  String? nearestTokenAfter(int offset) {
    var cursor = offset;
    while (cursor < format.length) {
      final char = format[cursor];
      final lower = char.toLowerCase();
      if ('ymdhsbeg'.contains(lower)) {
        return lower;
      }
      if (char == '[') {
        final end = format.indexOf(']', cursor + 1);
        cursor = end < 0 ? format.length : end + 1;
        continue;
      }
      if (char == '"') {
        final end = format.indexOf('"', cursor + 1);
        cursor = end < 0 ? format.length : end + 1;
        continue;
      }
      if (char == r'\') {
        cursor += 2;
        continue;
      }
      cursor += 1;
    }
    return null;
  }

  var index = 0;
  while (index < format.length) {
    final char = format[index];
    if (char == '"') {
      index += 1;
      while (index < format.length && format[index] != '"') {
        index += 1;
      }
      index += index < format.length ? 1 : 0;
      continue;
    }
    if (char == r'\') {
      index += index + 1 < format.length ? 2 : 1;
      continue;
    }
    if (char == '[') {
      final end = format.indexOf(']', index + 1);
      if (end < 0) {
        return false;
      }
      index = end + 1;
      continue;
    }
    final lower = char.toLowerCase();
    if ('ydeg'.contains(lower)) {
      return true;
    }
    var end = index + 1;
    while (end < format.length && format[end].toLowerCase() == lower) {
      end += 1;
    }
    if (lower == 'm') {
      final before = index > 0 ? format[index - 1] : '';
      final after = end < format.length ? format[end] : '';
      final isMinute =
          before == ':' ||
          after == ':' ||
          nearestTokenBefore(index) == 'h' ||
          nearestTokenAfter(end) == 's';
      if (!isMinute) {
        return true;
      }
    }
    index = end;
  }
  return false;
}

class _ApiDateParts {
  const _ApiDateParts({
    required this.year,
    required this.month,
    required this.day,
    required this.hour,
    required this.minute,
    required this.second,
    required this.weekday,
  });

  factory _ApiDateParts.fromDateTime(DateTime date) {
    return _ApiDateParts(
      year: date.year,
      month: date.month,
      day: date.day,
      hour: date.hour,
      minute: date.minute,
      second: date.second,
      weekday: date.weekday,
    );
  }

  final int year;
  final int month;
  final int day;
  final int hour;
  final int minute;
  final int second;
  final int weekday;
}

_ApiDateParts _apiDatePartsFromSerial(num serial) {
  final wholeDays = serial.floor();
  final fraction = serial - wholeDays;
  final seconds = (fraction * Duration.secondsPerDay).round();
  final hour = seconds ~/ Duration.secondsPerHour;
  final minute =
      seconds.remainder(Duration.secondsPerHour) ~/ Duration.secondsPerMinute;
  final second = seconds.remainder(Duration.secondsPerMinute);
  if (wholeDays == 60) {
    return _ApiDateParts(
      year: 1900,
      month: 2,
      day: 29,
      hour: hour,
      minute: minute,
      second: second,
      weekday: DateTime.wednesday,
    );
  }
  var date = DateTime.utc(1899, 12, 31).add(Duration(days: wholeDays));
  if (serial >= 60) {
    date = date.subtract(const Duration(days: 1));
  }
  date = date.add(Duration(seconds: seconds));
  return _ApiDateParts.fromDateTime(date);
}

int _apiGenerateScientificDigits(num value) {
  final exponent = value.toStringAsExponential();
  final fraction = exponent.contains('.')
      ? exponent.split('.')[1].split('e')[0]
      : '';
  return math.min(fraction.length, 5);
}

String _apiGenerateFormatScientific(
  num value,
  int decimalDigits, {
  bool forcePositiveSign = true,
}) {
  final parts = value.toStringAsExponential(decimalDigits).split('e');
  final exponent = int.parse(parts[1]);
  final sign = exponent < 0
      ? '-'
      : forcePositiveSign
      ? '+'
      : '';
  final exponentText = exponent.abs().toString().padLeft(2, '0');
  return '${parts[0]}E$sign$exponentText';
}

Map<String, Object?>? _apiGeneratePercent(String text) {
  final percentIndex = text.indexOf('%');
  if (percentIndex != text.length - 1) {
    return null;
  }
  final valueText = text.substring(0, percentIndex);
  final normalized = valueText.replaceAll(',', '');
  final number = num.tryParse(normalized);
  if (number == null || !_apiGenerateHasValidThousands(valueText)) {
    return null;
  }
  final decimalLength = valueText.contains('.')
      ? math.min(valueText.split('.').last.length, 9)
      : 0;
  final hasDecimalPoint = valueText.contains('.');
  final formatPrefix = valueText.split('.').first.contains(',') ? '#,##0' : '0';
  final format = hasDecimalPoint
      ? '$formatPrefix.${'0' * decimalLength}%'
      : '$formatPrefix%';
  return {
    'value': number / 100,
    'format': format,
    'decimalLength': decimalLength,
    'trailingDecimal': hasDecimalPoint && decimalLength == 0,
    'useThousands': valueText.split('.').first.contains(','),
  };
}

Map<String, Object?>? _apiGenerateDecimal(String text) {
  if (text.indexOf('.') != text.lastIndexOf('.')) {
    return null;
  }
  final parts = text.split('.');
  if (parts.length != 2) {
    return null;
  }
  final integerPart = parts[0];
  final decimalPart = parts[1];
  final hasTrailingDecimal = decimalPart.isEmpty;
  if ((hasTrailingDecimal && !integerPart.contains(',')) ||
      !_apiGenerateHasValidThousands(integerPart)) {
    return null;
  }
  final number = _apiGenerateNumericValue(text);
  if (number == null) {
    return null;
  }
  final decimalLength = math.min(decimalPart.length, 9);
  final formatPrefix = integerPart.contains(',') ? '#,##0' : '0';
  return {
    'value': number,
    'format': '$formatPrefix.${'0' * decimalLength}',
    'decimalLength': decimalLength,
    'trailingDecimal': hasTrailingDecimal,
    'useThousands': integerPart.contains(','),
  };
}

String _apiGenerateFormatFixed(
  num value,
  int decimalLength, {
  required bool useThousands,
  int? minDecimalLength,
}) {
  final minDecimals = math.min(
    minDecimalLength ?? decimalLength,
    decimalLength,
  );
  var text = value.toStringAsFixed(decimalLength);
  if (decimalLength > minDecimals && text.contains('.')) {
    final parts = text.split('.');
    var fraction = parts[1];
    while (fraction.length > minDecimals && fraction.endsWith('0')) {
      fraction = fraction.substring(0, fraction.length - 1);
    }
    text = fraction.isEmpty ? parts[0] : '${parts[0]}.$fraction';
  }
  if (!useThousands) {
    return text;
  }
  final parts = text.split('.');
  var integerPart = parts[0];
  final sign = integerPart.startsWith('-') ? '-' : '';
  if (sign.isNotEmpty) {
    integerPart = integerPart.substring(1);
  }
  final buffer = StringBuffer();
  for (var index = 0; index < integerPart.length; index += 1) {
    if (index > 0 && (integerPart.length - index) % 3 == 0) {
      buffer.write(',');
    }
    buffer.write(integerPart[index]);
  }
  return ['$sign$buffer', if (parts.length > 1) parts[1]].join('.');
}

bool _apiGenerateHasValidThousands(String text) {
  if (!text.contains(',')) {
    return true;
  }
  final unsigned = text.startsWith('-') ? text.substring(1) : text;
  final parts = unsigned.split(',');
  if (parts.first.isEmpty) {
    return false;
  }
  for (var index = 1; index < parts.length; index += 1) {
    if (parts[index].length < 3 || num.tryParse(parts[index]) == null) {
      return false;
    }
  }
  return true;
}

Map<String, Object?>? _apiGenerateDatePayload(String text) {
  final is24HourDate =
      isdatetime(text, '24') &&
      (text.contains('.') || text.contains(':') || text.length < 16);
  final is12HourDate =
      !is24HourDate &&
      isdatetime(text, '12') &&
      (text.contains('.') || text.contains(':') || text.length < 20);
  final isoDate = !is24HourDate && !is12HourDate
      ? _apiGenerateParseIsoUtcDate(text)
      : null;
  if (!is24HourDate && !is12HourDate && isoDate == null) {
    return null;
  }
  final parsedDate =
      isoDate ?? _apiGenerateParseDate(text, is12HourDate: is12HourDate);
  if (parsedDate == null) {
    return null;
  }
  final serial = datenumLocal(parsedDate);
  var format = 'yyyy-MM-dd';
  if (serial.toString().contains('.')) {
    if (is12HourDate) {
      if (text.length > 20) {
        format = 'yyyy-MM-dd hh:mm:ss AM/PM';
      } else if (text.length > 13) {
        format = 'yyyy-MM-dd hh:mm AM/PM';
      }
    } else if (text.length > 18) {
      format = 'yyyy-MM-dd hh:mm:ss';
    } else if (text.length > 11) {
      format = 'yyyy-MM-dd hh:mm';
    }
  }
  return {
    'value': serial,
    'format': format,
    'display': _apiGenerateFormatDate(parsedDate, format, serial: serial),
  };
}

DateTime? _apiGenerateParseIsoUtcDate(String text) {
  final trimmed = text.trim();
  if (!RegExp(
    r'^\d{4}-\d{1,2}-\d{1,2}T\d{1,2}:\d{1,2}(?::\d{1,2}(?:\.\d+)?)?Z$',
  ).hasMatch(trimmed)) {
    return null;
  }
  return DateTime.tryParse(trimmed);
}

String _apiGenerateFormatDate(Object dateValue, String format, {num? serial}) {
  final date = dateValue is _ApiDateParts
      ? dateValue
      : _ApiDateParts.fromDateTime(dateValue as DateTime);
  const monthShort = [
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ];
  const monthLong = [
    'January',
    'February',
    'March',
    'April',
    'May',
    'June',
    'July',
    'August',
    'September',
    'October',
    'November',
    'December',
  ];
  const weekdayShort = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
  const weekdayLong = [
    'Monday',
    'Tuesday',
    'Wednesday',
    'Thursday',
    'Friday',
    'Saturday',
    'Sunday',
  ];
  String two(int value) => value.toString().padLeft(2, '0');
  String formatNumber(int value, int length) {
    return length == 1 ? '$value' : two(value);
  }

  String? nearestDateTokenBefore(int offset) {
    var cursor = offset - 1;
    while (cursor >= 0) {
      final char = format[cursor];
      final lower = char.toLowerCase();
      if ('ymdhsbeg'.contains(lower)) {
        return lower;
      }
      if (char == ']') {
        final start = format.lastIndexOf('[', cursor - 1);
        if (start < 0) {
          return null;
        }
        cursor = start - 1;
        continue;
      }
      if (char == '"') {
        final start = format.lastIndexOf('"', cursor - 1);
        if (start < 0) {
          return null;
        }
        cursor = start - 1;
        continue;
      }
      if (cursor > 0 && format[cursor - 1] == r'\') {
        cursor -= 2;
        continue;
      }
      cursor -= 1;
    }
    return null;
  }

  String? nearestDateTokenAfter(int offset) {
    var cursor = offset;
    while (cursor < format.length) {
      final char = format[cursor];
      final lower = char.toLowerCase();
      if ('ymdhsbeg'.contains(lower)) {
        return lower;
      }
      if (char == '[') {
        final end = format.indexOf(']', cursor + 1);
        if (end < 0) {
          return null;
        }
        cursor = end + 1;
        continue;
      }
      if (char == '"') {
        final end = format.indexOf('"', cursor + 1);
        if (end < 0) {
          return null;
        }
        cursor = end + 1;
        continue;
      }
      if (char == r'\') {
        cursor += 2;
        continue;
      }
      cursor += 1;
    }
    return null;
  }

  var result = StringBuffer();
  var index = 0;
  while (index < format.length) {
    final marker = format.substring(index).toUpperCase();
    if (format[index] == '"') {
      index += 1;
      while (index < format.length && format[index] != '"') {
        result.write(format[index]);
        index += 1;
      }
      if (index < format.length) {
        index += 1;
      }
      continue;
    }
    if (format[index] == r'\') {
      if (index + 1 < format.length) {
        result.write(format[index + 1]);
        index += 2;
      } else {
        index += 1;
      }
      continue;
    }
    if (format[index] == '_') {
      result.write(' ');
      index += index + 1 < format.length ? 2 : 1;
      continue;
    }
    if (format[index] == '*') {
      index = _apiAdvanceStarFillToken(format, index);
      continue;
    }
    if (format[index] == '[') {
      final end = format.indexOf(']', index + 1);
      if (end < 0) {
        throw FormatException(
          'unterminated "[" block: |${format.substring(index)}|',
        );
      }
      final token = format.substring(index + 1, end);
      final elapsed = _apiFormatElapsedDateToken(serial, token);
      if (elapsed != null) {
        result.write(elapsed);
        index = end + 1;
        continue;
      }
    }
    if (marker.startsWith('AM/PM')) {
      result.write(date.hour >= 12 ? 'PM' : 'AM');
      index += 5;
      continue;
    }
    if (marker.startsWith('A/P')) {
      result.write(date.hour >= 12 ? 'P' : 'A');
      index += 3;
      continue;
    }
    if (format.substring(index).startsWith('上午/下午')) {
      result.write(date.hour >= 12 ? '下午' : '上午');
      index += 5;
      continue;
    }
    if ((format[index] == 'B' || format[index] == 'b') &&
        index + 1 < format.length &&
        (format[index + 1] == '1' || format[index + 1] == '2')) {
      index += 2;
      continue;
    }

    final char = format[index];
    final lower = char.toLowerCase();
    if (!'ymdhsbeg'.contains(lower)) {
      result.write(char);
      index += 1;
      continue;
    }

    var end = index + 1;
    while (end < format.length && format[end].toLowerCase() == lower) {
      end += 1;
    }
    final length = end - index;
    final before = index > 0 ? format[index - 1] : '';
    final after = end < format.length ? format[end] : '';
    final isMinute =
        lower == 'm' &&
        (before == ':' ||
            after == ':' ||
            nearestDateTokenBefore(index) == 'h' ||
            nearestDateTokenAfter(end) == 's');
    switch (lower) {
      case 'y':
        result.write(
          length <= 2
              ? (date.year % 100).toString().padLeft(2, '0')
              : date.year.toString().padLeft(4, '0'),
        );
      case 'b':
        final year = date.year + 543;
        result.write(
          length <= 2
              ? (year % 100).toString().padLeft(2, '0')
              : year.toString().padLeft(4, '0'),
        );
      case 'e':
        result.write(date.year.toString());
      case 'g':
        break;
      case 'm':
        if (!isMinute && length == 5) {
          result.write(monthShort[date.month - 1][0]);
        } else if (!isMinute && length >= 4) {
          result.write(monthLong[date.month - 1]);
        } else if (!isMinute && length == 3) {
          result.write(monthShort[date.month - 1]);
        } else {
          result.write(
            formatNumber(isMinute ? date.minute : date.month, length),
          );
        }
      case 'd':
        if (length >= 4) {
          result.write(weekdayLong[date.weekday - 1]);
        } else if (length == 3) {
          result.write(weekdayShort[date.weekday - 1]);
        } else {
          result.write(formatNumber(date.day, length));
        }
      case 'h':
        final usesAmPm =
            format.toUpperCase().contains('AM/PM') ||
            format.toUpperCase().contains('A/P') ||
            format.contains('上午/下午');
        final hour = usesAmPm
            ? date.hour % 12 == 0
                  ? 12
                  : date.hour % 12
            : date.hour;
        result.write(formatNumber(hour, length));
      case 's':
        result.write(formatNumber(date.second, length));
        if (end < format.length && format[end] == '.') {
          var decimalEnd = end + 1;
          while (decimalEnd < format.length && format[decimalEnd] == '0') {
            decimalEnd += 1;
          }
          final decimalLength = decimalEnd - end - 1;
          if (decimalLength > 0) {
            result.write('.');
            result.write(_apiFormatFractionalSecond(serial, decimalLength));
            end = decimalEnd;
          }
        }
    }
    index = end;
  }
  return result.toString();
}

String _apiFormatFractionalSecond(num? serial, int length) {
  if (serial == null) {
    return ''.padLeft(length, '0');
  }
  final totalMilliseconds = (serial.abs() * Duration.millisecondsPerDay)
      .round();
  final milliseconds = totalMilliseconds % Duration.millisecondsPerSecond;
  final fraction = milliseconds.toString().padLeft(3, '0');
  if (length <= fraction.length) {
    return fraction.substring(0, length);
  }
  return fraction.padRight(length, '0');
}

String? _apiFormatElapsedDateToken(num? serial, String token) {
  if (serial == null || token.isEmpty) {
    return null;
  }
  final lower = token.toLowerCase();
  if (!RegExp(r'^[hms]+$').hasMatch(lower)) {
    return null;
  }
  final unit = lower[0];
  if (lower.codeUnits.any((code) => code != unit.codeUnitAt(0))) {
    return null;
  }
  final sign = serial < 0 ? '-' : '';
  final totalSeconds = (serial.abs() * Duration.secondsPerDay).round();
  final value = switch (unit) {
    'h' => totalSeconds ~/ Duration.secondsPerHour,
    'm' => totalSeconds ~/ Duration.secondsPerMinute,
    's' => totalSeconds,
    _ => null,
  };
  if (value == null) {
    return null;
  }
  return '$sign${value.toString().padLeft(token.length, '0')}';
}

DateTime? _apiGenerateParseDate(String text, {required bool is12HourDate}) {
  final match = RegExp(
    r'^(\d{4})[-/](\d{1,2})[-/](\d{1,2})(?:\s+(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?)?\s*(AM|PM)?$',
    caseSensitive: false,
  ).firstMatch(text.trim());
  if (match == null) {
    return DateTime.tryParse(text.replaceAll('/', '-'));
  }
  final year = int.parse(match.group(1)!);
  final month = int.parse(match.group(2)!);
  final day = int.parse(match.group(3)!);
  var hour = int.tryParse(match.group(4) ?? '') ?? 0;
  final minute = int.tryParse(match.group(5) ?? '') ?? 0;
  final second = int.tryParse(match.group(6) ?? '') ?? 0;
  final marker = match.group(7)?.toUpperCase();
  if (is12HourDate && marker != null) {
    if (marker == 'PM' && hour < 12) {
      hour += 12;
    } else if (marker == 'AM' && hour == 12) {
      hour = 0;
    }
  }
  return DateTime(year, month, day, hour, minute, second);
}

bool isRealNull(Object? value) {
  return value == null || '$value'.replaceAll(RegExp(r'\s'), '').isEmpty;
}

bool isRealNum(Object? value) {
  if (isRealNull(value) || value is bool) {
    return false;
  }
  return !_apiDataVerificationNumber(value).isNaN;
}

List<Object?> getDropdownList(String text, {FortuneSheet? sheet}) {
  final list = <Object?>[];
  if (iscelldata(text)) {
    final range = sheet == null ? null : _apiRangeFromText(text, sheet);
    if (range == null || sheet == null) {
      return list;
    }
    for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        final cell = sheet.cells[FortuneCellCoord(row, column)];
        final rawValue = cell?.hasRawValue == true
            ? cell?.rawValue
            : cell?.value;
        if (_apiDropdownValueIsFalsy(rawValue)) {
          continue;
        }
        final displayValue = cell?.hasRawDisplayValue == true
            ? cell?.rawDisplayValue
            : cell?.displayValue;
        final value = _apiDropdownValueIsFalsy(displayValue)
            ? rawValue
            : displayValue;
        if (!list.contains(value)) {
          list.add(value);
        }
      }
    }
  } else {
    for (final value in text.split(',')) {
      if (value.isEmpty || list.contains(value)) {
        continue;
      }
      list.add(value);
    }
  }
  return list;
}

bool _apiDropdownValueIsFalsy(Object? value) {
  return value == null || value == '' || value == false || value == 0;
}

FortuneSheet checkboxChange(FortuneSheet sheet, int row, int column) {
  final key = '${row}_$column';
  final item = sheet.dataVerification[key];
  if (item is! Map) {
    return sheet.copyWith();
  }
  final nextItem = <String, Object?>{
    for (final entry in item.entries)
      '${entry.key}': cloneFortuneMetadata(entry.value),
  };
  final checked = !_apiJsTruthy(nextItem['checked']);
  nextItem['checked'] = checked;
  final nextDataVerification = _cloneStringObjectMap(sheet.dataVerification);
  nextDataVerification[key] = nextItem;
  final nextValue = checked ? nextItem['value1'] : nextItem['value2'];
  return setCellValue(
    sheet.copyWith(dataVerification: nextDataVerification),
    row,
    column,
    nextValue,
  );
}

Map<String, Object?>? cellFocus(
  FortuneSheet sheet,
  int row,
  int column, {
  bool clickMode = false,
  bool allowEdit = true,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  String lang = 'en',
}) {
  if (!allowEdit) {
    return null;
  }
  final item = sheet.dataVerification['${row}_$column'];
  if (item is! Map) {
    return {
      'sheet': sheet.copyWith(),
      'dataVerificationDropDownList': false,
      'showHintBox': {'display': 'none'},
      'dropDownButton': {'display': 'none'},
    };
  }
  var nextSheet = sheet.copyWith();
  if (clickMode && item['type'] == 'checkbox') {
    nextSheet = checkboxChange(sheet, row, column);
  }
  var rowEnd = row < visibleDataRows.length ? visibleDataRows[row] : 0;
  var rowPre = row == 0 || row - 1 >= visibleDataRows.length
      ? 0
      : visibleDataRows[row - 1];
  var columnEnd = column < visibleDataColumns.length
      ? visibleDataColumns[column]
      : 0;
  var columnPre = column == 0 || column - 1 >= visibleDataColumns.length
      ? 0
      : visibleDataColumns[column - 1];
  final merge = mergeBorder(
    sheet,
    row,
    column,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
  );
  if (merge != null) {
    final mergeRow = merge['row'];
    final mergeColumn = merge['column'];
    if (mergeRow is List && mergeRow.length >= 2) {
      rowPre = _nullableDoubleArg(mergeRow[0]) ?? rowPre;
      rowEnd = _nullableDoubleArg(mergeRow[1]) ?? rowEnd;
    }
    if (mergeColumn is List && mergeColumn.length >= 2) {
      columnPre = _nullableDoubleArg(mergeColumn[0]) ?? columnPre;
      columnEnd = _nullableDoubleArg(mergeColumn[1]) ?? columnEnd;
    }
  }
  final dropDownButton = item['type'] == 'dropdown'
      ? <String, Object?>{
          'display': 'block',
          'maxWidth': '${columnEnd - columnPre}px',
          'maxHeight': '${rowEnd - rowPre}px',
          'left': '${columnEnd - 20}px',
          'top': '${rowPre + (rowEnd - rowPre - 20) / 2 - 2}px',
        }
      : const <String, Object?>{'display': 'none'};
  Map<String, Object?> showHintBox = const {'display': 'none'};
  if (item['hintShow'] == true) {
    showHintBox = {
      'display': 'block',
      'left': '${columnPre}px',
      'top': '${rowEnd}px',
      'html':
          '${_apiDataVerificationFocusPrefix(lang, true)}${getHintText(Map<String, Object?>.from(item), lang: lang)}',
    };
  }
  final cellValue = sheet.getCellValue(row, column);
  if (!isRealNull(cellValue) &&
      !validateCellData(
        Map<String, Object?>.from(item),
        cellValue,
        sheet: sheet,
      )) {
    showHintBox = {
      'display': 'block',
      'left': '${columnPre}px',
      'top': '${rowEnd}px',
      'html':
          '${_apiDataVerificationFocusPrefix(lang, false)}${getFailureText(Map<String, Object?>.from(item), lang: lang)}',
    };
  }
  return {
    'sheet': nextSheet,
    'dataVerificationDropDownList': false,
    'showHintBox': showHintBox,
    'dropDownButton': dropDownButton,
  };
}

String _apiDataVerificationFocusPrefix(String lang, bool hint) {
  final color = hint ? '#f5a623' : '#f72626';
  final localeKey = _apiDataVerificationLocaleKey(lang);
  final label = switch (localeKey) {
    'ru' => hint ? 'Подсказка: ' : 'Ошибка: ',
    'zh' || 'zh-CN' || 'zh-TW' => hint ? '提示：' : '失效：',
    'es' => hint ? 'Consejos：' : 'Caducidad: ',
    'hi' => hint ? 'सुझाव: ' : 'असफलता: ',
    _ => hint ? 'Hint: ' : 'Failure: ',
  };
  return '<span style="color:$color;">$label</span>';
}

FortuneSheet setDropcownValue(
  FortuneSheet sheet,
  Object? value,
  Iterable<Object?> selectedValues,
) {
  final selection = sheet.getSelection();
  if (selection.isEmpty) {
    return sheet.copyWith();
  }
  final last = selection.last;
  final rowIndex = last.rowFocus ?? last.rowStart;
  final columnIndex = last.columnFocus ?? last.columnStart;
  final item = sheet.dataVerification['${rowIndex}_$columnIndex'];
  var nextValue = value;
  if (item is Map && item['type2'] == 'true') {
    final selected = selectedValues.map((item) => '$item').toSet();
    nextValue = '${item['value1'] ?? ''}'
        .split(',')
        .where((item) => selected.contains(item))
        .join(',');
  }
  return setCellValue(sheet, rowIndex, columnIndex, nextValue);
}

Map<String, Object?> confirmMessage(
  FortuneSheet sheet,
  Map<String, Object?> dataRegulation, {
  Map<String, String> generalDialog = const {},
  Map<String, String> dataVerification = const {},
}) {
  final rangeText = '${dataRegulation['rangeTxt'] ?? ''}';
  final ranges = getRangeByTxt(sheet, rangeText);
  if (ranges.isEmpty) {
    return <String, Object?>{
      'valid': false,
      'message': generalDialog['noSeletionError'] ?? 'no selection',
      'range': null,
    };
  }
  final range = ranges.last;
  if (range == null) {
    return const <String, Object?>{
      'valid': false,
      'message': null,
      'range': null,
    };
  }
  final normalized = FortuneRange(
    rowStart: math.max(0, range.rowStart),
    rowEnd: math.min(_apiSheetMaxRow(sheet), range.rowEnd),
    columnStart: math.max(0, range.columnStart),
    columnEnd: math.min(_apiSheetMaxColumn(sheet), range.columnEnd),
  );
  if (normalized.rowStart > normalized.rowEnd ||
      normalized.columnStart > normalized.columnEnd) {
    return const <String, Object?>{
      'valid': false,
      'message': null,
      'range': null,
    };
  }

  final type = dataRegulation['type']?.toString();
  final type2 = dataRegulation['type2']?.toString();
  final value1 = dataRegulation['value1'];
  final value2 = dataRegulation['value2'];
  final hasNumber1 = _apiParseFloat('${value1 ?? ''}') != null;
  final hasNumber2 = _apiParseFloat('${value2 ?? ''}') != null;
  final number1 = _apiDataVerificationNumber(value1);
  final number2 = _apiDataVerificationNumber(value2);

  String? message;
  var valid = true;
  if (type == 'dropdown') {
    if (!_apiJsTruthy(value1)) {
      message = dataVerification['tooltipInfo1'] ?? 'dropdown value required';
    }
  } else if (type == 'checkbox') {
    if (!_apiJsTruthy(value1) || !_apiJsTruthy(value2)) {
      message = dataVerification['tooltipInfo2'] ?? 'checkbox values required';
    }
  } else if (type == 'number' ||
      type == 'number_integer' ||
      type == 'number_decimal') {
    if (!hasNumber1) {
      message = dataVerification['tooltipInfo3'] ?? 'invalid number';
      valid = false;
    } else if (type2 == 'between' || type2 == 'notBetween') {
      if (!hasNumber2) {
        message = dataVerification['tooltipInfo3'] ?? 'invalid number';
        valid = false;
      } else if (!number1.isNaN && !number2.isNaN && number2 < number1) {
        message = dataVerification['tooltipInfo4'] ?? 'invalid range';
        valid = false;
      }
    }
  } else if (type == 'text_content') {
    if (!_apiJsTruthy(value1)) {
      message = dataVerification['tooltipInfo5'] ?? 'text value required';
      valid = false;
    }
  } else if (type == 'text_length') {
    if (!hasNumber1) {
      message = dataVerification['tooltipInfo3'] ?? 'invalid number';
      valid = false;
    } else if (!_apiIsNonNegativeInteger(value1)) {
      message = dataVerification['textlengthInteger'] ?? 'invalid text length';
      valid = false;
    } else if (type2 == 'between' || type2 == 'notBetween') {
      if (!hasNumber2) {
        message = dataVerification['tooltipInfo3'] ?? 'invalid number';
        valid = false;
      } else if (!_apiIsNonNegativeInteger(value2)) {
        message =
            dataVerification['textlengthInteger'] ?? 'invalid text length';
        valid = false;
      } else if (!number1.isNaN && !number2.isNaN && number2 < number1) {
        message = dataVerification['tooltipInfo4'] ?? 'invalid range';
        valid = false;
      }
    }
  } else if (type == 'date') {
    if (!isdatetime(value1)) {
      message = dataVerification['tooltipInfo6'] ?? 'invalid date';
      valid = false;
    } else if (type2 == 'between' || type2 == 'notBetween') {
      if (!isdatetime(value2)) {
        message = dataVerification['tooltipInfo6'] ?? 'invalid date';
        valid = false;
      } else if (diff(value1, value2) > 0) {
        message = dataVerification['tooltipInfo7'] ?? 'invalid date range';
        valid = false;
      }
    }
  }
  return <String, Object?>{
    'valid': valid,
    'message': message,
    'range': normalized,
  };
}

bool _apiIsNonNegativeInteger(Object? value) {
  final number = _apiDataVerificationNumber(value);
  return !number.isNaN && number % 1 == 0 && number >= 0;
}

Map<String, Object?> dataRangeSelection(
  FortuneSheet sheet,
  String rangeText,
  String type,
  String value, {
  Iterable<FortuneRange>? selection,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
  int rangeIndex = 0,
}) {
  final ranges = (selection ?? sheet.getSelection()).toList();
  final payload = <String, Object?>{
    'rangeDialog': <String, Object?>{
      'show': true,
      'type': type,
      'rangeTxt': value,
    },
    'luckysheetCellUpdate': const [0, 0],
    'formulaRangeSelect': null,
  };
  if (ranges.isEmpty || rangeText.isEmpty) {
    return payload;
  }
  final last = ranges.last;
  final rowIndex = last.rowFocus ?? last.rowStart;
  final columnIndex = last.columnFocus ?? last.columnStart;
  payload['luckysheetCellUpdate'] = [rowIndex, columnIndex];
  final range = getRangeByTxt(sheet, rangeText).firstOrNull;
  if (range == null) {
    return payload;
  }
  final rowStart = rowLocationByIndex(range.rowStart, visibleDataRows)[0];
  final rowEnd = rowLocationByIndex(range.rowEnd, visibleDataRows)[1];
  final columnStart = colLocationByIndex(
    range.columnStart,
    visibleDataColumns,
  )[0];
  final columnEnd = colLocationByIndex(range.columnEnd, visibleDataColumns)[1];
  payload['formulaRangeSelect'] = <String, Object?>{
    'height': rowEnd - rowStart - 1,
    'left': columnStart,
    'rangeIndex': rangeIndex,
    'top': rowStart,
    'width': columnEnd - columnStart - 1,
  };
  return payload;
}

bool validateCellData(
  Map<String, Object?> item,
  Object? cellValue, {
  FortuneSheet? sheet,
}) {
  final type = '${item['type']}';
  final type2 = item['type2']?.toString();
  var value1 = item['value1'];
  var value2 = item['value2'];
  if (type == 'dropdown') {
    final list = getDropdownList('${value1 ?? ''}', sheet: sheet);
    if (_apiJsTruthy(item['type2']) && _apiJsTruthy(cellValue)) {
      return '$cellValue'.split(',').every(list.contains);
    }
    return list.contains(cellValue);
  }
  if (type == 'checkbox') {
    return true;
  }
  if (type == 'number' ||
      type == 'number_integer' ||
      type == 'number_decimal') {
    if (isRealNull(cellValue) || cellValue is bool) {
      return false;
    }
    final number = _apiDataVerificationNumber(cellValue);
    if (number.isNaN) {
      return false;
    }
    if (type == 'number_integer' && number % 1 != 0) {
      return false;
    }
    if (type == 'number_decimal' && number % 1 == 0) {
      return false;
    }
    final comparisonValue1 = _apiDataVerificationNumber(
      item.containsKey('value1') ? value1 : _apiMissingDataVerificationValue,
    );
    final comparisonValue2 = _apiDataVerificationNumber(
      item.containsKey('value2') ? value2 : _apiMissingDataVerificationValue,
    );
    return _apiValidateComparison(
      number,
      comparisonValue1,
      comparisonValue2,
      type2,
    );
  }
  if (type == 'text_content') {
    final text = '$cellValue';
    final expected = '${value1 ?? ''}';
    if (type2 == 'include' && !text.contains(expected)) {
      return false;
    }
    if (type2 == 'exclude' && text.contains(expected)) {
      return false;
    }
    if (type2 == 'equal' && text != expected) {
      return false;
    }
  } else if (type == 'text_length') {
    final comparisonValue1 = _apiDataVerificationNumber(
      item.containsKey('value1') ? value1 : _apiMissingDataVerificationValue,
    );
    final comparisonValue2 = _apiDataVerificationNumber(
      item.containsKey('value2') ? value2 : _apiMissingDataVerificationValue,
    );
    return _apiValidateComparison(
      '$cellValue'.length,
      comparisonValue1,
      comparisonValue2,
      type2,
    );
  } else if (type == 'date') {
    if (!isdatetime(cellValue)) {
      return false;
    }
    if (type2 == 'between' &&
        (diff(cellValue, value1) < 0 || diff(cellValue, value2) > 0)) {
      return false;
    }
    if (type2 == 'notBetween' &&
        diff(cellValue, value1) >= 0 &&
        diff(cellValue, value2) <= 0) {
      return false;
    }
    if (type2 == 'equal' && diff(cellValue, value1) != 0) {
      return false;
    }
    if (type2 == 'notEqualTo' && diff(cellValue, value1) == 0) {
      return false;
    }
    if (type2 == 'earlierThan' && diff(cellValue, value1) >= 0) {
      return false;
    }
    if (type2 == 'noEarlierThan' && diff(cellValue, value1) < 0) {
      return false;
    }
    if (type2 == 'laterThan' && diff(cellValue, value1) <= 0) {
      return false;
    }
    if (type2 == 'noLaterThan' && diff(cellValue, value1) > 0) {
      return false;
    }
  } else if (type == 'validity') {
    final text = '$cellValue';
    if (type2 == 'identificationNumber' && !validateIdCard(text)) {
      return false;
    }
    if (type2 == 'phoneNumber' &&
        !RegExp(r'^1[3456789]\d{9}$').hasMatch(text)) {
      return false;
    }
  }
  return true;
}

final Object _apiMissingDataVerificationValue = Object();

num _apiDataVerificationNumber(Object? value) {
  if (identical(value, _apiMissingDataVerificationValue)) {
    return double.nan;
  }
  if (value == null) {
    return 0;
  }
  if (value is bool) {
    return value ? 1 : 0;
  }
  if (value is num) {
    return value;
  }
  if (value is String) {
    final trimmed = value.trim();
    if (trimmed.isEmpty) {
      return 0;
    }
    if (trimmed == 'Infinity' || trimmed == '+Infinity') {
      return double.infinity;
    }
    if (trimmed == '-Infinity') {
      return double.negativeInfinity;
    }
    final radixMatch = RegExp(
      r'^(0[xX][0-9a-fA-F]+|0[bB][01]+|0[oO][0-7]+)$',
    ).firstMatch(trimmed);
    if (radixMatch != null) {
      final text = radixMatch.group(1)!;
      final radix = switch (text.substring(0, 2).toLowerCase()) {
        '0x' => 16,
        '0b' => 2,
        _ => 8,
      };
      return int.parse(text.substring(2), radix: radix);
    }
    return num.tryParse(trimmed) ?? double.nan;
  }
  return double.nan;
}

String getFailureText(Map<String, Object?> item, {String lang = 'en'}) {
  final type = '${item['type'] ?? ''}';
  final type2 = '${item['type2'] ?? ''}';
  final value1 = '${item['value1'] ?? ''}';
  final value2 = '${item['value2'] ?? ''}';
  final localeKey = _apiDataVerificationLocaleKey(lang);
  final chinese = localeKey == 'zh';
  final traditionalChinese = localeKey == 'zh-TW';
  final spanish = localeKey == 'es';
  final hindi = localeKey == 'hi';
  final russian = localeKey == 'ru';
  if (chinese || traditionalChinese) {
    String label(String key) => _apiDataVerificationChineseOptionLabel(
      key,
      traditional: traditionalChinese,
    );
    if (type == 'dropdown') {
      return traditionalChinese ? '你選擇的不是下拉清單中的選項' : '你选择的不是下拉列表中的选项';
    }
    if (type == 'checkbox') {
      return '';
    }
    if (type == 'number' ||
        type == 'number_integer' ||
        type == 'number_decimal') {
      final buffer = StringBuffer(
        '${traditionalChinese ? '你輸入的不是' : '你输入的不是'}${label(type2)}$value1',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write(traditionalChinese ? '和$value2之間' : '和$value2之间');
      }
      buffer.write('的${label(type)}');
      return buffer.toString();
    }
    if (type == 'text_content') {
      return '${traditionalChinese ? '你輸入的不是內容' : '你输入的不是内容'}${label(type2)}$value1的文本';
    }
    if (type == 'text_length') {
      final buffer = StringBuffer(
        '${traditionalChinese ? '你輸入的不是長度' : '你输入的不是长度'}${label(type2)}$value1',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write(traditionalChinese ? '和$value2之間' : '和$value2之间');
      }
      buffer.write('的文本');
      return buffer.toString();
    }
    if (type == 'date') {
      final buffer = StringBuffer(
        '${traditionalChinese ? '你輸入的不是' : '你输入的不是'}${label(type2)}$value1',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write(traditionalChinese ? '和$value2之間' : '和$value2之间');
      }
      buffer.write('的日期');
      return buffer.toString();
    }
    if (type == 'validity') {
      return '${traditionalChinese ? '你輸入的不是一個正確的' : '你输入的不是一个正确的'}${label(type2)}';
    }
    return '';
  }
  if (russian) {
    String label(String key) => _apiDataVerificationRussianOptionLabel(key);
    if (type == 'dropdown') {
      return 'выбранный вами вариант отсутствует в выпадающем списке';
    }
    if (type == 'checkbox') {
      return '';
    }
    if (type == 'number' ||
        type == 'number_integer' ||
        type == 'number_decimal') {
      final buffer = StringBuffer(
        'введённое значение не является ${label(type)} ${label(type2)} $value1',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write(' и $value2');
      }
      return buffer.toString();
    }
    if (type == 'text_content') {
      return 'введённый текст не соответствует условию: ${label(type2)} $value1';
    }
    if (type == 'text_length') {
      final buffer = StringBuffer(
        'длина введённого текста не ${label(type2)} $value1 ',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write('и $value2');
      }
      return buffer.toString();
    }
    if (type == 'date') {
      final buffer = StringBuffer('введённая дата не undefined $value1 ');
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write('и $value2');
      }
      return buffer.toString();
    }
    if (type == 'validity') {
      return 'введённое значение некорректно: undefined ';
    }
    return '';
  }
  if (hindi) {
    String label(String key) => _apiDataVerificationHindiOptionLabel(key);
    if (type == 'dropdown') {
      return 'आपने जो चयन किया है वह ड्रॉप-डाउन सूची में एक विकल्प नहीं है';
    }
    if (type == 'checkbox') {
      return '';
