        type == 'number_integer' ||
        type == 'number_decimal') {
      final buffer = StringBuffer(
        'आपने जो दर्ज किया है वह ${label(type)} ${label(type2)} $value1 नहीं है',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write(' and $value2');
      }
      return buffer.toString();
    }
    if (type == 'text_content') {
      return 'आपने जो दर्ज किया है वह पाठ नहीं है जो ${label(type2)} $value1 है';
    }
    if (type == 'text_length') {
      final buffer = StringBuffer(
        'आपके द्वारा दर्ज किया गया पाठ की लंबाई ${label(type2)} $value1 नहीं है',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write(' और $value2');
      }
      return buffer.toString();
    }
    if (type == 'date') {
