  if (spanish) {
    String label(String key) => _apiDataVerificationSpanishOptionLabel(key);
    if (type == 'dropdown') {
      return 'No elegiste una opción en la lista desplegable';
    }
    if (type == 'checkbox') {
      return '';
    }
    if (type == 'number' ||
        type == 'number_integer' ||
        type == 'number_decimal') {
      final buffer = StringBuffer(
        'Lo que introduciste no es${label(type2)}$value1',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write('Y${value2}Entre');
      }
      buffer.write('De${label(type)}');
      return buffer.toString();
    }
    if (type == 'text_content') {
      return 'Lo que introduciste no fue contenido${label(type2)}${value1}Texto';
    }
    if (type == 'text_length') {
      final buffer = StringBuffer(
        'No introduciste la longitud${label(type2)}$value1',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write('Y${value2}Entre');
      }
      buffer.write('Texto');
      return buffer.toString();
    }
    if (type == 'date') {
      final buffer = StringBuffer(
        'Lo que introduciste no es${label(type2)}$value1',
      );
      if (type2 == 'between' || type2 == 'notBetween') {
        buffer.write('Y${value2}Entre');
      }
      buffer.write('Fecha');
      return buffer.toString();
    }
    if (type == 'validity') {
      return 'Lo que ingresas no es correcto${label(type2)}';
    }
    return '';
  }
  if (type == 'dropdown') {
    return 'what you selected is not an option in the drop-down list';
  }
  if (type == 'checkbox') {
    return '';
  }
  if (type == 'number' ||
      type == 'number_integer' ||
      type == 'number_decimal') {
    return _apiDataVerificationRangeText(
      'what you entered is not a ${_apiDataVerificationOptionLabel(type)} '
      '${_apiDataVerificationOptionLabel(type2)} $value1',
      type2,
      value2,
    );
  }
  if (type == 'text_content') {
    return 'what you entered is not text that '
        '${_apiDataVerificationOptionLabel(type2)} $value1';
  }
  if (type == 'text_length') {
    return _apiDataVerificationRangeText(
      'the text you entered is not length '
      '${_apiDataVerificationOptionLabel(type2)} $value1',
      type2,
      value2,
    );
  }
  if (type == 'date') {
    return _apiDataVerificationRangeText(
      'the date you entered is not '
      '${_apiDataVerificationOptionLabel(type2)} $value1',
      type2,
      value2,
    );
  }
  if (type == 'validity') {
    return 'what you entered is not a correct '
        '${_apiDataVerificationOptionLabel(type2)}';
  }
  return '';
}

