String _apiDataVerificationLocaleKey(String lang) {
  if (lang == 'zh-TW') {
    return lang;
  }
  final baseLang = lang.split('-').first;
  return switch (lang) {
    'en' || 'zh' || 'es' || 'hi' || 'ru' => lang,
    _ => switch (baseLang) {
      'zh' || 'es' || 'hi' || 'ru' => baseLang,
      _ => 'en',
    },
  };
}

String _apiDataVerificationRangeText(
  String prefix,
  String type,
  String value2,
) {
  if (type == 'between' || type == 'notBetween') {
    return '$prefix and $value2';
  }
  return prefix;
}

