Map<String, Object?> orderbydata(
  bool? isAsc,
  int index,
  List<List<FortuneCell?>> data,
) {
  final asc = isAsc ?? true;
  final sortedData = List<List<FortuneCell?>>.from(data);
  int compareRows(List<FortuneCell?> x, List<FortuneCell?> y) {
    return _apiCompareSortValues(
      index < x.length ? _apiSortCellValue(x[index]) : null,
      index < y.length ? _apiSortCellValue(y[index]) : null,
      asc,
    );
  }

  sortedData.sort(compareRows);
  final rowOffsets = <int>[];
  for (var sortedIndex = 0; sortedIndex < sortedData.length; sortedIndex += 1) {
    final row = sortedData[sortedIndex];
    final originalIndex = data.indexWhere(
      (candidate) => identical(candidate, row),
    );
    rowOffsets.add(sortedIndex - originalIndex);
  }
  return {'sortedData': sortedData, 'rowOffsets': rowOffsets};
}

FortuneSheet sortDataRange(
  FortuneSheet sheet,
  FortuneRange range,
  int index,
  bool isAsc,
) {
  final normalized = _normalizedApiRange(range);
  if (normalized == null) {
    return sheet.copyWith();
  }
  final dataRange = <List<FortuneCell?>>[];
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    final cells = <FortuneCell?>[];
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      cells.add(sheet.cells[FortuneCellCoord(row, column)]);
    }
    dataRange.add(cells);
  }
  final sortResult = orderbydata(isAsc, index, dataRange);
  final sortedData = sortResult['sortedData'] as List<List<FortuneCell?>>;
  final rowOffsets = sortResult['rowOffsets'] as List<int>;
  final nextCells = Map<FortuneCellCoord, FortuneCell>.from(sheet.cells);
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    final rowOffset = row - normalized.rowStart;
    final moveOffset = rowOffsets[rowOffset];
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      final columnOffset = column - normalized.columnStart;
      final coord = FortuneCellCoord(row, column);
      final cell = sortedData[rowOffset][columnOffset];
      if (cell == null) {
        nextCells.remove(coord);
      } else {
        nextCells[coord] = _apiSortMovedCell(cell, moveOffset);
      }
    }
  }
  return sheet.copyWith(cells: nextCells);
}

FortuneCell _apiSortMovedCell(FortuneCell cell, int moveOffset) {
  final formula = cell.formula;
  if (formula == null || moveOffset == 0) {
    return cell.copyWith();
  }
  final mode = moveOffset > 0 ? 'down' : 'up';
  final nextFormula = '=${functionCopy(formula, mode, moveOffset.abs())}';
  return cell.copyWith(
    formula: nextFormula,
    rawFormula: cell.hasRawFormula ? nextFormula : _sentinel,
    hasRawFormula: cell.hasRawFormula,
  );
}

FortuneSheet sortSelection(
  FortuneSheet sheet,
  bool isAsc, {
  int colIndex = 0,
  Iterable<FortuneRange>? selection,
}) {
  final ranges = (selection ?? sheet.getSelection()).toList();
  if (ranges.length != 1) {
    return sheet.copyWith();
  }
  final normalized = _normalizedApiRange(ranges.single);
  if (normalized == null) {
    return sheet.copyWith();
  }
  int? rowStart;
  int? rowEnd;
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    final cell = sheet.cells[FortuneCellCoord(row, normalized.columnStart)];
    final value = _apiSortCellValue(cell);
    if (cell == null || cell.merge != null || isRealNull(value)) {
      continue;
    }
    if (rowStart == null && RegExp(r'[\u4e00-\u9fa5]+').hasMatch('$value')) {
      rowStart = row + 1;
      rowEnd = row + 1;
      continue;
    }
    rowStart ??= row;
    rowEnd = row;
  }
  if (rowStart == null || rowEnd == null || rowStart > normalized.rowEnd) {
    return sheet.copyWith();
  }
  for (var row = rowStart; row <= rowEnd; row += 1) {
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      if (sheet.cells[FortuneCellCoord(row, column)]?.merge != null) {
        return sheet.copyWith();
      }
    }
  }
  return sortDataRange(
    sheet,
    FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: normalized.columnStart,
      columnEnd: normalized.columnEnd,
    ),
    colIndex,
    isAsc,
  );
}

Object? _apiSortCellValue(FortuneCell? cell) {
  return cell?.hasRawValue == true ? cell?.rawValue : cell?.value;
}

Map<String, Object?> orderbydatafiler(
  FortuneSheet sheet,
  int str,
  int stc,
  int edr,
  int edc,
  int curr,
  bool asc, {
  String mergeError = 'merge cell error',
}) {
  final rowStart = str + 1;
  for (var row = rowStart; row <= edr; row += 1) {
    for (var column = stc; column <= edc; column += 1) {
      if (sheet.cells[FortuneCellCoord(row, column)]?.merge != null) {
        return <String, Object?>{
          'sheet': sheet.copyWith(),
          'message': mergeError,
        };
      }
    }
  }
  return <String, Object?>{
    'sheet': sortDataRange(
      sheet,
      FortuneRange(
        rowStart: rowStart,
        rowEnd: edr,
        columnStart: stc,
        columnEnd: edc,
      ),
      curr - stc,
      asc,
    ),
    'message': null,
  };
}

int _apiCompareSortValues(Object? x, Object? y, bool isAsc) {
  final leftBlank = isRealNull(x);
  final rightBlank = isRealNull(y);
  if (leftBlank && rightBlank) {
    return 0;
  }
  if (leftBlank) {
    return 1;
  }
  if (rightBlank) {
    return -1;
  }

  int compareAsc(Object? left, Object? right) {
    if (isdatetime(left) && isdatetime(right)) {
      return diff(left, right).sign;
    }
    final leftIsNumber = isRealNum(left);
    final rightIsNumber = isRealNum(right);
    final leftNumber = _apiSortNumericValue(left);
    final rightNumber = _apiSortNumericValue(right);
    if (leftIsNumber && rightIsNumber) {
      if (leftNumber == null ||
          rightNumber == null ||
          leftNumber.isNaN ||
          rightNumber.isNaN) {
        return 0;
      }
      return leftNumber.compareTo(rightNumber);
    }
    if (!leftIsNumber && !rightIsNumber) {
      return '$left'.compareTo('$right');
    }
    if (!leftIsNumber) {
      return 1;
    }
    if (!rightIsNumber) {
      return -1;
    }
    return 0;
  }

  return isAsc ? compareAsc(x, y) : compareAsc(y, x);
}

num? _apiSortNumericValue(Object? value) {
  if (!isRealNum(value)) {
    return null;
  }
  if (value is num) {
    return value;
  }
  if (value is! String) {
    return _apiDataVerificationNumber(value);
  }
  final exponential = _apiSortExponentialValue(value);
  if (exponential != null) {
    return exponential;
  }
  if (!RegExp(r'[0-9]').hasMatch(value)) {
    return double.nan;
  }
  final negative =
      (value.split('-').length +
              math.min(
                value.split('(').length - 1,
                value.split(')').length - 1,
              )) %
          2 ==
      0;
  final digits = value.replaceAll(RegExp(r'[^0-9\.]+'), '');
  final parsed = num.tryParse(digits);
  if (parsed == null) {
    return null;
  }
  return negative ? -parsed : parsed;
}

num? _apiSortExponentialValue(String value) {
  final separator = value.contains('e+')
      ? 'e+'
      : (value.contains('e-') ? 'e-' : null);
  if (separator == null) {
    return null;
  }
  final parts = value.split(separator);
  if (parts.length != 2) {
    return double.nan;
  }
  final mantissa = num.tryParse(parts[0]);
  final power = num.tryParse(parts[1]);
  if (mantissa == null || power == null) {
    return double.nan;
  }
  final exponent = separator == 'e-' ? -power : power;
  return mantissa * math.pow(10, exponent);
}

// ignore: non_constant_identifier_names
bool is_date(String fmt, [Object? value]) {
  var i = 0;
  while (i < fmt.length) {
    final char = fmt[i];
    switch (char) {
      case 'G':
        if (_apiIsGeneralFormat(fmt, i)) {
          i += 6;
        }
        i += 1;
        continue;
      case '"':
        i += 1;
        while (i < fmt.length && fmt.codeUnitAt(i) != 34) {
          i += 1;
        }
        if (i < fmt.length) {
          i += 1;
        }
        continue;
      case '\\':
      case '_':
        i += 2;
        continue;
      case '@':
        i += 1;
        continue;
      case 'B':
      case 'b':
        if (i + 1 < fmt.length && (fmt[i + 1] == '1' || fmt[i + 1] == '2')) {
          return true;
        }
        return true;
      case 'M':
      case 'D':
      case 'Y':
      case 'H':
      case 'S':
      case 'E':
      case 'm':
      case 'd':
      case 'y':
      case 'h':
      case 's':
      case 'e':
      case 'g':
        return true;
      case 'A':
      case 'a':
      case '\u4e0a':
        final upper = fmt.substring(i).toUpperCase();
        if (upper.startsWith('A/P') ||
            upper.startsWith('AM/PM') ||
            upper.startsWith('\u4e0a\u5348/\u4e0b\u5348')) {
          return true;
        }
        i += 1;
        continue;
      case '[':
        final bracket = StringBuffer('[');
        i += 1;
        while (i < fmt.length && fmt[i] != ']') {
          bracket.write(fmt[i]);
          i += 1;
        }
        if (i < fmt.length && fmt[i] == ']') {
          bracket.write(']');
          i += 1;
        }
        if (RegExp(r'\[[HhMmSs\u0E0A\u0E19\u0E17]*\]').hasMatch('$bracket')) {
          return true;
        }
        continue;
      case '.':
      case '0':
      case '#':
        i += 1;
        while (i < fmt.length &&
            ('0#?.,E+-%'.contains(fmt[i]) ||
                (fmt[i] == '\\' &&
                    i + 2 < fmt.length &&
                    fmt[i + 1] == '-' &&
                    '0#'.contains(fmt[i + 2])))) {
          i += 1;
        }
        continue;
      case '?':
        i += 1;
        while (i < fmt.length && fmt[i] == '?') {
          i += 1;
        }
        continue;
      case '*':
        i += 1;
        if (i < fmt.length && (fmt[i] == ' ' || fmt[i] == '*')) {
          i += 1;
        }
        continue;
      case '(':
      case ')':
        i += 1;
        continue;
      case '1':
      case '2':
      case '3':
      case '4':
      case '5':
      case '6':
      case '7':
      case '8':
      case '9':
        i += 1;
        while (i < fmt.length && '0123456789'.contains(fmt[i])) {
          i += 1;
        }
        continue;
      case ' ':
        i += 1;
        continue;
      default:
        i += 1;
        continue;
    }
  }
  return false;
}

bool _apiIsGeneralFormat(String format, int index) {
  if (format.length < index + 7) {
    return false;
  }
  return format.substring(index, index + 7).toLowerCase() == 'general';
}

List<FortuneRange?> getRangeByTxt(FortuneSheet sheet, String text) {
  final ranges = <FortuneRange?>[];
  if (text.contains(',')) {
    for (final part in text.split(',')) {
      if (!iscelldata(part)) {
        return const [];
      }
      ranges.add(_apiRangeFromText(part, sheet));
    }
    return ranges;
  }
  if (iscelldata(text)) {
    ranges.add(_apiRangeFromText(text, sheet));
  }
  return ranges;
}

Map<String, Object?>? getcellrange(
  FortuneWorkbook workbook,
  String text, {
  String? formulaId,
  FormulaCache? formulaCache,
}) {
  if (text.isEmpty) {
    return null;
  }
  final activeSheetId = formulaId ?? workbook.activeSheet.id;
  final cellTextToIndexList = _apiCellTextToIndexList(formulaCache);
  final cacheKey = _apiCellTextToIndexListKey(text, activeSheetId);
  final cached = cellTextToIndexList?[cacheKey];
  if (cached is Map<String, Object?>) {
    return cached;
  }
  if (cached is Map) {
    final normalized = Map<String, Object?>.from(cached);
    cellTextToIndexList![cacheKey] = normalized;
    return normalized;
  }
  final parsed = _apiFormulaDependencyText(workbook, text, formulaId);
  if (parsed == null) {
    return null;
  }
  final sheet = parsed.sheet;
  final rangeText = parsed.rangeText.replaceAll(r'$', '');
  final parts = rangeText.split(':');
  if (parts.length == 1) {
    final row = _apiCellTextRow(parts.first);
    final column = columnCharToIndex(
      parts.first.replaceAll(RegExp(r'[^A-Za-z]'), ''),
    );
    if (row == null || column == null) {
      return null;
    }
    final item = <String, Object?>{
      'row': [row, row],
      'column': [column, column],
      'sheetId': sheet.id,
    };
    _apiAddToCellTextToIndexList(formulaCache, text, sheet.id, item);
    return item;
  }
  if (parts.length != 2) {
    return null;
  }
  final maxRow = _apiSheetMaxRow(sheet);
  final maxColumn = _apiSheetMaxColumn(sheet);
  final rawRowStart = _apiCellTextRow(parts[0]) ?? 0;
  final rawRowEnd = _apiCellTextRow(parts[1]) ?? maxRow;
  final rowStart = math.min(rawRowStart, rawRowEnd);
  final rowEnd = math.max(rawRowStart, rawRowEnd);
  final rawColumnStart =
      columnCharToIndex(parts[0].replaceAll(RegExp(r'[^A-Za-z]'), '')) ?? 0;
  final rawColumnEnd =
      columnCharToIndex(parts[1].replaceAll(RegExp(r'[^A-Za-z]'), '')) ??
      maxColumn;
  final columnStart = math.min(rawColumnStart, rawColumnEnd);
  final columnEnd = math.max(rawColumnStart, rawColumnEnd);
  final item = <String, Object?>{
    'row': [rowStart, rowEnd],
    'column': [columnStart, columnEnd],
    'sheetId': sheet.id,
  };
  _apiAddToCellTextToIndexList(formulaCache, text, sheet.id, item);
  return item;
}

Map<String, Object?>? _apiCellTextToIndexList(FormulaCache? formulaCache) {
  if (formulaCache == null) {
    return null;
  }
  final raw = formulaCache['cellTextToIndexList'];
  if (raw is Map<String, Object?>) {
    return raw;
  }
  if (raw is Map) {
    final normalized = Map<String, Object?>.from(raw);
    formulaCache['cellTextToIndexList'] = normalized;
    return normalized;
  }
  final created = <String, Object?>{};
  formulaCache['cellTextToIndexList'] = created;
  return created;
}

String _apiCellTextToIndexListKey(String text, String sheetId) {
  if (text.contains('!')) {
    return text.replaceAll(r"\'", "'").replaceAll("''", "'");
  }
  return '${text}_$sheetId';
}

void _apiAddToCellTextToIndexList(
  FormulaCache? formulaCache,
  String text,
  String sheetId,
  Map<String, Object?> item,
) {
  final cellTextToIndexList = _apiCellTextToIndexList(formulaCache);
  if (cellTextToIndexList == null || text.isEmpty) {
    return;
  }
  cellTextToIndexList[_apiCellTextToIndexListKey(text, sheetId)] = item;
}

String getRangetxt(
  FortuneWorkbook workbook,
  String sheetId,
  Object? range, {
  String? currentSheetId,
}) {
  final row = range is FortuneRange
      ? <Object?>[range.rowStart, range.rowEnd]
      : _apiRangeAxis(range, 'row');
  final column = range is FortuneRange
      ? <Object?>[range.columnStart, range.columnEnd]
      : _apiRangeAxis(range, 'column');
  if (row == null || column == null) {
    return '';
  }
  final row0 = _apiNullableInt(row[0]);
  final row1 = _apiNullableInt(row[1]);
  final column0 = _apiNullableInt(column[0]);
  final column1 = _apiNullableInt(column[1]);
  final sheetText = _apiRangeSheetPrefix(
    workbook,
    sheetId,
    currentSheetId ?? workbook.activeSheet.id,
  );
  if (sheetText == null) {
    return '';
  }
  if (row0 == null && row1 == null) {
    if (column0 == null || column1 == null) {
      return '';
    }
    return '$sheetText${indexToColumnChar(column0)}:${indexToColumnChar(column1)}';
  }
  if (column0 == null && column1 == null) {
    if (row0 == null || row1 == null) {
      return '';
    }
    return '$sheetText${row0 + 1}:${row1 + 1}';
  }
  if (row0 == null || row1 == null || column0 == null || column1 == null) {
    return '';
  }
  final start = '${indexToColumnChar(column0)}${row0 + 1}';
  final end = '${indexToColumnChar(column1)}${row1 + 1}';
  return start == end ? '$sheetText$start' : '$sheetText$start:$end';
}

List<Object?>? _apiRangeAxis(Object? range, String key) {
  if (range is! Map) {
    return null;
  }
  final raw = range[key];
  if (raw is! List || raw.length < 2) {
    return null;
  }
  return [raw[0], raw[1]];
}

String? _apiRangeSheetPrefix(
  FortuneWorkbook workbook,
  String sheetId,
  String currentSheetId,
) {
  if (sheetId == currentSheetId) {
    return '';
  }
  final sheet = workbook.sheets
      .where((sheet) => sheet.id == sheetId)
      .firstOrNull;
  if (sheet == null) {
    return null;
  }
  final escaped = sheet.name.replaceAll("'", "''");
  return _apiSheetNameCanBeUnquoted(escaped) ? '$escaped!' : "'$escaped'!";
}

bool _apiSheetNameCanBeUnquoted(String name) {
  return RegExp(
    r'^[:A-Z_a-z\u00C0-\u00D6\u00D8-\u00F6\u00F8-\u02FF\u0370-\u037D\u037F-\u1FFF\u200C-\u200D\u2070-\u218F\u2C00-\u2FEF\u3001-\uD7FF\uF900-\uFDCF\uFDF0-\uFFFD][:A-Z_a-z\u00C0-\u00D6\u00D8-\u00F6\u00F8-\u02FF\u0370-\u037D\u037F-\u1FFF\u200C-\u200D\u2070-\u218F\u2C00-\u2FEF\u3001-\uD7FF\uF900-\uFDCF\uFDF0-\uFFFD\-.0-9\u00B7\u0300-\u036F\u203F-\u2040]*$',
    unicode: true,
  ).hasMatch(name);
}

int? _apiNullableInt(Object? value) {
  if (value == null) {
    return null;
  }
  if (value is int) {
    return value;
  }
  if (value is num && value.isFinite) {
    return value.toInt();
  }
  return int.tryParse('$value');
}

({FortuneSheet sheet, String rangeText})? _apiFormulaDependencyText(
  FortuneWorkbook workbook,
  String text,
  String? formulaId,
) {
  if (text.contains('!')) {
    final match = RegExp(
      r"^([A-Za-z0-9_\u00C0-\u02AF]+|'(?:(?!').|'')*')!(\$?[A-Za-z]+\$?[0-9]+)(?:[:]([A-Za-z0-9_\u00C0-\u02AF]+|'(?:(?!').|'')*')!(\$?[A-Za-z]+\$?[0-9]+)|[:](\$?[A-Za-z]+\$?[0-9]+))?$",
    ).firstMatch(text);
    if (match == null) {
      return null;
    }
    final sheetName = _apiFormulaUnquoteSheetName(match.group(1)!);
    final secondSheetName = match.group(3) == null
        ? null
        : _apiFormulaUnquoteSheetName(match.group(3)!);
    if (secondSheetName != null && secondSheetName != sheetName) {
      return null;
    }
    final sheet = workbook.sheets
        .where((candidate) => candidate.name == sheetName)
        .firstOrNull;
    if (sheet == null) {
      return null;
    }
    final endText = match.group(4) ?? match.group(5);
    final rangeText = endText == null
        ? match.group(2)!
        : '${match.group(2)!}:$endText';
    return (sheet: sheet, rangeText: rangeText);
  }
  final sheet = formulaId == null
      ? workbook.activeSheet
      : workbook.sheets
            .where((candidate) => candidate.id == formulaId)
            .firstOrNull;
  if (sheet == null) {
    return null;
  }
  return (sheet: sheet, rangeText: text);
}

String _apiFormulaUnquoteSheetName(String sheetName) {
  if (sheetName.startsWith("'") && sheetName.endsWith("'")) {
    return sheetName
        .substring(1, sheetName.length - 1)
        .replaceAll(r"\'", "'")
        .replaceAll("''", "'");
  }
  return sheetName;
}

int _apiSheetMaxRow(FortuneSheet sheet) {
  return sheet.cells.keys.fold(
    math.max(0, (sheet.rowCount ?? 0) - 1),
    (maxValue, coord) => math.max(maxValue, coord.row),
  );
}

int _apiSheetMaxColumn(FortuneSheet sheet) {
  return sheet.cells.keys.fold(
    math.max(0, (sheet.columnCount ?? 0) - 1),
    (maxValue, coord) => math.max(maxValue, coord.column),
  );
}

void arrayMatch(
  Map<String, List<Map<String, Object?>>> arrayMatchCache,
  List<Map<String, Object?>> formulaDependency,
  Map<String, Object?>? formulaCellInfoMap,
  Map<String, Object?>? updateValueObjects,
  void Function(String key, int row, int column, Object? sheetId) callback,
) {
  for (final range in formulaDependency) {
    final rows = (range['row'] as List?)?.cast<Object?>();
    final columns = (range['column'] as List?)?.cast<Object?>();
    if (rows == null ||
        columns == null ||
        rows.length < 2 ||
        columns.length < 2) {
      continue;
    }
    final rowStart = _nullableIntArg(rows[0]);
    final rowEnd = _nullableIntArg(rows[1]);
    final columnStart = _nullableIntArg(columns[0]);
    final columnEnd = _nullableIntArg(columns[1]);
    if (rowStart == null ||
        rowEnd == null ||
        columnStart == null ||
        columnEnd == null ||
        rowStart > rowEnd ||
        columnStart > columnEnd) {
      continue;
    }
    final sheetId = range['sheetId'];
    final sheetIdText = sheetId?.toString() ?? 'undefined';
    final cacheKey =
        'r$rowStart${rowEnd}c$columnStart${columnEnd}id$sheetIdText';
    final cached = arrayMatchCache[cacheKey];
    if (cached != null) {
      for (final item in cached) {
        final row = _nullableIntArg(item['r']);
        final column = _nullableIntArg(item['c']);
        final key = item['key']?.toString();
        if (key != null && row != null && column != null) {
          callback(key, row, column, item['sheetId']);
        }
      }
      continue;
    }
    final functionArr = <Map<String, Object?>>[];
    for (var row = rowStart; row <= rowEnd; row += 1) {
      for (var column = columnStart; column <= columnEnd; column += 1) {
        final key = 'r${row}c${column}i$sheetIdText';
        callback(key, row, column, sheetId);
        if ((formulaCellInfoMap?.containsKey(key) ?? false) ||
            (updateValueObjects?.containsKey(key) ?? false)) {
          functionArr.add({
            'key': key,
            'r': row,
            'c': column,
            'sheetId': sheetId,
          });
        }
      }
    }
    if (formulaCellInfoMap != null || updateValueObjects != null) {
      arrayMatchCache[cacheKey] = functionArr;
    }
  }
}

List<Map<String, Object?>> getFormulaRunList(
  List<Map<String, Object?>?> updateValueArray,
  Map<String, Map<String, Object?>> formulaCellInfoMap,
) {
  final formulaRunList = <Map<String, Object?>>[];
  var stack = updateValueArray;
  final existsFormulaRunList = <String, int>{};
  while (stack.isNotEmpty) {
    final formulaObject = stack.removeLast();
    if (formulaObject == null) {
      continue;
    }
    final key = formulaObject['key'].toString();
    if (existsFormulaRunList.containsKey(key)) {
      continue;
    }
    if (formulaObject['color'] == 'b') {
      formulaObject['color'] = 'w';
      formulaRunList.add(formulaObject);
      existsFormulaRunList[key] = 1;
      continue;
    }
    final cacheStack = <Map<String, Object?>?>[];
    final parents = formulaObject['parents'];
    if (parents is Map) {
      for (final parentKey in parents.keys) {
        cacheStack.add(formulaCellInfoMap[parentKey.toString()]);
      }
    }
    cacheStack.removeWhere((item) => item == null);
    if (cacheStack.isEmpty) {
      formulaRunList.add(formulaObject);
      existsFormulaRunList[key] = 1;
    } else {
      formulaObject['color'] = 'b';
      stack.add(formulaObject);
      stack = [...stack, ...cacheStack];
    }
  }
  return formulaRunList.reversed.toList();
}

Map<String, Map<String, Object?>> setFormulaCellInfo(
  Map<String, Map<String, Object?>> formulaCellInfoMap,
  FortuneWorkbook workbook,
  Map<String, Object?> formulaCell, {
  Map<FortuneCellCoord, FortuneCell>? data,
  FormulaCache? formulaCache,
}) {
  final row = _nullableIntArg(formulaCell['r']);
  final column = _nullableIntArg(formulaCell['c']);
  final sheetId = formulaCell['id']?.toString();
  if (row == null || column == null || sheetId == null) {
    return formulaCellInfoMap;
  }
  final key = 'r${row}c${column}i$sheetId';
  final sheet = workbook.getSheet(id: sheetId);
  final formula = getcellFormula(sheet, row, column, data: data);
  if (formula == null) {
    formulaCellInfoMap.remove(key);
    return formulaCellInfoMap;
  }

  final dependencies = <Map<String, Object?>>[];
  final dependencyTokens = [
    ..._apiFormulaDependencyTokens(formula),
    ..._apiFormulaSpecialFunctionLiteralReferences(formula),
  ];
  for (final token in dependencyTokens) {
    final trimmed = token.trim();
    if (trimmed.length <= 1 || !iscelldata(trimmed)) {
      continue;
    }
    final range = getcellrange(
      workbook,
      trimmed,
      formulaId: sheetId,
      formulaCache: formulaCache,
    );
    if (range != null) {
      dependencies.add(range);
    }
  }
  formulaCellInfoMap[key] = {
    'formulaDependency': dependencies,
    'calc_funcStr': formula,
    'key': key,
    'r': row,
    'c': column,
    'id': sheetId,
    'parents': <String, Object?>{},
    'chidren': <String, Object?>{},
    'color': 'w',
  };
  return formulaCellInfoMap;
}

Map<String, Map<String, Object?>> setFormulaCellInfoMap(
  Map<String, Map<String, Object?>> formulaCellInfoMap,
  FortuneWorkbook workbook,
  Iterable<Map<String, Object?>>? calcChains, {
  Map<FortuneCellCoord, FortuneCell>? data,
  FormulaCache? formulaCache,
}) {
  if (calcChains == null) {
    return formulaCellInfoMap;
  }
  for (final formulaCell in calcChains) {
    setFormulaCellInfo(
      formulaCellInfoMap,
      workbook,
      formulaCell,
      data: data,
      formulaCache: formulaCache,
    );
  }
  return formulaCellInfoMap;
}

List<String> _apiFormulaDependencyTokens(String formula) {
  final tokens = <String>[];
  final singleQuoteTokenIndexes = <int>[];
  var point = 0;
  var singleQuote = -1;
  var doubleQuote = -1;
  for (var index = 0; index < formula.length; index += 1) {
    final char = formula[index];
    if (char == "'" && doubleQuote == -1) {
      if (singleQuote == -1) {
        if (point != index) {
          tokens.addAll(
            _apiSplitFormulaDependencyText(formula.substring(point, index)),
          );
        }
        singleQuote = index;
        point = index;
      } else if (index < formula.length - 1 && formula[index + 1] == "'") {
        index += 1;
      } else {
        point = index + 1;
        tokens.add(formula.substring(singleQuote, point));
        singleQuoteTokenIndexes.add(tokens.length - 1);
        singleQuote = -1;
      }
    } else if (char == '"' && singleQuote == -1) {
      if (doubleQuote == -1) {
        if (point != index) {
          tokens.addAll(
            _apiSplitFormulaDependencyText(formula.substring(point, index)),
          );
        }
        doubleQuote = index;
        point = index;
      } else if (index < formula.length - 1 && formula[index + 1] == '"') {
        index += 1;
      } else {
        point = index + 1;
        tokens.add(formula.substring(doubleQuote, point));
        doubleQuote = -1;
      }
    }
  }
  if (point != formula.length) {
    tokens.addAll(_apiSplitFormulaDependencyText(formula.substring(point)));
  }
  for (final tokenIndex in singleQuoteTokenIndexes.reversed) {
    if (tokenIndex != tokens.length - 1) {
      tokens[tokenIndex] = '${tokens[tokenIndex]}${tokens[tokenIndex + 1]}';
      tokens.removeAt(tokenIndex + 1);
    }
  }
  return tokens;
}

List<String> _apiFormulaSpecialFunctionLiteralReferences(String formula) {
  final references = <String>[];
  final pattern = RegExp(
    r'\b(?:INDIRECT|OFFSET|INDEX)\s*\(\s*"((?:[^"]|"")*)"',
    caseSensitive: false,
  );
  for (final match in pattern.allMatches(formula)) {
    references.add(match.group(1)!.replaceAll('""', '"'));
  }
  return references;
}

List<String> _apiSplitFormulaDependencyText(String text) {
  return text.split(RegExp(r'==|!=|<>|<=|>=|[,()=+\-/*%&^><]'));
}

bool _apiValidateComparison(num value, num value1, num value2, String? type) {
  final first = value1;
  final second = value2;
  if (type == 'between' && (value < first || value > second)) {
    return false;
  }
  if (type == 'notBetween' && value >= first && value <= second) {
    return false;
  }
  if (type == 'equal' && value != first) {
    return false;
  }
  if (type == 'notEqualTo' && value == first) {
    return false;
  }
  if (type == 'moreThanThe' && value <= first) {
    return false;
  }
  if (type == 'lessThan' && value >= first) {
    return false;
  }
  if (type == 'greaterOrEqualTo' && value < first) {
    return false;
  }
  if (type == 'lessThanOrEqualTo' && value > first) {
    return false;
  }
  return true;
}

FortuneRange? _apiRangeFromText(String text, FortuneSheet sheet) {
  final rangeText = text.split('!').last.replaceAll(r'$', '');
  final maxRow = sheet.cells.keys.fold(
    math.max(0, (sheet.rowCount ?? 0) - 1),
    (maxValue, coord) => math.max(maxValue, coord.row),
  );
  final maxColumn = sheet.cells.keys.fold(
    math.max(0, (sheet.columnCount ?? 0) - 1),
    (maxValue, coord) => math.max(maxValue, coord.column),
  );
  final parts = rangeText.split(':');
  if (parts.length == 1) {
    final row = _apiCellTextRow(parts.first);
    final column = columnCharToIndex(
      parts.first.replaceAll(RegExp(r'[^A-Za-z]'), ''),
    );
    if (row == null || column == null) {
      return null;
    }
    return FortuneRange(
      rowStart: row,
      rowEnd: row,
      columnStart: column,
      columnEnd: column,
    );
  }
  if (parts.length != 2) {
    return null;
  }
  final first = parts[0];
  final second = parts[1];
  final firstColumnOnly = RegExp(r'^[A-Za-z]+$').hasMatch(first);
  final secondColumnOnly = RegExp(r'^[A-Za-z]+$').hasMatch(second);
  final firstRowOnly = RegExp(r'^\d+$').hasMatch(first);
  final secondRowOnly = RegExp(r'^\d+$').hasMatch(second);
  if (firstColumnOnly && secondColumnOnly) {
    final rawColumnStart = columnCharToIndex(first);
    final rawColumnEnd = columnCharToIndex(second);
    if (rawColumnStart == null || rawColumnEnd == null) {
      return null;
    }
    final columnStart = math.min(rawColumnStart, rawColumnEnd);
    final columnEnd = math.max(rawColumnStart, rawColumnEnd);
    return FortuneRange(
      rowStart: 0,
      rowEnd: maxRow,
      columnStart: columnStart,
      columnEnd: columnEnd,
    );
  }
  if (firstRowOnly && secondRowOnly) {
    final rawRowStart = int.parse(first) - 1;
    final rawRowEnd = int.parse(second) - 1;
    final rowStart = math.min(rawRowStart, rawRowEnd);
    final rowEnd = math.max(rawRowStart, rawRowEnd);
    return FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: 0,
      columnEnd: maxColumn,
    );
  }
  final rawRowStart = _apiCellTextRow(first);
  final rawRowEnd = _apiCellTextRow(second);
  final rawColumnStart = columnCharToIndex(
    first.replaceAll(RegExp(r'[^A-Za-z]'), ''),
  );
  final rawColumnEnd = columnCharToIndex(
    second.replaceAll(RegExp(r'[^A-Za-z]'), ''),
  );
  if (rawRowStart == null ||
      rawRowEnd == null ||
      rawColumnStart == null ||
      rawColumnEnd == null) {
    return null;
  }
  final rowStart = math.min(rawRowStart, rawRowEnd);
  final rowEnd = math.max(rawRowStart, rawRowEnd);
  final columnStart = math.min(rawColumnStart, rawColumnEnd);
  final columnEnd = math.max(rawColumnStart, rawColumnEnd);
  return FortuneRange(
    rowStart: rowStart,
    rowEnd: rowEnd,
    columnStart: columnStart,
    columnEnd: columnEnd,
  );
}

bool isdatetime(Object? value, [String format = '24']) {
  if (value == null || '$value'.length < 5) {
    return false;
  }
  return _apiCheckDateTime('$value', format);
}

int diff(Object? now, Object? then) {
  return _apiDateMilliseconds(now) - _apiDateMilliseconds(then);
}

Map<String, bool> isdatatypemulti(Object? value) {
  final type = <String, bool>{};
  if (isdatetime(value)) {
    type['date'] = true;
  }
  final text = '$value';
  if (_apiParseFloat(text) != null && !hasChinaword(text)) {
    type['num'] = true;
  }
  return type;
}

String isdatatype(Object? value) {
  final text = '$value';
  if (isdatetime(value)) {
    return 'date';
  }
  if (_apiParseFloat(text) != null && !hasChinaword(text)) {
    return 'num';
  }
  return 'string';
}

bool hasPartMC(
  FortuneSheet sheet,
  int rowStart,
  int rowEnd,
  int columnStart,
  int columnEnd,
) {
  final selection = FortuneRange(
    rowStart: math.min(rowStart, rowEnd),
    rowEnd: math.max(rowStart, rowEnd),
    columnStart: math.min(columnStart, columnEnd),
    columnEnd: math.max(columnStart, columnEnd),
  );
  for (final entry in sheet.cells.entries) {
    final merge = entry.value.merge;
    if (merge == null || merge.rowSpan <= 1 && merge.columnSpan <= 1) {
      continue;
    }
    final mergeRange = FortuneRange(
      rowStart: merge.row,
      rowEnd: merge.row + merge.rowSpan - 1,
      columnStart: merge.column,
      columnEnd: merge.column + merge.columnSpan - 1,
    );
    final intersects =
        selection.rowStart <= mergeRange.rowEnd &&
        selection.rowEnd >= mergeRange.rowStart &&
        selection.columnStart <= mergeRange.columnEnd &&
        selection.columnEnd >= mergeRange.columnStart;
    if (!intersects) {
      continue;
    }
    final containsMerge =
        selection.rowStart <= mergeRange.rowStart &&
        selection.rowEnd >= mergeRange.rowEnd &&
        selection.columnStart <= mergeRange.columnStart &&
        selection.columnEnd >= mergeRange.columnEnd;
    if (!containsMerge) {
      return true;
    }
  }
  return false;
}

int _apiDateMilliseconds(Object? value) {
  if (value is DateTime) {
    return value.millisecondsSinceEpoch;
  }
  if (value is num) {
    return value.toInt();
  }
  final text = value?.toString() ?? '';
  final parsed = DateTime.tryParse(text) ?? _apiDateTimeFromText(text);
  return parsed?.millisecondsSinceEpoch ?? 0;
}

DateTime? _apiDateTimeFromText(String value) {
  final match = RegExp(
    r'^(\d{4})[-/](\d{1,2})[-/](\d{1,2})(?:\s(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?)?$',
  ).firstMatch(value);
  if (match == null || !_apiCheckDateTime(value, '24')) {
    return null;
  }
  final hour = match.group(4) == null ? 0 : int.parse(match.group(4)!);
  final minute = match.group(5) == null ? 0 : int.parse(match.group(5)!);
  final second = match.group(6) == null ? 0 : int.parse(match.group(6)!);
  return DateTime(
    int.parse(match.group(1)!),
    int.parse(match.group(2)!),
    int.parse(match.group(3)!),
    hour,
    minute,
    second,
  );
}

bool _apiCheckDateTime(String value, String format) {
  final pattern = format == '24'
      ? RegExp(
          r'^(\d{4})-(\d{1,2})-(\d{1,2})(\s(\d{1,2}):(\d{1,2})(:(\d{1,2}))?)?$',
        )
      : RegExp(
          r'^(\d{4})-(\d{1,2})-(\d{1,2})(\s(\d{1,2}):(\d{1,2})(:(\d{1,2}))?)?\s?(AM|PM)?$',
        );
  final slashPattern = format == '24'
      ? RegExp(
          r'^(\d{4})\/(\d{1,2})\/(\d{1,2})(\s(\d{1,2}):(\d{1,2})(:(\d{1,2}))?)?$',
        )
      : RegExp(
          r'^(\d{4})\/(\d{1,2})\/(\d{1,2})(\s(\d{1,2}):(\d{1,2})(:(\d{1,2}))?)?\s?(AM|PM)?$',
        );
  final match = pattern.firstMatch(value) ?? slashPattern.firstMatch(value);
  if (match == null) {
    return false;
  }
  final year = int.parse(match.group(1)!);
  final month = int.parse(match.group(2)!);
  final day = int.parse(match.group(3)!);
  if (year < 1900 || month > 12 || day > 31) {
    return false;
  }
  if (month == 2) {
    final leapYear = (year % 4 == 0 && year % 100 != 0) || year % 400 == 0;
    if (day > (leapYear ? 29 : 28)) {
      return false;
    }
  }
  return true;
}

bool validateIdCard(String idCard) {
  final pattern = RegExp(
    r'^(^[1-9]\d{7}((0\d)|(1[0-2]))(([0|1|2]\d)|3[0-1])\d{3}$)|(^[1-9]\d{5}[1-9]\d{3}((0\d)|(1[0-2]))(([0|1|2]\d)|3[0-1])((\d{4})|\d{3}[Xx])$)$',
  );
  if (!pattern.hasMatch(idCard)) {
    return false;
  }
  if (idCard.length != 18) {
    return false;
  }
  const weights = [7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2];
  const checks = [1, 0, 10, 9, 8, 7, 6, 5, 4, 3, 2];
  var sum = 0;
  for (var index = 0; index < 17; index += 1) {
    sum += int.parse(idCard.substring(index, index + 1)) * weights[index];
  }
  final check = checks[sum % 11];
  final last = idCard.substring(17);
  if (check == 10) {
    return last == 'X' || last == 'x';
  }
  return last == '$check';
}

String defaultFont(num defaultFontSize) {
  return 'normal normal normal ${_apiCssNumber(defaultFontSize)}pt '
      '"Helvetica Neue", Helvetica, Arial, "PingFang SC", '
      '"Hiragino Sans GB", "Heiti SC",  "WenQuanYi Micro Hei", sans-serif';
}

String getFontSet(
  Object? format,
  num defaultFontSize, {
  List<String>? fontArray,
}) {
  if (format is! Map) {
    return defaultFont(defaultFontSize);
  }
  final fontAttr = <String>[];
  final italic = format['it'];
  fontAttr.add(
    italic == '0' || italic == 0 || italic == null ? 'normal' : 'italic',
  );
  fontAttr.add('normal');
  final bold = format['bl'];
  fontAttr.add(bold == '0' || bold == 0 || bold == null ? 'normal' : 'bold');
  final fontSize = _apiJsTruthy(format['fs'])
      ? _apiJsMathCeil(format['fs'])
      : defaultFontSize;
  fontAttr.add('${_apiCssNumber(fontSize)}pt');
  var fontSet =
      '"Helvetica Neue", Helvetica, Arial, "PingFang SC", '
      '"Hiragino Sans GB", "Heiti SC", "Microsoft YaHei", '
      '"WenQuanYi Micro Hei", sans-serif';
  if (fontArray != null && fontArray.isNotEmpty) {
    final rawFamily = format['ff'];
    String? fontFamily;
    if (!_apiJsTruthy(rawFamily)) {
      fontFamily = fontArray.first;
    } else {
      if (isdatatypemulti(rawFamily)['num'] == true) {
        final index = _apiParseIntRadix10('$rawFamily');
        fontFamily = index != null && index >= 0 && index < fontArray.length
            ? fontArray[index]
            : 'undefined';
      } else {
        fontFamily = '$rawFamily'.replaceAll('"', '').replaceAll("'", '');
        if (fontFamily.contains(' ')) {
          fontFamily = '"$fontFamily"';
        }
      }
    }
    fontSet = '$fontFamily,$fontSet';
  }
  return '${fontAttr.join(' ')} $fontSet';
}

int? _apiParseIntRadix10(String value) {
  final match = RegExp(r'^[\s\u00A0\uFEFF]*([+-]?\d+)').firstMatch(value);
  if (match == null) {
    return null;
  }
  return int.tryParse(match.group(1)!);
}

num _apiJsMathCeil(Object? value) {
  final number = _apiDataVerificationNumber(value);
  if (number.isNaN || number.isInfinite) {
    return number;
  }
  return number.ceil();
}

Map<String, Object?>? drawLineInfo(
  Map<String, Object?> wordGroup,
  Object? cancelLine,
  Object? underLine,
  Map<String, Object?> option,
) {
  if (wordGroup['wrap'] == true) {
    return null;
  }
  final style = wordGroup['style'];
  if (wordGroup['inline'] == true && style is Map) {
    cancelLine = style['cl'];
    underLine = style['un'];
  }
  final left = _nullableDoubleArg(option['left']) ?? 0;
  final top = _nullableDoubleArg(option['top']) ?? 0;
  final width = _nullableDoubleArg(option['width']) ?? 0;
  final asc = _nullableDoubleArg(option['asc']) ?? 0;
  final desc = _nullableDoubleArg(option['desc']) ?? 0;
  final fs = option['fs'];
  if (_apiLineNumber(cancelLine) != 0) {
    final y = top - asc / 2 + 1;
    wordGroup['cancelLine'] = {
      'startX': left,
      'startY': y,
      'endX': left + width,
      'endY': y,
      'fs': fs,
    };
  }
  final nUnderline = _apiLineNumber(underLine);
  if (nUnderline != 0) {
    final lines = <Map<String, Object?>>[];
    void addLine(double y) {
      lines.add({
        'startX': left,
        'startY': y,
        'endX': left + width,
        'endY': y,
        'fs': fs,
      });
    }

    if (nUnderline == 1 || nUnderline == 2) {
      addLine(top + 3);
    }
    if (nUnderline == 2) {
      addLine(top + desc);
    }
    if (nUnderline == 3 || nUnderline == 4) {
      addLine(top + desc);
    }
    if (nUnderline == 4) {
      addLine(top + desc + 2);
    }
    wordGroup['underLine'] = lines;
  }
  return wordGroup;
}

num _apiLineNumber(Object? value) {
  if (value is bool) {
    return value ? 1 : 0;
  }
  if (value is num) {
    return value;
  }
  if (value is String) {
    final trimmed = value.trim();
    if (trimmed.isEmpty) {
      return 0;
    }
    return num.tryParse(trimmed) ?? double.nan;
  }
  return value == null ? 0 : double.nan;
}

bool _apiJsTruthy(Object? value) {
  if (value == null) {
    return false;
  }
  if (value is bool) {
    return value;
  }
  if (value is num) {
    return value != 0;
  }
  if (value is String) {
    return value.isNotEmpty;
  }
  return true;
}

double datenumLocal(DateTime value, {bool date1904 = false}) {
  var epoch = DateTime.utc(
    value.year,
    value.month,
    value.day,
    value.hour,
    value.minute,
    value.second,
  );
  if (date1904) {
    epoch = epoch.subtract(const Duration(days: 1461));
  } else if (!value.isBefore(DateTime(1900, 3))) {
    epoch = epoch.add(const Duration(days: 1));
  }
  final threshold = DateTime.utc(1899, 12, 31);
  return epoch.difference(threshold).inSeconds / Duration.secondsPerDay;
}

// ignore: non_constant_identifier_names
double datenum_local(DateTime value, [num? date1904]) {
  return datenumLocal(value, date1904: date1904 != null && date1904 != 0);
}

Map<String, Object?> deleteCellInSave(
  Map<String, Object?> cellSave,
  FortuneRange range,
) {
  final normalized = _normalizedApiRange(range);
  if (normalized == null) {
    return cellSave;
  }
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      cellSave.remove('${row}_$column');
    }
  }
  return cellSave;
}

List<FortuneRange> getRangeArr(
  int minRow,
  int maxRow,
  int minColumn,
  int maxColumn,
  Map<String, Object?> cellSave,
  List<FortuneRange> rangeArr,
  FortuneSheet sheet,
) {
  if (cellSave.isEmpty) {
    return rangeArr;
  }
  int? stackRowStart;
  int? stackRowEnd;
  int? stackColumnStart;
  int? stackColumnEnd;

  FortuneRange pushStackRange() {
    final range = FortuneRange(
      rowStart: stackRowStart!,
      rowEnd: stackRowEnd!,
      columnStart: stackColumnStart!,
      columnEnd: stackColumnEnd!,
    );
    rangeArr.add(range);
    deleteCellInSave(cellSave, range);
    return range;
  }

  for (var row = minRow; row <= maxRow; row += 1) {
    for (var column = minColumn; column <= maxColumn; column += 1) {
      final key = '${row}_$column';
      final mergeRange = _apiOwnedMergeRangeAt(sheet, row, column);
      if (cellSave.containsKey(key)) {
        if (mergeRange != null) {
          if (stackColumnStart == null) {
            rangeArr.add(mergeRange);
            deleteCellInSave(cellSave, mergeRange);
            return getRangeArr(
              minRow,
              maxRow,
              minColumn,
              maxColumn,
              cellSave,
              rangeArr,
              sheet,
            );
          }
          if (stackColumnEnd != null && column < stackColumnEnd) {
            pushStackRange();
            return getRangeArr(
              minRow,
              maxRow,
              minColumn,
              maxColumn,
              cellSave,
              rangeArr,
              sheet,
            );
          }
          break;
        } else if (stackColumnStart == null) {
          stackColumnStart = column;
          stackColumnEnd = column;
          stackRowStart = row;
          stackRowEnd = row;
        } else if (stackColumnEnd != null && column > stackColumnEnd) {
          stackColumnEnd = column;
        }
      } else if (stackColumnStart != null) {
        if (_apiHasMergeMarkerAt(sheet, row, column)) {
          break;
        } else if (column < stackColumnStart) {
          continue;
        } else if (stackColumnEnd != null && column <= stackColumnEnd) {
          pushStackRange();
          return getRangeArr(
            minRow,
            maxRow,
            minColumn,
            maxColumn,
            cellSave,
            rangeArr,
            sheet,
          );
        } else {
          stackRowEnd = row;
        }
      }
    }
  }
  if (stackColumnStart != null) {
    pushStackRange();
    return getRangeArr(
      minRow,
      maxRow,
      minColumn,
      maxColumn,
      cellSave,
      rangeArr,
      sheet,
    );
  }
  return rangeArr;
}

FortuneRange? _apiOwnedMergeRangeAt(FortuneSheet sheet, int row, int column) {
  final merge = sheet.cells[FortuneCellCoord(row, column)]?.merge;
  if (merge == null || merge.row != row || merge.column != column) {
    return null;
  }
  final rowSpan = math.max(1, merge.rowSpan);
  final columnSpan = math.max(1, merge.columnSpan);
  if (rowSpan == 1 && columnSpan == 1) {
    return null;
  }
  return FortuneRange(
    rowStart: merge.row,
    rowEnd: merge.row + rowSpan - 1,
    columnStart: merge.column,
    columnEnd: merge.column + columnSpan - 1,
  );
}

bool _apiHasMergeMarkerAt(FortuneSheet sheet, int row, int column) {
  return sheet.cells[FortuneCellCoord(row, column)]?.merge != null;
}

String? getOptionValue(Map<String, bool> constants) {
  final enabledCount = constants.values.where((value) => value).length;
  if (enabledCount == 0) {
    return '';
  }
  if (enabledCount == 5) {
    return 'all';
  }
  final values = <String>[];
  for (final entry in constants.entries) {
    if (!entry.value) {
      continue;
    }
    switch (entry.key) {
      case 'locationDate':
        values.add('d');
      case 'locationDigital':
        values.add('n');
      case 'locationString':
        values.add('s,g');
      case 'locationBool':
        values.add('b');
      case 'locationError':
        values.add('e');
    }
  }
  return values.join(',');
}

List<FortuneRange> applyLocation(
  FortuneSheet sheet,
  Iterable<FortuneRange> ranges,
  String type, [
  String? value,
]) {
  final rangeArr = <FortuneRange>[];
  final normalizedRanges = [
    for (final range in ranges)
      if (_normalizedApiRange(range) != null) _normalizedApiRange(range)!,
  ];
  if (type == 'locationFormula' ||
      type == 'locationConstant' ||
      type == 'locationNull') {
    int? minRow;
    int? maxRow;
    int? minColumn;
    int? maxColumn;
    final cellSave = <String, Object?>{};
    for (final range in normalizedRanges) {
      if (minRow == null || minRow < range.rowStart) {
        minRow = range.rowStart;
      }
      if (maxRow == null || maxRow > range.rowEnd) {
        maxRow = range.rowEnd;
      }
      if (minColumn == null || minColumn < range.columnStart) {
        minColumn = range.columnStart;
      }
      if (maxColumn == null || maxColumn > range.columnEnd) {
        maxColumn = range.columnEnd;
      }
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final cell = _apiLocationCellAt(sheet, row, column);
          final cellValue = cell == null ? null : _apiRawCellAttr(cell, 'v');
          final cellType = cell?.cellType?.type;
          if (type == 'locationFormula' &&
              cell != null &&
              _apiLocationHasNonNullFormulaValue(cell) &&
              cell.formula != null &&
              (value == 'all' ||
                  (value != null &&
                      cellType != null &&
                      value.contains(cellType)))) {
            cellSave['${row}_$column'] = 0;
          } else if (type == 'locationConstant' &&
              _apiJsTruthy(cellValue) &&
              (value == 'all' ||
                  (value != null &&
                      cellType != null &&
                      value.contains(cellType)))) {
            cellSave['${row}_$column'] = 0;
          } else if (type == 'locationNull' &&
              _apiLocationCellHasNullValue(cell)) {
            cellSave['${row}_$column'] = 0;
          }
        }
      }
    }
    if (minRow == null ||
        maxRow == null ||
        minColumn == null ||
        maxColumn == null) {
      return rangeArr;
    }
    return getRangeArr(
      minRow,
      maxRow,
      minColumn,
      maxColumn,
      cellSave,
      rangeArr,
      sheet,
    );
  }
  if (type == 'locationRowSpan') {
    for (final range in normalizedRanges) {
      if (range.rowStart == range.rowEnd) {
        continue;
      }
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        if ((row - range.rowStart).isEven) {
          rangeArr.add(
            FortuneRange(
              rowStart: row,
              rowEnd: row,
              columnStart: range.columnStart,
              columnEnd: range.columnEnd,
            ),
          );
        }
      }
    }
  } else if (type == 'locationColumnSpan') {
    for (final range in normalizedRanges) {
      if (range.columnStart == range.columnEnd) {
        continue;
      }
      for (
        var column = range.columnStart;
        column <= range.columnEnd;
        column += 1
      ) {
        if ((column - range.columnStart).isEven) {
          rangeArr.add(
            FortuneRange(
              rowStart: range.rowStart,
              rowEnd: range.rowEnd,
              columnStart: column,
              columnEnd: column,
            ),
          );
        }
      }
    }
  }
  return rangeArr;
}

FortuneCell? _apiLocationCellAt(FortuneSheet sheet, int row, int column) {
  final anchor = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
  return sheet.cells[anchor];
}

bool _apiLocationHasNonNullFormulaValue(FortuneCell cell) {
  return !(cell.hasRawValue && cell.rawValue == null);
}

bool _apiLocationCellHasNullValue(FortuneCell? cell) {
  return cell == null || cell.hasRawValue && cell.rawValue == null;
}

bool isAllowEdit(
  FortuneSheet sheet, {
  Iterable<FortuneRange>? ranges,
  FortuneSettings settings = const FortuneSettings(),
}) {
  if (!settings.allowEdit) {
    return false;
  }
  final judgeRanges = ranges ?? sheet.getSelection();
  for (final range in judgeRanges) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      if (_apiIsIndexReadOnly(sheet.rowReadOnly, row)) {
        return false;
      }
    }
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      if (_apiIsIndexReadOnly(sheet.colReadOnly, column)) {
        return false;
      }
    }
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      for (
        var column = normalized.columnStart;
        column <= normalized.columnEnd;
        column += 1
      ) {
        final coord = sheet.mergeAnchorFor(FortuneCellCoord(row, column));
        if (!_apiCanEditCellIgnoringAxisReadOnly(sheet, coord)) {
          return false;
        }
      }
    }
  }
  return true;
}

bool checkCellIsLocked(FortuneSheet? sheet, int row, int column) {
  if (sheet == null) {
    return false;
  }
  final cell = sheet.cells[FortuneCellCoord(row, column)];
  if (cell?.locked != null) {
    return cell!.locked!;
  }
  return !_apiCanEditSheetDefaultCell(sheet);
}

bool checkProtectionSelectLockedOrUnLockedCells(
  FortuneSheet? sheet,
  int row,
  int column,
) {
  final authority = sheet?.authority;
  if (sheet == null ||
      authority is! Map ||
      _apiAuthoritySheetEditable(authority)) {
    return true;
  }
  final cell = sheet.cells[FortuneCellCoord(row, column)];
  if (cell?.locked == false) {
    return _apiAuthorityAllows(authority, 'selectunLockedCells');
  }
  return _apiAuthorityAllows(authority, 'selectLockedCells');
}

bool checkProtectionAllSelected(FortuneSheet? sheet) {
  final authority = sheet?.authority;
  if (sheet == null ||
      authority is! Map ||
      _apiAuthoritySheetEditable(authority)) {
    return true;
  }
  return _apiAuthorityAllows(authority, 'selectunLockedCells') &&
      _apiAuthorityAllows(authority, 'selectLockedCells');
}

bool checkProtectionFormatCells(FortuneSheet? sheet) {
  final authority = sheet?.authority;
  return sheet == null ||
      authority is! Map ||
      _apiAuthoritySheetEditable(authority);
}

Map<String, num> selectTitlesMap(
  Map<String, num>? rangeMap,
  int rangeStart,
  int rangeEnd,
) {
  final map = rangeMap ?? <String, num>{};
  for (var index = rangeStart; index <= rangeEnd; index += 1) {
    map.putIfAbsent('$index', () => 0);
  }
  return map;
}

List<List<int>> selectTitlesRange(Map<String, num> map) {
  final indexes = map.keys.map(int.parse).toList()..sort();
  if (indexes.isEmpty) {
    return const [];
  }
  final ranges = <List<int>>[];
  var current = <int>[indexes.first];
  for (var index = 1; index < indexes.length; index += 1) {
    final value = indexes[index];
    if (value - indexes[index - 1] == 1) {
      current.add(value);
    } else {
      ranges.add(current);
      current = <int>[value];
    }
  }
  ranges.add(current);
  return ranges;
}

bool selectIsOverlap(FortuneSheet sheet, [Iterable<FortuneRange>? ranges]) {
  final seen = <FortuneCellCoord>{};
  for (final range in ranges ?? sheet.getSelection()) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      for (
        var column = normalized.columnStart;
        column <= normalized.columnEnd;
        column += 1
      ) {
        if (!seen.add(FortuneCellCoord(row, column))) {
          return true;
        }
      }
    }
  }
  return false;
}

FortuneSheet selectAll(FortuneSheet sheet) {
  return sheet.setSelection([
    FortuneRange(
      rowStart: 0,
      rowEnd: _apiSelectionRowEnd(sheet),
      columnStart: 0,
      columnEnd: _apiSelectionColumnEnd(sheet),
      rowFocus: 0,
      columnFocus: 0,
      extraFields: const {'row_select': true, 'column_select': true},
    ),
  ]);
}

bool rowHasMerged(FortuneSheet sheet, int row, int columnStart, int columnEnd) {
  final start = math.min(columnStart, columnEnd);
  final end = math.max(columnStart, columnEnd);
  for (final range in _apiMergedRanges(sheet)) {
    if (row >= range.rowStart &&
        row <= range.rowEnd &&
        start <= range.columnEnd &&
        end >= range.columnStart) {
      return true;
    }
  }
  return false;
}

bool colHasMerged(FortuneSheet sheet, int column, int rowStart, int rowEnd) {
  final start = math.min(rowStart, rowEnd);
  final end = math.max(rowStart, rowEnd);
  for (final range in _apiMergedRanges(sheet)) {
    if (column >= range.columnStart &&
        column <= range.columnEnd &&
        start <= range.rowEnd &&
        end >= range.rowStart) {
      return true;
    }
  }
  return false;
}

List<int?> getRowMerge(
  FortuneSheet sheet,
  int rowIndex,
  int columnStart,
  int columnEnd,
) {
  final merges = _apiMergedRanges(sheet);
  final maxRow = merges.fold(
    _apiSheetMaxRow(sheet),
    (maxValue, range) => math.max(maxValue, range.rowEnd),
  );
  final startColumn = math.min(columnStart, columnEnd);
  final endColumn = math.max(columnStart, columnEnd);
  int? start;
  if (rowIndex > 0) {
    for (var row = rowIndex; row >= 0; row -= 1) {
      for (final range in merges) {
        if (row >= range.rowStart &&
            row <= range.rowEnd &&
            startColumn <= range.columnEnd &&
            endColumn >= range.columnStart) {
          start = start == null
              ? range.rowStart
              : math.min(start, range.rowStart);
        }
      }
      if (start != null &&
          start > 0 &&
          rowHasMerged(sheet, start - 1, startColumn, endColumn)) {
        row = start;
      } else {
        break;
      }
    }
  } else {
    start = 0;
  }
  int? end;
  if (rowIndex < maxRow) {
    for (var row = rowIndex; row <= maxRow; row += 1) {
      for (final range in merges) {
        if (row >= range.rowStart &&
            row <= range.rowEnd &&
            startColumn <= range.columnEnd &&
            endColumn >= range.columnStart) {
          end = end == null ? range.rowEnd : math.max(end, range.rowEnd);
        }
      }
      if (end != null &&
          end < maxRow &&
          rowHasMerged(sheet, end + 1, startColumn, endColumn)) {
        row = end;
      } else {
        break;
      }
    }
  } else {
    end = maxRow;
  }
  return [start, end];
}

List<int?> getColMerge(
  FortuneSheet sheet,
  int columnIndex,
  int rowStart,
  int rowEnd,
) {
  final merges = _apiMergedRanges(sheet);
  final maxColumn = merges.fold(
    _apiSheetMaxColumn(sheet),
    (maxValue, range) => math.max(maxValue, range.columnEnd),
  );
  final startRow = math.min(rowStart, rowEnd);
  final endRow = math.max(rowStart, rowEnd);
  int? start;
  if (columnIndex > 0) {
    for (var column = columnIndex; column >= 0; column -= 1) {
      for (final range in merges) {
        if (column >= range.columnStart &&
            column <= range.columnEnd &&
            startRow <= range.rowEnd &&
            endRow >= range.rowStart) {
          start = start == null
              ? range.columnStart
              : math.min(start, range.columnStart);
        }
      }
      if (start != null &&
          start > 0 &&
          colHasMerged(sheet, start - 1, startRow, endRow)) {
        column = start;
      } else {
        break;
      }
    }
  } else {
    start = 0;
  }
  int? end;
  if (columnIndex < maxColumn) {
    for (var column = columnIndex; column <= maxColumn; column += 1) {
      for (final range in merges) {
        if (column >= range.columnStart &&
            column <= range.columnEnd &&
            startRow <= range.rowEnd &&
            endRow >= range.rowStart) {
          end = end == null ? range.columnEnd : math.max(end, range.columnEnd);
        }
      }
      if (end != null &&
          end < maxColumn &&
          colHasMerged(sheet, end + 1, startRow, endRow)) {
        column = end;
      } else {
        break;
      }
    }
  } else {
    end = maxColumn;
  }
  return [start, end];
}

Map<String, num>? seletedHighlistByindex(
  List<num> visibleRow,
  List<num> visibleColumn,
  int rowStart,
  int rowEnd,
  int columnStart,
  int columnEnd,
) {
  final row = _apiListValue(visibleRow, rowEnd);
  final previousRow = rowStart - 1 == -1
      ? 0
      : _apiListValue(visibleRow, rowStart - 1);
  final column = _apiListValue(visibleColumn, columnEnd);
  final previousColumn = columnStart - 1 == -1
      ? 0
      : _apiListValue(visibleColumn, columnStart - 1);
  if (row == null ||
      previousRow == null ||
      column == null ||
      previousColumn == null) {
    return null;
  }
  return {
    'left': previousColumn,
    'width': column - previousColumn - 1,
    'top': previousRow,
    'height': row - previousRow - 1,
  };
}

num? _apiListValue(List<num> values, int index) {
  if (index < 0 || index >= values.length) {
    return null;
  }
  return values[index];
}

List<Map<String, int>> getSearchIndexArr(
  String searchText,
  Iterable<FortuneRange> ranges,
  FortuneSheet sheet, {
  bool regCheck = false,
  bool wordCheck = false,
  bool caseCheck = false,
}) {
  final results = <Map<String, int>>[];
  final seen = <String>{};
  for (final range in ranges) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      for (
        var column = normalized.columnStart;
        column <= normalized.columnEnd;
        column += 1
      ) {
        final cell = sheet.cells[FortuneCellCoord(row, column)];
        if (cell == null) {
          continue;
        }
        final rawValue = valueShowEs(cell);
        if (rawValue == null || rawValue == '') {
          continue;
        }
        final value = rawValue == 0 ? '0' : rawValue.toString();
        if (!_apiSearchValueMatches(
          searchText,
          value,
          regCheck: regCheck,
          wordCheck: wordCheck,
          caseCheck: caseCheck,
        )) {
          continue;
        }
        final key = '${row}_$column';
        if (seen.add(key)) {
          results.add({'r': row, 'c': column});
        }
      }
    }
  }
  return results;
}

List<Map<String, Object?>> searchAll(
  FortuneWorkbook workbook,
  String sheetId,
  String searchText, {
  Iterable<FortuneRange>? selection,
  bool regCheck = false,
  bool wordCheck = false,
  bool caseCheck = false,
}) {
  if (searchText.isEmpty) {
    return const [];
  }
  final sheetIndex = getSheetIndex(workbook, sheetId);
  if (sheetIndex == null) {
    return const [];
  }
  final sheet = workbook.sheets[sheetIndex];
  final ranges = getSelectRange(sheet, selection: selection);
  final searchIndexArr = getSearchIndexArr(
    searchText,
    ranges,
    sheet,
    regCheck: regCheck,
    wordCheck: wordCheck,
    caseCheck: caseCheck,
  );
  return [
    for (final index in searchIndexArr)
      <String, Object?>{
        'r': index['r'],
        'c': index['c'],
        'sheetName': sheet.name,
        'sheetId': sheet.id,
        'cellPosition': '${chatatABC(index['c']!)}${index['r']! + 1}',
        'value': valueShowEs(
          sheet.cells[FortuneCellCoord(index['r']!, index['c']!)],
        ).toString(),
      },
  ];
}

Map<String, Object?> searchNext(
  FortuneSheet sheet,
  String searchText, {
  Iterable<FortuneRange>? selection,
  bool regCheck = false,
  bool wordCheck = false,
  bool caseCheck = false,
  String searchInputTip = 'Please enter the search content',
  String noFindTip = 'The content was not found',
}) {
  final sourceSelection = (selection ?? sheet.getSelection()).toList();
  if (searchText.isEmpty) {
    return <String, Object?>{'message': searchInputTip, 'selection': null};
  }
  final searchIndexArr = getSearchIndexArr(
    searchText,
    getSelectRange(sheet, selection: sourceSelection),
    sheet,
    regCheck: regCheck,
    wordCheck: wordCheck,
    caseCheck: caseCheck,
  );
  if (searchIndexArr.isEmpty) {
    return <String, Object?>{'message': noFindTip, 'selection': null};
  }

  var count = 0;
  final isFullSheetSearch =
      sourceSelection.isEmpty ||
      sourceSelection.length == 1 &&
          sourceSelection.first.rowStart == sourceSelection.first.rowEnd &&
          sourceSelection.first.columnStart == sourceSelection.first.columnEnd;
  if (isFullSheetSearch) {
    if (sourceSelection.isNotEmpty) {
      count = _apiSearchNextIndex(searchIndexArr, sourceSelection.first);
    }
    final target = searchIndexArr[count];
    final nextSelection = <FortuneRange>[
      FortuneRange(
        rowStart: target['r']!,
        rowEnd: target['r']!,
        columnStart: target['c']!,
        columnEnd: target['c']!,
      ),
    ];
    return <String, Object?>{
      'message': null,
      'selection': nextSelection,
      'row': target['r'],
      'column': target['c'],
    };
  }

  final ranges = [for (final range in sourceSelection) range.copyWith()];
  count = _apiSearchNextIndex(searchIndexArr, ranges.last);
  final target = searchIndexArr[count];
  for (var index = 0; index < ranges.length; index += 1) {
    final normalized = _normalizedApiRange(ranges[index]);
    if (normalized == null) {
      continue;
    }
    if (target['r']! >= normalized.rowStart &&
        target['r']! <= normalized.rowEnd &&
        target['c']! >= normalized.columnStart &&
        target['c']! <= normalized.columnEnd) {
      final focused = ranges
          .removeAt(index)
          .copyWith(rowFocus: target['r'], columnFocus: target['c']);
      ranges.add(focused);
      break;
    }
  }
  return <String, Object?>{
    'message': null,
    'selection': ranges,
    'row': target['r'],
    'column': target['c'],
  };
}

Map<String, Object?> replace(
  FortuneSheet sheet,
  String searchText,
  String replaceText, {
  Iterable<FortuneRange>? selection,
  bool allowEdit = true,
  bool regCheck = false,
  bool wordCheck = false,
  bool caseCheck = false,
  String modeTip = 'This operation is not available in this mode',
  String searchInputTip = 'Please enter the search content',
  String noReplaceTip = 'There is nothing to replace',
}) {
  if (!allowEdit) {
    return {'sheet': sheet.copyWith(), 'selection': null, 'message': modeTip};
  }
  if (searchText.isEmpty) {
    return {
      'sheet': sheet.copyWith(),
      'selection': null,
      'message': searchInputTip,
    };
  }
  final sourceSelection = (selection ?? sheet.getSelection()).toList();
  final searchIndexArr = getSearchIndexArr(
    searchText,
    getSelectRange(sheet, selection: sourceSelection),
    sheet,
    regCheck: regCheck,
    wordCheck: wordCheck,
    caseCheck: caseCheck,
  );
  if (searchIndexArr.isEmpty) {
    return {
      'sheet': sheet.copyWith(),
      'selection': null,
      'message': noReplaceTip,
    };
  }

  var count = 0;
  if (sourceSelection.isNotEmpty) {
    final last = sourceSelection.last;
    final rowFocus = last.rowFocus ?? last.rowStart;
    final columnFocus = last.columnFocus ?? last.columnStart;
    for (var index = 0; index < searchIndexArr.length; index += 1) {
      if (searchIndexArr[index]['r'] == rowFocus &&
          searchIndexArr[index]['c'] == columnFocus) {
        count = index;
        break;
      }
    }
  }
  final target = searchIndexArr[count];
  final row = target['r']!;
  final column = target['c']!;
  final nextValue = wordCheck
      ? replaceText
      : _apiReplaceSearchValue(
          sheet.cells[FortuneCellCoord(row, column)],
          searchText,
          replaceText,
          caseCheck: caseCheck,
        );
  final nextSheet = setCellValue(sheet, row, column, nextValue).setSelection([
    FortuneRange(
      rowStart: row,
      rowEnd: row,
      columnStart: column,
      columnEnd: column,
    ),
  ]);
  return {
    'sheet': nextSheet,
    'selection': nextSheet.getSelection(),
    'row': row,
    'column': column,
    'message': null,
  };
}

Map<String, Object?> replaceAll(
  FortuneSheet sheet,
  String searchText,
  String replaceText, {
  Iterable<FortuneRange>? selection,
  bool allowEdit = true,
  bool regCheck = false,
  bool wordCheck = false,
  bool caseCheck = false,
  String modeTip = 'This operation is not available in this mode',
  String searchInputTip = 'Please enter the search content',
  String noReplaceTip = 'There is nothing to replace',
  String successTip = r'${xlength} items found',
}) {
  if (!allowEdit) {
    return {'sheet': sheet.copyWith(), 'selection': null, 'message': modeTip};
  }
  if (searchText.isEmpty) {
    return {
      'sheet': sheet.copyWith(),
      'selection': null,
      'message': searchInputTip,
      'replaceCount': 0,
    };
  }
  final sourceSelection = (selection ?? sheet.getSelection()).toList();
  final searchIndexArr = getSearchIndexArr(
    searchText,
    getSelectRange(sheet, selection: sourceSelection),
    sheet,
    regCheck: regCheck,
    wordCheck: wordCheck,
    caseCheck: caseCheck,
  );
  if (searchIndexArr.isEmpty) {
    return {
      'sheet': sheet.copyWith(),
      'selection': null,
      'message': noReplaceTip,
      'replaceCount': 0,
    };
  }
  var nextSheet = sheet.copyWith();
  final replacedSelection = getSelectRange(sheet, selection: sourceSelection);
  var replaceCount = 0;
  for (final target in searchIndexArr) {
    final row = target['r']!;
    final column = target['c']!;
    final nextValue = wordCheck
        ? replaceText
        : _apiReplaceSearchValue(
            nextSheet.cells[FortuneCellCoord(row, column)],
            searchText,
            replaceText,
            caseCheck: caseCheck,
          );
    nextSheet = setCellValue(nextSheet, row, column, nextValue);
    replacedSelection.add(
      FortuneRange(
        rowStart: row,
        rowEnd: row,
        columnStart: column,
        columnEnd: column,
      ),
    );
    replaceCount += 1;
  }
  nextSheet = nextSheet.setSelection(replacedSelection);
  return {
    'sheet': nextSheet,
    'selection': replacedSelection,
    'message': replaceHtml(successTip, {'xlength': replaceCount}),
    'replaceCount': replaceCount,
  };
}

String _apiReplaceSearchValue(
  FortuneCell? cell,
  String searchText,
  String replaceText, {
  required bool caseCheck,
}) {
  final value = valueShowEs(cell)?.toString() ?? '';
  final pattern = getRegExpStr(searchText);
  return value.replaceAll(
    RegExp(pattern, caseSensitive: caseCheck),
    replaceText,
  );
}

int _apiSearchNextIndex(
  List<Map<String, int>> searchIndexArr,
  FortuneRange range,
) {
  final rowFocus = range.rowFocus ?? range.rowStart;
  final columnFocus = range.columnFocus ?? range.columnStart;
  for (var index = 0; index < searchIndexArr.length; index += 1) {
    if (searchIndexArr[index]['r'] == rowFocus &&
        searchIndexArr[index]['c'] == columnFocus) {
      return index == searchIndexArr.length - 1 ? 0 : index + 1;
    }
  }
  return 0;
}

bool _apiSearchValueMatches(
  String searchText,
  String value, {
  required bool regCheck,
  required bool wordCheck,
  required bool caseCheck,
}) {
  if (wordCheck) {
    return caseCheck
        ? searchText == value
        : searchText.toLowerCase() == value.toLowerCase();
  }
  if (regCheck) {
    final pattern = getRegExpStr(searchText);
    return RegExp(pattern, caseSensitive: caseCheck).hasMatch(value);
  }
  return caseCheck
      ? value.contains(searchText)
      : value.toLowerCase().contains(searchText.toLowerCase());
}

List<FortuneRange> _apiMergedRanges(FortuneSheet sheet) {
  final ranges = <FortuneRange>[];
  final seen = <String>{};
  for (final entry in sheet.cells.entries) {
    final merge = entry.value.merge;
    if (merge == null || merge.rowSpan <= 1 && merge.columnSpan <= 1) {
      continue;
    }
    final anchorMerge =
        sheet.cells[FortuneCellCoord(merge.row, merge.column)]?.merge;
    if (anchorMerge == null ||
        anchorMerge.row != merge.row ||
        anchorMerge.column != merge.column ||
        anchorMerge.rowSpan != merge.rowSpan ||
        anchorMerge.columnSpan != merge.columnSpan) {
      continue;
    }
    final key =
        '${merge.row}_${merge.column}_${merge.rowSpan}_${merge.columnSpan}';
    if (!seen.add(key)) {
      continue;
    }
    ranges.add(
      FortuneRange(
        rowStart: merge.row,
        rowEnd: merge.row + merge.rowSpan - 1,
        columnStart: merge.column,
        columnEnd: merge.column + merge.columnSpan - 1,
      ),
    );
  }
  return ranges;
}

List<Map<String, Object?>> filterPatch(Iterable<Map<String, Object?>> patches) {
  return [
    for (final patch in patches)
      if (_apiShouldKeepPatch(patch)) Map<String, Object?>.from(patch),
  ];
}

List<Map<String, Object?>> extractFormulaCellOps(
  Iterable<Map<String, Object?>> ops,
) {
  final formulaOps = <Map<String, Object?>>[];
  for (final op in ops) {
    if (op['op'] == 'remove') {
      continue;
    }
    final path = _apiPath(op['path']);
    final value = op['value'];
    if (path.length == 2 && value is List) {
      for (var index = 0; index < value.length; index += 1) {
        final cell = value[index];
        if (cell is Map && _apiIsTruthy(cell['f'])) {
          formulaOps.add({
            'op': 'replace',
            if (op.containsKey('id')) 'id': op['id'],
            'path': [...path, index],
            'value': cell,
          });
        }
      }
    } else if (path.length == 3 && value is Map && _apiIsTruthy(value['f'])) {
      formulaOps.add(Map<String, Object?>.from(op));
    } else if (path.length == 4 && path[3] == 'f') {
      formulaOps.add(Map<String, Object?>.from(op));
    }
  }
  return formulaOps;
}

Map<String, Object?>? inverseRowColOptions(Map<String, Object?>? options) {
  if (options == null) {
    return null;
  }
  final insert = options['insertRowColOp'];
  if (insert is Map) {
    final index = _nullableIntArg(insert['index']) ?? 0;
    final count = _nullableIntArg(insert['count']) ?? 0;
    final direction = insert['direction']?.toString();
    final start = direction == 'rightbottom' ? index + 1 : index;
    return {
      'deleteRowColOp': {
        'type': insert['type'],
        'id': insert['id'],
        'start': start,
        'end': start + count - 1,
      },
    };
  }
  final delete = options['deleteRowColOp'];
  if (delete is Map) {
    final start = _nullableIntArg(delete['start']) ?? 0;
    final end = _nullableIntArg(delete['end']) ?? start;
    return {
      'insertRowColOp': {
        'type': delete['type'],
        'id': delete['id'],
        'index': start,
        'count': end - start + 1,
        'direction': 'lefttop',
      },
    };
  }
  return Map<String, Object?>.from(options);
}

List<Map<String, Object?>> patchToOp(
  FortuneWorkbook workbook,
  Iterable<Map<String, Object?>> patches, [
  Map<String, Object?>? options,
  bool undo = false,
]) {
  final ops = <Map<String, Object?>>[];
  for (final patch in patches) {
    final path = _apiPath(patch['path']);
    final op = <String, Object?>{
      'op': patch['op'],
      if (patch.containsKey('value')) 'value': patch['value'],
      'path': path,
    };
    if (path.length >= 2 && path[0] == 'luckysheetfile' && path[1] is int) {
      final sheetIndex = path[1] as int;
      if (sheetIndex >= 0 && sheetIndex < workbook.sheets.length) {
        final sheet = workbook.sheets[sheetIndex];
        op['id'] = sheet.id;
        final sheetPath = path.sublist(2);
        if (_apiPathEquals(sheetPath, const ['calcChain', 'length'])) {
          op['path'] = ['calcChain'];
          op['value'] = sheet.calcChain;
        } else {
          op['path'] = sheetPath;
        }
      }
    }
    ops.add(op);
  }

  final hyperlinkOps = <Map<String, Object?>>[];
  for (final op in ops) {
    final value = op['value'];
    final path = _apiPath(op['path']);
    if (op['op'] == 'replace' &&
        value is Map &&
        value['hl'] != null &&
        path.length == 3 &&
        path[0] == 'data') {
      final sheet = workbook.getSheet(id: op['id']?.toString());
      final hyperlink = value['hl'];
      final hyperlinkRow = hyperlink is Map
          ? _nullableIntArg(hyperlink['r'])
          : null;
      final hyperlinkColumn = hyperlink is Map
          ? _nullableIntArg(hyperlink['c'])
          : null;
      final hyperlinkValue = hyperlinkRow == null || hyperlinkColumn == null
          ? null
          : sheet?.hyperlinks['${hyperlinkRow}_$hyperlinkColumn'];
      hyperlinkOps.add({
        'op': 'replace',
        if (op.containsKey('id')) 'id': op['id'],
        'path': ['hyperlink', '${path[1]}_${path[2]}'],
        'value': hyperlinkValue,
      });
    }
  }
  ops.addAll(hyperlinkOps);

  final insertRowColOp = options?['insertRowColOp'];
  if (insertRowColOp is Map) {
    return _apiPatchToRowColOps(
      workbook,
      ops,
      'insertRowCol',
      Map<String, Object?>.from(insertRowColOp),
      restoreDeletedCells: options?['restoreDeletedCells'] == true,
    );
  }
  final deleteRowColOp = options?['deleteRowColOp'];
  if (deleteRowColOp is Map) {
    return _apiPatchToRowColOps(
      workbook,
      ops,
      'deleteRowCol',
      Map<String, Object?>.from(deleteRowColOp),
    );
  }
  if (options?['addSheetOp'] == true) {
    return _apiPatchToAddSheetOps(
      workbook,
      ops,
      Map<String, Object?>.from(options!),
      undo: undo,
    );
  }
  final deleteSheetOp = options?['deleteSheetOp'];
  if (deleteSheetOp is Map) {
    return _apiPatchToDeleteSheetOps(
      workbook,
      Map<String, Object?>.from(options!),
      Map<String, Object?>.from(deleteSheetOp),
      undo: undo,
    );
  }
  return ops;
}

List<Map<String, Object?>> _apiPatchToAddSheetOps(
  FortuneWorkbook workbook,
  List<Map<String, Object?>> ops,
  Map<String, Object?> options, {
  bool undo = false,
}) {
  final addSheet = options['addSheet'] is Map
      ? Map<String, Object?>.from(options['addSheet']! as Map)
      : const <String, Object?>{};
  final id = addSheet['id']?.toString() ?? options['id']?.toString();
  final addSheetOps = <Map<String, Object?>>[];
  final otherOps = <Map<String, Object?>>[];
  for (final op in ops) {
    if (op['op'] == 'add' && _apiPath(op['path']).isEmpty) {
      addSheetOps.add(op);
    } else {
      otherOps.add(op);
    }
  }
  final addSheetValue = addSheetOps.isEmpty ? null : addSheetOps.first['value'];
  final sheetOp = <String, Object?>{
    'op': undo ? 'deleteSheet' : 'addSheet',
    'path': const <Object?>[],
    'value': undo ? addSheet : addSheetValue,
  };
  if (id != null) {
    sheetOp['id'] = id;
  }
  if (undo) {
    final order = _apiChangedSheetOrder(addSheet);
    if (order != null) {
      return [
        ...otherOps,
        sheetOp,
        ..._apiPatchSheetOrderOps(workbook, order, decrement: true),
      ];
    }
  }
  return [...otherOps, sheetOp];
}

List<Map<String, Object?>> _apiPatchToDeleteSheetOps(
  FortuneWorkbook workbook,
  Map<String, Object?> options,
  Map<String, Object?> deleteSheetOp, {
  bool undo = false,
}) {
  final deletedSheet = options['deletedSheet'] is Map
      ? Map<String, Object?>.from(options['deletedSheet']! as Map)
      : const <String, Object?>{};
  final id = deleteSheetOp['id']?.toString() ?? options['id']?.toString();
  if (undo) {
    final addSheetOp = <String, Object?>{
      'op': 'addSheet',
      'path': const <Object?>[],
      'value': deletedSheet['value'],
    };
    final nameOp = <String, Object?>{
      'op': 'replace',
      'path': const ['name'],
      'value': (deletedSheet['value'] is Map)
          ? (deletedSheet['value']! as Map)['name']
          : null,
    };
    if (id != null) {
      addSheetOp['id'] = id;
      nameOp['id'] = id;
    }
    final order = _apiChangedSheetOrder(deletedSheet);
    return [
      addSheetOp,
      nameOp,
      if (order != null)
        ..._apiPatchSheetOrderOps(workbook, order, excludeId: id),
    ];
  }
  final deleteOp = <String, Object?>{
    'op': 'deleteSheet',
    'path': const <Object?>[],
    'value': deletedSheet,
  };
  if (id != null) {
    deleteOp['id'] = id;
  }
  final order = _apiChangedSheetOrder(deletedSheet);
  return [
    deleteOp,
    if (order != null) ..._apiPatchSheetOrderOps(workbook, order),
  ];
}

int? _apiChangedSheetOrder(Map<String, Object?> changedSheet) {
  final rawValue = changedSheet['value'];
  if (rawValue is Map) {
    final value = Map<String, Object?>.from(rawValue);
    final order = _nullableIntArg(value['order']);
    if (order != null) {
      return order;
    }
  }
  return _nullableIntArg(changedSheet['order']);
}

List<Map<String, Object?>> _apiPatchSheetOrderOps(
  FortuneWorkbook workbook,
  int order, {
  String? excludeId,
  bool decrement = false,
}) {
  final ops = <Map<String, Object?>>[];
  for (final sheet in workbook.sheets) {
    final sheetOrder = sheet.order;
    if (sheetOrder == null || sheetOrder < order || sheet.id == excludeId) {
      continue;
    }
    ops.add({
      'op': 'replace',
      'id': sheet.id,
      'path': const ['order'],
      'value': decrement ? sheetOrder - 1 : sheetOrder,
    });
  }
  return ops;
}

List<Map<String, Object?>> _apiPatchToRowColOps(
  FortuneWorkbook workbook,
  List<Map<String, Object?>> ops,
  String opType,
  Map<String, Object?> rowColOp, {
  bool restoreDeletedCells = false,
}) {
  final nonDataOps = <Map<String, Object?>>[];
  final dataOps = <Map<String, Object?>>[];
  for (final op in ops) {
    final path = _apiPath(op['path']);
    if (path.isNotEmpty && path[0] == 'data') {
      dataOps.add(op);
    } else {
      nonDataOps.add(op);
    }
  }
  final nextOps = <Map<String, Object?>>[
    ...nonDataOps,
    {
      'op': opType,
      'id': rowColOp['id'],
      'path': const <Object?>[],
      'value': rowColOp,
    },
    ...extractFormulaCellOps(dataOps),
  ];
  nextOps.addAll(
    _apiPatchAdditionalMergeOps(nextOps, rowColOp['id']?.toString()),
  );
  if (opType == 'insertRowCol') {
    if (restoreDeletedCells) {
      nextOps.addAll(_apiPatchRestoreDeletedCellOps(workbook, rowColOp));
    } else {
      nextOps.addAll(_apiPatchAdditionalCellOps(workbook, rowColOp));
    }
  }
  return nextOps;
}

List<Map<String, Object?>> _apiPatchAdditionalMergeOps(
  Iterable<Map<String, Object?>> ops,
  String? fallbackSheetId,
) {
  final mergeOps = <Map<String, Object?>>[];
  for (final op in ops) {
    if (op['op'] != 'replace' ||
        !_apiPathEquals(_apiPath(op['path']), const ['config', 'merge'])) {
      continue;
    }
    final rawMerge = op['value'];
    if (rawMerge is! Map) {
      continue;
    }
    final sheetId = op['id']?.toString() ?? fallbackSheetId;
    for (final entry in rawMerge.entries) {
      final rawValue = entry.value;
      if (rawValue is! Map) {
        continue;
      }
      final merge = Map<String, Object?>.from(rawValue);
      final mergeRow = _nullableIntArg(merge['r']);
      final mergeColumn = _nullableIntArg(merge['c']);
      if (mergeRow == null || mergeColumn == null) {
        continue;
      }
      final rowSpan = math.max(1, _nullableIntArg(merge['rs']) ?? 1);
      final columnSpan = math.max(1, _nullableIntArg(merge['cs']) ?? 1);
      for (
        var rowIndex = mergeRow;
        rowIndex < mergeRow + rowSpan;
        rowIndex += 1
      ) {
        for (
          var columnIndex = mergeColumn;
          columnIndex < mergeColumn + columnSpan;
          columnIndex += 1
        ) {
          mergeOps.add({
            'op': 'replace',
            'id': ?sheetId,
            'path': ['data', rowIndex, columnIndex, 'mc'],
            'value': {'r': mergeRow, 'c': mergeColumn},
          });
        }
      }
      mergeOps.add({
        'op': 'replace',
        'id': ?sheetId,
        'path': ['data', mergeRow, mergeColumn, 'mc'],
        'value': cloneFortuneMetadata(merge),
      });
    }
  }
  return mergeOps;
}

List<Map<String, Object?>> _apiPatchRestoreDeletedCellOps(
  FortuneWorkbook workbook,
  Map<String, Object?> insertRowColOp,
) {
  final sheet = workbook.getSheet(id: insertRowColOp['id']?.toString());
  if (sheet == null) {
    return const [];
  }
  final type = insertRowColOp['type']?.toString();
  final index = _nullableIntArg(insertRowColOp['index']) ?? 0;
  final count = _nullableIntArg(insertRowColOp['count']) ?? 0;
  final ops = <Map<String, Object?>>[];
  for (final entry in sheet.cells.entries) {
    final coord = entry.key;
    final inRestoredRange = type == 'row'
        ? coord.row >= index && coord.row < index + count
        : coord.column >= index && coord.column < index + count;
    if (!inRestoredRange) {
      continue;
    }
    ops.add({
      'op': 'replace',
      'id': sheet.id,
      'path': ['data', coord.row, coord.column],
      'value': _apiCellToPatchValue(entry.value),
    });
  }
  return ops;
}

List<Map<String, Object?>> _apiPatchAdditionalCellOps(
  FortuneWorkbook workbook,
  Map<String, Object?> insertRowColOp,
) {
  final sheet = workbook.getSheet(id: insertRowColOp['id']?.toString());
  if (sheet == null) {
    return const [];
  }
  final type = insertRowColOp['type']?.toString();
  final index = _nullableIntArg(insertRowColOp['index']) ?? 0;
  final count = _nullableIntArg(insertRowColOp['count']) ?? 0;
  final direction = insertRowColOp['direction']?.toString();
  final startIndex = index + (direction == 'rightbottom' ? 1 : 0);
  final ops = <Map<String, Object?>>[];
  if (type == 'row') {
    for (final entry in sheet.cells.entries) {
      if (entry.key.row != startIndex) {
        continue;
      }
      for (var offset = 0; offset < count; offset += 1) {
        ops.add({
          'op': 'replace',
          'id': sheet.id,
          'path': ['data', startIndex + offset, entry.key.column],
          'value': _apiCellToPatchValue(entry.value),
        });
      }
    }
    return ops;
  }
  if (type == 'column') {
    for (final entry in sheet.cells.entries) {
      if (entry.key.column != startIndex) {
        continue;
      }
      for (var offset = 0; offset < count; offset += 1) {
        ops.add({
          'op': 'replace',
          'id': sheet.id,
          'path': ['data', entry.key.row, startIndex + offset],
          'value': _apiCellToPatchValue(entry.value),
        });
      }
    }
  }
  return ops;
}

Map<String, Object?> _apiCellToPatchValue(FortuneCell cell) {
  return FortuneSheetCodec.cellToJson(cell);
}

List<List<Map<String, Object?>>> opToPatch(
  FortuneWorkbook workbook,
  Iterable<Map<String, Object?>> ops, {
  String? currentSheetId,
}) {
  final normalOps = <Map<String, Object?>>[];
  final specialOps = <Map<String, Object?>>[];
  for (final op in ops) {
    final opType = op['op'];
    if (opType == 'add' || opType == 'remove' || opType == 'replace') {
      normalOps.add(op);
    } else {
      specialOps.add(Map<String, Object?>.from(op));
    }
  }

  final activeSheetId = currentSheetId ?? workbook.activeSheet.id;
  final patches = <Map<String, Object?>>[];
  final additionalPatches = <Map<String, Object?>>[];
  for (final op in normalOps) {
    final path = _apiPath(op['path']);
    final patch = <String, Object?>{
      'op': op['op'],
      if (op.containsKey('value')) 'value': op['value'],
      'path': path,
    };
    final id = op['id']?.toString();
    if (id != null) {
      final sheetIndex = getSheetIndex(workbook, id);
      if (sheetIndex != null) {
        patch['path'] = ['luckysheetfile', sheetIndex, ...path];
      }
      if (path.isNotEmpty && path[0] == 'images' && id == activeSheetId) {
        additionalPatches.add({
          ...patch,
          'path': ['insertedImgs'],
        });
      }
    }
    patches.add(patch);
  }
  return [patches.followedBy(additionalPatches).toList(), specialOps];
}

FortuneWorkbook applyOp(
  FortuneWorkbook workbook,
  Iterable<Map<String, Object?>> ops,
) {
  var nextWorkbook = workbook.copyWith();
  for (final rawOp in ops) {
    final op = Map<String, Object?>.from(rawOp);
    final opType = op['op']?.toString();
    switch (opType) {
      case 'add':
      case 'replace':
      case 'remove':
        nextWorkbook = _apiApplyNormalOp(nextWorkbook, opType!, op);
        break;
      case 'addSheet':
        nextWorkbook = _apiApplyAddSheetOp(nextWorkbook, op);
        break;
      case 'deleteSheet':
        nextWorkbook = _apiApplyDeleteSheetOp(nextWorkbook, op);
        break;
      case 'insertRowCol':
        nextWorkbook = _apiApplyRowColOp(nextWorkbook, op, insert: true);
        break;
      case 'deleteRowCol':
        nextWorkbook = _apiApplyRowColOp(nextWorkbook, op, insert: false);
        break;
    }
  }
  return nextWorkbook;
}

FortuneWorkbook _apiApplyNormalOp(
  FortuneWorkbook workbook,
  String opType,
  Map<String, Object?> op,
) {
  final sheetId = op['id']?.toString();
  final path = _apiPath(op['path']);
  if (sheetId == null && opType == 'add' && path.isEmpty) {
    return _apiApplyAddSheetOp(workbook, op);
  }
  if (sheetId == null) {
    final json = Map<String, Object?>.from(
      FortuneSheetCodec.workbookToJson(workbook),
    );
    _apiApplyJsonPathOp(json, path, opType, op['value']);
    return FortuneSheetCodec.workbookFromJson(
      json,
      settings: workbook.settings,
    );
  }
  final sheetIndex = getSheetIndex(workbook, sheetId);
  if (sheetIndex == null) {
    return workbook.copyWith();
  }
  final sheet = workbook.sheets[sheetIndex];
  final nextSheet = path.isNotEmpty && path.first == 'data'
      ? _apiApplyCellDataOp(sheet, path, opType, op['value'])
      : _apiApplySheetJsonOp(sheet, path, opType, op['value']);
  return _apiWorkbookWithSheet(workbook, nextSheet);
}

FortuneSheet _apiApplyCellDataOp(
  FortuneSheet sheet,
  List<Object?> path,
  String opType,
  Object? value,
) {
  if (path.length < 3) {
    return _apiApplySheetJsonOp(sheet, path, opType, value);
  }
  final row = _nullableIntArg(path[1]);
  final column = _nullableIntArg(path[2]);
  if (row == null || column == null || row < 0 || column < 0) {
    return sheet.copyWith();
  }
  final coord = FortuneCellCoord(row, column);
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  if (path.length == 3) {
    if (opType == 'remove' || value == null) {
      cells.remove(coord);
    } else if (value is Map) {
      cells[coord] = FortuneSheetCodec.cellFromJson(
        Map<String, Object?>.from(value),
      );
    }
    return sheet.copyWith(cells: cells);
  }
  if (opType == 'remove' && !cells.containsKey(coord)) {
    return sheet.copyWith();
  }
  final cellJson = cells.containsKey(coord)
      ? FortuneSheetCodec.cellToJson(cells[coord]!)
      : <String, Object?>{};
  _apiApplyJsonPathOp(cellJson, path.sublist(3), opType, value);
  cells[coord] = FortuneSheetCodec.cellFromJson(cellJson);
  return sheet.copyWith(cells: cells);
}

FortuneSheet _apiApplySheetJsonOp(
  FortuneSheet sheet,
  List<Object?> path,
  String opType,
  Object? value,
) {
  final json = Map<String, Object?>.from(FortuneSheetCodec.sheetToJson(sheet));
  _apiApplyJsonPathOp(json, path, opType, value);
  return FortuneSheetCodec.sheetFromJson(json);
}

FortuneWorkbook _apiApplyAddSheetOp(
  FortuneWorkbook workbook,
  Map<String, Object?> op,
) {
  final value = op['value'];
  if (value is! Map) {
    return workbook.copyWith();
  }
  final sheetJson = Map<String, Object?>.from(value);
  final id = op['id']?.toString();
  if (id != null) {
    sheetJson['id'] = id;
  }
  final sheet = FortuneSheetCodec.sheetFromJson(sheetJson);
  if (getSheetIndex(workbook, sheet.id) != null) {
    return _apiWorkbookWithSheet(workbook, sheet);
  }
  return workbook.copyWith(sheets: [...workbook.sheets, sheet]);
}

FortuneWorkbook _apiApplyDeleteSheetOp(
  FortuneWorkbook workbook,
  Map<String, Object?> op,
) {
  final value = op['value'];
  final valueMap = value is Map ? Map<String, Object?>.from(value) : null;
  final id = op['id']?.toString() ?? valueMap?['id']?.toString();
  if (id == null) {
    return workbook.copyWith();
  }
  return deleteSheet(workbook, id: id);
}

FortuneWorkbook _apiApplyRowColOp(
  FortuneWorkbook workbook,
  Map<String, Object?> op, {
  required bool insert,
}) {
  final value = op['value'];
  if (value is! Map) {
    return workbook.copyWith();
  }
  final rowColOp = Map<String, Object?>.from(value);
  final id = op['id']?.toString() ?? rowColOp['id']?.toString();
  final index = id == null ? null : getSheetIndex(workbook, id);
  if (index == null) {
    return workbook.copyWith();
  }
  final sheet = workbook.sheets[index];
  final type = rowColOp['type']?.toString() ?? 'row';
  final start = _nullableIntArg(rowColOp['start']) ?? 0;
  final end = _nullableIntArg(rowColOp['end']) ?? start;
  final deleteBounds = _apiDeleteBoundsForSheet(sheet, type, start, end);
  if (!insert && deleteBounds == null) {
    return workbook.copyWith();
  }
  final opIndex = insert
      ? _nullableIntArg(rowColOp['index']) ?? 0
      : deleteBounds!.start;
  final opCount = insert
      ? _nullableIntArg(rowColOp['count']) ?? 1
      : deleteBounds!.end - deleteBounds.start + 1;
  final direction = rowColOp['direction']?.toString() ?? 'rightbottom';
  final nextSheet = insert
      ? sheet.insertRowOrColumn(type, opIndex, opCount, direction: direction)
      : deleteRowOrColumn(sheet, type, start, end);
  final sheets = [
    for (final current in workbook.sheets)
      current.id == sheet.id
          ? nextSheet
          : _apiRewriteCalcChainCellFormulasForRowColOp(
              current,
              type: type,
              insert: insert,
              index: opIndex,
              count: opCount,
              direction: direction,
              targetSheetName: sheet.name,
            ),
  ];
  return workbook.copyWith(sheets: sheets);
}

FortuneSheet _apiRewriteCalcChainCellFormulasForRowColOp(
  FortuneSheet sheet, {
  required String type,
  required bool insert,
  required int index,
  required int count,
  required String direction,
  required String targetSheetName,
}) {
  final calcChain = _apiFormulaGroupEntries(sheet.calcChain);
  if (calcChain.isEmpty) {
    return sheet.copyWith();
  }
  var changed = false;
  final cells = {
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  for (final entry in calcChain) {
    final row = _nullableIntArg(entry['r']);
    final column = _nullableIntArg(entry['c']);
    final sheetId = entry['id']?.toString();
    if (row == null ||
        column == null ||
        sheetId != null && sheetId != sheet.id) {
      continue;
    }
    final coord = FortuneCellCoord(row, column);
    final cell = cells[coord];
    final formula = cell?.formula;
    if (cell == null || formula == null || !formula.startsWith('=')) {
      continue;
    }
    final nextFormula = insert
        ? rewriteFormulaReferencesForInsert(
            formula,
            type: type,
            index: index,
            count: count,
            direction: direction,
            targetSheetName: targetSheetName,
          )
        : rewriteFormulaReferencesForDelete(
            formula,
            type: type,
            start: index,
            end: index + count - 1,
            targetSheetName: targetSheetName,
          );
    if (nextFormula == formula) {
      continue;
    }
    changed = true;
    cells[coord] = cell.copyWith(
      formula: nextFormula,
      rawFormula: cell.hasRawFormula ? nextFormula : _sentinel,
      hasRawFormula: cell.hasRawFormula,
    );
  }
  return changed ? sheet.copyWith(cells: cells) : sheet.copyWith();
}

FortuneWorkbook _apiWorkbookWithSheet(
  FortuneWorkbook workbook,
  FortuneSheet sheet,
) {
  final sheets = [for (final current in workbook.sheets) current.copyWith()];
  final index = sheets.indexWhere((current) => current.id == sheet.id);
  if (index < 0) {
    return workbook.copyWith();
  }
  sheets[index] = sheet;
  return workbook.copyWith(sheets: sheets);
}

void _apiApplyJsonPathOp(
  Object? target,
  List<Object?> path,
  String opType,
  Object? value,
) {
  if (path.isEmpty) {
    return;
  }
  var current = target;
  for (var index = 0; index < path.length - 1; index += 1) {
    final segment = path[index];
    final nextSegment = path[index + 1];
    if (current is Map) {
      final key = segment.toString();
      current = current.putIfAbsent(
        key,
        () => nextSegment is int ? <Object?>[] : <String, Object?>{},
      );
    } else if (current is List) {
      final listIndex = _nullableIntArg(segment);
      if (listIndex == null || listIndex < 0) {
        return;
      }
      while (current.length <= listIndex) {
        current.add(null);
      }
      current[listIndex] ??= nextSegment is int
          ? <Object?>[]
          : <String, Object?>{};
      current = current[listIndex];
    } else {
      return;
    }
  }
  final last = path.last;
  final clonedValue = _apiCloneJsonPathValue(value);
  if (current is Map) {
    final key = last.toString();
    if (opType == 'remove') {
      current.remove(key);
    } else {
      current[key] = clonedValue;
    }
  } else if (current is List) {
    final listIndex = _nullableIntArg(last);
    if (listIndex == null || listIndex < 0) {
      return;
    }
    if (opType == 'add') {
      if (listIndex <= current.length) {
        current.insert(listIndex, clonedValue);
      }
    } else if (opType == 'remove') {
      if (listIndex < current.length) {
        current.removeAt(listIndex);
      }
    } else {
      while (current.length <= listIndex) {
        current.add(null);
      }
      current[listIndex] = clonedValue;
    }
  }
}

Object? _apiCloneJsonPathValue(Object? value) {
  if (value is Map) {
    return <String, Object?>{
      for (final entry in value.entries)
        entry.key.toString(): _apiCloneJsonPathValue(entry.value),
    };
  }
  if (value is List) {
    return <Object?>[for (final item in value) _apiCloneJsonPathValue(item)];
  }
  if (value is Set) {
    return <Object?>[for (final item in value) _apiCloneJsonPathValue(item)];
  }
  return value;
}

bool _apiPathEquals(List<Object?> left, List<Object?> right) {
  if (left.length != right.length) {
    return false;
  }
  for (var index = 0; index < left.length; index += 1) {
    if (left[index] != right[index]) {
      return false;
    }
  }
  return true;
}

List<Object?> _apiPath(Object? raw) {
  if (raw is List) {
    return List<Object?>.from(raw);
  }
  return const [];
}

bool _apiIsTruthy(Object? value) {
  if (value == null || value == false) {
    return false;
  }
  if (value is num) {
    return value != 0;
  }
  if (value is String) {
    return value.isNotEmpty;
  }
  return true;
}

String _apiTwoDigit(int value) => value < 10 ? '0$value' : '$value';

double? _apiParseFloat(String value) {
  final match = RegExp(
    r'^[\s\u00A0\uFEFF]*([+-]?(?:Infinity|(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][+-]?\d+)?))',
  ).firstMatch(value);
  if (match == null) {
    return null;
  }
  final token = match.group(1)!;
  if (token == 'Infinity' || token == '+Infinity') {
    return double.infinity;
  }
  if (token == '-Infinity') {
    return double.negativeInfinity;
  }
  return double.tryParse(token);
}

bool _apiShouldKeepPatch(Map<String, Object?> patch) {
  final path = _apiPath(patch['path']);
  return path.isNotEmpty &&
      path[0] == 'luckysheetfile' &&
      (path.length <= 2 || path[2] != 'luckysheet_select_save');
}

List<Map<String, Object?>> _apiConditionRulesBySheet(
  Iterable<FortuneSheet> sheets,
) {
  final rules = <Map<String, Object?>>[];
  var index = 0;
  for (final sheet in sheets) {
    rules.add({
      'sheetIndex': index,
      'luckysheet_conditionformat_save': cloneFortuneMetadata(
        sheet.conditionFormats,
      ),
    });
    index += 1;
  }
  return rules;
}

List<Map<String, Object?>> _apiFormulaGroupEntries(Object? value) {
  if (value is! Iterable) {
    return const [];
  }
  return [
    for (final entry in value)
      if (entry is Map) Map<String, Object?>.from(entry),
  ];
}

bool _apiFormulaGroupContains(Object? value, int row, int column, String id) {
  return _apiFormulaGroupEntries(value).any(
    (entry) => entry['r'] == row && entry['c'] == column && entry['id'] == id,
  );
}

List<Map<String, Object?>> _apiFormulaGroupWithout(
  Object? value,
  int row,
  int column,
  String id, {
  bool allowMissingId = false,
}) {
  final entries = _apiFormulaGroupEntries(value);
  final removeIndex = entries.indexWhere(
    (entry) =>
        entry['r'] == row &&
        entry['c'] == column &&
        (entry['id'] == id || allowMissingId && entry['id'] == null),
  );
  if (removeIndex < 0) {
    return entries;
  }
  return [...entries]..removeAt(removeIndex);
}

Object? _apiRawCellAttr(FortuneCell cell, String attr) {
  return switch (attr) {
    'v' => cell.hasRawValue ? cell.rawValue : cell.value,
    'm' => cell.hasRawDisplayValue ? cell.rawDisplayValue : cell.displayValue,
    'f' => cell.hasRawFormula ? cell.rawFormula : cell.formula,
    'bg' =>
      cell.hasRawBackground
          ? cell.rawBackground
          : cell.background == null
          ? null
          : _apiCssColor(cell.background!),
    'fc' =>
      cell.hasRawForeground
          ? cell.rawForeground
          : _apiCssColor(cell.foreground),
    'bl' => cell.hasRawBold ? cell.rawBold : cell.bold,
    'it' => cell.hasRawItalic ? cell.rawItalic : cell.italic,
    'cl' =>
      cell.hasRawStrikeThrough ? cell.rawStrikeThrough : cell.strikeThrough,
    'un' => cell.hasRawUnderline ? cell.rawUnderline : cell.underline,
    'fs' =>
      cell.hasRawFontSize
          ? cell.rawFontSize
          : cell.fontSize == null
          ? null
          : _apiCssNumber(cell.fontSize!),
    'ff' => cell.hasRawFontFamily ? cell.rawFontFamily : cell.fontFamily,
    'ht' =>
      cell.hasRawHorizontalAlign
          ? cell.rawHorizontalAlign
          : cell.horizontalAlign,
    'vt' =>
      cell.hasRawVerticalAlign ? cell.rawVerticalAlign : cell.verticalAlign,
    'tb' => cell.hasRawTextWrap ? cell.rawTextWrap : cell.textWrap,
    'tr' =>
      cell.hasRawTextRotationMode
          ? cell.rawTextRotationMode
          : cell.textRotationMode ?? cell.textRotation,
    _ => cell.extraFields[attr],
  };
}

Object? _apiNormalizeColorAttr(Object? value, String? fallback) {
  if (value == null) {
    return fallback;
  }
  if (value is String && value.contains('rgba')) {
    return rgbToHex(value);
  }
  return value;
}

Object? _apiNormalizeFlagAttr(Object? value) {
  if (value == null || value == false) {
    return '0';
  }
  if (value == true) {
    return '1';
  }
  if (value is num) {
    return value == 0 ? '0' : '1';
  }
  return value;
}

bool _apiIsIndexReadOnly(Object? raw, int index) {
  if (raw is! Map) {
    return false;
  }
  final value = raw[index] ?? raw['$index'];
  if (value == null) {
    return false;
  }
  if (value is bool) {
    return value;
  }
  if (value is num) {
    return value != 0;
  }
  final normalized = '$value'.toLowerCase();
  return normalized != '0' && normalized != 'false';
}

bool _apiCanEditCellIgnoringAxisReadOnly(
  FortuneSheet sheet,
  FortuneCellCoord coord,
) {
  final locked = sheet.cells[coord]?.locked;
  if (locked != null) {
    return !locked;
  }
  return _apiCanEditSheetDefaultCell(sheet);
}

bool _apiCanEditSheetDefaultCell(FortuneSheet sheet) {
  final authority = sheet.authority;
  if (authority is! Map) {
    return true;
  }
  final sheetProtection = authority['sheet'];
  if (sheetProtection == null) {
    return true;
  }
  return sheetProtection is num && sheetProtection == 0;
}

bool _apiAuthoritySheetEditable(Map authority) {
  final sheetProtection = authority['sheet'];
  if (sheetProtection == null) {
    return true;
  }
  return sheetProtection is num && sheetProtection == 0;
}

bool _apiAuthorityAllows(Map authority, String key) {
  final value = authority[key];
  if (value == null) {
    return true;
  }
  if (value is bool) {
    return value;
  }
  if (value is num) {
    return value == 1;
  }
  final normalized = '$value'.toLowerCase();
  return normalized == '1' || normalized == 'true';
}

