List<String> fortuneMenuItemsWithout(
  List<String> items,
  Set<String> hiddenItems,
) {
  final filtered = <String>[];
  for (final item in items) {
    if (hiddenItems.contains(item)) {
      continue;
    }
    if (item == '|') {
      if (filtered.isEmpty || filtered.last == '|') {
        continue;
      }
      filtered.add(item);
      continue;
    }
    filtered.add(item);
  }
  if (filtered.isNotEmpty && filtered.last == '|') {
    filtered.removeLast();
  }
  return filtered;
}

