const FortuneSettings defaultSettings = FortuneSettings();

String _generateDefaultSheetId() => _generateUuidV4();

List<Map<String, Object?>> dataToCelldata(Object? data) {
  return FortuneSheetCodec.dataToCelldata(data);
}

List<List<Object?>>? celldataToData(
  Object? celldata, {
  int? rowCount,
  int? columnCount,
}) {
  return FortuneSheetCodec.celldataToData(
    celldata,
    rowCount: rowCount,
    columnCount: columnCount,
  );
}

List<List<Object?>>? initSheetData(
  Map<String, Object?> sheet, {
  FortuneSettings settings = defaultSettings,
}) {
  return FortuneSheetCodec.initSheetData(sheet, settings: settings);
}

int effectiveRowCount(
  FortuneSheet sheet, {
  FortuneSettings settings = defaultSettings,
}) {
  return math.max(1, sheet.rowCount ?? settings.row);
}

int effectiveColumnCount(
  FortuneSheet sheet, {
  FortuneSettings settings = defaultSettings,
}) {
  return math.max(1, sheet.columnCount ?? settings.column);
}

FortuneSelection clampSelectionToSheet(
  FortuneSelection source,
  FortuneSheet sheet, {
  FortuneSettings settings = defaultSettings,
}) {
  final maxRow = effectiveRowCount(sheet, settings: settings) - 1;
  final maxColumn = effectiveColumnCount(sheet, settings: settings) - 1;
  return FortuneSelection(
    row: source.row.clamp(0, maxRow).toInt(),
    column: source.column.clamp(0, maxColumn).toInt(),
    rowEnd: source.rowEnd.clamp(0, maxRow).toInt(),
    columnEnd: source.columnEnd.clamp(0, maxColumn).toInt(),
  );
}

Offset clampScrollOffsetToSheet(
  Offset source,
  FortuneSheet sheet, {
  FortuneSettings settings = defaultSettings,
}) {
  final metrics = sheet.metrics(settings);
  return Offset(
    source.dx.clamp(0.0, metrics.columnTotalWidth).toDouble(),
    source.dy.clamp(0.0, metrics.rowTotalHeight).toDouble(),
  );
}

List<FortuneSheet> getAllSheets(FortuneWorkbook workbook) {
  return workbook.getAllSheets();
}

List<List<FortuneCell?>>? getFlowdata(
  FortuneWorkbook? workbook, {
  String? id,
  int? index,
}) {
  final sheet = workbook?.getSheet(id: id, index: index);
  if (sheet == null) {
    return null;
  }
  final rowCount = math.max(
    sheet.rowCount ?? 0,
    sheet.cells.keys.fold<int>(
      0,
      (maxRow, coord) => math.max(maxRow, coord.row + 1),
    ),
  );
  final columnCount = math.max(
    sheet.columnCount ?? 0,
    sheet.cells.keys.fold<int>(
      0,
      (maxColumn, coord) => math.max(maxColumn, coord.column + 1),
    ),
  );
  if (rowCount == 0 || columnCount == 0) {
    return const [];
  }
  return sheet.getCellsByRange(
    FortuneRange(
      rowStart: 0,
      rowEnd: rowCount - 1,
      columnStart: 0,
      columnEnd: columnCount - 1,
    ),
  );
}

List<Map<String, Object?>> getAllFunctionGroup(FortuneWorkbook workbook) {
  final result = <Map<String, Object?>>[];
  for (final sheet in workbook.sheets) {
    result.addAll(_apiFormulaGroupEntries(sheet.calcChain));
    result.addAll(_apiDynamicArrayComputeEntries(sheet));
  }
  return result;
}

List<Map<String, Object?>> _apiDynamicArrayComputeEntries(FortuneSheet sheet) {
  final value = sheet.dynamicArrayCompute;
  if (value is Iterable) {
    return _apiFormulaGroupEntries(value);
  }
  if (value is! Map) {
    return const [];
  }
  final entries = <Map<String, Object?>>[];
  for (final rawEntry in value.entries) {
    final entryValue = rawEntry.value;
    final formulaEntry = entryValue is Map
        ? Map<String, Object?>.from(entryValue)
        : <String, Object?>{};
    final keyParts = rawEntry.key.toString().split('_');
    final row =
        _nullableIntArg(formulaEntry['r']) ??
        (keyParts.isNotEmpty ? int.tryParse(keyParts[0]) : null);
    final column =
        _nullableIntArg(formulaEntry['c']) ??
        (keyParts.length > 1 ? int.tryParse(keyParts[1]) : null);
    if (row == null || column == null) {
      continue;
    }
    formulaEntry['r'] = row;
    formulaEntry['c'] = column;
    formulaEntry['id'] = _nullableStringArg(formulaEntry['id']) ?? sheet.id;
    entries.add(formulaEntry);
  }
  return entries;
}

FortuneWorkbook delFunctionGroup(
  FortuneWorkbook workbook,
  int row,
  int column, [
  String? id,
]) {
  final sheetId = id ?? workbook.activeSheet.id;
  final sheetIndex = workbook.sheets.indexWhere((sheet) => sheet.id == sheetId);
  if (sheetIndex < 0) {
    return workbook.copyWith();
  }
  final sheet = workbook.sheets[sheetIndex];
  final nextSheets = [
    for (final current in workbook.sheets) current.copyWith(),
  ];
  nextSheets[sheetIndex] = _apiSheetWithoutFunctionGroup(
    sheet,
    row,
    column,
    sheetId,
  );
  return workbook.copyWith(sheets: nextSheets);
}

FortuneSheet _apiSheetWithoutFunctionGroup(
  FortuneSheet sheet,
  int row,
  int column,
  String sheetId,
) {
  return sheet.copyWith(
    calcChain: _apiFormulaGroupWithout(sheet.calcChain, row, column, sheetId),
    hasRawCalcChain: sheet.hasRawCalcChain || sheet.calcChain != null,
    dynamicArray: _apiFormulaGroupWithout(
      sheet.dynamicArray,
      row,
      column,
      sheetId,
      allowMissingId: true,
    ),
    hasRawDynamicArray: sheet.hasRawDynamicArray || sheet.dynamicArray != null,
    dynamicArrayCompute: _apiDynamicArrayComputeWithout(
      sheet,
      row,
      column,
      sheetId,
    ),
    hasRawDynamicArrayCompute:
        sheet.hasRawDynamicArrayCompute || sheet.dynamicArrayCompute != null,
  );
}

Object? _apiDynamicArrayComputeWithout(
  FortuneSheet sheet,
  int row,
  int column,
  String id,
) {
  final value = sheet.dynamicArrayCompute;
  if (value is Iterable) {
    return _apiFormulaGroupWithout(
      value,
      row,
      column,
      id,
      allowMissingId: true,
    );
  }
  if (value is! Map) {
    return value;
  }
  final next = <String, Object?>{};
  for (final rawEntry in value.entries) {
    if (_apiDynamicArrayComputeEntryMatches(
      sheet,
      rawEntry.key,
      rawEntry.value,
      row,
      column,
      id,
    )) {
      continue;
    }
    next[rawEntry.key.toString()] = cloneFortuneMetadata(rawEntry.value);
  }
  return next;
}

bool _apiDynamicArrayComputeEntryMatches(
  FortuneSheet sheet,
  Object? rawKey,
  Object? rawValue,
  int row,
  int column,
  String id,
) {
  final formulaEntry = rawValue is Map
      ? Map<String, Object?>.from(rawValue)
      : <String, Object?>{};
  final keyParts = rawKey.toString().split('_');
  final entryRow =
      _nullableIntArg(formulaEntry['r']) ??
      (keyParts.isNotEmpty ? int.tryParse(keyParts[0]) : null);
  final entryColumn =
      _nullableIntArg(formulaEntry['c']) ??
      (keyParts.length > 1 ? int.tryParse(keyParts[1]) : null);
  final entryId = _nullableStringArg(formulaEntry['id']) ?? sheet.id;
  return entryRow == row && entryColumn == column && entryId == id;
}

FortuneWorkbook insertUpdateFunctionGroup(
  FortuneWorkbook workbook,
  int row,
  int column, [
  String? id,
  Set<String>? calcChainSet,
]) {
  final sheetId = id ?? workbook.activeSheet.id;
  final sheetIndex = workbook.sheets.indexWhere((sheet) => sheet.id == sheetId);
  if (sheetIndex < 0) {
    return workbook.copyWith();
  }
  if (calcChainSet != null &&
      calcChainSet.contains('${row}_${column}_$sheetId')) {
    return workbook.copyWith();
  }
  final sheet = workbook.sheets[sheetIndex];
  if (calcChainSet == null &&
      _apiFormulaGroupContains(sheet.calcChain, row, column, sheetId)) {
    return workbook.copyWith();
  }
  final nextSheets = [
    for (final current in workbook.sheets) current.copyWith(),
  ];
  nextSheets[sheetIndex] = sheet.copyWith(
    calcChain: [
      ..._apiFormulaGroupEntries(sheet.calcChain),
      {'r': row, 'c': column, 'id': sheetId},
    ],
    hasRawCalcChain: true,
  );
  return workbook.copyWith(sheets: nextSheets);
}

FortuneWorkbook groupValuesRefresh(
  FortuneWorkbook workbook,
  Iterable<Map<String, Object?>> refreshData,
) {
  final nextSheets = [for (final sheet in workbook.sheets) sheet.copyWith()];
  for (final item in refreshData) {
    final sheetId = _nullableStringArg(item['id']) ?? workbook.activeSheet.id;
    final row = _nullableIntArg(item['r']);
    final column = _nullableIntArg(item['c']);
    if (row == null || column == null) {
      continue;
    }
    final sheetIndex = nextSheets.indexWhere((sheet) => sheet.id == sheetId);
    if (sheetIndex < 0) {
      continue;
    }
    var sheet = nextSheets[sheetIndex];
    final updateValue = <String, Object?>{
      if (item.containsKey('v')) 'v': item['v'],
      if (item.containsKey('m')) 'm': item['m'],
      if (item.containsKey('f')) 'f': item['f'],
    };
    final special = item['spe'];
    if (special is Map) {
      if (special['type'] == 'sparklines') {
        updateValue['spl'] = cloneFortuneMetadata(special['data']);
      } else if (special['type'] == 'dynamicArrayItem') {
        sheet = _apiSheetWithoutStaleDynamicArrayFollowers(
          sheet,
          special['data'],
          sheetId,
        );
        sheet = sheet.copyWith(
          dynamicArray: _apiInsertUpdateDynamicArray(
            sheet.dynamicArray,
            special['data'],
            sheetId,
          ),
          hasRawDynamicArray: true,
        );
      }
    } else if (updateValue.containsKey('f')) {
      sheet = _apiSheetWithoutDynamicArrayAnchor(sheet, row, column, sheetId);
    }
    nextSheets[sheetIndex] = sheet.setCellValue(row, column, updateValue);
  }
  return workbook.copyWith(sheets: nextSheets);
}

FortuneSheet _apiSheetWithoutDynamicArrayAnchor(
  FortuneSheet sheet,
  int row,
  int column,
  String sheetId,
) {
  final previous = _apiDynamicArrayEntryFor(
    sheet.dynamicArray,
    row,
    column,
    sheetId,
  );
  if (previous == null) {
    return sheet;
  }
  var nextSheet = sheet;
  for (final coord in _apiDynamicArrayFollowerCoords(previous)) {
    final current = nextSheet.cells[coord];
    if (current == null) {
      continue;
    }
    final expected = _apiDynamicArrayValueAt(
      previous,
      coord.row - row,
      coord.column - column,
    );
    if (identical(expected, _sentinel) ||
        !_apiCellMatchesDynamicArrayValue(current, expected)) {
      continue;
    }
    nextSheet = nextSheet.clearCell(coord.row, coord.column);
  }
  return nextSheet.copyWith(
    dynamicArray: _apiFormulaGroupWithout(
      nextSheet.dynamicArray,
      row,
      column,
      sheetId,
    ),
    hasRawDynamicArray: true,
  );
}

FortuneSheet _apiSheetWithoutStaleDynamicArrayFollowers(
  FortuneSheet sheet,
  Object? item,
  String sheetId,
) {
  if (item is! Map) {
    return sheet;
  }
  final row = _nullableIntArg(item['r']);
  final column = _nullableIntArg(item['c']);
  if (row == null || column == null) {
    return sheet;
  }
  final previous = _apiDynamicArrayEntryFor(
    sheet.dynamicArray,
    row,
    column,
    sheetId,
  );
  if (previous == null) {
    return sheet;
  }
  final nextItem = Map<Object?, Object?>.from(item);
  final nextFootprint = _apiDynamicArrayFollowerCoords(nextItem);
  var nextSheet = sheet;
  for (final coord in _apiDynamicArrayFollowerCoords(previous)) {
    if (nextFootprint.contains(coord)) {
      continue;
    }
    final current = nextSheet.cells[coord];
    if (current == null) {
      continue;
    }
    final expected = _apiDynamicArrayValueAt(
      previous,
      coord.row - row,
      coord.column - column,
    );
    if (identical(expected, _sentinel) ||
        !_apiCellMatchesDynamicArrayValue(current, expected)) {
      continue;
    }
    nextSheet = nextSheet.clearCell(coord.row, coord.column);
  }
  return nextSheet;
}

Map<Object?, Object?>? _apiDynamicArrayEntryFor(
  Object? dynamicArray,
  int row,
  int column,
  String sheetId,
) {
  for (final entry in _apiFormulaGroupEntries(dynamicArray)) {
    if (_nullableIntArg(entry['r']) == row &&
        _nullableIntArg(entry['c']) == column &&
        _nullableStringArg(entry['id']) == sheetId) {
      return Map<Object?, Object?>.from(entry);
    }
  }
  return null;
}

Set<FortuneCellCoord> _apiDynamicArrayFollowerCoords(
  Map<Object?, Object?> item,
) {
  final row = _nullableIntArg(item['r']);
  final column = _nullableIntArg(item['c']);
  if (row == null || column == null) {
    return const <FortuneCellCoord>{};
  }
  final shape = _apiDynamicArrayShape(item);
  final coords = <FortuneCellCoord>{};
  for (var rowOffset = 0; rowOffset < shape.$1; rowOffset += 1) {
    for (var columnOffset = 0; columnOffset < shape.$2; columnOffset += 1) {
      if (rowOffset == 0 && columnOffset == 0) {
        continue;
      }
      coords.add(FortuneCellCoord(row + rowOffset, column + columnOffset));
    }
  }
  return coords;
}

(int, int) _apiDynamicArrayShape(Map<Object?, Object?> item) {
  final data = item['data'];
  final rowCount =
      _nullableIntArg(item['rowCount']) ??
      _nullableIntArg(item['rows']) ??
      (data is List && data.isNotEmpty && data.first is List
          ? data.length
          : data is List
          ? math.max(1, data.length)
          : 1);
  final columnCount =
      _nullableIntArg(item['columnCount']) ??
      _nullableIntArg(item['columns']) ??
      (data is List && data.isNotEmpty && data.first is List
          ? math.max(1, (data.first as List).length)
          : 1);
  return (math.max(1, rowCount), math.max(1, columnCount));
}

Object? _apiDynamicArrayValueAt(
  Map<Object?, Object?> item,
  int rowOffset,
  int columnOffset,
) {
  final data = item['data'];
  if (data is! List || rowOffset < 0 || columnOffset < 0) {
    return _sentinel;
  }
  if (data.isNotEmpty && data.first is List) {
    if (rowOffset >= data.length) {
      return _sentinel;
    }
    final row = data[rowOffset];
    if (row is! List || columnOffset >= row.length) {
      return _sentinel;
    }
    return row[columnOffset];
  }
  final shape = _apiDynamicArrayShape(item);
  final index = rowOffset * shape.$2 + columnOffset;
  if (index < 0 || index >= data.length) {
    return _sentinel;
  }
  return data[index];
}

bool _apiCellMatchesDynamicArrayValue(FortuneCell cell, Object? expected) {
  if (cell.formula != null ||
      (cell.hasRawFormula && cell.rawFormula != null) ||
      cell.hasSparkline ||
      cell.hasRawSparkline ||
      cell.inlineRuns != null) {
    return false;
  }
  final raw = cell.hasRawValue ? cell.rawValue : cell.value;
  if (_apiDynamicArrayValuesEqual(raw, expected)) {
    return true;
  }
  final expectedText = _apiDynamicArrayValueText(expected);
  return cell.renderedText == expectedText ||
      (cell.hasRawDisplayValue &&
          cell.rawDisplayValue?.toString() == expectedText);
}

bool _apiDynamicArrayValuesEqual(Object? a, Object? b) {
  if (a == b) {
    return true;
  }
  if (a is num && b is num) {
    return a == b;
  }
  return false;
}

String _apiDynamicArrayValueText(Object? value) {
  if (value == null) {
    return '';
  }
  if (value is num && value.isFinite && value == value.truncateToDouble()) {
    return value.toInt().toString();
  }
  return value.toString();
}

List<Map<String, Object?>> _apiInsertUpdateDynamicArray(
  Object? dynamicArray,
  Object? item,
  String sheetId,
) {
  final entries = _apiFormulaGroupEntries(dynamicArray);
  if (item is! Map) {
    return entries;
  }
  final nextItem = Map<String, Object?>.from(item);
  final row = _nullableIntArg(nextItem['r']);
  final column = _nullableIntArg(nextItem['c']);
  if (row == null || column == null) {
    return entries;
  }
  nextItem['id'] = _nullableStringArg(nextItem['id']) ?? sheetId;
  final index = entries.indexWhere(
    (entry) =>
        _nullableIntArg(entry['r']) == row &&
        _nullableIntArg(entry['c']) == column &&
        _nullableStringArg(entry['id']) == nextItem['id'],
  );
  if (index < 0) {
    return [...entries, nextItem];
  }
  final nextEntries = [...entries];
  final nextEntry = {
    ...nextEntries[index],
    'data': cloneFortuneMetadata(nextItem['data']),
    'f': cloneFortuneMetadata(nextItem['f']),
  };
  if (nextItem.containsKey('rowCount')) {
    nextEntry['rowCount'] = cloneFortuneMetadata(nextItem['rowCount']);
  }
  if (nextItem.containsKey('columnCount')) {
    nextEntry['columnCount'] = cloneFortuneMetadata(nextItem['columnCount']);
  }
  nextEntries[index] = nextEntry;
  return nextEntries;
}

