  AfterActivateSheetHook? afterActivateSheet,
}) {
  final sheet = getSheet(workbook, id: id, index: index);
  if (beforeActivateSheet?.call(sheet.id) == false) {
    return workbook.copyWith();
  }
  final nextWorkbook = workbook.activateSheet(sheet.id);
  _deferSheetAfterHook(() => afterActivateSheet?.call(sheet.id));
  return nextWorkbook;
}

