FortuneWorkbook editSheetName(
  FortuneWorkbook workbook,
  String name, {
  String? id,
  int? index,
  bool allowEdit = true,
  BeforeUpdateSheetNameHook? beforeUpdateSheetName,
  AfterUpdateSheetNameHook? afterUpdateSheetName,
}) {
  final sheet = getSheet(workbook, id: id, index: index);
  if (!allowEdit) {
    return workbook.copyWith();
  }
  final oldName = sheet.name;
  if (beforeUpdateSheetName?.call(sheet.id, oldName, name) == false) {
    return workbook.copyWith();
  }
  if (name.isEmpty) {
    throw const FortuneApiError('Sheet name cannot be empty');
  }
  if (name.length > 31 ||
      name.startsWith("'") ||
      name.endsWith("'") ||
      RegExp(r'[：:/？?*\[\]\\]').hasMatch(name)) {
    throw const FortuneApiError('The name cannot contain:[ ] :  ? * / \' "');
  }
  if (workbook.sheets.any(
    (current) => current.id != sheet.id && current.name == name,
  )) {
    return workbook.copyWith();
  }
  final nextWorkbook = workbook.setSheetName(sheet.id, name);
  _deferSheetAfterHook(
    () => afterUpdateSheetName?.call(sheet.id, oldName, name),
  );
  return nextWorkbook;
}

