FortuneWorkbook addSheet(
  FortuneWorkbook workbook, {
  String? id,
  String? name,
  int? rowCount,
  int? columnCount,
  FortuneSheet? sheet,
  BeforeAddSheetHook? beforeAddSheet,
  AfterAddSheetHook? afterAddSheet,
}) {
  final generatedId = id == null
      ? _generatedAddSheetIdCandidate(
          workbook.sheets,
          workbook.settings.generateSheetId,
        )
      : null;
  if (id == null &&
      workbook.settings.generateSheetId != null &&
      generatedId == null) {
    return workbook.copyWith();
  }
  final nextId = id ?? generatedId ?? _nextSheetIdFor(workbook.sheets);
  if (workbook.sheets.any((sheet) => sheet.id == nextId)) {
    return workbook.copyWith();
  }
  final nextName =
      name ?? sheet?.name ?? generateRandomSheetName(workbook.sheets);
  final nextSheet = (sheet ?? FortuneSheet(id: nextId, name: nextName))
      .copyWith(
        id: nextId,
        name: nextName,
        rowCount: rowCount ?? _sentinel,
        columnCount: columnCount ?? _sentinel,
        status: sheet == null ? 0 : _sentinel,
        order: sheet?.order ?? workbook.sheets.length,
      );
  if (beforeAddSheet?.call(nextSheet) == false) {
    return workbook.copyWith();
  }
  final nextWorkbook = workbook.addSheet(
    id: nextId,
    name: name,
    rowCount: rowCount,
    columnCount: columnCount,
    sheet: sheet,
  );
  final effectiveWorkbook = id == null
      ? nextWorkbook.copyWith(activeSheetIndex: nextWorkbook.sheets.length - 1)
      : nextWorkbook;
  if (effectiveWorkbook.sheets.length > workbook.sheets.length) {
    final addedSheet = effectiveWorkbook.sheets.firstWhere(
      (current) => current.id == nextSheet.id,
      orElse: () => nextSheet,
    );
    _deferSheetAfterHook(() => afterAddSheet?.call(addedSheet));
  }
  return effectiveWorkbook;
}

FortuneWorkbook deleteSheet(
  FortuneWorkbook workbook, {
  String? id,
  int? index,
  BeforeDeleteSheetHook? beforeDeleteSheet,
  AfterDeleteSheetHook? afterDeleteSheet,
}) {
  final sheet = getSheet(workbook, id: id, index: index);
  if (beforeDeleteSheet?.call(sheet.id) == false) {
    return workbook.copyWith();
  }
  final nextWorkbook = workbook.deleteSheet(sheet.id);
  if (nextWorkbook.sheets.length < workbook.sheets.length) {
    _deferSheetAfterHook(() => afterDeleteSheet?.call(sheet.id));
  }
  return nextWorkbook;
}

