FortuneSheet _clearedSheetFrom(
  FortuneSheet sheet, {
  int? rowCount,
  int? columnCount,
  int? gridClientWidthMm,
  int? gridClientHeightMm,
}) {
  final extraFields = <String, Object?>{
    for (final entry in sheet.extraFields.entries)
      entry.key: cloneFortuneMetadata(entry.value),
  };
  extraFields.remove('labelRtfImportSource');
  if (gridClientWidthMm != null && gridClientHeightMm != null) {
    extraFields[fortuneSheetGridClientWidthMmKey] = gridClientWidthMm;
    extraFields[fortuneSheetGridClientHeightMmKey] = gridClientHeightMm;
  }
  return FortuneSheet(
    id: sheet.id,
    rawId: sheet.rawId,
    hasRawId: sheet.hasRawId,
    name: sheet.name,
    rawName: sheet.rawName,
    hasRawName: sheet.hasRawName,
    order: sheet.order,
    rawOrder: sheet.rawOrder,
    hasRawOrder: sheet.hasRawOrder,
    rowCount: rowCount,
    columnCount: columnCount,
    hide: sheet.hide,
    rawHide: sheet.rawHide,
    hasRawHide: sheet.hasRawHide,
    status: sheet.status,
    rawStatus: sheet.rawStatus,
    hasRawStatus: sheet.hasRawStatus,
    extraFields: extraFields,
  );
}

