FortuneSheet insertRowOrColumn(
  FortuneSheet sheet,
  String type,
  int index,
  int count, {
  String direction = 'rightbottom',
}) {
  if (type != 'row' && type != 'column') {
    throw INVALID_PARAMS;
  }
  if (direction != 'lefttop' && direction != 'rightbottom') {
    throw INVALID_PARAMS;
  }
  if (index < 0 || count <= 0) {
    return sheet.copyWith();
  }
  if (type == 'row') {
    if (_apiIsIndexReadOnly(sheet.rowReadOnly, index)) {
      return sheet.copyWith();
    }
    final rowCount = sheet.rowCount;
    if (rowCount != null && rowCount + count >= _apiMaxRowCount) {
      return sheet.copyWith();
    }
  } else {
    if (_apiIsIndexReadOnly(sheet.colReadOnly, index)) {
      return sheet.copyWith();
    }
    final columnCount = sheet.columnCount;
    if (columnCount != null && columnCount + count >= _apiMaxColumnCount) {
      return sheet.copyWith();
    }
  }
  return sheet.insertRowOrColumn(type, index, count, direction: direction);
}

FortuneSheet deleteRowOrColumn(
  FortuneSheet sheet,
  String type,
  int start,
  int end,
) {
  if (type != 'row' && type != 'column') {
    throw INVALID_PARAMS;
  }
  final startIndex = math.min(start, end);
  final endIndex = math.max(start, end);
  if (type == 'row') {
    for (var row = startIndex; row <= endIndex; row += 1) {
      if (_apiIsIndexReadOnly(sheet.rowReadOnly, row)) {
        throw const FortuneApiError('readOnly');
      }
    }
  } else {
    for (var column = startIndex; column <= endIndex; column += 1) {
      if (_apiIsIndexReadOnly(sheet.colReadOnly, column)) {
        throw const FortuneApiError('readOnly');
      }
    }
  }
  return sheet.deleteRowOrColumn(type, start, end);
}

