}) {
  return insertRowOrColumn(sheet, type, index, count, direction: direction);
}

FortuneSheet deleteRowCol(FortuneSheet sheet, String type, int start, int end) {
  return deleteRowOrColumn(sheet, type, start, end);
}

List<List<T?>> expandRowsAndColumns<T>(
  List<List<T?>> data,
  int rowsToAdd,
  int columnsToAdd,
) {
  if (rowsToAdd <= 0 && columnsToAdd <= 0) {
    return [for (final row in data) List<T?>.from(row)];
  }

  if (data.length + rowsToAdd >= 10000) {
    throw StateError(
      'This action would increase the number of rows in the workbook above the limit of 10000.',
    );
  }

  final currentColumnLength = data.isEmpty ? 0 : data.first.length;
  if (currentColumnLength + columnsToAdd >= 1000) {
    throw StateError(
      'This action would increase the number of columns in the workbook above the limit of 1000.',
    );
  }

  final addRows = math.max(0, rowsToAdd);
  final addColumns = math.max(0, columnsToAdd);
  final nextData = [
    for (final row in data) [...row, ...List<T?>.filled(addColumns, null)],
  ];
  for (var row = 0; row < addRows; row += 1) {
    nextData.add(List<T?>.filled(currentColumnLength + addColumns, null));
  }
  return nextData;
}

String functionStrChange(
  String text,
  String type,
  String rowOrColumn,
  String? orient,
  int startIndex,
  int step,
) {
  if (text.isEmpty) {
    return '';
  }
  final axis = switch (rowOrColumn) {
    'row' => 'row',
    'col' => 'column',
    'column' => 'column',
    _ => null,
  };
  if (axis == null) {
    return '';
  }

  final formula = text.startsWith('=') ? text : '=$text';
  final rewritten = switch (type) {
    'add' => rewriteFormulaReferencesForInsert(
      formula,
      type: axis,
      index: startIndex,
      count: step,
      direction: orient ?? 'rightbottom',
    ),
    'del' => rewriteFormulaReferencesForDelete(
      formula,
      type: axis,
      start: startIndex,
      end: startIndex + step - 1,
    ),
    _ => '',
  };
  return rewritten.startsWith('=') ? rewritten.substring(1) : rewritten;
}

