Map<String, Object?> hideSelected(
  FortuneSheet sheet,
  String type, {
  Iterable<FortuneRange>? selection,
}) {
  final ranges = (selection ?? sheet.getSelection()).toList();
  if (ranges.length != 1) {
    return <String, Object?>{
      'message': 'noMulti',
      'sheet': sheet,
      'selection': ranges,
    };
  }
  final range = _normalizedApiRange(ranges.single);
  if (range == null) {
    return <String, Object?>{
      'message': 'noMulti',
      'sheet': sheet,
      'selection': ranges,
    };
  }
  final axis = type == 'row'
      ? [for (var row = range.rowStart; row <= range.rowEnd; row += 1) row]
      : [
          for (
            var column = range.columnStart;
            column <= range.columnEnd;
            column += 1
          )
            column,
        ];
  final nextSheet = sheet.hideRowOrColumn(axis, type);
  var nextRange = range;
  if (type == 'row') {
    final hiddenNumber = range.rowEnd;
    final rowLength = _apiSheetMaxRow(sheet) + 1;
    final isEndRow =
        rowLength - 1 == hiddenNumber ||
        nextSheet.hiddenRows.any((row) => row - 1 == hiddenNumber);
    final delta = isEndRow ? -1 : 1;
    nextRange = range.copyWith(
      rowStart: math.max(0, range.rowStart + delta),
      rowEnd: math.max(0, range.rowEnd + delta),
    );
  } else if (type == 'column') {
    final hiddenNumber = range.columnEnd;
    final columnLength = _apiSheetMaxColumn(sheet) + 1;
    final isEndColumn =
        columnLength - 1 == hiddenNumber ||
        nextSheet.hiddenColumns.any((column) => column - 1 == hiddenNumber);
    final delta = isEndColumn ? -1 : 1;
    nextRange = range.copyWith(
      columnStart: math.max(0, range.columnStart + delta),
      columnEnd: math.max(0, range.columnEnd + delta),
    );
  }
  return <String, Object?>{
    'message': '',
    'sheet': nextSheet,
    'selection': [nextRange],
  };
}

Map<String, Object?> showSelected(
  FortuneSheet sheet,
  String type, {
  Iterable<FortuneRange>? selection,
}) {
  final ranges = (selection ?? sheet.getSelection()).toList();
  if (ranges.length != 1) {
    return <String, Object?>{
      'message': 'noMulti',
      'sheet': sheet,
      'selection': ranges,
    };
  }
  final range = _normalizedApiRange(ranges.single);
  if (range == null) {
    return <String, Object?>{
      'message': 'noMulti',
      'sheet': sheet,
      'selection': ranges,
    };
  }
  final axis = type == 'row'
      ? [for (var row = range.rowStart; row <= range.rowEnd; row += 1) row]
      : [
          for (
            var column = range.columnStart;
            column <= range.columnEnd;
            column += 1
          )
            column,
        ];
  return <String, Object?>{
    'message': '',
    'sheet': sheet.showRowOrColumn(axis, type),
    'selection': [range],
  };
}

