FortuneSheet updateFormatCell(
  FortuneSheet sheet,
  String attr,
  Object? value,
  int rowStart,
  int rowEnd,
  int columnStart,
  int columnEnd, {
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet.copyWith();
  }
  return sheet.setCellFormatByRange(
    attr,
    _apiToolbarFormatValue(attr, value),
    FortuneRange(
      rowStart: rowStart,
      rowEnd: rowEnd,
      columnStart: columnStart,
      columnEnd: columnEnd,
    ),
  );
}

FortuneSheet updateFormat(
  FortuneSheet sheet,
  String attr,
  Object? value, {
  Iterable<FortuneRange>? selection,
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet.copyWith();
  }
  final ranges = selection?.toList() ?? getSelection(sheet);
  if (ranges.isEmpty) {
    return sheet.copyWith();
  }
  var nextSheet = sheet.copyWith();
  for (final range in ranges) {
    nextSheet = updateFormatCell(
      nextSheet,
      attr,
      value,
      range.rowStart,
      range.rowEnd,
      range.columnStart,
      range.columnEnd,
    );
  }
  return nextSheet;
}

