bool Function(FortuneCell?)? toolbarItemSelectedFunc(String name) {
  final attr = switch (name) {
    'bold' => 'bl',
    'italic' => 'it',
    'strike-through' => 'cl',
    'underline' => 'un',
    _ => null,
  };
  if (attr == null) {
    return null;
  }
  return (cell) => cell != null && _apiRawCellAttr(cell, attr) == 1;
}

typedef FortuneToolbarItemClickHandler =
    Object? Function(FortuneSheet sheet, {Iterable<FortuneRange>? selection});

