      selection: selection?.toList(),
    ),
    'merge-cancel' => (sheet, {selection}) => handleMerge(
      sheet,
      'merge-cancel',
      selection: selection?.toList(),
    ),
    'border-all' => (sheet, {selection}) => handleBorder(
      sheet,
      selection: selection?.toList(),
    ),
    'bold' => (sheet, {selection}) => handleBold(sheet, selection: selection),
    'italic' => (sheet, {selection}) => handleItalic(
      sheet,
      selection: selection,
    ),
    'strike-through' => (sheet, {selection}) => handleStrikeThrough(
      sheet,
      selection: selection,
    ),
    'underline' => (sheet, {selection}) => handleUnderline(
      sheet,
      selection: selection,
