  return autoSelectionFormula(
    sheet,
    formula: 'SUM',
    selection: selection,
    allowEdit: allowEdit,
  );
}

Map<String, Object?>? autoSelectionFormula(
  FortuneSheet sheet, {
  String formula = 'SUM',
  Iterable<FortuneRange>? selection,
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return null;
  }
  final ranges = selection?.toList() ?? getSelection(sheet);
  if (ranges.isEmpty) {
    return null;
  }
  final formulaName = formula.toUpperCase();
  final actions = <Map<String, Object?>>[];
  for (final range in ranges) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    if (normalized.rowStart == normalized.rowEnd &&
        normalized.columnStart == normalized.columnEnd) {
      actions.add(
        _apiAutoFormulaSingleCellAction(sheet, normalized, formulaName),
      );
      continue;
    }
    actions.addAll(_apiAutoFormulaRangeActions(sheet, normalized, formulaName));
  }
  return {
    'formula': formulaName,
    'actions': actions,
    'execFunctionExist': [
      for (final action in actions)
        if (action['type'] == 'setFormula')
          {'r': action['row'], 'c': action['column']},
    ],
    'needsRecalculate': actions.any((action) => action['type'] == 'setFormula'),
  };
}

Map<String, Object?> _apiAutoFormulaSingleCellAction(
  FortuneSheet sheet,
  FortuneRange range,
  String formula,
) {
  final row = range.rowStart;
  final column = range.columnStart;
  if (row - 1 < 0 && column - 1 < 0) {
    return _apiAutoFormulaInputAction(row, column, formula, null, isNull: true);
  }
  if (row - 1 >= 0 &&
      _apiAutoFormulaCellIsNumeric(
        sheet.cells[FortuneCellCoord(row - 1, column)],
      )) {
    final rowStart = _apiAutoFormulaNoNullValue(sheet, column, row, 'r');
    if (rowStart != null) {
      return _apiAutoFormulaInputAction(
        row,
        column,
        formula,
        _apiAutoFormulaRangeMap(rowStart, row - 1, column, column),
      );
    }
  }
  if (column - 1 >= 0 &&
      _apiAutoFormulaCellIsNumeric(
        sheet.cells[FortuneCellCoord(row, column - 1)],
      )) {
    final columnStart = _apiAutoFormulaNoNullValue(sheet, row, column, 'c');
    if (columnStart != null) {
      return _apiAutoFormulaInputAction(
        row,
        column,
        formula,
        _apiAutoFormulaRangeMap(row, row, columnStart, column - 1),
      );
    }
  }
  final rowStart = _apiAutoFormulaNoNullValue(sheet, column, row, 'r');
  if (rowStart != null) {
    return _apiAutoFormulaInputAction(
      row,
      column,
      formula,
      _apiAutoFormulaRangeMap(rowStart, row - 1, column, column),
    );
  }
  final columnStart = _apiAutoFormulaNoNullValue(sheet, row, column, 'c');
  if (columnStart != null) {
    return _apiAutoFormulaInputAction(
      row,
      column,
      formula,
      _apiAutoFormulaRangeMap(row, row, columnStart, column - 1),
    );
  }
  return _apiAutoFormulaInputAction(row, column, formula, null, isNull: true);
}

List<Map<String, Object?>> _apiAutoFormulaRangeActions(
  FortuneSheet sheet,
  FortuneRange range,
  String formula,
) {
  final actions = <Map<String, Object?>>[];
  if (range.rowStart == range.rowEnd) {
    final action = _apiAutoFormulaRowAction(
      sheet,
      range.rowStart,
      range,
      formula,
    );
    if (action != null) {
      actions.add(action);
    }
    return actions;
  }
  if (range.columnStart == range.columnEnd) {
    final action = _apiAutoFormulaColumnAction(
      sheet,
      range.columnStart,
      range,
      formula,
    );
    if (action != null) {
      actions.add(action);
    }
    return actions;
  }
  for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
    final action = _apiAutoFormulaRowAction(sheet, row, range, formula);
    if (action != null) {
      actions.add(action);
    }
  }
  for (var column = range.columnStart; column <= range.columnEnd; column += 1) {
    final action = _apiAutoFormulaColumnAction(sheet, column, range, formula);
    if (action != null) {
      actions.add(action);
    }
  }
  return actions;
}

Map<String, Object?>? _apiAutoFormulaRowAction(
  FortuneSheet sheet,
  int row,
  FortuneRange range,
  String formula,
) {
  var hasNumeric = false;
  for (var column = range.columnStart; column <= range.columnEnd; column += 1) {
    hasNumeric =
        _apiAutoFormulaCellIsNumeric(
          sheet.cells[FortuneCellCoord(row, column)],
        ) ||
        hasNumeric;
  }
  if (!hasNumeric) {
    return null;
  }
  final targetColumn = _apiAutoFormulaNextEmptyColumn(
    sheet,
    row,
    range.columnEnd + 1,
  );
  return _apiAutoFormulaSetAction(
    sheet,
    row,
    targetColumn,
    formula,
    _apiAutoFormulaRangeMap(row, row, range.columnStart, range.columnEnd),
  );
}

Map<String, Object?>? _apiAutoFormulaColumnAction(
  FortuneSheet sheet,
  int column,
  FortuneRange range,
  String formula,
) {
  var hasNumeric = false;
  for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
    hasNumeric =
        _apiAutoFormulaCellIsNumeric(
          sheet.cells[FortuneCellCoord(row, column)],
        ) ||
        hasNumeric;
  }
  if (!hasNumeric) {
    return null;
  }
  final targetRow = _apiAutoFormulaNextEmptyRow(
    sheet,
    column,
    range.rowEnd + 1,
  );
  return _apiAutoFormulaSetAction(
    sheet,
    targetRow,
    column,
    formula,
    _apiAutoFormulaRangeMap(range.rowStart, range.rowEnd, column, column),
  );
}

int _apiAutoFormulaNextEmptyColumn(
  FortuneSheet sheet,
  int row,
  int startColumn,
) {
  var column = startColumn;
  final maxColumn = math.max(_apiSheetMaxColumn(sheet) + 1, startColumn);
  while (column <= maxColumn &&
      _apiAutoFormulaCellHasValue(sheet.cells[FortuneCellCoord(row, column)])) {
    column += 1;
  }
  return column;
}

int _apiAutoFormulaNextEmptyRow(FortuneSheet sheet, int column, int startRow) {
  var row = startRow;
  final maxRow = math.max(_apiSheetMaxRow(sheet) + 1, startRow);
  while (row <= maxRow &&
      _apiAutoFormulaCellHasValue(sheet.cells[FortuneCellCoord(row, column)])) {
    row += 1;
  }
  return row;
}

int? _apiAutoFormulaNoNullValue(
  FortuneSheet sheet,
  int fixedIndex,
  int end,
  String type,
) {
  int? hasValueStart;
  var nullNum = 0;
  var nullTime = 0;
  for (var index = end - 1; index >= 0; index -= 1) {
    final cell = type == 'c'
        ? sheet.cells[FortuneCellCoord(fixedIndex, index)]
        : sheet.cells[FortuneCellCoord(index, fixedIndex)];
    if (_apiAutoFormulaCellIsNumeric(cell)) {
      hasValueStart = index;
    } else if (!_apiAutoFormulaCellHasValue(cell)) {
      nullNum += 1;
      if (nullNum >= 40) {
        if (nullTime <= 0) {
          nullTime = 1;
        } else {
          break;
        }
      }
    } else {
      break;
    }
  }
  return hasValueStart;
}

bool _apiAutoFormulaCellIsNumeric(FortuneCell? cell) {
  if (cell == null) {
    return false;
  }
  final value = cell.hasRawValue ? cell.rawValue : cell.value;
  final cellType = cell.cellType?.type;
  return !isRealNull(value) &&
      isdatatypemulti(value)['num'] == true &&
      (cellType == null || cellType == 'n' || cellType == 'g');
}

bool _apiAutoFormulaCellHasValue(FortuneCell? cell) {
  if (cell == null) {
    return false;
  }
  final value = cell.hasRawValue ? cell.rawValue : cell.value;
  return !isRealNull(value);
}

Map<String, Object?> _apiAutoFormulaInputAction(
  int row,
  int column,
  String formula,
  Map<String, Object?>? range, {
  bool isNull = false,
}) {
  return {
    'type': 'activeFormulaInput',
    'row': row,
    'column': column,
    'formula': formula,
    'range': range,
    'formulaText': isNull ? '=$formula()' : '=$formula(${range?['text']})',
    'isNull': isNull,
    'doNotUpdateCell': true,
  };
}

Map<String, Object?> _apiAutoFormulaSetAction(
  FortuneSheet sheet,
  int row,
  int column,
  String formula,
  Map<String, Object?> range,
) {
  final formulaText = '=$formula(${range['text']})';
  final computedValue = _apiAutoFormulaEvaluate(sheet, range, formula);
  final displayValue = computedValue == null ? null : '$computedValue';
  final value = <String, Object?>{'f': formulaText};
  if (computedValue != null) {
    value['v'] = computedValue;
  }
  if (displayValue != null) {
    value['m'] = displayValue;
  }
  return {
    'type': 'setFormula',
    'row': row,
    'column': column,
    'formula': formula,
    'formulaText': formulaText,
    'value': value,
    'range': range,
  };
}

Object? _apiAutoFormulaEvaluate(
  FortuneSheet sheet,
  Map<String, Object?> range,
  String formula,
) {
  final rows = range['row'];
  final columns = range['column'];
  if (rows is! List ||
      columns is! List ||
      rows.length < 2 ||
      columns.length < 2) {
    return null;
  }
  final rowStart = _nullableIntArg(rows[0]);
  final rowEnd = _nullableIntArg(rows[1]);
  final columnStart = _nullableIntArg(columns[0]);
  final columnEnd = _nullableIntArg(columns[1]);
  if (rowStart == null ||
      rowEnd == null ||
      columnStart == null ||
      columnEnd == null) {
    return null;
  }
  final values = <num>[];
  for (
    var row = math.min(rowStart, rowEnd);
    row <= math.max(rowStart, rowEnd);
    row += 1
  ) {
    for (
      var column = math.min(columnStart, columnEnd);
      column <= math.max(columnStart, columnEnd);
      column += 1
    ) {
      final value = _apiAutoFormulaCellNumber(
        sheet.cells[FortuneCellCoord(row, column)],
      );
      if (value != null) {
        values.add(value);
      }
    }
  }
  if (values.isEmpty) {
    return formula == 'COUNT' ? 0 : null;
  }
  final result = switch (formula) {
    'SUM' => values.fold<num>(0, (sum, value) => sum + value),
    'MIN' => values.reduce(math.min),
    'MAX' => values.reduce(math.max),
    'AVERAGE' =>
      values.fold<num>(0, (sum, value) => sum + value) / values.length,
    'COUNT' => values.length,
    _ => null,
  };
  return result is double && result == result.roundToDouble()
      ? result.toInt()
      : result;
}

num? _apiAutoFormulaCellNumber(FortuneCell? cell) {
  if (!_apiAutoFormulaCellIsNumeric(cell)) {
    return null;
  }
  final value = cell!.hasRawValue ? cell.rawValue : cell.value;
  if (value is num) {
    return value;
  }
  return num.tryParse('$value');
}

Map<String, Object?> _apiAutoFormulaRangeMap(
  int rowStart,
  int rowEnd,
  int columnStart,
  int columnEnd,
) {
  return {
    'row': [rowStart, rowEnd],
    'column': [columnStart, columnEnd],
    'text': _apiAutoFormulaRangeText(rowStart, rowEnd, columnStart, columnEnd),
  };
}

String _apiAutoFormulaRangeText(
  int rowStart,
  int rowEnd,
  int columnStart,
  int columnEnd,
) {
  final start = '${indexToColumnChar(columnStart)}${rowStart + 1}';
  final end = '${indexToColumnChar(columnEnd)}${rowEnd + 1}';
  return start == end ? start : '$start:$end';
}

