List<List<String>> getSplitColumnData(
  FortuneSheet sheet, {
  FortuneRange? selection,
  bool tab = false,
  bool semicolon = false,
  bool comma = false,
  bool space = false,
  String? other,
  bool consecutive = false,
}) {
  final range = selection ?? getSelection(sheet).firstOrNull;
  if (range == null) {
    return const [];
  }
  final rows = <List<String>>[];
  for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
    final coord = sheet.mergeAnchorFor(
      FortuneCellCoord(row, range.columnStart),
    );
    final cell = sheet.cells[coord];
    final value = cell == null
        ? ''
        : cell.renderedText.isNotEmpty
        ? cell.renderedText
        : '${getCellValue(sheet, coord.row, coord.column) ?? ''}';
    rows.add(
      _apiSplitColumnValue(
        value,
        tab: tab,
        semicolon: semicolon,
        comma: comma,
        space: space,
        other: other,
        consecutive: consecutive,
      ),
    );
  }
  final maxColumns = rows.fold<int>(0, (max, row) => math.max(max, row.length));
  if (maxColumns <= 1) {
    return rows;
  }
  return [
    for (final row in rows)
      [
        for (var index = 0; index < maxColumns; index += 1)
          index < row.length ? row[index] : '',
      ],
  ];
}

List<String> _apiSplitColumnValue(
  String value, {
  required bool tab,
  required bool semicolon,
  required bool comma,
  required bool space,
  String? other,
  required bool consecutive,
}) {
  final parts = <String>[];
  if (tab) {
    parts.add(r'\t');
  }
  if (semicolon) {
    parts.add(';');
  }
  if (comma) {
    parts.add(',');
  }
  if (space) {
    parts.add(r'\s');
  }
  if (other != null && other.isNotEmpty) {
    parts.add(RegExp.escape(other));
  }
  if (parts.isEmpty) {
    return [value];
  }
  final pattern = parts.length == 1 ? parts.single : '(?:${parts.join('|')})';
  try {
    return value.split(RegExp(consecutive ? '$pattern+' : pattern));
  } on FormatException {
    return [value];
  }
}

FortuneSheet handleBorder(
  FortuneSheet sheet, {
  String type = 'border-all',
  String? borderColor,
  String? borderStyle,
  List<FortuneRange>? selection,
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet.copyWith();
  }
  final ranges = selection ?? getSelection(sheet);
  final colorValue = borderColor == null || borderColor.isEmpty
      ? '#000'
      : borderColor;
  final styleValue = _nullableIntArg(borderStyle) ?? 1;
  final color = _nullableColorArg(colorValue) ?? const Color(0xff000000);
  final nextBorderInfo = sheet.borderInfo
      .map((border) => border.copyWith())
      .toList();
  if (type != 'border-slash') {
    nextBorderInfo.add(
      FortuneBorderInfo(
        rangeType: 'range',
        borderType: type,
        color: color,
        rawColor: colorValue,
        hasRawColor: true,
        style: styleValue,
        ranges: [for (final range in ranges) range.copyWith()],
      ),
    );
  } else {
    final seen = <String>{};
    for (final range in ranges) {
      for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
        for (
          var column = range.columnStart;
          column <= range.columnEnd;
          column += 1
        ) {
          final key = '${row}_$column';
          if (!seen.add(key)) {
            continue;
          }
          nextBorderInfo.add(
            FortuneBorderInfo(
              rangeType: 'range',
              borderType: type,
              color: color,
              rawColor: colorValue,
              hasRawColor: true,
              style: styleValue,
              ranges: [
                FortuneRange(
                  rowStart: row,
                  rowEnd: row,
                  columnStart: column,
                  columnEnd: column,
                ),
              ],
            ),
          );
        }
      }
    }
  }
  return sheet.copyWith(borderInfo: nextBorderInfo);
}

FortuneSheet _apiAdjustNumberFormat(
  FortuneSheet sheet,
  int delta, {
  Iterable<FortuneRange>? selection,
}) {
  final ranges = selection?.toList() ?? getSelection(sheet);
  final focus = ranges.firstOrNull;
  if (focus == null) {
    return sheet.copyWith();
  }
  final focusCell =
      sheet.cells[FortuneCellCoord(
        focus.rowFocus ?? focus.rowStart,
        focus.columnFocus ?? focus.columnStart,
      )];
  final cellType = focusCell?.cellType;
  if (cellType == null || cellType.type != 'n') {
    return sheet.copyWith();
  }
  final format =
      _nullableStringArg(cellType.rawFormat) ?? cellType.format ?? 'General';
  final nextFormat = delta > 0
      ? _apiIncreaseNumberFormat(format)
      : _apiDecreaseNumberFormat(format);
  if (nextFormat == null) {
    return sheet.copyWith();
  }
  return updateFormat(sheet, 'ct', {
    'fa': nextFormat,
    't': 'n',
  }, selection: ranges);
}

String? _apiDecreaseNumberFormat(String format) {
  if (format == 'General') {
    return null;
  }
  final largeUnit = RegExp(r'^(w|W)((0?)|(0\.0+))$');
  if (largeUnit.hasMatch(format)) {
    if (!format.contains('.')) {
      return format;
    }
    if (format.endsWith('.0')) {
      return format.split('.').first;
    }
    return format.substring(0, format.length - 1);
  }
  final dot = format.indexOf('.');
  if (dot < 0) {
    return null;
  }
  final prefix = format.substring(0, dot);
  final main = format.substring(dot + 1);
  final tail = _apiNumberFormatTail(main);
  final suffix = tail.isEmpty ? main : main.replaceFirst(tail, '');
  final pos = suffix.replaceAll('#', '0');
  final reduced = pos.isEmpty ? '' : pos.substring(0, pos.length - 1);
  return reduced.isEmpty ? '$prefix$tail' : '$prefix.$reduced$tail';
}

String? _apiIncreaseNumberFormat(String format) {
  if (format == 'General') {
    return '#.0';
  }
  final largeUnit = RegExp(r'^(w|W)((0?)|(0\.0+))$');
  if (largeUnit.hasMatch(format)) {
    if (format.contains('.')) {
      return '${format}0';
    }
    return format.endsWith('0') ? '$format.0' : '${format}0.0';
  }
  final dot = format.indexOf('.');
  final prefix = dot >= 0 ? format.substring(0, dot) : format;
  final main = dot >= 0 ? format.substring(dot + 1) : format;
  final tail = _apiNumberFormatTail(main);
  if (dot >= 0) {
    final suffix = tail.isEmpty ? main : main.replaceFirst(tail, '');
    final pos = suffix.replaceAll('#', '0');
    return '$prefix.${pos}0$tail';
  }
  return tail.isEmpty ? '$main.0' : '${main.replaceFirst(tail, '')}.0$tail';
}

String _apiNumberFormatTail(String main) {
  var tail = '';
  for (var index = main.length - 1; index >= 0; index -= 1) {
    final char = main[index];
    if (char != '#' &&
        char != '0' &&
        char != ',' &&
        int.tryParse(char) == null) {
      tail = char + tail;
    } else {
      break;
    }
  }
  return tail;
}

FortuneSheet handleSort(
  FortuneSheet sheet,
  bool isAsc, {
  int? colIndex,
  FortuneRange? selection,
}) {
  return sortSelection(
    sheet,
    isAsc,
    colIndex: colIndex ?? 0,
    selection: selection == null ? null : [selection],
  );
}

FortuneSheet handleMerge(
  FortuneSheet sheet,
  String type, {
  Iterable<FortuneRange>? selection,
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet.copyWith();
  }
  final ranges = selection?.toList() ?? getSelection(sheet);
  if (ranges.isEmpty || selectIsOverlap(sheet, ranges)) {
    return sheet.copyWith();
  }
  if (ranges.any(
    (range) => hasPartMC(
      sheet,
      range.rowStart,
      range.rowEnd,
      range.columnStart,
      range.columnEnd,
    ),
  )) {
    return sheet.copyWith();
  }
  final effectiveType =
      type != 'merge-cancel' &&
          ranges.any((range) => _apiRangeHasMerge(sheet.cells, range))
      ? 'merge-cancel'
      : type;
  var nextSheet = sheet.copyWith();
  for (final range in ranges) {
    nextSheet = nextSheet.mergeCells(range, effectiveType);
  }
  return nextSheet;
}

FortuneSheet handleFreeze(
  FortuneSheet sheet,
  String type, {
  FortuneRange? selection,
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet.copyWith();
  }
  if (type == 'freeze-cancel') {
    return sheet.copyWith(frozen: null);
  }
  final firstSelection = selection ?? getSelection(sheet).firstOrNull;
  if (firstSelection == null) {
    return sheet.copyWith();
  }
  final focus = sheet.mergeAnchorFor(
    FortuneCellCoord(
      firstSelection.rowFocus ?? firstSelection.rowStart,
      firstSelection.columnFocus ?? firstSelection.columnStart,
    ),
  );
  final merge = sheet.cells[focus]?.merge;
  final rowFocus = merge == null ? focus.row : merge.row + merge.rowSpan - 1;
  final columnFocus = merge == null
      ? focus.column
      : merge.column + merge.columnSpan - 1;
  final frozenType = switch (type) {
    'freeze-row' => 'rangeRow',
    'freeze-col' => 'rangeColumn',
    _ => 'both',
  };
  return sheet.copyWith(
    frozen: FortuneFrozenPane(
      type: frozenType,
      rowFocus: rowFocus,
      columnFocus: columnFocus,
    ),
  );
}

FortuneSheet handleClearFormat(
  FortuneSheet sheet, {
  Iterable<FortuneRange>? selection,
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet.copyWith();
  }
  final ranges = selection?.toList() ?? getSelection(sheet);
  if (ranges.isEmpty) {
    return sheet.copyWith();
  }
  final cells = <FortuneCellCoord, FortuneCell>{
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  for (final range in ranges) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      for (
        var column = normalized.columnStart;
        column <= normalized.columnEnd;
        column += 1
      ) {
        final coord = FortuneCellCoord(row, column);
        final cell = cells[coord];
        if (cell == null) {
          continue;
        }
        final nextCell = _apiCellWithoutFormat(cell);
        if (nextCell.isVisuallyEmpty &&
            nextCell.merge == null &&
            nextCell.cellType == null) {
          cells.remove(coord);
        } else {
          cells[coord] = nextCell;
        }
      }
    }
  }
  final nextRawBorderInfo = _apiClearFormatRawBorderInfo(sheet, ranges);
  return sheet.copyWith(
    cells: cells,
    borderInfo: _apiClearFormatBorderInfo(sheet.borderInfo, ranges),
    rawBorderInfo: nextRawBorderInfo,
    hasRawBorderInfo: nextRawBorderInfo != null,
  );
}

List<FortuneBorderInfo> _apiClearFormatBorderInfo(
  List<FortuneBorderInfo> borderInfo,
  Iterable<FortuneRange> selections,
) {
  var nextBorderInfo = [for (final border in borderInfo) border.copyWith()];
  for (final selection in selections) {
    final normalized = _normalizedApiRange(selection);
    if (normalized == null) {
      continue;
    }
    final current = <FortuneBorderInfo>[];
    for (final border in nextBorderInfo) {
      if (border.rangeType == 'cell') {
        final firstRange = border.ranges.firstOrNull;
        if (firstRange == null ||
            !_apiRangeStartInRange(firstRange, normalized)) {
          current.add(border.copyWith());
        }
        continue;
      }
      if (border.rangeType != 'range') {
        current.add(border.copyWith());
        continue;
      }
      if (border.borderType == 'border-slash') {
        final firstRange = border.ranges.firstOrNull;
        if (firstRange == null ||
            !_apiRangeStartInRange(firstRange, normalized)) {
          current.add(border.copyWith());
        }
        continue;
      }
      final ranges = <FortuneRange>[];
      for (final range in border.ranges) {
        ranges.addAll(cfSplitRange(range, normalized, normalized, 'restPart'));
      }
      if (ranges.isNotEmpty) {
        current.add(border.copyWith(ranges: ranges));
      }
    }
    nextBorderInfo = current;
  }
  return nextBorderInfo;
}

Object? _apiClearFormatRawBorderInfo(
  FortuneSheet sheet,
  Iterable<FortuneRange> selections,
) {
  if (!sheet.hasRawBorderInfo || sheet.rawBorderInfo is! List) {
    return sheet.rawBorderInfo == null
        ? null
        : cloneFortuneMetadata(sheet.rawBorderInfo);
  }
  var next = [for (final item in sheet.rawBorderInfo! as List) item];
  for (final selection in selections) {
    final normalized = _normalizedApiRange(selection);
    if (normalized == null) {
      continue;
    }
    final current = <Object?>[];
    for (final item in next) {
      if (item is! Map) {
        current.add(cloneFortuneMetadata(item));
        continue;
      }
      final map = Map<Object?, Object?>.from(cloneFortuneMetadata(item) as Map);
      final rangeType = _nullableStringArg(map['rangeType']);
      if (rangeType == 'cell') {
        final value = map['value'];
        final row = value is Map ? _nullableIntArg(value['row_index']) : null;
        final column = value is Map
            ? _nullableIntArg(value['col_index'])
            : null;
        if (row == null ||
            column == null ||
            row < normalized.rowStart ||
            row > normalized.rowEnd ||
            column < normalized.columnStart ||
            column > normalized.columnEnd) {
          current.add(map);
        }
        continue;
      }
      if (rangeType == 'range' && map['borderType'] == 'border-slash') {
        final firstRange = _apiRawBorderRanges(map['range']).firstOrNull;
        if (firstRange == null ||
            !_apiRangeStartInRange(firstRange, normalized)) {
          current.add(map);
        }
        continue;
      }
      if (rangeType == 'range') {
        final ranges = <FortuneRange>[];
        for (final range in _apiRawBorderRanges(map['range'])) {
          ranges.addAll(
            cfSplitRange(range, normalized, normalized, 'restPart'),
          );
        }
        if (ranges.isNotEmpty) {
          map['range'] = [
            for (final split in ranges) _apiRawBorderRange(split),
          ];
          current.add(map);
        }
        continue;
      }
      current.add(map);
    }
    next = current;
  }
  return next.isEmpty ? null : next;
}

List<FortuneRange> _apiRawBorderRanges(Object? raw) {
  if (raw is! List) {
    return const [];
  }
  final ranges = <FortuneRange>[];
  for (final item in raw) {
    if (item is! Map) {
      continue;
    }
    final row = _rawAxisPair(item['row']);
    final column = _rawAxisPair(item['column']);
    if (row == null || column == null) {
      continue;
    }
    ranges.add(
      FortuneRange(
        rowStart: math.min(row[0], row[1]),
        rowEnd: math.max(row[0], row[1]),
        columnStart: math.min(column[0], column[1]),
        columnEnd: math.max(column[0], column[1]),
      ),
    );
  }
  return ranges;
}

Map<String, Object?> _apiRawBorderRange(FortuneRange range) {
  return {
    'row': [range.rowStart, range.rowEnd],
    'column': [range.columnStart, range.columnEnd],
  };
}

bool _apiRangeStartInRange(FortuneRange range, FortuneRange container) {
  return range.rowStart >= container.rowStart &&
      range.rowStart <= container.rowEnd &&
      range.columnStart >= container.columnStart &&
      range.columnStart <= container.columnEnd;
}

Map<String, Object?>? handleLink(
  FortuneSheet sheet, {
  FortuneRange? selection,
  List<num> visibleDataRows = const [],
  List<num> visibleDataColumns = const [],
}) {
  final firstSelection = selection ?? getSelection(sheet).firstOrNull;
  if (firstSelection == null) {
    return null;
  }
  return showLinkCard(
    sheet,
    firstSelection.rowStart,
    firstSelection.columnStart,
    isEditing: true,
    visibleDataRows: visibleDataRows,
    visibleDataColumns: visibleDataColumns,
  );
}

Map<String, Object?>? handleScreenShot(
  FortuneSheet sheet, {
  Iterable<FortuneRange>? selection,
  required List<num> visibleDataRows,
  required List<num> visibleDataColumns,
  num devicePixelRatio = 1,
}) {
  final ranges = (selection ?? sheet.getSelection()).toList();
  if (ranges.isEmpty || ranges.length > 1) {
    return null;
  }
  final sourceRange = ranges.single;
  final range = FortuneRange(
    rowStart: math.min(sourceRange.rowStart, sourceRange.rowEnd),
    rowEnd: math.max(sourceRange.rowStart, sourceRange.rowEnd),
    columnStart: math.min(sourceRange.columnStart, sourceRange.columnEnd),
    columnEnd: math.max(sourceRange.columnStart, sourceRange.columnEnd),
    rowFocus: sourceRange.rowFocus,
    columnFocus: sourceRange.columnFocus,
  );
  if (hasPartMC(
    sheet,
    range.rowStart,
    range.rowEnd,
    range.columnStart,
    range.columnEnd,
  )) {
    return null;
  }
  if (range.rowEnd >= visibleDataRows.length ||
      range.columnEnd >= visibleDataColumns.length) {
    return null;
  }
  final scrollHeight = range.rowStart == 0
      ? 0
      : visibleDataRows[range.rowStart - 1];
  final drawHeight = range.rowStart == 0
      ? visibleDataRows[range.rowEnd]
      : visibleDataRows[range.rowEnd] - visibleDataRows[range.rowStart - 1];
  final scrollWidth = range.columnStart == 0
      ? 0
      : visibleDataColumns[range.columnStart - 1];
  final drawWidth = range.columnStart == 0
      ? visibleDataColumns[range.columnEnd]
      : visibleDataColumns[range.columnEnd] -
            visibleDataColumns[range.columnStart - 1];
  return {
    'range': range,
    'scrollWidth': scrollWidth,
    'scrollHeight': scrollHeight,
    'drawWidth': drawWidth,
    'drawHeight': drawHeight,
    'canvasWidth': (drawWidth * devicePixelRatio).ceil(),
    'canvasHeight': (drawHeight * devicePixelRatio).ceil(),
    'drawOptions': {
      'scrollWidth': scrollWidth,
      'scrollHeight': scrollHeight,
      'drawWidth': drawWidth,
      'drawHeight': drawHeight,
      'offsetLeft': 1,
      'offsetTop': 1,
      'clear': true,
    },
    'imageStyle': drawWidth > drawHeight
        ? const {'width': '100%'}
        : const {'height': '100%'},
  };
}

FortuneCell _apiCellWithoutFormat(FortuneCell cell) {
  return FortuneCell(
    value: cell.value,
    rawValue: cloneFortuneMetadata(cell.rawValue),
    hasRawValue: cell.hasRawValue,
    displayValue: cell.displayValue,
    rawDisplayValue: cloneFortuneMetadata(cell.rawDisplayValue),
    hasRawDisplayValue: cell.hasRawDisplayValue,
    formula: cell.formula,
    rawFormula: cloneFortuneMetadata(cell.rawFormula),
    hasRawFormula: cell.hasRawFormula,
    merge: cell.merge?.copyWith(),
    cellType: cell.cellType?.copyWith(),
  );
}

FortuneSheet _apiToggleToolbarAttr(
  FortuneSheet sheet,
  String attr, {
  Iterable<FortuneRange>? selection,
}) {
  final ranges = selection?.toList() ?? getSelection(sheet);
  final enabled = isAllSelectedCellsInStatus(sheet, attr, '1', ranges: ranges);
  return updateFormat(sheet, attr, enabled ? 0 : 1, selection: ranges);
}

Object? _apiToolbarFormatValue(String attr, Object? value) {
  if (attr == 'ht') {
    return switch ('$value') {
      'center' => '0',
      'left' => '1',
      'right' => '2',
      _ => value,
    };
  }
  if (attr == 'vt') {
    return switch ('$value') {
      'middle' => '0',
      'top' => '1',
      'bottom' => '2',
      _ => value,
    };
  }
  return value;
}

Object? getCellValue(
  FortuneSheet sheet,
  int row,
  int column, {
  String type = 'v',
}) {
  if (type == 'f') {
    final cell = sheet.cells[FortuneCellCoord(row, column)];
    final formula =
        cell?.formula ??
        (cell?.hasRawFormula == true ? cell?.rawFormula?.toString() : null);
    if (formula != null) {
      return functionHTMLGenerate(formula);
    }
  }
  return sheet.getCellValue(row, column, type: type);
}

FortuneSheet setCellValue(
  FortuneSheet sheet,
  int row,
  int column,
  Object? value,
) {
  return _apiSheetWithFunctionGroupCleanupAfterValueSet(
    sheet,
    sheet.setCellValue(row, column, value),
    row,
    column,
  );
}

FortuneSheet _apiSheetWithFunctionGroupCleanupAfterValueSet(
  FortuneSheet previousSheet,
  FortuneSheet nextSheet,
  int row,
  int column,
) {
  final current = previousSheet.cells[FortuneCellCoord(row, column)];
  final nextCell = nextSheet.cells[FortuneCellCoord(row, column)];
  final hadFormula =
      current?.formula != null ||
      (current?.hasRawFormula == true && current?.rawFormula != null);
  final hasNextFormula =
      nextCell?.formula != null ||
      (nextCell?.hasRawFormula == true && nextCell?.rawFormula != null);
  if (hadFormula && !hasNextFormula) {
    return _apiSheetWithoutFunctionGroup(
      nextSheet,
      row,
      column,
      previousSheet.id,
    );
  }
  return nextSheet;
}

Map<String, Object?>? updateCell(
  FortuneSheet sheet,
  int row,
  int column, {
  Object? value,
  String? inputText,
  String lang = 'en',
  BeforeUpdateCellHook? beforeUpdateCell,
  AfterUpdateCellHook? afterUpdateCell,
}) {
  if (row < 0 || column < 0) {
    return null;
  }
  final nextValue = value ?? inputText;
  if (beforeUpdateCell?.call(row, column, nextValue) == false) {
    return {
      'sheet': sheet,
      'cancelNormalSelected': true,
      'blocked': 'beforeUpdateCell',
    };
  }
  final verification = sheet.dataVerification['${row}_$column'];
  if (verification is Map && verification['prohibitInput'] == true) {
    final item = Map<String, Object?>.from(verification);
    if (!validateCellData(item, nextValue, sheet: sheet)) {
      return {
        'sheet': sheet,
        'cancelNormalSelected': true,
        'warnDialog': getFailureText(item, lang: lang),
        'blocked': 'dataVerification',
      };
    }
  }
  final current = sheet.cells[FortuneCellCoord(row, column)];
  if (isRealNull(nextValue) &&
      (current == null ||
          (isRealNull(current.value) &&
              current.formula == null &&
              !current.hasSparkline))) {
    return {'sheet': sheet, 'cancelNormalSelected': true, 'noop': true};
  }
  if (current != null && !current.quotePrefix) {
    final rawCurrent = current.hasRawValue ? current.rawValue : current.value;
    if (nextValue == current.formula ||
        nextValue == rawCurrent ||
        nextValue == current.displayValue) {
      return {'sheet': sheet, 'cancelNormalSelected': true, 'noop': true};
    }
  }
  var targetSheet = sheet;
  if (current != null &&
      current.quotePrefix &&
      !(nextValue is String &&
          nextValue.startsWith('=') &&
          nextValue.length > 1) &&
      !nextValue.toString().startsWith("'")) {
    final cells = Map<FortuneCellCoord, FortuneCell>.from(sheet.cells);
    cells[FortuneCellCoord(row, column)] = current.copyWith(
      quotePrefix: false,
      rawQuotePrefix: 0,
      hasRawQuotePrefix: true,
      cellType: const FortuneCellType(
        format: 'General',
        rawFormat: 'General',
        hasRawFormat: true,
        type: 'n',
        rawType: 'n',
        hasRawType: true,
      ),
    );
    targetSheet = sheet.copyWith(cells: cells);
  }
  final nextSheet = _apiSheetWithFunctionGroupCleanupAfterValueSet(
    targetSheet,
    targetSheet.setCellValue(row, column, nextValue),
    row,
    column,
  );
  afterUpdateCell?.call(
    row,
    column,
    current,
    nextSheet.cells[FortuneCellCoord(row, column)],
  );
  return {
    'sheet': nextSheet,
    'cancelNormalSelected': true,
    'formulaCellInfo': {'r': row, 'c': column, 'id': sheet.id},
    'execFunctionGlobalData': null,
  };
}

FortuneSheet updateMoreCell(
  FortuneSheet sheet,
  int row,
  int column,
  List<List<Object?>> dataMatrix, {
  bool allowEdit = true,
}) {
  if (!allowEdit) {
    return sheet.copyWith();
  }
  var next = sheet;
  for (var rowOffset = 0; rowOffset < dataMatrix.length; rowOffset += 1) {
    final rowData = dataMatrix[rowOffset];
    for (
      var columnOffset = 0;
      columnOffset < rowData.length;
      columnOffset += 1
    ) {
      next = setCellValue(
        next,
        row + rowOffset,
        column + columnOffset,
        rowData[columnOffset],
      );
    }
  }
  return next;
}

FortuneSheet clearCell(FortuneSheet sheet, int row, int column) {
  return _apiSheetWithFunctionGroupCleanupAfterValueSet(
    sheet,
    sheet.clearCell(row, column),
    row,
    column,
  );
}

FortuneSheet deleteSelectedCellText(
  FortuneSheet sheet, {
  Iterable<FortuneRange>? selection,
  bool allowEdit = true,
  bool hasPartMerge = false,
}) {
  if (!allowEdit || hasPartMerge) {
    return sheet.copyWith();
  }
  final ranges = selection?.toList() ?? getSelection(sheet);
  if (ranges.isEmpty) {
    return sheet.copyWith();
  }
  final cells = <FortuneCellCoord, FortuneCell>{
    for (final entry in sheet.cells.entries) entry.key: entry.value.copyWith(),
  };
  final hyperlinks = _cloneStringObjectMap(sheet.hyperlinks);
  for (final range in ranges) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      continue;
    }
    for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
      for (
        var column = normalized.columnStart;
        column <= normalized.columnEnd;
        column += 1
      ) {
        cells.remove(FortuneCellCoord(row, column));
        hyperlinks.remove('${row}_$column');
      }
    }
  }
  return sheet.copyWith(cells: cells, hyperlinks: hyperlinks);
}

FortuneSheet setCellFormat(
  FortuneSheet sheet,
  int row,
  int column,
  String attr,
  Object? value,
) {
  return sheet.setCellFormat(row, column, attr, value);
}

String _nextSheetIdFor(List<FortuneSheet> sheets) {
  var index = sheets.length + 1;
  while (sheets.any((sheet) => sheet.id == 'sheet_$index')) {
    index += 1;
  }
  return 'sheet_$index';
}

String _nextSheetIdForSeenIds(Set<String> seenIds) {
  var index = seenIds.length + 1;
  while (seenIds.contains('sheet_$index')) {
    index += 1;
  }
  return 'sheet_$index';
}

String? _generatedSheetIdCandidate(
  List<FortuneSheet> sheets,
  String Function()? generateSheetId,
) {
  if (generateSheetId == null) {
    return null;
  }
  final nextId = generateSheetId();
  if (nextId.isEmpty || sheets.any((sheet) => sheet.id == nextId)) {
    return null;
  }
  return nextId;
}

String? _generatedAddSheetIdCandidate(
  List<FortuneSheet> sheets,
  String Function()? generateSheetId,
) {
  return generateSheetId == null
      ? _generatedCopySheetId(sheets)
      : _generatedSheetIdCandidate(sheets, generateSheetId);
}

String _generateUuidV4({math.Random? random}) {
  final generator = random ?? math.Random.secure();
  final bytes = List<int>.generate(16, (_) => generator.nextInt(256));
  bytes[6] = (bytes[6] & 0x0f) | 0x40;
  bytes[8] = (bytes[8] & 0x3f) | 0x80;
  String hex(int value) => value.toRadixString(16).padLeft(2, '0');
  final text = bytes.map(hex).join();
  return '${text.substring(0, 8)}-'
      '${text.substring(8, 12)}-'
      '${text.substring(12, 16)}-'
      '${text.substring(16, 20)}-'
      '${text.substring(20)}';
}

String _generatedCopySheetId(List<FortuneSheet> sheets) {
  final existingIds = sheets.map((sheet) => sheet.id).toSet();
  String nextId;
  do {
    nextId = _generateUuidV4();
  } while (existingIds.contains(nextId));
  return nextId;
}

String _copySheetNameFor(String name, List<FortuneSheet> sheets) {
  final copyIndex = name.indexOf('(copy');
  final base = copyIndex < 0 ? name : name.substring(0, copyIndex);
  final names = sheets.map((sheet) => sheet.name).toSet();
  int? index;
  late String candidate;
  do {
    final suffix = index == null ? '(copy)' : '(copy$index)';
    final lengthLimit = 31 - suffix.length;
    final truncatedBase = base.length > lengthLimit
        ? '${base.substring(0, math.max(0, lengthLimit - 1))}…'
        : base;
    candidate = '$truncatedBase$suffix';
    index = (index ?? 1) + 1;
  } while (names.contains(candidate));
  return candidate;
}

List<FortuneSheet> ensureSheetIndex(
  List<FortuneSheet> sheets,
  String Function() generateSheetId,
) {
  if (sheets.isEmpty) {
    return const [];
  }
  var hasActive = false;
  final seenIds = <String>{};
  final nextSheets = <FortuneSheet>[];
  for (final sheet in sheets) {
    var nextSheet = sheet.copyWith();
    if (nextSheet.id.isEmpty || seenIds.contains(nextSheet.id)) {
      final generatedId = generateSheetId();
      final nextId = generatedId.isNotEmpty && !seenIds.contains(generatedId)
          ? generatedId
          : _nextSheetIdForSeenIds(seenIds);
      nextSheet = nextSheet.copyWith(id: nextId);
    }
    seenIds.add(nextSheet.id);
    final status = nextSheet.status ?? 0;
    if (status == 1) {
      if (hasActive) {
        nextSheet = nextSheet.copyWith(status: 0);
      } else {
        hasActive = true;
        nextSheet = nextSheet.copyWith(status: 1);
      }
    } else if (nextSheet.status == null) {
      nextSheet = nextSheet.copyWith(status: 0);
    }
    nextSheets.add(nextSheet);
  }
  if (!hasActive) {
    nextSheets[0] = nextSheets[0].copyWith(status: 1);
  }
  return nextSheets;
}

String? initSheetIndex(FortuneWorkbook workbook) {
  final shownSheets = [
    for (var index = 0; index < workbook.sheets.length; index += 1)
      if (workbook.sheets[index].hide != 1)
        MapEntry(index, workbook.sheets[index]),
  ];
  if (shownSheets.isEmpty) {
    return null;
  }
  shownSheets.sort((left, right) {
    final leftOrder = left.value.order ?? left.key;
    final rightOrder = right.value.order ?? right.key;
    final orderCompare = leftOrder.compareTo(rightOrder);
    return orderCompare != 0 ? orderCompare : left.key.compareTo(right.key);
  });
  var currentSheetId = shownSheets.first.value.id;
  for (final sheet in workbook.sheets) {
    if (sheet.status == 1 && sheet.hide != 1) {
      currentSheetId = sheet.id;
      break;
    }
  }
  return currentSheetId;
}

int _firstVisibleSheetIndex(List<FortuneSheet> sheets) {
  final shownSheets = [
    for (var index = 0; index < sheets.length; index += 1)
      if (sheets[index].hide != 1) MapEntry(index, sheets[index]),
  ];
  if (shownSheets.isEmpty) {
    return 0;
  }
  shownSheets.sort((left, right) {
    final leftOrder = left.value.order ?? left.key;
    final rightOrder = right.value.order ?? right.key;
    final orderCompare = leftOrder.compareTo(rightOrder);
    return orderCompare != 0 ? orderCompare : left.key.compareTo(right.key);
  });
  return shownSheets.first.key;
}

class FortuneWorkbook {
  FortuneWorkbook({
    required List<FortuneSheet> sheets,
    this.activeSheetIndex = 0,
    this.settings = const FortuneSettings(),
    Object? rawData,
    this.hasRawData = false,
    Map<String, Object?>? extraFields,
  }) : sheets = sheets.map((sheet) => sheet.copyWith()).toList(),
       rawData = cloneFortuneMetadata(rawData),
       extraFields = _cloneStringObjectMap(extraFields);

  final List<FortuneSheet> sheets;
  final int activeSheetIndex;
  final FortuneSettings settings;
  final Object? rawData;
  final bool hasRawData;
  final Map<String, Object?> extraFields;

  FortuneSheet get activeSheet => sheets[activeSheetIndex];

  List<FortuneSheet> getAllSheets() {
    return [for (final sheet in sheets) sheet.copyWith()];
  }

  FortuneSheet? getSheet({String? id, int? index}) {
    if (index != null) {
      if (index < 0 || index >= sheets.length) {
        return null;
      }
      return sheets[index].copyWith();
    }
    if (id != null) {
      final sheetIndex = sheets.indexWhere((sheet) => sheet.id == id);
      return sheetIndex < 0 ? null : sheets[sheetIndex].copyWith();
    }
    return activeSheet.copyWith();
  }

  Map<String, Object?>? getSheetWithLatestCelldata({String? id, int? index}) {
    final sheet = getSheet(id: id, index: index);
    if (sheet == null) {
      return null;
    }
    final json = FortuneSheetCodec.sheetToJson(sheet);
    final latestJson = FortuneSheetCodec.sheetToJson(
      sheet.copyWith(
        rawData: null,
        hasRawData: false,
        rawCelldata: null,
        hasRawCelldata: false,
      ),
    );
    json['celldata'] = cloneFortuneMetadata(
      latestJson['celldata'] ?? const <Object?>[],
    );
    return json;
  }

  FortuneWorkbook activateSheet(String sheetId) {
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    return copyWith(activeSheetIndex: index);
  }

  FortuneWorkbook setSheetName(String sheetId, String name) {
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    final nextSheets = [
      for (var sheetIndex = 0; sheetIndex < sheets.length; sheetIndex += 1)
        sheetIndex == index
            ? sheets[sheetIndex].copyWith(name: name)
            : sheets[sheetIndex].copyWith(),
    ];
    return copyWith(sheets: nextSheets);
  }

  FortuneWorkbook setSheetOrder(Map<String, int> orderList) {
    final currentActiveId = activeSheet.id;
    final nextSheets =
        [
          for (final sheet in sheets)
            orderList.containsKey(sheet.id)
                ? sheet.copyWith(order: orderList[sheet.id])
                : sheet.copyWith(),
        ]..sort((left, right) {
          final leftOrder =
              left.order ?? sheets.indexWhere((s) => s.id == left.id);
          final rightOrder =
              right.order ?? sheets.indexWhere((s) => s.id == right.id);
          final orderCompare = leftOrder.compareTo(rightOrder);
          return orderCompare != 0
              ? orderCompare
              : sheets
                    .indexWhere((sheet) => sheet.id == left.id)
                    .compareTo(
                      sheets.indexWhere((sheet) => sheet.id == right.id),
                    );
        });
    final normalizedSheets = [
      for (var index = 0; index < nextSheets.length; index += 1)
        nextSheets[index].copyWith(order: index),
    ];
    final nextActive = normalizedSheets.indexWhere(
      (sheet) => sheet.id == currentActiveId,
    );
    return copyWith(
      sheets: normalizedSheets,
      activeSheetIndex: nextActive < 0 ? activeSheetIndex : nextActive,
    );
  }

  FortuneWorkbook addSheet({
    String? id,
    String? name,
    int? rowCount,
    int? columnCount,
    FortuneSheet? sheet,
  }) {
    final currentActiveId = activeSheet.id;
    final generatedId = id == null
        ? _generatedAddSheetIdCandidate(sheets, settings.generateSheetId)
        : null;
    if (id == null && settings.generateSheetId != null && generatedId == null) {
      return copyWith();
    }
    final nextId = id ?? generatedId ?? _nextSheetIdFor(sheets);
    if (sheets.any((sheet) => sheet.id == nextId)) {
      return copyWith();
    }
    final nextName = name ?? sheet?.name ?? generateRandomSheetName(sheets);
    final insertOrder = sheet?.order;
    final nextSheet = (sheet ?? FortuneSheet(id: nextId, name: nextName))
        .copyWith(
          id: nextId,
          name: nextName,
          rowCount: rowCount ?? _sentinel,
          columnCount: columnCount ?? _sentinel,
          status: sheet == null ? 0 : _sentinel,
          order: insertOrder ?? sheets.length,
        );
    final nextSheets = [
      for (var sheetIndex = 0; sheetIndex < sheets.length; sheetIndex += 1)
        sheets[sheetIndex].copyWith(
          order: insertOrder == null
              ? sheets[sheetIndex].order
              : (sheets[sheetIndex].order ?? sheetIndex) < insertOrder
              ? sheets[sheetIndex].order ?? sheetIndex
              : (sheets[sheetIndex].order ?? sheetIndex) + 1,
        ),
      nextSheet,
    ];
    final currentActiveIndex = nextSheets.indexWhere(
      (sheet) => sheet.id == currentActiveId,
    );
    return copyWith(
      sheets: nextSheets,
      activeSheetIndex: id == null ? nextSheets.length - 1 : currentActiveIndex,
    );
  }

  FortuneWorkbook deleteSheet(String sheetId) {
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    final currentActiveId = activeSheet.id;
    final deletedOrder = sheets[index].order ?? index;
    final nextSheets = [
      for (var sheetIndex = 0; sheetIndex < sheets.length; sheetIndex += 1)
        if (sheetIndex != index)
          sheets[sheetIndex].copyWith(
            order: (sheets[sheetIndex].order ?? sheetIndex) < deletedOrder
                ? sheets[sheetIndex].order ?? sheetIndex
                : (sheets[sheetIndex].order ?? sheetIndex) - 1,
          ),
    ];
    final sameActive = nextSheets.indexWhere(
      (sheet) => sheet.id == currentActiveId,
    );
    final nextActive = sameActive >= 0
        ? sameActive
        : _firstVisibleSheetIndex(nextSheets);
    return copyWith(sheets: nextSheets, activeSheetIndex: nextActive);
  }

  FortuneWorkbook clearSheet(
    String sheetId, {
    int? rowCount,
    int? columnCount,
  }) {
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    final nextSheets = [
      for (var sheetIndex = 0; sheetIndex < sheets.length; sheetIndex += 1)
        sheetIndex == index
            ? _clearedSheetFrom(
                sheets[sheetIndex],
                rowCount: rowCount,
                columnCount: columnCount,
              )
            : sheets[sheetIndex].copyWith(),
    ];
    return copyWith(sheets: nextSheets);
  }

  FortuneWorkbook resizeSheetGridClientArea(
    String sheetId,
    int widthMm,
    int heightMm,
  ) {
    if (widthMm <= 0 || heightMm <= 0) {
      throw INVALID_PARAMS;
    }
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    final target = sheets[index];
    final extraFields = <String, Object?>{
      for (final entry in target.extraFields.entries)
        entry.key: cloneFortuneMetadata(entry.value),
      fortuneSheetGridClientWidthMmKey: widthMm,
      fortuneSheetGridClientHeightMmKey: heightMm,
    };
    final nextSheets = [
      for (var sheetIndex = 0; sheetIndex < sheets.length; sheetIndex += 1)
        sheetIndex == index
            ? target.copyWith(extraFields: extraFields)
            : sheets[sheetIndex].copyWith(),
    ];
    return copyWith(sheets: nextSheets);
  }

  FortuneWorkbook copySheet(String sheetId, {String? id}) {
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    final currentActiveId = activeSheet.id;
    final source = sheets[index];
    final nextSheets = [...sheets.map((sheet) => sheet.copyWith())];
    nextSheets.insert(
      index + 1,
      source.copyWith(
        id: id ?? _generatedCopySheetId(sheets),
        name: _copySheetNameFor(source.name, sheets),
        status: null,
        order: index + 1,
      ),
    );
    final normalizedSheets = [
      for (var sheetIndex = 0; sheetIndex < nextSheets.length; sheetIndex += 1)
        nextSheets[sheetIndex].copyWith(order: sheetIndex),
    ];
    final nextActive = normalizedSheets.indexWhere(
      (sheet) => sheet.id == currentActiveId,
    );
    return copyWith(
      sheets: normalizedSheets,
      activeSheetIndex: nextActive < 0 ? activeSheetIndex : nextActive,
    );
  }

  FortuneWorkbook hideSheet(String sheetId) {
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    final nextSheets = [
      for (var sheetIndex = 0; sheetIndex < sheets.length; sheetIndex += 1)
        sheetIndex == index
            ? sheets[sheetIndex].copyWith(hide: 1, status: 0)
            : sheets[sheetIndex].copyWith(),
    ];
    final visibleIndex = nextSheets.indexWhere((sheet) => sheet.hide != 1);
    final nextActive = visibleIndex >= 0
        ? visibleIndex
        : activeSheetIndex.clamp(0, nextSheets.length - 1).toInt();
    return copyWith(sheets: nextSheets, activeSheetIndex: nextActive);
  }

  FortuneWorkbook showSheet(String sheetId) {
    final index = sheets.indexWhere((sheet) => sheet.id == sheetId);
    if (index < 0) {
      return copyWith();
    }
    final nextSheets = [
      for (var sheetIndex = 0; sheetIndex < sheets.length; sheetIndex += 1)
        sheetIndex == index
            ? sheets[sheetIndex].copyWith(hide: null)
            : sheets[sheetIndex].copyWith(),
    ];
    return copyWith(sheets: nextSheets);
  }

  FortuneWorkbook updateSheet(List<FortuneSheet> data) {
    if (data.isEmpty) {
      return copyWith();
    }
    final currentActiveId = activeSheet.id;
    final nextSheets = [...sheets.map((sheet) => sheet.copyWith())];
    for (final sheet in data) {
      final index = nextSheets.indexWhere((current) => current.id == sheet.id);
      final nextSheet = sheet.copyWith();
      if (index < 0) {
        nextSheets.add(nextSheet);
      } else {
        nextSheets[index] = nextSheet;
      }
    }
    final nextActive = nextSheets.indexWhere(
      (sheet) => sheet.id == currentActiveId,
    );
    return copyWith(
      sheets: nextSheets,
      activeSheetIndex: nextActive < 0 ? activeSheetIndex : nextActive,
    );
  }

  FortuneWorkbook copyWith({
    List<FortuneSheet>? sheets,
    Object? activeSheetIndex = _sentinel,
    FortuneSettings? settings,
    Object? rawData = _sentinel,
    bool? hasRawData,
    Map<String, Object?>? extraFields,
  }) {
    final sourceSheets = sheets ?? this.sheets;
    final nextSheets = sourceSheets.map((sheet) => sheet.copyWith()).toList();
    final parsedActive = activeSheetIndex == _sentinel
        ? this.activeSheetIndex
        : _nullableIntArg(activeSheetIndex) ?? this.activeSheetIndex;
    final nextActive = nextSheets.isEmpty
        ? 0
        : parsedActive.clamp(0, nextSheets.length - 1).toInt();
    return FortuneWorkbook(
      sheets: nextSheets,
      activeSheetIndex: nextActive,
      settings: settings ?? this.settings,
      rawData: rawData == _sentinel
          ? sheets == null
                ? cloneFortuneMetadata(this.rawData)
                : null
          : cloneFortuneMetadata(rawData),
      hasRawData:
          hasRawData ??
          (rawData == _sentinel
              ? sheets == null
                    ? this.hasRawData
                    : false
              : true),
      extraFields: extraFields ?? _cloneStringObjectMap(this.extraFields),
    );
  }
}

