  FortuneCellCoord mergeAnchorFor(FortuneCellCoord coord) {
    final merge = cells[coord]?.merge;
    if (merge != null) {
      return FortuneCellCoord(merge.row, merge.column);
    }
    for (final entry in cells.entries) {
      final candidate = entry.value.merge;
      if (candidate == null ||
          (candidate.rowSpan <= 1 && candidate.columnSpan <= 1)) {
        continue;
      }
      if (coord.row >= candidate.row &&
          coord.row < candidate.row + candidate.rowSpan &&
          coord.column >= candidate.column &&
          coord.column < candidate.column + candidate.columnSpan) {
        return FortuneCellCoord(candidate.row, candidate.column);
      }
    }
    return coord;
  }

  Object? getCellValue(int row, int column, {String type = 'v'}) {
    if (row < 0 || column < 0) {
      return null;
    }
    final cell = cells[FortuneCellCoord(row, column)];
    if (cell == null) {
      return null;
    }
    return switch (type) {
      'v' => _apiGetCellValue(cell),
      'm' => cell.hasRawDisplayValue ? cell.rawDisplayValue : cell.displayValue,
      'f' => _apiGetFormulaCellValue(cell),
      _ => _apiRawCellAttr(cell, type),
    };
  }

  FortuneSheet setCellValue(int row, int column, Object? value) {
    if (row < 0 || column < 0) {
      return copyWith();
    }
    if (value == null || value == '') {
      return clearCell(row, column);
    }
    final coord = FortuneCellCoord(row, column);
    final current = cells[coord] ?? const FortuneCell();
    final nextCells = Map<FortuneCellCoord, FortuneCell>.from(cells);
    nextCells[coord] = switch (value) {
      FortuneCell cell => cell.copyWith(),
      String text when text.startsWith("'") => current.copyWith(
        value: text.substring(1),
        rawValue: text.substring(1),
        hasRawValue: true,
        displayValue: text.substring(1),
        rawDisplayValue: text.substring(1),
        hasRawDisplayValue: true,
        formula: null,
        rawFormula: null,
        hasRawFormula: false,
        cellType: const FortuneCellType(
          format: '@',
          rawFormat: '@',
          hasRawFormat: true,
          type: 's',
          rawType: 's',
          hasRawType: true,
        ),
        quotePrefix: true,
        rawQuotePrefix: 1,
        hasRawQuotePrefix: true,
        sparkline: null,
        rawSparkline: null,
        hasSparkline: false,
        hasRawSparkline: false,
      ),
      String text when text.startsWith('=') => current.copyWith(
        value: '',
        rawValue: null,
        hasRawValue: false,
        displayValue: null,
        rawDisplayValue: null,
        hasRawDisplayValue: false,
        formula: text,
        rawFormula: text,
        hasRawFormula: true,
        sparkline: null,
        rawSparkline: null,
        hasSparkline: false,
        hasRawSparkline: false,
      ),
      Map valueMap => _cellWithApiValueMap(current, valueMap),
      _ when current.quotePrefix => current.copyWith(
        value: value.toString(),
        rawValue: value.toString(),
        hasRawValue: true,
        displayValue: value.toString(),
        rawDisplayValue: value.toString(),
        hasRawDisplayValue: true,
        formula: null,
        rawFormula: null,
        hasRawFormula: false,
        cellType: const FortuneCellType(
          format: '@',
          rawFormat: '@',
          hasRawFormat: true,
          type: 's',
          rawType: 's',
          hasRawType: true,
        ),
        rawQuotePrefix: current.hasRawQuotePrefix ? current.rawQuotePrefix : 1,
        hasRawQuotePrefix: true,
        sparkline: null,
        rawSparkline: null,
        hasSparkline: false,
        hasRawSparkline: false,
      ),
      _ => _cellWithPlainSetValue(current, value),
    };
    final nextSheet = copyWith(cells: nextCells);
    return _apiSheetWithFunctionGroupCleanupAfterValueSet(
      this,
      nextSheet,
      row,
      column,
    );
  }

  FortuneSheet clearCell(int row, int column) {
    if (row < 0 || column < 0) {
      return copyWith();
    }
    final coord = FortuneCellCoord(row, column);
    final current = cells[coord];
    if (current == null) {
      return copyWith();
    }
    final nextCells = Map<FortuneCellCoord, FortuneCell>.from(cells);
    nextCells[coord] = current.copyWith(
      value: '',
      rawValue: null,
      hasRawValue: false,
      displayValue: null,
      rawDisplayValue: null,
      hasRawDisplayValue: false,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      sparkline: current.formula != null ? null : _sentinel,
      rawSparkline: current.formula != null ? null : _sentinel,
      hasSparkline: current.formula != null ? false : null,
      hasRawSparkline: current.formula != null ? false : null,
    );
    final nextSheet = copyWith(cells: nextCells);
    return _apiSheetWithFunctionGroupCleanupAfterValueSet(
      this,
      nextSheet,
      row,
      column,
    );
  }

  FortuneSheet setCellFormat(int row, int column, String attr, Object? value) {
    if (row < 0 || column < 0) {
      return copyWith();
    }
    if (attr.isEmpty) {
      throw const FortuneApiError('attr cannot be null or undefined');
    }
    if (attr == 'ct' &&
        (value is! Map ||
            !value.containsKey('fa') ||
            !value.containsKey('t'))) {
      throw const FortuneApiError(
        "'fa' and 't' should be present in value when attr is 'ct'",
      );
    }
    if (attr == 'bd') {
      return _sheetWithApiBorder(this, row, column, value);
    }
    final coord = FortuneCellCoord(row, column);
    final current = cells[coord] ?? const FortuneCell();
    final nextCells = Map<FortuneCellCoord, FortuneCell>.from(cells);
    nextCells[coord] = _cellWithApiFormat(current, attr, value);
    return copyWith(cells: nextCells);
  }

  FortuneSheet mergeCells(FortuneRange range, String type) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      return copyWith();
    }
    final nextCells = Map<FortuneCellCoord, FortuneCell>.from(cells);
    if (_apiRangeIsSingleCell(normalized)) {
      return copyWith(cells: nextCells);
    }
    final hasExistingMerge = _apiRangeHasMerge(nextCells, normalized);
    if (type != 'merge-cancel' && hasExistingMerge) {
      _clearMergesInApiRange(nextCells, normalized);
      return copyWith(cells: nextCells);
    }
    _clearMergesInApiRange(nextCells, normalized);
    switch (type) {
      case 'merge-cancel':
        break;
      case 'merge-horizontal':
        for (
          var row = normalized.rowStart;
          row <= normalized.rowEnd;
          row += 1
        ) {
          _mergeApiCellsAt(
            nextCells,
            FortuneCellCoord(row, normalized.columnStart),
            rowSpan: 1,
            columnSpan: normalized.columnEnd - normalized.columnStart + 1,
            allowSingleCell: true,
          );
        }
      case 'merge-vertical':
        for (
          var column = normalized.columnStart;
          column <= normalized.columnEnd;
          column += 1
        ) {
          _mergeApiCellsAt(
            nextCells,
            FortuneCellCoord(normalized.rowStart, column),
            rowSpan: normalized.rowEnd - normalized.rowStart + 1,
            columnSpan: 1,
            allowSingleCell: true,
          );
        }
      case 'merge-all':
      case 'merge-cell':
        _mergeApiCellsAt(
          nextCells,
          FortuneCellCoord(normalized.rowStart, normalized.columnStart),
          rowSpan: normalized.rowEnd - normalized.rowStart + 1,
          columnSpan: normalized.columnEnd - normalized.columnStart + 1,
        );
      default:
        return copyWith(cells: nextCells);
    }
    return copyWith(cells: nextCells);
  }

  FortuneSheet cancelMerge(FortuneRange range) {
    return mergeCells(range, 'merge-cancel');
  }

  FortuneSheet freeze(String type, {required int row, required int column}) {
    if (row < 0 || column < 0) {
      return copyWith();
    }
    final frozenType = switch (type) {
      'row' => 'rangeRow',
      'column' => 'rangeColumn',
      'both' => 'rangeBoth',
      _ => null,
    };
    if (frozenType == null) {
      return copyWith();
    }
    return copyWith(
      frozen: FortuneFrozenPane(
        type: frozenType,
        rowFocus: row,
        columnFocus: column,
      ),
    );
  }

  List<FortuneCellCoord> getFlattenRange(Iterable<FortuneRange> ranges) {
    final result = <FortuneCellCoord>[];
    for (final range in ranges) {
      final normalized = _normalizedApiRange(range);
      if (normalized == null) {
        continue;
      }
      for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
        for (
          var column = normalized.columnStart;
          column <= normalized.columnEnd;
          column += 1
        ) {
          result.add(FortuneCellCoord(row, column));
        }
      }
    }
    return result;
  }

  List<FortuneCell?> getCellsByFlattenRange(Iterable<FortuneCellCoord> range) {
    return [for (final coord in range) cells[coord]?.copyWith()];
  }

  List<List<FortuneCell?>> getCellsByRange(FortuneRange range) {
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      return const [];
    }
    return [
      for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1)
        [
          for (
            var column = normalized.columnStart;
            column <= normalized.columnEnd;
            column += 1
          )
            cells[FortuneCellCoord(row, column)]?.copyWith(),
        ],
    ];
  }

  String getHtmlByRange(Object range) {
    final ranges = _apiRangesFrom(range);
    final rowIndexes = <int>[];
    final columnIndexes = <int>[];
    for (final currentRange in ranges) {
      final normalized = _normalizedApiRange(currentRange);
      if (normalized == null) {
        continue;
      }
      for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
        if (!rowIndexes.contains(row)) {
          rowIndexes.add(row);
        }
        for (
          var column = normalized.columnStart;
          column <= normalized.columnEnd;
          column += 1
        ) {
          if (!columnIndexes.contains(column)) {
            columnIndexes.add(column);
          }
        }
      }
    }

    final bordersByCell = FortuneBorderCompute.compute(this);

    final colgroup = StringBuffer();
    for (final column in columnIndexes) {
      final width = columnWidths[column] ?? 72;
      colgroup.write('<colgroup width="${_apiCssNumber(width)}px"></colgroup>');
    }

    final rows = StringBuffer();
    for (final row in rowIndexes) {
      rows.write('<tr>');
      for (final column in columnIndexes) {
        final coord = FortuneCellCoord(row, column);
        final anchor = _apiMergeAnchorInCells(cells, coord);
        if (anchor != coord) {
          continue;
        }
        final cell = cells[coord];
        final style = StringBuffer();
        if (column == columnIndexes.first) {
          final height = rowHeights[row] ?? 19;
          style.write('height:${_apiCssNumber(height)}px;');
        }
        if (cell != null) {
          style.write(_apiHtmlStyleForCell(cell));
        }
        final merge = cell?.merge;
        final borderStyles = _apiHtmlBorderStylesForCell(
          coord,
          merge,
          bordersByCell,
        );
        if (borderStyles.isNotEmpty) {
          style.write(borderStyles);
        }
        final span = merge == null
            ? ''
            : ' rowspan="${math.max(1, merge.rowSpan)}" colspan="${math.max(1, merge.columnSpan)}"';
        final value = cell == null
            ? ''
            : _escapeApiHtml(_apiHtmlCellValue(cell));
        rows.write('<td$span style="${style.toString()}">$value</td>');
      }
      rows.write('</tr>');
    }

    return '<table data-type="fortune-copy-action-table">'
        '${colgroup.toString()}${rows.toString()}</table>';
  }

  FortuneSheet setCellValuesByRange(List<List<Object?>> data, Object range) {
    if (range is Iterable) {
      throw const FortuneApiError(
        'setCellValuesByRange does not support multiple ranges',
      );
    }
    if (range is! FortuneRange) {
      throw INVALID_PARAMS;
    }
    final normalized = _normalizedApiRange(range);
    if (normalized == null) {
      return copyWith();
    }
    final rowCount = normalized.rowEnd - normalized.rowStart + 1;
    final columnCount = normalized.columnEnd - normalized.columnStart + 1;
    if (data.length != rowCount ||
        data.any((row) => row.length != columnCount)) {
      throw const FortuneApiError('data size does not match range');
    }
    var next = this;
    for (var rowOffset = 0; rowOffset < rowCount; rowOffset += 1) {
      for (
        var columnOffset = 0;
        columnOffset < columnCount;
        columnOffset += 1
      ) {
        final row = normalized.rowStart + rowOffset;
        final column = normalized.columnStart + columnOffset;
        next = _apiSheetWithFunctionGroupCleanupAfterValueSet(
          next,
          next.setCellValue(row, column, data[rowOffset][columnOffset]),
          row,
          column,
        );
      }
    }
    return next;
  }

  FortuneSheet setCellFormatByRange(String attr, Object? value, Object range) {
    if (range is! FortuneRange && range is! Iterable<FortuneRange>) {
      throw INVALID_PARAMS;
    }
    var next = this;
    for (final coord in getFlattenRange(_apiRangesFrom(range))) {
      next = next.setCellFormat(coord.row, coord.column, attr, value);
    }
    return next;
  }

  List<FortuneRange> getSelection() {
    return [for (final range in _selectionRangesFrom(selectionSave)) range];
  }

  List<String> getSelectionCoordinates() {
    return [for (final range in getSelection()) _apiRangeText(range)];
  }

  FortuneSheet setSelection(Iterable<FortuneRange> ranges) {
    return copyWith(
      selectionSave: [
        for (final range in ranges) _selectionRangeToApiMap(range),
      ],
    );
  }

  Map<int, double> getRowHeights(
    Iterable<int> rows, {
    FortuneSettings settings = const FortuneSettings(),
  }) {
    final rowList = rows.toList();
    if (rowList.isEmpty) {
      throw INVALID_PARAMS;
    }
    final fallback = defaultRowHeight ?? settings.defaultRowHeight;
    return {
      for (final row in rowList)
        if (row >= 0) row: _apiSizeOrFallback(rowHeights[row], fallback),
    };
  }

  Map<int, double> getColumnWidths(
    Iterable<int> columns, {
    FortuneSettings settings = const FortuneSettings(),
  }) {
    final columnList = columns.toList();
    if (columnList.isEmpty) {
      throw INVALID_PARAMS;
    }
    final fallback = defaultColWidth ?? settings.defaultColWidth;
    return {
      for (final column in columnList)
        if (column >= 0)
          column: _apiSizeOrFallback(columnWidths[column], fallback),
    };
  }

  FortuneSheet setRowHeight(Map<int, double> rowInfo, {bool custom = false}) {
    final nextRowHeights = Map<int, double>.from(rowHeights);
    final nextCustomHeight = Map<int, double>.from(customHeight);
    for (final entry in rowInfo.entries) {
      if (entry.key < 0 || entry.value < 0 || !entry.value.isFinite) {
        continue;
      }
      nextRowHeights[entry.key] = entry.value;
      if (custom) {
        nextCustomHeight[entry.key] = 1;
      }
    }
    return copyWith(rowHeights: nextRowHeights, customHeight: nextCustomHeight);
  }

  FortuneSheet setColumnWidth(
    Map<int, double> columnInfo, {
    bool custom = false,
  }) {
    final nextColumnWidths = Map<int, double>.from(columnWidths);
    final nextCustomWidth = Map<int, double>.from(customWidth);
    for (final entry in columnInfo.entries) {
      if (entry.key < 0 || entry.value < 0 || !entry.value.isFinite) {
        continue;
      }
      nextColumnWidths[entry.key] = entry.value;
      if (custom) {
        nextCustomWidth[entry.key] = 1;
      }
    }
    return copyWith(
      columnWidths: nextColumnWidths,
      customWidth: nextCustomWidth,
    );
  }

  FortuneSheet hideRowOrColumn(Iterable<int> rowColInfo, String type) {
    if (type != 'row' && type != 'column') {
      throw INVALID_PARAMS;
    }
    switch (type) {
      case 'row':
        final nextHiddenRows = Set<int>.from(hiddenRows);
        final nextHiddenRowValues = Map<int, Object?>.from(hiddenRowValues);
        for (final row in rowColInfo) {
          if (row < 0) {
            continue;
          }
          nextHiddenRows.add(row);
          nextHiddenRowValues[row] = 0;
        }
        return copyWith(
          hiddenRows: nextHiddenRows,
          hiddenRowValues: nextHiddenRowValues,
        );
      case 'column':
        final nextHiddenColumns = Set<int>.from(hiddenColumns);
        final nextHiddenColumnValues = Map<int, Object?>.from(
          hiddenColumnValues,
        );
        for (final column in rowColInfo) {
          if (column < 0) {
            continue;
          }
          nextHiddenColumns.add(column);
          nextHiddenColumnValues[column] = 0;
        }
        return copyWith(
          hiddenColumns: nextHiddenColumns,
          hiddenColumnValues: nextHiddenColumnValues,
        );
      default:
        throw INVALID_PARAMS;
    }
  }

  FortuneSheet showRowOrColumn(Iterable<int> rowColInfo, String type) {
    if (type != 'row' && type != 'column') {
      throw INVALID_PARAMS;
    }
    switch (type) {
      case 'row':
        final nextHiddenRows = Set<int>.from(hiddenRows);
        final nextHiddenRowValues = Map<int, Object?>.from(hiddenRowValues);
        for (final row in rowColInfo) {
          nextHiddenRows.remove(row);
          nextHiddenRowValues.remove(row);
        }
        return copyWith(
          hiddenRows: nextHiddenRows,
          hiddenRowValues: nextHiddenRowValues,
        );
      case 'column':
        final nextHiddenColumns = Set<int>.from(hiddenColumns);
        final nextHiddenColumnValues = Map<int, Object?>.from(
          hiddenColumnValues,
        );
        for (final column in rowColInfo) {
          nextHiddenColumns.remove(column);
          nextHiddenColumnValues.remove(column);
        }
        return copyWith(
          hiddenColumns: nextHiddenColumns,
          hiddenColumnValues: nextHiddenColumnValues,
        );
      default:
        throw INVALID_PARAMS;
    }
  }

  FortuneSheet insertRowOrColumn(
