Map<FortuneCellCoord, FortuneCell> _rewriteApiCellFormulas(
  Map<FortuneCellCoord, FortuneCell> cells, {
  required String type,
  required String operation,
  required int index,
  required int count,
  required String direction,
}) {
  var changed = false;
  final result = <FortuneCellCoord, FortuneCell>{};
  for (final entry in cells.entries) {
    final formula = entry.value.formula;
    if (formula == null || !formula.startsWith('=')) {
      result[entry.key] = entry.value.copyWith();
      continue;
    }
    final nextFormula = operation == 'insert'
        ? rewriteFormulaReferencesForInsert(
            formula,
            type: type,
            index: index,
            count: count,
            direction: direction,
          )
        : rewriteFormulaReferencesForDelete(
            formula,
            type: type,
            start: index,
            end: index + count - 1,
          );
    changed = changed || nextFormula != formula;
    result[entry.key] = nextFormula == formula
        ? entry.value.copyWith()
        : entry.value.copyWith(
            formula: nextFormula,
            rawFormula: entry.value.hasRawFormula ? nextFormula : _sentinel,
            hasRawFormula: entry.value.hasRawFormula,
          );
  }
  return changed ? result : cells;
}

