FortuneCell _cellWithApiValueMap(FortuneCell current, Map value) {
  var next = current;
  MapEntry<Object?, Object?>? deferredCellType;
  for (final entry in value.entries) {
    final key = entry.key.toString();
    if (key == 'ct' && value.containsKey('v')) {
      deferredCellType = MapEntry(entry.key, entry.value);
      continue;
    }
    next = _cellWithApiFormat(next, key, entry.value);
    if (key == 'v' && deferredCellType != null) {
      next = _cellWithApiFormat(next, 'ct', deferredCellType.value);
      deferredCellType = null;
    }
  }
  if (deferredCellType != null) {
    next = _cellWithApiFormat(next, 'ct', deferredCellType.value);
  }
  return next;
}

FortuneCell _cellWithPlainSetValue(FortuneCell current, Object? value) {
  if (current.cellType?.format == '@') {
    final text = value.toString();
    return current.copyWith(
      value: text,
      rawValue: cloneFortuneMetadata(value),
      hasRawValue: true,
      displayValue: text,
      rawDisplayValue: text,
      hasRawDisplayValue: true,
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      sparkline: null,
      rawSparkline: null,
      hasSparkline: false,
      hasRawSparkline: false,
    );
  }
  final generated = _apiPlainSetValueGenerated(value);
  if (generated != null) {
    final typedBase = current.copyWith(
      formula: null,
      rawFormula: null,
      hasRawFormula: false,
      sparkline: null,
      rawSparkline: null,
      hasSparkline: false,
      hasRawSparkline: false,
    );
    return _cellWithApiValueMap(typedBase, {
      'v': generated[2],
      'ct': generated[1],
      'm': generated[0],
    });
  }
  return current.copyWith(
    value: value.toString(),
    rawValue: cloneFortuneMetadata(value),
    hasRawValue: true,
    displayValue: null,
    rawDisplayValue: null,
    hasRawDisplayValue: false,
    formula: null,
    rawFormula: null,
    hasRawFormula: false,
    sparkline: null,
    rawSparkline: null,
    hasSparkline: false,
    hasRawSparkline: false,
  );
}

List<Object?>? _apiPlainSetValueGenerated(Object? value) {
  if (value == null) {
    return null;
  }
  final text = value.toString();
  final upper = text.toUpperCase();
  final isBooleanLiteral = upper == 'TRUE' || upper == 'FALSE';
  final isPercentLiteral = _apiGeneratePercent(text) != null;
  final isDateLiteral = _apiGenerateDatePayload(text) != null;
  final isNumericLiteral =
      isRealNum(text) ||
      (text.contains(',') &&
          _apiGenerateNumericValue(text) != null &&
          _apiGenerateHasValidThousands(text.split('.').first));
  if (!isBooleanLiteral &&
      !isPercentLiteral &&
      !isDateLiteral &&
      !isNumericLiteral &&
      !valueIsError(text)) {
    return null;
  }
  return genarate(value);
}

