FortuneRange? _normalizedApiRange(FortuneRange range) {
  final rowStart = math.min(range.rowStart, range.rowEnd);
  final rowEnd = math.max(range.rowStart, range.rowEnd);
  final columnStart = math.min(range.columnStart, range.columnEnd);
  final columnEnd = math.max(range.columnStart, range.columnEnd);
  if (rowEnd < 0 || columnEnd < 0) {
    return null;
  }
  return FortuneRange(
    rowStart: math.max(0, rowStart),
    rowEnd: math.max(0, rowEnd),
    columnStart: math.max(0, columnStart),
    columnEnd: math.max(0, columnEnd),
  );
}

Iterable<FortuneRange> _apiRangesFrom(Object range) {
  if (range is FortuneRange) {
    return [range];
  }
  if (range is Iterable<FortuneRange>) {
    return range;
  }
  return const [];
}

List<FortuneRange> _selectionRangesFrom(Object? raw) {
