    for (final item in raw.whereType<Map>()) ?_selectionRangeFromApiMap(item),
  ];
}

FortuneRange? _selectionRangeFromApiMap(Map raw) {
  final row = raw['row'];
  final column = raw['column'];
  if (row is! List || column is! List || row.length < 2 || column.length < 2) {
    return null;
  }
  final rowStart = _nullableIntArg(row[0]);
  final rowEnd = _nullableIntArg(row[1]);
  final columnStart = _nullableIntArg(column[0]);
  final columnEnd = _nullableIntArg(column[1]);
  if (rowStart == null ||
      rowEnd == null ||
      columnStart == null ||
      columnEnd == null) {
    return null;
  }
  const handled = {'row', 'column', 'row_focus', 'column_focus'};
  return FortuneRange(
    rowStart: rowStart,
    rowEnd: rowEnd,
    rawRow: cloneFortuneMetadata(row),
    hasRawRow: true,
    columnStart: columnStart,
    columnEnd: columnEnd,
    rawColumn: cloneFortuneMetadata(column),
    hasRawColumn: true,
    rowFocus: _nullableIntArg(raw['row_focus']),
    rawRowFocus: cloneFortuneMetadata(raw['row_focus']),
    hasRawRowFocus: raw.containsKey('row_focus'),
    columnFocus: _nullableIntArg(raw['column_focus']),
    rawColumnFocus: cloneFortuneMetadata(raw['column_focus']),
    hasRawColumnFocus: raw.containsKey('column_focus'),
    extraFields: {
      for (final entry in raw.entries)
        if (!handled.contains(entry.key))
          entry.key.toString(): cloneFortuneMetadata(entry.value),
    },
  );
}

Map<String, Object?> _selectionRangeToApiMap(FortuneRange range) {
  return {
    for (final entry in range.extraFields.entries)
      entry.key: cloneFortuneMetadata(entry.value),
    'row': [range.rowStart, range.rowEnd],
    'column': [range.columnStart, range.columnEnd],
    if (range.rowFocus != null) 'row_focus': range.rowFocus,
    if (range.columnFocus != null) 'column_focus': range.columnFocus,
  };
}

String _apiRangeText(FortuneRange range) {
  final start = '${_apiColumnName(range.columnStart)}${range.rowStart + 1}';
  final end = '${_apiColumnName(range.columnEnd)}${range.rowEnd + 1}';
  return start == end ? start : '$start:$end';
}

String _apiColumnName(int index) {
  var value = math.max(0, index) + 1;
  final chars = <String>[];
  while (value > 0) {
    final remainder = (value - 1) % 26;
    chars.insert(0, String.fromCharCode(65 + remainder));
    value = (value - 1) ~/ 26;
  }
  return chars.join();
}

String _apiCssNumber(num value) {
  return value == value.roundToDouble() ? value.toInt().toString() : '$value';
}

String _apiHtmlStyleForCell(FortuneCell cell) {
  final style = StringBuffer();
  final background = cell.background == null
      ? null
      : _apiHtmlNormalizedColor(
          cell.hasRawBackground ? cell.rawBackground : null,
          cell.background!,
          null,
        );
  if (background != null) {
    style.write('background-color:$background;');
  }
  if (cell.inlineRuns == null) {
    final foreground = _apiHtmlNormalizedColor(
      cell.hasRawForeground ? cell.rawForeground : null,
      cell.foreground,
      '#000000',
    )!;
    if (foreground != '#000000') {
      style.write('color:$foreground;');
    }
    if (cell.bold) {
      style.write('font-weight:bold;');
    }
    if (cell.italic) {
      style.write('font-style:italic;');
    }
    if (cell.strikeThrough) {
      style.write('text-decoration:line-through;');
    }
    if (cell.underline) {
      final fontSize = cell.fontSize ?? 10;
      final underlineWidth = fontSize ~/ 9;
      style.write(
        'border-bottom:${_apiCssNumber(underlineWidth)}px solid '
        '$foreground;',
      );
    }
    if (cell.fontSize != null && cell.fontSize != 10) {
      style.write('font-size:${_apiCssNumber(cell.fontSize!)}pt;');
    }
  }
  final textAlign = _apiHtmlTextAlign(cell.horizontalAlign);
  if (textAlign != null) {
    style.write('text-align:$textAlign;');
  }
  final alignItems = _apiHtmlAlignItems(cell.verticalAlign);
  if (alignItems != null) {
    style.write('align-items:$alignItems;');
  }
  return style.toString();
}

Object? _apiHtmlCellValue(FortuneCell cell) {
  final format = cell.cellType?.format;
  if (format != null && RegExp(r'^(w|W)((0?)|(0\.0+))$').hasMatch(format)) {
    return cell.hasRawValue ? cell.rawValue : cell.value;
  }
  if (cell.hasRawDisplayValue) {
    return cell.rawDisplayValue;
  }
  return cell.displayValue ?? (cell.hasRawValue ? cell.rawValue : cell.value);
}

String? _apiHtmlNormalizedColor(
  Object? rawValue,
  Color color,
  String? fallback,
) {
  final value = rawValue ?? _apiCssColor(color);
  return _apiNormalizeColorAttr(value, fallback)?.toString();
}

String? _apiHtmlTextAlign(String? value) {
  return switch (value) {
    '0' || 'center' => 'center',
    '2' || 'right' => 'right',
    _ => null,
  };
}

String? _apiHtmlAlignItems(String? value) {
  return switch (value) {
    '0' || 'center' || 'middle' => 'center',
    '2' || 'bottom' || 'flex-end' => 'flex-end',
    _ => null,
  };
}

String _apiHtmlBorderStyles(FortuneCellBorders borders) {
  final style = StringBuffer();
  if (borders.left != null) {
    style.write('border-left:${_apiHtmlBorderStyle(borders.left!)}');
  }
  if (borders.right != null) {
    style.write('border-right:${_apiHtmlBorderStyle(borders.right!)}');
  }
  if (borders.top != null) {
    style.write('border-top:${_apiHtmlBorderStyle(borders.top!)}');
  }
  if (borders.bottom != null) {
    style.write('border-bottom:${_apiHtmlBorderStyle(borders.bottom!)}');
  }
  return style.toString();
}

String _apiHtmlBorderStylesForCell(
  FortuneCellCoord coord,
  FortuneCellMerge? merge,
  Map<FortuneCellCoord, FortuneCellBorders> bordersByCell,
) {
  if (merge == null || merge.rowSpan <= 1 && merge.columnSpan <= 1) {
    final borders = bordersByCell[coord];
    return borders == null ? '' : _apiHtmlBorderStyles(borders);
  }
  final rowSpan = merge.rowSpan < 1 ? 1 : merge.rowSpan;
  final columnSpan = merge.columnSpan < 1 ? 1 : merge.columnSpan;
  final rowEnd = coord.row + rowSpan - 1;
  final columnEnd = coord.column + columnSpan - 1;
  final style = StringBuffer();
  final left = _apiHtmlMergedBorderSide([
    for (var row = coord.row; row <= rowEnd; row += 1)
      bordersByCell[FortuneCellCoord(row, coord.column)]?.left,
  ], rowSpan);
  final right = _apiHtmlMergedBorderSide([
    for (var row = coord.row; row <= rowEnd; row += 1)
      bordersByCell[FortuneCellCoord(row, columnEnd)]?.right,
  ], rowSpan);
  final top = _apiHtmlMergedBorderSide([
    for (var column = coord.column; column <= columnEnd; column += 1)
      bordersByCell[FortuneCellCoord(coord.row, column)]?.top,
  ], columnSpan);
  final bottom = _apiHtmlMergedBorderSide([
    for (var column = coord.column; column <= columnEnd; column += 1)
      bordersByCell[FortuneCellCoord(rowEnd, column)]?.bottom,
  ], columnSpan);
  if (left != null) {
    style.write('border-left:${_apiHtmlBorderStyle(left)}');
  }
  if (right != null) {
    style.write('border-right:${_apiHtmlBorderStyle(right)}');
  }
  if (top != null) {
    style.write('border-top:${_apiHtmlBorderStyle(top)}');
  }
  if (bottom != null) {
    style.write('border-bottom:${_apiHtmlBorderStyle(bottom)}');
  }
  return style.toString();
}

FortuneBorderSide? _apiHtmlMergedBorderSide(
  List<FortuneBorderSide?> sides,
  int length,
) {
  final sideCounts = <String, ({FortuneBorderSide side, int count})>{};
  for (final side in sides.whereType<FortuneBorderSide>()) {
    final key = '${side.style}:${_apiCssColor(side.color)}';
    final current = sideCounts[key];
    sideCounts[key] = (side: side, count: (current?.count ?? 0) + 1);
  }
  for (final entry in sideCounts.values) {
    if (entry.count >= length / 2) {
      return entry.side;
    }
  }
  return null;
}

String _apiHtmlBorderStyle(FortuneBorderSide side) {
  final borderType = switch (side.style) {
    0 => 'none',
    1 => 'Thin',
    2 => 'Hair',
    3 => 'Dotted',
    4 => 'Dashed',
    5 => 'DashDot',
    6 => 'DashDotDot',
    7 => 'Double',
    8 => 'Medium',
    9 => 'MediumDashed',
    10 => 'MediumDashDot',
    11 => 'MediumDashDotDot',
    12 => 'SlantedDashDot',
    13 => 'Thick',
    _ => 'Thin',
  };
  final width = borderType.contains('Medium')
      ? '1pt '
      : borderType == 'Thick'
      ? '1.5pt '
      : '0.5pt ';
  final lineStyle = borderType == 'Hair'
      ? 'double '
      : borderType.contains('DashDotDot') || borderType.contains('Dotted')
      ? 'dotted '
      : borderType.contains('DashDot') || borderType.contains('Dashed')
      ? 'dashed '
      : 'solid ';
  return '$width$lineStyle${_apiCssColor(side.color)};';
}

String _apiCssColor(Color color) {
  final value = color.toARGB32();
  final alpha = (value >> 24) & 0xff;
  final red = (value >> 16) & 0xff;
  final green = (value >> 8) & 0xff;
  final blue = value & 0xff;
  if (alpha == 255) {
    return '#${red.toRadixString(16).padLeft(2, '0')}'
        '${green.toRadixString(16).padLeft(2, '0')}'
        '${blue.toRadixString(16).padLeft(2, '0')}';
  }
  final opacity = (alpha / 255)
      .toStringAsFixed(3)
      .replaceFirst(RegExp(r'0+$'), '')
      .replaceFirst(RegExp(r'\.$'), '');
  return 'rgba($red,$green,$blue,$opacity)';
}

String _escapeApiHtml(Object? value) {
  return (value?.toString() ?? '')
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll('>', '&gt;')
      .replaceAll('"', '&quot;')
      .replaceAll("'", '&#39;');
}

Map<FortuneCellCoord, FortuneCell> _insertApiCellRows(
  Map<FortuneCellCoord, FortuneCell> cells,
  int index,
  int insertAt,
  int count,
  String direction,
) {
  final shifted = <FortuneCellCoord, FortuneCell>{};
  for (final entry in cells.entries) {
    final nextCoord = FortuneCellCoord(
      entry.key.row >= insertAt ? entry.key.row + count : entry.key.row,
      entry.key.column,
    );
    var nextCell = _shiftApiCellMetadata(
      entry.value,
      rowFrom: insertAt,
      rowDelta: count,
    );
    final merge = nextCell.merge;
    if (_apiCellOwnsMerge(nextCoord, merge) &&
        _apiMergeExpandsOnInsert(
          start: merge!.row,
          span: merge.rowSpan,
          index: index,
          direction: direction,
        )) {
      nextCell = nextCell.copyWith(
        merge: merge.copyWith(
          rowSpan: merge.rowSpan + count,
          rawRowSpan: null,
          hasRawRowSpan: false,
        ),
      );
    }
    shifted[nextCoord] = nextCell;
  }
  _ensureApiMergeCoveredCells(shifted);
  return shifted;
}

Map<FortuneCellCoord, FortuneCell> _insertApiCellColumns(
  Map<FortuneCellCoord, FortuneCell> cells,
  int index,
  int insertAt,
  int count,
  String direction,
) {
  final shifted = <FortuneCellCoord, FortuneCell>{};
  for (final entry in cells.entries) {
    final nextCoord = FortuneCellCoord(
      entry.key.row,
      entry.key.column >= insertAt
          ? entry.key.column + count
          : entry.key.column,
    );
    var nextCell = _shiftApiCellMetadata(
      entry.value,
      columnFrom: insertAt,
      columnDelta: count,
    );
    final merge = nextCell.merge;
    if (_apiCellOwnsMerge(nextCoord, merge) &&
        _apiMergeExpandsOnInsert(
          start: merge!.column,
          span: merge.columnSpan,
          index: index,
          direction: direction,
        )) {
      nextCell = nextCell.copyWith(
        merge: merge.copyWith(
          columnSpan: merge.columnSpan + count,
          rawColumnSpan: null,
          hasRawColumnSpan: false,
        ),
      );
    }
    shifted[nextCoord] = nextCell;
  }
  _ensureApiMergeCoveredCells(shifted);
  return shifted;
}

bool _apiCellOwnsMerge(FortuneCellCoord coord, FortuneCellMerge? merge) {
  return merge != null &&
      merge.row == coord.row &&
      merge.column == coord.column;
}

bool _apiMergeExpandsOnInsert({
  required int start,
  required int span,
  required int index,
  required String direction,
}) {
  final end = start + math.max(1, span) - 1;
  if (index < start || index > end) {
    return false;
  }
  if (index == start) {
    return direction != 'lefttop';
  }
  if (index == end) {
    return direction == 'lefttop';
  }
  return true;
}

void _ensureApiMergeCoveredCells(Map<FortuneCellCoord, FortuneCell> cells) {
  final anchors = [
    for (final entry in cells.entries)
      if (_apiCellOwnsMerge(entry.key, entry.value.merge)) entry,
  ];
  for (final entry in anchors) {
    final merge = entry.value.merge!;
    final rowSpan = math.max(1, merge.rowSpan);
    final columnSpan = math.max(1, merge.columnSpan);
    if (rowSpan <= 1 && columnSpan <= 1) {
      continue;
    }
    for (var row = merge.row; row < merge.row + rowSpan; row += 1) {
      for (
        var column = merge.column;
        column < merge.column + columnSpan;
        column += 1
      ) {
        final coord = FortuneCellCoord(row, column);
        if (coord == entry.key) {
          continue;
        }
        cells[coord] = (cells[coord] ?? const FortuneCell()).copyWith(
          merge: FortuneCellMerge(row: merge.row, column: merge.column),
        );
      }
    }
  }
}

FortuneCell _shiftApiCellMetadata(
  FortuneCell cell, {
  int? rowFrom,
  int rowDelta = 0,
  int? columnFrom,
  int columnDelta = 0,
}) {
  final merge = cell.merge;
  if (merge == null) {
    return cell.copyWith();
  }
  final nextRow = rowFrom != null && merge.row >= rowFrom
      ? merge.row + rowDelta
      : merge.row;
  final nextColumn = columnFrom != null && merge.column >= columnFrom
      ? merge.column + columnDelta
      : merge.column;
  return cell.copyWith(
    merge: merge.copyWith(
      row: nextRow,
      rawRow: nextRow == merge.row ? merge.rawRow : null,
      hasRawRow: nextRow == merge.row ? merge.hasRawRow : false,
      column: nextColumn,
      rawColumn: nextColumn == merge.column ? merge.rawColumn : null,
      hasRawColumn: nextColumn == merge.column ? merge.hasRawColumn : false,
    ),
  );
}

Set<FortuneCellCoord> _shiftApiCoordRows(
  Set<FortuneCellCoord> coords,
  int from,
  int delta,
) {
  return {
    for (final coord in coords)
      FortuneCellCoord(
        coord.row >= from ? coord.row + delta : coord.row,
        coord.column,
      ),
  };
}

Set<FortuneCellCoord> _shiftApiCoordColumns(
  Set<FortuneCellCoord> coords,
  int from,
  int delta,
) {
  return {
    for (final coord in coords)
      FortuneCellCoord(
        coord.row,
        coord.column >= from ? coord.column + delta : coord.column,
      ),
  };
}

Map<int, double> _shiftApiIntDoubleMap(
  Map<int, double> values,
  int from,
  int delta,
) {
  return {
    for (final entry in values.entries)
      entry.key >= from ? entry.key + delta : entry.key: entry.value,
  };
}

Set<int> _shiftApiIntSet(Set<int> values, int from, int delta) {
  return {for (final value in values) value >= from ? value + delta : value};
}

Map<int, Object?> _shiftApiIntObjectMap(
  Map<int, Object?> values,
  int from,
  int delta,
) {
  return {
    for (final entry in values.entries)
      entry.key >= from ? entry.key + delta : entry.key: cloneFortuneMetadata(
        entry.value,
      ),
  };
}

Object? _shiftApiRawIntKeyMap(Object? raw, int from, int delta) {
  if (raw is! Map) {
    return cloneFortuneMetadata(raw);
  }
  return {
    for (final entry in raw.entries)
      '${_shiftApiRawIntKey(entry.key, from, delta)}': cloneFortuneMetadata(
        entry.value,
      ),
  };
}

Object _shiftApiRawIntKey(Object rawKey, int from, int delta) {
  final key = int.tryParse('$rawKey');
  if (key == null) {
    return rawKey;
  }
  return key >= from ? key + delta : key;
}

Object? _insertApiRawMergeConfig(
  Object? raw, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  if (raw is! Map) {
    return cloneFortuneMetadata(raw);
  }
  final next = <String, Object?>{};
  for (final entry in raw.entries) {
    final config = entry.value;
    if (config is! Map) {
      next[entry.key.toString()] = cloneFortuneMetadata(config);
      continue;
    }
    final shifted = _insertApiRawMergeItem(
      config,
      type: type,
      index: index,
      count: count,
      direction: direction,
    );
    next[_apiRawMergeKey(shifted, entry.key)] = shifted;
  }
  return next;
}

Map<Object?, Object?> _insertApiRawMergeItem(
  Map raw, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  final next = _cloneObjectMap(raw);
  final row = _nullableIntArg(raw['r']);
  final column = _nullableIntArg(raw['c']);
  final rowSpan = math.max(1, _nullableIntArg(raw['rs']) ?? 1);
  final columnSpan = math.max(1, _nullableIntArg(raw['cs']) ?? 1);
  if (row == null || column == null) {
    return next;
  }
  if (type == 'row') {
    final insertAt = direction == 'lefttop' ? index : index + 1;
    final nextRow = row >= insertAt ? row + count : row;
    if (nextRow != row) {
      next['r'] = nextRow;
    }
    if (_apiMergeExpandsOnInsert(
      start: row,
      span: rowSpan,
      index: index,
      direction: direction,
    )) {
      next['rs'] = rowSpan + count;
    }
  } else {
    final insertAt = direction == 'lefttop' ? index : index + 1;
    final nextColumn = column >= insertAt ? column + count : column;
    if (nextColumn != column) {
      next['c'] = nextColumn;
    }
    if (_apiMergeExpandsOnInsert(
      start: column,
      span: columnSpan,
      index: index,
      direction: direction,
    )) {
      next['cs'] = columnSpan + count;
    }
  }
  return next;
}

String _apiRawMergeKey(Map raw, Object? fallbackKey) {
  final row = _nullableIntArg(raw['r']);
  final column = _nullableIntArg(raw['c']);
  if (row == null || column == null) {
    return fallbackKey.toString();
  }
  return '${row}_$column';
}

Map<String, Object?> _insertApiCoordKeyMap(
  Map<String, Object?> values, {
  required String type,
  required int index,
  required int count,
  required String direction,
  required bool duplicateAtIndex,
}) {
  final shifted = <String, Object?>{};
  for (final entry in values.entries) {
    final coord = _apiCoordFromKey(entry.key);
    if (coord == null) {
      shifted[entry.key] = cloneFortuneMetadata(entry.value);
      continue;
    }
    void put(int row, int column) {
      shifted['${row}_$column'] = cloneFortuneMetadata(entry.value);
    }

    if (type == 'row') {
      final row = coord.row;
      final column = coord.column;
      if (index < row) {
        put(row + count, column);
      } else if (index == row) {
        if (direction == 'lefttop') {
          put(row + count, column);
          if (duplicateAtIndex) {
            for (var offset = 0; offset < count; offset += 1) {
              put(row + offset, column);
            }
          }
        } else {
          put(row, column);
          if (duplicateAtIndex) {
            for (var offset = 0; offset < count; offset += 1) {
              put(row + offset + 1, column);
            }
          }
        }
      } else {
        put(row, column);
      }
    } else {
      final row = coord.row;
      final column = coord.column;
      if (index < column) {
        put(row, column + count);
      } else if (index == column) {
        if (direction == 'lefttop') {
          put(row, column + count);
          if (duplicateAtIndex) {
            for (var offset = 0; offset < count; offset += 1) {
              put(row, column + offset);
            }
          }
        } else {
          put(row, column);
          if (duplicateAtIndex) {
            for (var offset = 0; offset < count; offset += 1) {
              put(row, column + offset + 1);
            }
          }
        }
      } else {
        put(row, column);
      }
    }
  }
  return shifted;
}

Object? _insertApiRawCoordKeyMap(
  Object? raw, {
  required String type,
  required int index,
  required int count,
  required String direction,
  required bool duplicateAtIndex,
}) {
  if (raw is! Map) {
    return cloneFortuneMetadata(raw);
  }
  return _insertApiCoordKeyMap(
    _stringObjectMap(raw),
    type: type,
    index: index,
    count: count,
    direction: direction,
    duplicateAtIndex: duplicateAtIndex,
  );
}

Object? _insertApiCalcChain(
  Object? raw, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  if (raw is! List) {
    return cloneFortuneMetadata(raw);
  }
  return [
    for (final item in raw)
      if (item is Map)
        _insertApiCalcChainItem(
          item,
          type: type,
          index: index,
          count: count,
          direction: direction,
        )
      else
        cloneFortuneMetadata(item),
  ];
}

Map<Object?, Object?> _insertApiCalcChainItem(
  Map item, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  final next = <Object?, Object?>{
    for (final entry in item.entries)
      entry.key: cloneFortuneMetadata(entry.value),
  };
  if (type == 'row') {
    final row = _nullableIntArg(next['r']);
    if (row != null && _apiShouldShiftInsertIndex(row, index, direction)) {
      next['r'] = row + count;
    }
  } else {
    final column = _nullableIntArg(next['c']);
    if (column != null &&
        _apiShouldShiftInsertIndex(column, index, direction)) {
      next['c'] = column + count;
    }
  }
  return next;
}

bool _apiShouldShiftInsertIndex(int value, int index, String direction) {
  return direction == 'lefttop' ? value >= index : value > index;
}

({int start, int end})? _apiDeleteBoundsForSheet(
  FortuneSheet sheet,
  String type,
  int start,
  int end,
) {
  final maxIndex = switch (type) {
    'row' => sheet.rowCount == null ? null : math.max(0, sheet.rowCount! - 1),
    'column' =>
      sheet.columnCount == null ? null : math.max(0, sheet.columnCount! - 1),
    _ => null,
  };
  var deleteStart = math.max(0, math.min(start, end));
  var deleteEnd = math.max(0, math.max(start, end));
  if (maxIndex != null) {
    deleteStart = math.min(deleteStart, maxIndex);
    deleteEnd = math.min(deleteEnd, maxIndex);
  }
  if (deleteStart > deleteEnd) {
    return null;
  }
  return (start: deleteStart, end: deleteEnd);
}

Object _insertApiSelection(
  FortuneSheet sheet, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  final start = direction == 'lefttop' ? index : index + 1;
  final end = start + count - 1;
  final range = type == 'row'
      ? FortuneRange(
          rowStart: start,
          rowEnd: end,
          columnStart: 0,
          columnEnd: _apiSelectionColumnEnd(sheet),
        )
      : FortuneRange(
          rowStart: 0,
          rowEnd: _apiSelectionRowEnd(sheet),
          columnStart: start,
          columnEnd: end,
        );
  return [_selectionRangeToApiMap(range)];
}

int _apiSelectionRowEnd(FortuneSheet sheet) {
  var maxRow = math.max(0, (sheet.rowCount ?? 1) - 1);
  for (final coord in sheet.cells.keys) {
    maxRow = math.max(maxRow, coord.row);
  }
  for (final coord in sheet.nullCells) {
    maxRow = math.max(maxRow, coord.row);
  }
  return maxRow;
}

int _apiSelectionColumnEnd(FortuneSheet sheet) {
  var maxColumn = math.max(0, (sheet.columnCount ?? 1) - 1);
  for (final coord in sheet.cells.keys) {
    maxColumn = math.max(maxColumn, coord.column);
  }
  for (final coord in sheet.nullCells) {
    maxColumn = math.max(maxColumn, coord.column);
  }
  return maxColumn;
}

