List<FortuneBorderInfo> _deleteApiBorderInfo(
  List<FortuneBorderInfo> items, {
  required String type,
  required int start,
  required int end,
}) {
  final next = <FortuneBorderInfo>[];
  for (final item in items) {
    final ranges = <FortuneRange>[];
    for (final range in item.ranges) {
      final nextRange = _deleteApiBorderRange(
        range,
        type: type,
        start: start,
        end: end,
      );
      if (nextRange != null) {
        ranges.add(nextRange);
      }
    }
    if (ranges.isNotEmpty) {
      next.add(item.copyWith(ranges: ranges));
    }
  }
  return next;
}

