Object? _insertApiRawBorderInfo(
  Object? raw, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  if (raw is! List) {
    return cloneFortuneMetadata(raw);
  }
  final next = <Object?>[];
  final cellCopies = <Map<Object?, Object?>>[];
  for (final item in raw) {
    if (item is! Map) {
      next.add(cloneFortuneMetadata(item));
      continue;
    }
    final map = Map<Object?, Object?>.from(item);
    final rangeType = _nullableStringArg(map['rangeType']);
    if (rangeType == 'range') {
      final ranges = _insertApiRawBorderRanges(
        map['range'],
        type: type,
        index: index,
        count: count,
        direction: direction,
      );
      if (ranges.isNotEmpty) {
        map['range'] = ranges;
        next.add(map);
      }
      continue;
    }
    if (rangeType == 'cell') {
      final value = map['value'];
      if (value is Map) {
        final valueMap = Map<Object?, Object?>.from(value);
        final key = type == 'row' ? 'row_index' : 'col_index';
        final coord = _nullableIntArg(valueMap[key]);
        if (coord != null) {
          if (coord == index) {
            cellCopies.add(Map<Object?, Object?>.from(map));
          }
          var nextCoord = coord;
          if (direction == 'lefttop') {
            if (index <= coord) {
              nextCoord += count;
            }
          } else if (index < coord) {
            nextCoord += count;
          }
          valueMap[key] = nextCoord;
          map['value'] = valueMap;
        }
      }
      next.add(map);
      continue;
    }
    next.add(map);
  }
  for (var offset = 0; offset < count; offset += 1) {
    for (final item in cellCopies) {
      final clone = cloneFortuneMetadata(item);
      if (clone is Map) {
        final value = clone['value'];
        if (value is Map) {
          final key = type == 'row' ? 'row_index' : 'col_index';
          final coord = _nullableIntArg(value[key]);
          if (coord != null) {
            value[key] = direction == 'lefttop'
                ? coord + offset
                : coord + offset + 1;
          }
        }
        next.add(clone);
      }
    }
  }
  return next;
}

List<Object?> _insertApiRawBorderRanges(
  Object? rawRanges, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  if (rawRanges is! List) {
    return const [];
  }
  final next = <Object?>[];
  for (final range in rawRanges) {
    if (range is! Map) {
      next.add(cloneFortuneMetadata(range));
      continue;
    }
    final map = Map<Object?, Object?>.from(range);
    final key = type == 'row' ? 'row' : 'column';
    final axis = _rawAxisPair(map[key]);
    if (axis == null) {
      next.add(map);
      continue;
    }
    final shifted = _insertApiFormatRangeAxis(
      axis,
      index: index,
      count: count,
      direction: direction,
    );
    map[key] = shifted;
    next.add(map);
  }
  return next;
}

Object? _deleteApiRawBorderInfo(
  Object? raw, {
  required String type,
  required int start,
  required int end,
}) {
  if (raw is! List) {
    return cloneFortuneMetadata(raw);
  }
  final next = <Object?>[];
  final count = end - start + 1;
  for (final item in raw) {
    if (item is! Map) {
      next.add(cloneFortuneMetadata(item));
      continue;
    }
    final map = Map<Object?, Object?>.from(item);
    final rangeType = _nullableStringArg(map['rangeType']);
    if (rangeType == 'range') {
      final ranges = _deleteApiRawBorderRanges(
        map['range'],
        type: type,
        start: start,
        end: end,
      );
      if (ranges.isNotEmpty) {
        map['range'] = ranges;
        next.add(map);
      }
      continue;
    }
    if (rangeType == 'cell') {
      final value = map['value'];
      if (value is Map) {
        final valueMap = Map<Object?, Object?>.from(value);
        final key = type == 'row' ? 'row_index' : 'col_index';
        final coord = _nullableIntArg(valueMap[key]);
        if (coord != null) {
          if (coord >= start && coord <= end) {
            continue;
          }
          if (coord > end) {
            valueMap[key] = coord - count;
          }
          map['value'] = valueMap;
        }
      }
      next.add(map);
      continue;
    }
    next.add(map);
  }
  return next;
}

List<Object?> _deleteApiRawBorderRanges(
  Object? rawRanges, {
  required String type,
  required int start,
  required int end,
}) {
  if (rawRanges is! List) {
    return const [];
  }
  final next = <Object?>[];
  for (final range in rawRanges) {
    if (range is! Map) {
      next.add(cloneFortuneMetadata(range));
      continue;
    }
    final map = Map<Object?, Object?>.from(range);
    final key = type == 'row' ? 'row' : 'column';
    final axis = _rawAxisPair(map[key]);
    if (axis == null) {
      next.add(map);
      continue;
    }
    final shifted = _deleteApiFormatRangeAxis(axis, start: start, end: end);
    if (shifted == null) {
      continue;
    }
    map[key] = shifted;
    next.add(map);
  }
  return next;
}

List<int>? _rawAxisPair(Object? raw) {
  if (raw is! List || raw.length < 2) {
    return null;
  }
  final start = _nullableIntArg(raw[0]);
  final end = _nullableIntArg(raw[1]);
  if (start == null || end == null) {
    return null;
  }
  return [start, end];
}

Object? _insertApiReadOnly(Object? raw, int index, int count) {
  if (raw is! Map) {
    return cloneFortuneMetadata(raw);
  }
  final next = <Object?, Object?>{};
  for (final entry in raw.entries) {
    final key = _nullableIntArg(entry.key);
    if (key == null) {
      next[entry.key] = cloneFortuneMetadata(entry.value);
    } else if (key < index) {
      next['$key'] = cloneFortuneMetadata(entry.value);
    } else if (key > index) {
      next['${key + count}'] = cloneFortuneMetadata(entry.value);
    }
  }
  return next;
}

Object? _deleteApiReadOnly(Object? raw, int start, int end) {
  if (raw is! Map) {
