Map<Object?, Object?> _insertApiFilterRowConfig(
  Map raw, {
  required int index,
  required int count,
  required String direction,
  required List<int>? rows,
}) {
  final next = _cloneObjectMap(raw);
  final rowhidden = raw['rowhidden'];
  if (rowhidden is Map) {
    next['rowhidden'] = {
      for (final entry in rowhidden.entries)
        if (_nullableIntArg(entry.key) case final hiddenRow?)
          '${_apiShouldShiftInsertIndex(hiddenRow, index, direction) ? hiddenRow + count : hiddenRow}':
              0,
    };
  }
  if (rows != null) {
    next['str'] = rows[0];
    next['edr'] = rows[1];
  }
  return next;
}

Map<String, Object?> _insertApiFilterColumns(
  Map<String, Object?> values, {
  required int index,
  required int count,
  required String direction,
  required Map filterSelect,
}) {
  final columns = _apiFormatRangeAxis(filterSelect['column']);
  final next = <String, Object?>{};
  for (final entry in values.entries) {
    final raw = entry.value;
    if (raw is! Map) {
      final keyIndex = _nullableIntArg(entry.key);
      final nextKey =
          keyIndex != null &&
              _apiShouldShiftInsertIndex(keyIndex, index, direction)
          ? '${keyIndex + count}'
          : entry.key;
      next[nextKey] = cloneFortuneMetadata(raw);
      continue;
    }
    final config = _cloneObjectMap(raw);
    var cindex = _nullableIntArg(config['cindex']);
    if (cindex != null &&
        _apiShouldShiftInsertIndex(cindex, index, direction)) {
      cindex += count;
      config['cindex'] = cindex;
    }
    if (columns != null) {
      config['stc'] = columns[0];
      config['edc'] = columns[1];
    }
    final key = cindex != null && columns != null
        ? '${cindex - columns[0]}'
        : entry.key;
    next[key] = config;
  }
  return next;
}

