Object? _insertApiSheetRangeMetadata(
  Object? raw, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  if (raw is List) {
    return [
      for (final item in raw)
        _insertApiSheetRangeMetadata(
          item,
          type: type,
          index: index,
          count: count,
          direction: direction,
        ),
    ];
  }
  if (raw is! Map) {
    return cloneFortuneMetadata(raw);
  }
  final next = _cloneObjectMap(raw);
  if (type == 'row') {
    final row = _apiFormatRangeAxis(raw['row']);
    if (row != null) {
      next['row'] = _insertApiFormatRangeAxis(
        row,
        index: index,
        count: count,
        direction: direction,
      );
    }
    final rowFocus = _insertApiIndex(raw['row_focus'], index, count, direction);
    if (rowFocus != null) {
      next['row_focus'] = rowFocus;
    }
    final r = _insertApiIndex(raw['r'], index, count, direction);
    if (r != null) {
      next['r'] = r;
    }
  } else {
    final column = _apiFormatRangeAxis(raw['column']);
    if (column != null) {
      next['column'] = _insertApiFormatRangeAxis(
        column,
        index: index,
        count: count,
        direction: direction,
      );
    }
    final columnFocus = _insertApiIndex(
      raw['column_focus'],
      index,
      count,
      direction,
    );
    if (columnFocus != null) {
      next['column_focus'] = columnFocus;
    }
    final c = _insertApiIndex(raw['c'], index, count, direction);
    if (c != null) {
      next['c'] = c;
    }
  }
  for (final entry in raw.entries) {
    if (_isApiRangeCoordinateKey(entry.key)) {
      continue;
    }
    final value = entry.value;
    if (value is List || value is Map) {
      next[entry.key] = _insertApiSheetRangeMetadata(
        value,
        type: type,
        index: index,
        count: count,
        direction: direction,
      );
    }
  }
  return next;
}

