List<int> _insertApiFormatRangeAxis(
  List<int> range, {
  required int index,
  required int count,
  required String direction,
}) {
  var start = range[0];
  var end = range[1];
  if (start < index) {
    if (end == index && direction == 'lefttop') {
      end += count;
    } else if (end > index) {
      end += count;
    }
  } else if (start == index) {
    if (direction == 'lefttop') {
      start += count;
      end += count;
    } else if (direction == 'rightbottom' && end > index) {
      end += count;
    }
  } else {
    start += count;
    end += count;
  }
  return [start, end];
}

List<int>? _apiFormatRangeAxis(Object? raw) {
  if (raw is! List || raw.length < 2) {
    return null;
  }
  final start = _nullableIntArg(raw[0]);
  final end = _nullableIntArg(raw[1]);
  if (start == null || end == null) {
    return null;
  }
  return [start, end];
}

Map<Object?, Object?> _cloneObjectMap(Map raw) {
  return {
    for (final entry in raw.entries)
      entry.key: cloneFortuneMetadata(entry.value),
  };
}

FortuneFrozenPane? _insertApiFrozenPane(
  FortuneFrozenPane? frozen, {
  required String type,
  required int index,
  required int count,
  required String direction,
}) {
  if (frozen == null) {
    return null;
  }
  final normalizedIndex = direction == 'lefttop' ? index - 1 : index;
  if (type == 'row' && frozen.freezesRows) {
    final rowFocus = frozen.rowFocus;
    if (rowFocus != null && rowFocus > normalizedIndex) {
      return frozen.copyWith(rowFocus: rowFocus + count);
    }
  }
  if (type == 'column' && frozen.freezesColumns) {
    final columnFocus = frozen.columnFocus;
    if (columnFocus != null && columnFocus > normalizedIndex) {
      return frozen.copyWith(columnFocus: columnFocus + count);
    }
  }
  return frozen.copyWith();
}

Map<String, Object?> _deleteApiCoordKeyMap(
  Map<String, Object?> values, {
  required String type,
  required int start,
  required int end,
}) {
  final count = end - start + 1;
  final shifted = <String, Object?>{};
  for (final entry in values.entries) {
    final coord = _apiCoordFromKey(entry.key);
    if (coord == null) {
      shifted[entry.key] = cloneFortuneMetadata(entry.value);
      continue;
    }
    final row = coord.row;
    final column = coord.column;
    if (type == 'row') {
      if (row < start) {
        shifted['${row}_$column'] = cloneFortuneMetadata(entry.value);
      } else if (row > end) {
        shifted['${row - count}_$column'] = cloneFortuneMetadata(entry.value);
      }
    } else {
      if (column < start) {
        shifted['${row}_$column'] = cloneFortuneMetadata(entry.value);
      } else if (column > end) {
        shifted['${row}_${column - count}'] = cloneFortuneMetadata(entry.value);
      }
    }
  }
  return shifted;
}

