Object? _deleteApiSheetRangeMetadata(
  Object? raw, {
  required String type,
  required int start,
  required int end,
}) {
  if (raw is List) {
    final next = [
      for (final item in raw)
        ?_deleteApiSheetRangeMetadata(item, type: type, start: start, end: end),
    ];
    return next.isEmpty ? null : next;
  }
  if (raw is! Map) {
    return cloneFortuneMetadata(raw);
  }
  final next = _cloneObjectMap(raw);
  if (type == 'row') {
    final row = _apiFormatRangeAxis(raw['row']);
    if (row != null) {
      final nextRow = _deleteApiFormatRangeAxis(row, start: start, end: end);
      if (nextRow == null) {
        return null;
      }
      next['row'] = nextRow;
    }
    final rowFocus = _deleteApiFocusIndex(raw['row_focus'], start, end);
    if (rowFocus != null) {
      next['row_focus'] = rowFocus;
    }
    if (raw.containsKey('r')) {
      final r = _deleteApiCoordinateIndex(raw['r'], start, end);
      if (r == null) {
        return null;
      }
      next['r'] = r;
    }
  } else {
    final column = _apiFormatRangeAxis(raw['column']);
    if (column != null) {
      final nextColumn = _deleteApiFormatRangeAxis(
        column,
        start: start,
        end: end,
      );
      if (nextColumn == null) {
        return null;
      }
      next['column'] = nextColumn;
    }
    final columnFocus = _deleteApiFocusIndex(raw['column_focus'], start, end);
    if (columnFocus != null) {
      next['column_focus'] = columnFocus;
    }
    if (raw.containsKey('c')) {
      final c = _deleteApiCoordinateIndex(raw['c'], start, end);
      if (c == null) {
        return null;
      }
      next['c'] = c;
    }
  }
  for (final entry in raw.entries) {
    if (_isApiRangeCoordinateKey(entry.key)) {
      continue;
    }
    final value = entry.value;
    if (value is List || value is Map) {
      final deleted = _deleteApiSheetRangeMetadata(
        value,
        type: type,
        start: start,
        end: end,
      );
      if (deleted == null) {
        next.remove(entry.key);
      } else {
        next[entry.key] = deleted;
      }
    }
  }
  return next;
}

