int? _deleteApiCoordinateIndex(Object? raw, int start, int end) {
  final value = _nullableIntArg(raw);
  if (value == null) {
    return null;
  }
  if (value >= start && value <= end) {
    return null;
  }
  return value > end ? value - (end - start + 1) : value;
}

int? _deleteApiFocusIndex(Object? raw, int start, int end) {
  final value = _nullableIntArg(raw);
  if (value == null) {
    return null;
  }
  if (value >= start && value <= end) {
    return math.max(0, start - 1);
  }
  return value > end ? value - (end - start + 1) : value;
}

bool _isApiRangeCoordinateKey(Object? key) {
  return key == 'row' ||
      key == 'column' ||
      key == 'row_focus' ||
      key == 'column_focus' ||
      key == 'r' ||
      key == 'c';
}

