List<int>? _deleteApiFormatRangeAxis(
  List<int> range, {
  required int start,
  required int end,
}) {
  var rangeStart = range[0];
  var rangeEnd = range[1];
  final count = end - start + 1;
  if (rangeStart >= start && rangeEnd <= end) {
    return null;
  }
  if (rangeStart > end) {
    rangeStart -= count;
    rangeEnd -= count;
  } else if (rangeStart < start) {
    if (rangeEnd < start) {
    } else if (rangeEnd <= end) {
      rangeEnd = start - 1;
    } else {
      rangeEnd -= count;
    }
  } else if (rangeEnd > end) {
    rangeStart = start;
    rangeEnd -= count;
  }
  return [rangeStart, rangeEnd];
}

