  required int end,
  required Object? filterSelect,
}) {
  if (filterSelect is! Map) {
    return const <String, Object?>{};
  }
  return type == 'row'
      ? _deleteApiFilterRows(
          values,
          start: start,
          end: end,
          filterSelect: filterSelect,
        )
      : _deleteApiFilterColumns(
          values,
          start: start,
          end: end,
          filterSelect: filterSelect,
        );
}

