Map<String, Object?> _deleteApiFilterRows(
  Map<String, Object?> values, {
  required int start,
  required int end,
  required Map filterSelect,
}) {
  final rows = _apiFormatRangeAxis(filterSelect['row']);
  final count = end - start + 1;
  final next = <String, Object?>{};
  for (final entry in values.entries) {
    final raw = entry.value;
    if (raw is! Map) {
      next[entry.key] = cloneFortuneMetadata(raw);
      continue;
    }
    final config = _cloneObjectMap(raw);
    final rowhidden = raw['rowhidden'];
    if (rowhidden is Map) {
      final shifted = <String, Object?>{};
      for (final hiddenEntry in rowhidden.entries) {
        final hiddenRow = _nullableIntArg(hiddenEntry.key);
        if (hiddenRow == null || (hiddenRow >= start && hiddenRow <= end)) {
          continue;
        }
        shifted['${hiddenRow > end ? hiddenRow - count : hiddenRow}'] = 0;
      }
      if (shifted.isEmpty) {
        continue;
      }
      config['rowhidden'] = shifted;
    }
    if (rows != null) {
      config['str'] = rows[0];
      config['edr'] = rows[1];
    }
    next[entry.key] = config;
  }
  return next;
}

Map<String, Object?> _deleteApiFilterColumns(
  Map<String, Object?> values, {
  required int start,
  required int end,
  required Map filterSelect,
}) {
  final columns = _apiFormatRangeAxis(filterSelect['column']);
  final count = end - start + 1;
  final next = <String, Object?>{};
  for (final entry in values.entries) {
    final raw = entry.value;
    final keyIndex = _nullableIntArg(entry.key);
    final rawCindex = raw is Map ? _nullableIntArg(raw['cindex']) : null;
    final cindex = rawCindex ?? keyIndex;
    if (cindex != null && cindex >= start && cindex <= end) {
      continue;
    }
    if (raw is! Map) {
      final nextKey = keyIndex != null && keyIndex > end
          ? '${keyIndex - count}'
          : entry.key;
      next[nextKey] = cloneFortuneMetadata(raw);
      continue;
    }
    final config = _cloneObjectMap(raw);
    final shiftedCindex = cindex != null && cindex > end
        ? cindex - count
        : cindex;
    if (rawCindex != null && shiftedCindex != null) {
      config['cindex'] = shiftedCindex;
    }
    if (columns != null) {
      config['stc'] = columns[0];
      config['edc'] = columns[1];
    }
    final key = rawCindex != null && shiftedCindex != null && columns != null
        ? '${shiftedCindex - columns[0]}'
        : keyIndex != null && keyIndex > end
        ? '${keyIndex - count}'
        : entry.key;
    next[key] = config;
  }
  return next;
}

FortuneFrozenPane? _deleteApiFrozenPane(
  FortuneFrozenPane? frozen, {
  required String type,
  required int start,
  required int end,
}) {
  if (frozen == null) {
    return null;
  }
  if (type == 'row' && frozen.freezesRows) {
    final rowFocus = frozen.rowFocus;
    if (rowFocus != null && rowFocus >= start) {
      final removedBeforeFocus = math.min(end, rowFocus) - start + 1;
      return frozen.copyWith(rowFocus: rowFocus - removedBeforeFocus);
    }
  }
  if (type == 'column' && frozen.freezesColumns) {
    final columnFocus = frozen.columnFocus;
    if (columnFocus != null && columnFocus >= start) {
      final removedBeforeFocus = math.min(end, columnFocus) - start + 1;
      return frozen.copyWith(columnFocus: columnFocus - removedBeforeFocus);
    }
  }
  return frozen.copyWith();
}

FortuneCellCoord? _apiCoordFromKey(String key) {
  final parts = key.split('_');
  if (parts.length != 2) {
    return null;
  }
  final row = int.tryParse(parts[0]);
  final column = int.tryParse(parts[1]);
  if (row == null || column == null || row < 0 || column < 0) {
    return null;
  }
  return FortuneCellCoord(row, column);
}

Map<FortuneCellCoord, FortuneCell> _deleteApiCellRows(
  Map<FortuneCellCoord, FortuneCell> cells,
  int start,
  int end,
) {
  final count = end - start + 1;
  final shifted = {
    for (final entry in cells.entries)
      if (entry.key.row < start || entry.key.row > end)
        FortuneCellCoord(
          entry.key.row > end ? entry.key.row - count : entry.key.row,
          entry.key.column,
        ): _shiftApiCellMetadata(
          entry.value,
          rowFrom: end + 1,
          rowDelta: -count,
        ).copyWith(merge: null),
  };
  for (final entry in cells.entries) {
    final merge = entry.value.merge;
    if (!_apiCellOwnsMerge(entry.key, merge)) {
      continue;
    }
    final adjusted = _apiMergeAfterRowDelete(merge!, start, end);
    if (adjusted == null) {
      continue;
    }
    final anchor = FortuneCellCoord(adjusted.row, adjusted.column);
    shifted[anchor] = (shifted[anchor] ?? const FortuneCell()).copyWith(
      merge: adjusted,
    );
  }
  _ensureApiMergeCoveredCells(shifted);
  return shifted;
}

Map<FortuneCellCoord, FortuneCell> _deleteApiCellColumns(
  Map<FortuneCellCoord, FortuneCell> cells,
  int start,
  int end,
) {
  final count = end - start + 1;
  final shifted = {
    for (final entry in cells.entries)
      if (entry.key.column < start || entry.key.column > end)
        FortuneCellCoord(
          entry.key.row,
          entry.key.column > end ? entry.key.column - count : entry.key.column,
        ): _shiftApiCellMetadata(
          entry.value,
          columnFrom: end + 1,
          columnDelta: -count,
        ).copyWith(merge: null),
  };
  for (final entry in cells.entries) {
    final merge = entry.value.merge;
    if (!_apiCellOwnsMerge(entry.key, merge)) {
      continue;
    }
    final adjusted = _apiMergeAfterColumnDelete(merge!, start, end);
    if (adjusted == null) {
      continue;
    }
    final anchor = FortuneCellCoord(adjusted.row, adjusted.column);
    shifted[anchor] = (shifted[anchor] ?? const FortuneCell()).copyWith(
      merge: adjusted,
    );
  }
  _ensureApiMergeCoveredCells(shifted);
  return shifted;
}

FortuneCellMerge? _apiMergeAfterRowDelete(
  FortuneCellMerge merge,
  int start,
  int end,
) {
  final count = end - start + 1;
  final mergeEnd = merge.row + math.max(1, merge.rowSpan) - 1;
  if (merge.row < start) {
    if (mergeEnd < start) {
      return merge.copyWith();
    }
    final nextSpan = mergeEnd < end ? start - merge.row : merge.rowSpan - count;
    return nextSpan <= 0
        ? null
        : merge.copyWith(
            rowSpan: nextSpan,
            rawRowSpan: null,
            hasRawRowSpan: false,
          );
  }
  if (merge.row <= end) {
    if (mergeEnd <= end) {
      return null;
    }
    final nextSpan = mergeEnd - end;
    return merge.copyWith(
      row: start,
      rawRow: null,
      hasRawRow: false,
      rowSpan: nextSpan,
      rawRowSpan: null,
      hasRawRowSpan: false,
    );
  }
  return merge.copyWith(row: merge.row - count, rawRow: null, hasRawRow: false);
}

FortuneCellMerge? _apiMergeAfterColumnDelete(
  FortuneCellMerge merge,
  int start,
  int end,
) {
  final count = end - start + 1;
  final mergeEnd = merge.column + math.max(1, merge.columnSpan) - 1;
  if (merge.column < start) {
    if (mergeEnd < start) {
      return merge.copyWith();
    }
    final nextSpan = mergeEnd < end
        ? start - merge.column
        : merge.columnSpan - count;
    return nextSpan <= 0
        ? null
        : merge.copyWith(
            columnSpan: nextSpan,
            rawColumnSpan: null,
            hasRawColumnSpan: false,
          );
  }
  if (merge.column <= end) {
    if (mergeEnd <= end) {
      return null;
    }
    final nextSpan = mergeEnd - end;
    return merge.copyWith(
      column: start,
      rawColumn: null,
      hasRawColumn: false,
      columnSpan: nextSpan,
      rawColumnSpan: null,
      hasRawColumnSpan: false,
    );
  }
  return merge.copyWith(
    column: merge.column - count,
    rawColumn: null,
    hasRawColumn: false,
  );
}

