  return {
    for (final entry in raw.entries)
      if (!_deleteApiRawIntKeyInRange(entry.key, start, end))
        '${_deleteApiRawIntKey(entry.key, end, count)}': cloneFortuneMetadata(
          entry.value,
        ),
  };
}

bool _deleteApiRawIntKeyInRange(Object rawKey, int start, int end) {
  final key = int.tryParse('$rawKey');
  return key != null && key >= start && key <= end;
}

Object _deleteApiRawIntKey(Object rawKey, int end, int count) {
  final key = int.tryParse('$rawKey');
  if (key == null) {
    return rawKey;
  }
  return key > end ? key - count : key;
}

Object? _deleteApiRawMergeConfig(
  Object? raw, {
  required String type,
  required int start,
  required int end,
}) {
  if (raw is! Map) {
    return cloneFortuneMetadata(raw);
  }
  final next = <String, Object?>{};
  for (final entry in raw.entries) {
    final config = entry.value;
    if (config is! Map) {
      next[entry.key.toString()] = cloneFortuneMetadata(config);
      continue;
    }
    final shifted = _deleteApiRawMergeItem(
      config,
      type: type,
      start: start,
      end: end,
    );
    if (shifted == null) {
      continue;
    }
    next[_apiRawMergeKey(shifted, entry.key)] = shifted;
  }
  return next;
}

Map<Object?, Object?>? _deleteApiRawMergeItem(
  Map raw, {
  required String type,
  required int start,
  required int end,
}) {
  final merge = _apiMergeFromRawConfig(raw);
  if (merge == null) {
    return _cloneObjectMap(raw);
  }
  final shifted = type == 'row'
      ? _apiMergeAfterRowDelete(merge, start, end)
      : _apiMergeAfterColumnDelete(merge, start, end);
  if (shifted == null) {
    return null;
  }
  final next = _cloneObjectMap(raw);
  if (shifted.row != merge.row) {
    next['r'] = shifted.row;
  }
  if (shifted.column != merge.column) {
    next['c'] = shifted.column;
  }
  if (shifted.rowSpan != merge.rowSpan) {
    next['rs'] = shifted.rowSpan;
  }
  if (shifted.columnSpan != merge.columnSpan) {
    next['cs'] = shifted.columnSpan;
  }
  return next;
}

FortuneCellMerge? _apiMergeFromRawConfig(Map raw) {
  final row = _nullableIntArg(raw['r']);
  final column = _nullableIntArg(raw['c']);
  if (row == null || column == null) {
    return null;
  }
  return FortuneCellMerge(
    row: row,
    column: column,
    rowSpan: math.max(1, _nullableIntArg(raw['rs']) ?? 1),
    columnSpan: math.max(1, _nullableIntArg(raw['cs']) ?? 1),
  );
}

bool _apiRangeIsSingleCell(FortuneRange range) =>
    range.rowStart == range.rowEnd && range.columnStart == range.columnEnd;

bool _apiRangeHasMerge(
  Map<FortuneCellCoord, FortuneCell> cells,
  FortuneRange range,
) {
  final normalized = _normalizedApiRange(range);
  if (normalized == null) {
    return false;
  }
  for (var row = normalized.rowStart; row <= normalized.rowEnd; row += 1) {
    for (
      var column = normalized.columnStart;
      column <= normalized.columnEnd;
      column += 1
    ) {
      if (cells[FortuneCellCoord(row, column)]?.merge != null) {
        return true;
      }
    }
  }
  return false;
}

void _clearMergesInApiRange(
  Map<FortuneCellCoord, FortuneCell> cells,
  FortuneRange range,
) {
  final targets = <FortuneCellCoord>{};
  for (var row = range.rowStart; row <= range.rowEnd; row += 1) {
    for (
      var column = range.columnStart;
      column <= range.columnEnd;
      column += 1
    ) {
      targets.add(FortuneCellCoord(row, column));
    }
  }
  for (final coord in targets) {
    _clearApiMergeAt(cells, coord);
  }
}

void _mergeApiCellsAt(
  Map<FortuneCellCoord, FortuneCell> cells,
  FortuneCellCoord anchor, {
  required int rowSpan,
  required int columnSpan,
  bool allowSingleCell = false,
}) {
  if (!allowSingleCell && rowSpan <= 1 && columnSpan <= 1) {
    return;
  }
  final merge = FortuneCellMerge(
    row: anchor.row,
    column: anchor.column,
    rowSpan: rowSpan,
    columnSpan: columnSpan,
  );
  final source = _apiFirstMergeSourceCell(
    cells,
    anchor,
    rowSpan: rowSpan,
    columnSpan: columnSpan,
  );
  cells[anchor] = (source ?? const FortuneCell()).copyWith(merge: merge);
  for (var row = anchor.row; row < anchor.row + rowSpan; row += 1) {
    for (
      var column = anchor.column;
      column < anchor.column + columnSpan;
      column += 1
    ) {
      final coord = FortuneCellCoord(row, column);
      if (coord == anchor) {
        continue;
      }
      cells[coord] = const FortuneCell().copyWith(
        merge: FortuneCellMerge(row: anchor.row, column: anchor.column),
      );
    }
  }
}

FortuneCell? _apiFirstMergeSourceCell(
  Map<FortuneCellCoord, FortuneCell> cells,
  FortuneCellCoord anchor, {
  required int rowSpan,
  required int columnSpan,
}) {
  for (var row = anchor.row; row < anchor.row + rowSpan; row += 1) {
    for (
      var column = anchor.column;
      column < anchor.column + columnSpan;
      column += 1
    ) {
      final cell = cells[FortuneCellCoord(row, column)];
      if (cell != null && _apiMergeCellHasContent(cell)) {
        return cell.copyWith();
      }
    }
  }
  return null;
}

bool _apiMergeCellHasContent(FortuneCell cell) {
  final rawValue = cell.hasRawValue ? cell.rawValue : cell.value;
  return _apiCellHasFormulaMetadata(cell) ||
      rawValue != null && rawValue.toString().isNotEmpty ||
      cell.inlineRuns != null && cell.inlineRuns!.isNotEmpty;
}

void _clearApiMergeAt(
  Map<FortuneCellCoord, FortuneCell> cells,
  FortuneCellCoord coord,
) {
  final anchor = _apiMergeAnchorInCells(cells, coord);
  final merge = cells[anchor]?.merge;
  if (merge == null) {
    return;
  }
  final rowSpan = math.max(1, merge.rowSpan);
  final columnSpan = math.max(1, merge.columnSpan);
  final anchorCell = cells[anchor];
  for (var row = merge.row; row < merge.row + rowSpan; row += 1) {
    for (
      var column = merge.column;
      column < merge.column + columnSpan;
      column += 1
    ) {
      final cellCoord = FortuneCellCoord(row, column);
      final cell = cells[cellCoord];
      if (cell == null) {
        continue;
      }
      final withoutMerge = cellCoord == anchor
          ? cell.copyWith(merge: null)
          : _apiMergeCancelCoveredCell(anchorCell ?? const FortuneCell());
      if (withoutMerge.isVisuallyEmpty &&
          !_apiCellHasNonVisualData(withoutMerge)) {
        cells.remove(cellCoord);
      } else {
        cells[cellCoord] = withoutMerge;
      }
    }
  }
}

FortuneCell _apiMergeCancelCoveredCell(FortuneCell anchorCell) {
  return anchorCell.copyWith(
    value: '',
    rawValue: null,
    hasRawValue: false,
    displayValue: null,
    rawDisplayValue: null,
    hasRawDisplayValue: false,
    formula: null,
    rawFormula: null,
    hasRawFormula: false,
    merge: null,
    cellType: null,
    sparkline: null,
    rawSparkline: null,
    hasSparkline: false,
    hasRawSparkline: false,
    inlineRuns: null,
  );
}

bool _apiCellHasNonVisualData(FortuneCell cell) {
  return cell.background != null ||
      cell.hasRawBackground ||
      cell.hasRawForeground ||
      cell.bold ||
      cell.hasRawBold ||
      cell.italic ||
      cell.hasRawItalic ||
      cell.strikeThrough ||
      cell.hasRawStrikeThrough ||
      cell.underline ||
      cell.hasRawUnderline ||
      cell.fontSize != null ||
      cell.hasRawFontSize ||
      cell.fontFamily != null ||
      cell.hasRawFontFamily ||
      cell.horizontalAlign != null ||
      cell.hasRawHorizontalAlign ||
      cell.verticalAlign != null ||
      cell.hasRawVerticalAlign ||
      cell.textWrap != null ||
      cell.hasRawTextWrap ||
      cell.textRotation != null ||
      cell.hasRawTextRotation ||
      cell.textRotationMode != null ||
      cell.hasRawTextRotationMode ||
      cell.quotePrefix ||
      cell.hasRawQuotePrefix ||
      cell.locked != null ||
      cell.hasRawLocked ||
      cell.comment != null ||
      cell.hyperlink != null ||
      cell.extraFields.isNotEmpty;
}

FortuneCellCoord _apiMergeAnchorInCells(
  Map<FortuneCellCoord, FortuneCell> cells,
  FortuneCellCoord coord,
) {
  final merge = cells[coord]?.merge;
  if (merge == null) {
    return coord;
  }
  return FortuneCellCoord(merge.row, merge.column);
}

class FortuneCellCoord {
  const FortuneCellCoord(this.row, this.column);

  final int row;
  final int column;

  @override
  bool operator ==(Object other) {
    return other is FortuneCellCoord &&
        other.row == row &&
        other.column == column;
  }

  @override
  int get hashCode => Object.hash(row, column);
}

