  String get normalizedTextRotationMode {
    return switch (textRotationMode) {
      '0' || '1' || '2' || '3' || '4' || '5' => textRotationMode!,
      _ => '0',
    };
  }

  bool get isVerticalText => normalizedTextRotationMode == '3';

  double get normalizedTextRotation {
    final explicitAngle = double.tryParse(textRotation ?? '');
    if (explicitAngle != null) {
      if (explicitAngle < 0 || explicitAngle > 180) {
        return 0;
      }
      if (explicitAngle > 90) {
        return 90 - explicitAngle;
      }
      return explicitAngle;
    }
    return switch (normalizedTextRotationMode) {
      '1' => 45,
      '2' => -45,
      '4' => 90,
      '5' => -90,
      _ => 0,
    };
  }

  String get normalizedFontFamily {
    return fortuneNormalizeFontFamily(fontFamily);
  }

