const Object _sentinel = Object();

double? _nullableDoubleArg(Object? value) {
  if (value == null) {
    return null;
  }
  if (value is num) {
    return value.toDouble();
  }
  return double.tryParse('$value');
}

int? _nullableIntArg(Object? value) {
  if (value == null) {
    return null;
  }
  if (value is int) {
    return value;
  }
  if (value is num) {
    return value.toInt();
  }
  return int.tryParse('$value');
}

bool? _nullableBoolArg(Object? value) {
  if (value == null) {
    return null;
  }
  if (value is bool) {
    return value;
  }
  if (value is num) {
    return value != 0;
  }
  final string = '$value'.toLowerCase();
  if (string == '1' || string == 'true') {
    return true;
  }
  if (string == '0' || string == 'false') {
    return false;
  }
  return null;
}

String? _nullableStringArg(Object? value) => value == null ? null : '$value';

Color? _nullableColorArg(Object? value) {
  if (value == null) {
    return null;
  }
  if (value is Color) {
    return value;
  }
  if (value is num) {
    return Color(value.toInt());
  }
  final raw = '$value'.trim();
  final hex = RegExp(r'^(?:#|0x)?([0-9a-fA-F]{6}|[0-9a-fA-F]{8})$');
  final match = hex.firstMatch(raw);
  if (match == null) {
    return null;
  }
  final digits = match.group(1)!;
  final parsed = int.tryParse(digits, radix: 16);
  if (parsed == null) {
    return null;
  }
  if (digits.length == 6) {
    return Color(0xff000000 | parsed);
  }
  return Color(parsed);
}

Object? cloneFortuneMetadata(Object? value) {
  if (value is Map) {
    return {
      for (final entry in value.entries)
        entry.key: cloneFortuneMetadata(entry.value),
    };
  }
  if (value is List) {
    return [for (final item in value) cloneFortuneMetadata(item)];
  }
  if (value is Set) {
    return {for (final item in value) cloneFortuneMetadata(item)};
  }
  return value;
}

class FortuneSelection {
  const FortuneSelection({
    required this.row,
    required this.column,
    int? rowEnd,
    int? columnEnd,
  }) : rowEnd = rowEnd ?? row,
       columnEnd = columnEnd ?? column;

  final int row;
  final int column;
  final int rowEnd;
  final int columnEnd;

  int get rowStart => math.min(row, rowEnd);
  int get normalizedRowEnd => math.max(row, rowEnd);
  int get columnStart => math.min(column, columnEnd);
  int get normalizedColumnEnd => math.max(column, columnEnd);
  bool get isSingleCell => row == rowEnd && column == columnEnd;
}

class FortuneSheetMetrics {
  const FortuneSheetMetrics({
    required this.visibleDataRows,
    required this.visibleDataColumns,
    required this.rowTotalHeight,
    required this.columnTotalWidth,
  });

  final List<double> visibleDataRows;
  final List<double> visibleDataColumns;
  final double rowTotalHeight;
  final double columnTotalWidth;

  factory FortuneSheetMetrics.fromSheet({
    required FortuneSheet sheet,
    required FortuneSettings settings,
    double zoomRatio = 1,
  }) {
    final rows = <double>[];
    var rowHeight = 0.0;
    final rowCount = sheet.rowCount ?? settings.row;
    for (var r = 0; r < rowCount; r += 1) {
      final height =
          sheet.rowHeights[r] ??
          sheet.defaultRowHeight ??
          settings.defaultRowHeight;
      if (!sheet.hiddenRows.contains(r)) {
        rowHeight += ((height + 1) * zoomRatio).roundToDouble();
      }
      rows.add(rowHeight);
    }
    rowHeight += 80;

    final columns = <double>[];
    var columnWidth = 0.0;
    final columnCount = sheet.columnCount ?? settings.column;
    for (var c = 0; c < columnCount; c += 1) {
      final width =
          sheet.columnWidths[c] ??
          sheet.defaultColWidth ??
          settings.defaultColWidth;
      if (!sheet.hiddenColumns.contains(c)) {
        columnWidth += ((width + 1) * zoomRatio).roundToDouble();
      }
      columns.add(columnWidth);
    }
    columnWidth += 120;

    return FortuneSheetMetrics(
      visibleDataRows: rows,
      visibleDataColumns: columns,
      rowTotalHeight: rowHeight,
      columnTotalWidth: columnWidth,
    );
  }

  FortuneAxisRange visibleRows(double scrollTop, double viewportHeight) {
    return FortuneAxisRange.fromVisibleData(
      visibleDataRows,
      scrollTop,
      viewportHeight,
    );
  }

  FortuneAxisRange visibleColumns(double scrollLeft, double viewportWidth) {
    return FortuneAxisRange.fromVisibleData(
      visibleDataColumns,
      scrollLeft,
      viewportWidth,
    );
  }

  FortuneAxisCell rowAt(double y) {
    return FortuneAxisCell.fromVisibleData(visibleDataRows, y);
  }

  FortuneAxisCell columnAt(double x) {
    return FortuneAxisCell.fromVisibleData(visibleDataColumns, x);
  }

  double rowStart(int row) => row <= 0 ? 0 : visibleDataRows[row - 1];

  double rowEnd(int row) => visibleDataRows[row];

  double columnStart(int column) =>
      column <= 0 ? 0 : visibleDataColumns[column - 1];

  double columnEnd(int column) => visibleDataColumns[column];
}

class FortuneAxisRange {
  const FortuneAxisRange({required this.start, required this.end});

  final int start;
  final int end;

  factory FortuneAxisRange.fromVisibleData(
    List<double> visibleData,
    double scroll,
    double viewport,
  ) {
    if (visibleData.isEmpty) {
      return const FortuneAxisRange(start: 0, end: -1);
    }
    final start = _lowerBound(visibleData, scroll);
    var end = _lowerBound(visibleData, scroll + viewport);
    if (end >= visibleData.length) {
      end = visibleData.length - 1;
    }
    return FortuneAxisRange(start: start, end: end);
  }
}

class FortuneAxisCell {
  const FortuneAxisCell({
    required this.index,
    required this.start,
    required this.end,
  });

  final int index;
  final double start;
  final double end;

  factory FortuneAxisCell.fromVisibleData(
    List<double> visibleData,
    double pos,
  ) {
    final index = _lowerBound(
      visibleData,
      pos,
    ).clamp(0, visibleData.length - 1);
    return FortuneAxisCell(
      index: index,
      start: index <= 0 ? 0 : visibleData[index - 1],
      end: visibleData[index],
    );
  }
}

int _lowerBound(List<double> values, double target) {
  var low = 0;
  var high = values.length;
  while (low < high) {
    final mid = low + ((high - low) >> 1);
    if (values[mid] < target) {
      low = mid + 1;
    } else {
      high = mid;
    }
  }
  return low;
}
